# 01_build_capability_profiles.R
# Purpose: Build defender capability profiles from tracking data.
# Inputs:  CSVs in ./train/ named like input_YYYY_wNN.csv
# Outputs: ./artifacts/capability_profiles.csv + console summary
# Root:    The current working directory IS the project root. Do setwd() before running.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) install.packages(need, quiet = TRUE)
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","purrr","stringr","scales"))

# Project paths (single source of truth)
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  train     = B("train"),
  artifacts = B("artifacts"),
  tmp       = B("artifacts","tmp")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# Small helpers
read_csv_clean <- function(path) readr::read_csv(path, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()
require_cols <- function(df, cols, where="data") {
  miss <- setdiff(cols, names(df))
  if (length(miss)) stop(sprintf("Missing required columns in %s: %s", where, paste(miss, collapse=", ")), call. = FALSE)
  invisible(TRUE)
}

# -------------------- 1) Load training files --------------------
files <- list.files(DIRS$train, pattern = "^input_\\d{4}_w\\d{2}\\.csv$", full.names = TRUE)
if (!length(files)) stop(sprintf("No training CSVs found in %s matching input_YYYY_wNN.csv", DIRS$train), call. = FALSE)

message(sprintf("[1/6] Found %d training files.", length(files)))
dat <- purrr::map_dfr(files, read_csv_clean)

# -------------------- 2) Column cleanup --------------------
dat <- dat |>
  janitor::clean_names() |>
  dplyr::rename(
    game_id  = dplyr::any_of("game_id"),
    play_id  = dplyr::any_of("play_id"),
    nfl_id   = dplyr::any_of(c("nfl_id","nflid")),
    frame_id = dplyr::any_of(c("frame_id","frameid")),
    x = dplyr::any_of("x"),
    y = dplyr::any_of("y"),
    s = dplyr::any_of("s"),
    a = dplyr::any_of("a"),
    dir = dplyr::any_of("dir"),
    o = dplyr::any_of("o"),
    event = dplyr::any_of("event")
  )

require_cols(dat, c("nfl_id","frame_id"), "tracking data (ids)")
require_cols(dat, c("s","dir"), "tracking data (capability features)")

# Minimal type normalization
num_cols <- intersect(c("x","y","s","a","dir","o"), names(dat))
for (nm in num_cols) dat[[nm]] <- suppressWarnings(as.numeric(dat[[nm]]))
dat$frame_id <- suppressWarnings(as.integer(dat$frame_id))
dat$nfl_id   <- as.character(dat$nfl_id)

# -------------------- 3) Sanity filters (no base-pipe curly nonsense) --------------------
DT <- 0.1  # seconds per frame (10 Hz)

dat <- dat |>
  dplyr::filter(!is.na(nfl_id), !is.na(frame_id)) |>
  dplyr::filter(!is.na(s), s >= 0, s <= 12)

if ("a" %in% names(dat)) {
  dat <- dat |> dplyr::filter(is.na(a) | (a >= -10 & a <= 10))
}

dat <- dat |> dplyr::filter(!is.na(dir), dir >= 0, dir <= 360)

message(sprintf("[2/6] Frames after sanity filters: %s", scales::comma(nrow(dat))))

# -------------------- 4) Turn-rate (angular velocity) prep --------------------
# Unwrap angles per player so 359->1 degrees becomes 2 degrees, not 358.
deg_unwrap <- function(deg_vec) {
  rad <- deg_vec * pi/180
  out <- numeric(length(rad))
  if (!length(rad)) return(out)
  out[1] <- rad[1]
  if (length(rad) > 1) {
    for (i in 2:length(rad)) {
      d <- rad[i] - rad[i-1]
      d <- atan2(sin(d), cos(d))  # wrap to [-pi, pi]
      out[i] <- out[i-1] + d
    }
  }
  out * 180/pi
}

# Compute per-player absolute angular velocity (deg/s)
turn_rate_tbl_full <- dat |>
  dplyr::arrange(nfl_id, frame_id) |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    turn_rate_abs = list({
      ang <- deg_unwrap(dir)
      if (length(ang) < 2) numeric(0) else abs(diff(ang)) / DT
    }),
    .groups = "drop"
  ) |>
  dplyr::mutate(
    n_turn = purrr::map_int(turn_rate_abs, length),
    turn_rate_p95_raw = purrr::map_dbl(turn_rate_abs, ~ if (length(.x)) quantile(.x, 0.95, na.rm = TRUE) else NA_real_)
  )

# Pooled prior for turn-rate uses the concatenated vector
turn_pooled <- unlist(turn_rate_tbl_full$turn_rate_abs, use.names = FALSE)
turn_prior <- if (length(turn_pooled)) quantile(turn_pooled, 0.95, na.rm = TRUE) else NA_real_

# Drop the heavy list column before joining
turn_rate_tbl <- turn_rate_tbl_full |>
  dplyr::select(nfl_id, n_turn, turn_rate_p95_raw)

# -------------------- 5) Per-player raw summaries --------------------
cap_raw <- dat |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    n_v = dplyr::n(),
    v_max_raw = quantile(s, 0.95, na.rm = TRUE),
    a_max_raw = if ("a" %in% names(dat)) quantile(pmax(a, 0), 0.95, na.rm = TRUE) else NA_real_,
    .groups = "drop"
  ) |>
  dplyr::left_join(turn_rate_tbl, by = "nfl_id")

# -------------------- 6) Global priors and EB shrinkage (vectorized) --------------------
v_prior <- quantile(dat$s, 0.95, na.rm = TRUE)
a_prior <- if ("a" %in% names(dat)) quantile(pmax(dat$a, 0), 0.95, na.rm = TRUE) else NA_real_
K <- 500  # pseudo-frames for shrinkage

# Vectorized shrink: prior is scalar, est/n are vectors
shrink_vec <- function(est, n, prior, k = K) {
  w <- n / (n + k)
  out <- w * est + (1 - w) * prior
  out[is.na(est) | is.na(n)] <- NA_real_
  out
}

has_a <- "a" %in% names(dat)  # whether acceleration was present at all

# Compute final capability metrics
v_max_vec <- shrink_vec(cap_raw$v_max_raw, cap_raw$n_v, v_prior, K)
a_max_vec <- if (has_a) {
  shrink_vec(cap_raw$a_max_raw, cap_raw$n_v, a_prior, K)
} else {
  rep(NA_real_, nrow(cap_raw))
}
turn_rate_vec <- shrink_vec(cap_raw$turn_rate_p95_raw, cap_raw$n_turn, turn_prior, K)

cap_final <- cap_raw |>
  dplyr::transmute(
    nfl_id,
    v_max = v_max_vec,
    a_max = a_max_vec,
    turn_rate_p95 = turn_rate_vec,
    n_frames_used = pmin(n_v, ifelse(is.na(n_turn), n_v, n_turn))
  ) |>
  # Plausible caps so one freak frame doesn’t invent a superhero
  dplyr::mutate(
    v_max = pmin(pmax(v_max, 4), 12),
    a_max = ifelse(is.na(a_max), NA_real_, pmin(pmax(a_max, 0), 8)),
    turn_rate_p95 = ifelse(is.na(turn_rate_p95), NA_real_, pmin(pmax(turn_rate_p95, 0), 1000))
  ) |>
  dplyr::arrange(nfl_id)

# -------------------- 7) Write artifact + summary --------------------
out_path <- file.path(DIRS$artifacts, "capability_profiles.csv")
readr::write_csv(cap_final, out_path)
message(sprintf("[3/6] Wrote %s rows to %s", nrow(cap_final), out_path))

# Tiny sanity report
non_na_cols <- c(
  "v_max" = sum(!is.na(cap_final$v_max)),
  "a_max" = sum(!is.na(cap_final$a_max)),
  "turn_rate_p95" = sum(!is.na(cap_final$turn_rate_p95))
)
rng <- function(x) paste0(sprintf("%.3f", suppressWarnings(min(x, na.rm = TRUE))), " .. ", sprintf("%.3f", suppressWarnings(max(x, na.rm = TRUE))))
v_rng <- if (all(is.na(cap_final$v_max))) "NA" else rng(cap_final$v_max)
a_rng <- if (all(is.na(cap_final$a_max))) "NA" else rng(cap_final$a_max)
t_rng <- if (all(is.na(cap_final$turn_rate_p95))) "NA" else rng(cap_final$turn_rate_p95)

message(sprintf("[4/6] Non-missing counts: v_max=%d, a_max=%d, turn_rate_p95=%d",
                non_na_cols[["v_max"]], non_na_cols[["a_max"]], non_na_cols[["turn_rate_p95"]]))
message(sprintf("[5/6] Ranges: v_max %s | a_max %s | turn_rate_p95 %s (deg/s)", v_rng, a_rng, t_rng))
message("[6/6] Done. Next step will consume artifacts/capability_profiles.csv.")










# 02_build_split_map.R
# Purpose: Create a leak-free train/val/test split map at the GAME level.
# Inputs: all CSVs in ./train/ matching input_2023_*.csv or input_YYYY_wNN.csv
# Output: ./data/splits/plays_split_map.csv (+ metrics + report)
# Rule: every game_id goes to exactly one of {train, val, test}. No leakage.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  train  = B("train"),
  splits = B("data","splits"),
  artifacts = B("artifacts")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_OUT      <- file.path(DIRS$splits, "plays_split_map.csv")
PATH_METRICS  <- file.path(DIRS$artifacts, "split_map_metrics.csv")
PATH_REPORT   <- file.path(DIRS$artifacts, "split_map_report.md")

# -------------------- 1) Load all plays --------------------
find_inputs <- function(train_dir = DIRS$train) {
  c(
    Sys.glob(file.path(train_dir, "input_2023_*.csv")),
    list.files(train_dir, pattern = "^input_\\d{4}_w\\d{2}\\.csv$", full.names = TRUE)
  ) |> unique()
}
files <- find_inputs()
if (!length(files)) stop("No training CSVs found under ", DIRS$train, call. = FALSE)

read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

raw <- purrr::map_dfr(files, read_csv_clean) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id))
  ) |>
  select(game_id, play_id) |>
  distinct()

if (!all(c("game_id","play_id") %in% names(raw))) {
  stop("Inputs must include game_id and play_id columns.", call. = FALSE)
}

# -------------------- 2) Compute game-level inventory --------------------
games <- raw |>
  count(game_id, name = "n_plays") |>
  arrange(game_id)

total_plays <- sum(games$n_plays)
n_games <- nrow(games)
if (n_games < 3) stop("Need at least 3 games to form train/val/test splits. Found: ", n_games, call. = FALSE)

# -------------------- 3) Deterministic shuffle and cut by play-count (70/15/15) --------------------
set.seed(2025)  # deterministic assignment
games <- games |> slice_sample(prop = 1)  # fixed random order

target_train <- 0.70 * total_plays
target_val   <- 0.15 * total_plays
# test gets the remainder

cum <- cumsum(games$n_plays)
cut_train <- max(which(cum <= target_train))
cut_val   <- max(which(cum <= target_train + target_val))

# ensure at least one game in each split
cut_train <- max(1, min(cut_train, n_games - 2))
cut_val   <- max(cut_train + 1, min(cut_val, n_games - 1))

games <- games |>
  mutate(
    split = case_when(
      row_number() <= cut_train ~ "train",
      row_number() <= cut_val   ~ "val",
      TRUE                      ~ "test"
    )
  )

# -------------------- 4) Expand to play level and guardrails --------------------
split_map <- raw |>
  left_join(games, by = "game_id") |>
  select(game_id, play_id, split) |>
  arrange(game_id, play_id)

# Guard: every game_id assigned exactly once
leak_chk <- games |> count(game_id) |> filter(n != 1)
if (nrow(leak_chk)) stop("Internal error: duplicate game assignment produced.", call. = FALSE)

# Guard: no NA splits
if (any(is.na(split_map$split))) {
  bad <- split_map |> filter(is.na(split)) |> distinct(game_id)
  stop("Some games were not assigned to a split. Example: ", paste(head(bad$game_id, 5), collapse = ", "), call. = FALSE)
}

# -------------------- 5) Write outputs --------------------
# Backup old map if it exists
if (file.exists(PATH_OUT)) {
  stamp <- format(Sys.time(), "%Y%m%d_%H%M%S")
  file.copy(PATH_OUT, file.path(DIRS$splits, paste0("plays_split_map.backup_", stamp, ".csv")), overwrite = TRUE)
}

readr::write_csv(split_map, PATH_OUT)

# Metrics and report
by_split <- split_map |>
  group_by(split) |>
  summarise(
    games   = n_distinct(game_id),
    plays   = n_distinct(play_id),
    .groups = "drop"
  ) |>
  arrange(factor(split, levels = c("train","val","test")))

cov_play <- by_split$plays / sum(by_split$plays)

metrics <- tibble(
  metric = c("games_total","plays_total",
             "games_train","plays_train","plays_train_share",
             "games_val","plays_val","plays_val_share",
             "games_test","plays_test","plays_test_share"),
  value = c(
    n_games, total_plays,
    by_split$games[by_split$split=="train"], by_split$plays[by_split$split=="train"], cov_play[by_split$split=="train"],
    by_split$games[by_split$split=="val"],   by_split$plays[by_split$split=="val"],   cov_play[by_split$split=="val"],
    by_split$games[by_split$split=="test"],  by_split$plays[by_split$split=="test"],  cov_play[by_split$split=="test"]
  )
)
readr::write_csv(metrics, PATH_METRICS)

report <- c(
  "# Split map report",
  "",
  sprintf("- Games total: %s", comma(n_games)),
  sprintf("- Plays total: %s", comma(total_plays)),
  "",
  "## Per split",
  paste0("- train: games=", by_split$games[by_split$split=="train"], 
         ", plays=", by_split$plays[by_split$split=="train"],
         " (", percent(cov_play[by_split$split=="train"]), ")"),
  paste0("- val:   games=", by_split$games[by_split$split=="val"], 
         ", plays=", by_split$plays[by_split$split=="val"],
         " (", percent(cov_play[by_split$split=="val"]), ")"),
  paste0("- test:  games=", by_split$games[by_split$split=="test"], 
         ", plays=", by_split$plays[by_split$split=="test"],
         " (", percent(cov_play[by_split$split=="test"]), ")"),
  "",
  "## Integrity checks",
  "- Each game_id appears in exactly one split: PASS",
  "- No missing splits: PASS"
)
writeLines(report, PATH_REPORT, useBytes = TRUE)

# Console summary
message("Wrote: ", PATH_OUT)
print(by_split)
message("Done.")










# 02a_split_map_verification.R (by-GAME gating; plays are informational)
# Verifies data/splits/plays_split_map.csv. PASS/FAIL gates use 70/15/15 BY GAMES.

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  train     = B("train"),
  splits    = B("data","splits"),
  artifacts = B("artifacts")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_MAP   <- file.path(DIRS$splits, "plays_split_map.csv")
PATH_M02   <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")

OUT_STATUS_CSV <- file.path(DIRS$artifacts, "split_map_verification_status.csv")
OUT_STATUS_MD  <- file.path(DIRS$artifacts, "split_map_verification_status.md")
OUT_METRICS    <- file.path(DIRS$artifacts, "split_map_verification_metrics.csv")
OUT_REPORT     <- file.path(DIRS$artifacts, "split_map_verification_report.md")

# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
skip <- function() "SKIP"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

# -------------------- Load split map --------------------
if (!file.exists(PATH_MAP)) stop("Missing split map at ", PATH_MAP, call. = FALSE)
map <- read_csv_clean(PATH_MAP) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    split   = tolower(as.character(split))
  )
need_map <- c("game_id","play_id","split")
miss_map <- setdiff(need_map, names(map))
if (length(miss_map)) stop("Split map missing columns: ", paste(miss_map, collapse=", "), call. = FALSE)

# -------------------- Optional sources for cross-checks --------------------
find_inputs <- function(train_dir = DIRS$train) {
  c(
    Sys.glob(file.path(train_dir, "input_2023_*.csv")),
    list.files(train_dir, pattern = "^input_\\d{4}_w\\d{2}\\.csv$", full.names = TRUE)
  ) |> unique()
}
in_files <- find_inputs()
inputs <- if (length(in_files)) {
  purrr::map_dfr(in_files, read_csv_clean) |>
    mutate(game_id = as.character(game_id),
           play_id = suppressWarnings(as.integer(play_id))) |>
    select(game_id, play_id) |>
    distinct()
} else NULL

m02 <- if (file.exists(PATH_M02)) {
  read_csv_clean(PATH_M02) |>
    mutate(game_id = as.character(game_id),
           play_id = suppressWarnings(as.integer(play_id))) |>
    select(game_id, play_id) |>
    distinct()
} else NULL

# -------------------- Basic integrity checks --------------------
allowed_splits <- c("train","val","test")
by_game <- map |> distinct(game_id, split)

has_rows               <- nrow(map) > 0
split_values_valid     <- all(map$split %in% allowed_splits)
no_na_split            <- !any(is.na(map$split))
unique_game_assignment <- all(by_game %>% count(game_id) %>% pull(n) == 1)
no_dup_rows            <- nrow(map) == nrow(distinct(map, game_id, play_id, split))

# -------------------- Coverage vs inputs --------------------
cov_games_inputs <- cov_plays_inputs <- NA
if (!is.null(inputs)) {
  inputs_games <- inputs |> distinct(game_id)
  cov_games_inputs <- setdiff(inputs_games$game_id, by_game$game_id)
  cov_plays_inputs <- anti_join(inputs, map, by = c("game_id","play_id"))
}

# -------------------- Coverage vs Model 02 --------------------
cov_games_m02 <- cov_plays_m02 <- NA
if (!is.null(m02)) {
  m02_games <- m02 |> distinct(game_id)
  cov_games_m02 <- setdiff(m02_games$game_id, by_game$game_id)
  cov_plays_m02 <- anti_join(m02, map, by = c("game_id","play_id"))
}

# -------------------- Shares by GAME (gating) and by PLAY (info) --------------------
by_split_games <- by_game %>%
  count(split, name = "games") %>%
  arrange(factor(split, levels = allowed_splits))
n_games <- sum(by_split_games$games)
share_games <- by_split_games %>%
  mutate(share_games = if (n_games>0) games/n_games else NA_real_)

by_split_plays <- map %>%
  group_by(split) %>%
  summarise(plays = n_distinct(play_id), .groups = "drop") %>%
  arrange(factor(split, levels = allowed_splits))
total_plays <- sum(by_split_plays$plays)
share_plays <- by_split_plays %>%
  mutate(share_plays = if (total_plays>0) plays/total_plays else NA_real_)

tol <- if (n_games >= 20) 0.05 else 0.10  # tolerance applies to GAME shares
target <- c(train = 0.70, val = 0.15, test = 0.15)

share_games_ok <- all(sapply(allowed_splits, function(s) {
  if (!(s %in% share_games$split)) return(FALSE)
  abs(share_games$share_games[share_games$split==s] - target[[s]]) <= tol
}))

# each split must exist and have ≥1 GAME (gating)
nonempty_splits_games <- all(sapply(allowed_splits, function(s) {
  if (!(s %in% by_split_games$split)) return(FALSE)
  by_split_games$games[by_split_games$split == s][1] > 0
}))

# -------------------- Reproducibility check (re-derive by the Script 02 rule) --------------------
# NOTE: Script 02 used deterministic shuffle and *cut by play-count*; we mirror that logic here.
repro_ok <- NA
repro_note <- "SKIP (no training inputs found)"
if (!is.null(inputs)) {
  games_ct <- inputs %>% count(game_id, name = "n_plays") %>% arrange(game_id)
  total_plays_in <- sum(games_ct$n_plays)
  if (nrow(games_ct) >= 3) {
    set.seed(2025)
    games_shuf <- games_ct %>% slice_sample(prop = 1)
    target_train <- 0.70 * total_plays_in
    target_val   <- 0.15 * total_plays_in
    cum <- cumsum(games_shuf$n_plays)
    cut_train <- max(which(cum <= target_train))
    cut_val   <- max(which(cum <= (target_train + target_val)))
    cut_train <- max(1, min(cut_train, nrow(games_shuf) - 2))
    cut_val   <- max(cut_train + 1, min(cut_val, nrow(games_shuf) - 1))
    expected <- games_shuf %>%
      mutate(split = case_when(
        row_number() <= cut_train ~ "train",
        row_number() <= cut_val   ~ "val",
        TRUE                      ~ "test"
      )) %>%
      select(game_id, split)
    cmp <- expected %>%
      inner_join(by_game, by = "game_id", suffix = c("_exp","_map"))
    repro_ok <- nrow(cmp) == nrow(expected) && all(cmp$split_exp == cmp$split_map)
    repro_note <- if (isTRUE(repro_ok)) "OK" else "Mismatch vs deterministic rule"
  } else {
    repro_ok <- NA
    repro_note <- "SKIP (need ≥3 games)"
  }
}

# -------------------- Metrics --------------------
metrics <- tibble(
  metric = c(
    "games_total","plays_total",
    "train_games","val_games","test_games",
    "train_plays","val_plays","test_plays",
    "train_share_games","val_share_games","test_share_games",
    "train_share_plays","val_share_plays","test_share_plays",
    "tolerance_used_on_games","reproducibility_checked"
  ),
  value  = c(
    n_games, total_plays,
    by_split_games$games[by_split_games$split=="train"],
    by_split_games$games[by_split_games$split=="val"],
    by_split_games$games[by_split_games$split=="test"],
    by_split_plays$plays[by_split_plays$split=="train"],
    by_split_plays$plays[by_split_plays$split=="val"],
    by_split_plays$plays[by_split_plays$split=="test"],
    share_games$share_games[share_games$split=="train"],
    share_games$share_games[share_games$split=="val"],
    share_games$share_games[share_games$split=="test"],
    share_plays$share_plays[share_plays$split=="train"],
    share_plays$share_plays[share_plays$split=="val"],
    share_plays$share_plays[share_plays$split=="test"],
    tol, ifelse(is.null(inputs), 0, 1)
  )
)
readr::write_csv(metrics, OUT_METRICS)

# -------------------- PASS/FAIL table (gates on BY-GAME checks) --------------------
checks <- tibble::tibble(
  check = c(
    "has_rows",
    "schema_ok_(game_id,play_id,split)",
    "split_values_in_{train,val,test}",
    "no_na_split",
    "unique_game_assignment",
    "no_duplicate_rows_(game_id,play_id,split)",
    "all_input_games_covered_in_map",
    "all_input_plays_covered_in_map",
    "all_model02_games_covered_in_map",
    "shares_by_GAME_within_tolerance",
    "each_split_has_at_least_one_GAME",
    "reproducible_with_seed_2025"
  ),
  status = c(
    pass(has_rows),
    pass(length(miss_map) == 0),
    pass(split_values_valid),
    pass(no_na_split),
    pass(unique_game_assignment),
    pass(no_dup_rows),
    if (is.null(inputs)) skip() else pass(length(cov_games_inputs) == 0),
    if (is.null(inputs)) skip() else pass(nrow(cov_plays_inputs) == 0),
    if (is.null(m02))    skip() else pass(length(cov_games_m02) == 0),
    pass(share_games_ok),
    pass(nonempty_splits_games),
    if (is.na(repro_ok)) skip() else pass(isTRUE(repro_ok))
  ),
  details = c(
    sprintf("rows=%d", nrow(map)),
    "columns present",
    if (split_values_valid) "OK" else paste("bad:", paste(setdiff(unique(map$split), allowed_splits), collapse=",")),
    if (no_na_split) "OK" else sprintf("NA_count=%d", sum(is.na(map$split))),
    "one split per game",
    if (no_dup_rows) "OK" else "duplicate (game_id,play_id,split) rows exist",
    if (is.null(inputs)) "SKIP: no training inputs found" else sprintf("missing_games=%d", length(cov_games_inputs)),
    if (is.null(inputs)) "SKIP: no training inputs found" else sprintf("missing_plays=%d", nrow(cov_plays_inputs)),
    if (is.null(m02))    "SKIP: model02 not found" else sprintf("missing_games=%d", length(cov_games_m02)),
    sprintf("target by GAME 70/15/15 ±%.2f | shares: %s",
            tol, paste(sprintf("%s=%.3f", share_games$split, share_games$share_games), collapse=", ")),
    paste(share_games$split, share_games$games, sep=":", collapse=", "),
    repro_note
  )
)

readr::write_csv(checks, OUT_STATUS_CSV)
writeLines(c("# Split Map Verification — Status", "", md_table(checks)), OUT_STATUS_MD, useBytes = TRUE)

# -------------------- Report --------------------
rep <- c(
  "# Split Map Verification",
  "",
  "## Shares by GAME (gating)",
  sprintf("- train: games=%s (share=%.3f)",
          by_split_games$games[by_split_games$split=="train"],
          share_games$share_games[share_games$split=="train"]),
  sprintf("- val:   games=%s (share=%.3f)",
          by_split_games$games[by_split_games$split=="val"],
          share_games$share_games[share_games$split=="val"]),
  sprintf("- test:  games=%s (share=%.3f)",
          by_split_games$games[by_split_games$split=="test"],
          share_games$share_games[share_games$split=="test"]),
  "",
  "## Shares by PLAY (info only)",
  sprintf("- train: plays=%s (share=%.3f)",
          by_split_plays$plays[by_split_plays$split=="train"],
          share_plays$share_plays[share_plays$split=="train"]),
  sprintf("- val:   plays=%s (share=%.3f)",
          by_split_plays$plays[by_split_plays$split=="val"],
          share_plays$share_plays[share_plays$split=="val"]),
  sprintf("- test:  plays=%s (share=%.3f)",
          by_split_plays$plays[by_split_plays$split=="test"],
          share_plays$share_plays[share_plays$split=="test"]),
  "",
  "## Notes",
  paste0("- Tolerance ±", tol, " applied to GAME shares per spec."),
  "- Repro check mirrors Script 02 (deterministic shuffle, cut by play-count)."
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

# -------------------- Hard stop on FAIL --------------------
if (any(checks$status == "FAIL")) {
  print(checks)
  stop("Split map verification: FAIL. See artifacts/split_map_verification_status.{csv,md}", call. = FALSE)
}
message("Split map verification: PASS.")










# 03_build_model02_contest.R
# Purpose: Build contest dataset + labels for start-of-flight classifier.
# Inputs:
#   - ./train/input_2023_*.csv   (must include: game_id, play_id, nfl_id, frame_id, x, y, s or enough to derive, num_frames_output, ball_land_x, ball_land_y)
#   - ./artifacts/capability_profiles.csv  (from Script 1; must include nfl_id, v_max, a_max)
# Optional:
#   - ./data/splits/plays_split_map.csv (columns: game_id, play_id, split ∈ {train,val,test})
# Outputs:
#   - ./artifacts/model02_contest_dataset_raw.csv
#   - ./artifacts/model02_contest_dataset_final.csv
#   - ./artifacts/model02_contest_dataset_fixed1p0.csv (contest = tight 1.0 yd)
#   - ./artifacts/model02_contest_dataset_fixed1p5.csv (contest = primary 1.5 yd)
# Assumption: The current working directory IS the project root. Do setwd() before running.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(rlang)
})

# -------------------- 1) Config (single source of truth) --------------------
DT <- 0.1            # seconds per frame (10 Hz)
ELIG_THRESHOLD <- 0.05  # minimum max reach-prob to count as "eligible"
R_PRIMARY <- 1.5     # yards, contest at arrival (primary)
R_TIGHT   <- 1.0     # yards, contest at arrival (tight)
SIDELINE_BUF <- 0.5  # yards taken off extreme field quantiles to mark throwaways

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  train     = B("train"),
  artifacts = B("artifacts"),
  splits    = B("data","splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

CAPS_PATH   <- file.path(DIRS$artifacts, "capability_profiles.csv")
SPLIT_PATH  <- file.path(DIRS$splits, "plays_split_map.csv")
OUT_RAW     <- file.path(DIRS$artifacts, "model02_contest_dataset_raw.csv")
OUT_FINAL   <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")
OUT_FIX_10  <- file.path(DIRS$artifacts, "model02_contest_dataset_fixed1p0.csv")
OUT_FIX_15  <- file.path(DIRS$artifacts, "model02_contest_dataset_fixed1p5.csv")

# -------------------- 2) Small helpers --------------------
read_csv_clean <- function(path) readr::read_csv(path, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

rename_if_exists <- function(df, old, new) {
  if (old %in% names(df)) dplyr::rename(df, !!new := .data[[old]]) else df
}

standardize_tracking_cols <- function(df) {
  df <- df |>
    janitor::clean_names() |>
    rename_if_exists("nflid",      "nfl_id") |>
    rename_if_exists("player_id",  "nfl_id") |>
    rename_if_exists("frame",      "frame_id") |>
    rename_if_exists("speed",      "s") |>
    rename_if_exists("accel",      "a")
  df
}

# Maximum reachable distance given current speed v0, a_max, v_max and horizon tau
reach_radius <- function(v0, a_max, v_max, tau) {
  v_cap <- pmin(v0 + a_max * tau, v_max)
  t_acc <- pmax((v_cap - v0) / pmax(a_max, 1e-9), 0)
  t_acc <- pmin(t_acc, tau)
  d_ramp <- v0 * tau + 0.5 * a_max * t_acc^2
  pmin(d_ramp, v_cap * tau)
}

# Smooth probability of reaching, given distance and reach radius
p_reach_fun <- function(distance, r, lambda = 0.7) exp(-lambda * pmax(distance - r, 0))

# -------------------- 3) Load inputs --------------------
if (!file.exists(CAPS_PATH)) stop("Missing capability profiles: ", CAPS_PATH, call. = FALSE)

caps <- read_csv_clean(CAPS_PATH)
# Accept either 'nfl_id' or 'player_id' from Script 1 variants; coerce to integer IDs
if (!("nfl_id" %in% names(caps)) && ("player_id" %in% names(caps))) {
  caps <- caps |> dplyr::rename(nfl_id = player_id)
}
req_caps <- c("nfl_id","v_max","a_max")
miss_caps <- setdiff(req_caps, names(caps))
if (length(miss_caps)) stop("capability_profiles.csv missing columns: ", paste(miss_caps, collapse=", "), call. = FALSE)

caps <- caps |>
  mutate(
    nfl_id = suppressWarnings(as.integer(nfl_id)),
    v_max = as.numeric(v_max),
    a_max = as.numeric(a_max),
    # reasonable fallbacks if Script 1 left some NA
    v_max = ifelse(is.na(v_max) | v_max <= 0, 8, v_max),
    a_max = ifelse(is.na(a_max) | a_max <= 0, 4, a_max)
  ) |>
  distinct(nfl_id, .keep_all = TRUE)

in_files <- Sys.glob(file.path(DIRS$train, "input_2023_*.csv"))
if (!length(in_files)) stop("No input_2023_*.csv files found in ", DIRS$train, call. = FALSE)

inputs <- purrr::map_dfr(in_files, read_csv_clean) |>
  standardize_tracking_cols() |>
  mutate(
    game_id  = as.character(game_id),
    play_id  = suppressWarnings(as.integer(play_id)),
    frame_id = suppressWarnings(as.integer(frame_id)),
    nfl_id   = suppressWarnings(as.integer(nfl_id)),
    x = as.numeric(x), y = as.numeric(y),
    s = as.numeric(s),
    num_frames_output = as.numeric(num_frames_output),
    ball_land_x = as.numeric(ball_land_x),
    ball_land_y = as.numeric(ball_land_y)
  )

req_inputs <- c("game_id","play_id","nfl_id","frame_id","x","y","num_frames_output","ball_land_x","ball_land_y")
miss_inputs <- setdiff(req_inputs, names(inputs))
if (length(miss_inputs)) stop("Training inputs missing columns: ", paste(miss_inputs, collapse=", "), call. = FALSE)

# Optional split map by game (no leakage across games)
split_tbl <- if (file.exists(SPLIT_PATH)) {
  read_csv_clean(SPLIT_PATH) |>
    mutate(game_id = as.character(game_id),
           play_id = suppressWarnings(as.integer(play_id)),
           split   = tolower(as.character(split))) |>
    distinct(game_id, play_id, split)
} else {
  tibble(game_id = unique(inputs$game_id), play_id = NA_integer_, split = "unknown")
}

# -------------------- 4) Define pass windows per play --------------------
# We rely on num_frames_output and ball landing coords already included in input_*.csv
windows <- inputs |>
  group_by(game_id, play_id) |>
  summarise(
    t1     = suppressWarnings(max(frame_id, na.rm = TRUE)),            # last frame of window
    num    = suppressWarnings(max(num_frames_output, na.rm = TRUE)),   # window length in frames
    x_land = suppressWarnings(max(ball_land_x, na.rm = TRUE)),
    y_land = suppressWarnings(max(ball_land_y, na.rm = TRUE)),
    .groups = "drop"
  ) |>
  mutate(t0 = t1 - num + 1) |>
  filter(is.finite(t0), is.finite(t1), t1 >= t0)

if (!nrow(windows)) {
  readr::write_csv(tibble(), OUT_RAW)
  readr::write_csv(tibble(), OUT_FINAL)
  message("Model 02: no windows formed. Wrote empty outputs.")
  quit(save = "no")
}

# -------------------- 5) Defender tracks + capability join --------------------
# Prefer explicit defensive filter if provided
players <- if ("player_side" %in% names(inputs)) {
  inputs |> filter(tolower(player_side) == "defense")
} else if ("player_role" %in% names(inputs)) {
  inputs |> filter(grepl("defensive", tolower(player_role)))
} else {
  inputs
}

players <- players |>
  select(game_id, play_id, frame_id, nfl_id, x, y, s) |>
  arrange(game_id, play_id, nfl_id, frame_id)

# Derive speed if column missing or NA-heavy
if (!("s" %in% names(players)) || all(is.na(players$s))) {
  players <- players |>
    group_by(game_id, play_id, nfl_id) |>
    mutate(
      dx = x - dplyr::lag(x),
      dy = y - dplyr::lag(y),
      s  = sqrt((dx/DT)^2 + (dy/DT)^2)
    ) |>
    ungroup()
}

players <- players |>
  inner_join(caps, by = "nfl_id")

# -------------------- 6) Frame-level reach and distances --------------------
pv <- players |>
  inner_join(windows, by = c("game_id","play_id")) |>
  filter(frame_id >= t0, frame_id <= t1) |>
  mutate(
    tau = pmax((t1 - frame_id) * DT, 0),
    d_to_land = sqrt((x_land - x)^2 + (y_land - y)^2),
    r = reach_radius(pmax(s, 0), a_max, v_max, tau),
    p_reach = p_reach_fun(d_to_land, r)
  )

# -------------------- 7) Collapse to defender-play rows --------------------
per_def_play <- pv |>
  group_by(game_id, play_id, nfl_id) |>
  summarise(
    p_reach_max = suppressWarnings(max(p_reach, na.rm = TRUE)),
    d_min       = suppressWarnings(min(d_to_land, na.rm = TRUE)),
    .groups = "drop"
  )

start_of_flight <- pv |>
  group_by(game_id, play_id, nfl_id) |>
  slice_min(abs(frame_id - first(t0)), n = 1, with_ties = FALSE) |>
  ungroup() |>
  transmute(game_id, play_id, nfl_id,
            p_reach_start = p_reach,
            d_start       = d_to_land)

arrival <- players |>
  inner_join(windows |> select(game_id, play_id, t1, x_land, y_land), by = c("game_id","play_id")) |>
  filter(frame_id == t1) |>
  transmute(game_id, play_id, nfl_id,
            d_arrival = sqrt((x_land - x)^2 + (y_land - y)^2))

ds_raw <- per_def_play |>
  left_join(start_of_flight, by = c("game_id","play_id","nfl_id")) |>
  left_join(arrival,        by = c("game_id","play_id","nfl_id")) |>
  mutate(
    eligible = p_reach_max >= ELIG_THRESHOLD
  ) |>
  left_join(split_tbl |> distinct(game_id, split), by = "game_id")

# -------------------- 8) Throwaway detection (landing out of bounds) --------------------
bounds <- inputs |>
  summarise(
    x_min = quantile(x, 0.005, na.rm = TRUE),
    x_max = quantile(x, 0.995, na.rm = TRUE),
    y_min = quantile(y, 0.005, na.rm = TRUE),
    y_max = quantile(y, 0.995, na.rm = TRUE)
  )
x_lo <- bounds$x_min + SIDELINE_BUF; x_hi <- bounds$x_max - SIDELINE_BUF
y_lo <- bounds$y_min + SIDELINE_BUF; y_hi <- bounds$y_max - SIDELINE_BUF

land <- windows |> select(game_id, play_id, x_land, y_land)

ds_raw <- ds_raw |>
  left_join(land, by = c("game_id","play_id")) |>
  mutate(
    oob_landing = is.finite(x_land) & is.finite(y_land) &
      (x_land < x_lo | x_land > x_hi | y_land < y_lo | y_land > y_hi),
    throwaway   = oob_landing
  ) |>
  select(-x_land, -y_land)

readr::write_csv(ds_raw, OUT_RAW)

# -------------------- 9) Final labels and convenience exports --------------------
ds_final <- ds_raw |>
  mutate(
    contest_primary = (!throwaway) & eligible & is.finite(d_arrival) & d_arrival <= R_PRIMARY,
    contest_tight   = (!throwaway) & eligible & is.finite(d_arrival) & d_arrival <= R_TIGHT
  )

readr::write_csv(ds_final, OUT_FINAL)

readr::write_csv(
  ds_final %>% mutate(contest = contest_tight) %>% select(-contest_primary, -contest_tight),
  OUT_FIX_10
)

readr::write_csv(
  ds_final %>% mutate(contest = contest_primary) %>% select(-contest_primary, -contest_tight),
  OUT_FIX_15
)

# -------------------- 10) Console audit --------------------
aud <- ds_final |>
  summarise(
    plays               = dplyr::n_distinct(paste(game_id, play_id)),
    defenders           = dplyr::n_distinct(nfl_id),
    eligible_rate       = mean(eligible, na.rm = TRUE),
    contest_rate_primary= mean(contest_primary, na.rm = TRUE),
    contest_rate_tight  = mean(contest_tight,   na.rm = TRUE),
    throwaway_rate      = mean(throwaway, na.rm = TRUE)
  )
print(aud)

message("Wrote:",
        "\n  - ", OUT_RAW,
        "\n  - ", OUT_FINAL,
        "\n  - ", OUT_FIX_10,
        "\n  - ", OUT_FIX_15,
        "\nDone.")

# End of 03_build_model02_contest.R










# 04_verify_foundation.R
# Purpose: Verify Script 1 (capability profiles) and Script 2 (contest dataset).
# Inputs:
#   artifacts/capability_profiles.csv
#   artifacts/model02_contest_dataset_final.csv
# Optional:
#   data/splits/plays_split_map.csv  (game_id-level split map)
# Outputs:
#   artifacts/model01_metrics.csv, artifacts/model01_report.md
#   artifacts/model02_metrics.csv, artifacts/model02_report.md
# Root: current working dir is the project root. Run setwd() before sourcing.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  artifacts = B("artifacts"),
  splits    = B("data","splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_CAPS   <- file.path(DIRS$artifacts, "capability_profiles.csv")
PATH_M02    <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")
PATH_SPLITS <- file.path(DIRS$splits, "plays_split_map.csv")

# -------------------- 1) Helpers --------------------
read_csv_clean <- function(path) readr::read_csv(path, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

rng <- function(x) {
  if (length(x) == 0 || all(is.na(x))) return(c(NA_real_, NA_real_))
  c(suppressWarnings(min(x, na.rm = TRUE)), suppressWarnings(max(x, na.rm = TRUE)))
}
flag_out_range <- function(x, lo, hi) {
  any(is.finite(x) & (x < lo | x > hi), na.rm = TRUE)
}

write_lines <- function(lines, path) {
  dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)
  writeLines(lines, path, useBytes = TRUE)
}

# -------------------- 2) Load inputs --------------------
if (!file.exists(PATH_CAPS)) stop("Missing artifact from Script 1: ", PATH_CAPS, call. = FALSE)
if (!file.exists(PATH_M02))  stop("Missing artifact from Script 2: ", PATH_M02,  call. = FALSE)

caps <- read_csv_clean(PATH_CAPS) |>
  mutate(
    nfl_id = suppressWarnings(as.integer(nfl_id)),
    v_max = as.numeric(v_max),
    a_max = as.numeric(a_max),
    turn_rate_p95 = as.numeric(turn_rate_p95),
    n_frames_used = suppressWarnings(as.integer(n_frames_used))
  )

m02 <- read_csv_clean(PATH_M02) |>
  mutate(
    game_id  = as.character(game_id),
    play_id  = suppressWarnings(as.integer(play_id)),
    nfl_id   = suppressWarnings(as.integer(nfl_id))
  )

splits <- if (file.exists(PATH_SPLITS)) {
  read_csv_clean(PATH_SPLITS) |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      split   = tolower(as.character(split))
    ) |>
    distinct(game_id, split)
} else {
  tibble(game_id = character(), split = character())
}

# -------------------- 3) Verify Model 01: capability profiles --------------------
req_caps <- c("nfl_id","v_max","a_max","turn_rate_p95","n_frames_used")
miss_caps <- setdiff(req_caps, names(caps))
if (length(miss_caps)) stop("capability_profiles.csv missing columns: ", paste(miss_caps, collapse=", "), call. = FALSE)

# Uniqueness and NA checks
dup_caps <- caps |> count(nfl_id) |> filter(n > 1)
if (nrow(dup_caps)) stop("Duplicate nfl_id in capability_profiles.csv")

n_players <- n_distinct(caps$nfl_id)
non_na_v  <- sum(!is.na(caps$v_max))
non_na_a  <- sum(!is.na(caps$a_max))
non_na_t  <- sum(!is.na(caps$turn_rate_p95))

v_rng <- rng(caps$v_max)
a_rng <- rng(caps$a_max)
t_rng <- rng(caps$turn_rate_p95)

v_out <- flag_out_range(caps$v_max, 4, 12)
a_out <- flag_out_range(caps$a_max, 0, 8)
t_out <- flag_out_range(caps$turn_rate_p95, 0, 1000)

low_frames_50  <- mean(caps$n_frames_used < 50,  na.rm = TRUE)
low_frames_100 <- mean(caps$n_frames_used < 100, na.rm = TRUE)
low_frames_500 <- mean(caps$n_frames_used < 500, na.rm = TRUE)

m01_metrics <- tibble(
  metric = c(
    "players","non_na_v_max","non_na_a_max","non_na_turn_rate_p95",
    "v_max_min","v_max_max","a_max_min","a_max_max","turn_p95_min","turn_p95_max",
    "v_max_out_of_plausible_[4,12]",
    "a_max_out_of_plausible_[0,8]",
    "turn_rate_p95_out_of_plausible_[0,1000]",
    "frac_n_frames_used_<50",
    "frac_n_frames_used_<100",
    "frac_n_frames_used_<500"
  ),
  value = c(
    n_players, non_na_v, non_na_a, non_na_t,
    v_rng[1], v_rng[2], a_rng[1], a_rng[2], t_rng[1], t_rng[2],
    as.numeric(v_out), as.numeric(a_out), as.numeric(t_out),
    low_frames_50, low_frames_100, low_frames_500
  )
)

readr::write_csv(m01_metrics, file.path(DIRS$artifacts, "model01_metrics.csv"))

m01_report <- c(
  "# Model 01 Verification",
  "",
  sprintf("- Players: %d", n_players),
  sprintf("- Non-missing: v_max=%d, a_max=%d, turn_rate_p95=%d", non_na_v, non_na_a, non_na_t),
  sprintf("- v_max range: [%s, %s] (plausible 4..12 m/s) %s",
          signif(v_rng[1],3), signif(v_rng[2],3), if (v_out) "⚠ out-of-range values present" else "OK"),
  sprintf("- a_max range: [%s, %s] (plausible 0..8 m/s^2) %s",
          signif(a_rng[1],3), signif(a_rng[2],3), if (a_out) "⚠ out-of-range values present" else "OK"),
  sprintf("- turn_rate_p95 range: [%s, %s] (plausible 0..1000 deg/s) %s",
          signif(t_rng[1],3), signif(t_rng[2],3), if (t_out) "⚠ out-of-range values present" else "OK"),
  sprintf("- Sample size risk: frames_used<50: %.3f, <100: %.3f, <500: %.3f",
          low_frames_50, low_frames_100, low_frames_500),
  "",
  if (nrow(dup_caps)) "⚠ Duplicate nfl_id rows found (should be none)." else "Uniqueness: OK"
)
write_lines(m01_report, file.path(DIRS$artifacts, "model01_report.md"))

message("[Model 01] Wrote metrics + report.")

# -------------------- 4) Verify Model 02: contest dataset --------------------
req_m02 <- c("game_id","play_id","nfl_id","eligible","throwaway","d_arrival","contest_primary","contest_tight")
miss_m02 <- setdiff(req_m02, names(m02))
if (length(miss_m02)) stop("model02_contest_dataset_final.csv missing columns: ", paste(miss_m02, collapse=", "), call. = FALSE)

# Key uniqueness: one row per defender-play
dup_m02 <- m02 |> count(game_id, play_id, nfl_id, name = "n") |> filter(n != 1)
if (nrow(dup_m02)) stop("Duplicate or zero rows for some (game_id, play_id, nfl_id) keys in Model 02 dataset.")

# Basic rates overall
plays_total <- n_distinct(paste(m02$game_id, m02$play_id))
def_total   <- n_distinct(m02$nfl_id)
rows_total  <- nrow(m02)

eligible_rate <- mean(m02$eligible, na.rm = TRUE)
throw_rate    <- mean(m02$throwaway, na.rm = TRUE)
cp_rate       <- mean(m02$contest_primary, na.rm = TRUE)
ct_rate       <- mean(m02$contest_tight,   na.rm = TRUE)

arrival_na_rate <- mean(is.na(m02$d_arrival))
arrival_neg     <- any(is.finite(m02$d_arrival) & m02$d_arrival < 0, na.rm = TRUE)

# Split integrity (if split map provided)
split_leak_note <- "Split map not provided; skipped leak check."
if (nrow(splits)) {
  # each game_id should appear in exactly one split
  leak <- splits |> count(game_id) |> filter(n != 1)
  if (nrow(leak)) stop("Split leakage: some game_id appear in multiple splits in plays_split_map.csv")
  # if dataset includes split column, check consistency against map
  if ("split" %in% names(m02)) {
    split_mismatch <- m02 |>
      distinct(game_id, split) |>
      left_join(splits, by = "game_id", suffix = c("_ds","_map")) |>
      mutate(match = is.na(split_map) | split_ds == split_map) |>
      filter(!match)
    if (nrow(split_mismatch)) stop("Split mismatch between dataset and split map for some game_ids.")
    split_leak_note <- "Split integrity: OK"
  } else {
    split_leak_note <- "Dataset has no split column; verified map itself only (OK)."
  }
}

# Per-split rates if split column present
rate_by_split <- if ("split" %in% names(m02)) {
  m02 |>
    mutate(split = tolower(as.character(split))) |>
    group_by(split) |>
    summarise(
      rows = n(),
      plays = n_distinct(paste(game_id, play_id)),
      eligible_rate = mean(eligible, na.rm = TRUE),
      throwaway_rate = mean(throwaway, na.rm = TRUE),
      contest_primary_rate = mean(contest_primary, na.rm = TRUE),
      contest_tight_rate   = mean(contest_tight,   na.rm = TRUE),
      .groups = "drop"
    )
} else {
  tibble()
}

# Write metrics
m02_metrics <- tibble(
  metric = c("rows","plays","defenders","eligible_rate","throwaway_rate","contest_primary_rate","contest_tight_rate","arrival_distance_na_rate","any_negative_arrival_distance"),
  value  = c(rows_total, plays_total, def_total, eligible_rate, throw_rate, cp_rate, ct_rate, arrival_na_rate, as.numeric(arrival_neg))
)

readr::write_csv(m02_metrics, file.path(DIRS$artifacts, "model02_metrics.csv"))
if (nrow(rate_by_split)) {
  readr::write_csv(rate_by_split, file.path(DIRS$artifacts, "model02_metrics_by_split.csv"))
}

# Write report
m02_report <- c(
  "# Model 02 Verification",
  "",
  sprintf("- Rows: %s | Plays: %s | Defenders: %s", comma(rows_total), comma(plays_total), comma(def_total)),
  sprintf("- Eligible rate: %.4f | Throwaway rate: %.4f", eligible_rate, throw_rate),
  sprintf("- Contest rates: primary=%.4f | tight=%.4f", cp_rate, ct_rate),
  sprintf("- d_arrival NA rate: %.4f%s", arrival_na_rate, if (arrival_neg) " | ⚠ negative values present" else ""),
  sprintf("- %s", split_leak_note),
  "",
  if (nrow(rate_by_split)) "## By split" else NULL
)

if (nrow(rate_by_split)) {
  split_lines <- rate_by_split |>
    mutate(line = sprintf("- %s: rows=%s, plays=%s, eligible=%.4f, throwaway=%.4f, primary=%.4f, tight=%.4f",
                          split, comma(rows), comma(plays), eligible_rate, throwaway_rate, contest_primary_rate, contest_tight_rate)) |>
    pull(line)
  m02_report <- c(m02_report, split_lines)
}

write_lines(m02_report, file.path(DIRS$artifacts, "model02_report.md"))

message("[Model 02] Wrote metrics + report.")
message("Verification complete.")


# -------------------- 5) PASS/FAIL tables (append-only) --------------------
# Helper to label
.pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
.skip <- function() "SKIP"

# Simple markdown table formatter to avoid extra deps
.md_table <- function(df) {
  hdr <- paste("|", paste(names(df), collapse = " | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse = " | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse = " | "), "|"))
  c(hdr, sep, rows)
}

