# 05_train_model03_classifier.R
# Purpose: Train start-of-flight contest classifier (Model 03) for both thresholds:
#          - Primary: 1.5 yd  (label = contest_primary)
#          - Backup:  1.0 yd  (label = contest_tight)
# Inputs:
#   - ./artifacts/model02_contest_dataset_final.csv
#   - ./artifacts/capability_profiles.csv
#   - ./data/splits/plays_split_map.csv
# Outputs (primary, no suffix):
#   - ./artifacts/model03_model_rds.rds
#   - ./artifacts/model03_calibration_glm.rds  (if calibration fitted)
#   - ./artifacts/model03_val_preds.csv
#   - ./artifacts/model03_test_preds.csv
#   - ./artifacts/model03_metrics.csv
#   - ./artifacts/model03_report.md
# Outputs (backup, suffix _1p0):
#   - ./artifacts/model03_model_rds_1p0.rds
#   - ./artifacts/model03_calibration_glm_1p0.rds (if calibration fitted)
#   - ./artifacts/model03_val_preds_1p0.csv
#   - ./artifacts/model03_test_preds_1p0.csv
#   - ./artifacts/model03_metrics_1p0.csv
#   - ./artifacts/model03_report_1p0.md
# Assumption: current working directory is the project root.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) install.packages(need, quiet = TRUE)
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","purrr","tibble","scales","ranger","pROC","rlang"))

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  artifacts = B("artifacts"),
  splits    = B("data","splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_DS   <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")
PATH_CAPS <- file.path(DIRS$artifacts, "capability_profiles.csv")
PATH_MAP  <- file.path(DIRS$splits,   "plays_split_map.csv")

# -------------------- 1) Load data --------------------
req <- function(path, name){
  if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE)
}
req(PATH_DS,   "model02_contest_dataset_final.csv")
req(PATH_CAPS, "capability_profiles.csv")
req(PATH_MAP,  "plays_split_map.csv")

read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

ds <- read_csv_clean(PATH_DS) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id))
  )

caps <- read_csv_clean(PATH_CAPS) |>
  transmute(
    nfl_id = suppressWarnings(as.integer(nfl_id)),
    v_max  = as.numeric(v_max),
    a_max  = as.numeric(a_max)
  ) |>
  distinct(nfl_id, .keep_all = TRUE)

splits <- read_csv_clean(PATH_MAP) |>
  transmute(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    split   = tolower(as.character(split))
  ) |>
  distinct(game_id, play_id, split)

# Force split from map (overwrite any split column in ds)
ds <- ds |>
  select(-any_of("split")) |>
  left_join(splits, by = c("game_id","play_id"))

# -------------------- 2) Keep only usable rows and join caps --------------------
req_cols <- c("p_reach_start","d_start","p_reach_max","d_min","d_arrival","eligible","throwaway","contest_primary","contest_tight")
miss <- setdiff(req_cols, names(ds))
if (length(miss)) stop("Dataset missing expected columns: ", paste(miss, collapse=", "), call. = FALSE)

ds_use <- ds |>
  filter(eligible, !throwaway) |>
  left_join(caps, by = "nfl_id")

# -------------------- 3) Feature assembly + split frames --------------------
feat_cols <- c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")

base_train <- ds_use |> filter(split == "train") |> select(all_of(feat_cols))
base_val   <- ds_use |> filter(split == "val")   |> select(all_of(feat_cols))
base_test  <- ds_use |> filter(split == "test")  |> select(all_of(feat_cols))
if (nrow(base_train) == 0 || nrow(base_val) == 0 || nrow(base_test) == 0) {
  stop("One of the splits has zero rows after filtering eligible & non-throwaway. Check data/splits.", call. = FALSE)
}

# Median imputer learned on TRAIN only (reused for both labels)
meds <- base_train |> summarise(across(everything(), ~ suppressWarnings(median(.x, na.rm = TRUE))))
impute_median <- function(df, meds_row){
  nm <- intersect(names(meds_row), names(df))
  for (v in nm) df[[v]][is.na(df[[v]])] <- meds_row[[v]][1]
  df
}

# -------------------- 4) Utilities --------------------
clip <- function(p, eps = 1e-6) pmin(pmax(p, eps), 1 - eps)
logit <- function(p) log(clip(p) / (1 - clip(p)))
to_factor <- function(x) factor(ifelse(x, "yes", "no"), levels = c("no","yes"))
get_p_yes <- function(pred) {
  if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"yes"]) else as.numeric(pred$predictions)
}
logloss <- function(y, p) -mean(y * log(clip(p)) + (1 - y) * log(1 - clip(p)))
brier <- function(y, p) mean((p - y)^2)
ece <- function(y, p, bins = 10) {
  b <- cut(p, breaks = seq(0,1,length.out=bins+1), include.lowest = TRUE, labels = FALSE)
  n <- length(y); e <- 0
  for (i in 1:bins) {
    idx <- which(b == i); if (!length(idx)) next
    p_bar <- mean(p[idx]); y_bar <- mean(y[idx])
    e <- e + (length(idx)/n) * abs(p_bar - y_bar)
  }
  e
}
sweep_thresholds <- function(y_true, p, by = 0.01) {
  ths <- seq(0, 1, by = by)
  f1 <- precision <- recall <- numeric(length(ths))
  for (i in seq_along(ths)) {
    t <- ths[i]; pred <- as.integer(p >= t)
    tp <- sum(pred==1 & y_true==1); fp <- sum(pred==1 & y_true==0); fn <- sum(pred==0 & y_true==1)
    precision[i] <- if ((tp+fp)==0) 0 else tp/(tp+fp)
    recall[i]    <- if ((tp+fn)==0) 0 else tp/(tp+fn)
    f1[i]        <- if ((precision[i]+recall[i])==0) 0 else 2*precision[i]*recall[i]/(precision[i]+recall[i])
  }
  i_best <- which.max(f1)
  list(th = ths[i_best], f1 = f1[i_best], precision = precision[i_best], recall = recall[i_best])
}

train_one <- function(LABEL, suffix = NULL) {
  cols <- c("game_id","play_id","nfl_id", LABEL, feat_cols)
  tr <- ds_use |> filter(split=="train") |> select(all_of(cols))
  va <- ds_use |> filter(split=="val")   |> select(all_of(cols))
  te <- ds_use |> filter(split=="test")  |> select(all_of(cols))
  if (nrow(tr)==0 || nrow(va)==0 || nrow(te)==0) stop("Split has zero rows for label: ", LABEL, call. = FALSE)
  
  tr <- impute_median(tr, meds); va <- impute_median(va, meds); te <- impute_median(te, meds)
  
  # Build training frame without using the magrittr dot
  rf_train <- tr |>
    dplyr::transmute(
      y = to_factor(.data[[LABEL]]),
      dplyr::across(all_of(feat_cols))
    )
  
  set.seed(2025)
  rf_fit <- ranger::ranger(
    y ~ ., data = rf_train,
    num.trees = 500, mtry = max(1, floor(sqrt(length(feat_cols)))),
    min.node.size = 10, probability = TRUE, respect.unordered.factors = TRUE, seed = 2025
  )
  
  # Predict raw probabilities
  p_raw_tr <- get_p_yes(predict(rf_fit, data = tr[, feat_cols, drop = FALSE]))
  p_raw_va <- get_p_yes(predict(rf_fit, data = va[, feat_cols, drop = FALSE]))
  p_raw_te <- get_p_yes(predict(rf_fit, data = te[, feat_cols, drop = FALSE]))
  
  # Platt calibration on validation
  y_tr <- as.integer(tr[[LABEL]]); y_va <- as.integer(va[[LABEL]]); y_te <- as.integer(te[[LABEL]])
  calib_glm <- NULL
  if (length(unique(y_va)) >= 2) {
    calib_glm <- glm(y ~ l, data = data.frame(y = y_va, l = logit(p_raw_va)), family = binomial())
    p_cal_tr <- predict(calib_glm, newdata = data.frame(l = logit(p_raw_tr)), type = "response")
    p_cal_va <- predict(calib_glm, newdata = data.frame(l = logit(p_raw_va)), type = "response")
    p_cal_te <- predict(calib_glm, newdata = data.frame(l = logit(p_raw_te)), type = "response")
  } else {
    warning("Validation split has a single class for label ", LABEL, "; using uncalibrated probabilities.")
    p_cal_tr <- p_raw_tr; p_cal_va <- p_raw_va; p_cal_te <- p_raw_te
  }
  
  # Threshold selection on validation
  sel <- sweep_thresholds(y_va, p_cal_va, by = 0.01)
  best_th <- sel$th
  
  # Metrics
  auc_va  <- as.numeric(pROC::roc(y_va,  p_cal_va, quiet = TRUE)$auc)
  auc_te  <- as.numeric(pROC::roc(y_te,  p_cal_te, quiet = TRUE)$auc)
  metrics <- tibble::tibble(
    metric = c("label","auc_val","auc_test","logloss_val","logloss_test","brier_val","brier_test","ece_val","ece_test",
               "val_best_threshold","val_best_f1","val_best_precision","val_best_recall",
               "train_rows","val_rows","test_rows"),
    value  = c(LABEL, auc_va, auc_te,
               logloss(y_va, p_cal_va), logloss(y_te, p_cal_te),
               brier(y_va,   p_cal_va), brier(y_te,  p_cal_te),
               ece(y_va,     p_cal_va), ece(y_te,    p_cal_te),
               best_th, sel$f1, sel$precision, sel$recall,
               nrow(tr), nrow(va), nrow(te))
  )
  
  # Output paths
  suf <- if (is.null(suffix) || suffix=="") "" else paste0("_", suffix)
  OUT_MODEL   <- file.path(DIRS$artifacts, paste0("model03_model_rds", suf, ".rds"))
  OUT_CALIB   <- file.path(DIRS$artifacts, paste0("model03_calibration_glm", suf, ".rds"))
  OUT_VAL     <- file.path(DIRS$artifacts, paste0("model03_val_preds", suf, ".csv"))
  OUT_TEST    <- file.path(DIRS$artifacts, paste0("model03_test_preds", suf, ".csv"))
  OUT_METRICS <- file.path(DIRS$artifacts, paste0("model03_metrics",   suf, ".csv"))
  OUT_REPORT  <- file.path(DIRS$artifacts, paste0("model03_report",    suf, ".md"))
  
  # Save artifacts
  saveRDS(list(
    model = rf_fit,
    features = feat_cols,
    medians = meds,
    label = LABEL,
    threshold = best_th,
    seed = 2025
  ), OUT_MODEL)
  if (!is.null(calib_glm)) saveRDS(calib_glm, OUT_CALIB)
  
  val_preds <- va |> transmute(game_id, play_id, nfl_id, y = y_va, p_raw = p_raw_va, p_cal = p_cal_va)
  test_preds<- te |> transmute(game_id, play_id, nfl_id, y = y_te, p_raw = p_raw_te, p_cal = p_cal_te)
  readr::write_csv(val_preds, OUT_VAL)
  readr::write_csv(test_preds, OUT_TEST)
  readr::write_csv(metrics,   OUT_METRICS)
  
  rep_lines <- c(
    paste0("# Model 03 — ", LABEL, if (suf=="") " (primary 1.5 yd)" else " (backup 1.0 yd)"),
    "",
    paste0("Train rows: ", nrow(tr), " | Val rows: ", nrow(va), " | Test rows: ", nrow(te)),
    "Features: p_reach_start, d_start, p_reach_max, d_min, v_max, a_max",
    "Algorithm: ranger random forest (500 trees) with Platt calibration",
    paste0("AUC: val=", signif(auc_va,3), " | test=", signif(auc_te,3)),
    paste0("Threshold (val F1): ", signif(best_th,3),
           " | F1=", signif(sel$f1,3),
           " | P=", signif(sel$precision,3),
           " | R=", signif(sel$recall,3)),
    "Files:",
    paste0("- ", basename(OUT_MODEL)),
    if (!is.null(calib_glm)) paste0("- ", basename(OUT_CALIB)) else "- (no calibration file; identity used)",
    paste0("- ", basename(OUT_VAL)),
    paste0("- ", basename(OUT_TEST)),
    paste0("- ", basename(OUT_METRICS))
  )
  writeLines(rep_lines, OUT_REPORT, useBytes = TRUE)
  
  message("Wrote: ",
          "\n  - ", OUT_MODEL,
          if (!is.null(calib_glm)) paste0("\n  - ", OUT_CALIB) else "\n  - (no calibration file; identity used)",
          "\n  - ", OUT_VAL,
          "\n  - ", OUT_TEST,
          "\n  - ", OUT_METRICS,
          "\n  - ", OUT_REPORT)
}

# -------------------- 5) Train both models --------------------
train_one("contest_primary", suffix = "")   # Primary: 1.5 yd
train_one("contest_tight",  suffix = "1p0") # Backup:  1.0 yd

message("Done. Primary (1.5 yd) and backup (1.0 yd) models trained and exported.")










# 05a_model03_verification.R
# What it does:
# Verifies Model 03 (contest classifier, primary 1.5 yd) by reproducing calibrated probabilities on val/test.
# It loads the saved model + (optional) calibration, rebuilds the exact feature frame with saved medians,
# computes AUC/Brier/LogLoss/ECE and calibration slope/intercept, sanity-checks the threshold, and emits PASS/FAIL.
# Conventions: project root is the working dir; writes to artifacts/*. Stops on FAIL after writing status.

suppressWarnings(suppressMessages({
  if (!requireNamespace("utils", quietly = TRUE)) stop("utils not available")
  if (!requireNamespace("stats", quietly = TRUE)) stop("stats not available")
}))

# -------------------------- small utils --------------------------
ts_iso <- function() format(Sys.time(), "%Y-%m-%dT%H:%M:%S%z")
add_row <- function(tbl, check, status, details) {
  rbind(tbl, data.frame(check=as.character(check), status=as.character(status),
                        details=as.character(details), timestamp=ts_iso(), stringsAsFactors=FALSE))
}
md_escape <- function(x) gsub("\\|","\\\\|",as.character(x))

write_status <- function(df, overall) {
  dir.create("artifacts", showWarnings=FALSE, recursive=TRUE)
  utils::write.csv(df, "artifacts/model03_model_verification_status.csv", row.names=FALSE)
  lines <- c(sprintf("# Model 03 Verification — %s", overall), "",
             sprintf("_Generated: %s_", ts_iso()), "",
             "| check | status | details | timestamp |", "|---|---|---|---|")
  if (nrow(df)==0) {
    lines <- c(lines, "| No checks recorded | FAIL | Empty table | |")
  } else {
    for (i in seq_len(nrow(df))) {
      lines <- c(lines, sprintf("| %s | %s | %s | %s |",
                                md_escape(df$check[i]), md_escape(df$status[i]),
                                md_escape(df$details[i]), md_escape(df$timestamp[i])))
    }
  }
  cat(paste0(paste(lines, collapse="\n"), "\n"), file="artifacts/model03_model_verification_status.md")
}

write_report <- function(lines) {
  dir.create("artifacts", showWarnings=FALSE, recursive=TRUE)
  cat(paste0(paste(lines, collapse="\n"), "\n"), file="artifacts/model03_model_verification_report.md")
}
write_debug <- function(lines) {
  dir.create("artifacts", showWarnings=FALSE, recursive=TRUE)
  cat(paste0(paste(lines, collapse="\n"), "\n"), file="artifacts/model03_model_verification_debug.md")
}

safe_read_csv <- function(path) utils::read.csv(path, stringsAsFactors=FALSE, check.names=FALSE)
safe_readRDS  <- function(path) tryCatch(readRDS(path), error=function(e) stop(sprintf("Failed to read RDS at %s: %s", path, conditionMessage(e))))

# -------------------------- metrics (NA-safe) --------------------------
auc_mw <- function(y, p) {
  y <- as.integer(y); p <- as.numeric(p)
  ok <- is.finite(y) & !is.na(y) & is.finite(p) & !is.na(p)
  y <- y[ok]; p <- p[ok]
  if (!length(y)) return(NA_real_)
  n1 <- sum(y == 1, na.rm = TRUE)
  n0 <- sum(y == 0, na.rm = TRUE)
  if (n1 == 0 || n0 == 0) return(NA_real_)
  r <- rank(p, ties.method = "average")
  (sum(r[y == 1], na.rm = TRUE) - n1 * (n1 + 1) / 2) / (n1 * n0)
}
brier <- function(y, p) {
  y <- as.numeric(y); p <- as.numeric(p)
  ok <- is.finite(y) & is.finite(p)
  if (!any(ok)) return(NA_real_)
  y <- y[ok]; p <- p[ok]
  mean((p - y)^2)
}
logloss <- function(y, p) {
  y <- as.numeric(y); p <- as.numeric(p)
  ok <- is.finite(y) & is.finite(p)
  if (!any(ok)) return(NA_real_)
  y <- y[ok]; p <- p[ok]
  eps <- 1e-12
  p <- pmin(pmax(p, eps), 1 - eps)
  -mean(y * log(p) + (1 - y) * log(1 - p))
}
ece20 <- function(y, p, bins = 20L) {
  y <- as.numeric(y); p <- as.numeric(p)
  ok <- is.finite(y) & is.finite(p)
  y <- y[ok]; p <- p[ok]
  if (!length(y)) return(NA_real_)
  cutp <- cut(p, breaks = seq(0, 1, length.out = bins + 1L), include.lowest = TRUE)
  tb <- table(cutp)
  e <- tapply(p, cutp, mean)
  a <- tapply(y, cutp, mean)
  w <- as.numeric(tb) / length(p)
  sum(w * abs(a - e), na.rm = TRUE)
}
cal_slope_intercept <- function(y, p) {
  y <- as.numeric(y); p <- as.numeric(p)
  ok <- is.finite(y) & is.finite(p)
  y <- y[ok]; p <- p[ok]
  if (!length(y)) return(list(intercept=NA_real_, slope=NA_real_))
  eps <- 1e-6
  p <- pmin(pmax(p, eps), 1 - eps)
  x <- stats::qlogis(p)
  fit <- stats::glm(y ~ x, family = stats::binomial())
  co <- stats::coef(summary(fit))
  list(intercept = unname(co[1,1]), slope = unname(co[2,1]))
}

# -------------------------- split joiner (game/play) --------------------------
attach_split <- function(df) {
  pth <- "data/splits/plays_split_map.csv"
  if (!file.exists(pth)) { df[["split"]] <- "overall"; return(df) }
  sm <- safe_read_csv(pth)
  if (!all(c("game_id","play_id") %in% names(sm))) {
    df[["split"]] <- "overall"; return(df)
  }
  split_col <- if ("split" %in% names(sm)) "split" else names(sm)[grep("split", names(sm), ignore.case=TRUE)][1]
  mg <- tryCatch(merge(df, sm[, c("game_id","play_id", split_col)], by=c("game_id","play_id"), all.x=TRUE, sort=FALSE), error=function(e) NULL)
  if (is.null(mg)) { df[["split"]] <- "overall"; return(df) }
  names(mg)[names(mg)==split_col] <- "split"
  mg$split <- tolower(as.character(mg$split))
  if (!any(mg$split %in% c("train","val","test"))) mg$split <- "overall"
  mg
}

# -------------------------- prediction helpers --------------------------
clip01 <- function(p, eps = 1e-6) { p <- pmin(p, 1 - eps); p <- pmax(p, eps); p }
logit  <- function(p) log(clip01(p)/(1-clip01(p)))

get_p_yes <- function(pred) {
  pr <- pred$predictions
  if (is.numeric(pr)) return(as.numeric(pr))
  if (is.matrix(pr) || is.data.frame(pr)) {
    cn <- colnames(pr)
    pick <- intersect(c("yes","1","TRUE",".pred_yes",".pred_1",".pred_TRUE"), cn)
    if (!length(pick) && length(cn)>=2) pick <- cn[min(2, length(cn))] # fallback: second column
    return(as.numeric(pr[, pick[1], drop=TRUE]))
  }
  rep(NA_real_, if (!is.null(nrow(pr))) nrow(pr) else 0)
}
unwrap_predictor <- function(obj) { if (is.list(obj) && "model" %in% names(obj)) obj$model else obj }
apply_calibration <- function(p_raw, cal_glm) {
  if (is.null(cal_glm)) return(as.numeric(p_raw))
  vn <- all.vars(stats::formula(cal_glm))
  newd <- if (length(vn)>=2 && vn[2]!="(Intercept)") {
    data.frame(setNames(list(logit(p_raw)), vn[2]))
  } else data.frame(l = logit(p_raw))
  as.numeric(tryCatch(stats::predict(cal_glm, newdata=newd, type="response"),
                      error=function(e) rep(NA_real_, length(p_raw))))
}
sweep_thresholds <- function(y_true, p, by = 0.01) {
  y_true <- as.integer(y_true); p <- as.numeric(p)
  ok <- is.finite(y_true) & is.finite(p)
  y_true <- y_true[ok]; p <- p[ok]
  if (!length(y_true)) return(list(th=NA_real_, f1=NA_real_, precision=NA_real_, recall=NA_real_))
  ths <- seq(0, 1, by = by)
  f1 <- precision <- recall <- numeric(length(ths))
  for (i in seq_along(ths)) {
    t <- ths[i]; pred <- as.integer(p >= t)
    tp <- sum(pred==1 & y_true==1); fp <- sum(pred==1 & y_true==0); fn <- sum(pred==0 & y_true==1)
    precision[i] <- if ((tp+fp)==0) 0 else tp/(tp+fp)
    recall[i]    <- if ((tp+fn)==0) 0 else tp/(tp+fn)
    f1[i]        <- if ((precision[i]+recall[i])==0) 0 else 2*precision[i]*recall[i]/(precision[i]+recall[i])
  }
  i_best <- which.max(f1)
  list(th = ths[i_best], f1 = f1[i_best], precision = precision[i_best], recall = recall[i_best])
}

# -------------------------- main --------------------------
status <- data.frame(check=character(), status=character(), details=character(), timestamp=character(), stringsAsFactors=FALSE)
dbg <- c("# Model 03 — Verification Debug", "", sprintf("_Generated: %s_", ts_iso()), "")

fail <- function(msg) { write_debug(dbg); write_status(status, "FAIL"); stop(msg, call. = FALSE) }

# Paths
PATH_DS      <- "artifacts/model02_contest_dataset_final.csv"
PATH_CAPS    <- "artifacts/capability_profiles.csv"
PATH_MODEL   <- "artifacts/model03_model_rds.rds"        # primary 1.5 yd
PATH_CALIB   <- "artifacts/model03_calibration_glm.rds"  # optional

# Guards
if (!file.exists(PATH_MODEL)) { status <- add_row(status,"Model artifact","FAIL","Missing artifacts/model03_model_rds.rds"); fail("Missing model artifact.") }
if (!file.exists(PATH_DS))    { status <- add_row(status,"Contest dataset","FAIL","Missing artifacts/model02_contest_dataset_final.csv"); fail("Missing dataset.") }
if (!file.exists(PATH_CAPS))  { status <- add_row(status,"Capability profiles","FAIL","Missing artifacts/capability_profiles.csv"); fail("Missing capability profiles.") }

# Load
mobj <- safe_readRDS(PATH_MODEL);   status <- add_row(status,"Model artifact load","PASS", paste("Top-level class:", paste(class(mobj), collapse=",")))
cobj <- if (file.exists(PATH_CALIB)) safe_readRDS(PATH_CALIB) else NULL
status <- add_row(status,"Calibration artifact presence","PASS", if (is.null(cobj)) "Not found (identity used)" else paste("Class:", paste(class(cobj), collapse=",")))

ds <- safe_read_csv(PATH_DS)
caps <- safe_read_csv(PATH_CAPS)

# basic coercions
coerce_cols <- function(df) {
  if ("game_id" %in% names(df)) df$game_id <- as.character(df$game_id)
  if ("play_id" %in% names(df)) df$play_id <- suppressWarnings(as.integer(df$play_id))
  if ("nfl_id"  %in% names(df)) df$nfl_id  <- suppressWarnings(as.integer(df$nfl_id))
  df
}
ds   <- coerce_cols(ds)
caps <- coerce_cols(caps)

# required columns in dataset
req_ds <- c("game_id","play_id","nfl_id","eligible","throwaway","p_reach_start","d_start","p_reach_max","d_min","contest_primary")
miss_ds <- setdiff(req_ds, names(ds))
if (length(miss_ds)) { status <- add_row(status,"Dataset columns","FAIL", paste("Missing:", paste(miss_ds, collapse=", "))); fail("Dataset missing required columns.") }
status <- add_row(status,"Contest dataset load","PASS", paste("Rows:", nrow(ds), "Cols:", ncol(ds)))

# ensure capability columns
req_caps <- c("nfl_id","v_max","a_max")
miss_caps <- setdiff(req_caps, names(caps))
if (length(miss_caps)) { status <- add_row(status,"Capability columns","FAIL", paste("Missing:", paste(miss_caps, collapse=", "))); fail("Capabilities missing required columns.") }

# Build evaluation frame (eligible & not throwaway) + caps + split
ds_use <- subset(ds, eligible & !throwaway,
                 select = c("game_id","play_id","nfl_id","p_reach_start","d_start","p_reach_max","d_min","contest_primary"))
ds_use <- merge(ds_use, caps[, req_caps], by = "nfl_id", all.x = TRUE, sort = FALSE)
ds_use <- attach_split(ds_use)

val_n  <- sum(ds_use$split=="val", na.rm=TRUE)
test_n <- sum(ds_use$split=="test", na.rm=TRUE)
if (val_n == 0 || test_n == 0) {
  status <- add_row(status,"Split join","FAIL", sprintf("val rows: %d | test rows: %d", val_n, test_n))
  fail("No val/test rows available for verification.")
}
status <- add_row(status,"Split join","PASS", sprintf("val rows: %d | test rows: %d", val_n, test_n))

# Unwrap predictor from saved object (Script 05 saved list(model=..., features=..., medians=...))
m_core <- unwrap_predictor(mobj)
feat_cols <- if (is.list(mobj) && "features" %in% names(mobj)) as.character(mobj$features) else c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")
meds_row  <- if (is.list(mobj) && "medians" %in% names(mobj)) mobj$medians else NULL

if (is.null(meds_row) || !length(feat_cols)) {
  status <- add_row(status,"Model components","FAIL","Missing 'features' and/or 'medians' in artifact")
  fail("Model artifact lacks features/medians required for deterministic scoring.")
}
status <- add_row(status,"Model components","PASS", paste("features:", paste(feat_cols, collapse=", ")))

missing_feats <- setdiff(feat_cols, names(ds_use))
if (length(missing_feats)) { status <- add_row(status,"Feature availability","FAIL", paste("Missing:", paste(missing_feats, collapse=", "))); fail("Missing features in evaluation frame.") }

# Impute with training medians from artifact
impute_median <- function(df, meds_one_row){
  nm <- intersect(names(meds_one_row), names(df))
  for (v in nm) df[[v]][is.na(df[[v]])] <- meds_one_row[[v]][1]
  df
}
X_all <- impute_median(ds_use[, feat_cols, drop=FALSE], meds_row)

# Predict raw probs (primary label)
pred_try <- try(predict(m_core, data = X_all), silent = TRUE)
if (inherits(pred_try, "try-error")) {
  status <- add_row(status,"Primary predict()","FAIL", as.character(attr(pred_try,"condition")$message))
  fail("Predict() failed on evaluation frame.")
}
p_raw_all <- get_p_yes(pred_try)
if (!any(is.finite(p_raw_all))) {
  status <- add_row(status,"Primary predict()","FAIL","All NA/non-finite probabilities")
  fail("Predictions were NA/non-finite.")
}
status <- add_row(status,"Primary predict()","PASS",
                  sprintf("n=%d, range=[%.4f, %.4f]", length(p_raw_all), min(p_raw_all,na.rm=TRUE), max(p_raw_all,na.rm=TRUE)))

# Apply calibration if present
p_cal_all <- apply_calibration(p_raw_all, cobj)
if (!any(is.finite(p_cal_all))) {
  status <- add_row(status,"Calibration apply","FAIL","Calibration returned NA/non-finite")
  fail("Calibration produced NA/non-finite.")
}
status <- add_row(status,"Calibration apply","PASS",
                  sprintf("range=[%.4f, %.4f]", min(p_cal_all,na.rm=TRUE), max(p_cal_all,na.rm=TRUE)))

# Prepare y and splits
y_all <- as.integer(ds_use$contest_primary)
ok <- is.finite(y_all) & !is.na(y_all) & is.finite(p_cal_all) & !is.na(p_cal_all)
y_all <- y_all[ok]; p_all <- p_cal_all[ok]; sp_all <- ds_use$split[ok]

if (!length(y_all)) { status <- add_row(status,"Effective sample","FAIL","No rows after filtering NA"); fail("No valid rows to score after NA filtering.") }

# Metrics blocks (per-split)
blk <- function(idx) {
  y <- y_all[idx]; p <- p_all[idx]
  ok2 <- is.finite(y) & is.finite(p)
  y <- y[ok2]; p <- p[ok2]
  if (!length(y)) return(list(n=0, prevalence=NA, auc=NA, brier=NA, logloss=NA, ece=NA, cal=list(intercept=NA, slope=NA)))
  list(
    n = length(y),
    prevalence = mean(y),
    auc = auc_mw(y, p),
    brier = brier(y, p),
    logloss = logloss(y, p),
    ece = ece20(y, p),
    cal = cal_slope_intercept(y, p)
  )
}
m_overall <- blk(rep(TRUE, length(y_all)))
m_val     <- blk(sp_all=="val")
m_test    <- blk(sp_all=="test")

# Threshold sanity (robust to NA / missing)
best_th <- NA_real_
if (is.list(mobj) && "threshold" %in% names(mobj)) best_th <- suppressWarnings(as.numeric(mobj$threshold))
if (!is.finite(best_th)) {
  sv <- sweep_thresholds(y_all[sp_all=="val"], p_all[sp_all=="val"], by=0.01)
  best_th <- sv$th
}
if (!is.finite(best_th)) best_th <- 0.5  # safe default

th_block <- function(idx, th) {
  y <- y_all[idx]; p <- p_all[idx]
  if (!length(y) || !is.finite(th)) return(c(f1=NA, precision=NA, recall=NA))
  pred <- as.integer(p >= th)
  tp <- sum(pred==1 & y==1); fp <- sum(pred==1 & y==0); fn <- sum(pred==0 & y==1)
  if (is.na(tp) || is.na(fp) || is.na(fn)) return(c(f1=NA, precision=NA, recall=NA))
  precision <- if ((tp+fp)==0) 0 else tp/(tp+fp)
  recall    <- if ((tp+fn)==0) 0 else tp/(tp+fn)
  f1        <- if ((precision+recall)==0) 0 else 2*precision*recall/(precision+recall)
  c(f1=f1, precision=precision, recall=recall)
}
th_val  <- th_block(sp_all=="val",  best_th)
th_test <- th_block(sp_all=="test", best_th)

# Report
cap <- function(nm) paste0(toupper(substr(nm,1,1)), substring(nm,2))
emit <- function(nm, m) c(sprintf("## %s metrics", cap(nm)),"",
                          sprintf("- n: %d", m$n),
                          sprintf("- prevalence: %.4f", m$prevalence),
                          sprintf("- AUC: %.4f", m$auc),
                          sprintf("- Brier: %.6f", m$brier),
                          sprintf("- Log loss: %.6f", m$logloss),
                          sprintf("- ECE@20: %.6f", m$ece),
                          sprintf("- Calibration: intercept=%.4f, slope=%.4f", m$cal$intercept, m$cal$slope), "")

rep <- c("# Model 03 — Verification Report (primary 1.5 yd)","",
         sprintf("_Generated: %s_", ts_iso()), "",
         "- Verifies the saved artifact from Script 05 by reproducing calibrated probabilities on val/test splits.",
         "- Uses the model’s saved feature list and train medians; applies calibration if the GLM file exists.", "",
         sprintf("**Threshold used**: %.3f (saved-or-val, default 0.5 if unavailable)", best_th), "",
         emit("overall", m_overall),
         emit("val",     m_val),
         emit("test",    m_test),
         "## Threshold sanity (using threshold above)",
         sprintf("- Val:  F1=%.4f | P=%.4f | R=%.4f", th_val["f1"],  th_val["precision"], th_val["recall"]),
         sprintf("- Test: F1=%.4f | P=%.4f | R=%.4f", th_test["f1"], th_test["precision"], th_test["recall"]),
         "")
write_report(rep)

# Debug notes
dbg <- c(dbg,
         "## Artifact structure",
         paste0("- model class: ", paste(class(m_core), collapse=",")),
         paste0("- features: ", paste(feat_cols, collapse=", ")),
         "## Sample sizes",
         paste0("- val n: ", val_n, " | test n: ", test_n),
         "## Probability ranges",
         sprintf("- raw: [%.4f, %.4f] | cal: [%.4f, %.4f]",
                 min(p_raw_all,na.rm=TRUE), max(p_raw_all,na.rm=TRUE),
                 min(p_all,na.rm=TRUE),     max(p_all,na.rm=TRUE))
)
write_debug(dbg)

# Wrap-up: PASS
write_status(status, "PASS")
message("Model 03 verification PASSED. See artifacts/model03_model_verification_status.md and artifacts/model03_model_verification_report.md")










# 06_build_model04_leverage_dataset.R
# Purpose: Build leverage dataset for Model 04 (who should go), using Model 03 probabilities.
# Inputs (must exist):
#   - ./artifacts/model02_contest_dataset_final.csv
#   - ./artifacts/capability_profiles.csv
#   - ./data/splits/plays_split_map.csv
#   - ./artifacts/model03_model_rds.rds                 (primary 1.5 yd)
#   - ./artifacts/model03_model_rds_1p0.rds             (backup  1.0 yd)
#   - ./artifacts/model03_calibration_glm.rds           (optional; primary)
#   - ./artifacts/model03_calibration_glm_1p0.rds       (optional; backup)
# Outputs:
#   - ./artifacts/model04_leverage_dataset.csv
#   - ./artifacts/model04_build_metrics.csv
#   - ./artifacts/model04_build_metrics_by_split.csv
#   - ./artifacts/model04_build_report.md
#   - ./artifacts/model04_build_verification_status.csv
#   - ./artifacts/model04_build_verification_status.md
# Assumption: current working directory is the project root.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
  library(rlang)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  artifacts = B("artifacts"),
  splits    = B("data","splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# Paths
PATH_DS        <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")
PATH_CAPS      <- file.path(DIRS$artifacts, "capability_profiles.csv")
PATH_MAP       <- file.path(DIRS$splits,   "plays_split_map.csv")
PATH_M03_PRI   <- file.path(DIRS$artifacts, "model03_model_rds.rds")
PATH_M03_CAL   <- file.path(DIRS$artifacts, "model03_calibration_glm.rds")
PATH_M03_BK    <- file.path(DIRS$artifacts, "model03_model_rds_1p0.rds")
PATH_M03_CAL_B <- file.path(DIRS$artifacts, "model03_calibration_glm_1p0.rds")

OUT_DATA    <- file.path(DIRS$artifacts, "model04_leverage_dataset.csv")
OUT_METRICS <- file.path(DIRS$artifacts, "model04_build_metrics.csv")
OUT_METRICS_SPLIT <- file.path(DIRS$artifacts, "model04_build_metrics_by_split.csv")
OUT_REPORT  <- file.path(DIRS$artifacts, "model04_build_report.md")

# -------------------- 1) Guard required files --------------------
req <- function(path, name){
  if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE)
}
req(PATH_DS,      "model02_contest_dataset_final.csv")
req(PATH_CAPS,    "capability_profiles.csv")
req(PATH_MAP,     "plays_split_map.csv")
req(PATH_M03_PRI, "model03_model_rds.rds")
req(PATH_M03_BK,  "model03_model_rds_1p0.rds")

# -------------------- 2) Load inputs --------------------
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

ds <- read_csv_clean(PATH_DS) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id))
  )

caps <- read_csv_clean(PATH_CAPS) |>
  transmute(
    nfl_id = suppressWarnings(as.integer(nfl_id)),
    v_max  = as.numeric(v_max),
    a_max  = as.numeric(a_max)
  ) |>
  distinct(nfl_id, .keep_all = TRUE)

splits <- read_csv_clean(PATH_MAP) |>
  transmute(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    split   = tolower(as.character(split))
  ) |>
  distinct(game_id, play_id, split)

# Enforce split from map (overwrite if ds has a split column)
ds <- ds |>
  select(-any_of("split")) |>
  left_join(splits, by = c("game_id","play_id"))

# Keep only eligible defenders on non-throwaway plays
need_cols <- c("eligible","throwaway","p_reach_start","d_start","p_reach_max","d_min","contest_primary","contest_tight")
miss <- setdiff(need_cols, names(ds))
if (length(miss)) stop("Dataset missing expected columns: ", paste(miss, collapse=", "), call. = FALSE)

ds_use <- ds |>
  filter(eligible, !throwaway) |>
  left_join(caps, by = "nfl_id")

# -------------------- 3) Load models + calibration --------------------
m03_primary <- readRDS(PATH_M03_PRI)  # list: model, features, medians, label, threshold, seed
m03_backup  <- readRDS(PATH_M03_BK)

cal_primary <- if (file.exists(PATH_M03_CAL))   readRDS(PATH_M03_CAL)   else NULL
cal_backup  <- if (file.exists(PATH_M03_CAL_B)) readRDS(PATH_M03_CAL_B) else NULL

# Utility: impute with model medians learned on train
impute_with_medians <- function(df, meds_one_row) {
  nm <- intersect(names(meds_one_row), names(df))
  for (v in nm) df[[v]][is.na(df[[v]])] <- meds_one_row[[v]][1]
  df
}

# Utilities for probability handling
clip01 <- function(p, eps = 1e-6) pmin(pmax(p, eps), 1 - eps)
logit  <- function(p) log(clip01(p) / (1 - clip01(p)))
get_p_yes <- function(pred) {
  if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"yes"]) else as.numeric(pred$predictions)
}

predict_calibrated <- function(model_obj, calib_glm, df_features) {
  # Impute with saved train medians
  df_imp <- impute_with_medians(df_features, model_obj$medians)
  # Predict raw probs
  p_raw <- get_p_yes(predict(model_obj$model, data = df_imp[, model_obj$features, drop = FALSE]))
  # Calibrate if calibration model exists
  if (!is.null(calib_glm)) {
    p_cal <- as.numeric(predict(calib_glm, newdata = data.frame(l = logit(p_raw)), type = "response"))
  } else {
    p_cal <- p_raw
  }
  list(raw = p_raw, cal = p_cal)
}

# -------------------- 4) Assemble feature frame for prediction --------------------
feat_cols <- m03_primary$features
missing_feats <- setdiff(feat_cols, names(ds_use))
if (length(missing_feats)) stop("Missing features for prediction: ", paste(missing_feats, collapse=", "), call. = FALSE)

X <- ds_use |>
  select(game_id, play_id, nfl_id, split, all_of(feat_cols))

# -------------------- 5) Predict probabilities (primary 1.5 and backup 1.0) --------------------
p1 <- predict_calibrated(m03_primary, cal_primary, X)
p0 <- predict_calibrated(m03_backup,  cal_backup,  X)

pred <- X |>
  mutate(
    p03_primary_raw = p1$raw,
    p03_primary     = p1$cal,
    p03_1p0_raw     = p0$raw,
    p03_1p0         = p0$cal
  )

# -------------------- 6) Build leverage table with within-play ranks --------------------
# Context from ds_use (may duplicate some feature columns). We'll coalesce duplicates after join.
core <- ds_use |>
  select(game_id, play_id, nfl_id, split,
         v_max, a_max,
         p_reach_start, d_start, p_reach_max, d_min,
         d_arrival, contest_primary, contest_tight)

# Join and coalesce duplicate columns so plain names exist (no .core suffix mess)
lev_joined <- pred |>
  left_join(core, by = c("game_id","play_id","nfl_id","split"), suffix = c("", ".core"))

dup_feats <- c("p_reach_start","d_start","p_reach_max","d_min")
for (v in dup_feats) {
  v_core <- paste0(v, ".core")
  if (v %in% names(lev_joined) && v_core %in% names(lev_joined)) {
    lev_joined[[v]] <- dplyr::coalesce(lev_joined[[v]], lev_joined[[v_core]])
    lev_joined[[v_core]] <- NULL
  }
}

lev <- lev_joined |>
  group_by(game_id, play_id) |>
  mutate(
    n_defenders_play = n(),
    # Ranks within play
    rank_d_start        = rank(d_start, ties.method = "min"),         # smaller is better
    rank_d_min          = rank(d_min,   ties.method = "min"),         # smaller is better
    rank_v_max          = rank(-v_max,  ties.method = "min"),         # larger is better
    rank_p03_primary    = rank(-p03_primary, ties.method = "min"),    # larger is better
    rank_p03_1p0        = rank(-p03_1p0,     ties.method = "min"),    # larger is better
    is_nearest_start    = as.integer(rank_d_start == 1),
    is_fastest          = as.integer(rank_v_max   == 1),
    is_highest_p03      = as.integer(rank_p03_primary == 1),
    # Normalized ranks [0,1], where 1 is best for “good” metrics
    d_start_rank_norm   = (max(rank_d_start) - rank_d_start) / (max(rank_d_start) - 1 + 1e-9),
    d_min_rank_norm     = (max(rank_d_min)   - rank_d_min)   / (max(rank_d_min)   - 1 + 1e-9),
    v_max_rank_norm     = (max(rank_v_max)   - rank_v_max)   / (max(rank_v_max)   - 1 + 1e-9),
    p03_primary_norm    = (max(rank_p03_primary) - rank_p03_primary) / (max(rank_p03_primary) - 1 + 1e-9),
    p03_1p0_norm        = (max(rank_p03_1p0)     - rank_p03_1p0)     / (max(rank_p03_1p0)     - 1 + 1e-9)
  ) |>
  ungroup()

# Keep a clean set of columns for downstream training
lev_out <- lev |>
  select(
    game_id, play_id, nfl_id, split,
    v_max, a_max,
    p_reach_start, d_start, p_reach_max, d_min,
    p03_primary_raw, p03_primary, p03_1p0_raw, p03_1p0,
    d_arrival, contest_primary, contest_tight,
    n_defenders_play,
    rank_d_start, rank_d_min, rank_v_max, rank_p03_primary, rank_p03_1p0,
    is_nearest_start, is_fastest, is_highest_p03,
    d_start_rank_norm, d_min_rank_norm, v_max_rank_norm, p03_primary_norm, p03_1p0_norm
  )

readr::write_csv(lev_out, OUT_DATA)

# -------------------- 7) Metrics + report --------------------
plays_total <- n_distinct(paste(lev_out$game_id, lev_out$play_id))
rows_total  <- nrow(lev_out)
def_total   <- n_distinct(lev_out$nfl_id)

cov_p_primary <- mean(!is.na(lev_out$p03_primary))
cov_p_1p0     <- mean(!is.na(lev_out$p03_1p0))

by_split <- lev_out |>
  group_by(split) |>
  summarise(rows = n(),
            plays = n_distinct(paste(game_id, play_id)),
            defenders = n_distinct(nfl_id),
            p_primary_na = mean(is.na(p03_primary)),
            p_1p0_na     = mean(is.na(p03_1p0)),
            .groups = "drop")

metrics <- tibble(
  metric = c("rows_total","plays_total","defenders_total","coverage_p03_primary","coverage_p03_1p0"),
  value  = c(rows_total, plays_total, def_total, cov_p_primary, cov_p_1p0)
)
readr::write_csv(metrics, OUT_METRICS)
readr::write_csv(by_split, OUT_METRICS_SPLIT)

rep <- c(
  "# Model 04 — Leverage dataset (build)",
  "",
  sprintf("- Rows: %s | Plays: %s | Defenders: %s", comma(rows_total), comma(plays_total), comma(def_total)),
  sprintf("- Coverage: p03_primary=%.4f | p03_1p0=%.4f", cov_p_primary, cov_p_1p0),
  "",
  "## Notes",
  "- Probabilities are calibrated if calibration files were present, else raw.",
  "- Ranks are computed within each play so we can compare defenders fairly.",
  "",
  "## Files",
  paste0("- ", OUT_DATA),
  paste0("- ", OUT_METRICS),
  paste0("- ", OUT_METRICS_SPLIT)
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

message("Wrote:",
        "\n  - ", OUT_DATA,
        "\n  - ", OUT_METRICS,
        "\n  - ", OUT_METRICS_SPLIT,
        "\n  - ", OUT_REPORT)

# -------------------- 8) PASS/FAIL verification for leverage dataset --------------------
.chk_pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
.md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

dup_keys <- lev_out |> dplyr::count(game_id, play_id, nfl_id, name="n") |> dplyr::filter(n != 1)
na_primary <- mean(is.na(lev_out$p03_primary))
na_backup  <- mean(is.na(lev_out$p03_1p0))
split_bad  <- setdiff(unique(tolower(lev_out$split)), c("train","val","test"))
plays_cov  <- lev_out |> dplyr::count(game_id, play_id, name="n_def") 
min_def    <- if (nrow(plays_cov)) min(plays_cov$n_def) else 0

lev_checks <- tibble::tibble(
  check = c(
    "has_rows",
    "unique_(game_id,play_id,nfl_id)",
    "split_values_in_{train,val,test}",
    "no_play_has_zero_defenders",
    "p03_primary_na_rate<=0.01",
    "p03_1p0_na_rate<=0.01"
  ),
  status = c(
    .chk_pass(nrow(lev_out) > 0),
    .chk_pass(nrow(dup_keys) == 0),
    .chk_pass(length(split_bad) == 0),
    .chk_pass(min_def >= 1),
    .chk_pass(na_primary <= 0.01),
    .chk_pass(na_backup  <= 0.01)
  ),
  details = c(
    paste0("rows=", nrow(lev_out)),
    if (nrow(dup_keys)) paste0("bad_rows=", nrow(dup_keys)) else "OK",
    if (length(split_bad)) paste("bad=", paste(split_bad, collapse=",")) else "OK",
    paste0("min_defenders_per_play=", min_def),
    sprintf("na_primary=%.4f", na_primary),
    sprintf("na_1p0=%.4f", na_backup)
  )
)

# write artifacts
readr::write_csv(lev_checks, file.path(DIRS$artifacts, "model04_build_verification_status.csv"))
dash <- c("# Model 04 leverage verification", "", .md_table(lev_checks))
writeLines(dash, file.path(DIRS$artifacts, "model04_build_verification_status.md"), useBytes = TRUE)

# console + hard stop on FAIL
print(lev_checks)
if (any(lev_checks$status == "FAIL")) stop("Model 04 leverage verification failed. See artifacts/model04_build_verification_status.*", call. = FALSE)
message("Leverage dataset verification: all critical checks passed.")










# 07_train_model04_assignment.R
# Purpose: Train leverage/assignment model (Model 04) to pick the "go" defender per play.
# Inputs:
#   - ./artifacts/model04_leverage_dataset.csv         (from 06_build_model04_leverage_dataset.R)
# Outputs:
#   - ./artifacts/model04_model_rds.rds
#   - ./artifacts/model04_val_preds.csv
#   - ./artifacts/model04_test_preds.csv
#   - ./artifacts/model04_metrics.csv
#   - ./artifacts/model04_report.md
# Assumptions:
#   - Current working directory is the project root.
#   - The leverage dataset contains: game_id, play_id, nfl_id, split, v_max, a_max,
#     p_reach_start, d_start, p_reach_max, d_min, p03_primary, p03_1p0, d_arrival,
#     contest_primary (TRUE/FALSE), plus rank features added in Script 6.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) install.packages(need, quiet = TRUE)
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","ranger","scales"))

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_LEV <- file.path(DIRS$artifacts, "model04_leverage_dataset.csv")

OUT_MODEL   <- file.path(DIRS$artifacts, "model04_model_rds.rds")
OUT_VAL     <- file.path(DIRS$artifacts, "model04_val_preds.csv")
OUT_TEST    <- file.path(DIRS$artifacts, "model04_test_preds.csv")
OUT_METRICS <- file.path(DIRS$artifacts, "model04_metrics.csv")
OUT_REPORT  <- file.path(DIRS$artifacts, "model04_report.md")

# -------------------- 1) Load leverage dataset --------------------
if (!file.exists(PATH_LEV)) stop("Missing leverage dataset: ", PATH_LEV, call. = FALSE)
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

lev <- read_csv_clean(PATH_LEV) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id)),
    split   = tolower(as.character(split))
  )

need_cols <- c("game_id","play_id","nfl_id","split",
               "p_reach_start","d_start","p_reach_max","d_min",
               "v_max","a_max","p03_primary","p03_1p0",
               "d_arrival","contest_primary")
miss <- setdiff(need_cols, names(lev))
if (length(miss)) stop("Leverage dataset missing columns: ", paste(miss, collapse=", "), call. = FALSE)

# -------------------- 2) Build per-play 'winner' label --------------------
# Rule:
#   - If the play was contested (any contest_primary == TRUE), winner = contesting defender with smallest d_arrival.
#   - Else (no contest), winner = defender with smallest d_arrival (closest at arrival).
# Tie-breakers automatically handled by which.min (first min). That’s fine.

winners <- lev |>
  group_by(game_id, play_id) |>
  mutate(
    contested_play = any(contest_primary, na.rm = TRUE),
    d_arrival_eff  = ifelse(contested_play & !contest_primary, Inf, d_arrival)
  ) |>
  summarise(
    nfl_id_winner = nfl_id[which.min(d_arrival_eff)],
    .groups = "drop"
  )

lev_y <- lev |>
  left_join(winners, by = c("game_id","play_id")) |>
  mutate(y_go = as.integer(nfl_id == nfl_id_winner))

# Guard: exactly one winner per play in each split
dupchk <- lev_y |> count(game_id, play_id, y_go) |> filter(y_go == 1, n != 1)
if (nrow(dupchk)) stop("Label construction failed: some plays have != 1 winner.", call. = FALSE)

# -------------------- 3) Assemble features --------------------
feat_cols <- c(
  # probabilities from Model 03
  "p03_primary","p03_1p0",
  # distances / reach features at start-of-flight
  "p_reach_start","d_start","p_reach_max","d_min",
  # capability
  "v_max","a_max",
  # ranks from Script 6 (they’re helpful within-play signals)
  "rank_d_start","rank_d_min","rank_v_max","rank_p03_primary","rank_p03_1p0",
  "d_start_rank_norm","d_min_rank_norm","v_max_rank_norm","p03_primary_norm","p03_1p0_norm"
)
missing_feats <- setdiff(feat_cols, names(lev_y))
if (length(missing_feats)) stop("Missing feature columns: ", paste(missing_feats, collapse=", "), call. = FALSE)

use_df <- lev_y |>
  select(game_id, play_id, nfl_id, split, y_go, all_of(feat_cols))

# -------------------- 4) Train/Val/Test splits --------------------
train_df <- use_df |> filter(split == "train")
val_df   <- use_df |> filter(split == "val")
test_df  <- use_df |> filter(split == "test")

if (nrow(train_df) == 0 || nrow(val_df) == 0 || nrow(test_df) == 0) {
  stop("One of the splits has zero rows. Check split map and upstream steps.", call. = FALSE)
}

# Median imputer learned on train only
meds <- train_df |> summarise(across(all_of(feat_cols), ~ suppressWarnings(median(.x, na.rm = TRUE))))
impute_median <- function(df, meds_row){
  for (nm in feat_cols) {
    if (!nm %in% names(df)) df[[nm]] <- NA_real_
    df[[nm]][is.na(df[[nm]])] <- meds_row[[nm]][1]
  }
  df
}
train_df <- impute_median(train_df, meds)
val_df   <- impute_median(val_df, meds)
test_df  <- impute_median(test_df, meds)

# -------------------- 5) Train assignment model (ranger classifier) --------------------
# Only one positive per play -> class imbalance. Use simple class weights.
pos_rate <- mean(train_df$y_go == 1)
w_pos <- 0.5 / max(pos_rate, 1e-9)
w_neg <- 0.5 / max(1 - pos_rate, 1e-9)
cls_w  <- c("0" = w_neg, "1" = w_pos)

rf_train <- train_df |>
  transmute(y = factor(y_go, levels = c(0,1)),
            !!!rlang::syms(feat_cols))

set.seed(2026)
rf_fit <- ranger::ranger(
  y ~ .,
  data = rf_train,
  num.trees = 500,
  mtry = max(1, floor(sqrt(length(feat_cols)))),
  min.node.size = 10,
  probability = TRUE,
  class.weights = cls_w,
  respect.unordered.factors = TRUE,
  seed = 2026
)

# -------------------- 6) Predict probabilities --------------------
get_p1 <- function(pred) {
  if (is.matrix(pred$predictions)) {
    # Columns are factor levels ("0","1"); pick "1"
    as.numeric(pred$predictions[,"1"])
  } else {
    as.numeric(pred$predictions)
  }
}

p_train <- get_p1(predict(rf_fit, data = train_df[, feat_cols, drop = FALSE]))
p_val   <- get_p1(predict(rf_fit, data = val_df[,   feat_cols, drop = FALSE]))
p_test  <- get_p1(predict(rf_fit, data = test_df[,  feat_cols, drop = FALSE]))

# -------------------- 7) Per-play ranking metrics --------------------
# Top-1 accuracy: % of plays where argmax p equals the winner.
top1_acc <- function(df, p) {
  df |>
    mutate(p = p, key = paste(game_id, play_id)) |>
    group_by(key) |>
    mutate(rank = rank(-p, ties.method = "first")) |>
    summarise(hit = as.integer(any(y_go == 1 & rank == 1)), .groups = "drop") |>
    summarise(mean(hit)) |>
    pull()
}

# Mean Reciprocal Rank (MRR) of the true winner
mrr <- function(df, p) {
  df |>
    mutate(p = p, key = paste(game_id, play_id)) |>
    group_by(key) |>
    mutate(rank = rank(-p, ties.method = "first")) |>
    filter(y_go == 1) |>
    summarise(rr = 1 / rank[1], .groups = "drop") |>
    summarise(mean(rr)) |>
    pull()
}

# Rowwise log loss for completeness (not group-normalized)
clip01 <- function(x, eps = 1e-6) pmin(pmax(x, eps), 1 - eps)
logloss <- function(y, p) { y <- as.numeric(y); -mean(y*log(clip01(p)) + (1-y)*log(clip01(1-p))) }

metrics <- tibble::tibble(
  metric = c("top1_val","top1_test","mrr_val","mrr_test","logloss_val","logloss_test",
             "train_rows","val_rows","test_rows","train_pos_rate"),
  value  = c(
    top1_acc(val_df,  p_val),
    top1_acc(test_df, p_test),
    mrr(val_df,  p_val),
    mrr(test_df, p_test),
    logloss(val_df$y_go,  p_val),
    logloss(test_df$y_go, p_test),
    nrow(train_df), nrow(val_df), nrow(test_df), pos_rate
  )
)

# -------------------- 8) Save artifacts --------------------
saveRDS(list(
  model = rf_fit,
  features = feat_cols,
  medians = meds,
  class_weights = cls_w,
  seed = 2026
), OUT_MODEL)

val_out <- val_df |> transmute(game_id, play_id, nfl_id, y = y_go, p_go = p_val)
test_out<- test_df|> transmute(game_id, play_id, nfl_id, y = y_go, p_go = p_test)

readr::write_csv(val_out, OUT_VAL)
readr::write_csv(test_out, OUT_TEST)
readr::write_csv(metrics, OUT_METRICS)

# -------------------- 9) Report --------------------
rep <- c(
  "# Model 04 — Assignment model (who should go)",
  "",
  "## Data",
  paste0("- Train rows: ", scales::comma(nrow(train_df)),
         " | Val rows: ", scales::comma(nrow(val_df)),
         " | Test rows: ", scales::comma(nrow(test_df))),
  paste0("- Positives per play: exactly one (constructed by closest-at-arrival rule)"),
  "",
  "## Model",
  "- Algorithm: ranger random forest (500 trees), probability output",
  "- Features: p03_primary, p03_1p0, p_reach_start, d_start, p_reach_max, d_min, v_max, a_max",
  "- Plus within-play ranks and normalized ranks from Script 6",
  "- Class weights used to balance the single-positive-per-play setup",
  "",
  "## Metrics",
  paste0("- Top-1 accuracy: val=", signif(metrics$value[metrics$metric == "top1_val"],3),
         " | test=", signif(metrics$value[metrics$metric == "top1_test"],3)),
  paste0("- MRR: val=", signif(metrics$value[metrics$metric == "mrr_val"],3),
         " | test=", signif(metrics$value[metrics$metric == "mrr_test"],3)),
  paste0("- LogLoss (rowwise): val=", signif(metrics$value[metrics$metric == "logloss_val"],3),
         " | test=", signif(metrics$value[metrics$metric == "logloss_test"],3)),
  "",
  "## Files",
  paste0("- ", OUT_MODEL),
  paste0("- ", OUT_VAL),
  paste0("- ", OUT_TEST),
  paste0("- ", OUT_METRICS)
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

message("Wrote:",
        "\n  - ", OUT_MODEL,
        "\n  - ", OUT_VAL,
        "\n  - ", OUT_TEST,
        "\n  - ", OUT_METRICS,
        "\n  - ", OUT_REPORT,
        "\nDone.")










# 07a_model04_training_verification.R
# Verifies Model 04 (assignment) training outputs produced by Script 07.

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
  library(ranger)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# Inputs
P_LEV      <- file.path(DIRS$artifacts, "model04_leverage_dataset.csv")
P_MODEL    <- file.path(DIRS$artifacts, "model04_model_rds.rds")
P_VAL      <- file.path(DIRS$artifacts, "model04_val_preds.csv")
P_TEST     <- file.path(DIRS$artifacts, "model04_test_preds.csv")
P_VAL_CAL  <- file.path(DIRS$artifacts, "model04_val_preds_cal.csv")
P_TEST_CAL <- file.path(DIRS$artifacts, "model04_test_preds_cal.csv")
P_METRICS07<- file.path(DIRS$artifacts, "model04_metrics.csv") # informational

# Outputs
OUT_STATUS_CSV <- file.path(DIRS$artifacts, "model04_training_verification_status.csv")
OUT_STATUS_MD  <- file.path(DIRS$artifacts, "model04_training_verification_status.md")
OUT_METRICS    <- file.path(DIRS$artifacts, "model04_training_verification_metrics.csv")
OUT_REPORT     <- file.path(DIRS$artifacts, "model04_training_verification_report.md")

# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
skip <- function() "SKIP"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

safe_top1 <- function(df, pcol = "p"){
  if (!nrow(df)) return(NA_real_)
  res <- df |>
    mutate(key = paste(game_id, play_id), p = .data[[pcol]]) |>
    group_by(key) |>
    mutate(r = rank(-p, ties.method = "first")) |>
    summarise(hit = as.integer(any(y == 1 & r == 1)), .groups="drop") |>
    summarise(mean(hit)) |> pull()
  if (length(res)==0) NA_real_ else res
}

safe_mrr <- function(df, pcol = "p"){
  if (!nrow(df)) return(NA_real_)
  res <- df |>
    mutate(key = paste(game_id, play_id), p = .data[[pcol]]) |>
    group_by(key) |>
    mutate(r = rank(-p, ties.method = "first")) |>
    filter(y == 1) |>
    summarise(rr = 1 / r[1], .groups="drop") |>
    summarise(mean(rr)) |> pull()
  if (length(res)==0) NA_real_ else res
}

harmonic <- function(n) if (is.na(n) || n <= 0) NA_real_ else sum(1 / seq_len(n))
baseline_random <- function(df){
  if (!nrow(df)) return(tibble(top1 = NA_real_, mrr = NA_real_))
  per_play <- df |> mutate(key = paste(game_id, play_id)) |> group_by(key) |> summarise(N = n(), .groups = "drop")
  tibble(
    top1 = mean(1 / per_play$N),
    mrr  = mean(sapply(per_play$N, function(N) harmonic(N) / N))
  )
}

load_preds <- function(raw_path, cal_path, split_name){
  if (file.exists(raw_path)) {
    df <- read_csv_clean(raw_path)
    need <- c("game_id","play_id","nfl_id","y","p_go")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop("Preds file missing columns: ", raw_path, " -> ", paste(miss, collapse=", "), call. = FALSE)
    df <- df |> mutate(p = as.numeric(p_go))
  } else if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    need <- c("game_id","play_id","nfl_id","y")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop("Fallback preds file missing core columns: ", cal_path, " -> ", paste(miss, collapse=", "), call. = FALSE)
    if ("p_cal" %in% names(df)) df <- df |> mutate(p = as.numeric(p_cal))
    else if ("p_go" %in% names(df)) df <- df |> mutate(p = as.numeric(p_go))
    else stop("Fallback preds has neither p_cal nor p_go: ", cal_path, call. = FALSE)
  } else {
    stop("Missing prediction files for split=", split_name, " (checked raw and calibrated).", call. = FALSE)
  }
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y),
      split   = split_name
    ) |>
    select(game_id, play_id, nfl_id, split, y, p)
}

# -------------------- Load artifacts --------------------
if (!file.exists(P_LEV))   stop("Missing leverage dataset: ", P_LEV, call. = FALSE)
if (!file.exists(P_MODEL)) stop("Missing Model 04 object: ", P_MODEL, call. = FALSE)

lev <- read_csv_clean(P_LEV) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id)),
    split   = tolower(as.character(split))
  )

pred_val  <- load_preds(P_VAL,  P_VAL_CAL,  "val")
pred_test <- load_preds(P_TEST, P_TEST_CAL, "test")
preds <- bind_rows(pred_val, pred_test)

# -------------------- Basic schema & uniqueness --------------------
need_pred <- c("game_id","play_id","nfl_id","split","y","p")
miss_pred <- setdiff(need_pred, names(preds))
if (length(miss_pred)) stop("Predictions missing columns after load: ", paste(miss_pred, collapse=", "), call. = FALSE)

one_winner <- preds |>
  group_by(split, game_id, play_id) |>
  summarise(pos = sum(y == 1), .groups="drop") |>
  summarise(all_one = all(pos == 1), .groups="drop") |> pull(all_one)

p_in_range <- all(is.finite(preds$p) & preds$p >= 0 & preds$p <= 1)
p_var_val  <- preds %>% filter(split=="val")  %>% summarise(n = n(), v = var(p))  %>% pull(v)
p_var_test <- preds %>% filter(split=="test") %>% summarise(n = n(), v = var(p))  %>% pull(v)
p_nonconst_val  <- !is.na(p_var_val)  && p_var_val  > 0
p_nonconst_test <- !is.na(p_var_test) && p_var_test > 0

# -------------------- Coverage vs leverage dataset --------------------
plays_lev_val  <- lev %>% filter(split=="val")  %>% summarise(n = n_distinct(paste(game_id,play_id)))  %>% pull(n)
plays_lev_test <- lev %>% filter(split=="test") %>% summarise(n = n_distinct(paste(game_id,play_id)))  %>% pull(n)
plays_pred_val  <- preds %>% filter(split=="val")  %>% summarise(n = n_distinct(paste(game_id,play_id))) %>% pull(n)
plays_pred_test <- preds %>% filter(split=="test") %>% summarise(n = n_distinct(paste(game_id,play_id))) %>% pull(n)
coverage_val_ok  <- (is.na(plays_lev_val)  || plays_lev_val  == plays_pred_val)
coverage_test_ok <- (is.na(plays_lev_test) || plays_lev_test == plays_pred_test)

# -------------------- Performance vs random baselines --------------------
t1_val   <- safe_top1(preds %>% filter(split=="val"))
t1_test  <- safe_top1(preds %>% filter(split=="test"))
mrr_val  <- safe_mrr (preds %>% filter(split=="val"))
mrr_test <- safe_mrr (preds %>% filter(split=="test"))

base_val  <- baseline_random(preds %>% filter(split=="val"))
base_test <- baseline_random(preds %>% filter(split=="test"))

n_plays_val  <- preds %>% filter(split=="val")  %>% summarise(n = n_distinct(paste(game_id,play_id))) %>% pull(n)
n_plays_test <- preds %>% filter(split=="test") %>% summarise(n = n_distinct(paste(game_id,play_id))) %>% pull(n)
margin <- function(n_plays) ifelse(is.na(n_plays) || n_plays < 50, 0.000, 0.010)

t1_val_ok   <- is.finite(t1_val)  && (t1_val  >= base_val$top1  + margin(n_plays_val))
t1_test_ok  <- is.finite(t1_test) && (t1_test >= base_test$top1 + margin(n_plays_test))
mrr_val_ok  <- is.finite(mrr_val) && (mrr_val >= base_val$mrr   + margin(n_plays_val))
mrr_test_ok <- is.finite(mrr_test)&& (mrr_test>= base_test$mrr  + margin(n_plays_test))

# -------------------- Model object predict sanity --------------------
obj <- readRDS(P_MODEL)
obj_ok <- is.list(obj) && all(c("model","features","medians") %in% names(obj))

pred_sanity_ok <- NA
pred_sanity_note <- "SKIP"
if (obj_ok) {
  feat <- obj$features
  miss_feat <- setdiff(feat, names(lev))
  if (length(miss_feat) == 0) {
    sample_df <- lev %>%
      filter(split %in% c("val","test")) %>%
      select(all_of(feat)) %>%
      head(200)
    impute_with_medians <- function(df, meds_one_row) {
      nm <- intersect(names(meds_one_row), names(df))
      for (v in nm) df[[v]][is.na(df[[v]])] <- meds_one_row[[v]][1]
      df
    }
    sample_imp <- impute_with_medians(sample_df, obj$medians)
    pr <- predict(obj$model, data = sample_imp)
    p1 <- if (is.matrix(pr$predictions)) {
      if ("1" %in% colnames(pr$predictions)) as.numeric(pr$predictions[,"1"]) else as.numeric(pr$predictions[,2])
    } else as.numeric(pr$predictions)
    pred_sanity_ok <- all(is.finite(p1)) && all(p1 >= 0 & p1 <= 1) && (var(p1) > 0)
    pred_sanity_note <- if (pred_sanity_ok) "OK" else "predictions degenerate or invalid"
  } else {
    pred_sanity_ok <- NA
    pred_sanity_note <- paste0("SKIP (missing features in leverage dataset: ", paste(head(miss_feat,10), collapse=", "), ")")
  }
}

# -------------------- Metrics table --------------------
metrics <- tibble::tibble(
  metric = c(
    "plays_val","plays_test",
    "top1_val","top1_test","baseline_top1_val","baseline_top1_test",
    "mrr_val","mrr_test","baseline_mrr_val","baseline_mrr_test",
    "p_variance_val","p_variance_test"
  ),
  value = c(
    n_plays_val, n_plays_test,
    t1_val, t1_test, base_val$top1, base_test$top1,
    mrr_val, mrr_test, base_val$mrr, base_test$mrr,
    p_var_val, p_var_test
  )
)
readr::write_csv(metrics, OUT_METRICS)

# -------------------- PASS/FAIL table --------------------
pred_files_present <- (file.exists(P_VAL) || file.exists(P_VAL_CAL)) && (file.exists(P_TEST) || file.exists(P_TEST_CAL))

checks <- tibble::tibble(
  check = c(
    "pred_files_present_(val,test)",
    "one_positive_label_per_play",
    "probabilities_in_[0,1]_and_non_degenerate",
    "coverage_val_matches_leverage_plays",
    "coverage_test_matches_leverage_plays",
    "top1_val_>=_random_baseline(+margin)",
    "top1_test_>=_random_baseline(+margin)",
    "mrr_val_>=_random_baseline(+margin)",
    "mrr_test_>=_random_baseline(+margin)",
    "model_object_loads_and_predicts"
  ),
  status = c(
    pass(pred_files_present),
    pass(isTRUE(one_winner)),
    pass(p_in_range && isTRUE(p_nonconst_val) && isTRUE(p_nonconst_test)),
    if (is.na(plays_lev_val))  skip() else pass(coverage_val_ok),
    if (is.na(plays_lev_test)) skip() else pass(coverage_test_ok),
    pass(isTRUE(t1_val_ok)),
    pass(isTRUE(t1_test_ok)),
    pass(isTRUE(mrr_val_ok)),
    pass(isTRUE(mrr_test_ok)),
    if (is.na(pred_sanity_ok)) skip() else pass(isTRUE(pred_sanity_ok))
  ),
  details = c(
    paste("val:", ifelse(file.exists(P_VAL),"raw","(cal)"),
          "| test:", ifelse(file.exists(P_TEST),"raw","(cal)")),
    "exactly one y==1 per (game_id, play_id)",
    sprintf("p_valid=%s | var_val=%.4g | var_test=%.4g",
            p_in_range, p_var_val, p_var_test),
    sprintf("pred_val=%d vs lev_val=%d", plays_pred_val, plays_lev_val),
    sprintf("pred_test=%d vs lev_test=%d", plays_pred_test, plays_lev_test),
    sprintf("top1=%.4f vs base=%.4f (plays=%d)", t1_val, base_val$top1, n_plays_val),
    sprintf("top1=%.4f vs base=%.4f (plays=%d)", t1_test, base_test$top1, n_plays_test),
    sprintf("mrr=%.4f vs base=%.4f (plays=%d)", mrr_val, base_val$mrr, n_plays_val),
    sprintf("mrr=%.4f vs base=%.4f (plays=%d)", mrr_test, base_test$mrr, n_plays_test),
    pred_sanity_note
  )
)

readr::write_csv(checks, OUT_STATUS_CSV)
writeLines(c("# Model 04 Training Verification — Status", "", md_table(checks)), OUT_STATUS_MD, useBytes = TRUE)

# -------------------- Report --------------------
rep <- c(
  "# Model 04 — Training Verification",
  "",
  "## Coverage",
  sprintf("- Plays (val): preds=%d | leverage=%d", plays_pred_val, plays_lev_val),
  sprintf("- Plays (test): preds=%d | leverage=%d", plays_pred_test, plays_lev_test),
  "",
  "## Performance vs random baseline",
  sprintf("- Top-1 (val):  model=%.4f | random=%.4f", t1_val,  base_val$top1),
  sprintf("- Top-1 (test): model=%.4f | random=%.4f", t1_test, base_test$top1),
  sprintf("- MRR   (val):  model=%.4f | random=%.4f", mrr_val,  base_val$mrr),
  sprintf("- MRR   (test): model=%.4f | random=%.4f", mrr_test, base_test$mrr),
  "",
  "## Notes",
  "- Random baselines computed per-play using defenders-per-play (Top-1 = mean(1/N); MRR = mean(H_N/N)).",
  "- Margin for superiority is 1pp if ≥50 plays; otherwise ties allowed due to small-sample noise.",
  if (is.na(pred_sanity_ok)) "- Predict sanity skipped due to missing features in leverage dataset." else "- Predict sanity completed on a small sample from leverage dataset."
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

# -------------------- Hard stop on FAIL --------------------
if (any(checks$status == "FAIL")) {
  print(checks)
  stop("Model 04 training verification: FAIL. See artifacts/model04_training_verification_status.{csv,md}", call. = FALSE)
}
message("Model 04 training verification: PASS.")

