B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

P_VAL   <- file.path(DIRS$artifacts, "model04_val_preds.csv")
P_TEST  <- file.path(DIRS$artifacts, "model04_test_preds.csv")
P_MODEL <- file.path(DIRS$artifacts, "model04_model_rds.rds")

OUT_CALIB     <- file.path(DIRS$artifacts, "model04_calibration_glm.rds")
OUT_VAL_CAL   <- file.path(DIRS$artifacts, "model04_val_preds_cal.csv")
OUT_TST_CAL   <- file.path(DIRS$artifacts, "model04_test_preds_cal.csv")
OUT_METRICS   <- file.path(DIRS$artifacts, "model04_calibration_metrics.csv")
OUT_REPORT    <- file.path(DIRS$artifacts, "model04_calibration_report.md")
OUT_STATUS    <- file.path(DIRS$artifacts, "model04_calibration_status.csv")
OUT_STATUS_MD <- file.path(DIRS$artifacts, "model04_calibration_status.md")

req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
req(P_VAL,  "model04_val_preds.csv"); req(P_TEST, "model04_test_preds.csv"); req(P_MODEL,"model04_model_rds.rds")

read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()
val <- read_csv_clean(P_VAL)  |> mutate(game_id=as.character(game_id), play_id=as.integer(play_id), nfl_id=as.integer(nfl_id))
tst <- read_csv_clean(P_TEST) |> mutate(game_id=as.character(game_id), play_id=as.integer(play_id), nfl_id=as.integer(nfl_id))

need <- c("game_id","play_id","nfl_id","y","p_go")
miss <- setdiff(need, names(val)); if (length(miss)) stop("VAL missing cols: ", paste(miss, collapse=", "))
miss <- setdiff(need, names(tst)); if (length(miss)) stop("TEST missing cols: ", paste(miss, collapse=", "))

# ---------- helpers ----------
clip01 <- function(x, eps = 1e-6) pmin(pmax(x, eps), 1 - eps)
logit  <- function(p) log(clip01(p)/(1-clip01(p)))
logloss <- function(y, p) { y <- as.numeric(y); -mean(y*log(clip01(p)) + (1-y)*log(clip01(1-p))) }
brier   <- function(y, p) mean((p - y)^2)
ece <- function(y, p, bins = 10) {
  b <- cut(p, breaks = seq(0,1,length.out=bins+1), include.lowest = TRUE, labels = FALSE)
  n <- length(y); e <- 0
  for (i in 1:bins) {
    idx <- which(b == i); if (!length(idx)) next
    p_bar <- mean(p[idx]); y_bar <- mean(y[idx]); e <- e + (length(idx)/n)*abs(p_bar - y_bar)
  }
  e
}
top1_acc <- function(df, pcol = "p_go") {
  df |>
    mutate(key = paste(game_id, play_id), p = .data[[pcol]]) |>
    group_by(key) |>
    mutate(r = rank(-p, ties.method = "first")) |>
    summarise(hit = as.integer(any(y == 1 & r == 1)), .groups = "drop") |>
    summarise(mean(hit)) |> pull()
}

# ---------- fit calibration on validation (using a clean 'p' column) ----------
y_val <- as.integer(val$y)
p_val_raw <- as.numeric(val$p_go)
calib_glm <- NULL
if (length(unique(y_val)) >= 2) {
  df_cal <- data.frame(y = y_val, p = p_val_raw)
  calib_glm <- glm(y ~ logit(p), data = df_cal, family = binomial())
  saveRDS(calib_glm, OUT_CALIB)
} else {
  warning("Validation has single class; using identity calibration (no change).")
}

predict_cal <- function(p_raw, model) {
  if (is.null(model)) return(p_raw)
  as.numeric(predict(model, newdata = data.frame(p = p_raw), type = "response"))
}

val$p_cal <- predict_cal(val$p_go, calib_glm)
tst$p_cal <- predict_cal(tst$p_go, calib_glm)

# ---------- metrics before/after ----------
mk_metrics <- function(df_raw, split_name){
  tibble(
    split = split_name,
    metric = c("logloss","brier","ece","top1_acc","avg_p","var_p"),
    raw = c(
      logloss(df_raw$y, df_raw$p_go),
      brier(df_raw$y, df_raw$p_go),
      ece(df_raw$y, df_raw$p_go, bins = 10),
      top1_acc(df_raw, "p_go"),
      mean(df_raw$p_go), var(df_raw$p_go)
    ),
    cal = c(
      logloss(df_raw$y, df_raw$p_cal),
      brier(df_raw$y, df_raw$p_cal),
      ece(df_raw$y, df_raw$p_cal, bins = 10),
      top1_acc(df_raw, "p_cal"),
      mean(df_raw$p_cal), var(df_raw$p_cal)
    )
  )
}
M_val  <- mk_metrics(val,  "val")
M_test <- mk_metrics(tst,  "test")
M_all  <- bind_rows(M_val, M_test)
readr::write_csv(M_all, OUT_METRICS)

# ---------- PASS/FAIL ----------
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
getM <- function(s, m, col) M_all %>% filter(split==s, metric==m) %>% pull({{col}})

checks <- tibble(
  check = c(
    "calibration_fit_or_identity",
    "ECE_val_not_worse",
    "LogLoss_val_not_worse_+0.01_tolerance",
    "Top1_val_unchanged_after_calibration"
  ),
  status = c(
    pass(TRUE),
    pass(getM("val","ece", cal) <= getM("val","ece", raw) + 1e-9),
    pass(getM("val","logloss", cal) <= getM("val","logloss", raw) + 0.01),
    pass(abs(getM("val","top1_acc", cal) - getM("val","top1_acc", raw)) < 1e-12)
  ),
  details = c(
    if (is.null(calib_glm)) "identity mapping (single-class val)" else "Platt glm fitted on val",
    sprintf("ECE val: raw=%.4f cal=%.4f", getM("val","ece", raw), getM("val","ece", cal)),
    sprintf("LogLoss val: raw=%.4f cal=%.4f", getM("val","logloss", raw), getM("val","logloss", cal)),
    sprintf("Top1 val: raw=%.4f cal=%.4f", getM("val","top1_acc", raw), getM("val","top1_acc", cal))
  )
)
readr::write_csv(checks, OUT_STATUS)
writeLines(c("# Model 04 calibration status", "", md_table(checks)), OUT_STATUS_MD, useBytes = TRUE)

# ---------- save calibrated preds + report ----------
readr::write_csv(val, OUT_VAL_CAL)
readr::write_csv(tst, OUT_TST_CAL)

rep <- c(
  "# Model 04 — Calibration & verification",
  "",
  "## Validation",
  sprintf("- ECE: raw=%.4f | cal=%.4f", getM("val","ece", raw), getM("val","ece", cal)),
  sprintf("- LogLoss: raw=%.4f | cal=%.4f", getM("val","logloss", raw), getM("val","logloss", cal)),
  sprintf("- Top-1 (invariant): raw=%.4f | cal=%.4f", getM("val","top1_acc", raw), getM("val","top1_acc", cal)),
  "",
  "## Test",
  sprintf("- ECE: raw=%.4f | cal=%.4f", getM("test","ece", raw), getM("test","ece", cal)),
  sprintf("- LogLoss: raw=%.4f | cal=%.4f", getM("test","logloss", raw), getM("test","logloss", cal)),
  sprintf("- Top-1 (invariant): raw=%.4f | cal=%.4f", getM("test","top1_acc", raw), getM("test","top1_acc", cal)),
  "",
  "## Files",
  paste0("- ", OUT_CALIB),
  paste0("- ", OUT_VAL_CAL),
  paste0("- ", OUT_TST_CAL),
  paste0("- ", OUT_METRICS),
  paste0("- ", OUT_STATUS, " + ", OUT_STATUS_MD)
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

message("Wrote:",
        "\n  - ", OUT_CALIB,
        "\n  - ", OUT_VAL_CAL,
        "\n  - ", OUT_TST_CAL,
        "\n  - ", OUT_METRICS,
        "\n  - ", OUT_STATUS, " and ", OUT_STATUS_MD,
        "\n  - ", OUT_REPORT,
        "\nDone.")

# ---- One-line verdict for calibration verification ----
suppressPackageStartupMessages({ library(readr); library(janitor) })
status_tbl <- tryCatch(readr::read_csv(OUT_STATUS, show_col_types = FALSE) |> janitor::clean_names(),
                       error = function(e) NULL)
if (!is.null(status_tbl) && nrow(status_tbl)) {
  all_ok <- all(status_tbl$status %in% c("PASS","SKIP"))
  print(status_tbl)
  if (!all_ok) stop("Model 04 calibration verification: FAIL (see table above).", call. = FALSE)
  message("Model 04 calibration verification: PASS.")
} else {
  warning("No status table found to summarize. Did the script write ", OUT_STATUS, "?")
}










# 09_observed_vs_optimal.R
# Purpose: Compare observed defender choice vs optimal (by calibrated assignment prob).
# Inputs:
#   - ./artifacts/model04_leverage_dataset.csv
#   - ./artifacts/model04_val_preds_cal.csv   (preferred) or ./artifacts/model04_val_preds.csv
#   - ./artifacts/model04_test_preds_cal.csv  (preferred) or ./artifacts/model04_test_preds.csv
# Outputs:
#   - ./artifacts/endgame_observed_vs_optimal.csv
#   - ./artifacts/endgame_summary.csv
#   - ./artifacts/endgame_report.md
#   - ./artifacts/endgame_status.csv
#   - ./artifacts/endgame_status.md
# Assumption: current working directory is the project root.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
ART <- B("artifacts")
invisible(dir.create(ART, recursive = TRUE, showWarnings = FALSE))

# -------------------- 1) Paths --------------------
PATH_LEV   <- file.path(ART, "model04_leverage_dataset.csv")

VAL_CAL    <- file.path(ART, "model04_val_preds_cal.csv")
VAL_RAW    <- file.path(ART, "model04_val_preds.csv")

TEST_CAL   <- file.path(ART, "model04_test_preds_cal.csv")
TEST_RAW   <- file.path(ART, "model04_test_preds.csv")

OUT_PLAYS  <- file.path(ART, "endgame_observed_vs_optimal.csv")
OUT_SUM    <- file.path(ART, "endgame_summary.csv")
OUT_REP    <- file.path(ART, "endgame_report.md")
OUT_STAT   <- file.path(ART, "endgame_status.csv")
OUT_STATMD <- file.path(ART, "endgame_status.md")

req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
req(PATH_LEV, "model04_leverage_dataset.csv")
if (!file.exists(VAL_CAL) && !file.exists(VAL_RAW)) stop("Need either model04_val_preds_cal.csv or model04_val_preds.csv")
if (!file.exists(TEST_CAL) && !file.exists(TEST_RAW)) stop("Need either model04_test_preds_cal.csv or model04_test_preds.csv")

# -------------------- 2) Load data --------------------
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

lev <- read_csv_clean(PATH_LEV) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id)),
    split   = tolower(as.character(split))
  )

load_preds <- function(cal_path, raw_path, assumed_split){
  if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    if (!("p_cal" %in% names(df))) stop("Calibrated file present but no p_cal column: ", cal_path, call. = FALSE)
    df <- df |> mutate(p_used = as.numeric(p_cal))
  } else {
    df <- read_csv_clean(raw_path)
    if (!("p_go" %in% names(df))) stop("Raw preds file missing p_go: ", raw_path, call. = FALSE)
    df <- df |> mutate(p_used = as.numeric(p_go))
  }
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      split   = assumed_split
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_used)
}

pred_val  <- load_preds(VAL_CAL,  VAL_RAW,  "val")
pred_test <- load_preds(TEST_CAL, TEST_RAW, "test")
preds <- bind_rows(pred_val, pred_test)

need_cols <- c("game_id","play_id","nfl_id","split","y","p_used")
miss <- setdiff(need_cols, names(preds))
if (length(miss)) stop("Predictions missing columns: ", paste(miss, collapse=", "), call. = FALSE)

# -------------------- 3) Build observed and optimal selections --------------------
# observed: y==1 row per (game_id,play_id,split)
obs_check <- preds |>
  filter(y == 1) |>
  count(game_id, play_id, split, name = "n") |>
  filter(n != 1)
if (nrow(obs_check)) stop("Some plays don't have exactly one observed winner in preds. Investigate label construction.", call. = FALSE)

observed <- preds |>
  filter(y == 1) |>
  select(game_id, play_id, split, nfl_id_obs = nfl_id, p_go_obs = p_used)

# optimal: argmax p_used within each play
optimal <- preds |>
  group_by(game_id, play_id, split) |>
  slice_max(order_by = p_used, n = 1, with_ties = FALSE) |>
  ungroup() |>
  transmute(game_id, play_id, split, nfl_id_opt = nfl_id, p_go_opt = p_used)

# -------------------- 4) Join context (distances & Model 03 contest probs) --------------------
need_lev <- c("game_id","play_id","nfl_id","split","d_arrival","p03_primary","p03_1p0","contest_primary")
miss_lev <- setdiff(need_lev, names(lev))
if (length(miss_lev)) stop("Leverage dataset missing columns: ", paste(miss_lev, collapse=", "), call. = FALSE)

lev_small <- lev |> select(all_of(need_lev))

obs_ctx <- observed |>
  left_join(lev_small, by = c("game_id","play_id","split"), relationship = "many-to-many") |>
  filter(nfl_id == nfl_id_obs) |>
  select(-nfl_id) |>
  rename(d_arrival_obs = d_arrival,
         p03_primary_obs = p03_primary,
         p03_1p0_obs     = p03_1p0,
         contest_primary_obs = contest_primary)

opt_ctx <- optimal |>
  left_join(lev_small, by = c("game_id","play_id","split"), relationship = "many-to-many") |>
  filter(nfl_id == nfl_id_opt) |>
  select(-nfl_id) |>
  rename(d_arrival_opt = d_arrival,
         p03_primary_opt = p03_primary,
         p03_1p0_opt     = p03_1p0,
         contest_primary_opt = contest_primary)

# -------------------- 5) Build per-play comparison --------------------
cmp <- obs_ctx |>
  inner_join(opt_ctx, by = c("game_id","play_id","split")) |>
  mutate(
    same_choice = as.integer(nfl_id_obs == nfl_id_opt),
    delta_d_arrival = d_arrival_opt - d_arrival_obs,          # negative means optimal is closer
    delta_p03_primary = p03_primary_opt - p03_primary_obs,    # positive means higher contest chance
    delta_p03_1p0     = p03_1p0_opt     - p03_1p0_obs
  ) |>
  arrange(split, game_id, play_id)

readr::write_csv(cmp, OUT_PLAYS)

# -------------------- 6) Summaries (robust, no weighted.mean pitfalls) --------------------
# Per-split
sum_by_split <- cmp |>
  group_by(split) |>
  summarise(
    plays            = n(),
    agree_rate       = mean(same_choice, na.rm = TRUE),
    mean_delta_d     = mean(delta_d_arrival, na.rm = TRUE),
    median_delta_d   = median(delta_d_arrival, na.rm = TRUE),
    mean_delta_p     = mean(delta_p03_primary, na.rm = TRUE),
    median_delta_p   = median(delta_p03_primary, na.rm = TRUE),
    obs_contest_rate = mean(contest_primary_obs, na.rm = TRUE),
    opt_avg_p03      = mean(p03_primary_opt, na.rm = TRUE),
    obs_avg_p03      = mean(p03_primary_obs, na.rm = TRUE),
    .groups = "drop"
  )

# Overall computed directly from the full comparison table
sum_overall <- tibble::tibble(
  split            = "overall",
  plays            = nrow(cmp),
  agree_rate       = mean(cmp$same_choice, na.rm = TRUE),
  mean_delta_d     = mean(cmp$delta_d_arrival, na.rm = TRUE),
  median_delta_d   = median(cmp$delta_d_arrival, na.rm = TRUE),
  mean_delta_p     = mean(cmp$delta_p03_primary, na.rm = TRUE),
  median_delta_p   = median(cmp$delta_p03_primary, na.rm = TRUE),
  obs_contest_rate = mean(cmp$contest_primary_obs, na.rm = TRUE),
  opt_avg_p03      = mean(cmp$p03_primary_opt, na.rm = TRUE),
  obs_avg_p03      = mean(cmp$p03_primary_obs, na.rm = TRUE)
)

summary_all <- bind_rows(sum_by_split, sum_overall)
readr::write_csv(summary_all, OUT_SUM)

# -------------------- 7) Report --------------------
rep <- c(
  "# Observed vs Optimal (Endgame)",
  "",
  sprintf("- Plays compared: %s", comma(nrow(cmp))),
  sprintf("- Agreement rate (obs == opt): %0.3f", summary_all$agree_rate[summary_all$split=="overall"]),
  sprintf("- Δ d_arrival (opt - obs): mean=%0.3f, median=%0.3f (negative is better)",
          summary_all$mean_delta_d[summary_all$split=="overall"],
          summary_all$median_delta_d[summary_all$split=="overall"]),
  sprintf("- Δ P(contest 1.5yd) (opt - obs): mean=%0.3f, median=%0.3f",
          summary_all$mean_delta_p[summary_all$split=="overall"],
          summary_all$median_delta_p[summary_all$split=="overall"]),
  "",
  "## Split detail",
  paste0("- val:   plays=", summary_all$plays[summary_all$split=="val"],
         ", agree=", signif(summary_all$agree_rate[summary_all$split=="val"],3),
         ", mean Δd=", signif(summary_all$mean_delta_d[summary_all$split=="val"],3),
         ", mean ΔP=", signif(summary_all$mean_delta_p[summary_all$split=="val"],3)),
  paste0("- test:  plays=", summary_all$plays[summary_all$split=="test"],
         ", agree=", signif(summary_all$agree_rate[summary_all$split=="test"],3),
         ", mean Δd=", signif(summary_all$mean_delta_d[summary_all$split=="test"],3),
         ", mean ΔP=", signif(summary_all$mean_delta_p[summary_all$split=="test"],3)),
  "",
  "## Files",
  paste0("- ", OUT_PLAYS),
  paste0("- ", OUT_SUM)
)
writeLines(rep, OUT_REP, useBytes = TRUE)

message("Wrote:",
        "\n  - ", OUT_PLAYS,
        "\n  - ", OUT_SUM,
        "\n  - ", OUT_REP)

# -------------------- 8) PASS/FAIL gate --------------------
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

plays_pred_val  <- preds |> filter(split=="val")  |> summarise(n=n_distinct(paste(game_id,play_id))) |> pull(n)
plays_pred_test <- preds |> filter(split=="test") |> summarise(n=n_distinct(paste(game_id,play_id))) |> pull(n)
plays_cmp_val   <- cmp   |> filter(split=="val")  |> summarise(n=n_distinct(paste(game_id,play_id))) |> pull(n)
plays_cmp_test  <- cmp   |> filter(split=="test") |> summarise(n=n_distinct(paste(game_id,play_id))) |> pull(n)

checks <- tibble::tibble(
  check = c(
    "val_all_plays_have_comparison",
    "test_all_plays_have_comparison",
    "no_missing_deltas",
    "nonzero_play_counts"
  ),
  status = c(
    pass(plays_cmp_val  == plays_pred_val),
    pass(plays_cmp_test == plays_pred_test),
    pass(all(is.finite(cmp$delta_d_arrival)) && all(is.finite(cmp$delta_p03_primary))),
    pass(nrow(summary_all) > 0 && sum(summary_all$plays[summary_all$split %in% c("val","test")], na.rm = TRUE) > 0)
  ),
  details = c(
    sprintf("pred_val=%d vs cmp_val=%d", plays_pred_val, plays_cmp_val),
    sprintf("pred_test=%d vs cmp_test=%d", plays_pred_test, plays_cmp_test),
    sprintf("NA delta_d=%s | NA delta_p=%s",
            sum(!is.finite(cmp$delta_d_arrival)), sum(!is.finite(cmp$delta_p03_primary))),
    paste("splits=", paste(unique(cmp$split), collapse=","))
  )
)

readr::write_csv(checks, OUT_STAT)
writeLines(c("# Endgame verification status", "", md_table(checks)), OUT_STATMD, useBytes = TRUE)

print(checks)
if (any(checks$status == "FAIL")) stop("Endgame verification failed. See artifacts/endgame_status.*", call. = FALSE)
message("Endgame verification: PASS.")










# 10_reporting_rollups.R
# Purpose: Turn endgame results into deliverables: per-play table, split/team/position summaries.
# Robust behavior:
#   - If no roster file exists, auto-build a roster from leverage dataset columns.
#   - If no team/position info exists anywhere, synthesize UNKNOWN teams/positions so rollups never skip.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
ART <- B("artifacts"); invisible(dir.create(ART, recursive = TRUE, showWarnings = FALSE))
DAT <- B("data")

# -------------------- 1) Paths --------------------
P_END   <- file.path(ART, "endgame_observed_vs_optimal.csv")
P_LEV   <- file.path(ART, "model04_leverage_dataset.csv")

# Roster candidates (any one of these will do)
ROSTER_CANDIDATES <- c(
  file.path(ART, "roster_map.csv"),
  file.path(DAT, "roster_map.csv"),
  file.path(ART, "roster.csv"),
  file.path(DAT, "roster.csv"),
  file.path(ART, "players.csv"),
  file.path(DAT, "players.csv")
)

OUT_PLAY     <- file.path(ART, "report_per_play.csv")
OUT_SPLIT    <- file.path(ART, "report_split_summary.csv")
OUT_TEAM     <- file.path(ART, "report_team_summary.csv")
OUT_POS      <- file.path(ART, "report_position_summary.csv")
OUT_STATUS   <- file.path(ART, "reporting_status.csv")
OUT_STATUSMD <- file.path(ART, "reporting_status.md")
OUT_NOTES    <- file.path(ART, "reporting_notes.md")

# -------------------- 2) Load inputs --------------------
req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
req(P_END, "endgame_observed_vs_optimal.csv")

read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

cmp <- read_csv_clean(P_END) |>
  mutate(
    game_id   = as.character(game_id),
    play_id   = suppressWarnings(as.integer(play_id)),
    split     = tolower(as.character(split)),
    nfl_id_obs = suppressWarnings(as.integer(nfl_id_obs)),
    nfl_id_opt = suppressWarnings(as.integer(nfl_id_opt))
  )

# -------------------- 3) Per-play deliverable (no extra joins = no collisions) --------------------
per_play <- cmp |>
  mutate(
    agree_flag = as.integer(same_choice == 1),
    lift_p03   = delta_p03_primary,     # positive = optimal has higher P(contest 1.5)
    lift_d     = -delta_d_arrival       # positive = optimal is closer at arrival
  ) |>
  select(
    game_id, play_id, split,
    nfl_id_obs, nfl_id_opt, agree_flag,
    d_arrival_obs, d_arrival_opt, delta_d_arrival, lift_d,
    p03_primary_obs, p03_primary_opt, delta_p03_primary, lift_p03,
    p03_1p0_obs, p03_1p0_opt, delta_p03_1p0,
    p_go_obs, p_go_opt,
    contest_primary_obs, contest_primary_opt
  )

readr::write_csv(per_play, OUT_PLAY)

# -------------------- 4) Split-level summary --------------------
split_summary <- per_play |>
  group_by(split) |>
  summarise(
    plays            = n(),
    agree_rate       = mean(agree_flag, na.rm = TRUE),
    mean_lift_d      = mean(lift_d, na.rm = TRUE),
    median_lift_d    = median(lift_d, na.rm = TRUE),
    mean_lift_p03    = mean(lift_p03, na.rm = TRUE),
    median_lift_p03  = median(lift_p03, na.rm = TRUE),
    obs_contest_rate = mean(contest_primary_obs, na.rm = TRUE),
    opt_avg_p03      = mean(p03_primary_opt, na.rm = TRUE),
    obs_avg_p03      = mean(p03_primary_obs, na.rm = TRUE),
    .groups = "drop"
  )
readr::write_csv(split_summary, OUT_SPLIT)

# -------------------- 5) Roster handling: read, auto-build, or synthesize --------------------
# Safe extractor: first existing column among choices, else NA vector
pick_col <- function(df, choices) {
  nm <- choices[choices %in% names(df)]
  if (length(nm)) df[[nm[1]]] else rep(NA, nrow(df))
}

# Try to read any provided roster file
read_roster_candidate <- function(paths) {
  cand <- paths[file.exists(paths)]
  if (!length(cand)) return(NULL)
  read_csv_clean(cand[1]) |> clean_names()
}
roster_raw <- read_roster_candidate(ROSTER_CANDIDATES)

# If no roster file, try to auto-build from leverage dataset
if (is.null(roster_raw)) {
  if (file.exists(P_LEV)) {
    lev <- read_csv_clean(P_LEV) |> clean_names()
    team_candidates <- intersect(names(lev), c(
      "def_team","team","team_abbr","club_code","club","team_name","defense_team","defteam","unit_team"
    ))
    pos_candidates <- intersect(names(lev), c(
      "position","pos","position_group","positiongroup","pfr_position","gsis_position","role"
    ))
    if (length(team_candidates)) {
      roster_raw <- tibble(
        nfl_id  = suppressWarnings(as.integer(lev$nfl_id)),
        team    = as.character(lev[[team_candidates[1]]]),
        position= if (length(pos_candidates)) as.character(lev[[pos_candidates[1]]]) else NA_character_
      ) |>
        filter(!is.na(nfl_id), nzchar(team)) |>
        distinct(nfl_id, .keep_all = TRUE)
    }
  }
}

# If still nothing, synthesize a minimal roster so rollups don't skip
if (is.null(roster_raw) || !nrow(roster_raw)) {
  ids <- sort(unique(c(per_play$nfl_id_obs, per_play$nfl_id_opt)))
  roster_raw <- tibble(
    nfl_id = as.integer(ids),
    team = "UNKNOWN",
    position = NA_character_
  )
}

# Normalize roster columns using safe picks
rr <- roster_raw |> clean_names()
roster <- tibble(
  nfl_id  = suppressWarnings(as.integer(pick_col(rr, c("nfl_id","player_id","nflid","gsis_id","pff_id")))),
  team    = as.character(pick_col(rr, c("team","team_abbr","team_code","team_name","club_code","club","team_short","def_team"))),
  position= as.character(pick_col(rr, c("position","pos","position_group","positiongroup","pfr_position","gsis_position","role")))
) |>
  mutate(
    team = if_else(is.na(team) | !nzchar(team), "UNKNOWN", team),
    position = if_else(is.na(position) | !nzchar(position), "UNKNOWN", position)
  ) |>
  filter(!is.na(nfl_id)) |>
  distinct(nfl_id, .keep_all = TRUE)

# -------------------- 6) Team and position rollups --------------------
per_play_team <- per_play |>
  left_join(roster, by = c("nfl_id_obs" = "nfl_id")) |>
  rename(team_obs = team, position_obs = position) |>
  left_join(roster |> rename(nfl_id_opt2 = nfl_id, team_opt = team, position_opt = position),
            by = c("nfl_id_opt" = "nfl_id_opt2")) |>
  mutate(
    team_obs  = if_else(is.na(team_obs) | !nzchar(team_obs), "UNKNOWN", team_obs),
    team_opt  = if_else(is.na(team_opt) | !nzchar(team_opt), "UNKNOWN", team_opt),
    position_obs = if_else(is.na(position_obs) | !nzchar(position_obs), "UNKNOWN", position_obs),
    team_mismatch = as.integer(!is.na(team_obs) & !is.na(team_opt) & team_obs != team_opt)
  )

team_summary <- per_play_team |>
  group_by(split, team = team_obs) |>
  summarise(
    plays          = n(),
    agree_rate     = mean(agree_flag, na.rm = TRUE),
    mean_lift_d    = mean(lift_d, na.rm = TRUE),
    mean_lift_p03  = mean(lift_p03, na.rm = TRUE),
    team_mismatch_rate = mean(team_mismatch, na.rm = TRUE),
    .groups = "drop"
  ) |>
  arrange(split, desc(plays))
readr::write_csv(team_summary, OUT_TEAM)

pos_summary <- per_play_team |>
  group_by(split, position = position_obs) |>
  summarise(
    plays          = n(),
    agree_rate     = mean(agree_flag, na.rm = TRUE),
    mean_lift_d    = mean(lift_d, na.rm = TRUE),
    mean_lift_p03  = mean(lift_p03, na.rm = TRUE),
    .groups = "drop"
  ) |>
  arrange(split, desc(plays))
readr::write_csv(pos_summary, OUT_POS)

# -------------------- 7) PASS/FAIL verification --------------------
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

split_counts <- per_play |> count(split, name = "plays")

det_team <- if (nrow(team_summary)) "generated" else "EMPTY"
det_pos  <- if (nrow(pos_summary)) "generated" else "EMPTY"

checks <- tibble::tibble(
  check = c(
    "per_play_rows>0",
    "no_NA_key_deltas",
    "split_summary_matches_counts",
    "team_rollup_generated",
    "position_rollup_generated"
  ),
  status = c(
    pass(nrow(per_play) > 0),
    pass(all(is.finite(per_play$delta_d_arrival)) & all(is.finite(per_play$delta_p03_primary))),
    pass({
      s1 <- split_summary |> arrange(split)
      s2 <- split_counts   |> arrange(split)
      all(s1$split == s2$split) && all(s1$plays == s2$plays)
    }),
    pass(nrow(team_summary) > 0),
    pass(nrow(pos_summary)  > 0)
  ),
  details = c(
    sprintf("rows=%d", nrow(per_play)),
    sprintf("NA delta_d=%d | NA delta_p=%d",
            sum(!is.finite(per_play$delta_d_arrival)),
            sum(!is.finite(per_play$delta_p03_primary))),
    "split counts equal",
    det_team,
    det_pos
  )
)

readr::write_csv(checks, OUT_STATUS)
writeLines(c("# Reporting status", "", md_table(checks)), OUT_STATUSMD, useBytes = TRUE)

# -------------------- 8) Notes/report --------------------
notes <- c(
  "# Reporting & rollups",
  "",
  "- `report_per_play.csv` is the clean per-play deliverable with observed vs optimal, deltas, and calibrated probs.",
  "- `report_split_summary.csv` gives val/test aggregates for agreement and lifts.",
  "- `report_team_summary.csv` and `report_position_summary.csv` are always produced.",
  if (file.exists(P_LEV)) "- Roster was sourced or auto-built from leverage dataset when needed." else "- Roster synthesized (UNKNOWN) due to no team info found.",
  ""
)
writeLines(notes, OUT_NOTES, useBytes = TRUE)

message("Wrote:",
        "\n  - ", OUT_PLAY,
        "\n  - ", OUT_SPLIT,
        "\n  - ", OUT_TEAM,
        "\n  - ", OUT_POS,
        "\n  - ", OUT_STATUS, " and ", OUT_STATUSMD,
        "\n  - ", OUT_NOTES,
        "\nDone.")










# 11_leverage_index.R
# What it does (2–4 sentences):
# Computes a Leverage Index showing how much lift you'd get by following the optimal assignment vs observed.
# Uses calibrated assignment choices from endgame files to define “optimal”, and p03_primary (1.5 yd) for expected ΔP(contest)
# with p03_1p0 as a secondary column. Produces player- and team-level CSVs, a short report, and a PASS/FAIL gate that stops on FAIL.

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"), data = B("data"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# Inputs
P_LEV <- file.path(DIRS$artifacts, "model04_leverage_dataset.csv")
P_END <- file.path(DIRS$artifacts, "endgame_observed_vs_optimal.csv")

# Roster candidates (reuse Script 10 policy)
ROSTER_CANDIDATES <- c(
  file.path(DIRS$artifacts, "roster_map.csv"),
  file.path(DIRS$data,      "roster_map.csv"),
  file.path(DIRS$artifacts, "roster.csv"),
  file.path(DIRS$data,      "roster.csv"),
  file.path(DIRS$artifacts, "players.csv"),
  file.path(DIRS$data,      "players.csv")
)

# Outputs
OUT_PLAYER <- file.path(DIRS$artifacts, "player_leverage_index.csv")
OUT_TEAM   <- file.path(DIRS$artifacts, "team_leverage_index.csv")
OUT_STAT   <- file.path(DIRS$artifacts, "leverage_index_status.csv")
OUT_STATMD <- file.path(DIRS$artifacts, "leverage_index_status.md")
OUT_REP    <- file.path(DIRS$artifacts, "leverage_index_report.md")

# Config
N_MIN_OPT <- 20  # min # of optimal opportunities to include a player

# -------------------- Helpers --------------------
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"

pick_col <- function(df, choices) {
  nm <- choices[choices %in% names(df)]
  if (length(nm)) df[[nm[1]]] else rep(NA, nrow(df))
}
read_roster_candidate <- function(paths) {
  cand <- paths[file.exists(paths)]
  if (!length(cand)) return(NULL)
  read_csv_clean(cand[1]) |> clean_names()
}
req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }

# -------------------- Load --------------------
req(P_LEV, "model04_leverage_dataset.csv")
req(P_END, "endgame_observed_vs_optimal.csv")

lev <- read_csv_clean(P_LEV) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id)),
    split   = tolower(as.character(split))
  )

cmp <- read_csv_clean(P_END) |>
  mutate(
    game_id    = as.character(game_id),
    play_id    = suppressWarnings(as.integer(play_id)),
    split      = tolower(as.character(split)),
    nfl_id_obs = suppressWarnings(as.integer(nfl_id_obs)),
    nfl_id_opt = suppressWarnings(as.integer(nfl_id_opt))
  )

need_lev <- c("game_id","play_id","nfl_id","split")
miss_lev <- setdiff(need_lev, names(lev))
if (length(miss_lev)) stop("Leverage dataset missing columns: ", paste(miss_lev, collapse=", "))

need_cmp <- c("game_id","play_id","split","nfl_id_obs","nfl_id_opt",
              "p03_primary_obs","p03_primary_opt","p03_1p0_obs","p03_1p0_opt",
              "delta_p03_primary","delta_p03_1p0")
miss_cmp <- setdiff(need_cmp, names(cmp))
if (length(miss_cmp)) stop("Endgame comparison missing columns: ", paste(miss_cmp, collapse=", "))

# Keep only splits present in endgame; align play universe
valid_splits <- sort(unique(cmp$split))
lev_use <- lev |> filter(split %in% valid_splits) |> mutate(key = paste(game_id, play_id, split))
cmp_use <- cmp |> filter(split %in% valid_splits)
lev_use <- semi_join(lev_use, cmp_use |> transmute(key = paste(game_id, play_id, split)), by = "key")

# -------------------- Roster: file -> auto -> synthesize --------------------
roster_raw <- read_roster_candidate(ROSTER_CANDIDATES)
if (is.null(roster_raw)) {
  team_candidates <- intersect(names(lev), c("def_team","team","team_abbr","club_code","club","team_name","defense_team","defteam","unit_team"))
  pos_candidates  <- intersect(names(lev), c("position","pos","position_group","positiongroup","pfr_position","gsis_position","role"))
  if (length(team_candidates)) {
    roster_raw <- tibble(
      nfl_id  = suppressWarnings(as.integer(lev$nfl_id)),
      team    = as.character(lev[[team_candidates[1]]]),
      position= if (length(pos_candidates)) as.character(lev[[pos_candidates[1]]]) else NA_character_
    ) |>
      filter(!is.na(nfl_id), nzchar(team)) |>
      distinct(nfl_id, .keep_all = TRUE)
  }
}
if (is.null(roster_raw) || !nrow(roster_raw)) {
  ids <- sort(unique(c(lev_use$nfl_id, cmp_use$nfl_id_obs, cmp_use$nfl_id_opt)))
  roster_raw <- tibble(nfl_id = as.integer(ids), team = "UNKNOWN", position = NA_character_)
}
rr <- roster_raw |> clean_names()
roster <- tibble(
  nfl_id  = suppressWarnings(as.integer(pick_col(rr, c("nfl_id","player_id","nflid","gsis_id","pff_id")))),
  team    = as.character(pick_col(rr, c("team","team_abbr","team_code","team_name","club_code","club","team_short","def_team"))),
  position= as.character(pick_col(rr, c("position","pos","position_group","positiongroup","pfr_position","gsis_position","role")))
) |>
  mutate(
    team = if_else(is.na(team) | !nzchar(team), "UNKNOWN", team),
    position = if_else(is.na(position) | !nzchar(position), "UNKNOWN", position)
  ) |>
  filter(!is.na(nfl_id)) |>
  distinct(nfl_id, .keep_all = TRUE)

# -------------------- Player-level index --------------------
den_player <- lev_use |>
  transmute(nfl_id, split, key = paste(game_id, play_id)) |>
  distinct() |>
  count(nfl_id, split, name = "n_eligible")

opt_player <- cmp_use |> count(nfl_id_opt, split, name = "plays_optimal") |> rename(nfl_id = nfl_id_opt)
obs_player <- cmp_use |> count(nfl_id_obs, split, name = "plays_observed") |> rename(nfl_id = nfl_id_obs)
agree_player <- cmp_use |> filter(nfl_id_obs == nfl_id_opt) |>
  count(nfl_id_opt, split, name = "plays_observed_as_optimal") |> rename(nfl_id = nfl_id_opt)

lift_player <- cmp_use |>
  group_by(nfl_id_opt, split) |>
  summarise(
    exp_lift_p03 = mean(delta_p03_primary, na.rm = TRUE),
    exp_lift_p03_1p0 = mean(delta_p03_1p0, na.rm = TRUE),
    .groups = "drop"
  ) |>
  rename(nfl_id = nfl_id_opt)

player_idx_split <- den_player |>
  left_join(opt_player,  by = c("nfl_id","split")) |>
  left_join(obs_player,  by = c("nfl_id","split")) |>
  left_join(agree_player,by = c("nfl_id","split")) |>
  left_join(lift_player, by = c("nfl_id","split")) |>
  mutate(
    plays_optimal = replace_na(plays_optimal, 0L),
    plays_observed = replace_na(plays_observed, 0L),
    plays_observed_as_optimal = replace_na(plays_observed_as_optimal, 0L),
    exp_lift_p03 = replace_na(exp_lift_p03, 0),
    exp_lift_p03_1p0 = replace_na(exp_lift_p03_1p0, 0),
    observed_share = if_else(n_eligible > 0, plays_observed / n_eligible, NA_real_),
    optimal_share  = if_else(n_eligible > 0, plays_optimal  / n_eligible, NA_real_),
    usage_gap      = optimal_share - observed_share,
    n_opt_plays    = plays_optimal,
    min_opt_plays  = N_MIN_OPT
  ) |>
  left_join(roster, by = "nfl_id") |>
  select(split, nfl_id, team, position, n_eligible,
         plays_optimal, plays_observed_as_optimal,
         observed_share, optimal_share, usage_gap,
         exp_lift_p03, exp_lift_p03_1p0,
         n_opt_plays, min_opt_plays)

player_idx_overall <- lev_use |>
  transmute(nfl_id, split = "overall", key = paste(game_id, play_id)) |>
  distinct() |>
  count(nfl_id, split, name = "n_eligible") |>
  left_join(cmp_use |> count(nfl_id_opt, name = "plays_optimal") |> mutate(split="overall") |> rename(nfl_id = nfl_id_opt),
            by = c("nfl_id","split")) |>
  left_join(cmp_use |> count(nfl_id_obs, name = "plays_observed") |> mutate(split="overall") |> rename(nfl_id = nfl_id_obs),
            by = c("nfl_id","split")) |>
  left_join(cmp_use |> filter(nfl_id_obs == nfl_id_opt) |> count(nfl_id_opt, name="plays_observed_as_optimal") |> mutate(split="overall") |> rename(nfl_id = nfl_id_opt),
            by = c("nfl_id","split")) |>
  left_join(cmp_use |> group_by(nfl_id_opt) |> summarise(exp_lift_p03 = mean(delta_p03_primary, na.rm=TRUE),
                                                         exp_lift_p03_1p0 = mean(delta_p03_1p0, na.rm=TRUE),
                                                         .groups="drop") |> mutate(split="overall") |> rename(nfl_id = nfl_id_opt),
            by = c("nfl_id","split")) |>
  mutate(
    across(c(plays_optimal, plays_observed, plays_observed_as_optimal), ~replace_na(.x, 0L)),
    exp_lift_p03 = replace_na(exp_lift_p03, 0),
    exp_lift_p03_1p0 = replace_na(exp_lift_p03_1p0, 0),
    observed_share = if_else(n_eligible > 0, plays_observed / n_eligible, NA_real_),
    optimal_share  = if_else(n_eligible > 0, plays_optimal  / n_eligible, NA_real_),
    usage_gap      = optimal_share - observed_share,
    n_opt_plays    = plays_optimal,
    min_opt_plays  = N_MIN_OPT
  ) |>
  left_join(roster, by = "nfl_id") |>
  select(split, nfl_id, team, position, n_eligible,
         plays_optimal, plays_observed_as_optimal,
         observed_share, optimal_share, usage_gap,
         exp_lift_p03, exp_lift_p03_1p0,
         n_opt_plays, min_opt_plays)

player_idx_all <- bind_rows(player_idx_split, player_idx_overall) |>
  arrange(split, desc(plays_optimal))
player_idx_filtered <- player_idx_all |> filter(n_opt_plays >= N_MIN_OPT)

# -------------------- Team-level index --------------------
cmp_team <- cmp_use |>
  select(game_id, play_id, split, nfl_id_obs, nfl_id_opt, delta_p03_primary, delta_p03_1p0) |>
  left_join(roster |> select(nfl_id, team) |> rename(team_obs = team),
            by = c("nfl_id_obs" = "nfl_id")) |>
  left_join(roster |> select(nfl_id, team) |> rename(team_opt = team),
            by = c("nfl_id_opt" = "nfl_id")) |>
  mutate(
    team_obs = if_else(is.na(team_obs) | !nzchar(team_obs), "UNKNOWN", team_obs),
    team_opt = if_else(is.na(team_opt) | !nzchar(team_opt), "UNKNOWN", team_opt)
  )

plays_by_split <- cmp_team |> count(split, name = "plays")
opt_counts_split <- cmp_team |> count(split, team_opt, name = "plays_optimal") |> rename(team = team_opt)
obs_counts_split <- cmp_team |> count(split, team_obs, name = "obs_count")     |> rename(team = team_obs)
agree_counts_split <- cmp_team |>
  mutate(match = team_obs == team_opt) |>
  group_by(split, team = team_opt) |>
  summarise(plays_observed_as_optimal = sum(match, na.rm = TRUE), .groups = "drop")
lifts_split <- cmp_team |>
  group_by(split, team = team_opt) |>
  summarise(
    exp_lift_p03    = mean(delta_p03_primary, na.rm = TRUE),
    exp_lift_p03_1p0= mean(delta_p03_1p0,    na.rm = TRUE),
    .groups = "drop"
  )

team_idx_split <- opt_counts_split |>
  full_join(agree_counts_split, by = c("split","team")) |>
  full_join(lifts_split,        by = c("split","team")) |>
  left_join(plays_by_split,     by = "split") |>
  left_join(obs_counts_split,   by = c("split","team")) |>
  mutate(
    plays_optimal = replace_na(plays_optimal, 0L),
    plays_observed_as_optimal = replace_na(plays_observed_as_optimal, 0L),
    obs_count = replace_na(obs_count, 0L),
    exp_lift_p03 = replace_na(exp_lift_p03, 0),
    exp_lift_p03_1p0 = replace_na(exp_lift_p03_1p0, 0),
    observed_share = if_else(plays > 0, obs_count / plays, NA_real_),
    optimal_share  = if_else(plays > 0, plays_optimal / plays, NA_real_),
    usage_gap      = optimal_share - observed_share
  ) |>
  select(split, team, plays, plays_optimal, plays_observed_as_optimal,
         observed_share, optimal_share, usage_gap, exp_lift_p03, exp_lift_p03_1p0) |>
  arrange(split, desc(plays_optimal))

plays_overall <- nrow(cmp_team)
opt_overall   <- cmp_team |> count(team = team_opt, name = "plays_optimal")
obs_overall   <- cmp_team |> count(team = team_obs, name = "obs_count")
agree_overall <- cmp_team |>
  mutate(match = team_obs == team_opt) |>
  group_by(team = team_opt) |>
  summarise(plays_observed_as_optimal = sum(match, na.rm = TRUE), .groups = "drop")
lifts_overall <- cmp_team |>
  group_by(team = team_opt) |>
  summarise(
    exp_lift_p03    = mean(delta_p03_primary, na.rm = TRUE),
    exp_lift_p03_1p0= mean(delta_p03_1p0,    na.rm = TRUE),
    .groups = "drop"
  )

team_idx_overall <- opt_overall |>
  full_join(agree_overall, by = "team") |>
  full_join(lifts_overall,  by = "team") |>
  left_join(obs_overall,    by = "team") |>
  mutate(
    split = "overall",
    plays = plays_overall,
    across(c(plays_optimal, plays_observed_as_optimal, obs_count), ~replace_na(.x, 0L)),
    exp_lift_p03 = replace_na(exp_lift_p03, 0),
    exp_lift_p03_1p0 = replace_na(exp_lift_p03_1p0, 0),
    observed_share = if_else(plays_overall > 0, obs_count / plays_overall, NA_real_),
    optimal_share  = if_else(plays > 0, plays_optimal / plays, NA_real_),
    usage_gap      = optimal_share - observed_share
  ) |>
  select(split, team, plays, plays_optimal, plays_observed_as_optimal,
         observed_share, optimal_share, usage_gap, exp_lift_p03, exp_lift_p03_1p0) |>
  arrange(desc(plays_optimal))

team_idx_all <- bind_rows(team_idx_split, team_idx_overall)

# -------------------- Write outputs --------------------
readr::write_csv(player_idx_filtered, OUT_PLAYER)
readr::write_csv(team_idx_all,       OUT_TEAM)

# -------------------- Report --------------------
rep <- c(
  "# Leverage Index — Report",
  "",
  sprintf("- Player filter: N_MIN_OPT = %d", N_MIN_OPT),
  sprintf("- Player rows written: %s", scales::comma(nrow(player_idx_filtered))),
  sprintf("- Team rows written: %s", scales::comma(nrow(team_idx_all))),
  "",
  "## Definitions",
  "- Player observed_share   = plays_observed / n_eligible",
  "- Player optimal_share    = plays_optimal  / n_eligible",
  "- Team observed_share     = fraction of plays where observed winner’s team == team",
  "- Team optimal_share      = fraction of plays where optimal team == team",
  "- usage_gap               = optimal_share - observed_share",
  "- exp_lift_p03 / exp_lift_p03_1p0 computed where the entity was optimal."
)
writeLines(rep, OUT_REP, useBytes = TRUE)

# -------------------- Verification (PASS/FAIL) --------------------
chk1 <- all(player_idx_filtered$n_opt_plays >= N_MIN_OPT)

player_key_cols <- c("plays_optimal","plays_observed_as_optimal","observed_share","optimal_share","usage_gap","exp_lift_p03")
team_key_cols   <- c("plays_optimal","plays_observed_as_optimal","observed_share","optimal_share","usage_gap","exp_lift_p03")

chk2_players <- if (nrow(player_idx_filtered)) all(stats::complete.cases(player_idx_filtered[, player_key_cols, drop = FALSE])) else TRUE
chk2_teams   <- if (nrow(team_idx_all))       all(stats::complete.cases(team_idx_all[,       team_key_cols,   drop = FALSE])) else TRUE

plays_by_split_chk <- cmp_use |> count(split, name = "plays")
sum_team_opt <- team_idx_all |>
  group_by(split) |>
  summarise(plays_optimal_sum = sum(plays_optimal), .groups = "drop")
chk3_tbl <- plays_by_split_chk |> left_join(sum_team_opt, by = "split") |>
  mutate(ok = plays_optimal_sum == plays)
chk3 <- all(chk3_tbl$ok, na.rm = TRUE)

status <- tibble::tibble(
  check = c("player_filter_honored","no_NA_in_player_index","no_NA_in_team_index","team_optimal_counts_match_plays"),
  status = c(pass(chk1), pass(chk2_players), pass(chk2_teams), pass(chk3)),
  details = c(
    sprintf("N_MIN_OPT=%d | rows_out=%d", N_MIN_OPT, nrow(player_idx_filtered)),
    sprintf("rows=%d", nrow(player_idx_filtered)),
    sprintf("rows=%d", nrow(team_idx_all)),
    paste0("splits: ", paste(sprintf("%s(%d vs %d)", chk3_tbl$split, chk3_tbl$plays_optimal_sum, chk3_tbl$plays), collapse=", "))
  )
)

readr::write_csv(status, OUT_STAT)
writeLines(c("# Leverage Index — Status", "", md_table(status)), OUT_STATMD, useBytes = TRUE)

if (any(status$status == "FAIL")) stop("Leverage Index verification: FAIL. See artifacts/leverage_index_status.*", call. = FALSE)
message("Leverage Index verification: PASS.")










# 12_threshold_sensitivity.R
# Purpose: Threshold sensitivity for Model 03 (contest) and Model 04 (assignment).
# Outputs:
#   - artifacts/model03_threshold_sweep.csv
#   - artifacts/model04_threshold_sweep.csv
#   - artifacts/threshold_sensitivity_report.md
#   - artifacts/threshold_sensitivity_status.csv
#   - artifacts/threshold_sensitivity_status.md

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)
suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# Inputs (M03)
P_M03_VAL      <- file.path(DIRS$artifacts, "model03_val_preds.csv")
P_M03_TEST     <- file.path(DIRS$artifacts, "model03_test_preds.csv")
P_M03_VAL_1P0  <- file.path(DIRS$artifacts, "model03_val_preds_1p0.csv")
P_M03_TEST_1P0 <- file.path(DIRS$artifacts, "model03_test_preds_1p0.csv")
RDS_M03_PRI    <- file.path(DIRS$artifacts, "model03_model_rds.rds")
RDS_M03_TGT    <- file.path(DIRS$artifacts, "model03_model_rds_1p0.rds")

# Inputs (M04) – prefer calibrated, fallback to raw
P_M04_VAL_CAL  <- file.path(DIRS$artifacts, "model04_val_preds_cal.csv")
P_M04_TEST_CAL <- file.path(DIRS$artifacts, "model04_test_preds_cal.csv")
P_M04_VAL_RAW  <- file.path(DIRS$artifacts, "model04_val_preds.csv")
P_M04_TEST_RAW <- file.path(DIRS$artifacts, "model04_test_preds.csv")

# Outputs
OUT_M03   <- file.path(DIRS$artifacts, "model03_threshold_sweep.csv")
OUT_M04   <- file.path(DIRS$artifacts, "model04_threshold_sweep.csv")
OUT_REP   <- file.path(DIRS$artifacts, "threshold_sensitivity_report.md")
OUT_STAT  <- file.path(DIRS$artifacts, "threshold_sensitivity_status.csv")
OUT_STATM <- file.path(DIRS$artifacts, "threshold_sensitivity_status.md")

# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()

safe_ratio <- function(num, den) ifelse(den > 0, num/den, NA_real_)
clip01 <- function(x, eps = 1e-12) pmin(pmax(x, eps), 1 - eps)

md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"

# -------------------- Load inputs & guards --------------------
req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }

# M03
req(P_M03_VAL,     "model03_val_preds.csv")
req(P_M03_TEST,    "model03_test_preds.csv")
req(P_M03_VAL_1P0, "model03_val_preds_1p0.csv")
req(P_M03_TEST_1P0,"model03_test_preds_1p0.csv")
# RDS thresholds are optional but used for reporting if present
m03_rds_primary <- if (file.exists(RDS_M03_PRI)) readRDS(RDS_M03_PRI) else NULL
m03_rds_1p0     <- if (file.exists(RDS_M03_TGT)) readRDS(RDS_M03_TGT) else NULL

m03_val      <- read_csv_clean(P_M03_VAL)
m03_test     <- read_csv_clean(P_M03_TEST)
m03_val_1p0  <- read_csv_clean(P_M03_VAL_1P0)
m03_test_1p0 <- read_csv_clean(P_M03_TEST_1P0)

for (nm in c("y","p_cal")) {
  if (!nm %in% names(m03_val))  stop("model03_val_preds.csv missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_test)) stop("model03_test_preds.csv missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_val_1p0))  stop("model03_val_preds_1p0.csv missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_test_1p0)) stop("model03_test_preds_1p0.csv missing column: ", nm, call. = FALSE)
}

# M04 (prefer calibrated)
load_m04 <- function(cal_path, raw_path, split_name){
  if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    need <- c("game_id","play_id","nfl_id","y","p_cal")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(cal_path), " missing columns: ", paste(miss, collapse=", "), call. = FALSE)
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
  } else {
    req(raw_path, basename(raw_path))
    df <- read_csv_clean(raw_path)
    need <- c("game_id","play_id","nfl_id","y","p_go")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(raw_path), " missing columns: ", paste(miss, collapse=", "), call. = FALSE)
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_go))
  }
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y)
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_used)
}

m04_val  <- load_m04(P_M04_VAL_CAL,  P_M04_VAL_RAW,  "val")
m04_test <- load_m04(P_M04_TEST_CAL, P_M04_TEST_RAW, "test")

# -------------------- M03: threshold sweep --------------------
ths <- seq(0, 1, by = 0.01)

sweep_bin <- function(df, split_name, label_name){
  y <- as.integer(df$y)
  p <- as.numeric(df$p_cal)
  tibble(th = ths) |>
    rowwise() |>
    mutate(
      tp = sum(y == 1 & p >= th, na.rm = TRUE),
      fp = sum(y == 0 & p >= th, na.rm = TRUE),
      tn = sum(y == 0 & p <  th, na.rm = TRUE),
      fn = sum(y == 1 & p <  th, na.rm = TRUE),
      n  = tp + fp + tn + fn,
      precision = safe_ratio(tp, tp + fp),
      recall    = safe_ratio(tp, tp + fn),
      f1        = ifelse(is.na(precision) | is.na(recall) | (precision+recall)==0, NA_real_,
                         2*precision*recall/(precision+recall)),
      pred_pos_rate = safe_ratio(tp + fp, n),
      prevalence    = mean(y, na.rm = TRUE)
    ) |>
    ungroup() |>
    mutate(split = split_name, label = label_name, .before = 1)
}

m03_primary_val  <- sweep_bin(m3v  <- m03_val,     "val",  "primary_1p5")
m03_primary_test <- sweep_bin(m3t  <- m03_test,    "test", "primary_1p5")
m03_1p0_val      <- sweep_bin(m31v <- m03_val_1p0, "val",  "backup_1p0")
m03_1p0_test     <- sweep_bin(m31t <- m03_test_1p0,"test", "backup_1p0")

m03_sweep <- bind_rows(m03_primary_val, m03_primary_test, m03_1p0_val, m03_1p0_test)

# Add RDS-selected thresholds (if available)
sel_th_primary <- if (!is.null(m03_rds_primary) && !is.null(m03_rds_primary$threshold)) as.numeric(m03_rds_primary$threshold) else NA_real_
sel_th_1p0     <- if (!is.null(m03_rds_1p0)     && !is.null(m03_rds_1p0$threshold))     as.numeric(m03_rds_1p0$threshold)     else NA_real_

m03_sel <- tibble(
  label = c("primary_1p5","backup_1p0"),
  sel_threshold = c(sel_th_primary, sel_th_1p0)
)

# Compute F1 at selected threshold for val/test
f1_at_sel <- function(sweep_tbl, th_sel){
  if (is.na(th_sel)) return(NA_real_)
  # interpolate by taking the nearest threshold in the grid
  i <- which.min(abs(sweep_tbl$th - th_sel))
  as.numeric(sweep_tbl$f1[i])
}
m03_summary <- m03_sweep |>
  group_by(label, split) |>
  summarise(
    best_th = th[which.max(replace_na(f1, -Inf))][1],
    best_f1 = max(replace_na(f1, -Inf), na.rm = TRUE),
    .groups = "drop"
  ) |>
  left_join(m03_sel, by = "label") |>
  rowwise() |>
  mutate(f1_at_selected = f1_at_sel(
    m03_sweep |> filter(label==.data$label, split==.data$split),
    sel_threshold),
    sel_f1_gap = best_f1 - f1_at_selected) |>
  ungroup()

readr::write_csv(m03_sweep, OUT_M03)

# -------------------- M04: coverage vs accuracy sweep --------------------
rank_and_cover <- function(df_one_split){
  # Per-play ranking and top probability
  plays <- df_one_split |>
    group_by(game_id, play_id) |>
    mutate(rank = rank(-p_used, ties.method = "first")) |>
    summarise(
      max_p = max(p_used, na.rm = TRUE),
      top1  = as.integer(any(y == 1 & rank == 1)),
      rr    = {
        if (any(y == 1)) {
          r <- rank[y == 1]
          1 / min(r, na.rm = TRUE)
        } else NA_real_
      },
      .groups = "drop"
    )
  plays
}

sweep_cov <- function(df, split_name){
  plays <- rank_and_cover(df)
  total <- nrow(plays)
  tibble(th = ths) |>
    rowwise() |>
    mutate(
      covered = sum(plays$max_p >= th, na.rm = TRUE),
      coverage = safe_ratio(covered, total),
      abstain_rate = 1 - coverage,
      top1_on_cov = {
        idx <- which(plays$max_p >= th)
        safe_ratio(sum(plays$top1[idx], na.rm = TRUE), length(idx))
      },
      mrr_on_cov = {
        idx <- which(plays$max_p >= th)
        if (length(idx) == 0) NA_real_ else mean(plays$rr[idx], na.rm = TRUE)
      }
    ) |>
    ungroup() |>
    mutate(split = split_name, .before = 1)
}

m04_val_sweep  <- sweep_cov(m04_val,  "val")
m04_test_sweep <- sweep_cov(m04_test, "test")
m04_sweep <- bind_rows(m04_val_sweep, m04_test_sweep)

readr::write_csv(m04_sweep, OUT_M04)

# -------------------- Report --------------------
rep <- c(
  "# Threshold sensitivity",
  "",
  "## Model 03 (contest)",
  "- Swept thresholds on validation and test for primary (1.5 yd) and backup (1.0 yd).",
  "- Metrics per threshold: precision, recall, F1, confusion counts, predicted positive rate, and prevalence.",
  "",
  "### Selected thresholds (from training) vs best-F1",
  paste0(
    m03_summary |>
      mutate(line = sprintf("- %s/%s: selected=%.3f | best=%.3f | F1(selected)=%.3f | F1(best)=%.3f | gap=%.3f",
                            label, split, sel_threshold, best_th, f1_at_selected, best_f1, sel_f1_gap)) |>
      pull(line),
    collapse = "\n"
  ),
  "",
  "## Model 04 (assignment)",
  "- Swept a confidence threshold on the top `p_go` per play; reports coverage (fraction of plays with max p ≥ threshold), abstain rate, Top-1 accuracy and MRR on covered plays (val/test).",
  "",
  "## Files",
  paste0("- ", OUT_M03),
  paste0("- ", OUT_M04)
)
writeLines(rep, OUT_REP, useBytes = TRUE)

# -------------------- Verification (PASS/FAIL) --------------------
checks <- list()

# M03 rows present
checks[["m03_rows_present"]] <- nrow(m03_sweep) > 0

# M04 rows present
checks[["m04_rows_present"]] <- nrow(m04_sweep) > 0

# M04 monotonic coverage (non-increasing with threshold) and coverage(th=0) ~ 1
cov_ok <- TRUE; cov_zero_ok <- TRUE
for (sp in unique(m04_sweep$split)) {
  x <- m04_sweep |> filter(split == sp) |> arrange(th)
  covs <- x$coverage
  if (length(covs) > 1) {
    diffs <- diff(covs)
    cov_ok <- cov_ok && all(diffs <= 1e-9 | is.na(diffs))
  }
  cov_zero_ok <- cov_zero_ok && isTRUE(all.equal(covs[1], 1, tolerance = 1e-6))
}
checks[["m04_coverage_monotone"]] <- cov_ok
checks[["m04_coverage_at_zero_is_one"]] <- cov_zero_ok

# No NA in core reported columns
checks[["m03_no_na_metrics"]] <- !any(is.na(m03_sweep$f1) & is.na(m03_sweep$precision) & is.na(m03_sweep$recall))
checks[["m04_no_na_core"]]    <- !any(is.na(m04_sweep$coverage))

# Assemble status table
status_tbl <- tibble::tibble(
  check = c(
    "m03_rows_present",
    "m04_rows_present",
    "m04_coverage_monotone",
    "m04_coverage_at_zero_is_one",
    "m03_no_na_metrics",
    "m04_no_na_core"
  ),
  status = sapply(checks, pass),
  details = c(
    sprintf("rows=%s", nrow(m03_sweep)),
    sprintf("rows=%s", nrow(m04_sweep)),
    if (cov_ok) "OK" else "coverage not non-increasing",
    if (cov_zero_ok) "coverage(th=0)=1" else "coverage(th=0)!=1",
    "F1/precision/recall present across grid",
    "coverage column present across grid"
  )
)

readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# Threshold sensitivity — Status", "", md_table(status_tbl)), OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) stop("Threshold sensitivity verification: FAIL. See artifacts/threshold_sensitivity_status.*", call. = FALSE)
message("Threshold sensitivity verification: PASS.")

# -------------------- Console breadcrumbs --------------------
message("Wrote:",
        "\n  - ", OUT_M03,
        "\n  - ", OUT_M04,
        "\n  - ", OUT_REP,
        "\n  - ", OUT_STAT, " and ", OUT_STATM)










# 12a_select_and_apply_pstar.R
# What it does:
# Selects operating points (p*) for M03 (both labels) and M04 from Script 12 sweeps,
# applies them to existing predictions, compares against baselines, and writes
# operating_points + summary + evals + PASS/FAIL status. Stops on FAIL.

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
