load_m04 <- function(cal_path, raw_path, split_name){
  if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    need <- c("game_id","play_id","nfl_id","y","p_cal")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(cal_path), " missing: ", paste(miss, collapse=", "))
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
  } else {
    df <- read_csv_clean(raw_path)
    need <- c("game_id","play_id","nfl_id","y","p_go")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(raw_path), " missing: ", paste(miss, collapse=", "))
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_go))
  }
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y)
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_used)
}
m04_val  <- load_m04(P_M04_VAL_CAL,  P_M04_VAL_RAW,  "val")
m04_test <- load_m04(P_M04_TEST_CAL, P_M04_TEST_RAW, "test")

# -------------------- Select p* --------------------
# M03: F1-optimal on validation (fallback to Youden's J if all NA); tie-break to lower th.
pick_m03 <- function(df_sw_label){
  val <- df_sw_label |> filter(split == "val") |> arrange(th)
  if (!nrow(val)) return(tibble(p_star = NA_real_, objective = NA_character_, objective_val = NA_real_, note = NA_character_))
  if (all(is.na(val$f1))) {
    tpr <- safe_ratio(val$tp, val$tp + val$fn)
    fpr <- safe_ratio(val$fp, val$fp + val$tn)
    j <- tpr - fpr
    best <- max(replace_na(j, -Inf), na.rm = TRUE)
    i <- which.min(ifelse(j >= best - 1e-9, val$th, Inf))
    tibble(p_star = val$th[i], objective = "youden_j_on_val", objective_val = j[i], note = "tie->lower_th")
  } else {
    best <- max(replace_na(val$f1, -Inf), na.rm = TRUE)
    i <- which.min(ifelse(val$f1 >= best - 1e-9, val$th, Inf))
    tibble(p_star = val$th[i], objective = "f1_on_val", objective_val = val$f1[i], note = "tie->lower_th")
  }
}

labs <- unique(m03_sw$label)
m03_ops <- purrr::map_dfr(labs, function(lab){
  sel <- pick_m03(m03_sw |> filter(label == lab))
  tibble(model = paste0("M03_", lab), p_star = sel$p_star, objective = sel$objective, objective_val = sel$objective_val, note = sel$note)
})

# M04: maximize coverage * top1_on_cov on validation; tie-break to lower th within tol
pick_m04 <- function(df_sw_val, tol = 0.005){
  if (!nrow(df_sw_val)) return(tibble(p_star = NA_real_, objective = NA_character_, objective_val = NA_real_, note = NA_character_))
  cand <- df_sw_val |> mutate(expected_correct = coverage * top1_on_cov)
  best <- max(replace_na(cand$expected_correct, -Inf), na.rm = TRUE)
  tie  <- cand |> filter(expected_correct >= best - tol) |> arrange(th) |> slice(1)
  tibble(p_star = tie$th[1], objective = "coverage_x_top1_on_val", objective_val = tie$expected_correct[1],
         note = sprintf("min_th_within_%.3f_of_best", tol))
}
m04_ops <- pick_m04(m04_sw |> filter(split == "val")) |>
  mutate(model = "M04_assignment", .before = 1)

