# M04 eval at thresholds: p*, baseline_0.00 (always decide), baseline_0.50
rank_and_cover <- function(df_one_split){
  df_one_split |>
    group_by(game_id, play_id) |>
    mutate(rank = rank(-p_used, ties.method = "first")) |>
    summarise(
      max_p = max(p_used, na.rm = TRUE),
      top1  = as.integer(any(y == 1 & rank == 1)),
      rr    = {
        if (any(y == 1)) {
          r <- rank[y == 1]; 1/min(r, na.rm = TRUE)
        } else NA_real_
      },
      .groups = "drop"
    )
}
cover_at <- function(plays, th){
  total <- nrow(plays); idx <- which(plays$max_p >= th)
  tibble(
    th = th,
    covered = length(idx),
    coverage = safe_ratio(length(idx), total),
    abstain_rate = 1 - safe_ratio(length(idx), total),
    top1_on_cov = if (length(idx)==0) NA_real_ else mean(plays$top1[idx], na.rm = TRUE),
    mrr_on_cov  = if (length(idx)==0) NA_real_ else mean(plays$rr[idx],   na.rm = TRUE),
    expected_correct = if (length(idx)==0) NA_real_ else safe_ratio(length(idx), total) * mean(plays$top1[idx], na.rm = TRUE)
  )
}
eval_m04_split <- function(df_split, ths){
  plays <- rank_and_cover(df_split)
  bind_rows(lapply(ths, function(t) cover_at(plays, t)))
}
th_m04 <- unique(round(c(
  ops$p_star[ops$model=="M04_assignment"],
  0.00, 0.50
), 3))

m04_eval <- bind_rows(
  eval_m04_split(m04_val,  th_m04) |> mutate(split="val"),
  eval_m04_split(m04_test, th_m04) |> mutate(split="test")
) |>
  mutate(threshold_type = case_when(
    !is.na(ops$p_star[ops$model=="M04_assignment"]) & abs(th - ops$p_star[ops$model=="M04_assignment"]) < 1e-9 ~ "p_star",
    abs(th - 0.00) < 1e-9 ~ "baseline_0p00",
    abs(th - 0.50) < 1e-9 ~ "baseline_0p50",
    TRUE ~ "other"
  )) |>
  select(split, threshold_type, th, covered, coverage, abstain_rate, top1_on_cov, mrr_on_cov, expected_correct) |>
  arrange(split, match(threshold_type, c("p_star","baseline_0p00","baseline_0p50","other")), th)

