m03_test_y_backup  <- m02 |> filter(split=="test") |> pull(contest_tight)   |> as.integer()

# -------------------- Load M03 models + predict helpers --------------------
m03_primary <- readRDS(P_M03_PRI)   # list: model, features, medians, label, threshold, seed
m03_backup  <- readRDS(P_M03_BAK)
cal_primary <- if (file.exists(P_M03_CAL))  readRDS(P_M03_CAL)  else NULL
cal_backup  <- if (file.exists(P_M03_CALB)) readRDS(P_M03_CALB) else NULL

if (!all(m03_primary$features %in% names(m03_val_X))) stop("Primary features missing in M03 frame.")
if (!all(m03_backup$features  %in% names(m03_val_X))) stop("Backup features missing in M03 frame.")

predict_m03 <- function(model_obj, calib_glm, dfX){
  df_imp <- { nm <- intersect(names(model_obj$medians), names(dfX)); out <- dfX;
  for (v in nm) out[[v]][is.na(out[[v]])] <- model_obj$medians[[v]][1]; out }
  pred <- predict(model_obj$model, data = df_imp[, model_obj$features, drop=FALSE])
  p_raw <- if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"yes"]) else as.numeric(pred$predictions)
  if (is.null(calib_glm)) p_raw else as.numeric(predict(calib_glm, newdata = data.frame(l = logit(p_raw)), type = "response"))
}

# Baseline predictions
p_val_primary  <- predict_m03(m03_primary, cal_primary, m03_val_X)
p_test_primary <- predict_m03(m03_primary, cal_primary, m03_test_X)
p_val_backup   <- predict_m03(m03_backup,  cal_backup,  m03_val_X)
p_test_backup  <- predict_m03(m03_backup,  cal_backup,  m03_test_X)

# Choose p* (fallback to model threshold or 0.50 if missing)
if (!length(pstar_m03_primary) || !is.finite(pstar_m03_primary)) pstar_m03_primary <- if (!is.null(m03_primary$threshold)) as.numeric(m03_primary$threshold) else 0.50
if (!length(pstar_m03_backup)  || !is.finite(pstar_m03_backup))  pstar_m03_backup  <- if (!is.null(m03_backup$threshold))  as.numeric(m03_backup$threshold)  else 0.50

# Baseline metrics
baseline_m03 <- tibble(
  label = rep(c("primary_1p5","backup_1p0"), each = 2),
  split = rep(c("val","test"), times = 2),
  auc = c(auc_safe(m03_val_y_primary, p_val_primary),
          auc_safe(m03_test_y_primary, p_test_primary),
          auc_safe(m03_val_y_backup,  p_val_backup),
          auc_safe(m03_test_y_backup, p_test_backup)),
  logloss = c(logloss(m03_val_y_primary, p_val_primary),
              logloss(m03_test_y_primary, p_test_primary),
              logloss(m03_val_y_backup,  p_val_backup),
              logloss(m03_test_y_backup, p_test_backup)),
  f1_pstar = c(f1_at(m03_val_y_primary,  p_val_primary,  pstar_m03_primary),
               f1_at(m03_test_y_primary, p_test_primary, pstar_m03_primary),
               f1_at(m03_val_y_backup,   p_val_backup,   pstar_m03_backup),
               f1_at(m03_test_y_backup,  p_test_backup,  pstar_m03_backup))
)

# -------------------- M03: permutation importance (K=5) --------------------
K <- 5
fi_m03_rows <- list()
for (v in m03_primary$features) {
  d_auc_val_p  <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_val_X,  v)); baseline_m03$auc[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"]  - auc_safe(m03_val_y_primary, pv) }, K)
  d_auc_test_p <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_test_X, v)); baseline_m03$auc[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] - auc_safe(m03_test_y_primary, pv) }, K)
  d_ll_val_p   <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_val_X,  v)); -(baseline_m03$logloss[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"]  - logloss(m03_val_y_primary,  pv)) }, K)
  d_ll_test_p  <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_test_X, v)); -(baseline_m03$logloss[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] - logloss(m03_test_y_primary, pv)) }, K)
  d_f1_val_p   <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_val_X,  v)); baseline_m03$f1_pstar[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"]  - f1_at(m03_val_y_primary,  pv, pstar_m03_primary) }, K)
  d_f1_test_p  <- repeat_mean(function(){ pv <- predict_m03(m03_primary, cal_primary, permute_once(m03_test_X, v)); baseline_m03$f1_pstar[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] - f1_at(m03_test_y_primary, pv, pstar_m03_primary) }, K)
  
  d_auc_val_b  <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_val_X,  v)); baseline_m03$auc[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"]  - auc_safe(m03_val_y_backup, pv) }, K)
  d_auc_test_b <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_test_X, v)); baseline_m03$auc[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] - auc_safe(m03_test_y_backup, pv) }, K)
  d_ll_val_b   <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_val_X,  v)); -(baseline_m03$logloss[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"]  - logloss(m03_val_y_backup,  pv)) }, K)
  d_ll_test_b  <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_test_X, v)); -(baseline_m03$logloss[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] - logloss(m03_test_y_backup, pv)) }, K)
  d_f1_val_b   <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_val_X,  v)); baseline_m03$f1_pstar[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"]  - f1_at(m03_val_y_backup,  pv, pstar_m03_backup) }, K)
  d_f1_test_b  <- repeat_mean(function(){ pv <- predict_m03(m03_backup,  cal_backup,  permute_once(m03_test_X, v)); baseline_m03$f1_pstar[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] - f1_at(m03_test_y_backup, pv, pstar_m03_backup) }, K)
  
  fi_m03_rows[[length(fi_m03_rows)+1]] <- bind_rows(
    tibble(model="M03", label="primary_1p5", split="val",  feature=v, d_auc=d_auc_val_p,  d_logloss=d_ll_val_p,  d_f1=d_f1_val_p),
    tibble(model="M03", label="primary_1p5", split="test", feature=v, d_auc=d_auc_test_p, d_logloss=d_ll_test_p, d_f1=d_f1_test_p),
    tibble(model="M03", label="backup_1p0",  split="val",  feature=v, d_auc=d_auc_val_b,  d_logloss=d_ll_val_b,  d_f1=d_f1_val_b),
    tibble(model="M03", label="backup_1p0",  split="test", feature=v, d_auc=d_auc_test_b, d_logloss=d_ll_test_b, d_f1=d_f1_test_b)
  )
}
m03_fi <- bind_rows(fi_m03_rows)
readr::write_csv(m03_fi, OUT_M03_FI)

# -------------------- M03: group ablations --------------------
mask_group <- function(df, meds, vars){
  out <- df
  for (v in vars) if (v %in% names(out) && v %in% names(meds)) out[[v]] <- meds[[v]][1]
  out
}
groups_m03 <- list(
  distance   = c("d_start","d_min"),
  reach      = c("p_reach_start","p_reach_max"),
  capability = c("v_max","a_max")
)
abl_rows <- list()
for (g in names(groups_m03)) {
  Xv_val  <- mask_group(m03_val_X,  m03_primary$medians, groups_m03[[g]])
  Xv_test <- mask_group(m03_test_X, m03_primary$medians, groups_m03[[g]])
  pv_val_p  <- predict_m03(m03_primary, cal_primary, Xv_val)
  pv_test_p <- predict_m03(m03_primary, cal_primary, Xv_test)
  pv_val_b  <- predict_m03(m03_backup,  cal_backup,  Xv_val)
  pv_test_b <- predict_m03(m03_backup,  cal_backup,  Xv_test)
  
  abl_rows[[length(abl_rows)+1]] <- tibble(model="M03", group=g, label="primary_1p5",
                                           split="val",
                                           d_auc = baseline_m03$auc[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"] -
                                             auc_safe(m03_val_y_primary, pv_val_p),
                                           d_logloss = - (baseline_m03$logloss[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"] -
                                                            logloss(m03_val_y_primary, pv_val_p)),
                                           d_f1 = baseline_m03$f1_pstar[baseline_m03$label=="primary_1p5" & baseline_m03$split=="val"] -
                                             f1_at(m03_val_y_primary, pv_val_p, pstar_m03_primary))
  
  abl_rows[[length(abl_rows)+1]] <- tibble(model="M03", group=g, label="primary_1p5",
                                           split="test",
                                           d_auc = baseline_m03$auc[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] -
                                             auc_safe(m03_test_y_primary, pv_test_p),
                                           d_logloss = - (baseline_m03$logloss[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] -
                                                            logloss(m03_test_y_primary, pv_test_p)),
                                           d_f1 = baseline_m03$f1_pstar[baseline_m03$label=="primary_1p5" & baseline_m03$split=="test"] -
                                             f1_at(m03_test_y_primary, pv_test_p, pstar_m03_primary))
  
  abl_rows[[length(abl_rows)+1]] <- tibble(model="M03", group=g, label="backup_1p0",
                                           split="val",
                                           d_auc = baseline_m03$auc[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"] -
                                             auc_safe(m03_val_y_backup, pv_val_b),
                                           d_logloss = - (baseline_m03$logloss[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"] -
                                                            logloss(m03_val_y_backup, pv_val_b)),
                                           d_f1 = baseline_m03$f1_pstar[baseline_m03$label=="backup_1p0" & baseline_m03$split=="val"] -
                                             f1_at(m03_val_y_backup, pv_val_b, pstar_m03_backup))
  
  abl_rows[[length(abl_rows)+1]] <- tibble(model="M03", group=g, label="backup_1p0",
                                           split="test",
                                           d_auc = baseline_m03$auc[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] -
                                             auc_safe(m03_test_y_backup, pv_test_b),
                                           d_logloss = - (baseline_m03$logloss[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] -
                                                            logloss(m03_test_y_backup, pv_test_b)),
                                           d_f1 = baseline_m03$f1_pstar[baseline_m03$label=="backup_1p0" & baseline_m03$split=="test"] -
                                             f1_at(m03_test_y_backup, pv_test_b, pstar_m03_backup))
}
m03_abl <- bind_rows(abl_rows)
readr::write_csv(m03_abl, OUT_M03_ABL)

# -------------------- M04: labels, prediction, metrics --------------------
lev <- read_csv_clean(P_LEV) |>
  mutate(game_id = as.character(game_id),
         play_id = suppressWarnings(as.integer(play_id)),
         nfl_id  = suppressWarnings(as.integer(nfl_id)),
         split   = tolower(as.character(split)))
need_lev <- c("game_id","play_id","nfl_id","split","d_arrival","contest_primary")
miss_lev <- setdiff(need_lev, names(lev)); if (length(miss_lev)) stop("Leverage dataset missing columns: ", paste(miss_lev, collapse=", "))

winners <- lev |>
  group_by(game_id, play_id) |>
  mutate(contested_play = any(contest_primary, na.rm = TRUE),
         d_arrival_eff  = ifelse(contested_play & !contest_primary, Inf, d_arrival)) |>
  summarise(nfl_id_winner = nfl_id[which.min(d_arrival_eff)], .groups="drop")

lev_y <- lev |>
  left_join(winners, by = c("game_id","play_id")) |>
  mutate(y_go = as.integer(nfl_id == nfl_id_winner))

m04_obj <- readRDS(P_M04)
feat_m04 <- m04_obj$features
if (!all(feat_m04 %in% names(lev_y))) stop("Some Model 04 features are missing in leverage dataset.")

impute_meds <- function(df, meds, feats){
  out <- df
  for (v in feats) {
    if (!v %in% names(out)) out[[v]] <- NA_real_
    out[[v]][is.na(out[[v]])] <- meds[[v]][1]
  }
  out
}
pred_p_go <- function(df_feats){
  pred <- predict(m04_obj$model, data = df_feats[, feat_m04, drop=FALSE])
  if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"1"]) else as.numeric(pred$predictions)
}
top1_acc <- function(df, p){
  df |>
    mutate(p=p, key=paste(game_id,play_id)) |>
    group_by(key) |>
    mutate(r = rank(-p, ties.method="first")) |>
    summarise(hit = as.integer(any(y_go==1 & r==1)), .groups="drop") |>
    summarise(mean(hit)) |> pull()
}
mrr <- function(df, p){
  df |>
    mutate(p=p, key=paste(game_id,play_id)) |>
    group_by(key) |>
    mutate(r = rank(-p, ties.method="first")) |>
    filter(y_go==1) |>
    summarise(rr = 1/min(r), .groups="drop") |>
    summarise(mean(rr)) |> pull()
}

lev_val  <- lev_y |> filter(split=="val")
lev_test <- lev_y |> filter(split=="test")
X_val  <- impute_meds(lev_val,  m04_obj$medians, feat_m04)
X_test <- impute_meds(lev_test, m04_obj$medians, feat_m04)
p_val_m04  <- pred_p_go(X_val)
p_test_m04 <- pred_p_go(X_test)

baseline_m04 <- tibble(
  split = c("val","test"),
  top1 = c(top1_acc(lev_val, p_val_m04), top1_acc(lev_test, p_test_m04)),
  mrr  = c(mrr(lev_val, p_val_m04),      mrr(lev_test, p_test_m04))
)

# -------------------- M04: permutation importance (K=5) --------------------
fi_m04_rows <- list()
for (v in feat_m04) {
  d_top1_val <- repeat_mean(function(){
    Xv <- X_val; if (v %in% names(Xv)) Xv[[v]] <- sample(Xv[[v]])
    pv <- pred_p_go(Xv); baseline_m04$top1[baseline_m04$split=="val"] - top1_acc(lev_val, pv)
  }, K)
  d_top1_test <- repeat_mean(function(){
    Xv <- X_test; if (v %in% names(Xv)) Xv[[v]] <- sample(Xv[[v]])
    pv <- pred_p_go(Xv); baseline_m04$top1[baseline_m04$split=="test"] - top1_acc(lev_test, pv)
  }, K)
  d_mrr_val <- repeat_mean(function(){
    Xv <- X_val; if (v %in% names(Xv)) Xv[[v]] <- sample(Xv[[v]])
    pv <- pred_p_go(Xv); baseline_m04$mrr[baseline_m04$split=="val"] - mrr(lev_val, pv)
  }, K)
  d_mrr_test <- repeat_mean(function(){
    Xv <- X_test; if (v %in% names(Xv)) Xv[[v]] <- sample(Xv[[v]])
    pv <- pred_p_go(Xv); baseline_m04$mrr[baseline_m04$split=="test"] - mrr(lev_test, pv)
  }, K)
  
  fi_m04_rows[[length(fi_m04_rows)+1]] <- bind_rows(
    tibble(model="M04", feature=v, split="val",  d_top1=d_top1_val,  d_mrr=d_mrr_val),
    tibble(model="M04", feature=v, split="test", d_top1=d_top1_test, d_mrr=d_mrr_test)
  )
}
m04_fi <- bind_rows(fi_m04_rows)
readr::write_csv(m04_fi, OUT_M04_FI)

# -------------------- M04: group ablations --------------------
groups_m04 <- list(
  m03_probs = c("p03_primary","p03_1p0"),
  distance  = c("p_reach_start","d_start","p_reach_max","d_min"),
  capability= c("v_max","a_max"),
  ranks     = c("rank_d_start","rank_d_min","rank_v_max","rank_p03_primary","rank_p03_1p0",
                "d_start_rank_norm","d_min_rank_norm","v_max_rank_norm","p03_primary_norm","p03_1p0_norm")
)
abl_m04_rows <- list()
for (g in names(groups_m04)) {
  Xv_val  <- X_val;  for (v in groups_m04[[g]]) if (v %in% names(Xv_val))  Xv_val[[v]]  <- m04_obj$medians[[v]][1]
  Xv_test <- X_test; for (v in groups_m04[[g]]) if (v %in% names(Xv_test)) Xv_test[[v]] <- m04_obj$medians[[v]][1]
  pv_val  <- pred_p_go(Xv_val)
  pv_test <- pred_p_go(Xv_test)
  abl_m04_rows[[length(abl_m04_rows)+1]] <- tibble(
    model="M04", group=g, split="val",
    d_top1 = baseline_m04$top1[baseline_m04$split=="val"] - top1_acc(lev_val, pv_val),
    d_mrr  = baseline_m04$mrr[ baseline_m04$split=="val"] - mrr(lev_val, pv_val)
  )
  abl_m04_rows[[length(abl_m04_rows)+1]] <- tibble(
    model="M04", group=g, split="test",
    d_top1 = baseline_m04$top1[baseline_m04$split=="test"] - top1_acc(lev_test, pv_test),
    d_mrr  = baseline_m04$mrr[ baseline_m04$split=="test"] - mrr(lev_test, pv_test)
  )
}
m04_abl <- bind_rows(abl_m04_rows)
readr::write_csv(m04_abl, OUT_M04_ABL)

# -------------------- Report --------------------
top_m03_val <- m03_fi |> filter(label=="primary_1p5", split=="val") |> arrange(desc(d_auc)) |> head(5)
top_m04_val <- m04_fi |> filter(split=="val") |> arrange(desc(d_top1)) |> head(5)

rep <- c(
  "# Feature importance & ablations",
  "",
  "## Model 03 (contest)",
  "- Deltas are drops when a feature/group is destroyed (bigger = more important).",
  "",
  "Top features (val; primary 1.5 yd, by d_auc):",
  paste0(
    apply(top_m03_val, 1, function(r)
      sprintf("- %s: d_auc=%.4f, d_logloss=%.4f, d_f1=%.4f", r[["feature"]], as.numeric(r[["d_auc"]]), as.numeric(r[["d_logloss"]]), as.numeric(r[["d_f1"]]))
    ),
    collapse = "\n"
  ),
  "",
  "## Model 04 (assignment)",
  "Top features (val; by d_top1):",
  paste0(
    apply(top_m04_val, 1, function(r)
      sprintf("- %s: d_top1=%.4f, d_mrr=%.4f", r[["feature"]], as.numeric(r[["d_top1"]]), as.numeric(r[["d_mrr"]]))
    ),
    collapse = "\n"
  ),
  "",
  "## Files",
  paste0("- ", OUT_M03_FI),
  paste0("- ", OUT_M03_ABL),
  paste0("- ", OUT_M04_FI),
  paste0("- ", OUT_M04_ABL)
)
writeLines(rep, OUT_REP, useBytes = TRUE)

# -------------------- PASS/FAIL verification --------------------
checks <- list()

checks[["m03_fi_written"]]  <- file.exists(OUT_M03_FI)  && nrow(read_csv_clean(OUT_M03_FI))  > 0
checks[["m03_ab_written"]]  <- file.exists(OUT_M03_ABL) && nrow(read_csv_clean(OUT_M03_ABL)) > 0
checks[["m04_fi_written"]]  <- file.exists(OUT_M04_FI)  && nrow(read_csv_clean(OUT_M04_FI))  > 0
checks[["m04_ab_written"]]  <- file.exists(OUT_M04_ABL) && nrow(read_csv_clean(OUT_M04_ABL)) > 0

m03fi <- tryCatch(read_csv_clean(OUT_M03_FI),  error=function(e) NULL)
m04fi <- tryCatch(read_csv_clean(OUT_M04_FI),  error=function(e) NULL)

checks[["m03_fi_has_signal"]] <- !is.null(m03fi) && any(is.finite(m03fi$d_auc) | is.finite(m03fi$d_logloss) | is.finite(m03fi$d_f1))
checks[["m04_fi_has_signal"]] <- !is.null(m04fi) && any(is.finite(m04fi$d_top1) | is.finite(m04fi$d_mrr))

status_tbl <- tibble::tibble(
  check = names(checks),
  status = sapply(checks, pass),
  details = c(
    OUT_M03_FI, OUT_M03_ABL, OUT_M04_FI, OUT_M04_ABL,
    "M03: at least one finite delta",
    "M04: at least one finite delta"
  )
)

readr::write_csv(status_tbl, OUT_STATUS)
writeLines(c("# Feature importance & ablations — Status", "", md_table(status_tbl)), OUT_STATUSMD, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) stop("Feature importance/ablations: FAIL. See artifacts/feature_importance_status.*", call. = FALSE)
message("Feature importance/ablations: PASS.")

message("Wrote:",
        "\n  - ", OUT_M03_FI,
        "\n  - ", OUT_M03_ABL,
        "\n  - ", OUT_M04_FI,
        "\n  - ", OUT_M04_ABL,
        "\n  - ", OUT_REP,
        "\n  - ", OUT_STATUS, " and ", OUT_STATUSMD)

# Also write ablation-alias files for downstream compatibility
file.copy(file.path("artifacts","feature_importance_status.csv"),
          file.path("artifacts","feature_ablation_status.csv"), overwrite = TRUE)
file.copy(file.path("artifacts","feature_importance_status.md"),
          file.path("artifacts","feature_ablation_status.md"), overwrite = TRUE)

# --- Compatibility shim: accept either "feature_importance_*" or "feature_ablation_*" ---
ART <- file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), "artifacts")

imp_csv <- file.path(ART, "feature_importance_status.csv")
abl_csv <- file.path(ART, "feature_ablation_status.csv")
