# -------------------- Extract saved seeds from model RDS --------------------
seed_rows <- list()
grab_seed <- function(rds_path, model_name){
  if (!file.exists(rds_path)) return(NULL)
  obj <- tryCatch(readRDS(rds_path), error = function(e) NULL)
  if (is.null(obj)) return(NULL)
  seed <- NA_integer_
  if (is.list(obj) && "seed" %in% names(obj)) seed <- suppressWarnings(as.integer(obj$seed))
  tibble(model = model_name, rds = rds_path, seed = seed)
}

seed_rows[[length(seed_rows)+1]] <- grab_seed(file.path(DIRS$artifacts, "model03_model_rds.rds"),      "Model03_primary")
seed_rows[[length(seed_rows)+1]] <- grab_seed(file.path(DIRS$artifacts, "model03_model_rds_1p0.rds"),  "Model03_backup_1p0")
seed_rows[[length(seed_rows)+1]] <- grab_seed(file.path(DIRS$artifacts, "model04_model_rds.rds"),      "Model04_assignment")

seeds <- bind_rows(seed_rows) |> mutate(seed_present = !is.na(seed))
