    sprintf("lines=%d", length(sess)),
    paste0("seeds: ", paste(paste0(seeds$model, "=", ifelse(is.na(seeds$seed), "NA", seeds$seed)), collapse=", "))
  )
)

readr::write_csv(checks, OUT_STATUS_CSV)
