OUT_DIR         <- file.path(DIRS$artifacts, "score"); dir.create(OUT_DIR, showWarnings = FALSE, recursive = TRUE)
suppressWarnings(unlink(Sys.glob(file.path(OUT_DIR, "*")), recursive = TRUE, force = TRUE))
OUT_FEATS       <- file.path(OUT_DIR, "score_features.csv")
OUT_M03         <- file.path(OUT_DIR, "score_model03_preds.csv")
OUT_M04         <- file.path(OUT_DIR, "score_model04_preds.csv")
OUT_TOP         <- file.path(OUT_DIR, "score_assignment_top.csv")
