OUT_STATUS_CSV  <- file.path(OUT_DIR, "score_status.csv")
OUT_STATUS_MD   <- file.path(OUT_DIR, "score_status.md")

# ---------- Helpers ----------
read_csv_clean <- function(path) suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
rename_if_exists <- function(df, from, to){ if (from %in% names(df) && !(to %in% names(df))) df <- dplyr::rename(df, !!to := !!sym(from)); df }
standardize_tracking_cols <- function(df){
  df |>
    janitor::clean_names() |>
    rename_if_exists("nflid","nfl_id") |>
    rename_if_exists("player_id","nfl_id") |>
    rename_if_exists("frame","frame_id") |>
    rename_if_exists("speed","s") |>
    rename_if_exists("accel","a")
}
find_score_inputs <- function(score_dir = DIRS$score){
  env <- Sys.getenv("SCORE_FILES", "")
  if (nzchar(env)) {
    files <- unique(normalizePath(unlist(strsplit(env, "[,;]+")), winslash = "/", mustWork = FALSE))
    files <- files[file.exists(files)]
    if (length(files)) return(files)
  }
  files <- Sys.glob(file.path(score_dir, "*.csv"))
  unique(files[file.exists(files)])
}
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
req  <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
ensure_col <- function(df, name, value = NA_real_) { if (!(name %in% names(df))) df[[name]] <- value; df }

# ---------- Physics / knobs ----------
DT <- 0.1
ELIG_THRESHOLD <- 0.05
SIDELINE_BUF <- 0.5
LAMBDA_REACH <- 0.7
reach_radius <- function(v0, a_max, v_max, tau){
  v_cap <- pmin(v0 + a_max * tau, v_max)
  t_acc <- pmax((v_cap - v0) / pmax(a_max, 1e-9), 0); t_acc <- pmin(t_acc, tau)
  d_ramp <- v0 * tau + 0.5 * a_max * t_acc^2
  pmin(d_ramp, v_cap * tau)
}
clip01 <- function(p, eps = 1e-6) pmin(pmax(p, eps), 1 - eps)
logit  <- function(p) log(clip01(p) / (1 - clip01(p)))
p_reach_fun <- function(distance, r, lambda = LAMBDA_REACH) exp(-lambda * pmax(distance - r, 0))

# ---------- Guards ----------
req(PATH_CAPS,      "capability_profiles.csv")
req(PATH_M03_PRI,   "model03_model_rds.rds")
req(PATH_M03_BK,    "model03_model_rds_1p0.rds")
req(PATH_M04,       "model04_model_rds.rds")
req(PATH_SPLIT_MAP, "plays_split_map.csv")

# ---------- Load artifacts ----------
caps_raw <- read_csv_clean(PATH_CAPS) |>
  mutate(nfl_id = suppressWarnings(as.integer(nfl_id))) |>
  filter(!is.na(nfl_id)) |>
  distinct(nfl_id, .keep_all = TRUE)

pick_cap_col <- function(df, candidates){ cand <- intersect(candidates, names(df)); if (length(cand)) df[[cand[1]]] else NULL }
v_col <- pick_cap_col(caps_raw, c("v_max","vmax","v_max_mps","vmax_mps","v_top","speed_max","speed_top"))
a_col <- pick_cap_col(caps_raw, c("a_max","amax","a_max_mps","amax_mps","accel_max","acceleration_max","acceleration"))

# Defaults from model medians if available, else constants
m03_tmp <- readRDS(PATH_M03_PRI)
v_default <- if (!is.null(m03_tmp$medians[["v_max"]])) as.numeric(m03_tmp$medians[["v_max"]][1]) else 7.5
a_default <- if (!is.null(m03_tmp$medians[["a_max"]])) as.numeric(m03_tmp$medians[["a_max"]][1]) else 3.0

if (is.null(v_col) || is.null(a_col)) {
  caps <- caps_raw |>
    mutate(v_max = if (is.null(v_col)) v_default else as.numeric(v_col),
           a_max = if (is.null(a_col)) a_default else as.numeric(a_col)) |>
    select(nfl_id, v_max, a_max)
} else {
  caps <- caps_raw |> mutate(v_max = as.numeric(v_col), a_max = as.numeric(a_col)) |> select(nfl_id, v_max, a_max)
}

m03_primary <- readRDS(PATH_M03_PRI)
m03_backup  <- readRDS(PATH_M03_BK)
cal_m03_pri <- if (file.exists(PATH_M03_CAL))   readRDS(PATH_M03_CAL)   else NULL
cal_m03_bak <- if (file.exists(PATH_M03_CAL_B)) readRDS(PATH_M03_CAL_B) else NULL
m04_model   <- readRDS(PATH_M04)
cal_m04     <- if (file.exists(PATH_M04_CAL))   readRDS(PATH_M04_CAL)   else NULL
ops_tbl     <- if (file.exists(PATH_OPS)) read_csv_clean(PATH_OPS) else tibble(model=character(), p_star=double())
pstar_m03_primary <- if ("M03_primary_1p5" %in% ops_tbl$model) ops_tbl$p_star[ops_tbl$model=="M03_primary_1p5"][1] else NA_real_
pstar_m03_backup  <- if ("M03_backup_1p0"  %in% ops_tbl$model) ops_tbl$p_star[ops_tbl$model=="M03_backup_1p0"][1]  else NA_real_
pstar_m04         <- if ("M04_assignment"  %in% ops_tbl$model) ops_tbl$p_star[ops_tbl$model=="M04_assignment"][1]  else NA_real_

# ---------- Build TEST list ----------
split_map <- read_csv_clean(PATH_SPLIT_MAP) |>
  transmute(game_id = as.character(game_id),
            play_id = suppressWarnings(as.integer(play_id)),
            split = tolower(as.character(split)))
test_plays <- split_map |> filter(split == "test") |> distinct(game_id, play_id)

# ---------- If ./score/ is empty, fill it from TEST 15% ----------
dir.create(DIRS$score, showWarnings = FALSE, recursive = TRUE)
score_files <- find_score_inputs()
if (!length(score_files)) {
  train_files <- Sys.glob(file.path(DIRS$train, "input_*.csv"))
  if (!length(train_files)) stop("No input_*.csv files found in ./train/ to build TEST scoring inputs.", call. = FALSE)
  suppressWarnings(unlink(Sys.glob(file.path(DIRS$score, "*")), recursive = TRUE, force = TRUE))
  
  write_scoring_csv <- function(df_play){
    if (!nrow(df_play)) return(invisible(NULL))
    if (!"s" %in% names(df_play)) df_play$s <- NA_real_
    if (!"a" %in% names(df_play)) df_play$a <- NA_real_
    gid <- unique(df_play$game_id)[1]; pid <- unique(df_play$play_id)[1]
    out_path <- file.path(DIRS$score, sprintf("test_%s_%s.csv", gid, pid))
    readr::write_csv(df_play |> select(game_id, play_id, nfl_id, frame_id, x, y, s, a, num_frames_output, ball_land_x, ball_land_y), out_path)
    out_path
  }
  
  written <- character(0)
  for (f in train_files) {
    df <- read_csv_clean(f) |> standardize_tracking_cols()
    need_cols <- c("game_id","play_id","nfl_id","frame_id","x","y","num_frames_output","ball_land_x","ball_land_y")
    if (length(setdiff(need_cols, names(df)))) next
    if (!"s" %in% names(df)) df$s <- NA_real_
    if (!"a" %in% names(df)) df$a <- NA_real_
    df <- df |>
      mutate(game_id = as.character(game_id),
             play_id = suppressWarnings(as.integer(play_id)),
             frame_id = suppressWarnings(as.integer(frame_id)),
             nfl_id = suppressWarnings(as.integer(nfl_id)),
             x = as.numeric(x), y = as.numeric(y),
             s = as.numeric(s), a = as.numeric(a)) |>
      inner_join(test_plays, by = c("game_id","play_id")) |>
      arrange(game_id, play_id, nfl_id, frame_id)
    if (!nrow(df)) next
    sp <- split(df, interaction(df$game_id, df$play_id, drop = TRUE))
    for (k in seq_along(sp)) {
      pth <- write_scoring_csv(sp[[k]])
      if (!is.null(pth)) written <- c(written, pth)
    }
  }
  if (!length(written)) stop("No TEST plays could be assembled into ./score/ from ./train/.", call. = FALSE)
  score_files <- sort(unique(written))
}

# ---------- Ingest scoring inputs ----------
raw_inputs <- purrr::map_dfr(score_files, read_csv_clean) |>
  standardize_tracking_cols()
if (!"s" %in% names(raw_inputs)) raw_inputs$s <- NA_real_
if (!"a" %in% names(raw_inputs)) raw_inputs$a <- NA_real_

raw_inputs <- raw_inputs |>
  mutate(
    game_id  = as.character(game_id),
    play_id  = suppressWarnings(as.integer(play_id)),
    frame_id = suppressWarnings(as.integer(frame_id)),
    nfl_id   = suppressWarnings(as.integer(nfl_id)),
    x = as.numeric(x), y = as.numeric(y),
    s = as.numeric(s), a = as.numeric(a),
    num_frames_output = as.numeric(num_frames_output),
    ball_land_x = as.numeric(ball_land_x),
    ball_land_y = as.numeric(ball_land_y)
  ) |>
  arrange(game_id, play_id, nfl_id, frame_id)

need_cols <- c("game_id","play_id","nfl_id","frame_id","x","y","num_frames_output","ball_land_x","ball_land_y")
if (length(setdiff(need_cols, names(raw_inputs)))) stop("Scoring inputs missing required columns.", call. = FALSE)

# Derive speed if entirely missing
if (all(is.na(raw_inputs$s))) {
  raw_inputs <- raw_inputs |>
    group_by(game_id, play_id, nfl_id) |>
    mutate(
      dx = x - dplyr::lag(x), dy = y - dplyr::lag(y),
      s  = sqrt((dx/DT)^2 + (dy/DT)^2)
    ) |>
    ungroup() |>
    select(-dx, -dy)
}

# ---------- Pass windows & bounds ----------
windows <- raw_inputs |>
  group_by(game_id, play_id) |>
  summarise(
    t1     = suppressWarnings(max(frame_id, na.rm = TRUE)),
    num    = suppressWarnings(max(num_frames_output, na.rm = TRUE)),
    x_land = suppressWarnings(max(ball_land_x, na.rm = TRUE)),
    y_land = suppressWarnings(max(ball_land_y, na.rm = TRUE)),
    .groups = "drop"
  ) |>
  mutate(t0 = t1 - num + 1) |>
  filter(is.finite(t0), is.finite(t1), is.finite(num), num >= 1, t1 >= t0)
if (!nrow(windows)) stop("No valid pass windows found in inputs.", call. = FALSE)

bounds <- raw_inputs |>
  summarise(
    x_min = quantile(x, 0.005, na.rm = TRUE),
    x_max = quantile(x, 0.995, na.rm = TRUE),
    y_min = quantile(y, 0.005, na.rm = TRUE),
    y_max = quantile(y, 0.995, na.rm = TRUE)
  )
x_lo <- bounds$x_min + SIDELINE_BUF; x_hi <- bounds$x_max - SIDELINE_BUF
y_lo <- bounds$y_min + SIDELINE_BUF; y_hi <- bounds$y_max - SIDELINE_BUF

# ---------- Frame-level → defender-play features ----------
players_caps <- raw_inputs |> inner_join(caps, by = "nfl_id")

pv <- players_caps |>
  inner_join(windows, by = c("game_id","play_id")) |>
  filter(frame_id >= t0, frame_id <= t1) |>
  mutate(
    tau = pmax((t1 - frame_id) * DT, 0),
    d_to_land = sqrt((x_land - x)^2 + (y_land - y)^2),
    r = reach_radius(pmax(s, 0), a_max, v_max, tau),
    p_reach = p_reach_fun(d_to_land, r)
  )

per_def_play <- pv |>
  group_by(game_id, play_id, nfl_id) |>
  summarise(
    p_reach_max = suppressWarnings(max(p_reach, na.rm = TRUE)),
    d_min       = suppressWarnings(min(d_to_land, na.rm = TRUE)),
    .groups = "drop"
  )

start_of_flight <- pv |>
  group_by(game_id, play_id, nfl_id) |>
  arrange(abs(frame_id - first(t0)), .by_group = TRUE) |>
  summarise(
    p_reach_start = dplyr::first(p_reach),
    d_start       = dplyr::first(d_to_land),
    .groups = "drop"
  )

arrival <- pv |>
  group_by(game_id, play_id, nfl_id) |>
  slice_max(p_reach, n = 1, with_ties = FALSE) |>
  summarise(
    d_arrival = dplyr::first(d_to_land),
    .groups = "drop"
  )

ds_raw <- per_def_play |>
  left_join(start_of_flight, by = c("game_id","play_id","nfl_id")) |>
  left_join(arrival,        by = c("game_id","play_id","nfl_id")) |>
  left_join(caps |> select(nfl_id, v_max, a_max), by = "nfl_id") |>
  mutate(split = "score")

# ---- HARD GUARANTEES on required cols (and refill from caps/defaults) ----
ds_raw <- ensure_col(ds_raw, "p_reach_max", NA_real_)
ds_raw <- ensure_col(ds_raw, "d_min",       NA_real_)
ds_raw <- ensure_col(ds_raw, "p_reach_start", NA_real_)
ds_raw <- ensure_col(ds_raw, "d_start",       NA_real_)
ds_raw <- ensure_col(ds_raw, "v_max", NA_real_)
ds_raw <- ensure_col(ds_raw, "a_max", NA_real_)

# Re-join caps as safety net, then coalesce and default
ds_raw <- ds_raw |>
  left_join(caps, by = "nfl_id", suffix = c("", "_cap")) |>
  mutate(
    v_max = coalesce(as.numeric(v_max), as.numeric(v_max_cap), v_default),
    a_max = coalesce(as.numeric(a_max), as.numeric(a_max_cap), a_default),
    p_reach_start = coalesce(p_reach_start, p_reach_max),
    d_start       = coalesce(d_start,       d_min)
  ) |>
  select(-ends_with("_cap"))

# Throwaway detection (landing far out of bounds)
throwaway <- windows |>
  mutate(
    oob_landing = is.finite(x_land) & is.finite(y_land) &
      (x_land < x_lo | x_land > x_hi | y_land < y_lo | y_land > y_hi),
    throwaway = oob_landing
  ) |>
  select(game_id, play_id, oob_landing, throwaway)

ds_raw <- ds_raw |>
  left_join(throwaway, by = c("game_id","play_id")) |>
  mutate(eligible = p_reach_max >= ELIG_THRESHOLD)

ds_use <- ds_raw |> filter(eligible, !throwaway)

# Final safety before modeling
ds_use <- ensure_col(ds_use, "p_reach_start", NA_real_)
ds_use <- ensure_col(ds_use, "d_start", NA_real_)
ds_use <- ensure_col(ds_use, "v_max", NA_real_)
ds_use <- ensure_col(ds_use, "a_max", NA_real_)
ds_use <- ds_use |>
  mutate(
    p_reach_start = coalesce(p_reach_start, p_reach_max),
    d_start       = coalesce(d_start,       d_min),
    v_max         = coalesce(as.numeric(v_max), v_default),
    a_max         = coalesce(as.numeric(a_max), a_default)
  )

# Persist features
readr::write_csv(
  ds_use |> select(game_id, play_id, nfl_id, split,
                   v_max, a_max, p_reach_start, d_start, p_reach_max, d_min, d_arrival,
                   eligible, throwaway),
  OUT_FEATS
)

# ---------- Prediction helpers ----------
impute_with_medians <- function(df, meds_one_row){
  nm <- intersect(names(meds_one_row), names(df))
  for (v in nm) df[[v]][is.na(df[[v]])] <- meds_one_row[[v]][1]
  df
}
get_p_yes_ranger <- function(pred){
  if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"yes"]) else as.numeric(pred$predictions)
}
get_p1_ranger <- function(pred){
  if (is.matrix(pred$predictions)) as.numeric(pred$predictions[,"1"]) else as.numeric(pred$predictions)
}
predict_m03 <- function(model_obj, calib_glm, df_feats){
  df_imp <- impute_with_medians(df_feats, model_obj$medians)
  p_raw <- get_p_yes_ranger(predict(model_obj$model, data = df_imp[, model_obj$features, drop = FALSE]))
  if (!is.null(calib_glm)) as.numeric(predict(calib_glm, newdata = data.frame(l = logit(p_raw)), type = "response")) else p_raw
}
predict_m04 <- function(model_obj, calib_glm, df_feats){
  df_imp <- impute_with_medians(df_feats, model_obj$medians)
  p_raw <- get_p1_ranger(predict(model_obj$model, data = df_imp[, model_obj$features, drop = FALSE]))
  if (!is.null(calib_glm)) as.numeric(predict(calib_glm, newdata = data.frame(p = p_raw), type = "response")) else p_raw
}

# ---------- Predict Model 03 (primary & 1.0) ----------
feat_m03 <- c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")
if (length(setdiff(feat_m03, names(ds_use)))) stop("Missing Model 03 features in ds_use.", call. = FALSE)
X_m03 <- ds_use |> select(game_id, play_id, nfl_id, split, all_of(feat_m03))
p03_primary <- predict_m03(m03_primary, cal_m03_pri, X_m03)
p03_1p0     <- predict_m03(m03_backup,  cal_m03_bak, X_m03)

m03_preds <- X_m03 |>
  mutate(
    p03_primary = p03_primary,
    p03_1p0     = p03_1p0,
    m03_primary_decision = if (is.finite(pstar_m03_primary)) as.integer(p03_primary >= pstar_m03_primary) else NA_integer_,
    m03_1p0_decision     = if (is.finite(pstar_m03_backup))  as.integer(p03_1p0     >= pstar_m03_backup)  else NA_integer_
  )
readr::write_csv(m03_preds, OUT_M03)

# ---------- Predict Model 04 (assignment p_go) ----------
lev0 <- m03_preds |>
  left_join(ds_use |> select(game_id, play_id, nfl_id, split, v_max, a_max,
                             p_reach_start, d_start, p_reach_max, d_min, d_arrival),
            by = c("game_id","play_id","nfl_id","split"))

# GUARANTEES for lev: ensure & fill v_max/a_max and start fields
lev0 <- ensure_col(lev0, "p_reach_start", NA_real_)
lev0 <- ensure_col(lev0, "d_start", NA_real_)
lev0 <- ensure_col(lev0, "d_min", NA_real_)
lev0 <- ensure_col(lev0, "p_reach_max", NA_real_)
lev0 <- ensure_col(lev0, "v_max", NA_real_)
lev0 <- ensure_col(lev0, "a_max", NA_real_)

# Re-join caps to fill any gaps; then default if still NA
lev <- lev0 |>
  left_join(caps, by = "nfl_id", suffix = c("", "_cap")) |>
  mutate(
    d_start       = coalesce(d_start, d_min),
    p_reach_start = coalesce(p_reach_start, p_reach_max),
    v_max         = coalesce(as.numeric(v_max), as.numeric(v_max_cap), v_default),
    a_max         = coalesce(as.numeric(a_max), as.numeric(a_max_cap), a_default)
  ) |>
  select(-ends_with("_cap")) |>
  group_by(game_id, play_id) |>
  mutate(
    n_defenders_play = n(),
    rank_d_start        = rank(d_start, ties.method = "min"),
    rank_d_min          = rank(d_min,   ties.method = "min"),
    rank_v_max          = rank(-v_max,  ties.method = "min"),
    rank_p03_primary    = rank(-p03_primary, ties.method = "min"),
    rank_p03_1p0        = rank(-p03_1p0,     ties.method = "min"),
    d_start_rank_norm   = (max(rank_d_start) - rank_d_start) / (max(rank_d_start) - 1 + 1e-9),
    d_min_rank_norm     = (max(rank_d_min)   - rank_d_min)   / (max(rank_d_min)   - 1 + 1e-9),
    v_max_rank_norm     = (max(rank_v_max)   - rank_v_max)   / (max(rank_v_max)   - 1 + 1e-9),
    p03_primary_norm    = (max(rank_p03_primary) - rank_p03_primary) / (max(rank_p03_primary) - 1 + 1e-9),
    p03_1p0_norm        = (max(rank_p03_1p0)     - rank_p03_1p0)     / (max(rank_p03_1p0)     - 1 + 1e-9)
  ) |>
  ungroup()

feat_m04 <- c("p03_primary","p03_1p0",
              "p_reach_start","d_start","p_reach_max","d_min",
              "v_max","a_max",
              "rank_d_start","rank_d_min","rank_v_max","rank_p03_primary","rank_p03_1p0",
              "d_start_rank_norm","d_min_rank_norm","v_max_rank_norm","p03_primary_norm","p03_1p0_norm")
if (length(setdiff(feat_m04, names(lev)))) stop("Missing Model 04 features.", call. = FALSE)

X_m04 <- lev |> select(game_id, play_id, nfl_id, split, all_of(feat_m04))
p_go   <- predict_m04(m04_model, cal_m04, X_m04)

m04_preds <- X_m04 |>
  mutate(p_go = p_go)
readr::write_csv(m04_preds, OUT_M04)

# ---------- Top-per-play (+ p*) ----------
top <- m04_preds |>
  group_by(game_id, play_id) |>
  arrange(desc(p_go), .by_group = TRUE) |>
  mutate(
    rank = row_number(),
    max_p_go = max(p_go, na.rm = TRUE),
    second_p_go = if (n() >= 2) sort(p_go, decreasing = TRUE)[2] else NA_real_
  ) |>
  slice_head(n = 1L) |>
  ungroup() |>
  mutate(decision = if (is.finite(pstar_m04)) ifelse(max_p_go >= pstar_m04, "assign", "abstain") else "assign") |>
  select(game_id, play_id, nfl_id, split, p_go, max_p_go, second_p_go, decision)
readr::write_csv(top, OUT_TOP)

# ---------- Report ----------
n_inputs <- length(score_files)
plays_scored <- ds_use |> summarise(n = n_distinct(paste(game_id, play_id))) |> pull(n)
def_rows <- nrow(ds_use)
assignable <- sum(top$decision == "assign", na.rm = TRUE)
abstained  <- sum(top$decision == "abstain", na.rm = TRUE)

rep_lines <- c(
  "# Scoring report",
  "",
  sprintf("- Input scoring CSVs used: %d", n_inputs),
  sprintf("- Plays scored (eligible, non-throwaway): %s", comma(plays_scored)),
  sprintf("- Defender-rows scored: %s", comma(def_rows)),
  "",
  "## Model 03",
  if (is.finite(pstar_m03_primary))
    sprintf("- Primary 1.5 p*: %.3f (m03_primary_decision applied).", pstar_m03_primary) else
      "- Primary 1.5 p*: not applied.",
  if (is.finite(pstar_m03_backup))
    sprintf("- Backup  1.0 p*: %.3f (m03_1p0_decision applied).", pstar_m03_backup) else
      "- Backup  1.0 p*: not applied.",
  "",
  "## Model 04",
  if (is.finite(pstar_m04))
    sprintf("- Assignment p* applied: %.3f (assign/abstain).", pstar_m04) else
      "- Assignment p*: not applied (missing).",
  sprintf("- Top-per-play rows: %s | assign=%s | abstain=%s", comma(nrow(top)), comma(assignable), comma(abstained)),
  "",
  "## Output files",
  paste0("- ", OUT_FEATS),
  paste0("- ", OUT_M03),
  paste0("- ", OUT_M04),
  paste0("- ", OUT_TOP)
)
writeLines(rep_lines, OUT_REPORT, useBytes = TRUE)

# ---------- PASS/FAIL ----------
checks <- tibble::tibble(
  check = c(
    "models_present",
    "capability_profiles_present",
    "score_folder_exists",
    "found_or_built_inputs",
    "built_features_rows>0",
    "m03_probs_no_na",
    "m04_probs_no_na",
    "top_one_row_per_play",
    "if_pstar_m04_then_decisions_valid"
  ),
  status = c(
    pass(file.exists(PATH_M03_PRI) && file.exists(PATH_M03_BK) && file.exists(PATH_M04)),
    pass(file.exists(PATH_CAPS)),
    pass(dir.exists(DIRS$score)),
    pass(n_inputs > 0),
    pass(nrow(ds_use) > 0),
    pass(!any(is.na(m03_preds$p03_primary)) && !any(is.na(m03_preds$p03_1p0))),
    pass(!any(is.na(m04_preds$p_go))),
    pass(nrow(top) == dplyr::n_distinct(paste(top$game_id, top$play_id))),
    pass(if (is.finite(pstar_m04)) all(top$decision %in% c("assign","abstain")) else TRUE)
  )
)
readr::write_csv(checks, OUT_STATUS_CSV)
writeLines(c("# Scoring status", "", md_table(checks)), OUT_STATUS_MD, useBytes = TRUE)

if (any(checks$status == "FAIL")) stop("Scoring verification: FAIL. See artifacts/score/score_status.{csv,md}", call. = FALSE)

message("Scoring verification: PASS.")
message("Wrote:",
        "\n  - ", OUT_FEATS,
        "\n  - ", OUT_M03,
        "\n  - ", OUT_M04,
        "\n  - ", OUT_TOP,
        "\n  - ", OUT_REPORT,
        "\n  - ", OUT_STATUS_CSV, " and ", OUT_STATUS_MD,
        "\n  - Per-play scoring inputs under ./score/ (created if needed)")










# 16_player_id_autosuggest.R — build/patch data/nfl_id_map.csv from train inputs using exact+fuzzy matches
# Outputs:
#   data/nfl_id_map.csv
#   artifacts/external_player_map_status.csv
#   artifacts/external_player_map_suggestions.csv

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE,
  nflreadr.verbose = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(stringr)
  library(rlang)
})

# Ensure stringdist available
if (!requireNamespace("stringdist", quietly = TRUE)) install.packages("stringdist", quiet = TRUE)
suppressPackageStartupMessages(library(stringdist))

set.seed(2025)

# ---------- Paths ----------
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  data      = B("data"),
  train     = B("train"),
  artifacts = B("artifacts"),
  raw       = B("artifacts","external_raw")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

OUT_STATUS   <- file.path(DIRS$artifacts, "external_player_map_status.csv")
OUT_SUGGEST  <- file.path(DIRS$artifacts, "external_player_map_suggestions.csv")
OUT_MAP      <- file.path(DIRS$data, "nfl_id_map.csv")

# ---------- Helpers ----------
read_csv_clean <- function(path) suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
rename_if_exists <- function(df, from, to){ if (from %in% names(df) && !(to %in% names(df))) dplyr::rename(df, !!to := !!sym(from)) else df }

norm_name <- function(x){
  x <- toupper(ifelse(is.na(x),"",as.character(x)))
  x <- str_replace_all(x, "\\b(JR|SR|II|III|IV|V)\\b\\.?","")
  x <- str_replace_all(x, "[^A-Z0-9 ]", " ")
  x <- str_squish(x)
  x
}

mode1 <- function(x){
  x <- x[!is.na(x) & x != ""]
  if (!length(x)) NA_character_ else names(sort(table(x), decreasing = TRUE))[1]
}

# ---------- Load training hints ----------
train_files <- Sys.glob(file.path(DIRS$train, "input_*.csv"))
if (!length(train_files)) stop("No train/input_*.csv files found.")

inp <- purrr::map_dfr(train_files, read_csv_clean)
inp <- inp |> rename_if_exists("nflid","nfl_id") |> rename_if_exists("player_id","nfl_id")
if (!("nfl_id" %in% names(inp))) stop("Train inputs must contain an nfl_id column (internal ID).")

# Discover hint columns (case-insensitive)
name_cols <- names(inp)[str_detect(names(inp), regex("(player_to_predict|display|name)", ignore_case = TRUE))]
team_cols <- names(inp)[str_detect(names(inp),  regex("(^team$|defense_team|offense_team)", ignore_case = TRUE))]

# Build hints WITHOUT tidy-eval / sym()
player_name_hint_vec <- if (length(name_cols) > 0) {
  mat <- as.data.frame(lapply(inp[, name_cols, drop = FALSE], as.character), stringsAsFactors = FALSE)
  apply(mat, 1, function(r) paste(r, collapse = " / "))
} else {
  rep(NA_character_, nrow(inp))
}

team_col <- if (length(team_cols) > 0) team_cols[1] else NA_character_
team_hint_vec <- if (!is.na(team_col)) as.character(inp[[team_col]]) else rep(NA_character_, nrow(inp))

hints <- tibble::tibble(
  internal_nfl_id   = as.character(inp$nfl_id),
  player_name_hint  = player_name_hint_vec,
  team_hint         = team_hint_vec
) %>%
  dplyr::group_by(internal_nfl_id) %>%
  dplyr::summarise(across(everything(), mode1), .groups = "drop")

# ---------- Load public refs: prefer saved raw; else download ----------
players_path <- file.path(DIRS$raw, "players.csv")
rosters_path <- file.path(DIRS$raw, "rosters.csv")
have_saved <- file.exists(players_path) && file.exists(rosters_path)

if (have_saved) {
  players_raw <- read_csv_clean(players_path)
  rosters_raw <- read_csv_clean(rosters_path)
} else {
  if (!requireNamespace("nflreadr", quietly = TRUE)) install.packages("nflreadr", quiet = TRUE)
  library(nflreadr)
  players_raw <- nflreadr::load_players() |> janitor::clean_names()
  rosters_raw <- nflreadr::load_rosters(seasons = nflreadr::most_recent_season()) |> janitor::clean_names()
}

players <- tibble(
  gsis_id      = if ("gsis_id" %in% names(players_raw)) as.character(players_raw$gsis_id) else NA_character_,
  nfl_id_chr   = if ("nfl_id" %in% names(players_raw))  as.character(players_raw$nfl_id)  else NA_character_,
  display_name = if ("display_name" %in% names(players_raw)) as.character(players_raw$display_name) else NA_character_,
  # position may not exist in some dumps; synthesize NA to keep downstream stable
  position     = if ("position" %in% names(players_raw)) as.character(players_raw$position) else NA_character_
) |>
  mutate(
    display_name_norm = norm_name(display_name),
    nfl_id_num_chr = {
      tmp <- gsub("[^0-9]", "", nfl_id_chr)
      ifelse(tmp=="", NA_character_, tmp)
    }
  ) |>
  distinct()

team_vec <- if ("team" %in% names(rosters_raw)) {
  as.character(rosters_raw$team)
} else if ("team_abbr" %in% names(rosters_raw)) {
  as.character(rosters_raw$team_abbr)
} else {
  rep(NA_character_, nrow(rosters_raw))
}

rosters <- tibble(
  season  = if ("season" %in% names(rosters_raw)) as.integer(rosters_raw$season) else NA_integer_,
  team    = team_vec,
  position= if ("position" %in% names(rosters_raw)) as.character(rosters_raw$position) else NA_character_,
  gsis_id = if ("gsis_id" %in% names(rosters_raw)) as.character(rosters_raw$gsis_id) else NA_character_
) |> distinct()

# Candidate pool (name + team); tolerate missing columns
pool <- rosters |>
  left_join(
    players |> select(any_of(c("gsis_id","display_name","display_name_norm","nfl_id_num_chr","position"))),
    by = "gsis_id"
  ) |>
  mutate(
    pool_team = team,
    pool_name_norm = display_name_norm
  ) |>
  select(any_of(c("pool_team","pool_name_norm","nfl_id_num_chr","gsis_id","display_name","position"))) |>
  distinct()

# Ensure 'position' exists for suggestion display
if (!"position" %in% names(pool)) pool <- dplyr::mutate(pool, position = NA_character_)

# ---------- Start from existing map (normalize types to character) ----------
existing <- if (file.exists(OUT_MAP)) read_csv_clean(OUT_MAP) else tibble(internal_nfl_id=character(), nflverse_nfl_id=character())
if (!all(c("internal_nfl_id","nflverse_nfl_id") %in% names(existing))) {
  existing <- tibble(internal_nfl_id=character(), nflverse_nfl_id=character())
}
existing <- existing %>%
  mutate(
    internal_nfl_id = as.character(internal_nfl_id),
    nflverse_nfl_id = as.character(nflverse_nfl_id)
  )

base <- hints %>% left_join(existing, by = "internal_nfl_id")

# ---------- Exact matches ----------
cand_exact <- base |>
  mutate(player_name_hint_norm = norm_name(player_name_hint)) |>
  filter(!is.na(player_name_hint_norm) & player_name_hint_norm!="") |>
  left_join(pool, by = c("player_name_hint_norm" = "pool_name_norm"))

pick_exact <- cand_exact |>
  mutate(team_match = !is.na(team_hint) & !is.na(pool_team) & (team_hint == pool_team)) |>
  group_by(internal_nfl_id) |>
  arrange(desc(team_match), display_name) |>
  slice_head(n=1) |>
  ungroup() |>
  transmute(internal_nfl_id, nflverse_nfl_id = nfl_id_num_chr,
            match_type = "exact", match_team = ifelse(team_match, "Y","N")) |>
  mutate(
    internal_nfl_id = as.character(internal_nfl_id),
    nflverse_nfl_id = as.character(nflverse_nfl_id),
    match_type = as.character(match_type),
    match_team = as.character(match_team)
  )

remaining <- anti_join(base, pick_exact, by = "internal_nfl_id")

# ---------- Fuzzy matches (Jaro–Winkler) ----------
cand_fuzzy <- remaining |>
  mutate(player_name_hint_norm = norm_name(player_name_hint)) |>
  filter(!is.na(player_name_hint_norm) & player_name_hint_norm!="")

get_top5 <- function(name_norm, team_hint){
  d <- stringdist::stringdist(name_norm, pool$pool_name_norm, method="jw")
  o <- order(d, na.last = TRUE)
  idx <- head(o, 5)
  tibble(
    pool_team = pool$pool_team[idx],
    pool_name_norm = pool$pool_name_norm[idx],
    nfl_id_num_chr = pool$nfl_id_num_chr[idx],
    gsis_id = pool$gsis_id[idx],
    display_name = pool$display_name[idx],
    position = pool$position[idx],
    dist_jw = d[idx],
    team_match = !is.na(team_hint) & !is.na(pool$pool_team[idx]) & (team_hint == pool$pool_team[idx])
  )
}

fz_blocks <- cand_fuzzy |>
  mutate(
    tmp = purrr::pmap(
      list(player_name_hint_norm, team_hint),
      function(nm, tm) get_top5(nm, tm)
    )
  )

# Flatten suggestions (top-5 per internal id), robust even if empty
suggestions <- fz_blocks |>
  select(internal_nfl_id, player_name_hint, team_hint, tmp) |>
  tidyr::unnest(cols = c(tmp), keep_empty = TRUE)

# Ensure expected columns exist even when empty
for (nm in c("dist_jw","team_match","nfl_id_num_chr","gsis_id","display_name","position","pool_team","pool_name_norm")) {
  if (!(nm %in% names(suggestions))) suggestions[[nm]] <- NA
}

# Safe ordering (won't error if 'dist_jw' was just created)
if (nrow(suggestions) > 0) {
  suggestions <- suggestions %>%
    arrange(internal_nfl_id, dist_jw, dplyr::desc(team_match))
}

# Best fuzzy pick (first by distance, then by team match)
pick_fuzzy <- suggestions %>%
  group_by(internal_nfl_id) %>%
  arrange(dist_jw, dplyr::desc(team_match)) %>%
  slice_head(n=1) %>%
  ungroup() %>%
  transmute(internal_nfl_id, nflverse_nfl_id = nfl_id_num_chr,
            match_type = "fuzzy", match_team = ifelse(team_match, "Y","N")) %>%
  mutate(
    internal_nfl_id = as.character(internal_nfl_id),
    nflverse_nfl_id = as.character(nflverse_nfl_id),
    match_type = as.character(match_type),
    match_team = as.character(match_team)
  )

# ---------- Merge picks with existing (existing wins) ----------
picks <- bind_rows(pick_exact, pick_fuzzy) |>
  filter(!is.na(nflverse_nfl_id) & nflverse_nfl_id != "") |>
  group_by(internal_nfl_id) |>
  slice_head(n=1) |>
  ungroup() %>%
  mutate(
    internal_nfl_id = as.character(internal_nfl_id),
    nflverse_nfl_id = as.character(nflverse_nfl_id)
  )

map_filled <- base |>
  transmute(internal_nfl_id, nflverse_nfl_id = nflverse_nfl_id) |>
  left_join(picks, by = "internal_nfl_id", suffix = c("_ex","_pick")) |>
  mutate(nflverse_nfl_id = dplyr::coalesce(nflverse_nfl_id_ex, nflverse_nfl_id_pick)) |>
  select(internal_nfl_id, nflverse_nfl_id) |>
  distinct()

# ---------- Write outputs ----------
dir.create(DIRS$data, showWarnings=FALSE, recursive=TRUE)
dir.create(DIRS$artifacts, showWarnings=FALSE, recursive=TRUE)

readr::write_csv(map_filled, OUT_MAP)
readr::write_csv(suggestions, OUT_SUGGEST)

status <- tibble::tibble(
  total_internal_ids = nrow(hints),
  suggested_or_existing = sum(!is.na(map_filled$nflverse_nfl_id) & map_filled$nflverse_nfl_id!=""),
  remaining_blank = sum(is.na(map_filled$nflverse_nfl_id) | map_filled$nflverse_nfl_id=="")
)
readr::write_csv(status, OUT_STATUS)

message("PLAYER MAP AUTOSUGGEST: COMPLETE")
message("Wrote:\n  - ", OUT_MAP,
        "\n  - ", OUT_STATUS,
        "\n  - ", OUT_SUGGEST)










# 16.2_external_enrichment.R — external enrichment w/ inline game_id mapping (no separate 16c needed)
# Outputs:
#   artifacts/external_features.csv
#   artifacts/external_features_status.{csv,md}
#   artifacts/external_features_schema.md
#   artifacts/external_features_report.md
#   artifacts/external_raw/{players.csv, rosters.csv, pbp.csv, schedules.csv}
#   artifacts/external_unmatched_game_ids.csv
#   artifacts/external_unmatched_nfl_ids.csv
#   data/game_id_map.csv
#   artifacts/external_game_map_status.csv

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE,
  nflreadr.verbose = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
  library(rlang)
  library(stringr)
})

ensure_pkg <- function(pkg){
  if (!requireNamespace(pkg, quietly = TRUE)) install.packages(pkg, quiet = TRUE)
  suppressPackageStartupMessages(library(pkg, character.only = TRUE))
}
ensure_pkg("dplyr"); ensure_pkg("readr"); ensure_pkg("tidyr"); ensure_pkg("tibble"); ensure_pkg("purrr"); ensure_pkg("janitor"); ensure_pkg("stringr"); ensure_pkg("nflreadr")

set.seed(2025)

# ---------------- Paths ----------------
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  data      = B("data"),
  splits    = B("data","splits"),
  train     = B("train"),
  artifacts = B("artifacts")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_SPLIT_MAP    <- file.path(DIRS$splits, "plays_split_map.csv")
PATH_SCORE_FEATS  <- file.path(DIRS$artifacts, "score", "score_features.csv")
PATH_GAMEID_MAP   <- file.path(DIRS$data, "game_id_map.csv")   # may be empty; we will build/patch
PATH_NFLID_MAP    <- file.path(DIRS$data, "nfl_id_map.csv")    # optional

OUT_DIR      <- DIRS$artifacts
OUT_RAW      <- file.path(OUT_DIR, "external_raw"); dir.create(OUT_RAW, showWarnings = FALSE, recursive = TRUE)
OUT_CSV      <- file.path(OUT_DIR, "external_features.csv")
OUT_STATUS_C <- file.path(OUT_DIR, "external_features_status.csv")
OUT_STATUS_M <- file.path(OUT_DIR, "external_features_status.md")
OUT_SCHEMA_M <- file.path(OUT_DIR, "external_features_schema.md")
OUT_REPORT_M <- file.path(OUT_DIR, "external_features_report.md")
OUT_UNMATCH_GID <- file.path(OUT_DIR, "external_unmatched_game_ids.csv")
OUT_UNMATCH_NID <- file.path(OUT_DIR, "external_unmatched_nfl_ids.csv")
OUT_GAME_MAP_STATUS <- file.path(OUT_DIR, "external_game_map_status.csv")

# ---------------- Helpers (no '.' pronoun inside mutate/select) ----------------
read_csv_clean <- function(path) suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
rename_if_exists <- function(df, from, to){ if (from %in% names(df) && !(to %in% names(df))) dplyr::rename(df, !!to := !!sym(from)) else df }
ensure_cols <- function(df, cols, value = NA){ for (nm in cols) if (!(nm %in% names(df))) df[[nm]] <- value; df }
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
is_syn_id <- function(x){ x <- toupper(as.character(x)); startsWith(x, "SYN") }
extract_years_from_ids <- function(x){
  x <- as.character(x)
  y1 <- suppressWarnings(as.integer(stringr::str_extract(x, "^(\\d{4})(?=_)")))
  y2 <- suppressWarnings(as.integer(stringr::str_extract(x, "^(\\d{4})(?=\\d{6})")))
  y3 <- suppressWarnings(as.integer(stringr::str_extract(x, "(\\d{4})")))
  dplyr::coalesce(y1, y2, y3)
}
col_or_char <- function(df, nm){ if (nm %in% names(df)) as.character(df[[nm]]) else rep(NA_character_, nrow(df)) }
col_or_int  <- function(df, nm){ if (nm %in% names(df)) suppressWarnings(as.integer(df[[nm]])) else rep(NA_integer_, nrow(df)) }
col_or_num  <- function(df, nm){ if (nm %in% names(df)) suppressWarnings(as.numeric(df[[nm]])) else rep(NA_real_, nrow(df)) }

# team code normalization
fix_team <- function(x){
  x <- stringr::str_trim(toupper(ifelse(is.na(x), "", as.character(x))))
  dplyr::recode(
    x,
    "JAC"="JAX","WSH"="WAS","ARZ"="ARI","STL"="LAR","LA"="LAR","SD"="LAC","OAK"="LV","WFT"="WAS",
    "TBB"="TB","NOR"="NO","NWE"="NE","GNB"="GB","SFO"="SF","KCC"="KC",
    .default = x
  )
}

# robust flexible column picker
pick_col <- function(df, preferred = character(), pattern = NULL, required = FALSE, desc = "column") {
  for (nm in preferred) if (nm %in% names(df)) return(nm)
  if (!is.null(pattern)) {
    hits <- names(df)[grepl(pattern, names(df), ignore.case = TRUE)]
    if (length(hits)) return(hits[1])
  }
  if (required) stop(sprintf("Could not find %s. Columns: %s", desc, paste(names(df), collapse=", ")))
  NA_character_
}

# find supplementary_data.csv (for mapping)
find_sup <- function(root = B(".")) {
  cands <- c(
    file.path(DIRS$train, "supplementary_data.csv"),
    file.path(root, "supplementary_data.csv"),
    file.path(DIRS$data, "supplementary_data.csv"),
    file.path(DIRS$artifacts, "supplementary_data.csv")
  )
  hit <- cands[file.exists(cands)]
  if (length(hit)) return(hit[1])
  hit2 <- list.files(root, pattern="^supplementary_data\\.csv$", recursive=TRUE, full.names=TRUE)
  if (length(hit2)) return(hit2[1])
  NA_character_
}

# ---------------- Build the base key set (UNION of all sources) ----------------
base_list <- list()

if (file.exists(PATH_SCORE_FEATS)) {
  df <- read_csv_clean(PATH_SCORE_FEATS)
  if (all(c("game_id","play_id") %in% names(df))) {
    df2 <- df |>
      transmute(game_id = as.character(game_id),
                play_id = suppressWarnings(as.integer(play_id)),
                nfl_id  = suppressWarnings(as.integer(if ("nfl_id" %in% names(df)) nfl_id else NA)))
    base_list[["score_features"]] <- distinct(df2)
  }
}

train_files <- Sys.glob(file.path(DIRS$train, "input_*.csv"))
if (length(train_files)) {
  inp <- purrr::map_dfr(train_files, read_csv_clean)
  inp <- inp |> rename_if_exists("nflid","nfl_id") |> rename_if_exists("player_id","nfl_id")
  if (all(c("game_id","play_id") %in% names(inp))) {
    base_list[["train_inputs"]] <- inp |>
      transmute(game_id = as.character(game_id),
                play_id = suppressWarnings(as.integer(play_id)),
                nfl_id  = suppressWarnings(as.integer(if ("nfl_id" %in% names(inp)) nfl_id else NA))) |>
      distinct()
  }
}

if (file.exists(PATH_SPLIT_MAP)) {
  sp <- read_csv_clean(PATH_SPLIT_MAP)
  if (all(c("game_id","play_id") %in% names(sp))) {
    base_list[["splits_map"]] <- sp |>
      transmute(game_id = as.character(game_id),
                play_id = suppressWarnings(as.integer(play_id)),
                nfl_id  = NA_integer_) |>
      distinct()
  }
}

if (length(base_list) == 0L) stop("No keys found: need one of artifacts/score/score_features.csv, train/input_*.csv, or data/splits/plays_split_map.csv.")

base_keys <- dplyr::bind_rows(base_list) |> distinct()

# ---------------- Seasons to fetch (robust) ----------------
years_from_raw  <- extract_years_from_ids(base_keys$game_id[!is_syn_id(base_keys$game_id)])
train_years_from_names <- {
  if (length(train_files)) {
    ys <- stringr::str_extract(basename(train_files), "(?<=input_)\\d{4}(?=_w)")
    suppressWarnings(as.integer(ys[!is.na(ys)]))
  } else integer()
}
cand_years <- sort(unique(c(years_from_raw, train_years_from_names)))
seasons_guess <- if (length(train_years_from_names) > 0L) sort(unique(train_years_from_names)) else
  if (length(cand_years) > 0L) cand_years else
    nflreadr::most_recent_season()

# ---------------- Download public external data ----------------
players_raw <- nflreadr::load_players() |> janitor::clean_names()
players <- {
  df <- players_raw
  tibble(
    gsis_id      = col_or_char(df, "gsis_id"),
    nfl_id_chr   = col_or_char(df, "nfl_id"),
    position     = col_or_char(df, "position"),
    ngs_position = col_or_char(df, "ngs_position"),
    display_name = col_or_char(df, "display_name")
  ) |>
    mutate(nfl_id_num = suppressWarnings(as.integer(gsub("[^0-9]", "", nfl_id_chr)))) |>
    distinct()
}

# Dedup map to prevent many-to-many on player IDs
players_map <- players |>
  filter(!is.na(nfl_id_num), !is.na(gsis_id), nfl_id_num != 0, gsis_id != "") |>
  count(nfl_id_num, gsis_id, name = "freq") |>
  arrange(nfl_id_num, desc(freq), gsis_id) |>
  group_by(nfl_id_num) |> slice_head(n = 1) |> ungroup() |>
  select(nfl_id_num, gsis_id)

players_by_gsis <- players |>
  filter(!is.na(gsis_id), gsis_id != "") |>
  arrange(gsis_id, desc(nchar(coalesce(display_name, "")))) |>
  distinct(gsis_id, .keep_all = TRUE) |>
  select(gsis_id, display_name, position)

rosters_raw <- nflreadr::load_rosters(seasons = seasons_guess) |> janitor::clean_names()
rosters <- {
  df <- rosters_raw
  team_vec <- if ("team" %in% names(df)) as.character(df$team) else if ("team_abbr" %in% names(df)) as.character(df$team_abbr) else rep(NA_character_, nrow(df))
  tibble(
    season  = col_or_int(df, "season"),
    team    = team_vec,
    position= col_or_char(df, "position"),
    gsis_id = col_or_char(df, "gsis_id")
  ) |> distinct()
}

# Canonicalize to one row per (season, gsis_id) to avoid many-to-many explosions
rosters_canon <- rosters |>
  mutate(position = ifelse(is.na(position) | position=="", NA_character_, position)) |>
  count(season, gsis_id, team, position, name = "freq") |>
  arrange(season, gsis_id, desc(freq), team) |>
  group_by(season, gsis_id) |> slice_head(n = 1) |> ungroup() |>
  select(season, gsis_id, team, position)

sched_raw <- nflreadr::load_schedules(seasons = seasons_guess) |> janitor::clean_names()
sched <- {
  df <- sched_raw
  tibble(
    season    = col_or_int(df, "season"),
    week      = col_or_int(df, "week"),
    game_id   = col_or_char(df, "game_id"),
    roof      = col_or_char(df, "roof"),
    surface   = col_or_char(df, "surface"),
    temp_f    = col_or_num(df, "temp"),
    wind_mph  = col_or_num(df, "wind"),
    home_team = fix_team(col_or_char(df, "home_team")),
    away_team = fix_team(col_or_char(df, "away_team"))
  ) |> distinct()
}
sched_ids <- toupper(trimws(as.character(sched$game_id)))

pbp_raw <- nflreadr::load_pbp(seasons = seasons_guess) |> janitor::clean_names()
pbp_std <- pbp_raw |>
  rename_if_exists("qtr","quarter") |>
  rename_if_exists("posteam","offense_team") |>
  rename_if_exists("defteam","defense_team") |>
  ensure_cols(c("down","distance","ydstogo","quarter","game_seconds_remaining",
                "score_differential","yardline_100","shotgun","no_huddle",
                "offense_team","defense_team","game_id","play_id"))
if (all(is.na(pbp_std$distance)) && !all(is.na(pbp_std$ydstogo))) {
  pbp_std$distance <- pbp_std$ydstogo
}
pbp <- {
  df <- pbp_std
  tibble(
    game_id = as.character(df$game_id),
    play_id = suppressWarnings(as.integer(df$play_id)),
    down = suppressWarnings(as.integer(df$down)),
    distance = suppressWarnings(as.integer(df$distance)),
    ydstogo = suppressWarnings(as.integer(df$ydstogo)),
    quarter = suppressWarnings(as.integer(df$quarter)),
    game_seconds_remaining = suppressWarnings(as.numeric(df$game_seconds_remaining)),
    score_differential = suppressWarnings(as.integer(df$score_differential)),
    yardline_100 = suppressWarnings(as.numeric(df$yardline_100)),
    shotgun = as.logical(df$shotgun),
    no_huddle = as.logical(df$no_huddle),
    offense_team = as.character(df$offense_team),
    defense_team = as.character(df$defense_team)
  ) |> distinct(game_id, play_id, .keep_all = TRUE)
}

# --- Save raw downloads for inspection ---
readr::write_csv(players,  file.path(OUT_RAW, "players.csv"))
readr::write_csv(rosters,  file.path(OUT_RAW, "rosters.csv"))
readr::write_csv(pbp,      file.path(OUT_RAW, "pbp.csv"))
readr::write_csv(sched,    file.path(OUT_RAW, "schedules.csv"))

# ---------------- Inline GAME-ID MAP (no many-to-many joins) ----------------
existing_map <- if (file.exists(PATH_GAMEID_MAP)) {
  read_csv_clean(PATH_GAMEID_MAP) |>
    transmute(internal_game_id = as.character(internal_game_id),
              nflverse_game_id = as.character(nflverse_game_id)) |>
    distinct()
} else tibble(internal_game_id = character(), nflverse_game_id = character())

need_internal_ids <- base_keys |> transmute(internal_game_id = as.character(game_id)) |> distinct()

# supplementary_data.csv builder
sup_path <- find_sup()
built_map <- tibble(internal_game_id=character(), nflverse_game_id=character())
ambiguities <- tibble(internal_game_id=character(), candidates=character())

if (!is.na(sup_path) && file.exists(sup_path)) {
  sup <- read_csv_clean(sup_path)
  
  col_game   <- pick_col(sup, preferred=c("game_id","internal_game_id","gid"),           pattern="^game.*id$", required=TRUE,  desc="game_id")
  col_season <- pick_col(sup, preferred=c("season","season_year","year"),                pattern="season|year", required=TRUE,  desc="season")
  col_week   <- pick_col(sup, preferred=c("week","week_no","week_number","wk"),         pattern="^wk$|week",   required=TRUE,  desc="week")
  col_home   <- pick_col(sup, preferred=c("home_team_abbr","home_abbr","home_team"),    pattern="^home.*(abbr|team)$|^home$", required=TRUE,  desc="home team")
  col_away   <- pick_col(sup, preferred=c("away_team_abbr","visitor_team_abbr","away_abbr","away_team","visitor_team"),
                         pattern="^(away|visitor).*(abbr|team)$|^(away|visitor)$", required=TRUE, desc="away team")
  
  games0 <- sup |>
    transmute(
      internal_game_id = as.character(!!sym(col_game)),
      season = suppressWarnings(as.integer(!!sym(col_season))),
      week   = suppressWarnings(as.integer(!!sym(col_week))),
      home   = fix_team(!!sym(col_home)),
      away   = fix_team(!!sym(col_away))
    ) |>
    filter(!is.na(season), !is.na(week), !is.na(home), !is.na(away), home!="" , away!="") |>
    distinct() |>
    mutate(week_str = sprintf("%02d", week),
           primary = paste(season, week_str, away, home, sep="_"))
  
  # Fast path: primary candidate present in schedules
  ok <- games0 |> filter(toupper(primary) %in% sched_ids) |>
    transmute(internal_game_id, nflverse_game_id = primary)
  
  # Remaining need candidate search; try swap and LA disambiguation without joining schedules
  
  rem <- games0 |> anti_join(ok |> select(internal_game_id), by = "internal_game_id")
  # Deterministic join on season/week/home/away using normalized teams from schedules
  if (nrow(rem) > 0) {
    sched_key <- sched |>
      transmute(season = as.integer(season),
                week   = as.integer(week),
                home   = as.character(home_team),
                away   = as.character(away_team),
                nflverse_game_id = toupper(as.character(game_id)))
    join_hit <- rem |>
      left_join(sched_key, by = c("season","week","home"="home","away"="away")) |>
      filter(!is.na(nflverse_game_id)) |>
      transmute(internal_game_id, nflverse_game_id)
    ok <- bind_rows(ok, join_hit) |> distinct()
    rem <- games0 |> anti_join(ok |> select(internal_game_id), by = "internal_game_id")
  }
  if (nrow(rem) > 0) {
    
    try_candidates <- function(season, week_str, home, away) {
      cands <- c(
        paste(season, week_str, away, home, sep="_"),
        paste(season, week_str, home, away, sep="_") # swap
      )
      # LA disambiguation
      swap_la <- function(t) if (t %in% c("LAR","LAC")) setdiff(c("LAR","LAC"), t) else character(0)
      if (home %in% c("LAR","LAC") || away %in% c("LAR","LAC")) {
        h2 <- if (length(swap_la(home))) swap_la(home) else home
        a2 <- if (length(swap_la(away))) swap_la(away) else away
        # Try both toggles individually and together, both orientations
        cand_set <- unique(c(
          paste(season, week_str, a2, home, sep="_"),
          paste(season, week_str, away, h2, sep="_"),
          paste(season, week_str, a2, h2, sep="_"),
          paste(season, week_str, h2, a2, sep="_")
        ))
        cands <- unique(c(cands, cand_set))
      }
      cands
    }
    
    resolved <- pmap_dfr(rem, function(internal_game_id, season, week, home, away, week_str, primary){
      cands <- try_candidates(season, week_str, home, away)
      hits <- cands[toupper(cands) %in% sched_ids]
      if (length(hits) == 0) {
        tibble(internal_game_id = internal_game_id, nflverse_game_id = NA_character_, candidates = paste(cands, collapse=";"))
      } else {
        tibble(internal_game_id = internal_game_id, nflverse_game_id = hits[1], candidates = paste(hits, collapse=";"))
      }
    })
    
    # Collect ambiguous cases (multiple hits)
    amb <- resolved |> filter(!is.na(nflverse_game_id) & grepl(";", candidates))
    if (nrow(amb)) {
      ambiguities <- bind_rows(ambiguities, amb |> select(internal_game_id, candidates))
    }
    
    built_map <- bind_rows(ok, resolved |> filter(!is.na(nflverse_game_id)) |> select(internal_game_id, nflverse_game_id)) |>
      distinct(internal_game_id, .keep_all = TRUE)
  } else {
    built_map <- ok |> distinct()
  }
}

# Fallback: allow internal IDs already in nflverse pattern that exist in schedules
still_need <- need_internal_ids |> anti_join(existing_map,  by="internal_game_id") |> anti_join(built_map, by="internal_game_id")
if (nrow(still_need) > 0) {
  pat <- "^[0-9]{4}_[0-9]{2}_[A-Z]{2,3}_[A-Z]{2,3}$"
  fallback <- still_need |>
    filter(str_detect(toupper(internal_game_id), pat)) |>
    mutate(nflverse_game_id = internal_game_id) |>
    filter(toupper(nflverse_game_id) %in% sched_ids) |>
    distinct()
  built_map <- bind_rows(built_map, fallback) |> distinct(internal_game_id, .keep_all = TRUE)
}

# Merge precedence: built_map wins
full_map <- bind_rows(built_map, existing_map |> anti_join(built_map, by="internal_game_id")) |>
  semi_join(need_internal_ids, by = "internal_game_id") |>
  distinct()

# Write map + status
dir.create(DIRS$data, showWarnings=FALSE, recursive=TRUE)
readr::write_csv(full_map, PATH_GAMEID_MAP)

dup_check <- nrow(full_map) == dplyr::n_distinct(full_map$internal_game_id)
public_match_cnt <- sum(toupper(full_map$nflverse_game_id) %in% sched_ids)
gm_status <- tibble::tibble(
  check  = c("map_written","rows>0","distinct_internal==rows","exist_in_public_schedules","source_sup_path","ambiguities_found"),
  detail = c(
    PATH_GAMEID_MAP,
    paste0("rows=", nrow(full_map)),
    paste0("distinct_internal=", dplyr::n_distinct(full_map$internal_game_id)),
    paste0("public_match=", public_match_cnt, "/", nrow(full_map)),
    ifelse(is.na(sup_path),"NA",sup_path),
    if (nrow(ambiguities)) paste0("ambiguous=", nrow(ambiguities), " (first: ", paste(head(ambiguities$internal_game_id,3), collapse=", "), ")") else "ambiguous=0"
  ),
  status = c(
    "PASS",
    pass(nrow(full_map)>0),
    pass(dup_check),
    pass(public_match_cnt == nrow(full_map)),
    "INFO",
    pass(nrow(ambiguities) == 0)
  )
)
readr::write_csv(gm_status, OUT_GAME_MAP_STATUS)

# ---------------- Optional player map (internal -> nflverse id)
nid_map <- if (file.exists(PATH_NFLID_MAP)) {
  read_csv_clean(PATH_NFLID_MAP) |>
    transmute(internal_nfl_id = suppressWarnings(as.integer(internal_nfl_id)),
              nfl_id_join = suppressWarnings(as.integer(nflverse_nfl_id))) |>
    filter(!is.na(internal_nfl_id)) |>
    distinct()
} else tibble(internal_nfl_id = integer(), nfl_id_join = integer())

# ---------------- Build keys w/ maps ----------------
gid_map <- full_map |>
  transmute(game_id = as.character(internal_game_id),
            game_id_join = as.character(nflverse_game_id))

keys0 <- base_keys |>
  mutate(game_id = as.character(game_id),
         nfl_id  = suppressWarnings(as.integer(nfl_id))) |>
  left_join(gid_map, by = "game_id") |>
  mutate(game_id_join = dplyr::coalesce(game_id_join, game_id)) |>
  # optional player map to override nfl_id if provided
  left_join(nid_map, by = c("nfl_id" = "internal_nfl_id")) |>
  mutate(nfl_id_join = dplyr::coalesce(nfl_id_join, nfl_id)) |>
  distinct(game_id, play_id, nfl_id, game_id_join, nfl_id_join, .keep_all = TRUE)

# Filter PBP/Sched to mapped games to keep memory low
mapped_ids <- unique(na.omit(keys0$game_id_join))
sched_small <- sched |> semi_join(tibble(game_id = mapped_ids), by = "game_id")
pbp_small   <- pbp   |> semi_join(tibble(game_id = mapped_ids), by = "game_id")
gid_season  <- sched_small |> select(game_id, season) |> distinct()

# Start enrichment
enriched <- keys0 |>
  mutate(play_id = suppressWarnings(as.integer(play_id))) |>
  left_join(gid_season, by = c("game_id_join" = "game_id")) |>
  # nfl_id_join -> players_map (nfl_id_num -> gsis_id)
  left_join(players_map, by = c("nfl_id_join" = "nfl_id_num")) |>
  # gsis_id -> players_by_gsis (display_name/position hint)
  left_join(players_by_gsis, by = "gsis_id") |>
  mutate(position_hint = position) |>
  select(-position) |>
  # season+gsis_id -> canonical roster (one row per key)
  left_join(rosters_canon, by = c("season","gsis_id")) |>
  mutate(
    team     = ifelse(is.na(team), "UNKNOWN", team),
    position = dplyr::coalesce(position, position_hint, "UNKNOWN")
  ) |>
  select(-position_hint) |>
  # PBP and Schedules
  left_join(pbp_small,   by = c("game_id_join" = "game_id", "play_id" = "play_id")) |>
  left_join(sched_small |> select(-season), by = c("game_id_join" = "game_id")) |>
  # final columns
  transmute(
    game_id = game_id, play_id = play_id, nfl_id = nfl_id,
    team, position,
    down, distance, ydstogo, quarter, game_seconds_remaining,
    score_differential, yardline_100, shotgun, no_huddle,
    offense_team, defense_team, home_team, away_team,
    roof, surface, temp_f, wind_mph
  ) |>
  ensure_cols(
    c("team","position","down","distance","ydstogo","quarter","game_seconds_remaining",
      "score_differential","yardline_100","shotgun","no_huddle","offense_team","defense_team",
      "home_team","away_team","roof","surface","temp_f","wind_mph"),
    value = NA
  ) |>
  arrange(game_id, play_id, nfl_id)

enriched <- dplyr::filter(enriched, !is_syn_id(game_id))

# ---------------- Gap reports ----------------
# Write ALL unmatched (including SYN*) for transparency
unmatched_gid_all <- keys0 |>
  distinct(game_id, game_id_join) |>
  anti_join(gid_season |> rename(game_id_join = game_id), by = "game_id_join")
readr::write_csv(unmatched_gid_all, OUT_UNMATCH_GID)

# But for PASS/FAIL, treat SYN* as out-of-scope
unmatched_gid_real <- unmatched_gid_all |> filter(!is_syn_id(game_id_join))

unmatched_nid <- keys0 |>
  distinct(nfl_id, nfl_id_join) |>
  filter(!is.na(nfl_id_join)) |>
  anti_join(players_map |> transmute(nfl_id_join = nfl_id_num) |> distinct(), by = "nfl_id_join")
readr::write_csv(unmatched_nid, OUT_UNMATCH_NID)

# ---------------- Write outputs ----------------
dir.create(OUT_DIR, recursive = TRUE, showWarnings = FALSE)
readr::write_csv(enriched, OUT_CSV)

# ---------------- PASS/FAIL & coverage ----------------
n_base <- nrow(keys0)
n_out  <- nrow(enriched)
dups   <- enriched |> count(game_id, play_id, nfl_id, name = "n") |> filter(n > 1)

cov_roster <- if (n_out > 0) mean(enriched$team != "UNKNOWN" | enriched$position != "UNKNOWN", na.rm = TRUE) else NA_real_
cov_pbp    <- if (n_out > 0) mean(!is.na(enriched$down) | !is.na(enriched$ydstogo), na.rm = TRUE) else NA_real_
cov_weath  <- if (n_out > 0) mean(!is.na(enriched$roof) | !is.na(enriched$surface) | !is.na(enriched$temp_f) | !is.na(enriched$wind_mph), na.rm = TRUE) else NA_real_

non_syn_base <- nrow(keys0 |> filter(!is_syn_id(game_id_join)))
matched_gid_cnt <- non_syn_base - nrow(unmatched_gid_real)

matched_nid_base <- nrow(keys0 |> filter(!is.na(nfl_id)))
matched_nid_cnt  <- matched_nid_base - nrow(unmatched_nid)

checks <- tibble::tibble(
  check = c(
    "base_rows_found",
    "output_written",
    "no_duplicate_keys_(game,play,nfl)",
    "players_downloaded",
    "rosters_downloaded",
    "pbp_downloaded",
    "schedules_downloaded",
    "game_id_map_written",
    "game_id_matches_all",
    "nfl_id_matches_all",
    "roster_coverage>=0",
    "pbp_coverage>=0",
    "weather_coverage>=0",
    "seasons_chosen"
  ),
  detail = c(
    paste0("base_rows=", n_base),
    paste0("rows_out=", n_out, " | file=", OUT_CSV),
    paste0("dups=", nrow(dups)),
    paste0("players_n=", nrow(players)),
    paste0("rosters_n=", nrow(rosters)),
    paste0("pbp_n=", nrow(pbp)),
    paste0("sched_n=", nrow(sched)),
    paste0("game_id_map=", PATH_GAMEID_MAP, " | rows=", nrow(full_map)),
    paste0("matched=", matched_gid_cnt,
           " | non_synthetic_total=", non_syn_base,
           " | unmatched_list=", basename(OUT_UNMATCH_GID),
           " (file lists SYN* too)"),
    paste0("matched=", matched_nid_cnt, "/", matched_nid_base, " | unmatched_list=", basename(OUT_UNMATCH_NID)),
    if (is.finite(cov_roster)) sprintf("coverage=%.3f", cov_roster) else "n/a",
    if (is.finite(cov_pbp))    sprintf("coverage=%.3f", cov_pbp)    else "n/a",
    if (is.finite(cov_weath))  sprintf("coverage=%.3f", cov_weath)  else "n/a",
    paste(seasons_guess, collapse = ", ")
  ),
  status = c(
    pass(n_base > 0),
    pass(file.exists(OUT_CSV) && n_out >= 0),
    pass(nrow(dups) == 0),
    pass(nrow(players) > 0),
    pass(nrow(rosters) > 0),
    pass(nrow(pbp) > 0),
    pass(nrow(sched) > 0),
    pass(file.exists(PATH_GAMEID_MAP) && nrow(full_map) > 0),
    pass(matched_gid_cnt == non_syn_base),
    pass(matched_nid_cnt == matched_nid_base),
    pass(is.finite(cov_roster)),
    pass(is.finite(cov_pbp)),
    pass(is.finite(cov_weath)),
    pass(length(seasons_guess) > 0)
  )
)

readr::write_csv(checks, OUT_STATUS_C)
writeLines(c("# External enrichment status", "", md_table(checks)), OUT_STATUS_M, useBytes = TRUE)

# ---------------- Schema & brief report ----------------
schema_lines <- c(
  "# external_features.csv — schema",
  "",
  "Keys: game_id, play_id, nfl_id (your internal IDs).",
  "Mapping now inlined (no 16c needed): data/game_id_map.csv is built/filled here.",
  "Optional player map: data/nfl_id_map.csv [internal_nfl_id,nflverse_nfl_id] (used if present).",
  "Joined fields: team, position (rosters/players); down,distance,ydstogo,quarter,game_seconds_remaining,",
  "score_differential,yardline_100,shotgun,no_huddle,offense_team,defense_team (pbp);",
  "home_team,away_team,roof,surface,temp_f,wind_mph (schedules).",
  "",
  paste0("Seasons fetched: ", paste(seasons_guess, collapse = ", "))
)
writeLines(schema_lines, OUT_SCHEMA_M, useBytes = TRUE)

rep_lines <- c(
  "# External enrichment report",
  "",
  sprintf("- Base rows: %s", scales::comma(n_base)),
  sprintf("- Output rows: %s", scales::comma(n_out)),
  "",
  sprintf("- Game-ID matches (non-SYN): %s/%s (see %s; file lists SYN* too)",
          scales::comma(matched_gid_cnt), scales::comma(non_syn_base), basename(OUT_UNMATCH_GID)),
  sprintf("- NFL-ID matches:  %s/%s (see %s)",
          scales::comma(matched_nid_cnt), scales::comma(matched_nid_base), basename(OUT_UNMATCH_NID)),
  "",
  sprintf("- Coverage — roster=%s | pbp=%s | weather=%s",
          if (is.finite(cov_roster)) sprintf("%.3f", cov_roster) else "n/a",
          if (is.finite(cov_pbp))    sprintf("%.3f", cov_pbp)    else "n/a",
          if (is.finite(cov_weath))  sprintf("%.3f", cov_weath)  else "n/a"),
  "",
  "- Raw downloads saved under artifacts/external_raw/: players.csv, rosters.csv, pbp.csv, schedules.csv"
)
writeLines(rep_lines, OUT_REPORT_M, useBytes = TRUE)

message("External enrichment: COMPLETE (with inline game_id mapping, no many-to-many joins).")
message("Wrote:\n  - ", OUT_CSV,
        "\n  - ", OUT_STATUS_C, " and ", OUT_STATUS_M,
        "\n  - ", OUT_SCHEMA_M, " and ", OUT_REPORT_M,
        "\n  - ", OUT_UNMATCH_GID, " and ", OUT_UNMATCH_NID,
        "\n  - Raw downloads in ", OUT_RAW,
        "\n  - Game map at ", PATH_GAMEID_MAP,
        "\n  - Game map status at ", OUT_GAME_MAP_STATUS)

# === Add-on: cosmetically complete nfl_id_map.csv (identity fill when valid) ===
# Safe to paste at the very end of 16_external_enrichment.R

try({
  # 1) Internal IDs used this run (from keys0)
  needed_ids_tbl <- keys0 |>
    dplyr::filter(!is.na(nfl_id)) |>
    dplyr::transmute(internal_nfl_id = as.character(nfl_id)) |>
    dplyr::distinct()
  
  # 2) Load existing map (or start empty)
  map_path <- PATH_NFLID_MAP
  map0 <- if (file.exists(map_path)) read_csv_clean(map_path)
  else tibble::tibble(internal_nfl_id=character(), nflverse_nfl_id=character())
  if (!("internal_nfl_id" %in% names(map0))) map0$internal_nfl_id <- character()
  if (!("nflverse_nfl_id" %in% names(map0))) map0$nflverse_nfl_id <- character()
  map0 <- map0 |>
    dplyr::mutate(
      internal_nfl_id = as.character(internal_nfl_id),
      nflverse_nfl_id = as.character(nflverse_nfl_id)
    )
  
  # 3) Ensure all needed IDs are present
  map_full <- needed_ids_tbl |>
    dplyr::left_join(map0, by = "internal_nfl_id")
  
  # 4) Valid public NFL IDs (from players loaded earlier in 16)
  valid_public <- players |>
    dplyr::mutate(nfl_id_num = suppressWarnings(as.integer(gsub("[^0-9]", "", nfl_id_chr)))) |>
    dplyr::filter(!is.na(nfl_id_num)) |>
    dplyr::distinct(nfl_id_num) |>
    dplyr::pull(nfl_id_num)
  
  # 5) Identity-fill blanks where internal already equals a valid public ID
  map_full <- map_full |>
    dplyr::mutate(
      internal_num = suppressWarnings(as.integer(gsub("[^0-9]", "", internal_nfl_id))),
      nflverse_nfl_id = dplyr::case_when(
        !is.na(nflverse_nfl_id) & nflverse_nfl_id != "" ~ nflverse_nfl_id,                  # keep existing
        !is.na(internal_num) & internal_num %in% valid_public ~ as.character(internal_num),  # identity fill
        TRUE ~ ""                                                                            # leave blank otherwise
      )
    ) |>
    dplyr::select(internal_nfl_id, nflverse_nfl_id) |>
    dplyr::distinct()
  
  # 6) Write map + tiny status (purely cosmetic)
  readr::write_csv(map_full, map_path)
  
  filled_count <- sum(map_full$nflverse_nfl_id != "" & !is.na(map_full$nflverse_nfl_id))
  total_needed <- nrow(map_full)
  status_row <- tibble::tibble(
    check  = c("nfl_id_map_present","identity_fill_applied"),
    detail = c(paste0("rows=", total_needed, " | file=", map_path),
               paste0("filled_now=", filled_count, " / ", total_needed)),
    status = c(if (total_needed>0) "PASS" else "FAIL", "INFO")
  )
  readr::write_csv(status_row, file.path(OUT_DIR, "external_player_map_status.csv"))
}, silent = TRUE)










# 16a_verify_outputs.R — independent verification for 16 (enrichment) and 16a (player map)
# Outputs:
#   artifacts/external_verification_status.{csv,md}
#   artifacts/player_id_preview.csv  (names ↔ IDs quick look)

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(stringr)
  library(scales)
})

set.seed(2025)

# ---------------- Paths / helpers ----------------
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  data      = B("data"),
  artifacts = B("artifacts"),
  raw       = B("artifacts","external_raw")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_FEATURES          <- file.path(DIRS$artifacts, "external_features.csv")
PATH_FEATURES_STATUS   <- file.path(DIRS$artifacts, "external_features_status.csv")
PATH_GAME_MAP          <- file.path(DIRS$data, "game_id_map.csv")
PATH_GAME_MAP_STATUS   <- file.path(DIRS$artifacts, "external_game_map_status.csv")
PATH_PLAYER_MAP        <- file.path(DIRS$data, "nfl_id_map.csv")
PATH_PLAYER_MAP_STATUS <- file.path(DIRS$artifacts, "external_player_map_status.csv")
PATH_UNMATCH_GID       <- file.path(DIRS$artifacts, "external_unmatched_game_ids.csv")
PATH_UNMATCH_NID       <- file.path(DIRS$artifacts, "external_unmatched_nfl_ids.csv")
PATH_PLAYERS           <- file.path(DIRS$raw, "players.csv")

OUT_STATUS_C <- file.path(DIRS$artifacts, "external_verification_status.csv")
OUT_STATUS_M <- file.path(DIRS$artifacts, "external_verification_status.md")
OUT_PREVIEW  <- file.path(DIRS$artifacts, "player_id_preview.csv")

read_csv_clean <- function(path) suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(x) if (isTRUE(x)) "PASS" else "FAIL"
exists_ok <- function(p) file.exists(p)

# ---------------- Load inputs (tolerant) ----------------
has <- list(
  features        = exists_ok(PATH_FEATURES),
  features_status = exists_ok(PATH_FEATURES_STATUS),
  game_map        = exists_ok(PATH_GAME_MAP),
  game_map_status = exists_ok(PATH_GAME_MAP_STATUS),
  player_map      = exists_ok(PATH_PLAYER_MAP),
  player_map_status = exists_ok(PATH_PLAYER_MAP_STATUS),
  unmatched_gid   = exists_ok(PATH_UNMATCH_GID),
  unmatched_nid   = exists_ok(PATH_UNMATCH_NID),
  players         = exists_ok(PATH_PLAYERS)
)

features   <- if (has$features) read_csv_clean(PATH_FEATURES) else tibble()
gmap       <- if (has$game_map) read_csv_clean(PATH_GAME_MAP) else tibble()
pmap_raw   <- if (has$player_map) read_csv_clean(PATH_PLAYER_MAP) else tibble()
players    <- if (has$players) read_csv_clean(PATH_PLAYERS) else tibble()
ugi        <- if (has$unmatched_gid) read_csv_clean(PATH_UNMATCH_GID) else tibble()
uni        <- if (has$unmatched_nid) read_csv_clean(PATH_UNMATCH_NID) else tibble()

# ---------------- Recompute core checks ----------------

# 1) external_features: shape / duplicates / coverage
feat_ok_cols <- all(c("game_id","play_id","nfl_id") %in% names(features))
dup_groups <- if (nrow(features) > 0 && feat_ok_cols) {
  features |> count(game_id, play_id, nfl_id, name="n") |> filter(n > 1)
} else tibble()
dup_free <- nrow(dup_groups) == 0

cov_roster <- if (nrow(features) > 0) mean((features$team != "UNKNOWN") | (features$position != "UNKNOWN"), na.rm=TRUE) else NA_real_
cov_pbp    <- if (nrow(features) > 0) mean(!is.na(features$down) | !is.na(features$ydstogo), na.rm=TRUE) else NA_real_
cov_weath  <- if (nrow(features) > 0) mean(!is.na(features$roof) | !is.na(features$surface) | !is.na(features$temp_f) | !is.na(features$wind_mph), na.rm=TRUE) else NA_real_

no_syn_in_features <- if (nrow(features) > 0) !any(startsWith(toupper(as.character(features$game_id)), "SYN")) else TRUE

# 2) game_id_map coverage for real (non-SYN) game_ids used in features
gmap_ok_cols <- all(c("internal_game_id","nflverse_game_id") %in% names(gmap))
feat_gid <- if (feat_ok_cols) unique(as.character(features$game_id)) else character()
feat_gid_real <- feat_gid[!startsWith(toupper(feat_gid), "SYN")]
gmap_internal <- if (gmap_ok_cols) unique(as.character(gmap$internal_game_id)) else character()
game_map_covers_all_real <- length(setdiff(feat_gid_real, gmap_internal)) == 0

# 3) player map effective coverage (blanks = identity)
to_int <- function(x){
  z <- gsub("[^0-9]", "", as.character(x))
  z[z == ""] <- NA_character_
  suppressWarnings(as.integer(z))
}
players_nflid <- if (nrow(players)) {
  if ("nfl_id" %in% names(players)) to_int(players$nfl_id) else
    if ("nfl_id_num" %in% names(players)) to_int(players$nfl_id_num) else rep(NA_integer_, nrow(players))
} else integer()
player_ok <- length(players_nflid) > 0 && any(!is.na(players_nflid))

pmap_eff <- if (nrow(pmap_raw)) {
  tibble(
    internal_nfl_id = as.character(pmap_raw$internal_nfl_id %||% character()),
    nflverse_nfl_id = as.character(pmap_raw$nflverse_nfl_id %||% character())
  ) |>
    mutate(
      eff_target = ifelse(nflverse_nfl_id != "" & !is.na(nflverse_nfl_id), nflverse_nfl_id, internal_nfl_id),
      eff_target_num = to_int(eff_target)
    )
} else {
  tibble(internal_nfl_id = character(), nflverse_nfl_id = character(), eff_target_num = integer())
}
pmap_covered <- if (nrow(pmap_eff) > 0 && player_ok) {
  sum(!is.na(pmap_eff$eff_target_num) & (pmap_eff$eff_target_num %in% unique(players_nflid))) / nrow(pmap_eff)
} else if (nrow(pmap_eff) == 0) {
  1.0
} else {
  0.0
}
player_map_effective_pass <- pmap_covered >= 0.99

# 4) unmatched game ids: allow only SYN*
only_syn_unmatched <- if (nrow(ugi) == 0) TRUE else {
  join_col <- if ("game_id_join" %in% names(ugi)) "game_id_join" else if ("game_id" %in% names(ugi)) "game_id" else names(ugi)[1]
  all(startsWith(toupper(as.character(ugi[[join_col]])), "SYN"))
}

# 5) unmatched nfl ids should be zero (strict)
unmatched_nfl_ids_zero <- nrow(uni) == 0

# ---------------- Compose status table ----------------
fmt_cov <- function(x) if (is.na(x)) "n/a" else sprintf("coverage=%.6f", x)
checks <- tibble::tibble(
  check = c(
    "features_file_present",
    "features_has_keys(game_id,play_id,nfl_id)",
    "no_duplicate_key_groups",
    "coverage_roster>0",
    "coverage_pbp>0",
    "coverage_weather>0",
    "no_SYN_rows_in_features",
    "game_id_map_present",
    "game_id_map_covers_all_real_feature_games",
    "player_map_effective_coverage>=0.99",
    "unmatched_game_ids_only_SYN",
    "unmatched_nfl_ids_zero"
  ),
  detail = c(
    paste0("file=", PATH_FEATURES, " | rows=", nrow(features)),
    as.character(feat_ok_cols),
    paste0("dup_groups=", nrow(dup_groups)),
    fmt_cov(cov_roster),
    fmt_cov(cov_pbp),
    fmt_cov(cov_weath),
    as.character(no_syn_in_features),
    paste0("file=", PATH_GAME_MAP, " | rows=", nrow(gmap)),
    paste0("uncovered_real_games=", length(setdiff(feat_gid_real, gmap_internal))),
    sprintf("effective_player_id_coverage=%.4f", pmap_covered),
    paste0("unmatched_gid_rows=", nrow(ugi)),
    paste0("unmatched_nfl_id_rows=", nrow(uni))
  ),
  status = c(
    pass(has$features),
    pass(feat_ok_cols),
    pass(dup_free),
    pass(is.finite(cov_roster) && cov_roster > 0),
    pass(is.finite(cov_pbp)    && cov_pbp    > 0),
    pass(is.finite(cov_weath)  && cov_weath  > 0),
    pass(no_syn_in_features),
    pass(has$game_map),
    pass(game_map_covers_all_real),
    pass(player_map_effective_pass),
    pass(only_syn_unmatched),
    pass(unmatched_nfl_ids_zero)
  )
)

readr::write_csv(checks, OUT_STATUS_C)
writeLines(c("# External verification status", "", md_table(checks)), OUT_STATUS_M, useBytes = TRUE)

# ---------------- Player name ↔ ID preview (curiosity table) ----------------
# Effective ID set = from map if present (identity fill on blanks); else from features
if (nrow(players) > 0) {
  if (nrow(pmap_eff) > 0) {
    eff_ids <- unique(na.omit(pmap_eff$eff_target_num))
  } else if ("nfl_id" %in% names(features)) {
    eff_ids <- unique(na.omit(to_int(features$nfl_id)))
  } else {
    eff_ids <- integer()
  }
  players_num <- if ("nfl_id" %in% names(players)) to_int(players$nfl_id) else
    if ("nfl_id_num" %in% names(players)) to_int(players$nfl_id_num) else rep(NA_integer_, nrow(players))
  
  preview <- players |>
    mutate(nfl_id_num = players_num) |>
    filter(!is.na(nfl_id_num) & nfl_id_num %in% eff_ids) |>
    select(any_of(c("nfl_id","nfl_id_num","display_name","position","gsis_id"))) |>
    distinct() |>
    arrange(display_name, nfl_id_num)
  
  if (nrow(pmap_eff) > 0) {
    pmap_show <- pmap_raw |>
      mutate(
        internal_nfl_id = as.character(internal_nfl_id),
        nflverse_nfl_id = as.character(nflverse_nfl_id),
        eff_target = ifelse(nflverse_nfl_id != "" & !is.na(nflverse_nfl_id), nflverse_nfl_id, internal_nfl_id),
        eff_target_num = to_int(eff_target)
      ) |>
      select(internal_nfl_id, eff_target_num) |>
      distinct()
    preview <- pmap_show |>
      left_join(preview, by = c("eff_target_num" = "nfl_id_num")) |>
      select(any_of(c("internal_nfl_id","eff_target_num","display_name","position","gsis_id","nfl_id"))) |>
      arrange(display_name, eff_target_num)
  }
  
  readr::write_csv(preview, OUT_PREVIEW)
}

# ---------------- Final verdict ----------------
all_pass <- all(checks$status == "PASS")
if (all_pass) {
  message("VERIFICATION: PASS for 16 & 16.2.")
  message("Wrote:\n  - ", OUT_STATUS_C, " and ", OUT_STATUS_M,
          if (file.exists(OUT_PREVIEW)) paste0("\n  - ", OUT_PREVIEW) else "")
} else {
  message("VERIFICATION: FAIL — see ", OUT_STATUS_C, " / ", OUT_STATUS_M, " for failing checks.")
}










#!/usr/bin/env Rscript
# 16b_verify_mapping_integrity_v2.1.R
# Safer verifier: no quit(); supports nflverse_game_id; robust column detection.
# Stops with clear errors and writes CSV diagnostics into artifacts/.

suppressPackageStartupMessages({
  library(readr); library(dplyr); library(janitor); library(stringr); library(tibble)
})

msg  <- function(...) cat(sprintf("[%s] %s\n", format(Sys.time(), "%Y-%m-%d %H:%M:%S"), sprintf(...)))
die  <- function(...) stop(sprintf(...), call. = FALSE)

# ---------- Project root ----------
resolve_bdb_root <- function(){
  home <- path.expand("~")
  tries <- unique(c(
    file.path(home, "bdb_project"),
    file.path(home, "Desktop", "bdb_project"),
    file.path(home, "Documents", "bdb_project")
  ))
  cwd <- normalizePath(getwd(), mustWork = FALSE)
  cand <- cwd
  repeat {
    if (basename(cand) == "bdb_project" && dir.exists(cand)) tries <- c(cand, tries)
    parent <- dirname(cand); if (identical(parent, cand)) break; cand <- parent
  }
  tries <- unique(tries)
  for (p in tries) {
    if (dir.exists(p) &&
        file.exists(file.path(p, "artifacts", "model02_contest_dataset_final.csv")) &&
        dir.exists(file.path(p, "data", "splits"))) return(normalizePath(p, mustWork = FALSE))
  }
  die("Could not locate a usable 'bdb_project'.")
}

root <- resolve_bdb_root()
art  <- file.path(root, "artifacts")
dat  <- file.path(root, "data")
trn  <- file.path(root, "train")
msg("Project: %s", root)

# ---------- Helpers ----------
trim_chr <- function(x) { y <- as.character(x); y <- trimws(y); y }
coalesce_cols <- function(df, choices){
  hit <- intersect(choices, names(df))
  if (length(hit) == 0) return(rep(NA_character_, nrow(df)))
  out <- df[[hit[1]]]
  if (length(hit) > 1) for (j in hit[-1]) out <- ifelse(!is.na(out) & nzchar(as.character(out)), out, df[[j]])
  as.character(out)
}

# ---------- Candidate map discovery ----------
ext_candidates <- c("external_game_id","ext_game_id","source_game_id",
                    "bdb_game_id","gsis_game_id","nfl_game_id","pbp_game_id",
                    "nflverse_game_id","espn_game_id","pfr_game_id","cbs_game_id")
int_candidates <- c("internal_game_id","target_game_id","contest_game_id","model_game_id","game_id")

score_candidate <- function(path){
  nm <- tolower(basename(path)); sc <- 0L; why <- c()
  if (str_detect(nm, "map|mapping|match")) { sc <- sc + 2L; why <- c(why, "name:map") }
  if (str_detect(nm, "game")) { sc <- sc + 1L; why <- c(why, "name:game") }
  ok <- try(readr::read_csv(path, n_max = 250, show_col_types = FALSE), silent = TRUE)
  if (inherits(ok, "try-error")) return(tibble(path=path, score=sc, note="unreadable"))
  nms <- tolower(names(ok))
  if (any(nms %in% ext_candidates)) { sc <- sc + 2L; why <- c(why, "has_ext") }
  if (any(nms %in% int_candidates)) { sc <- sc + 2L; why <- c(why, "has_int") }
  id_like <- nms[str_detect(nms, "game") & str_detect(nms, "id")]
  if (length(unique(id_like)) >= 2) { sc <- sc + 1L; why <- c(why, "two_idlike") }
  tibble(path=path, score=sc, note=paste(why, collapse="|"))
}

# Prefer status hint if present
status_path <- file.path(art, "external_game_map_status.csv")
status_hint <- NA_character_
if (file.exists(status_path)) {
  st <- suppressMessages(readr::read_csv(status_path, show_col_types = FALSE))
  if (all(c("check","detail") %in% names(st))) {
    row <- st %>% dplyr::filter(check == "map_written") %>% dplyr::slice(1)
    if (nrow(row)) {
      status_hint <- row$detail[[1]]
      if (!is.na(status_hint) && nzchar(status_hint)) {
        rel <- sub("^.*?/bdb_project/?", "", status_hint)
        if (file.exists(status_hint)) { msg("Status suggested map: %s", status_hint) }
        else if (file.exists(file.path(root, rel))) { status_hint <- file.path(root, rel); msg("Status suggested map (relocated): %s", status_hint) }
        else status_hint <- NA_character_
      }
    }
  }
}

if (!is.na(status_hint)) {
  map_path <- status_hint
} else {
  msg("Scanning for mapping candidates…")
  csvs <- c(
    list.files(art,  pattern="\\.csv$", full.names = TRUE, recursive = FALSE),
    list.files(dat,  pattern="\\.csv$", full.names = TRUE, recursive = TRUE),
    list.files(trn,  pattern="\\.csv$", full.names = TRUE, recursive = TRUE)
  )
  cand <- dplyr::bind_rows(lapply(unique(csvs), score_candidate)) %>% dplyr::arrange(dplyr::desc(score))
  if (nrow(cand) == 0) die("No CSVs found to scan for mapping.")
  prefer <- cand %>% dplyr::filter(score == max(score))
  prefer <- prefer %>% dplyr::arrange(
    !stringr::str_detect(tolower(basename(path)), "status|unmatched"),
    !stringr::str_detect(tolower(basename(path)), "external_game_map_status"),
    !stringr::str_detect(tolower(basename(path)), "player|suggest"),
    nchar(basename(path))
  )
  map_path <- prefer$path[1]
}
if (!file.exists(map_path)) die("Mapping file not found: %s", map_path)
msg("Using mapping file: %s", map_path)

# ---------- Load mapping and pick columns robustly ----------
m_raw <- suppressMessages(readr::read_csv(map_path, show_col_types = FALSE)) %>% janitor::clean_names()
nms <- names(m_raw)

ext <- coalesce_cols(m_raw, ext_candidates)
int <- coalesce_cols(m_raw, int_candidates)

# If ambiguous or identical, try smart guesses
if (all(is.na(ext)) || all(is.na(int)) || identical(ext, int)) {
  nflverse_cols <- nms[stringr::str_detect(nms, "nflverse") & stringr::str_detect(nms, "game") & stringr::str_detect(nms, "id")]
  if (length(nflverse_cols) && all(is.na(ext))) ext <- m_raw[[nflverse_cols[1]]]
  if ("game_id" %in% nms && all(is.na(int))) int <- m_raw[["game_id"]]
}

# Final fallback: infer by overlap with dataset game_id
if (all(is.na(ext)) || all(is.na(int)) || identical(ext, int)) {
  ds_path <- file.path(art, "model02_contest_dataset_final.csv")
  if (file.exists(ds_path)) {
    ds <- suppressMessages(readr::read_csv(ds_path, show_col_types = FALSE))
    if ("game_id" %in% names(ds)) {
      ds_ids <- unique(trim_chr(ds$game_id))
      idlike <- nms[stringr::str_detect(nms, "game") & stringr::str_detect(nms, "id")]
      if (length(idlike) >= 2) {
        scores <- sapply(idlike, function(col){
          vals <- trim_chr(m_raw[[col]])
          mean(vals %in% ds_ids, na.rm = TRUE)
        })
        best_int <- idlike[which.max(scores)]
        if (all(is.na(int))) int <- m_raw[[best_int]]
        other <- setdiff(idlike, best_int)
        if (length(other) && all(is.na(ext))) ext <- m_raw[[other[1]]]
      }
    }
  }
}

if (all(is.na(ext)) || all(is.na(int)) || identical(ext, int)) {
  msg("Mapping columns present: %s", paste(nms, collapse=", "))
  die("Couldn't identify distinct external/internal game id columns in %s", map_path)
}

m <- tibble::tibble(
  external_game_id = trim_chr(ext),
  internal_game_id = trim_chr(int)
) %>% dplyr::filter(!is.na(external_game_id), !is.na(internal_game_id),
                    nzchar(external_game_id), nzchar(internal_game_id))

msg("Mapping rows (non‑NA): %d", nrow(m))

# ---------- 1) Enforce 1↔1 uniqueness ----------
dup_ext <- m %>% dplyr::count(external_game_id, name="n") %>% dplyr::filter(n > 1)
dup_int <- m %>% dplyr::count(internal_game_id, name="n") %>% dplyr::filter(n > 1)

if (nrow(dup_ext) == 0 && nrow(dup_int) == 0) {
  msg("✅ Mapping is 1↔1: no external→multi‑internal and no internal→multi‑external.")
} else {
  if (nrow(dup_ext)) {
    out <- file.path(art, "audit_dup_external_game_ids.csv")
    readr::write_csv(dup_ext, out); msg("❌ Wrote external dup list → %s", out)
  }
  if (nrow(dup_int)) {
    out <- file.path(art, "audit_dup_internal_game_ids.csv")
    readr::write_csv(dup_int, out); msg("❌ Wrote internal dup list → %s", out)
  }
  die("Mapping has duplicates. See CSV(s) above.")
}

# ---------- 2) Previously‑unmatched check ----------
unmatched_path <- file.path(art, "external_unmatched_game_ids.csv")
if (file.exists(unmatched_path)) {
  u <- suppressMessages(readr::read_csv(unmatched_path, show_col_types = FALSE)) %>% janitor::clean_names()
  u_ext <- coalesce_cols(u, c("external_game_id","ext_game_id","bdb_game_id","gsis_game_id","nfl_game_id","pbp_game_id","nflverse_game_id"))
  u_ids <- tibble::tibble(external_game_id = trim_chr(u_ext)) %>% dplyr::distinct() %>% dplyr::filter(!is.na(external_game_id), nzchar(external_game_id))
  if (nrow(u_ids) > 0) {
    check34 <- m %>% dplyr::semi_join(u_ids, by="external_game_id") %>% dplyr::count(external_game_id, name="n") %>% dplyr::filter(n > 1)
    if (nrow(check34) == 0) msg("✅ None of the previously‑unmatched external IDs are multi‑mapped now.")
    else {
      out <- file.path(art, "audit_prev_unmatched_multimapped.csv")
      readr::write_csv(check34, out); die("Some of the previously‑unmatched ids are multi‑mapped → %s", out)
    }
  } else {
    msg("Info: external_unmatched_game_ids.csv contains 0 rows (nothing to re‑check).")
  }
} else {
  msg("Info: external_unmatched_game_ids.csv not found; skipping the 34‑id specific check.")
}

# ---------- 3) Dataset integrity ----------
ds_path <- file.path(art, "model02_contest_dataset_final.csv")
if (!file.exists(ds_path)) die("Dataset missing: %s", ds_path)

ds <- suppressMessages(readr::read_csv(ds_path, show_col_types = FALSE))
need <- c("game_id","play_id","nfl_id")
missing <- setdiff(need, names(ds))
if (length(missing)) die("Dataset is missing required columns: %s", paste(missing, collapse=", "))

dup_triple <- ds %>% dplyr::count(game_id, play_id, nfl_id, name="n") %>% dplyr::filter(n > 1)
if (nrow(dup_triple) == 0) {
  msg("✅ (game_id, play_id, nfl_id) is unique throughout.")
} else {
  out <- file.path(art, "audit_dup_game_play_candidate_rows.csv")
  readr::write_csv(dup_triple, out); die("True duplicates at candidate level → %s", out)
}

# Optional preview
ncand <- ds %>% dplyr::count(game_id, play_id, name="n_candidates") %>% dplyr::arrange(dplyr::desc(n_candidates)) %>% dplyr::slice_head(n = 10)
readr::write_csv(ncand, file.path(art, "preview_top_candidate_counts.csv"))
msg("Info: wrote preview_top_candidate_counts.csv (top 10 plays by candidate count).")

# ---------- 4) Join sources sanity ----------
spl_path  <- file.path(root, "data", "splits", "plays_split_map.csv")
caps_path <- file.path(art,  "capability_profiles.csv")

if (!file.exists(spl_path))  die("Missing splits file: %s", spl_path)
if (!file.exists(caps_path)) die("Missing capability profiles: %s", caps_path)

spl  <- suppressMessages(readr::read_csv(spl_path, show_col_types = FALSE))
caps <- suppressMessages(readr::read_csv(caps_path, show_col_types = FALSE))

dups_splits <- spl %>% dplyr::count(game_id, play_id, name="n") %>% dplyr::filter(n>1)
dups_caps   <- caps %>% dplyr::count(nfl_id, name="n") %>% dplyr::filter(n>1)

if (nrow(dups_splits)==0) msg("✅ splits is 1 row per (game_id, play_id).") else {
  out <- file.path(art, "audit_dup_in_splits.csv")
  readr::write_csv(dups_splits, out); die("splits has duplicate (game_id, play_id) → %s", out)
}
if (nrow(dups_caps)==0) msg("✅ capability_profiles is 1 row per nfl_id.") else {
  out <- file.path(art, "audit_dup_in_capabilities.csv")
  readr::write_csv(dups_caps, out); die("capability_profiles has duplicate nfl_id → %s", out)
}

msg("All mapping and dataset integrity checks passed.")
invisible(TRUE)










#!/usr/bin/env Rscript
# 17_param_sweep_inputs.R — v17.11.3
# Changes vs v17.10.4:
# - FIX: read_csv_cast signature so readr::read_csv doesn't get show_col_types twice.
# - FIX: PR-AUC implementation (length-safe step integration; no warnings).
# - PR-AUC tie-breaker added wherever we sort by F1 (affects only exact F1 ties).
# - BDB_PROJECT_ROOT environment override (optional; no math impact).
# - Compatibility shims if resuming from old Stage-1 CSVs lacking val_pr_auc.
# Additions in v17.11.3:
# - Stage-2 reuse guard (REUSE_STAGE2). If artifacts/sweep_stage2_grid.csv exists, reuse it.
# - Final grid de-dup by (lambda_reach, ELIG_THRESHOLD) with deterministic tie-breaking and assert.

suppressPackageStartupMessages({
  library(openssl); library(readr); library(dplyr); library(tidyr); library(tibble)
  library(janitor); library(ranger); library(pROC); library(purrr); library(rlang); library(glue); library(stringr)
  
  # ---- readr helper with safe signature (FIXED) ----
  read_csv_cast <- function(file, show_col_types = FALSE, ...) {
    df <- readr::read_csv(file, show_col_types = show_col_types, ...)
    if ("run_id" %in% names(df)) {
      df <- dplyr::mutate(df, run_id = as.character(.data$run_id))
    }
    df
  }
  
  # bind_rows that preserves run_id type if present
  bind_rows_safe <- function(...) {
    dots <- list(...)
    cast_one <- function(x) {
      if (is.null(x)) return(x)
      if (inherits(x, "list")) {
        lapply(x, cast_one)
      } else if (is.data.frame(x) && "run_id" %in% names(x)) {
        dplyr::mutate(x, run_id = as.character(.data$run_id))
      } else {
        x
      }
    }
    dots2 <- lapply(dots, cast_one)
    do.call(dplyr::bind_rows, dots2)
  }
  # -----------------------------------------------
})

`%||%` <- function(a,b) if (is.null(a)) b else a
msg  <- function(...) cat(sprintf("[%s] %s\n", format(Sys.time(), "%Y-%m-%d %H:%M:%S"), sprintf(...)))
clip <- function(p, eps = 1e-12) pmin(pmax(p, eps), 1 - eps)
to_factor <- function(x) factor(ifelse(x, "yes", "no"), levels = c("no","yes"))

# PR-AUC (step-area, length-safe) — FIXED
pr_auc <- function(y, p){
  y <- as.integer(y)
  o <- order(p, decreasing = TRUE)
  y <- y[o]; p <- p[o]
  
  P <- sum(y == 1L); N <- sum(y == 0L)
  if (P == 0L || (P + N) == 0L) return(NA_real_)
  
  tp <- cumsum(y == 1L)
  fp <- cumsum(y == 0L)
  
  rec  <- tp / P
  prec <- tp / pmax(tp + fp, 1L)
  
  rec2  <- c(0, rec)
  prec2 <- c(1, prec)
  
  sum(diff(rec2) * head(prec2, -1))
}

best_f1 <- function(y, p){
  ths1 <- seq(0.01, 0.99, by = 0.01); yb <- as.logical(y)
  f1s1 <- vapply(ths1, function(t){ pr <- p>=t; tp<-sum(pr&yb); fp<-sum(pr&!yb); fn<-sum(!pr&yb)
  if ((2*tp+fp+fn)==0) NA_real_ else 2*tp/(2*tp+fp+fn)}, numeric(1))
  j1 <- which.max(f1s1); t0 <- ths1[j1]
  lo <- max(0.001, t0 - 0.02); hi <- min(0.999, t0 + 0.02)
  ths2 <- seq(lo, hi, by = 0.001)
  f1s2 <- vapply(ths2, function(t){ pr <- p>=t; tp<-sum(pr&yb); fp<-sum(pr&!yb); fn<-sum(!pr&yb)
  if ((2*tp+fp+fn)==0) NA_real_ else 2*tp/(2*tp+fp+fn)}, numeric(1))
  j2 <- which.max(f1s2); list(threshold = ths2[j2], f1 = f1s2[j2])
}
logloss <- function(y, p, eps = 1e-12){ p <- clip(p, eps); -mean(y*log(p) + (1-y)*log(1-p)) }
ece <- function(y, p, n_bins = 10){
  b <- cut(p, breaks = seq(0,1,length.out = n_bins+1), include.lowest = TRUE, right = TRUE)
  df <- data.frame(y=y, p=p, b=b) |> dplyr::group_by(b) |>
    dplyr::summarise(acc=mean(y), conf=mean(p), n=dplyr::n(), .groups="drop")
  sum(df$n*abs(df$acc-df$conf))/sum(df$n)
}
reparam_p <- function(p_old, lambda_old, lambda_new, eps = 1e-12){
  p_old <- clip(p_old, eps); delta <- -log(p_old)/lambda_old; exp(-lambda_new*delta)
}

write_csv_atomic <- function(df, path){
  dir.create(dirname(path), recursive = TRUE, showWarnings = FALSE)
  tmp <- paste0(path, ".tmp_", as.integer(runif(1, 1e8, 9e8)))
  readr::write_csv(df, tmp)
  ok <- suppressWarnings(file.rename(tmp, path))
  if (!ok) stop("Atomic write failed for: ", path)
}
remove_if_exists <- function(path){ if (file.exists(path)) try(file.remove(path), silent=TRUE) }

script_version <- "17.11.3"
run_id <- format(as.POSIXct(Sys.time(), tz = "UTC"), "%Y%m%dT%H%M%SZ")
suppressWarnings({ RNGkind(kind = "Mersenne-Twister", normal.kind = "Inversion") })

resolve_bdb_root <- function(){
  home <- path.expand("~")
  tries <- unique(c(
    file.path(home, "bdb_project"),
    file.path(home, "Desktop", "bdb_project"),
    file.path(home, "Documents", "bdb_project")
  ))
  cwd <- normalizePath(getwd(), mustWork = FALSE)
  cand <- cwd
  repeat { if (basename(cand) == "bdb_project" && dir.exists(cand)) tries <- c(cand, tries)
  parent <- dirname(cand); if (identical(parent, cand)) break; cand <- parent }
  tries <- unique(tries)
  for (p in tries) {
    if (dir.exists(p) &&
        file.exists(file.path(p, "artifacts", "model02_contest_dataset_final.csv")) &&
        dir.exists(file.path(p, "data", "splits"))) return(normalizePath(p, mustWork = FALSE))
  }
  stop("Could not locate a usable 'bdb_project'. Searched:\n  - ", paste(tries, collapse = "\n  - "))
}

# Environment override (optional but robust)
get_project_root <- function(){
  env <- Sys.getenv("BDB_PROJECT_ROOT", unset = NA_character_)
  if (!is.na(env) && dir.exists(env)) return(normalizePath(env, mustWork = FALSE))
  resolve_bdb_root()
}

project_root <- get_project_root()
if (basename(project_root) != "bdb_project") stop("Resolved project_root is not a 'bdb_project' folder: ", project_root)
artifacts_dir <- file.path(project_root, "artifacts")
data_dir      <- file.path(project_root, "data")
ds_path       <- file.path(artifacts_dir, "model02_contest_dataset_final.csv")
caps_path     <- file.path(artifacts_dir, "capability_profiles.csv")
split_path    <- file.path(data_dir, "splits", "plays_split_map.csv")

if (!file.exists(ds_path))   stop("Missing dataset: ", ds_path)
if (!file.exists(caps_path)) stop("Missing capability profiles: ", caps_path)
if (!file.exists(split_path))stop("Missing split map: ", split_path)

ds   <- read_csv_cast(ds_path, show_col_types = FALSE)
caps <- read_csv_cast(caps_path, show_col_types = FALSE)
splits_tbl <- read_csv_cast(split_path, show_col_types = FALSE) |> dplyr::select(game_id, play_id, split)

REUSE_STAGE1  <- TRUE
RESUME_STAGE1 <- TRUE

# --- Stage-2 reuse flags (ADD-IN) ---
REUSE_STAGE2   <- TRUE
stage2_path    <- file.path(artifacts_dir, "sweep_stage2_grid.csv")
preserve_stage2 <- REUSE_STAGE2 && file.exists(stage2_path)

stage1_path   <- file.path(artifacts_dir, "sweep_stage1_grid.csv")
stage1_part   <- file.path(artifacts_dir, "sweep_stage1_grid_partial.csv")

preserve_stage1_full    <- REUSE_STAGE1  && file.exists(stage1_path)
preserve_stage1_partial <- RESUME_STAGE1 && file.exists(stage1_part)

targets <- c("sweep_stage2_grid.csv", "sweep_microgrid.csv", "sweep_refine_rounds.csv",
             "sweep_bootstrap_summary.csv", "sweep_choice_with_ci.csv",
             "sweep_inputs_choice.csv", "sweep_inputs_status.csv",
             "sweep_inputs_grid.csv")

# Don't delete Stage-2 grid if reusing it
if (preserve_stage2) {
  targets <- setdiff(targets, "sweep_stage2_grid.csv")
}

invisible(lapply(file.path(artifacts_dir, targets), remove_if_exists))
if (!(preserve_stage1_full || preserve_stage1_partial)) {
  invisible(lapply(c(stage1_path, stage1_part), remove_if_exists))
}

req_cols <- c("game_id","play_id","nfl_id","p_reach_start","d_start","p_reach_max","d_min","d_arrival",
              "eligible","throwaway","contest_primary","contest_tight")
miss <- setdiff(req_cols, names(ds)); if (length(miss)) stop("Dataset missing columns: ", paste(miss, collapse=", "))

feat_candidates <- c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")
feat_cols <- intersect(feat_candidates, names(ds))
core_needed <- c("p_reach_start","d_start","p_reach_max","d_min")
missing_core <- setdiff(core_needed, feat_cols)
if (length(missing_core)) stop("Core feature(s) missing: ", paste(missing_core, collapse=", "))
if (!("throwaway" %in% names(ds))) ds$throwaway <- FALSE
base_den  <- nrow(ds |> dplyr::filter(!.data[["throwaway"]]))

digest_file <- function(p) if (file.exists(p)) openssl::sha256(file(p)) else NA_character_
input_hash <- tibble::tibble(
  dataset = digest_file(ds_path),
  capabilities = digest_file(caps_path),
  splits = digest_file(split_path)
)
write_csv_atomic(input_hash, file.path(artifacts_dir, "sweep_input_hashes.csv"))
try(capture.output(utils::sessionInfo(), file = file.path(artifacts_dir, "sweep_session_info.txt")), silent = TRUE)

dup_rows <- sum(duplicated(ds))
