LAMBDA_BASELINE <- 0.7
COVERAGE_MIN    <- 0.02
LR_MIN_ALLOWED  <- 0.30

ensure_split <- function(df){
  if ("split" %in% names(df)) df <- dplyr::select(df, -split)
  out <- dplyr::left_join(df, splits_tbl, by = c("game_id","play_id"))
  if (all(c("split.x","split.y") %in% names(out))) {
    out <- out |> dplyr::mutate(split = dplyr::coalesce(.data[["split.x"]], .data[["split.y"]])) |> dplyr::select(-split.x, -split.y)
  }
  if (!("split" %in% names(out))) stop("ensure_split(): failed to attach 'split'")
  out |> dplyr::mutate(split = as.character(.data[["split"]])) |>
    dplyr::mutate(split = dplyr::case_when(split %in% c("train","val","test") ~ split, TRUE ~ NA_character_))
}

impute_median <- function(df, meds_row){
  nm <- intersect(names(meds_row), names(df))
  for (v in nm) df[[v]][is.na(df[[v]])] <- meds_row[[v]][1]
  df
}

safe_ranger <- function(formula, data, ntrees, minnode, threads, mtry = NULL, class_weights = NULL,
                        splitrule = 'gini', sample_fraction = 0.8){
  for (trees_try in c(ntrees, max(200, floor(ntrees*0.7)), 200)) {
    gc()
    ok <- try({
      fit <- ranger::ranger(
        formula, data = data, probability = TRUE,
        num.trees = trees_try, min.node.size = minnode,
        mtry = mtry, class.weights = class_weights,
        respect.unordered.factors = "order",
        splitrule = splitrule, sample.fraction = sample_fraction, replace = TRUE,
        num.threads = threads
      )
      assign(".fit_tmp", fit, inherits = TRUE); TRUE
    }, silent = TRUE)
    if (isTRUE(ok)) return(get(".fit_tmp", inherits = TRUE))
  }
  stop("ranger failed at all fallback tree counts.")
}

iso_calibrate <- function(y, p){
  y_num <- as.numeric(y)
  ord <- order(p); p_sorted <- p[ord]; y_sorted <- y_num[ord]
  iso <- try(stats::isoreg(p_sorted, y_sorted), silent = TRUE)
  if (inherits(iso, "try-error")) return(rep(NA_real_, length(p)))
  tdf <- aggregate(y ~ x, data = data.frame(x = p_sorted, y = iso$yf), FUN = mean)
  approx(x = tdf$x, y = tdf$y, xout = p, ties = "ordered", rule = 2)$y
}
choose_calibration <- function(y, p_raw){
  p_clip <- clip(p_raw, 1e-6)
  q <- tryCatch(qlogis(p_clip), error=function(e) NULL)
  p_platt <- tryCatch({ if (is.null(q)) stop("qlogis failed"); glm_cal <- glm(y ~ q, family = binomial()); plogis(stats::predict(glm_cal, type="link")) }, error=function(e) rep(NA_real_, length(y)))
  p_iso   <- tryCatch(iso_calibrate(y, p_clip), error=function(e) rep(NA_real_, length(y)))
  score <- function(pp){ if (any(!is.finite(pp))) return(c(ece=Inf, ll=Inf)); c(ece=ece(as.numeric(y), pp), ll=logloss(as.numeric(y), pp)) }
  s_raw <- score(p_clip); s_platt <- score(p_platt); s_iso <- score(p_iso)
  sel <- list(name="raw", p=p_clip, ece=s_raw["ece"], ll=s_raw["ll"])
  if (s_platt["ece"] < sel$ece || (s_platt["ece"]==sel$ece && s_platt["ll"] < sel$ll)) sel <- list(name="platt", p=p_platt, ece=s_platt["ece"], ll=s_platt["ll"])
  if (s_iso["ece"]   < sel$ece || (s_iso["ece"]  ==sel$ece && s_iso["ll"]   < sel$ll)) sel <- list(name="isotonic", p=p_iso,  ece=s_iso["ece"],  ll=s_iso["ll"])
  sel
}

fit_eval_once <- function(frame, label = "contest_primary", ntrees = 200, min_node = 50,
                          seed = 2025, threads = 1, mtry = NULL, splitrule = "gini", sample_fraction = 0.8){
  if (!("split" %in% names(frame))) stop("fit_eval_once(): 'split' missing; check ensure_split().")
  tr <- frame |> dplyr::filter(.data[["split"]] == "train")
  va <- frame |> dplyr::filter(.data[["split"]] == "val")
  if (nrow(tr)==0 || nrow(va)==0) return(list(val_auc=NA_real_, val_pr_auc=NA_real_, val_f1=NA_real_, val_th=NA_real_, val_logloss=NA_real_, val_ece=NA_real_,
                                              val_prev=NA_real_, rows_tr=nrow(tr), rows_va=nrow(va), p_val=numeric(0), y_val=logical(0), game_val=character(0)))
  miss_feat <- setdiff(feat_cols, names(tr))
  if (length(miss_feat)) return(list(val_auc=NA_real_, val_pr_auc=NA_real_, val_f1=NA_real_, val_th=NA_real_, val_logloss=NA_real_, val_ece=NA_real_,
                                     val_prev=NA_real_, rows_tr=nrow(tr), rows_va=nrow(va),
                                     p_val=numeric(0), y_val=logical(0), game_val=character(0),
                                     note=paste0("missing features: ", paste(miss_feat, collapse="|"))))
  meds <- tr |> summarise(across(all_of(feat_cols), ~ suppressWarnings(median(.x, na.rm = TRUE))))
  tr2 <- tr |> mutate(dplyr::across(all_of(feat_cols), ~ is.na(.x), .names = "{.col}_isna"))
  va2 <- va |> mutate(dplyr::across(all_of(feat_cols), ~ is.na(.x), .names = "{.col}_isna"))
  rf_train <- tr2 |> transmute(y = to_factor(.data[[label]]), dplyr::across(all_of(feat_cols)), dplyr::across(all_of(paste0(feat_cols,"_isna")))) |> impute_median(meds)
  rf_val   <- va2 |> transmute(y = to_factor(.data[[label]]), dplyr::across(all_of(feat_cols)), dplyr::across(all_of(paste0(feat_cols,"_isna")))) |> impute_median(meds)
  
  set.seed(seed)
  prev <- mean(rf_train$y == "yes")
  cw <- c("no" = 0.5/(1-prev+1e-9), "yes" = 0.5/(prev+1e-9))
  fit <- safe_ranger(y ~ ., data = rf_train, ntrees = ntrees, minnode = min_node, threads = threads,
                     mtry = mtry, class_weights = cw, splitrule = splitrule, sample_fraction = sample_fraction)
  p_raw <- predict(fit, rf_val)$predictions[, "yes"]; rm(fit); invisible(gc())
  y_val <- rf_val$y == "yes"
  cal <- choose_calibration(y_val, p_raw); p_val <- cal$p
  auc <- tryCatch(as.numeric(pROC::roc(y_val, p_val, quiet = TRUE)$auc), error = function(e) NA_real_)
  pra <- tryCatch(pr_auc(y_val, p_val), error = function(e) NA_real_)
  sel <- best_f1(y_val, p_val)
  list(val_auc=auc, val_pr_auc=pra, val_f1=sel$f1, val_th=sel$threshold,
       val_logloss=logloss(as.numeric(y_val), p_val),
       val_ece=ece(as.numeric(y_val), p_val),
       val_prev=mean(y_val), rows_tr=nrow(tr), rows_va=nrow(va),
       p_val=p_val, y_val=y_val, game_val=as.character(va$game_id %||% NA_character_))
}

eval_combo <- function(frame, ntrees, min_node, seeds, threads, mtry=NULL, splitrule="gini", sample_fraction=0.8){
  runs <- lapply(seq_len(seeds), function(i){
    fit_eval_once(frame, ntrees = ntrees, min_node = min_node, seed = 2025 + 17*i, threads = threads,
                  mtry = mtry, splitrule = splitrule, sample_fraction = sample_fraction)
  })
  auc  <- median(vapply(runs, `[[`, numeric(1), "val_auc"),     na.rm = TRUE)
  pr   <- median(vapply(runs, `[[`, numeric(1), "val_pr_auc"),  na.rm = TRUE)
  f1   <- median(vapply(runs, `[[`, numeric(1), "val_f1"),      na.rm = TRUE)
  th   <- median(vapply(runs, `[[`, numeric(1), "val_th"),      na.rm = TRUE)
  ths  <- vapply(runs, `[[`, numeric(1), "val_th")
  th_q10 <- suppressWarnings(as.numeric(stats::quantile(ths, 0.10, na.rm=TRUE, names=FALSE)))
  th_q90 <- suppressWarnings(as.numeric(stats::quantile(ths, 0.90, na.rm=TRUE, names=FALSE)))
  ll   <- median(vapply(runs, `[[`, numeric(1), "val_logloss"), na.rm = TRUE)
  ec   <- median(vapply(runs, `[[`, numeric(1), "val_ece"),     na.rm = TRUE)
  prev <- median(vapply(runs, `[[`, numeric(1), "val_prev"),    na.rm = TRUE)
  rt   <- runs[[1]]$rows_tr %||% NA_integer_; rv <- runs[[1]]$rows_va %||% NA_integer_
  list(val_auc=auc, val_pr_auc=pr, val_f1=f1, val_th=th, th_q10=th_q10, th_q90=th_q90, val_logloss=ll, val_ece=ec, val_prev=prev, rows_tr=rt, rows_va=rv)
}

build_frame <- function(ds_in, lam, et, caps) {
  ds_in |>
    mutate(p_reach_start = reparam_p(p_reach_start, LAMBDA_BASELINE, lam),
           p_reach_max   = reparam_p(p_reach_max,   LAMBDA_BASELINE, lam),
           eligible_tmp  = p_reach_max >= et) |>
    dplyr::filter(.data[["eligible_tmp"]], !.data[["throwaway"]]) |>
    dplyr::left_join(caps, by = "nfl_id") |>
    ensure_split()
}

ET_min <- 0.005; ET_max <- 0.12;  ET_step <- 0.005
LR_min <- 0.30;  LR_max <- 1.50;   LR_step <- 0.05

stage1_eval <- function(ET_min, ET_max, ET_step, LR_min, LR_max, LR_step, existing=NULL){
  msg("Stage 1: ET=[%.3f,%.3f] step %.3f; λ=[%.2f,%.2f] step %.2f", ET_min,ET_max,ET_step, LR_min,LR_max,LR_step)
  ETs <- seq(ET_min, ET_max, by = ET_step); LRs <- seq(LR_min, LR_max, by = LR_step); total <- length(ETs) * length(LRs)
  
  existing_keys <- NULL
  if (!is.null(existing) && nrow(existing)) {
    existing <- existing %>% distinct(lambda_reach, ELIG_THRESHOLD, .keep_all = TRUE)
    existing_keys <- existing %>% transmute(k=paste0(lambda_reach,"|",ELIG_THRESHOLD)) %>% pull(k)
    msg("Stage 1: resuming with %d existing combos.", length(existing_keys))
  }
  
  recs <- list(); k <- 0L; done <- 0L
  for (lam in LRs) {
    ds_lam <- ds |> mutate(p_reach_start = reparam_p(p_reach_start, LAMBDA_BASELINE, lam),
                           p_reach_max   = reparam_p(p_reach_max,   LAMBDA_BASELINE, lam))
    for (et in ETs) {
      key <- paste0(lam,"|",et)
      if (!is.null(existing_keys) && key %in% existing_keys) { done <- done + 1L; next }
      k <- k + 1L
      frame <- ds_lam |> mutate(eligible_tmp = p_reach_max >= et) |>
        dplyr::filter(.data[["eligible_tmp"]], !.data[["throwaway"]]) |>
        dplyr::left_join(caps, by = "nfl_id") |> ensure_split()
      covg <- if (base_den > 0) nrow(frame) / base_den else NA_real_
      if (is.finite(COVERAGE_MIN) && is.finite(covg) && covg < COVERAGE_MIN) {
        row <- tibble(lambda_reach=lam, ELIG_THRESHOLD=et, coverage=covg,
                      val_auc=NA_real_, val_pr_auc=NA_real_, val_f1=NA_real_, val_th=NA_real_, val_logloss=NA_real_, val_ece=NA_real_,
                      rows_tr=0L, rows_va=0L, stage="stage1", note=sprintf("coverage<%.3f", COVERAGE_MIN))
      } else {
        m <- eval_combo(frame, ntrees = 120, min_node = 60, seeds = 5, threads = threads)
        row <- tibble(lambda_reach=lam, ELIG_THRESHOLD=et, coverage=covg,
                      val_auc=m$val_auc, val_pr_auc=m$val_pr_auc, val_f1=m$val_f1, val_th=m$val_th, val_logloss=m$val_logloss, val_ece=m$val_ece,
                      rows_tr=m$rows_tr, rows_va=m$rows_va, stage="stage1", note=NA_character_)
      }
      recs[[length(recs)+1L]] <- dplyr::bind_cols(row, tibble(run_id = run_id, script_version = script_version))
      if (((done + length(recs)) %% 10L) == 0L) msg("Stage 1 progress: %d / %d (λ=%.2f, ET=%.3f)", done + length(recs), total, lam, et)
      if (((done + length(recs)) %% 50L) == 0L) {
        tmp <- bind_rows_safe(if (!is.null(existing)) existing else NULL, bind_rows_safe(recs))
        write_csv_atomic(tmp, stage1_part)
      }
      invisible(gc())
    }
  }
  out <- bind_rows_safe(if (!is.null(existing)) existing else NULL, bind_rows_safe(recs)) %>%
    dplyr::distinct(lambda_reach, ELIG_THRESHOLD, .keep_all = TRUE) %>%
    dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc))
  write_csv_atomic(out, stage1_part)
  out
}

tic_total <- Sys.time()
stage1 <- NULL

if (REUSE_STAGE1 && file.exists(stage1_path)) {
