    dplyr::mutate(run_id = run_id, script_version = script_version)
  write_csv_atomic(stage1, stage1_path)
}

expand_if_edge <- function(df, ET_min, ET_max, LR_min, LR_max){
  w <- df |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1)
  expand <- list(ET_min = ET_min, ET_max = ET_max, LR_min = LR_min, LR_max = LR_max, changed = FALSE)
  if (abs(w$ELIG_THRESHOLD - ET_min) < 1e-9) { expand$ET_min <- max(0.001, ET_min - 0.02); expand$changed <- TRUE }
  if (abs(w$ELIG_THRESHOLD - ET_max) < 1e-9) { expand$ET_max <- min(0.20, ET_max + 0.02); expand$changed <- TRUE }
  if (abs(w$lambda_reach   - LR_min) < 1e-9) { expand$LR_min <- max(0.30, LR_min - 0.20); expand$changed <- TRUE }
  if (abs(w$lambda_reach   - LR_max) < 1e-9) { expand$LR_max <- min(2.00, LR_max + 0.20); expand$changed <- TRUE }
  expand
}
edge_round <- 0L
repeat {
  edge_round <- edge_round + 1L
  exp <- expand_if_edge(stage1, ET_min, ET_max, LR_min, LR_max)
  if (!isTRUE(exp$changed) || edge_round > 2L) break
  msg("Edge expansion round %d: ET=[%.3f,%.3f], λ=[%.2f,%.2f]", edge_round, exp$ET_min, exp$ET_max, exp$LR_min, exp$LR_max)
  stage1b <- stage1_eval(exp$ET_min, exp$ET_max, ET_step, exp$LR_min, exp$LR_max, LR_step, existing=NULL)
  stage1  <- dplyr::bind_rows(stage1, stage1b) |>
    dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |>
    dplyr::distinct(lambda_reach, ELIG_THRESHOLD, .keep_all = TRUE) |>
    dplyr::mutate(run_id = run_id, script_version = script_version)
  write_csv_atomic(stage1, stage1_path)
  ET_min <- exp$ET_min; ET_max <- exp$ET_max; LR_min <- exp$LR_min; LR_max <- exp$LR_max
}

TOP_K_STAGE2 <- min(20L, max(10L, ceiling(0.03 * nrow(stage1 |> dplyr::filter(is.finite(val_f1))))))
finalists <- stage1 |> dplyr::filter(is.finite(val_f1)) |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1:TOP_K_STAGE2)
msg("Stage 2: retrain top %d with stronger model", nrow(finalists))

# --- Stage-2 compute or reuse ---
if (!preserve_stage2) {
  recs2 <- vector("list", nrow(finalists))
  for (i in seq_len(nrow(finalists))) {
    lam <- finalists$lambda_reach[i]; et <- finalists$ELIG_THRESHOLD[i]
    frame <- build_frame(ds, lam, et, caps)
    covg  <- if (base_den > 0) nrow(frame) / base_den else NA_real_
    p <- length(feat_cols); mtry_i <- pmax(1L, round(sqrt(p)))
    sr <- "gini"; sf <- 0.8; mn <- 30L
    m <- eval_combo(frame, ntrees = 800, min_node = mn, seeds = 9, threads = threads,
                    mtry = mtry_i, splitrule = sr, sample_fraction = sf)
    recs2[[i]] <- tibble(
      lambda_reach=lam, ELIG_THRESHOLD=et, coverage=covg,
      val_auc=m$val_auc, val_pr_auc=m$val_pr_auc, val_f1=m$val_f1, val_th=m$val_th,
      val_logloss=m$val_logloss, val_ece=m$val_ece,
      rows_tr=m$rows_tr, rows_va=m$rows_va, stage="stage2", note=NA_character_,
      mtry=mtry_i, splitrule=sr, sample_fraction=sf, min_node=mn,
      th_q10 = m$th_q10 %||% NA_real_, th_q90 = m$th_q90 %||% NA_real_,
      run_id = run_id, script_version = script_version
    ); invisible(gc())
  }
  stage2 <- bind_rows(recs2) |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc))
  write_csv_atomic(stage2, file.path(artifacts_dir, "sweep_stage2_grid.csv"))
} else {
  message("[17] Reusing existing Stage 2 grid: ", stage2_path)
  stage2 <- read_csv_cast(stage2_path, show_col_types = FALSE)
}

refine_rounds <- list()
center <- stage2 |> dplyr::slice(1) |> dplyr::select(lambda_reach, ELIG_THRESHOLD)
steps <- tibble(ET = c(0.02, 0.01, 0.005, 0.002), LR = c(0.20, 0.10, 0.05, 0.02))
prev_best_f1 <- -Inf
all_micro <- list()

for (r in seq_len(nrow(steps))) {
  det <- steps[r,]
  et0 <- as.numeric(center$ELIG_THRESHOLD[1]); lr0 <- as.numeric(center$lambda_reach[1])
  ET_micro <- sort(unique(pmin(pmax(et0 + c(-det$ET, -det$ET/2, 0, det$ET/2, det$ET), 0.0005), 0.9999)))
  LR_micro <- sort(unique(pmax(lr0 + c(-det$LR, -det$LR/2, 0, det$LR/2, det$LR),  LR_MIN_ALLOWED)))
  recsM <- list()
  sr <- "gini"; sf <- 0.8; mn <- 30L
  for (lam in LR_micro) for (et in ET_micro) {
    frame <- build_frame(ds, lam, et, caps)
    covg  <- if (base_den > 0) nrow(frame) / base_den else NA_real_
    if (is.finite(COVERAGE_MIN) && is.finite(covg) && covg < COVERAGE_MIN) {
      recsM[[length(recsM)+1]] <- tibble(lambda_reach=lam, ELIG_THRESHOLD=et, coverage=covg,
                                         val_auc=NA_real_, val_pr_auc=NA_real_, val_f1=NA_real_, val_th=NA_real_, val_logloss=NA_real_, val_ece=NA_real_,
                                         rows_tr=0L, rows_va=0L, stage=paste0("micro_r", r),
                                         note=sprintf("coverage<%.3f", COVERAGE_MIN), run_id = run_id, script_version = script_version)
    } else {
      p <- length(feat_cols); mtries <- unique(pmax(1L, round(sqrt(p) * c(0.75, 1, 1.25))))
      for (mtry_i in mtries) {
        m <- eval_combo(frame, ntrees = 800, min_node = mn, seeds = 9, threads = threads,
                        mtry = mtry_i, splitrule = sr, sample_fraction = sf)
        recsM[[length(recsM)+1]] <- tibble(lambda_reach=lam, ELIG_THRESHOLD=et, coverage=covg,
                                           val_auc=m$val_auc, val_pr_auc=m$val_pr_auc, val_f1=m$val_f1, val_th=m$val_th,
                                           val_logloss=m$val_logloss, val_ece=m$val_ece,
                                           rows_tr=m$rows_tr, rows_va=m$rows_va,
                                           mtry=mtry_i, splitrule=sr, sample_fraction=sf, min_node=mn,
                                           th_q10 = m$th_q10 %||% NA_real_, th_q90 = m$th_q90 %||% NA_real_,
                                           stage=paste0("micro_r", r), note=NA_character_, run_id = run_id, script_version = script_version)
      }
    }
    invisible(gc())
  }
  micro_r <- bind_rows(recsM) |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc))
  all_micro[[length(all_micro)+1]] <- micro_r
  write_csv_atomic(bind_rows(all_micro), file.path(artifacts_dir, "sweep_microgrid.csv"))
  best_r <- micro_r |> dplyr::slice(1)
  refine_rounds[[length(refine_rounds)+1]] <- best_r |> dplyr::mutate(round = r)
  center <- best_r |> dplyr::select(lambda_reach, ELIG_THRESHOLD)
  lift <- best_r$val_f1[1] - prev_best_f1
  msg("Refine round %d: winner λ=%.3f ET=%.3f F1=%.3f (ΔF1=%.4f)", r, center$lambda_reach[1], center$ELIG_THRESHOLD[1], best_r$val_f1[1], ifelse(is.finite(lift), lift, NA_real_))
  if (is.finite(prev_best_f1) && (!is.finite(lift) || lift < 0.002)) break
  prev_best_f1 <- best_r$val_f1[1]
}
refine_tbl <- bind_rows(refine_rounds) |> dplyr::mutate(run_id = run_id, script_version = script_version)
write_csv_atomic(refine_tbl, file.path(artifacts_dir, "sweep_refine_rounds.csv"))

final_micro <- if (exists("all_micro") && length(all_micro) > 0) all_micro[[length(all_micro)]] else stage2

combined_grid <- bind_rows_safe(
  stage1 %>% dplyr::mutate(source = "stage1"),
  stage2 %>% dplyr::mutate(source = "stage2"),
  final_micro %>% dplyr::mutate(source = "micro_final")
) %>%
  dplyr::mutate(
    lambda_reach   = round(as.numeric(lambda_reach),   3),
    ELIG_THRESHOLD = round(as.numeric(ELIG_THRESHOLD), 3)
  )

# Optional breadcrumb to see what was duplicated before dedup
dups_before <- combined_grid %>%
  dplyr::count(lambda_reach, ELIG_THRESHOLD, name = "n") %>% dplyr::filter(n > 1)
if (nrow(dups_before) > 0) {
  readr::write_csv(
    combined_grid %>%
      dplyr::semi_join(dups_before, by = c("lambda_reach","ELIG_THRESHOLD")) %>%
      dplyr::arrange(lambda_reach, ELIG_THRESHOLD, dplyr::desc(val_f1)),
    file.path(artifacts_dir, "17_debug_dups_before_dedup.csv")
  )
}

sweep_inputs_grid <- combined_grid %>%
  dplyr::arrange(
    dplyr::desc(val_f1),
    val_ece,
    val_logloss,
    dplyr::desc(val_auc),
    dplyr::desc(val_pr_auc),
    dplyr::coalesce(source, stage, "zzz")
  ) %>%
  dplyr::distinct(lambda_reach, ELIG_THRESHOLD, .keep_all = TRUE)

dup_key <- sweep_inputs_grid %>%
  dplyr::count(lambda_reach, ELIG_THRESHOLD) %>% dplyr::filter(n > 1)
if (nrow(dup_key) > 0) {
  readr::write_csv(dup_key, file.path(artifacts_dir, "17_dup_keys_after_dedup.csv"))
  stop("Duplicate key pairs remain after normalization; see artifacts/17_dup_keys_after_dedup.csv")
}

write_csv_atomic(sweep_inputs_grid, file.path(artifacts_dir, "sweep_inputs_grid.csv"))

MIN_VALID_BOOT <- 2L; MAX_CANDIDATES <- 12L
cand_base <- bind_rows(
  stage2 |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1:min(3, nrow(stage2))),
  final_micro |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1:min(2, nrow(final_micro)))
) |> dplyr::distinct(lambda_reach, ELIG_THRESHOLD, .keep_all = TRUE)

k_take <- min(nrow(cand_base), 5L)
repeat { cand <- cand_base |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1:k_take); boot_records <- list(); break }

for (i in seq_len(nrow(cand))) {
  lam <- cand$lambda_reach[i]; et <- cand$ELIG_THRESHOLD[i]
  frame <- build_frame(ds, lam, et, caps)
  one <- fit_eval_once(frame, ntrees = 800, min_node = 30, seed = 9091, threads = threads)
  p_val <- one$p_val; y_val <- one$y_val; th <- one$val_th; game <- one$game_val
  if (length(p_val)==0L || anyNA(th)) {
    boot_records[[length(boot_records)+1]] <- tibble(
      lambda_reach=lam, ELIG_THRESHOLD=et,
      f1_median=NA_real_, f1_p2.5=NA_real_, f1_p97.5=NA_real_,
      n_val=length(p_val), note="no_val_predictions",
      run_id = run_id, script_version = script_version
    ); next
  }
  df_val <- tibble(y = y_val, p = p_val, game = game)
  
  safe_f1 <- function(y, p, th){
    yhat <- p >= th
    tp <- sum(yhat & (y==1)); fp <- sum(yhat & (y==0)); fn <- sum(!yhat & (y==1))
    prec <- ifelse((tp+fp)>0, tp/(tp+fp), 0); rec  <- ifelse((tp+fn)>0, tp/(tp+fn), 0)
    if ((prec+rec) == 0) return(0); (2*prec*rec)/(prec+rec)
  }
  eps <- c(-0.02, 0, +0.02)
  f1_jitters <- sapply(eps, function(e) safe_f1(df_val$y, df_val$p, th + e))
  f1_jitter_mean <- mean(f1_jitters, na.rm = TRUE)
  f1_jitter_min  <- min(f1_jitters, na.rm = TRUE)
  f1_at_choice   <- safe_f1(df_val$y, df_val$p, th)
  f1_jitter_drop <- max(0, f1_at_choice - f1_jitter_min)
  
  pg <- try(dplyr::summarise(dplyr::group_by(df_val, game), f1 = safe_f1(y, p, th)), silent = TRUE)
  if (inherits(pg, "try-error")) { min_game_f1 <- NA_real_; p10_game_f1 <- NA_real_ } else {
    min_game_f1 <- suppressWarnings(min(pg$f1, na.rm = TRUE))
    p10_game_f1 <- suppressWarnings(as.numeric(stats::quantile(pg$f1, 0.10, na.rm = TRUE, names = FALSE)))
  }
  
  games  <- unique(df_val$game); if (anyNA(games)) games <- as.character(seq_len(nrow(df_val)))
  set.seed(2026); BOOT_N <- 2000
  f1s <- numeric(BOOT_N)
  for (b in seq_len(BOOT_N)) {
    gb <- sample(games, size = length(games), replace = TRUE)
    idx <- which(df_val$game %in% gb)
    yy  <- df_val$y[idx]; pp <- df_val$p[idx]
    pred <- pp >= th
    tp <- sum(pred & yy); fp <- sum(pred & !yy); fn <- sum(!pred & yy)
    f1s[b] <- if ((2*tp + fp + fn) == 0) NA_real_ else 2*tp / (2*tp + fp + fn)
  }
  boot_records[[length(boot_records)+1]] <- tibble(
    lambda_reach=lam, ELIG_THRESHOLD=et,
    f1_median = median(f1s, na.rm = TRUE),
    f1_p2.5   = quantile(f1s, 0.025, na.rm = TRUE, names = FALSE),
    f1_p97.5  = quantile(f1s, 0.975, na.rm = TRUE, names = FALSE),
    n_val = nrow(df_val), note = NA_character_, run_id = run_id, script_version = script_version,
    f1_jitter_mean = f1_jitter_mean, f1_jitter_min = f1_jitter_min, f1_jitter_drop = f1_jitter_drop,
    min_game_f1 = min_game_f1, p10_game_f1 = p10_game_f1
  )
  invisible(gc())
}
boot <- bind_rows(boot_records)

valid_boot <- sum(is.finite(boot$f1_median))
if (valid_boot < MIN_VALID_BOOT && k_take < min(nrow(cand_base), MAX_CANDIDATES)) {
  k_take <- min(k_take + 2L, MAX_CANDIDATES)
  msg("Expanding bootstrap candidates to %d due to insufficient valid validation predictions (had %d).", k_take, valid_boot)
  boot_records <- list()
  exp_cand <- cand_base |> dplyr::arrange(dplyr::desc(val_f1), dplyr::desc(val_pr_auc), dplyr::desc(val_auc)) |> dplyr::slice(1:k_take)
  for (i in seq_len(nrow(exp_cand))) {
    lam <- exp_cand$lambda_reach[i]; et <- exp_cand$ELIG_THRESHOLD[i]
    frame <- build_frame(ds, lam, et, caps)
    one <- fit_eval_once(frame, ntrees = 800, min_node = 30, seed = 9091, threads = threads)
    p_val <- one$p_val; y_val <- one$y_val; th <- one$val_th; game <- one$game_val
    if (length(p_val)==0L || anyNA(th)) {
      boot_records[[length(boot_records)+1]] <- tibble(
        lambda_reach=lam, ELIG_THRESHOLD=et, f1_median=NA_real_, f1_p2.5=NA_real_, f1_p97.5=NA_real_,
        n_val=length(p_val), note="no_val_predictions", run_id = run_id, script_version = script_version
      ); next
    }
    df_val <- tibble(y = y_val, p = p_val, game = game)
    games  <- unique(df_val$game); if (anyNA(games)) games <- as.character(seq_len(nrow(df_val)))
    set.seed(2026); BOOT_N <- 2000
    f1s <- numeric(BOOT_N)
    for (b in seq_len(BOOT_N)){
      gg <- sample(games, length(games), replace = TRUE)
      idx <- df_val$game %in% gg
      yy <- df_val$y[idx]; pp <- df_val$p[idx]
      pr <- pp >= th
      tp <- sum(pr & (yy==1)); fp <- sum(pr & (yy==0)); fn <- sum(!pr & (yy==1))
      f1s[b] <- if ((2*tp+fp+fn)==0) NA_real_ else 2*tp/(2*tp+fp+fn)
    }
    boot_records[[length(boot_records)+1]] <- tibble(
      lambda_reach=lam, ELIG_THRESHOLD=et,
      f1_median = median(f1s, na.rm = TRUE),
      f1_p2.5   = quantile(f1s, 0.025, na.rm = TRUE, names = FALSE),
      f1_p97.5  = quantile(f1s, 0.975, na.rm = TRUE, names = FALSE),
      n_val = nrow(df_val), note = NA_character_, run_id = run_id, script_version = script_version
    )
  }
  boot <- bind_rows(boot_records)
}
write_csv_atomic(boot, file.path(artifacts_dir, "sweep_bootstrap_summary.csv"))

all_candidates <- bind_rows_safe(
  stage2 %>% dplyr::mutate(source = "stage2"),
  final_micro %>% dplyr::mutate(source = "micro_final")
) %>% dplyr::semi_join(cand %>% dplyr::select(lambda_reach, ELIG_THRESHOLD), by = c("lambda_reach","ELIG_THRESHOLD"))

final_table <- all_candidates %>%
  dplyr::left_join(boot, by = c("lambda_reach","ELIG_THRESHOLD")) %>%
  dplyr::mutate(se = (`f1_p97.5` - `f1_p2.5`) / 3.92,
                lcb1 = ifelse(is.na(se), val_f1, val_f1 - se))

ece_cap <- 0.02; logloss_cap <- 0.04
eligible <- final_table %>% dplyr::filter(val_ece <= ece_cap, val_logloss <= logloss_cap)
if (nrow(eligible) == 0) eligible <- final_table

best_idx <- which.max(eligible$val_f1); best_f1 <- eligible$val_f1[best_idx]
best_se  <- ifelse(is.na(eligible$se[best_idx]), 0, eligible$se[best_idx])
elite_thr <- best_f1 - best_se

elite <- eligible %>% dplyr::filter(val_f1 >= elite_thr)

if ("p10_game_f1" %in% names(elite)) {
  elite <- elite %>% dplyr::filter(is.na(p10_game_f1) | p10_game_f1 >= 0.10)
  if (nrow(elite) == 0) elite <- eligible %>% dplyr::filter(val_f1 >= elite_thr)
}

if (all(c("f1_jitter_drop","min_game_f1") %in% names(elite))) {
  elite <- elite %>% dplyr::filter(is.na(f1_jitter_drop) | f1_jitter_drop <= 0.03,
                                   is.na(min_game_f1)    | min_game_f1    >= (val_f1 - 0.08))
  if (nrow(elite) == 0) elite <- eligible %>% dplyr::filter(val_f1 >= elite_thr)
}

loess_safe <- function(df){
  if (nrow(df) < 15) return(rep(NA_real_, nrow(df)))
  ok <- stats::complete.cases(df$lambda_reach, df$ELIG_THRESHOLD, df$val_f1)
  fit <- try(suppressWarnings(stats::loess(val_f1 ~ lambda_reach + ELIG_THRESHOLD,
                                           data = df[ok,], span = 0.5, degree = 1,
                                           control = stats::loess.control(surface="direct"))), silent = TRUE)
  if (inherits(fit, "try-error")) return(rep(NA_real_, nrow(df)))
  pred <- try(stats::predict(fit, newdata = df[,c("lambda_reach","ELIG_THRESHOLD")]), silent = TRUE)
  if (inherits(pred, "try-error")) pred <- rep(NA_real_, nrow(df))
  as.numeric(pred)
}
elite$f1_loess <- loess_safe(elite)
elite$lcb1_sm <- ifelse(is.na(elite$f1_loess), elite$lcb1, elite$f1_loess - ifelse(is.na(elite$se), 0, elite$se))

add_roughness <- function(df, d_lambda = 0.05, d_et = 0.01){
  df <- df %>% dplyr::arrange(lambda_reach, ELIG_THRESHOLD)
  rough <- numeric(nrow(df))
  for (i in seq_len(nrow(df))){
    row <- df[i,]
    idx <- abs(df$lambda_reach - row$lambda_reach) <= d_lambda &
      abs(df$ELIG_THRESHOLD - row$ELIG_THRESHOLD) <= d_et
    vals <- df$val_f1[idx]; rough[i] <- if (length(vals) >= 2) stats::sd(vals) else 0
  }
  df$roughness <- rough; df
}
elite <- add_roughness(elite)

k_rough <- 0.25; k_ece <- 0.02; k_log <- 0.01
elite <- elite %>% dplyr::mutate(
  stability_score = lcb1_sm - k_rough*roughness - k_ece*val_ece - k_log*val_logloss -
    dplyr::if_else(!is.na(.data$`f1_jitter_drop`), 0.5*.data$`f1_jitter_drop`, 0)
)

# Keep original choice policy; tie-breakers already handled in earlier sorts
choice <- elite %>%
  dplyr::arrange(dplyr::desc(stability_score), val_ece, val_logloss, dplyr::desc(val_auc), dplyr::desc(val_f1)) %>%
  dplyr::slice(1) %>% dplyr::mutate(run_id = run_id, script_version = script_version)

for (nm in c("th_q10","th_q90","mtry","splitrule","sample_fraction","min_node"))
  if (!(nm %in% names(choice))) choice[[nm]] <- NA_real_

write_csv_atomic(choice %>% dplyr::mutate(LCB_1 = lcb1, lcb1_sm = lcb1_sm, roughness = roughness,
                                          th_q10 = th_q10, th_q90 = th_q90,
                                          mtry = mtry, splitrule = splitrule, sample_fraction = sample_fraction, min_node = min_node),
                 file.path(artifacts_dir, "sweep_choice_with_ci.csv"))
write_csv_atomic(choice %>% dplyr::select(lambda_reach, ELIG_THRESHOLD, run_id, script_version),
                 file.path(artifacts_dir, "sweep_inputs_choice.csv"))

elapsed <- difftime(Sys.time(), tic_total, units = "mins")
status <- tibble::tibble(
  script=17L, script_version=script_version, run_id=run_id, name="param_sweep_inputs", status="PASS",
  baseline_lambda=LAMBDA_BASELINE, coverage_min=COVERAGE_MIN,
  seeds_stage1=5L, seeds_late=9L, threads=threads,
  stage1_rows=nrow(stage1), stage2_rows=nrow(stage2),
  micro_rows=if (length(all_micro)) nrow(all_micro[[length(all_micro)]]) else 0L,
  boot_cands=nrow(boot),
  final_lambda = choice$lambda_reach[1], final_ET = choice$ELIG_THRESHOLD[1],
  elapsed_minutes = as.numeric(elapsed),
  timestamp_utc = format(as.POSIXct(Sys.time(), tz = "UTC"), "%Y-%m-%dT%H:%M:%SZ")
)
write_csv_atomic(status, file.path(artifacts_dir, "sweep_inputs_status.csv"))

choice_reload <- read_csv_cast(file.path(artifacts_dir, "sweep_choice_with_ci.csv"), show_col_types = FALSE)
stopifnot(isTRUE(all.equal(choice_reload$lambda_reach[1], choice$lambda_reach[1])),
          isTRUE(all.equal(choice_reload$ELIG_THRESHOLD[1], choice$ELIG_THRESHOLD[1])))

msg("Done. Winner: λ=%.3f, ET=%.3f (VAL F1=%.3f, AUC=%.3f).",
    choice$lambda_reach[1], choice$ELIG_THRESHOLD[1], choice$val_f1[1], choice$val_auc[1])










#!/usr/bin/env Rscript
# 17a_stability_selection.R — v17a.99.2
# Stability add-on after 17.
# - Computes neighborhood roughness & composite stability score inside the elite set
# - Emits a stable choice and a detailed report
# - Compares against prior winners and logs whether the winner changed
# - FIX: normalize `selected_utc` to string before bind_rows to avoid POSIXct/character clashes

suppressPackageStartupMessages({
  library(readr); library(dplyr); library(tidyr); library(stringr); library(ggplot2)
  # ---- run_id hygiene helpers (auto-injected) ----
  read_csv_cast <- function(...) {
    dots <- list(...)
    if (is.null(names(dots)) || !("show_col_types" %in% names(dots))) dots$show_col_types <- FALSE
    df <- do.call(readr::read_csv, dots)
    if ("run_id" %in% names(df)) df <- dplyr::mutate(df, run_id = as.character(.data$run_id))
    df
  }
  bind_rows_safe <- function(...) {
    dots <- list(...)
    cast_one <- function(x) {
      if (is.null(x)) return(x)
      if (inherits(x, "list")) lapply(x, cast_one)
      else if (is.data.frame(x) && "run_id" %in% names(x)) dplyr::mutate(x, run_id = as.character(.data$run_id))
      else x
    }
    dots2 <- lapply(dots, cast_one)
    do.call(dplyr::bind_rows, dots2)
  }
})

script_version <- "17a.99.2"
utc_now <- function() format(as.POSIXct(Sys.time(), tz = "UTC"), "%Y-%m-%dT%H:%M:%SZ")
msg <- function(fmt, ...) cat(sprintf(paste0("[17a] ", fmt, "\n"), ...))

# ADDED: normalize POSIXct/character to a uniform ISO-UTC string
normalize_selected_utc <- function(df){
  if (!("selected_utc" %in% names(df))) return(df)
  v <- df$selected_utc
  if (inherits(v, "POSIXct")) {
    v <- format(v, "%Y-%m-%dT%H:%M:%SZ", tz = "UTC")
  } else {
    p <- suppressWarnings(as.POSIXct(v, tz = "UTC"))
    v <- ifelse(is.na(p), as.character(v), format(p, "%Y-%m-%dT%H:%M:%SZ", tz = "UTC"))
  }
  df$selected_utc <- v
  df
}

paths <- list(
  dir        = "artifacts",
  choice_csv = "artifacts/sweep_inputs_choice.csv",      # from 17
  choice_ci  = "artifacts/sweep_choice_with_ci.csv",     # from 17
  grid_all   = "artifacts/sweep_inputs_grid.csv",
  microgrid  = "artifacts/sweep_microgrid.csv",
  stage2     = "artifacts/sweep_stage2_grid.csv",
  bootstrap  = "artifacts/sweep_bootstrap_summary.csv",
  out_choice = "artifacts/sweep_choice_stable.csv",
  out_report = "artifacts/sweep_choice_stability_report.csv",
  out_neigh  = "artifacts/sweep_choice_neighbors.csv",
  out_plot   = "artifacts/sweep_choice_stability_plot.png",
  out_log    = "artifacts/17a_status.csv"
)

read_csv_safe <- function(p){
  if (!file.exists(p)) return(NULL)
  out <- tryCatch(read_csv_cast(p, show_col_types = FALSE), error = function(e) NULL)
  # ADDED: keep any pre-existing `selected_utc` columns consistent on read
  if (!is.null(out)) out <- normalize_selected_utc(out)
  out
}

add_roughness <- function(df, d_lambda = 0.05, d_et = 0.01){
  stopifnot(all(c("lambda_reach","ELIG_THRESHOLD","val_f1") %in% names(df)))
  df <- df %>% arrange(lambda_reach, ELIG_THRESHOLD)
  rough <- numeric(nrow(df))
  for (i in seq_len(nrow(df))){
    row <- df[i,]
    idx <- abs(df$lambda_reach - row$lambda_reach) <= d_lambda &
      abs(df$ELIG_THRESHOLD - row$ELIG_THRESHOLD) <= d_et
    vals <- df$val_f1[idx]
    rough[i] <- if (length(vals) >= 2) stats::sd(vals) else 0
  }
  df$roughness <- rough
  df
}

attach_bootstrap <- function(grid, bs){
  if (is.null(bs)) { grid$se <- NA_real_; grid$lcb1 <- grid$val_f1; return(grid) }
  bs2 <- bs %>% mutate(se = (f1_p97.5 - f1_p2.5) / 3.92) %>% select(lambda_reach, ELIG_THRESHOLD, se)
  grid %>% left_join(bs2, by = c("lambda_reach","ELIG_THRESHOLD")) %>%
    mutate(lcb1 = val_f1 - ifelse(is.na(se), 0, se))
}

loess_safe <- function(df){
  if (nrow(df) < 15) return(rep(NA_real_, nrow(df)))
  ok <- stats::complete.cases(df$lambda_reach, df$ELIG_THRESHOLD, df$val_f1)
  fit <- try(suppressWarnings(stats::loess(
    val_f1 ~ lambda_reach + ELIG_THRESHOLD,
    data = df[ok,], span = 0.5, degree = 1,
    control = stats::loess.control(surface="direct"))), silent = TRUE)
  if (inherits(fit, "try-error")) return(rep(NA_real_, nrow(df)))
  pred <- try(stats::predict(fit, newdata = df[,c("lambda_reach","ELIG_THRESHOLD")]), silent = TRUE)
  if (inherits(pred, "try-error")) pred <- rep(NA_real_, nrow(df))
  as.numeric(pred)
}

main <- function(){
  dir.create(paths$dir, showWarnings = FALSE, recursive = TRUE)
  
  # Load grids in decreasing preference
  grid <- read_csv_safe(paths$grid_all)
  if (is.null(grid)) grid <- read_csv_safe(paths$microgrid)
  if (is.null(grid)) grid <- read_csv_safe(paths$stage2)
  bs   <- read_csv_safe(paths$bootstrap)
  
  if (is.null(grid)) stop("[17a] No grid file found (looked for sweep_inputs_grid.csv, sweep_microgrid.csv, stage2).")
  
  # Required columns
  required <- c("lambda_reach","ELIG_THRESHOLD","val_f1","val_auc","val_ece","val_logloss")
  miss <- setdiff(required, names(grid))
  if (length(miss)) stop("[17a] Grid missing: ", paste(miss, collapse=", "))
  
  grid <- grid %>% mutate(
    lambda_reach   = as.numeric(lambda_reach),
    ELIG_THRESHOLD = as.numeric(ELIG_THRESHOLD),
    val_f1         = as.numeric(val_f1),
    val_auc        = as.numeric(val_auc),
    val_ece        = as.numeric(val_ece),
    val_logloss    = as.numeric(val_logloss)
  )
  
  # Stability features
  grid <- add_roughness(grid, d_lambda = 0.05, d_et = 0.01)
  grid <- attach_bootstrap(grid, bs)
  
  if (!is.null(bs)) {
    grid <- dplyr::left_join(
      grid,
      bs %>% dplyr::select(lambda_reach, ELIG_THRESHOLD, dplyr::any_of(c("f1_jitter_drop","min_game_f1"))),
      by = c("lambda_reach","ELIG_THRESHOLD")
    )
  }
  
  # Elite set threshold from 17's choice if available, else 1-SE from grid
  choice_ci <- read_csv_safe(paths$choice_ci)
  if (!is.null(choice_ci) && nrow(choice_ci) >= 1) {
    best_f1 <- choice_ci$val_f1[1]
    best_se <- ifelse(all(c("f1_p97.5","f1_p2.5") %in% names(choice_ci)),
                      (choice_ci$f1_p97.5[1]-choice_ci$f1_p2.5[1])/3.92, 0)
  } else {
    best_idx <- which.max(grid$val_f1)
    best_f1 <- grid$val_f1[best_idx]
    best_se <- ifelse(is.na(grid$se[best_idx]), 0, grid$se[best_idx])
  }
  elite_thr <- best_f1 - best_se
  elite <- grid %>% filter(val_f1 >= elite_thr)
  
  # Optional filters if present
  if ("p10_game_f1" %in% names(elite)) {
    keep <- elite %>% filter(is.na(p10_game_f1) | p10_game_f1 >= 0.10)
    if (nrow(keep) > 0) elite <- keep
  }
  if (all(c("f1_jitter_drop","min_game_f1") %in% names(elite))) {
    keep <- elite %>% filter(is.na(f1_jitter_drop) | f1_jitter_drop <= 0.03,
                             is.na(min_game_f1)    | min_game_f1    >= (val_f1 - 0.08))
    if (nrow(keep) > 0) elite <- keep
  }
  
  # Composite stability score
  elite$f1_loess <- loess_safe(elite)
  elite$lcb1_sm  <- ifelse(is.na(elite$f1_loess), elite$lcb1, elite$f1_loess - ifelse(is.na(elite$se), 0, elite$se))
  k_rough <- 0.25; k_ece <- 0.02; k_log <- 0.01
  elite <- elite %>% mutate(
    stability_score = lcb1_sm - k_rough*roughness - k_ece*val_ece - k_log*val_logloss -
      dplyr::if_else(!is.na(.data$`f1_jitter_drop`), 0.5*.data$`f1_jitter_drop`, 0)
  )
  
  winner <- elite %>%
    arrange(desc(stability_score), val_ece, val_logloss, desc(val_auc), desc(val_f1)) %>%
    slice(1)
  
  # Compare against current 17 choice (and CI choice)
  prior_choice <- read_csv_safe(paths$choice_csv)
  prev_lam <- if (!is.null(prior_choice)) as.numeric(prior_choice$lambda_reach[1]) else NA_real_
  prev_et  <- if (!is.null(prior_choice)) as.numeric(prior_choice$ELIG_THRESHOLD[1]) else NA_real_
  
  prior_ci <- read_csv_safe(paths$choice_ci)
  prev_ci_lam <- if (!is.null(prior_ci)) as.numeric(prior_ci$lambda_reach[1]) else NA_real_
  prev_ci_et  <- if (!is.null(prior_ci))  as.numeric(prior_ci$ELIG_THRESHOLD[1]) else NA_real_
  
  changed_vs_choice <- isTRUE(all.equal(winner$lambda_reach[1], prev_lam)) &&
    isTRUE(all.equal(winner$ELIG_THRESHOLD[1], prev_et))
  changed_vs_choice <- !changed_vs_choice
  changed_vs_ci <- isTRUE(all.equal(winner$lambda_reach[1], prev_ci_lam)) &&
    isTRUE(all.equal(winner$ELIG_THRESHOLD[1], prev_ci_et))
  changed_vs_ci <- !changed_vs_ci
  
  # Write artifacts
  out_choice <- winner %>%
    transmute(
      lambda_reach, ELIG_THRESHOLD,
      coverage = if ("coverage" %in% names(winner)) coverage else NA_real_,
      val_f1, val_auc, val_ece, val_logloss,
      val_th = if ("val_th" %in% names(winner)) val_th else NA_real_,
      f1_median = if ("f1_median" %in% names(winner)) f1_median else val_f1,
      `f1_p2.5` = if ("f1_p2.5" %in% names(winner)) `f1_p2.5` else NA_real_,
      `f1_p97.5` = if ("f1_p97.5" %in% names(winner)) `f1_p97.5` else NA_real_,
      n_val = if ("rows_va" %in% names(winner)) rows_va else NA_integer_,
      LCB_1 = if ("lcb1" %in% names(winner)) lcb1 else val_f1,
      roughness, stability_score,
      source = if ("stage" %in% names(winner)) winner$stage else "stability",
      selected_utc = utc_now(),
      run_id = if ("run_id" %in% names(winner)) winner$run_id else format(as.POSIXct(Sys.time(), tz="UTC"), "%Y%m%dT%H%M%SZ"),
      script_version = script_version
    )
  
  suppressWarnings(readr::write_csv(out_choice, paths$out_choice))
  suppressWarnings(readr::write_csv(
    elite %>% select(lambda_reach, ELIG_THRESHOLD, val_f1, val_auc, val_ece, val_logloss,
                     dplyr::any_of(c("th_q10","th_q90","mtry","splitrule","sample_fraction","min_node")),
                     se, lcb1, f1_loess, lcb1_sm, roughness, stability_score),
    paths$out_report
  ))
  neigh <- grid %>% filter(
    abs(lambda_reach - winner$lambda_reach[1]) <= 0.05,
    abs(ELIG_THRESHOLD - winner$ELIG_THRESHOLD[1]) <= 0.01
  ) %>% arrange(desc(val_f1))
  suppressWarnings(readr::write_csv(neigh, paths$out_neigh))
  
  # Optional plot (don’t crash if ggplot2 complains)
  try({
    p <- ggplot(grid, aes(lambda_reach, ELIG_THRESHOLD)) +
      geom_point(aes(size = val_f1, alpha = 1 - pmin(roughness, 1))) +
      geom_point(data = winner, color = "red", size = 4, shape = 4, stroke = 1.2) +
      labs(title = "17a stability map",
           subtitle = sprintf("Winner λ=%.3f, ET=%.3f (red X)", winner$lambda_reach, winner$ELIG_THRESHOLD),
           x = "lambda_reach", y = "ELIG_THRESHOLD") +
      theme_minimal()
    ggsave(paths$out_plot, p, width = 7, height = 5, dpi = 120)
  }, silent = TRUE)
  
  # Log status row (ADDED: normalize both sides before bind_rows)
  status_row <- tibble::tibble(
    script = "17a", version = script_version, selected_utc = utc_now(),
    winner_lambda = winner$lambda_reach[1], winner_ET = winner$ELIG_THRESHOLD[1],
    prev_lambda = prev_lam, prev_ET = prev_et,
    prev_ci_lambda = prev_ci_lam, prev_ci_ET = prev_ci_et,
    changed_vs_choice = changed_vs_choice, changed_vs_choice_ci = changed_vs_ci
  )
  status_row <- normalize_selected_utc(status_row)
  if (file.exists(paths$out_log)) {
    old <- suppressWarnings(read_csv_cast(paths$out_log, show_col_types=FALSE))
    old <- normalize_selected_utc(old)
    status_all <- bind_rows_safe(old, status_row)
  } else {
    status_all <- status_row
  }
  suppressWarnings(readr::write_csv(status_all, paths$out_log))
  
  # Loud console summary so you can see it did something
  msg("Script %s | choice_stable: λ=%.3f, ET=%.3f", script_version, winner$lambda_reach, winner$ELIG_THRESHOLD)
  if (!is.na(prev_lam) && !is.na(prev_et)) {
    if (changed_vs_choice) {
      msg("Changed vs sweep_inputs_choice.csv: was λ=%.3f, ET=%.3f", prev_lam, prev_et)
    } else {
      msg("No change vs sweep_inputs_choice.csv")
    }
  } else {
    msg("No prior sweep_inputs_choice.csv found for comparison.")
  }
  if (!is.na(prev_ci_lam) && !is.na(prev_ci_et)) {
    if (changed_vs_ci) {
      msg("Changed vs sweep_choice_with_ci.csv: was λ=%.3f, ET=%.3f", prev_ci_lam, prev_ci_et)
    } else {
      msg("No change vs sweep_choice_with_ci.csv")
    }
  }
  msg("Wrote: %s, %s, %s, %s",
      paths$out_choice, paths$out_report, paths$out_neigh, paths$out_log)
}

# Always run main so sourcing actually does something
main()










#!/usr/bin/env Rscript
suppressPackageStartupMessages({ library(readr); library(dplyr); library(fs) })

stable  <- "artifacts/sweep_choice_stable.csv"
target  <- "artifacts/sweep_inputs_choice.csv"
status  <- "artifacts/17c_status.csv"

if (!file_exists(stable)) stop("Missing: ", stable)
x <- readr::read_csv(stable, show_col_types = FALSE)
need <- c("lambda_reach","ELIG_THRESHOLD")
miss <- setdiff(need, names(x)); if (length(miss)) stop("Stable choice missing columns: ", paste(miss, collapse=", "))

tmp <- paste0(target, ".tmp_", as.integer(runif(1,1e8,9e8)))
dir_create(path_dir(target))
readr::write_csv(x, tmp)
file_delete(target) |> suppressWarnings()
file_move(tmp, target)

readr::write_csv(tibble::tibble(
  timestamp_utc = format(as.POSIXct(Sys.time(), tz="UTC"), "%Y-%m-%dT%H:%M:%SZ"),
  promoted_from = stable, promoted_to = target,
  winner_lambda = x$lambda_reach[1], winner_ET = x$ELIG_THRESHOLD[1]
), status)

cat("Promoted 17a stable choice to ", target, "\n", sep = "")










#!/usr/bin/env Rscript
# 17c_generate_17b_artifacts.R — v1.2
# Purpose: Generate ALL four "17b" artifacts needed by the 17c verifier,
#          WITHOUT modifying your final choice. Safe to run anytime.
#
# Emits:
#   - artifacts/17b_candidates_eval.csv
#   - artifacts/17b_choice.csv
#   - artifacts/17b_bootstrap_summary.csv
#   - artifacts/17b_status.csv
#
# Inputs (if present):
#   - artifacts/sweep_inputs_grid.csv          (to fetch metrics for candidates)
#   - artifacts/sweep_bootstrap_summary.csv    (to copy bootstrap stats where available)
#   - artifacts/sweep_choice_stable.csv        (to mirror stable winner when possible)
#
# No training. No side-effects outside the four files above.

suppressPackageStartupMessages({
  library(readr); library(dplyr); library(tidyr); library(tibble); library(purrr)
})

say <- function(fmt, ...) cat(sprintf(paste0("[17c.gen-17b] ", fmt, "\n"), ...))
utc_now <- function() format(as.POSIXct(Sys.time(), tz="UTC"), "%Y-%m-%dT%H:%M:%SZ")
r3 <- function(x) round(as.numeric(x), 3)

# ---------- locate project root (same logic as your verifier) ----------
resolve_root <- function(){
  cand <- normalizePath(getwd(), mustWork = FALSE)
  for (i in 1:10) {
    if (dir.exists(file.path(cand, "artifacts"))) return(cand)
    parent <- dirname(cand); if (identical(parent, cand)) break; cand <- parent
  }
  home <- path.expand("~")
  p <- file.path(home, "bdb_project")
  if (dir.exists(file.path(p, "artifacts"))) return(p)
  stop("[17c.gen-17b] Could not find project root with 'artifacts' directory.")
}
root <- resolve_root()
art  <- function(...) file.path(root, "artifacts", ...)

# ---------- load optional inputs ----------
path_grid   <- art("sweep_inputs_grid.csv")
path_boot   <- art("sweep_bootstrap_summary.csv")
path_stable <- art("sweep_choice_stable.csv")

grid <- if (file.exists(path_grid)) try(readr::read_csv(path_grid, show_col_types = FALSE), silent = TRUE) else NULL
if (inherits(grid, "try-error")) grid <- NULL

boot <- if (file.exists(path_boot)) try(readr::read_csv(path_boot, show_col_types = FALSE), silent = TRUE) else NULL
if (inherits(boot, "try-error")) boot <- NULL

stable <- if (file.exists(path_stable)) try(readr::read_csv(path_stable, show_col_types = FALSE), silent = TRUE) else NULL
if (inherits(stable, "try-error")) stable <- NULL

# ---------- required 4-candidate set ----------
cands <- tibble::tribble(
  ~lambda_reach, ~ELIG_THRESHOLD,
  0.70,          0.050,
  0.30,          0.0001,
  0.65,          0.025,
  0.50,          0.005
)

# ---------- helper: pull best metrics for a candidate from grid ----------
match_metrics <- function(lam, et){
  if (is.null(grid) || !nrow(grid)) {
    return(tibble(val_f1 = NA_real_, val_auc = NA_real_, val_pr_auc = NA_real_,
                  val_ece = NA_real_, val_logloss = NA_real_))
  }
  g <- grid %>%
    mutate(lam_g = as.numeric(lambda_reach),
           et_g  = as.numeric(ELIG_THRESHOLD))
  # try exact, then 3dp match
  hit <- g %>% filter(abs(lam_g - lam) <= 1e-12 & abs(et_g - et) <= 1e-12)
  if (!nrow(hit)) {
    hit <- g %>% filter(abs(round(lam_g,3) - round(lam,3)) <= 1e-12 &
                          abs(round(et_g,3)  - round(et,3))  <= 1e-12)
  }
  if (!nrow(hit)) {
    return(tibble(val_f1 = NA_real_, val_auc = NA_real_, val_pr_auc = NA_real_,
                  val_ece = NA_real_, val_logloss = NA_real_))
  }
  hit %>%
    arrange(dplyr::desc(val_f1), val_ece, val_logloss, dplyr::desc(val_auc), dplyr::desc(val_pr_auc)) %>%
    slice(1) %>%
    transmute(val_f1 = as.numeric(val_f1),
              val_auc = dplyr::coalesce(as.numeric(val_auc), NA_real_),
              val_pr_auc = dplyr::coalesce(as.numeric(val_pr_auc), NA_real_),
              val_ece = dplyr::coalesce(as.numeric(val_ece), NA_real_),
              val_logloss = dplyr::coalesce(as.numeric(val_logloss), NA_real_))
}

# ---------- 1) emit 17b_candidates_eval.csv ----------
eval_rows <- dplyr::bind_rows(lapply(seq_len(nrow(cands)), function(i){
  lam <- cands$lambda_reach[i]; et <- cands$ELIG_THRESHOLD[i]
  tibble(lambda_reach = lam, ELIG_THRESHOLD = et) %>%
    dplyr::bind_cols(match_metrics(lam, et))
}))

path_b_eval <- art("17b_candidates_eval.csv")
readr::write_csv(eval_rows, path_b_eval)
say("Wrote %s (%d rows).", path_b_eval, nrow(eval_rows))

# ---------- 2) emit 17b_choice.csv ----------
# Prefer stable winner if it matches one of the four; else best val_f1 among four; else fallback to 0.50/0.005.
choose_b <- function(){
  if (!is.null(stable) && nrow(stable) >= 1 && all(c("lambda_reach","ELIG_THRESHOLD") %in% names(stable))) {
    sl <- r3(stable$lambda_reach[1]); se <- r3(stable$ELIG_THRESHOLD[1])
    hit <- eval_rows %>%
      mutate(lr = r3(lambda_reach), et = r3(ELIG_THRESHOLD)) %>%
      filter(lr == sl & et == se)
    if (nrow(hit)) return(hit %>% select(lambda_reach, ELIG_THRESHOLD) %>% slice(1))
  }
  if ("val_f1" %in% names(eval_rows) && any(is.finite(eval_rows$val_f1))) {
    return(eval_rows %>% arrange(dplyr::desc(val_f1)) %>% select(lambda_reach, ELIG_THRESHOLD) %>% slice(1))
  }
  return(tibble(lambda_reach = 0.50, ELIG_THRESHOLD = 0.005))
}
b_choice <- choose_b()

path_b_choice <- art("17b_choice.csv")
readr::write_csv(b_choice, path_b_choice)
say("Wrote %s (λ=%.3f ET=%.3f).", path_b_choice, b_choice$lambda_reach[1], b_choice$ELIG_THRESHOLD[1])

# ---------- 3) emit 17b_bootstrap_summary.csv ----------
# If overall sweep bootstrap is available, filter to the four candidates (3dp). Otherwise, create NA skeleton.
path_b_boot <- art("17b_bootstrap_summary.csv")
b_boot <- NULL
if (!is.null(boot) && nrow(boot)) {
  b_boot <- boot %>%
    mutate(lr = r3(lambda_reach), et = r3(ELIG_THRESHOLD)) %>%
    semi_join(cands %>% mutate(lr = r3(lambda_reach), et = r3(ELIG_THRESHOLD)), by = c("lr","et")) %>%
    select(-lr, -et)
  # Ensure expected columns exist
  need_cols <- c("lambda_reach","ELIG_THRESHOLD","f1_median","f1_p2.5","f1_p97.5","n_val",
                 "f1_jitter_mean","f1_jitter_min","f1_jitter_drop","min_game_f1","p10_game_f1",
                 "note","run_id","script_version")
  for (nm in setdiff(need_cols, names(b_boot))) b_boot[[nm]] <- NA
  b_boot <- b_boot %>% select(all_of(need_cols))
} else {
  b_boot <- cands %>% transmute(
    lambda_reach, ELIG_THRESHOLD,
    f1_median = NA_real_, `f1_p2.5` = NA_real_, `f1_p97.5` = NA_real_,
    n_val = NA_integer_,
    f1_jitter_mean = NA_real_, f1_jitter_min = NA_real_, f1_jitter_drop = NA_real_,
    min_game_f1 = NA_real_, p10_game_f1 = NA_real_,
    note = "no_sweep_bootstrap", run_id = NA_character_, script_version = "17c.gen-17b"
  )
}
readr::write_csv(b_boot, path_b_boot)
say("Wrote %s (%d rows).", path_b_boot, nrow(b_boot))

# ---------- 4) emit 17b_status.csv ----------
path_b_status <- art("17b_status.csv")
status <- tibble(
  script = "17c_generate_17b_artifacts",
  version = "v1.2",
  generated_utc = utc_now(),
  have_grid = !is.null(grid) && nrow(grid) > 0,
  have_bootstrap = !is.null(boot) && nrow(boot) > 0,
  candidates = nrow(cands),
  choice_lambda = b_choice$lambda_reach[1],
  choice_ET = b_choice$ELIG_THRESHOLD[1]
)
readr::write_csv(status, path_b_status)
say("Wrote %s.", path_b_status)

say("Done. All four 17b artifacts emitted. No changes to sweep_inputs_choice.csv.")










#!/usr/bin/env Rscript
# 17d_verify_17_pipeline.R — v17d.1.1
# Change: Option B — replace hard-coded (0.5,0.005) policy with "final equals stable winner"
# Verifies outputs from scripts 17, 17a, 17b and 17c.
# Produces an overall PASS/FAIL and a detailed checklist.

suppressPackageStartupMessages({
  library(readr); library(dplyr); library(tidyr); library(tibble); library(stringr); library(janitor)
})

# ---------- helpers ----------
now_utc <- function() format(as.POSIXct(Sys.time(), tz="UTC"), "%Y-%m-%dT%H:%M:%SZ")

resolve_root <- function() {
  # Try CWD, its parents, and ~/bdb_project for an "artifacts" dir
  cand <- normalizePath(getwd(), mustWork = FALSE)
  for (i in 1:10) {
    if (dir.exists(file.path(cand, "artifacts"))) return(cand)
    parent <- dirname(cand); if (identical(parent, cand)) break; cand <- parent
  }
  home <- path.expand("~")
  p <- file.path(home, "bdb_project")
  if (dir.exists(file.path(p, "artifacts"))) return(p)
  stop("Could not find project root containing 'artifacts' directory. Run from within your project or adjust.")
}

root <- resolve_root()
art <- function(...) file.path(root, "artifacts", ...)

read_csv_safe <- function(path) {
  if (!file.exists(path)) return(NULL)
  tryCatch(readr::read_csv(path, show_col_types = FALSE), error = function(e) NULL)
}

mk_checks <- function() tibble(
  scope = character(), check = character(), file = character(),
  severity = character(), status = character(), detail = character()
)

add_check <- function(tbl, scope, check, file, ok, detail = "", severity = c("ERROR","WARN")) {
  severity <- match.arg(severity)
  status <- if (isTRUE(ok)) "PASS" else if (severity == "ERROR") "FAIL" else "WARN"
  bind_rows(tbl, tibble(scope = scope, check = check, file = file,
                        severity = severity, status = status, detail = detail))
}

in_range <- function(x, lo, hi, na_ok = FALSE) {
  if (na_ok) return(all(is.na(x) | (x >= lo & x <= hi)))
  all(!is.na(x) & x >= lo & x <= hi)
}

# ---------- expected artifacts ----------
paths <- list(
  # 17 core
  sweep_choice           = art("sweep_inputs_choice.csv"),
  sweep_choice_ci        = art("sweep_choice_with_ci.csv"),
  sweep_grid             = art("sweep_inputs_grid.csv"),
  sweep_bootstrap        = art("sweep_bootstrap_summary.csv"),
  sweep_microgrid        = art("sweep_microgrid.csv"),     # optional
  sweep_stage2           = art("sweep_stage2_grid.csv"),   # optional
  # 17a outputs
  stable_choice          = art("sweep_choice_stable.csv"),
  stable_neighbors       = art("sweep_choice_neighbors.csv"),
  stability_report       = art("sweep_choice_stability_report.csv"), # optional text/csv
  status_17a             = art("17a_status.csv"),
  # 17b outputs
  b_candidates_eval      = art("17b_candidates_eval.csv"),
  b_bootstrap_summary    = art("17b_bootstrap_summary.csv"),
  b_choice               = art("17b_choice.csv"),
  b_status               = art("17b_status.csv")
  # 17c (optional) would have updated sweep_inputs_choice.csv in place
)

# ---------- verification ----------
checks <- mk_checks()

# Existence checks
for (k in c("sweep_choice","sweep_choice_ci","sweep_grid","sweep_bootstrap",
            "stable_choice","stable_neighbors","status_17a",
            "b_candidates_eval","b_bootstrap_summary","b_choice","b_status")) {
  checks <- add_check(checks, "existence", paste0("file present: ", k), paths[[k]],
                      file.exists(paths[[k]]),
                      severity = if (k %in% c("stable_choice","b_candidates_eval","b_choice","sweep_choice","sweep_grid")) "ERROR" else "WARN")
}

# Load what we can
df_choice     <- read_csv_safe(paths$sweep_choice)
df_choice_ci  <- read_csv_safe(paths$sweep_choice_ci)
df_grid       <- read_csv_safe(paths$sweep_grid)
df_boot       <- read_csv_safe(paths$sweep_bootstrap)
df_stable     <- read_csv_safe(paths$stable_choice)
df_neighbors  <- read_csv_safe(paths$stable_neighbors)
df_b_eval     <- read_csv_safe(paths$b_candidates_eval)
df_b_boot     <- read_csv_safe(paths$b_bootstrap_summary)
df_b_choice   <- read_csv_safe(paths$b_choice)
df_b_status   <- read_csv_safe(paths$b_status)

# Common required columns
need_choice_cols <- c("lambda_reach","ELIG_THRESHOLD")
need_grid_cols   <- c("lambda_reach","ELIG_THRESHOLD","val_f1")
opt_grid_cols    <- c("val_auc","val_pr_auc","val_ece","val_logloss")

# 17 choice schema
if (!is.null(df_choice)) {
  checks <- add_check(checks, "17", "choice has required cols", paths$sweep_choice,
                      all(need_choice_cols %in% names(df_choice)),
                      detail = paste("missing:", paste(setdiff(need_choice_cols, names(df_choice)), collapse=", ")),
                      severity = "ERROR")
  if (all(need_choice_cols %in% names(df_choice))) {
    checks <- add_check(checks, "17", "choice values in plausible ranges", paths$sweep_choice,
                        in_range(df_choice$lambda_reach, 0.25, 1.5) &&
                          in_range(df_choice$ELIG_THRESHOLD, 0, 0.2),
                        "expect lambda in [0.25,1.5], ET in [0,0.2]", "ERROR")
  }
}

# 17 grid schema + value ranges
if (!is.null(df_grid)) {
  checks <- add_check(checks, "17", "grid has required cols", paths$sweep_grid,
                      all(need_grid_cols %in% names(df_grid)),
                      detail = paste("missing:", paste(setdiff(need_grid_cols, names(df_grid)), collapse=", ")),
                      severity = "ERROR")
  checks <- add_check(checks, "17", "grid non-empty", paths$sweep_grid,
                      nrow(df_grid) > 0, "", "ERROR")
  # Deduplicate key
  if (all(need_choice_cols %in% names(df_grid))) {
    dup <- df_grid %>% count(lambda_reach, ELIG_THRESHOLD) %>% filter(n > 1)
    checks <- add_check(checks, "17", "grid pairs unique", paths$sweep_grid,
                        nrow(dup) == 0, paste("duplicates:", nrow(dup)), "ERROR")
  }
  # Value sanity
  if ("val_f1" %in% names(df_grid)) {
    checks <- add_check(checks, "17", "val_f1 within [0,1]", paths$sweep_grid,
                        in_range(df_grid$val_f1, 0, 1, na_ok = FALSE),
                        "", "ERROR")
  }
  for (cname in intersect(opt_grid_cols, names(df_grid))) {
    rng_ok <- switch(cname,
                     val_auc = in_range(df_grid[[cname]], 0.5, 1, na_ok = TRUE),
                     val_pr_auc = in_range(df_grid[[cname]], 0, 1, na_ok = TRUE),
                     val_ece = in_range(df_grid[[cname]], 0, 1, na_ok = TRUE),
                     val_logloss = all(is.finite(df_grid[[cname]]) & df_grid[[cname]] >= 0),
                     TRUE
    )
    checks <- add_check(checks, "17", paste0(cname, " sane range"), paths$sweep_grid, rng_ok, "", "WARN")
  }
}

# 17 bootstrap schema
if (!is.null(df_boot)) {
  need_boot <- c("lambda_reach","ELIG_THRESHOLD","f1_p2.5","f1_p97.5")
  checks <- add_check(checks, "17", "bootstrap has required cols", paths$sweep_bootstrap,
                      all(need_boot %in% names(df_boot)),
                      paste("missing:", paste(setdiff(need_boot, names(df_boot)), collapse=", ")),
                      "WARN")
  if (all(need_boot %in% names(df_boot))) {
    ok_ci <- all(df_boot$`f1_p97.5` >= df_boot$`f1_p2.5` | (is.na(df_boot$`f1_p97.5`) & is.na(df_boot$`f1_p2.5`)))
    checks <- add_check(checks, "17", "bootstrap CI ordering", paths$sweep_bootstrap, ok_ci, "", "WARN")
  }
}

# Stable choice existence and consistency with grid
if (!is.null(df_stable)) {
  checks <- add_check(checks, "17a", "stable choice has required cols", paths$stable_choice,
                      all(need_choice_cols %in% names(df_stable)), "", "ERROR")
  if (all(need_choice_cols %in% names(df_stable)) && !is.null(df_grid) &&
      all(need_choice_cols %in% names(df_grid))) {
    key <- df_grid %>% transmute(lambda_reach, ELIG_THRESHOLD) %>% distinct()
    found <- inner_join(df_stable %>% transmute(lambda_reach, ELIG_THRESHOLD),
                        key, by = c("lambda_reach","ELIG_THRESHOLD"))
    checks <- add_check(checks, "17a", "stable choice present in grid", paths$stable_choice,
                        nrow(found) >= 1, "", "ERROR")
  }
}

# Neighbors (sanity only)
if (!is.null(df_neighbors)) {
  need_nei <- c("lambda_reach","ELIG_THRESHOLD","val_f1")
  checks <- add_check(checks, "17a", "neighbors table has key metrics", paths$stable_neighbors,
                      all(need_nei %in% names(df_neighbors)), "", "WARN")
}

# 17b: candidates shape and membership
if (!is.null(df_b_eval)) {
  checks <- add_check(checks, "17b", "candidates eval has required cols", paths$b_candidates_eval,
                      all(c("lambda_reach","ELIG_THRESHOLD","val_f1") %in% names(df_b_eval)),
                      "", "ERROR")
  if (all(c("lambda_reach","ELIG_THRESHOLD") %in% names(df_b_eval))) {
    checks <- add_check(checks, "17b", "exactly four candidates present", paths$b_candidates_eval,
                        nrow(df_b_eval) == 4, paste("rows:", nrow(df_b_eval)), "ERROR")
    # Expected four pairs
    target_pairs <- tribble(
      ~lambda_reach, ~ELIG_THRESHOLD,
      0.70,          0.050,
      0.30,          0.0001,
      0.65,          0.025,
      0.50,          0.005
    )
    miss <- anti_join(target_pairs, df_b_eval, by = c("lambda_reach","ELIG_THRESHOLD"))
    checks <- add_check(checks, "17b", "candidate set matches expected four pairs", paths$b_candidates_eval,
                        nrow(miss) == 0, paste("missing pairs:", paste(apply(miss,1,paste,collapse=","), collapse=" | ")), "ERROR")
  }
}
if (!is.null(df_b_choice)) {
  checks <- add_check(checks, "17b", "choice schema", paths$b_choice,
                      all(need_choice_cols %in% names(df_b_choice)), "", "ERROR")
  if (!is.null(df_b_eval) && all(need_choice_cols %in% names(df_b_eval))) {
    hit <- inner_join(df_b_choice %>% select(all_of(need_choice_cols)),
                      df_b_eval %>% select(all_of(need_choice_cols)),
                      by = need_choice_cols)
    checks <- add_check(checks, "17b", "choice is among evaluated candidates", paths$b_choice,
                        nrow(hit) == 1, "", "ERROR")
  }
}

# Cross-check (Option B): final choice equals stable winner (rounded to verifier precision)
if (!is.null(df_stable) && !is.null(df_choice) &&
    all(need_choice_cols %in% names(df_stable)) && all(need_choice_cols %in% names(df_choice))) {
  s_l <- round(as.numeric(df_stable$lambda_reach[1]), 3)
  s_e <- round(as.numeric(df_stable$ELIG_THRESHOLD[1]), 3)
  f_l <- round(as.numeric(df_choice$lambda_reach[1]), 3)
  f_e <- round(as.numeric(df_choice$ELIG_THRESHOLD[1]), 3)
  same <- isTRUE(all.equal(s_l, f_l)) && isTRUE(all.equal(s_e, f_e))
  detail_msg <- sprintf("stable=(%.3f,%.3f) final=(%.3f,%.3f)", s_l, s_e, f_l, f_e)
  checks <- add_check(
    checks, "cross", "final equals stable winner", paths$sweep_choice,
    same, detail_msg, "WARN"
  )
}

# ---------- finalize ----------
# Overall decision: FAIL if any ERROR fails; otherwise PASS (WARNs allowed)
fails <- sum(checks$status == "FAIL")
warns <- sum(checks$status == "WARN")
passes <- sum(checks$status == "PASS")

overall <- if (fails == 0) "PASS" else "FAIL"

dir.create(file.path(root, "artifacts"), showWarnings = FALSE, recursive = TRUE)
readr::write_csv(checks, art("17d_verification_checks.csv"))
readr::write_csv(tibble(
  timestamp_utc = now_utc(),
  overall_status = overall,
  pass = passes, warn = warns, fail = fails
), art("17d_status.csv"))

# Markdown report
mk <- c(
  "# 17d Verification Report",
  paste0("- Time (UTC): ", now_utc()),
  paste0("- Overall: **", overall, "**"),
  paste0("- Checks: PASS=", passes, "  WARN=", warns, "  FAIL=", fails),
  "",
  "## Details",
  paste0("| Scope | Check | File | Severity | Status | Detail |"),
  "|---|---|---|---|---|---|",
  apply(checks, 1, function(r) sprintf("| %s | %s | %s | %s | %s | %s |",
                                       r[["scope"]], r[["check"]], r[["file"]],
                                       r[["severity"]], r[["status"]], r[["detail"]]))
)
writeLines(mk, art("17d_report.md"))

cat(sprintf("[17d] Overall: %s  (PASS=%d WARN=%d FAIL=%d)\n", overall, passes, warns, fails))
if (overall != "PASS") {
  bad <- checks %>% filter(status == "FAIL")
  cat("Failing checks:\n")
  print(bad %>% select(scope, check, file, detail))
}










#!/usr/bin/env Rscript

# =====================================================================
# 18_m03_v2_train_ab.R — RF + XGB A/B with calibration, metrics, curves,
# importance, champion selection, and zero XGBoost deprecation warnings.
# =====================================================================

# --- bootstrap: auto-install required packages if missing ---------------
.ensure_pkgs <- function(pkgs){
  missing <- setdiff(pkgs, rownames(installed.packages()))
  if (length(missing)) {
    repos <- getOption("repos")
    if (is.null(repos) || is.na(repos["CRAN"]) || repos["CRAN"] == "@CRAN@") {
      options(repos = c(CRAN = "https://cloud.r-project.org"))
    }
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(missing, dependencies = TRUE, quiet = TRUE), silent = TRUE)
  }
}
.ensure_pkgs(c("optparse","tidyverse","readr","janitor","data.table",
               "ranger","pROC","knitr","jsonlite","xgboost","tibble","dplyr"))
rm(.ensure_pkgs)

suppressPackageStartupMessages({
  library(optparse)
  library(tidyverse)
  library(readr)
  library(janitor)
  library(data.table)
  library(ranger)
  library(pROC)
  library(knitr)
  library(jsonlite)
})

# Tie-break epsilons
EPS_AUC <- 1e-3
EPS_LOGLOSS <- 5e-3

hash_file <- function(path){
  if (!file.exists(path)) return(NA_character_)
  as.character(tools::md5sum(path))
}

# ----------------------------- CLI ------------------------------------
option_list <- list(
  make_option("--dataset_csv", type = "character", default = NA),
  make_option("--caps_csv", type = "character", default = NA),
  make_option("--split_map_csv", type = "character", default = NA),
  make_option("--elig_col", type = "character", default = "eligibility_score"),
  make_option("--elig_threshold", type = "double", default = NA),
  make_option("--reach_cols", type = "character", default = "p_reach_start,p_reach_max"),
  make_option("--lambda", type = "double", default = NA),
  make_option("--algos", type = "character", default = "rf,xgb"),
  make_option("--out_dir", type = "character", default = "artifacts"),
  make_option("--prefix_base", type = "character", default = "v2_model03"),
  make_option("--seed", type = "integer", default = 2025),
  make_option("--threads", type = "integer", default = 0),
  make_option("--auc_min_val", type = "double", default = 0.90),
  make_option("--fit_calibration", action = "store_true", default = TRUE),
  make_option("--ece_bins", type = "integer", default = 15),
  make_option("--write_train_preds", action = "store_true", default = FALSE)
)
args <- parse_args(OptionParser(option_list = option_list))
set.seed(args$seed)

# ----------------------------- PATHS & KNOBS ---------------------------
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
DIRS <- list(artifacts = B(args$out_dir), splits = B("data","splits"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_DS   <- if (!is.na(args$dataset_csv)) args$dataset_csv else B("artifacts","model02_contest_dataset_final.csv")
PATH_CAPS <- if (!is.na(args$caps_csv))    args$caps_csv    else B("artifacts","capability_profiles.csv")
PATH_MAP  <- if (!is.na(args$split_map_csv)) args$split_map_csv else B("data","splits","plays_split_map.csv")

choice_paths <- c(B("artifacts","sweep_inputs_choice.csv"),
                  B("artifacts","sweep_inputs","sweep_inputs_choice.csv"))
choice_path <- choice_paths[file.exists(choice_paths)][1]
ELIG_THRESHOLD <- if (!is.na(args$elig_threshold)) args$elig_threshold else 0.0
lambda <- if (!is.na(args$lambda)) args$lambda else 0.5
if (!is.na(choice_path)) {
  ch <- tryCatch(data.table::fread(choice_path), error = function(e) NULL)
  if (!is.null(ch)) {
    if (is.na(args$elig_threshold) && "ELIG_THRESHOLD" %in% names(ch)) ELIG_THRESHOLD <- ch$ELIG_THRESHOLD[1]
    if (is.na(args$lambda) && "lambda" %in% names(ch)) lambda <- ch$lambda[1]
  }
}
message(sprintf("Using knobs: ELIG_THRESHOLD=%.6f, lambda=%.3f", ELIG_THRESHOLD, lambda))

# ----------------------------- LOAD DATA --------------------------------
req <- function(path, name){ if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE) }
req(PATH_DS,   basename(PATH_DS))
req(PATH_CAPS, basename(PATH_CAPS))
req(PATH_MAP,  basename(PATH_MAP))

read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

ds <- read_csv_clean(PATH_DS) |>
  mutate(game_id = as.character(game_id),
         play_id = suppressWarnings(as.integer(play_id)),
         nfl_id  = suppressWarnings(as.integer(nfl_id)))

caps <- read_csv_clean(PATH_CAPS) |>
  transmute(nfl_id = suppressWarnings(as.integer(nfl_id)),
            v_max  = as.numeric(v_max),
            a_max  = as.numeric(a_max)) |>
  distinct(nfl_id, .keep_all = TRUE)

splits <- read_csv_clean(PATH_MAP) |>
  transmute(game_id = as.character(game_id),
            play_id = suppressWarnings(as.integer(play_id)),
            split   = tolower(as.character(split)))

ds <- ds |> select(-any_of("split")) |> left_join(splits, by = c("game_id","play_id"))

# ----------------------------- FILTER + FEATURES ------------------------
use_numeric_elig <- args$elig_col %in% names(ds)
if (use_numeric_elig) {
  before_n <- nrow(ds); ds <- ds |> filter(.data[[args$elig_col]] >= ELIG_THRESHOLD)
  message(sprintf("Eligibility filter %s >= %.6f: %d -> %d rows", args$elig_col, ELIG_THRESHOLD, before_n, nrow(ds)))
} else if ("eligible" %in% names(ds)) {
  before_n <- nrow(ds); ds <- ds |> filter(eligible)
  message(sprintf("Eligibility boolean filter 'eligible': %d -> %d rows", before_n, nrow(ds)))
} else {
  message("No eligibility column found; proceeding without eligibility filter.")
}

ds <- ds |> select(-any_of(c("v_max","a_max"))) |> left_join(caps, by = "nfl_id")

reach_cols <- strsplit(args$reach_cols, ",")[[1]] |> trimws()
if (length(reach_cols) == 2 && all(reach_cols %in% names(ds))) {
  ds <- ds |> mutate(p_reach_blend = lambda * .data[[reach_cols[1]]] + (1 - lambda) * .data[[reach_cols[2]]])
  message(sprintf("Added p_reach_blend from %s and %s (lambda=%.3f)", reach_cols[1], reach_cols[2], lambda))
}

base_feats <- c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")
feat_cols <- unique(c(base_feats, intersect("p_reach_blend", names(ds))))

for (sp in c("train","val","test")) if (!any(ds$split == sp)) stop("Split has zero rows: ", sp, call. = FALSE)

# ----------------------------- UTILITIES --------------------------------
clip <- function(p, eps = 1e-6) pmin(pmax(p, eps), 1 - eps)
logit <- function(p) log(clip(p) / (1 - clip(p)))
logloss <- function(p, y){ p <- clip(p); -mean(y*log(p) + (1-y)*log(1-p)) }
brier   <- function(p, y) mean((p - y)^2)
auc_safe <- function(y, p) suppressMessages(suppressWarnings(as.numeric(pROC::auc(y, p, quiet = TRUE))))
ece <- function(p, y, bins=args$ece_bins){
  brks <- seq(0,1,length.out=bins+1)
  cutp <- cut(p, breaks=brks, include.lowest=TRUE)
  dt <- data.table(p=p, y=y, bin=cutp)[, .(p_bar=mean(p), y_bar=mean(y), n=.N), by=bin]
  dt[, w := n/sum(n)]; sum(dt$w * abs(dt$p_bar - dt$y_bar))
}

encode_y01 <- function(v){
  if (is.logical(v)) return(as.integer(v == TRUE))
  if (is.numeric(v)) return(as.integer(v >= 0.5))
  if (is.factor(v) || is.character(v)) return(as.integer(tolower(as.character(v)) %in% c("1","yes","true","y","t")))
  stop("Unsupported label type: ", typeof(v))
}

validate_split <- function(df, LABEL, split_name){
  if (nrow(df) == 0) stop("Split has zero rows: ", split_name, " for label ", LABEL, call. = FALSE)
  y <- encode_y01(df[[LABEL]])
  if (length(unique(y[!is.na(y)])) < 2) stop("Validation requires at least one positive and one negative in ", split_name, " for label ", LABEL, call. = FALSE)
  invisible(TRUE)
}

meds <- ds |> filter(split=="train") |> select(all_of(feat_cols)) |>
  summarise(across(everything(), ~ suppressWarnings(median(.x, na.rm = TRUE))))
impute_median <- function(df, meds_row){
  nm <- intersect(names(meds_row), names(df))
  for (v in nm) {
    suppressWarnings(df[[v]][!is.finite(df[[v]])] <- NA)
    df[[v]][is.na(df[[v]])] <- meds_row[[v]][1]
  }
  df
}

get_yes <- function(pred_obj){ as.numeric(pred_obj$predictions[,"yes"]) }

prep_splits <- function(LABEL){
  cols <- c("game_id","play_id","nfl_id", LABEL, feat_cols)
  list(
    tr = ds |> filter(split=="train") |> select(all_of(cols)) |> impute_median(meds),
    va = ds |> filter(split=="val")   |> select(all_of(cols)) |> impute_median(meds),
    te = ds |> filter(split=="test")  |> select(all_of(cols)) |> impute_median(meds)
  )
}

# ----------------------------- TRAIN: RF ---------------------------------
train_one_rf <- function(LABEL){
  S <- prep_splits(LABEL)
  validate_split(S$tr, LABEL, "train"); validate_split(S$va, LABEL, "val"); validate_split(S$te, LABEL, "test")
  
  rf_train <- S$tr |> mutate(y01 = encode_y01(.data[[LABEL]])) |>
    transmute(y = factor(ifelse(y01==1, "yes","no"), levels=c("no","yes")),
              across(all_of(feat_cols)))
  
  fit <- ranger::ranger(
    y ~ ., data = rf_train,
    num.trees = 500,
    mtry = max(1, floor(sqrt(length(feat_cols)))),
    min.node.size = 10,
    probability = TRUE,
    respect.unordered.factors = TRUE,
    seed = args$seed,
    num.threads = if (args$threads > 0) args$threads else NULL,
    importance = "impurity"
  )
  
  p_raw_tr <- get_yes(predict(fit, data = S$tr[, feat_cols, drop = FALSE]))
  p_raw_va <- get_yes(predict(fit, data = S$va[, feat_cols, drop = FALSE]))
  p_raw_te <- get_yes(predict(fit, data = S$te[, feat_cols, drop = FALSE]))
  
  calib_glm <- NULL
  if (isTRUE(args$fit_calibration)) {
    y_va <- encode_y01(S$va[[LABEL]])
    cal_df <- data.frame(y = y_va, l = logit(p_raw_va))
    suppressWarnings(calib_glm <- glm(y ~ l, data = cal_df, family = binomial()))
    if (any(is.na(coef(calib_glm)))) stop("Calibration GLM failed (NA coefficients) for RF on label ", LABEL)
  }
  p_cal <- function(p) if (is.null(calib_glm)) p else predict(calib_glm, newdata = data.frame(l = logit(p)), type = "response")
  
  imp <- tryCatch({
    tibble::tibble(feature = names(ranger::importance(fit)),
                   importance = as.numeric(ranger::importance(fit)))
  }, error=function(e) tibble::tibble())
  
  list(
    ids = list(tr=S$tr[,c("game_id","play_id","nfl_id")],
               va=S$va[,c("game_id","play_id","nfl_id")],
               te=S$te[,c("game_id","play_id","nfl_id")]),
    y_tr = encode_y01(S$tr[[LABEL]]),
    y_va = encode_y01(S$va[[LABEL]]),
    y_te = encode_y01(S$te[[LABEL]]),
    p_tr = p_cal(p_raw_tr),
    p_va = p_cal(p_raw_va),
    p_te = p_cal(p_raw_te),
    model = fit, calib = calib_glm, importance = imp,
    algo = "rf", label = LABEL
  )
}

# ----------------------------- TRAIN: XGB --------------------------------
train_one_xgb <- function(LABEL){
  if (!requireNamespace("xgboost", quietly = TRUE)) {
    stop("Package \"xgboost\" is required for --algos including xgb. Install it or run with --algos rf.", call. = FALSE)
  }
  suppressPackageStartupMessages(library(xgboost))
  
  S <- prep_splits(LABEL)
  validate_split(S$tr, LABEL, "train"); validate_split(S$va, LABEL, "val"); validate_split(S$te, LABEL, "test")
  
  Xtr <- as.matrix(S$tr[, feat_cols, drop = FALSE])
  Xva <- as.matrix(S$va[, feat_cols, drop = FALSE])
  Xte <- as.matrix(S$te[, feat_cols, drop = FALSE])
  ytr <- encode_y01(S$tr[[LABEL]])
  yva <- encode_y01(S$va[[LABEL]])
  yte <- encode_y01(S$te[[LABEL]])
  
  set.seed(args$seed)
  dtr <- xgboost::xgb.DMatrix(Xtr, label = ytr)
  dva <- xgboost::xgb.DMatrix(Xva, label = yva)
  
  params <- list(
    objective = "binary:logistic",
    eval_metric = c("logloss","auc"),
    max_depth = 6,
    eta = 0.05,
    subsample = 0.8,
    colsample_bytree = 0.8,
    min_child_weight = 1,
    nthread = if (args$threads > 0) args$threads else 0
  )
  
  # Train with early stopping to discover best iteration (fit_main)
  fit_main <- xgboost::xgb.train(
    params = params,
    data = dtr,
    watchlist = list(train = dtr, val = dva),
    nrounds = 2000,
    early_stopping_rounds = 100,
    verbose = 0
  )
  iter_end <- if (!is.null(fit_main$best_iteration)) fit_main$best_iteration else fit_main$best_ntreelimit
  
  # Retrain a compact model to EXACT best iteration, so predict() needs no limits
  set.seed(args$seed)
  fit <- xgboost::xgb.train(
    params = params,
    data = dtr,
    watchlist = list(train = dtr),
    nrounds = iter_end,
    verbose = 0
  )
  
  p_raw_tr <- predict(fit, dtr)
  p_raw_va <- predict(fit, dva)
  p_raw_te <- predict(fit, xgboost::xgb.DMatrix(Xte))
  
  calib_glm <- NULL
  if (isTRUE(args$fit_calibration)) {
    cal_df <- data.frame(y = yva, l = logit(p_raw_va))
    suppressWarnings(calib_glm <- glm(y ~ l, data = cal_df, family = binomial()))
    if (any(is.na(coef(calib_glm)))) stop("Calibration GLM failed (NA coefficients) for XGB on label ", LABEL)
  }
  p_cal <- function(p) if (is.null(calib_glm)) p else predict(calib_glm, newdata = data.frame(l = logit(p)), type = "response")
  
  imp <- tryCatch({
    tibble::as_tibble(xgboost::xgb.importance(model=fit, feature_names=colnames(Xtr))) |>
      dplyr::select(Feature, Gain, Cover, Frequency) |>
      dplyr::rename(feature=Feature, gain=Gain, cover=Cover, frequency=Frequency)
  }, error=function(e) tibble::tibble())
  
  list(
    ids = list(tr=S$tr[,c("game_id","play_id","nfl_id")],
               va=S$va[,c("game_id","play_id","nfl_id")],
               te=S$te[,c("game_id","play_id","nfl_id")]),
    y_tr = ytr, y_va = yva, y_te = yte,
    p_tr = p_cal(p_raw_tr), p_va = p_cal(p_raw_va), p_te = p_cal(p_raw_te),
    model = fit, calib = calib_glm, importance = imp,
    algo = "xgb", label = LABEL
  )
}

# ----------------------------- WRITE ARTIFACTS --------------------------
write_bundle <- function(out, prefix, suffix = ""){
  build_cal_curve <- function(p, y, bins=args$ece_bins){
    brks <- seq(0,1,length.out=bins+1)
    cutp <- cut(p, breaks=brks, include.lowest=TRUE)
    data.table(prob=p, y=y, bin=cutp)[, .(bin_pred=mean(prob), bin_obs=mean(y), n=.N), by=bin]
  }
  
  OUT_TRAIN   <- file.path(DIRS$artifacts, paste0(prefix, "_train_preds", suffix, ".csv"))
  OUT_VAL     <- file.path(DIRS$artifacts, paste0(prefix, "_val_preds",   suffix, ".csv"))
  OUT_TEST    <- file.path(DIRS$artifacts, paste0(prefix, "_test_preds",  suffix, ".csv"))
  OUT_METRICS <- file.path(DIRS$artifacts, paste0(prefix, "_metrics",     suffix, ".csv"))
  OUT_MODEL   <- file.path(DIRS$artifacts, paste0(prefix, "_model_rds",   suffix, ".rds"))
  OUT_CALIB   <- file.path(DIRS$artifacts, paste0(prefix, "_calibration_glm", suffix, ".rds"))
  OUT_STATUS  <- file.path(DIRS$artifacts, paste0(prefix, "_status",      suffix, ".csv"))
  OUT_REPORT  <- file.path(DIRS$artifacts, paste0(prefix, "_report",      suffix, ".md"))
  OUT_IMPORT  <- file.path(DIRS$artifacts, paste0(prefix, "_feature_importance", suffix, ".csv"))
  
  metrics <- tibble::tibble(
    split = c("train","val","test"),
    auc   = c(auc_safe(out$y_tr, out$p_tr), auc_safe(out$y_va, out$p_va), auc_safe(out$y_te, out$p_te)),
    logloss = c(logloss(out$p_tr,out$y_tr), logloss(out$p_va,out$y_va), logloss(out$p_te,out$y_te)),
    brier   = c(brier(out$p_tr,out$y_tr),   brier(out$p_va,out$y_va),   brier(out$p_te,out$y_te)),
    ece     = c(ece(out$p_tr,out$y_tr),     ece(out$p_va,out$y_va),     ece(out$p_te,out$y_te)),
    algo    = out$algo,
    label   = out$label
  )
  
  make_preds_frame <- function(ids, y, p){
    tibble::tibble(game_id = ids$game_id, play_id = ids$play_id, nfl_id = ids$nfl_id,
                   y = as.integer(y), p_cal = as.numeric(p))
  }
  
  if (isTRUE(args$write_train_preds)) readr::write_csv(make_preds_frame(out$ids$tr, out$y_tr, out$p_tr), OUT_TRAIN)
  readr::write_csv(make_preds_frame(out$ids$va, out$y_va, out$p_va), OUT_VAL)
  readr::write_csv(make_preds_frame(out$ids$te, out$y_te, out$p_te), OUT_TEST)
  readr::write_csv(metrics, OUT_METRICS)
  
  saveRDS(out$model, OUT_MODEL)
  if (!is.null(out$calib)) saveRDS(out$calib, OUT_CALIB)
  if (!is.null(out$importance) && nrow(out$importance) > 0) readr::write_csv(out$importance, OUT_IMPORT)
  
  val_auc <- metrics$auc[metrics$split=="val"][1]
  status <- if (!is.na(val_auc) && val_auc >= args$auc_min_val) "PASS" else "FAIL"
  status_df <- data.frame(
    step = "18_retrain_model03_v2", label = out$label, suffix = suffix, status = status,
    val_auc = val_auc, elig_threshold = ELIG_THRESHOLD, lambda = lambda, seed = args$seed,
    algo = out$algo, timestamp = as.character(Sys.time())
  )
  data.table::fwrite(status_df, OUT_STATUS)
  
  rep_lines <- c(
    paste0("# Model 03 v2 — ", out$label, if (suffix=="") " (primary 1.5 yd)" else " (backup 1.0 yd)"),
    "", sprintf("Algorithm: %s", if (out$algo=="rf") "ranger random forest (500 trees)" else "XGBoost (binary:logistic)"),
    sprintf("Eligibility: %s", if (exists("use_numeric_elig") && use_numeric_elig) paste0(args$elig_col, ">=", format(ELIG_THRESHOLD)) else "eligible == TRUE"),
    if ("p_reach_blend" %in% feat_cols) sprintf("Reach blending: %s = %.3f*%s + %.3f*%s",
                                                "p_reach_blend", lambda, reach_cols[1], 1-lambda, reach_cols[2]) else "Reach blending: none",
    paste0("Features: ", paste(feat_cols, collapse=", ")), "",
    sprintf("Train rows: %d | Val rows: %d | Test rows: %d",
            sum(ds$split=="train"), sum(ds$split=="val"), sum(ds$split=="test")),
    "",
    "## Metrics (calibrated)",
    paste(capture.output(print(knitr::kable(metrics, digits = 4, format = "markdown"))), collapse = "\\n")
  )
  suppressWarnings(writeLines(rep_lines, OUT_REPORT))
  
  invisible(list(metrics = metrics, prefix = prefix, suffix = suffix, status = status, val_auc = val_auc))
}

# ----------------------------- RUN & SELECT -----------------------------
if (!all(c("contest_primary","contest_tight") %in% names(ds))) {
  stop("Dataset missing contest labels 'contest_primary' and/or 'contest_tight'", call. = FALSE)
}

algos <- strsplit(args$algos, ",")[[1]] |> tolower() |> trimws()
algos <- intersect(algos, c("rf","xgb"))
if (length(algos) == 0) stop("--algos must include at least one of {rf,xgb}", call. = FALSE)

runner <- function(a){ if (a == "rf") return(train_one_rf); if (a == "xgb") return(train_one_xgb); stop("Unknown algo: ", a) }

results <- list()
for (a in algos) {
  px <- paste0(args$prefix_base, "_", a)
  out_p <- runner(a)("contest_primary"); write_bundle(out_p, px, suffix = "")
  out_b <- runner(a)("contest_tight");  write_bundle(out_b, px, suffix = "_1p0")
  results[[a]] <- list(prefix = px,
                       val_auc_primary = auc_safe(out_p$y_va, out_p$p_va),
                       val_logloss_primary = logloss(out_p$p_va, out_p$y_va),
                       val_ece_primary = ece(out_p$p_va, out_p$y_va))
}

cmp <- bind_rows(lapply(names(results), function(a){
  tibble::tibble(algo = a,
                 prefix = results[[a]]$prefix,
                 val_auc = results[[a]]$val_auc_primary,
                 val_logloss = results[[a]]$val_logloss_primary,
                 val_ece = results[[a]]$val_ece_primary)
})) |> dplyr::mutate(pass = val_auc >= args$auc_min_val)

ord_all <- cmp |>
  dplyr::mutate(pref = dplyr::if_else(algo=="rf", 1L, 2L)) |>
  dplyr::arrange(dplyr::desc(val_auc), val_logloss, val_ece, pref)
ord_pass <- ord_all |> dplyr::filter(pass)

cmp_path_csv <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_comparison.csv"))
cmp_path_md  <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_comparison.md"))
readr::write_csv(cmp, cmp_path_csv)

if (nrow(ord_pass) == 0) {
  cmp_md <- c(
    paste0("# Model 03 v2 — RF vs XGB comparison"),
    "",
    paste0("Eligibility threshold: ", format(ELIG_THRESHOLD), " | lambda: ", format(lambda)),
    "",
    paste0("auc_min_val = ", args$auc_min_val, " — no algorithm met the threshold."),
    "",
    paste(capture.output(print(knitr::kable(cmp, digits = 4, format = "markdown"))), collapse = "\\n")
  )
  suppressWarnings(writeLines(cmp_md, cmp_path_md))
  stop("No algorithm met auc_min_val; not selecting a champion.", call. = FALSE)
}

best_auc <- max(ord_pass$val_auc, na.rm = TRUE)
auc_top <- ord_pass |> dplyr::filter(val_auc >= best_auc - EPS_AUC)
best_ll <- min(auc_top$val_logloss, na.rm = TRUE)
ll_top  <- auc_top |> dplyr::filter(val_logloss <= best_ll + EPS_LOGLOSS)
champ   <- ll_top  |> dplyr::arrange(val_ece, pref) |> dplyr::slice(1)
champ_prefix <- champ$prefix[1]

cmp_md <- c(
  paste0("# Model 03 v2 — RF vs XGB comparison"),
  "",
  paste0("Eligibility threshold: ", format(ELIG_THRESHOLD), " | lambda: ", format(lambda)),
  "",
  paste0("auc_min_val = ", args$auc_min_val, "; table includes pass/fail."),
  "",
  "Champion selection rule: higher val AUC, then lower val logloss, then lower ECE, then prefer RF (ties).",
  "",
  paste(capture.output(print(knitr::kable(cmp, digits = 4, format = "markdown"))), collapse = "\\n"),
  "",
  paste0("**Champion prefix:** `", champ_prefix, "`")
)
suppressWarnings(writeLines(cmp_md, cmp_path_md))

champ_path <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_champion.txt"))
writeLines(champ_prefix, champ_path)

run_summary <- list(
  timestamp = as.character(Sys.time()),
  prefix_base = args$prefix_base,
  champion_prefix = champ_prefix,
  auc_min_val = args$auc_min_val,
  ece_bins = args$ece_bins,
  knobs = list(ELIG_THRESHOLD = ELIG_THRESHOLD, lambda = lambda),
  algos_run = algos,
  comparison = cmp,
  files = list(dataset = PATH_DS, caps = PATH_CAPS, splits = PATH_MAP,
               dataset_md5 = hash_file(PATH_DS), caps_md5 = hash_file(PATH_CAPS), splits_md5 = hash_file(PATH_MAP)),
  rows = list(after_filter = nrow(ds),
              train = sum(ds$split=="train"), val = sum(ds$split=="val"), test = sum(ds$split=="test"))
)
jsonlite::write_json(run_summary, file.path(DIRS$artifacts, paste0(args$prefix_base, "_run_summary.json")), auto_unbox = TRUE, pretty = TRUE)

message(sprintf("Champion selected: %s", champ_prefix))

capture.output({ cat("\n==== SESSION INFO ====\n"); print(sessionInfo()) },
               file = file.path(DIRS$artifacts, paste0(args$prefix_base, "_session_info.txt")))

cat("\nAll done.\n")










#!/usr/bin/env Rscript

# =====================================================================
# 18a_m03_v2_verify_ready.R
# Verifies outputs from script 18, checks overfitting & calibration,
# and emits a single PASS/FAIL verdict to proceed to script 19.
# - Computes AUC/ECE directly from prediction files
# - Uses primary TEST preds, falls back to _1p0 if needed
# - Skips Train–Val gap if train preds aren't saved
# - Defaults tolerate base-rate shift (|intercept| <= 0.70)
# - Quiet pROC; robust report building
# =====================================================================

# --- bootstrap: auto-install required packages if missing ---------------------
.ensure_pkgs <- function(pkgs){
  missing <- setdiff(pkgs, rownames(installed.packages()))
  if (length(missing)) {
    repos <- getOption("repos")
    if (is.null(repos) || is.na(repos["CRAN"]) || repos["CRAN"] == "@CRAN@") {
      options(repos = c(CRAN = "https://cloud.r-project.org"))
    }
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(missing, dependencies = TRUE, quiet = TRUE), silent = TRUE)
  }
}
.ensure_pkgs(c("optparse","readr","dplyr","jsonlite","pROC","knitr","data.table","tibble"))
rm(.ensure_pkgs)
suppressPackageStartupMessages({
  library(optparse); library(readr); library(dplyr); library(jsonlite)
  library(pROC); library(knitr); library(data.table); library(tibble)
})

# ----------------------------- CLI ------------------------------------------
option_list <- list(
  make_option("--out_dir", type="character", default="artifacts",
              help="Artifacts directory (from script 18) [default %default]"),
  make_option("--prefix_base", type="character", default="v2_model03",
              help="Base prefix used by script 18 [default %default]"),
  # Overfitting/calibration gates (tunable)
  make_option("--auc_train_val_max_gap", type="double", default=0.05,
              help="Max allowed Train - Val AUC gap [default %default]"),
  make_option("--auc_val_test_max_drop", type="double", default=0.02,
              help="Max allowed Val - Test AUC drop [default %default]"),
  make_option("--ece_test_max", type="double", default=0.08,
              help="Max allowed ECE on Test [default %default]"),
  make_option("--cal_slope_min", type="double", default=0.80,
              help="Min acceptable calibration slope on Test [default %default]"),
  make_option("--cal_slope_max", type="double", default=1.20,
              help="Max acceptable calibration slope on Test [default %default]"),
  make_option("--cal_intercept_abs_max", type="double", default=0.70,
              help="Max |intercept| for calibration GLM on Test [default %default]"),
  make_option("--ece_bins", type="integer", default=15,
              help="Bins for Expected Calibration Error [default %default]"),
  make_option("--ci_level", type="double", default=0.95,
              help="Confidence level for AUC CI [default %default]")
)
args <- parse_args(OptionParser(option_list=option_list))

B <- function(...) file.path(normalizePath(getwd(), winslash="/", mustWork=FALSE), ...)
DIRS <- list(artifacts = B(args$out_dir)); dir.create(DIRS$artifacts, showWarnings = FALSE, recursive = TRUE)

# ----------------------------- Helpers ---------------------------------------
clip <- function(p, eps=1e-6) pmin(pmax(p, eps), 1-eps)
logloss <- function(p,y){ p <- clip(p); -mean(y*log(p)+(1-y)*log(1-p)) }
brier <- function(p,y) mean((p-y)^2)
ece <- function(p,y,bins=args$ece_bins){
  brks <- seq(0,1,length.out=bins+1)
  cutp <- cut(p, breaks=brks, include.lowest=TRUE)
  dt <- data.table(prob=p, y=y, bin=cutp)[, .(bin_pred=mean(prob), bin_obs=mean(y), n=.N), by=bin]
  dt[, w := n/sum(n)]; sum(dt$w * abs(dt$bin_pred - dt$bin_obs))
}
logit <- function(p) log(clip(p)/(1-clip(p)))
to_str <- function(x){
  if (is.null(x)) return("NA")
  if (is.logical(x) && length(x) == 1) return(as.character(x))
  if (length(x) > 1) {
    v <- suppressWarnings(as.numeric(x))
    if (any(is.na(v))) v <- x
    nm <- names(x)
    if (!is.null(nm)) {
      return(paste(paste0(nm, "=", signif(as.numeric(v), 6)), collapse = " | "))
    } else {
      return(paste(signif(as.numeric(v), 6), collapse = " | "))
    }
  }
  return(as.character(signif(suppressWarnings(as.numeric(x)), 6)))
}
must <- function(cond, msg){ if (!cond) stop(msg, call.=FALSE) }

# Metric computation from preds
compute_metrics <- function(df){
  if (is.null(df)) return(NULL)
  must(all(c("y") %in% names(df)), "Preds missing 'y' column.")
  pcol <- if ("p_cal" %in% names(df)) "p_cal" else if ("p" %in% names(df)) "p" else stop("Preds missing probability column ('p_cal' or 'p').")
  y <- as.integer(df$y); p <- as.numeric(df[[pcol]])
  roc_obj <- tryCatch(suppressMessages(suppressWarnings(
    pROC::roc(response = y, predictor = p, quiet = TRUE, levels = c(0,1), direction = "<")
  )), error = function(e) NULL)
  auc_val <- if (!is.null(roc_obj)) as.numeric(pROC::auc(roc_obj)) else NA_real_
  ci <- tryCatch(if (!is.null(roc_obj)) suppressMessages(suppressWarnings(pROC::ci.auc(roc_obj, conf.level = args$ci_level))) else NA, error=function(e) NA)
  list(
    n = length(y),
    auc = auc_val,
    auc_ci = if (is.numeric(ci)) as.numeric(ci) else c(NA_real_, NA_real_, NA_real_),
    logloss = logloss(p,y),
    brier = brier(p,y),
    ece = ece(p,y,bins=args$ece_bins),
    p = p, y = y
  )
}

# ----------------------------- Locate champion -------------------------------
champ_path <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_champion.txt"))
must(file.exists(champ_path), paste0("Missing champion file: ", champ_path, ". Run script 18 first."))
champ <- readLines(champ_path, warn = FALSE)[1]
must(nchar(champ) > 0, "Champion file was empty.")

# Input files for champion
f_val  <- file.path(DIRS$artifacts, paste0(champ, "_val_preds.csv"))
f_test <- file.path(DIRS$artifacts, paste0(champ, "_test_preds.csv"))
f_test_b <- file.path(DIRS$artifacts, paste0(champ, "_test_preds_1p0.csv"))
f_train <- file.path(DIRS$artifacts, paste0(champ, "_train_preds.csv"))

must(file.exists(f_val),  paste0("Missing validation preds: ", f_val))
if (!file.exists(f_test)) {
  must(file.exists(f_test_b), paste0("Missing test preds: ", f_test, " and backup: ", f_test_b))
  f_test <- f_test_b
}
pred_val   <- suppressMessages(readr::read_csv(f_val,  show_col_types = FALSE))
pred_test  <- suppressMessages(readr::read_csv(f_test, show_col_types = FALSE))
pred_train <- if (file.exists(f_train)) suppressMessages(readr::read_csv(f_train, show_col_types = FALSE)) else NULL

# ----------------------------- Compute metrics --------------------------------
m_val   <- compute_metrics(pred_val)
m_test  <- compute_metrics(pred_test)
m_train <- compute_metrics(pred_train)

# Calibration GLM on TEST
cal_glm <- suppressWarnings(glm(m_test$y ~ logit(m_test$p), family = binomial()))
cal_ok <- all(!is.na(coef(cal_glm)))
slope <- if (cal_ok) unname(coef(cal_glm)[["logit(m_test$p)"]]) else NA_real_
inter <- if (cal_ok) unname(coef(cal_glm)[["(Intercept)"]]) else NA_real_

# ----------------------------- Define checks ----------------------------------
checks <- list()

# Train - Val AUC gap (only if train preds exist)
if (!is.null(m_train)) {
  gap_train_val <- m_train$auc - m_val$auc
  checks$auc_train_val_gap <- list(
    pass = !is.na(gap_train_val) && gap_train_val <= args$auc_train_val_max_gap,
    value = gap_train_val,
    rule  = paste0("Train - Val AUC <= ", args$auc_train_val_max_gap),
    status = if (!is.na(gap_train_val) && gap_train_val <= args$auc_train_val_max_gap) "PASS" else "FAIL"
  )
} else {
  checks$auc_train_val_gap <- list(pass = NA, value = NA_real_,
                                   rule = paste0("Train - Val AUC <= ", args$auc_train_val_max_gap, " (SKIPPED: no train preds)"),
                                   status = "SKIPPED")
}

# Val - Test AUC drop
gap_val_test <- m_val$auc - m_test$auc
checks$auc_val_test_drop <- list(
  pass = !is.na(gap_val_test) && gap_val_test <= args$auc_val_test_max_drop,
  value = gap_val_test,
  rule  = paste0("Val - Test AUC <= ", args$auc_val_test_max_drop),
  status = if (!is.na(gap_val_test) && gap_val_test <= args$auc_val_test_max_drop) "PASS" else "FAIL"
)

# ECE on test
checks$ece_test <- list(
  pass = !is.na(m_test$ece) && m_test$ece <= args$ece_test_max,
  value = m_test$ece,
  rule  = paste0("ECE(Test) <= ", args$ece_test_max),
  status = if (!is.na(m_test$ece) && m_test$ece <= args$ece_test_max) "PASS" else "FAIL"
)

# Calibration GLM ok
checks$cal_glm_ok <- list(
  pass = cal_ok,
  value = as.logical(cal_ok),
  rule  = "Calibration GLM converged (no NA coefficients)",
  status = if (isTRUE(cal_ok)) "PASS" else "FAIL"
)

# Calibration slope range
checks$cal_slope_range <- list(
  pass = !is.na(slope) && slope >= args$cal_slope_min && slope <= args$cal_slope_max,
  value = slope,
  rule  = paste0("Calibration slope in [", args$cal_slope_min, ", ", args$cal_slope_max, "]"),
  status = if (!is.na(slope) && slope >= args$cal_slope_min && slope <= args$cal_slope_max) "PASS" else "FAIL"
)

# Calibration intercept bound (tolerant default = 0.70)
checks$cal_intercept_abs <- list(
  pass = !is.na(inter) && abs(inter) <= args$cal_intercept_abs_max,
  value = inter,
  rule  = paste0("|Calibration intercept| <= ", args$cal_intercept_abs_max),
  status = if (!is.na(inter) && abs(inter) <= args$cal_intercept_abs_max) "PASS" else "FAIL"
)

# Validation AUC within Test AUC CI
ci_lo <- m_test$auc_ci[1]; ci_hi <- m_test$auc_ci[3]
checks$val_in_test_CI <- list(
  pass = is.finite(ci_lo) && is.finite(ci_hi) && !is.na(m_val$auc) && (m_val$auc >= ci_lo && m_val$auc <= ci_hi),
  value = c(ci_lo=ci_lo, auc_val=m_val$auc, ci_hi=ci_hi),
  rule  = paste0("Val AUC within Test AUC ", as.integer(args$ci_level*100), "% CI"),
  status = if (is.finite(ci_lo) && is.finite(ci_hi) && !is.na(m_val$auc) && (m_val$auc >= ci_lo && m_val$auc <= ci_hi)) "PASS" else "FAIL"
)

# Verdict = all TRUE among non-NA passes
pass_vec <- vapply(checks, function(x) x$pass, logical(1))
verdict_pass <- all(pass_vec[!is.na(pass_vec)])

# ----------------------------- Write outputs ---------------------------------
prefix <- champ
report_md <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_18a_verification.md"))
verdict_json <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_18a_verdict.json"))
status_csv <- file.path(DIRS$artifacts, paste0(args$prefix_base, "_18a_status.csv"))
cal_curve_path <- file.path(DIRS$artifacts, paste0(prefix, "_calibration_curve_test.csv"))
readr::write_csv(data.frame(bin_pred = NA_real_, bin_obs = NA_real_, n = NA_integer_)[0,], cal_curve_path) # initialize

# Calibration curve on TEST
brks <- seq(0,1,length.out=args$ece_bins+1)
cutp <- cut(m_test$p, breaks=brks, include.lowest=TRUE)
cal_curve_test <- data.table(prob=m_test$p, y=m_test$y, bin=cutp)[, .(bin_pred=mean(prob), bin_obs=mean(y), n=.N), by=bin]
readr::write_csv(cal_curve_test, cal_curve_path)

# Status CSV
status_df <- tibble::tibble(
  step = "18a_verify_ready",
  prefix_base = args$prefix_base,
  champion_prefix = champ,
  test_file = basename(f_test),
  ready_for_19 = verdict_pass,
  n_val = m_val$n, n_test = m_test$n, n_train = if (is.null(m_train)) NA_integer_ else m_train$n,
  auc_train = if (is.null(m_train)) NA_real_ else m_train$auc,
  auc_val = m_val$auc, auc_test = m_test$auc,
  gap_train_val = if (is.null(m_train)) NA_real_ else (m_train$auc - m_val$auc),
  gap_val_test = m_val$auc - m_test$auc,
  ece_test = m_test$ece,
  cal_slope = slope, cal_intercept = inter,
  test_auc_ci_lo = ci_lo, test_auc_ci_hi = ci_hi,
  timestamp = as.character(Sys.time())
)
readr::write_csv(status_df, status_csv)

# JSON verdict
verdict <- list(
  ready_for_19 = verdict_pass,
  prefix_base = args$prefix_base,
  champion_prefix = champ,
  test_file_used = basename(f_test),
  rules = list(
    auc_train_val_max_gap = args$auc_train_val_max_gap,
    auc_val_test_max_drop = args$auc_val_test_max_drop,
    ece_test_max = args$ece_test_max,
    cal_slope_range = c(args$cal_slope_min, args$cal_slope_max),
    cal_intercept_abs_max = args$cal_intercept_abs_max,
    ci_level = args$ci_level
  ),
  values = list(
    n = list(val = m_val$n, test = m_test$n, train = if (is.null(m_train)) NA_integer_ else m_train$n),
    auc = list(train = if (is.null(m_train)) NA_real_ else m_train$auc, val = m_val$auc, test = m_test$auc),
    auc_ci_test = m_test$auc_ci,
    gaps = list(train_val = if (is.null(m_train)) NA_real_ else (m_train$auc - m_val$auc), val_test = m_val$auc - m_test$auc),
    ece_test = m_test$ece,
    cal = list(slope = slope, intercept = inter)
  ),
  checks = lapply(checks, function(x) list(status = x$status, pass = x$pass, value = x$value, rule = x$rule))
)
jsonlite::write_json(verdict, verdict_json, pretty = TRUE, auto_unbox = TRUE)

# Markdown report
tbl_metrics <- tibble::tibble(
  split = c("train","val","test"),
  n     = c(if (is.null(m_train)) NA_integer_ else m_train$n, m_val$n, m_test$n),
  auc   = c(if (is.null(m_train)) NA_real_ else m_train$auc, m_val$auc, m_test$auc),
  logloss = c(if (is.null(m_train)) NA_real_ else m_train$logloss, m_val$logloss, m_test$logloss),
  brier   = c(if (is.null(m_train)) NA_real_ else m_train$brier,   m_val$brier,   m_test$brier),
  ece     = c(if (is.null(m_train)) NA_real_ else m_train$ece,     m_val$ece,     m_test$ece)
)

tbl_checks <- tibble::tibble(
  check = names(checks),
  status = vapply(checks, function(x) x$status, character(1)),
  rule  = vapply(checks, function(x) x$rule, character(1)),
  value = vapply(checks, function(x) to_str(x$value), character(1))
)

rep_lines <- c(
  paste0("# Step 18a — Verification for prefix_base = `", args$prefix_base, "`"),
  "",
  paste0("**Champion:** `", champ, "`"),
  paste0("**Test file used:** `", basename(f_test), "`"),
  "",
  "## Headline metrics (computed from prediction files)",
  paste(capture.output(print(knitr::kable(tbl_metrics, digits = 4, format = "markdown"))), collapse = "\n"),
  "",
  "## Overfitting & calibration checks",
  paste(capture.output(print(knitr::kable(tbl_checks, digits = 4, format = "markdown"))), collapse = "\n"),
  "",
  paste0("**Verdict:** ", if (verdict_pass) "PASS — Ready for script 19." else "FAIL — Do not proceed to script 19."),
  "",
  "## Notes",
  "- Validation AUC is compared to the Test AUC confidence interval computed on the prediction file above.",
  "- The calibration intercept bound is tolerant by default (|b0| <= 0.70) to allow reasonable prevalence shifts.",
  "- If train predictions were not saved by step 18, the Train–Val gap check is marked SKIPPED."
)
suppressWarnings(writeLines(rep_lines, report_md))

message(if (verdict_pass) "READY: All checks passed. Proceed to script 19." else "STOP: One or more checks failed. See verification report.")
cat("\nAll done.\n")










#!/usr/bin/env Rscript

# =====================================================================
# 19_build_leverage_v2.R — rebuild the Model 04 leverage dataset (v2)
# Re-runs the Script 06 logic but:
#   • uses the v2 M03 champion models (primary 1.5 and backup 1.0)
#   • merges optional external enrichment from Script 16 as ext_* columns
#   • writes v2-prefixed artifacts
# =====================================================================

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
  library(rlang)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  artifacts = B("artifacts"),
  splits    = B("data","splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# -------------------- 1) Paths & helpers --------------------
PATH_DS   <- file.path(DIRS$artifacts, "model02_contest_dataset_final.csv")
PATH_CAPS <- file.path(DIRS$artifacts, "capability_profiles.csv")
PATH_MAP  <- file.path(DIRS$splits,   "plays_split_map.csv")
PATH_EXT  <- file.path(DIRS$artifacts, "external_features.csv")

# Guards
req <- function(path, name){ if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE) }
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

logit <- function(p){ p <- pmax(pmin(p, 1 - 1e-12), 1e-12); log(p/(1-p)) }

impute_with_medians <- function(df, meds_one_row){
  nm <- intersect(names(meds_one_row), names(df))
  for (v in nm) {
    suppressWarnings(df[[v]][!is.finite(df[[v]])] <- NA)
    df[[v]][is.na(df[[v]])] <- meds_one_row[[v]][1]
  }
  df
}

# -------------------- 2) Guard required files --------------------
req(PATH_DS,   basename(PATH_DS))
req(PATH_CAPS, basename(PATH_CAPS))
req(PATH_MAP,  basename(PATH_MAP))

# -------------------- 3) Load inputs --------------------
ds <- read_csv_clean(PATH_DS) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id))
  )

caps <- read_csv_clean(PATH_CAPS) |>
  transmute(
    nfl_id = suppressWarnings(as.integer(nfl_id)),
    v_max  = as.numeric(v_max),
    a_max  = as.numeric(a_max)
  ) |>
  distinct(nfl_id, .keep_all = TRUE)

splits <- read_csv_clean(PATH_MAP) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    split   = tolower(as.character(split))
  ) |>
  distinct(game_id, play_id, split)

# enforce split map
ds <- ds |>
  select(-any_of("split")) |>
  left_join(splits, by = c("game_id","play_id"))

# base checks
need_cols <- c("eligible","throwaway","p_reach_start","d_start","p_reach_max","d_min","contest_primary","contest_tight")
miss <- setdiff(need_cols, names(ds))
if (length(miss)) stop("Dataset missing expected columns: ", paste(miss, collapse=", "), call. = FALSE)

# filter eligible non-throwaway and join capabilities
ds_use <- ds |>
  filter(eligible, !throwaway) |>
  left_join(caps, by = "nfl_id")

# -------------------- 3b) Champion + features alignment (from v2 reports) --------------------
# v2 M03 champion finder
FIND_M03_V2 <- local({
  champion_txt <- file.path(DIRS$artifacts, "v2_model03_champion.txt")
  function(kind = c("primary","backup")) {
    kind <- match.arg(kind)
    pref <- if (file.exists(champion_txt)) trimws(readLines(champion_txt, warn = FALSE)[1]) else "v2_model03_xgb"
    list(
      model = file.path(DIRS$artifacts, paste0(pref, "_model_rds", if (kind=="backup") "_1p0" else "", ".rds")),
      calib = file.path(DIRS$artifacts, paste0(pref, "_calibration_glm", if (kind=="backup") "_1p0" else "", ".rds"))
    )
  }
})

# parse reach blending from champion report
parse_blend <- function(prefix){
  rep_path <- file.path(DIRS$artifacts, paste0(prefix, "_report.md"))
  if (!file.exists(rep_path)) return(NULL)
  lines <- readLines(rep_path, warn = FALSE)
  ix <- grep("^Reach blending:", lines)
  if (!length(ix)) return(NULL)
  line <- lines[ix[1]]
  if (grepl("none", line, ignore.case = TRUE)) return(NULL)
  # IMPORTANT: escape regex metacharacters in R strings -> \\* and \\+
  m <- regexec("p_reach_blend = ([0-9.]+)\\*([A-Za-z0-9_]+) \\+ ([0-9.]+)\\*([A-Za-z0-9_]+)", line)
  g <- regmatches(line, m)[[1]]
  if (length(g) == 5) return(list(a = as.numeric(g[2]), col1 = g[3], b = as.numeric(g[4]), col2 = g[5]))
  NULL
}

champion_txt <- file.path(DIRS$artifacts, "v2_model03_champion.txt")
champ_pref <- if (file.exists(champion_txt)) trimws(readLines(champion_txt, warn=FALSE)[1]) else "v2_model03_xgb"
blend <- parse_blend(champ_pref)

# if champion used blending, create p_reach_blend in BOTH ds and ds_use
if (!is.null(blend)) {
  if (all(c(blend$col1, blend$col2) %in% names(ds))) {
    ds <- ds |> mutate(p_reach_blend = blend$a*.data[[blend$col1]] + blend$b*.data[[blend$col2]])
  }
  if (all(c(blend$col1, blend$col2) %in% names(ds_use))) {
    ds_use <- ds_use |> mutate(p_reach_blend = blend$a*.data[[blend$col1]] + blend$b*.data[[blend$col2]])
  }
}

# -------------------- 4) Load v2 M03 models --------------------
m03p <- FIND_M03_V2("primary"); req(m03p$model, basename(m03p$model))
m03b <- FIND_M03_V2("backup");  req(m03b$model,  basename(m03b$model))

cal_primary <- if (file.exists(m03p$calib)) readRDS(m03p$calib) else NULL
cal_backup  <- if (file.exists(m03b$calib)) readRDS(m03b$calib) else NULL

m03_primary <- readRDS(m03p$model)
m03_backup  <- readRDS(m03b$model)

# Recreate v2 feature set exactly like Script 18
base_feats <- c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max")
feat_cols <- unique(c(base_feats, intersect("p_reach_blend", names(ds_use))))

# Compute medians on TRAIN split using the post-join ds_use frame
if (!any(ds_use$split == "train", na.rm = TRUE)) stop("No TRAIN rows present to compute medians.")
meds_row <- ds_use |>
  filter(split == "train") |>
  summarise(across(all_of(feat_cols), ~ suppressWarnings(median(as.numeric(.x), na.rm = TRUE))))

unwrap_predictor <- function(obj) { if (is.list(obj) && "model" %in% names(obj)) obj$model else obj }

predict_prob_yes <- function(model, newdata){
  # ensure numeric matrix where needed
  as_num_df <- function(df){
    df <- df[, feat_cols, drop = FALSE]
    for (v in feat_cols) df[[v]] <- suppressWarnings(as.numeric(df[[v]]))
    df
  }
  # ranger
  if (inherits(model, "ranger")) {
    pr <- predict(model, data = as_num_df(newdata), type = "response")
    if (!is.null(pr$predictions)) {
      if (is.matrix(pr$predictions) && "yes" %in% colnames(pr$predictions)) return(as.numeric(pr$predictions[,"yes"]))
      if (is.vector(pr$predictions)) return(as.numeric(pr$predictions))
    }
  }
  # xgboost
  if (inherits(model, "xgb.Booster")) {
    if (!requireNamespace("xgboost", quietly = TRUE)) stop("xgboost package not available")
    Xdf <- as_num_df(newdata)
    Xm  <- as.matrix(Xdf)
    colnames(Xm) <- feat_cols
    dmat <- xgboost::xgb.DMatrix(Xm)
    return(as.numeric(predict(model, dmat)))
  }
  # caret::train
  if ("train" %in% class(model)) {
    pr <- predict(model, newdata = as_num_df(newdata), type = "prob")
    if (is.data.frame(pr) && "yes" %in% names(pr)) return(as.numeric(pr$yes))
  }
  # glm-like fallback
  pr <- tryCatch(predict(model, newdata = as_num_df(newdata), type = "response"), error = function(e) NULL)
  if (!is.null(pr)) return(as.numeric(pr))
  stop("Unsupported model class for prediction: ", paste(class(model), collapse=","))
}

predict_calibrated <- function(model_obj, calib_glm, df_features){
  mdl <- unwrap_predictor(model_obj)
  X <- df_features[, feat_cols, drop = FALSE]
  # impute with TRAIN medians
  for (v in feat_cols) {
    suppressWarnings(X[[v]][!is.finite(as.numeric(X[[v]]))] <- NA)
    X[[v]][is.na(X[[v]])] <- meds_row[[v]][1]
  }
  p_raw <- predict_prob_yes(mdl, X)
  p_cal <- if (!is.null(calib_glm)) as.numeric(predict(calib_glm, newdata = data.frame(l = logit(p_raw)), type = "response")) else p_raw
  list(raw = p_raw, cal = p_cal)
}

# -------------------- 5) Predict p03 (primary 1.5 / backup 1.0) --------------------
X_keys <- ds_use |> select(game_id, play_id, nfl_id, split)
res1 <- predict_calibrated(m03_primary, cal_primary, ds_use)
res0 <- predict_calibrated(m03_backup,  cal_backup,  ds_use)

pred <- X_keys |>
  mutate(
    p03_primary_raw = res1$raw,
    p03_primary     = res1$cal,
    p03_1p0_raw     = res0$raw,
    p03_1p0         = res0$cal
  )

# -------------------- 6) Join + engineer leverage features --------------------
lev <- ds_use |>
  select(game_id, play_id, nfl_id, split, v_max, a_max,
         p_reach_start, d_start, p_reach_max, d_min, d_arrival,
         contest_primary, contest_tight) |>
  left_join(pred, by = c("game_id","play_id","nfl_id","split"))

lev <- lev |>
  group_by(game_id, play_id) |>
  mutate(
    n_defenders_play = n(),
    rank_d_start        = rank(d_start, ties.method = "min"),         # smaller is better
    rank_d_min          = rank(d_min,   ties.method = "min"),         # smaller is better
    rank_v_max          = rank(-v_max,  ties.method = "min"),         # larger is better
    rank_p03_primary    = rank(-p03_primary, ties.method = "min"),    # larger is better
    rank_p03_1p0        = rank(-p03_1p0,     ties.method = "min"),    # larger is better
    is_nearest_start    = as.integer(rank_d_start == 1),
    is_fastest          = as.integer(rank_v_max   == 1),
    is_highest_p03      = as.integer(rank_p03_primary == 1),
    # Normalized ranks [0,1]
    d_start_rank_norm   = (max(rank_d_start) - rank_d_start) / (max(rank_d_start) - 1 + 1e-9),
    d_min_rank_norm     = (max(rank_d_min)   - rank_d_min)   / (max(rank_d_min)   - 1 + 1e-9),
    v_max_rank_norm     = (max(rank_v_max)   - rank_v_max)   / (max(rank_v_max)   - 1 + 1e-9),
    p03_primary_norm    = (max(rank_p03_primary) - rank_p03_primary) / (max(rank_p03_primary) - 1 + 1e-9),
    p03_1p0_norm        = (max(rank_p03_1p0)     - rank_p03_1p0)     / (max(rank_p03_1p0)     - 1 + 1e-9)
  ) |>
  ungroup()

# -------------------- 7) Optional external enrichment (Script 16) --------------------
lev_ext <- lev
ext_present <- file.exists(PATH_EXT)
if (ext_present) {
  ext <- read_csv_clean(PATH_EXT) |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id))
    )
  key_cols <- c("game_id","play_id","nfl_id")
  other <- setdiff(names(ext), key_cols)
  names(ext)[match(other, names(ext))] <- paste0("ext_", other)
  lev_ext <- lev |>
    left_join(ext, by = c("game_id","play_id","nfl_id"))
}

# -------------------- 8) Write outputs (v2-prefixed) --------------------
lev_out <- lev_ext |>
  select(
    game_id, play_id, nfl_id, split,
    v_max, a_max,
    p_reach_start, d_start, p_reach_max, d_min,
    p03_primary_raw, p03_primary, p03_1p0_raw, p03_1p0,
    d_arrival, contest_primary, contest_tight,
    n_defenders_play,
    rank_d_start, rank_d_min, rank_v_max, rank_p03_primary, rank_p03_1p0,
    is_nearest_start, is_fastest, is_highest_p03,
    d_start_rank_norm, d_min_rank_norm, v_max_rank_norm, p03_primary_norm, p03_1p0_norm,
    starts_with("ext_")
  )

OUT_DATA          <- file.path(DIRS$artifacts, "v2_model04_leverage_dataset.csv")
OUT_METRICS       <- file.path(DIRS$artifacts, "v2_model04_build_metrics.csv")
OUT_METRICS_SPLIT <- file.path(DIRS$artifacts, "v2_model04_build_metrics_by_split.csv")
OUT_REPORT        <- file.path(DIRS$artifacts, "v2_model04_build_report.md")
OUT_STATUS_CSV    <- file.path(DIRS$artifacts, "v2_model04_build_verification_status.csv")
OUT_STATUS_MD     <- file.path(DIRS$artifacts, "v2_model04_build_verification_status.md")

readr::write_csv(lev_out, OUT_DATA)

plays_total <- n_distinct(paste(lev_out$game_id, lev_out$play_id))
rows_total  <- nrow(lev_out)
def_total   <- n_distinct(lev_out$nfl_id)

cov_p_primary <- mean(!is.na(lev_out$p03_primary))
cov_p_1p0     <- mean(!is.na(lev_out$p03_1p0))

by_split <- lev_out |>
  group_by(split) |>
  summarise(
    rows = n(),
    plays = n_distinct(paste(game_id, play_id)),
    defenders = n_distinct(nfl_id),
    p_primary_na = mean(is.na(p03_primary)),
    p_1p0_na     = mean(is.na(p03_1p0)),
    .groups = "drop"
  )

metrics <- tibble(
  metric = c("rows_total","plays_total","defenders_total","coverage_p03_primary","coverage_p03_1p0","external_features_joined"),
  value  = c(rows_total, plays_total, def_total, cov_p_primary, cov_p_1p0, as.numeric(ext_present))
)
readr::write_csv(metrics, OUT_METRICS)
readr::write_csv(by_split, OUT_METRICS_SPLIT)

rep <- c(
  "# Model 04 — Leverage dataset (v2 build)",
  "",
  sprintf("- Rows: %s | Plays: %s | Defenders: %s", comma(rows_total), comma(plays_total), comma(def_total)),
  sprintf("- Coverage: p03_primary=%.4f | p03_1p0=%.4f", cov_p_primary, cov_p_1p0),
  if (ext_present) "- External enrichment merged (columns prefixed ext_)" else "- External enrichment not found; skipped merge.",
  "",
  "## Files",
  paste0("- ", OUT_DATA),
  paste0("- ", OUT_METRICS),
  paste0("- ", OUT_METRICS_SPLIT)
)
writeLines(rep, OUT_REPORT, useBytes = TRUE)

message(
  "Wrote:",
  "\n  - ", OUT_DATA,
  "\n  - ", OUT_METRICS,
  "\n  - ", OUT_METRICS_SPLIT,
  "\n  - ", OUT_REPORT
)

# -------------------- 9) Verification checks --------------------
.chk_pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
.md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

dup_keys <- lev_out |> dplyr::count(game_id, play_id, nfl_id, name="n") |> dplyr::filter(n != 1)
na_primary <- mean(is.na(lev_out$p03_primary))
na_backup  <- mean(is.na(lev_out$p03_1p0))
split_bad  <- setdiff(unique(tolower(lev_out$split)), c("train","val","test"))
plays_cov  <- lev_out |> dplyr::count(game_id, play_id, name="n_def")
min_def    <- if (nrow(plays_cov)) min(plays_cov$n_def) else 0

lev_checks <- tibble::tibble(
  check = c(
    "has_rows",
    "unique_(game_id,play_id,nfl_id)",
    "split_values_in_{train,val,test}",
    "no_play_has_zero_defenders",
    "p03_primary_na_rate<=0.01",
    "p03_1p0_na_rate<=0.01"
  ),
  status = c(
    .chk_pass(nrow(lev_out) > 0),
    .chk_pass(nrow(dup_keys) == 0),
    .chk_pass(length(split_bad) == 0),
    .chk_pass(min_def >= 1),
    .chk_pass(na_primary <= 0.01),
    .chk_pass(na_backup  <= 0.01)
  ),
  details = c(
    paste0("rows=", nrow(lev_out)),
    if (nrow(dup_keys)) paste0("bad_rows=", nrow(dup_keys)) else "OK",
    if (length(split_bad)) paste("bad=", paste(split_bad, collapse=",")) else "OK",
    paste0("min_defenders_per_play=", min_def),
    sprintf("na_primary=%.4f", na_primary),
    sprintf("na_1p0=%.4f", na_backup)
  )
)

readr::write_csv(lev_checks, OUT_STATUS_CSV)
dash <- c("# Model 04 leverage verification (v2)", "", .md_table(lev_checks))
writeLines(dash, OUT_STATUS_MD, useBytes = TRUE)

print(lev_checks)
if (any(lev_checks$status == "FAIL")) stop("Model 04 leverage verification failed. See artifacts/v2_model04_build_verification_status.*", call. = FALSE)
message("Leverage v2 dataset verification: all critical checks passed.")










#!/usr/bin/env Rscript

# =====================================================================
# 20_train_calibrate_model04_v2.R — Train + calibrate M04 on v2 leverage
# =====================================================================

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(pROC)
  library(scales)
  library(rlang)
})

SCRIPT_VERSION <- "20_v2.4"
set.seed(42)

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# -------------------- 1) Paths & helpers --------------------
PATH_LEV <- file.path(DIRS$artifacts, "v2_model04_leverage_dataset.csv")

OUT_MODEL_RDS     <- file.path(DIRS$artifacts, "v2_model04_model_rds.rds")
OUT_CALIB_RDS     <- file.path(DIRS$artifacts, "v2_model04_calibration_glm.rds")
OUT_VAL_PREDS     <- file.path(DIRS$artifacts, "v2_model04_val_preds.csv")
OUT_TEST_PREDS    <- file.path(DIRS$artifacts, "v2_model04_test_preds.csv")
OUT_METRICS       <- file.path(DIRS$artifacts, "v2_model04_metrics.csv")
OUT_CALIB_COMPARE <- file.path(DIRS$artifacts, "v2_model04_calibration_compare.csv")
OUT_CALIB_METHOD  <- file.path(DIRS$artifacts, "v2_model04_calibration_method.txt")
OUT_STATUS_CSV    <- file.path(DIRS$artifacts, "v2_model04_status.csv")
OUT_STATUS_MD     <- file.path(DIRS$artifacts, "v2_model04_status.md")
OUT_REPORT_MD     <- file.path(DIRS$artifacts, "v2_model04_training_report.md")

req <- function(path, name){ if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE) }
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

logit <- function(p){ p <- pmax(pmin(p, 1 - 1e-12), 1e-12); log(p/(1-p)) }
safe_as_numeric <- function(x) suppressWarnings(as.numeric(x))

safe_auc <- function(y, p) {
  tryCatch({
    r <- pROC::roc(response = y, predictor = p, quiet = TRUE)
    as.numeric(pROC::auc(r))
  }, error = function(e) NA_real_)
}

# Ensure package is installed and attached, else STOP
ensure_pkg_attached <- function(pkg) {
  if (!requireNamespace(pkg, quietly = TRUE)) {
    message("Installing required package: ", pkg)
    ok <- FALSE
    # Try binary first, then source
    tryCatch({ install.packages(pkg, quiet = TRUE); ok <<- TRUE }, error = function(e) {})
    if (!requireNamespace(pkg, quietly = TRUE)) {
      tryCatch({ install.packages(pkg, type = "source", quiet = TRUE); ok <<- TRUE }, error = function(e) {})
    }
  }
  if (!requireNamespace(pkg, quietly = TRUE)) {
    stop("Required package '", pkg, "' not available after attempted install. Install manually and re-run.", call. = FALSE)
  }
  suppressPackageStartupMessages(require(pkg, character.only = TRUE))
}

to_label01 <- function(x) {
  if (is.logical(x)) return(as.integer(x))
  if (is.numeric(x)) return(as.integer(x > 0))
  lx <- tolower(as.character(x))
  as.integer(lx %in% c("yes", "1", "true", "y"))
}

bin_metrics <- function(y, p, split_name) {
  y <- as.integer(y); p <- as.numeric(p)
  th <- 0.5
  pred <- as.integer(p >= th)
  tp <- sum(pred==1 & y==1); tn <- sum(pred==0 & y==0)
  fp <- sum(pred==1 & y==0); fn <- sum(pred==0 & y==1)
  tibble(
    split = split_name,
    auc = safe_auc(y, p),
    accuracy = (tp+tn)/length(y),
    precision = ifelse(tp+fp==0, NA_real_, tp/(tp+fp)),
    recall = ifelse(tp+fn==0, NA_real_, tp/(tp+fn)),
    f1 = {prec <- ifelse(tp+fp==0, NA_real_, tp/(tp+fp)); rec <- ifelse(tp+fn==0, NA_real_, tp/(tp+fn));
    ifelse(is.na(prec)|is.na(rec)|(prec+rec)==0, NA_real_, 2*prec*rec/(prec+rec))},
    prevalence = mean(y)
  )
}

brier <- function(y, p) mean((as.numeric(y) - as.numeric(p))^2)

# -------------------- 2) Load leverage dataset --------------------
req(PATH_LEV, basename(PATH_LEV))
lev <- read_csv_clean(PATH_LEV) |>
  mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    nfl_id  = suppressWarnings(as.integer(nfl_id)),
    split   = tolower(as.character(split))
  )

need_cols <- c("contest_primary","p03_primary","p03_1p0")
miss <- setdiff(need_cols, names(lev))
if (length(miss)) stop("Leverage dataset missing expected columns: ", paste(miss, collapse=", "), call. = FALSE)

# -------------------- 3) Features & label --------------------
label_col <- "contest_primary"
exclude_cols <- c("game_id","play_id","nfl_id","split","contest_tight",label_col)
cand <- setdiff(names(lev), exclude_cols)

num_cols <- cand[ purrr::map_lgl(lev[cand], ~ is.numeric(.x) || all(suppressWarnings(!is.na(as.numeric(head(.x, 100))))) ) ]
num_cols <- num_cols[ purrr::map_lgl(lev[num_cols], ~ sum(!is.na(.x)) > 0) ]
lev[num_cols] <- lapply(lev[num_cols], safe_as_numeric)

lev <- lev |> mutate(y = to_label01(.data[[label_col]]))
if (any(is.na(lev$y))) stop("Label conversion produced NA for contest_primary.", call. = FALSE)

train_idx <- which(lev$split == "train")
val_idx   <- which(lev$split == "val")
test_idx  <- which(lev$split == "test")
if (!length(train_idx) || !length(val_idx) || !length(test_idx)) stop("Need train/val/test splits.", call. = FALSE)

meds_row <- lev[train_idx, num_cols, drop = FALSE] |>
  summarise(across(everything(), ~ suppressWarnings(median(as.numeric(.x), na.rm = TRUE))))

impute_df <- function(df) {
  X <- df[, num_cols, drop = FALSE]
  for (v in num_cols) {
    suppressWarnings(X[[v]][!is.finite(as.numeric(X[[v]]))] <- NA)
    X[[v]][is.na(X[[v]])] <- meds_row[[v]][1]
  }
  X
}

Xtr <- impute_df(lev[train_idx, , drop = FALSE])
Xva <- impute_df(lev[val_idx, , drop = FALSE])
Xte <- impute_df(lev[test_idx, , drop = FALSE])
ytr <- lev$y[train_idx]; yva <- lev$y[val_idx]; yte <- lev$y[test_idx]

# -------------------- 4) Train M04 (xgboost primary; ranger fallback) --------------------
model_obj <- NULL; algo <- NULL

if (requireNamespace("xgboost", quietly = TRUE)) {
  library(xgboost)
  dtr <- xgb.DMatrix(as.matrix(Xtr), label = ytr)
  dva <- xgb.DMatrix(as.matrix(Xva), label = yva)
  dte <- xgb.DMatrix(as.matrix(Xte), label = yte)
  
  params <- list(objective="binary:logistic", eval_metric=c("logloss","auc"),
                 max_depth=5, eta=0.05, subsample=0.8, colsample_bytree=0.8, min_child_weight=1)
  m <- xgb.train(params=params, data=dtr, nrounds=1000,
                 watchlist=list(train=dtr, val=dva), early_stopping_rounds=50, verbose=0)
  
  p_tr_raw <- as.numeric(predict(m, dtr))
  p_va_raw <- as.numeric(predict(m, dva))
  p_te_raw <- as.numeric(predict(m, dte))
  model_obj <- m; algo <- "xgb"
} else if (requireNamespace("ranger", quietly = TRUE)) {
  library(ranger)
  df_tr <- cbind.data.frame(Xtr, y = factor(ytr, levels=c(0,1), labels=c("no","yes")))
  m <- ranger::ranger(y ~ ., data=df_tr, probability=TRUE, num.trees=1000,
                      mtry=max(2, floor(sqrt(ncol(Xtr)))), min.node.size=5,
                      respect.unordered.factors="partition", seed=42)
  p_tr_raw <- { pv <- predict(m, data=Xtr)$predictions; if (is.matrix(pv)) pv[,"yes"] else as.numeric(pv) }
  p_va_raw <- { pv <- predict(m, data=Xva)$predictions; if (is.matrix(pv)) pv[,"yes"] else as.numeric(pv) }
  p_te_raw <- { pv <- predict(m, data=Xte)$predictions; if (is.matrix(pv)) pv[,"yes"] else as.numeric(pv) }
  model_obj <- m; algo <- "ranger"
} else {
  stop("Neither xgboost nor ranger is available. Install one of them.", call. = FALSE)
}

# -------------------- 5) Calibration on validation (compare methods) --------------------
# Ensure glmnet is installed AND attached before use
ensure_pkg_attached("glmnet")
glmnet_ver <- as.character(utils::packageVersion("glmnet"))

fit_calibrators <- function(y_val, p_raw_val){
  yv <- as.integer(y_val); pr <- as.numeric(p_raw_val)
  cands <- list()
  
  # 5.1 Platt GLM
  glm_obj <- tryCatch(suppressWarnings(glm(yv ~ logit(pr), family = binomial())), error = function(e) NULL)
  if (!is.null(glm_obj) && isTRUE(glm_obj$converged) &&
      all(is.finite(coef(glm_obj))) && all(abs(coef(glm_obj)) < 50)) {
    pred <- function(p){ as.numeric(predict(glm_obj, newdata = data.frame(`logit(pr)` = logit(p)), type = "response")) }
    cands[["platt_glm"]] <- list(predict = pred, model = glm_obj)
  }
  
  # 5.2 Ridge-Platt via glmnet (pad to >=2 cols for safety)
  {
    z  <- logit(pr)
    X  <- matrix(z, ncol = 1)
    pf <- 1
    if (ncol(X) < 2) { X <- cbind(z, z*0); pf <- c(1,0) }
    fit <- glmnet::cv.glmnet(X, yv, family="binomial", alpha=0, nfolds=5,
                             standardize=TRUE, intercept=TRUE, penalty.factor=pf)
    pred <- function(p){
      znew <- logit(p)
      Xnew <- if (length(pf)==1) matrix(znew, ncol = 1) else cbind(znew, znew*0)
      as.numeric(predict(fit, newx = Xnew, type = "response", s = "lambda.min"))
    }
    cands[["platt_ridge_glmnet"]] <- list(predict = pred, model = fit)
  }
  
  # 5.3 Isotonic
  ord <- order(pr); xiso <- as.numeric(pr[ord]); yiso <- as.numeric(yv[ord])
  iso <- stats::isoreg(xiso, yiso)
  yfit_ord <- iso$yf
  pred_iso <- function(p){ approx(x = xiso, y = yfit_ord, xout = as.numeric(p), ties = "ordered", rule = 2)$y }
  cands[["isotonic"]] <- list(predict = pred_iso, model = iso)
  
  # Score on validation
  rows <- lapply(names(cands), function(m){
    pv <- cands[[m]]$predict(pr)
    tibble(
      method = m,
      brier  = brier(yv, pv),
      auc    = safe_auc(yv, pv),
      logloss= { eps <- 1e-12; p2 <- pmin(pmax(pv, eps), 1 - eps); -mean(yv*log(p2) + (1 - yv)*log(1 - p2)) }
    )
  })
  cmp <- bind_rows(rows) |> arrange(brier, desc(auc))
  list(best = cmp$method[1], table = cmp, cands = cands)
}

comp <- fit_calibrators(yva, p_va_raw)

calib_method <- comp$best

message("Calibration chosen: ", calib_method)
message("glmnet version: ", glmnet_ver)
calib_pred   <- comp$cands[[calib_method]]$predict
p_tr <- calib_pred(p_tr_raw)
p_va <- calib_pred(p_va_raw)
p_te <- calib_pred(p_te_raw)

readr::write_csv(comp$table, OUT_CALIB_COMPARE)
writeLines(calib_method, OUT_CALIB_METHOD, useBytes = TRUE)

if (calib_method == "platt_glm") {
  saveRDS(comp$cands[["platt_glm"]]$model, OUT_CALIB_RDS)
} else {
  if (file.exists(OUT_CALIB_RDS)) tryCatch(file.remove(OUT_CALIB_RDS), error = function(e) NULL)
  saveRDS(list(method = calib_method), OUT_CALIB_RDS)
}

# -------------------- 6) Metrics --------------------
m_tr <- bin_metrics(ytr, p_tr, "train")
m_va <- bin_metrics(yva, p_va, "val")
m_te <- bin_metrics(yte, p_te, "test")
metrics_all <- bind_rows(m_tr, m_va, m_te)
readr::write_csv(metrics_all, OUT_METRICS)

# -------------------- 7) Save predictions --------------------
keys_tr <- lev[train_idx, c("game_id","play_id","nfl_id","split")]
keys_va <- lev[val_idx,   c("game_id","play_id","nfl_id","split")]
keys_te <- lev[test_idx,  c("game_id","play_id","nfl_id","split")]

val_preds  <- bind_cols(keys_va, tibble(y = yva, p_raw = p_va_raw, p_cal = p_va))
test_preds <- bind_cols(keys_te, tibble(y = yte, p_raw = p_te_raw, p_cal = p_te))
readr::write_csv(val_preds,  OUT_VAL_PREDS)
readr::write_csv(test_preds, OUT_TEST_PREDS)

# -------------------- 8) Save model bundle --------------------
imp <- NULL
if (identical(algo, "xgb")) {
  imp <- tryCatch({
    xm <- xgboost::xgb.importance(model = model_obj)
    xm |> as_tibble() |> select(Feature, Gain, Cover, Frequency)
  }, error = function(e) NULL)
}

bundle <- list(
  version   = "v2",
  model     = model_obj,
  features  = num_cols,
  medians   = meds_row,
  label     = label_col,
  algo      = algo,
  trained_at= as.character(Sys.time()),
  importance= imp
)
saveRDS(bundle, OUT_MODEL_RDS)

# -------------------- 9) Status + report --------------------
has_ext <- any(startsWith(num_cols, "ext_"))
n_ext   <- sum(startsWith(num_cols, "ext_"))

status <- tibble(
  item = c("script_version","algo","calibration_method","glmnet_version","n_features","n_ext_features","train_rows","val_rows","test_rows",
           "auc_train","auc_val","auc_test"),
  value = c(SCRIPT_VERSION, algo, calib_method, glmnet_ver, length(num_cols), n_ext,
            length(train_idx), length(val_idx), length(test_idx),
            m_tr$auc, m_va$auc, m_te$auc)
)
readr::write_csv(status, OUT_STATUS_CSV)

rep <- c(
  "# Model 04 v2 — Training report",
  "",
  paste0("- Script: ", SCRIPT_VERSION),
  paste0("- Algorithm: ", algo),
  paste0("- Calibration: ", calib_method, " (glmnet ", glmnet_ver, ")"),
  paste0("- Features: ", length(num_cols), " (ext_* present: ", has_ext, ", count: ", n_ext, ")"),
  paste0("- Rows: train=", length(train_idx), " | val=", length(val_idx), " | test=", length(test_idx)),
  "",
  "## Metrics",
  paste0("- AUC: train=", sprintf("%.4f", m_tr$auc),
         " | val=", sprintf("%.4f", m_va$auc),
         " | test=", sprintf("%.4f", m_te$auc)),
  paste0("- F1 (0.5): train=", sprintf("%.4f", m_tr$f1),
         " | val=", sprintf("%.4f", m_va$f1),
         " | test=", sprintf("%.4f", m_te$f1)),
  "",
  "## Files",
  paste0("- ", OUT_MODEL_RDS),
  paste0("- ", OUT_CALIB_RDS, if (!file.exists(OUT_CALIB_RDS)) " (not GLM; see calibration_method.txt)" else ""),
  paste0("- ", OUT_VAL_PREDS),
  paste0("- ", OUT_TEST_PREDS),
  paste0("- ", OUT_METRICS),
  paste0("- ", OUT_CALIB_COMPARE),
  paste0("- ", OUT_CALIB_METHOD)
)
writeLines(rep, OUT_REPORT_MD, useBytes = TRUE)

# CI-like checks
aok_has_rows <- nrow(lev) > 0
aok_splits   <- all(sort(unique(lev$split)) %in% c("train","val","test"))
aok_auc      <- isTRUE(m_va$auc > 0.5)

status_checks <- tibble::tibble(
  check = c("has_rows","splits_ok","auc_val_gt_0.5"),
  status = c(if (aok_has_rows) "PASS" else "FAIL",
             if (aok_splits) "PASS" else "FAIL",
             if (aok_auc) "PASS" else "WARN"),
  details = c(paste0("rows=", nrow(lev)),
              paste("splits=", paste(sort(unique(lev$split)), collapse=",")),
              paste0("auc_val=", sprintf("%.4f", m_va$auc)))
)
readr::write_csv(status_checks, OUT_STATUS_CSV, append = TRUE)

dash <- c("# Model 04 v2 — Status", "", paste(capture.output(print(status_checks)), collapse = "\n"))
writeLines(dash, OUT_STATUS_MD, useBytes = TRUE)

message("Wrote:\n  - ", OUT_MODEL_RDS,
        "\n  - ", OUT_CALIB_RDS,
        "\n  - ", OUT_VAL_PREDS,
        "\n  - ", OUT_TEST_PREDS,
        "\n  - ", OUT_METRICS,
        "\n  - ", OUT_CALIB_COMPARE,
        "\n  - ", OUT_CALIB_METHOD,
        "\n  - ", OUT_STATUS_CSV,
        "\n  - ", OUT_STATUS_MD,
        "\n  - ", OUT_REPORT_MD)










#!/usr/bin/env Rscript
# =====================================================================
# 20a_verify_model04_v2.R — Unified verifier for Script 20 (M04 v2)
# =====================================================================

options(repos = c(CRAN = "https://cloud.r-project.org"),
        timeout = max(600, getOption("timeout", 60)),
        dplyr.summarise.inform = FALSE,
        stringsAsFactors = FALSE)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(pROC)
  library(digest)
})

set.seed(42)

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

req <- function(path, name){ if (!file.exists(path)) stop("Missing required file: ", name, " at ", path, call. = FALSE) }
read_csv_clean <- function(p) readr::read_csv(p, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()

brier <- function(y, p) mean((as.numeric(y) - as.numeric(p))^2)
logloss_vec <- function(y,p){ eps <- 1e-12; p2 <- pmin(pmax(p,eps),1-eps); -mean(y*log(p2)+(1-y)*log(1-p2)) }
safe_auc <- function(y,p) tryCatch(as.numeric(pROC::auc(y, p)), error = function(e) NA_real_)
pass <- function(x) if (isTRUE(x)) "PASS" else if (is.na(x)) "N/A" else "FAIL"

MODE <- tolower(Sys.getenv("VERIFY_MODE","deep"))

# -------------------- 1) Paths --------------------
PATH_LEV           <- file.path(DIRS$artifacts, "v2_model04_leverage_dataset.csv")
PATH_MODEL_RDS     <- file.path(DIRS$artifacts, "v2_model04_model_rds.rds")
PATH_VAL_PREDS     <- file.path(DIRS$artifacts, "v2_model04_val_preds.csv")
PATH_TEST_PREDS    <- file.path(DIRS$artifacts, "v2_model04_test_preds.csv")
PATH_METRICS       <- file.path(DIRS$artifacts, "v2_model04_metrics.csv")
PATH_CALIB_COMPARE <- file.path(DIRS$artifacts, "v2_model04_calibration_compare.csv")
PATH_CALIB_METHOD  <- file.path(DIRS$artifacts, "v2_model04_calibration_method.txt")
PATH_CALIB_RDS     <- file.path(DIRS$artifacts, "v2_model04_calibration_glm.rds")

OUT_STATUS_CSV     <- file.path(DIRS$artifacts, "v2_model04_verify_status.csv")
OUT_REPORT_MD      <- file.path(DIRS$artifacts, "v2_model04_verify_report.md")
OUT_HASHES_CSV     <- file.path(DIRS$artifacts, "v2_model04_verify_hashes.csv")
OUT_DEEP_CSV       <- file.path(DIRS$artifacts, "v2_model04_verify_deep.csv")

# -------------------- 2) Load artifacts --------------------
paths <- c(PATH_LEV, PATH_MODEL_RDS, PATH_VAL_PREDS, PATH_TEST_PREDS, PATH_METRICS, PATH_CALIB_COMPARE, PATH_CALIB_METHOD)
for (p in paths) req(p, basename(p))

lev <- read_csv_clean(PATH_LEV) |>
  mutate(game_id = as.character(game_id),
         play_id = suppressWarnings(as.integer(play_id)),
         nfl_id  = suppressWarnings(as.integer(nfl_id)),
         split   = tolower(as.character(split)))

val_preds  <- read_csv_clean(PATH_VAL_PREDS)
test_preds <- read_csv_clean(PATH_TEST_PREDS)
metrics    <- read_csv_clean(PATH_METRICS)

# strict schema avoids parse warnings
cal_cmp <- readr::read_csv(
  PATH_CALIB_COMPARE,
  col_types = readr::cols_only(
    method  = readr::col_character(),
    brier   = readr::col_double(),
    auc     = readr::col_double(),
    logloss = readr::col_double()
  ),
  show_col_types = FALSE,
  progress = FALSE
)

cal_method <- trimws(readLines(PATH_CALIB_METHOD, warn = FALSE)[1])
bundle <- readRDS(PATH_MODEL_RDS)
stopifnot(is.list(bundle))

# -------------------- 3) Baseline integrity --------------------
checks <- list()
checks$splits_ok <- all(sort(unique(lev$split)) %in% c("train","val","test"))
checks$val_rows_match  <- nrow(val_preds)  == sum(lev$split=="val")
checks$test_rows_match <- nrow(test_preds) == sum(lev$split=="test")
key_unique <- function(df) nrow(df) == nrow(dplyr::distinct(df, game_id, play_id, nfl_id))
checks$val_keys_unique  <- key_unique(val_preds)
checks$test_keys_unique <- key_unique(test_preds)
req_fields <- c("version","model","features","medians","label","algo")
checks$bundle_has_fields <- all(req_fields %in% names(bundle))
checks$bundle_version_v2 <- identical(bundle$version, "v2")
checks$bundle_label_ok   <- identical(bundle$label, "contest_primary")
feat_cols <- bundle$features
checks$features_in_lev <- all(feat_cols %in% names(lev))
checks$medians_one_row <- is.data.frame(bundle$medians) && nrow(bundle$medians)==1

# -------------------- 4) Parity from saved predictions (val/test) --------------------
calc_metrics <- function(df, split_name){
  y  <- as.integer(df$y)
  pc <- as.numeric(df$p_cal)
  pr <- as.numeric(df$p_raw)
  th <- 0.5
  pred <- as.integer(pc >= th)
  tp <- sum(pred==1 & y==1); tn <- sum(pred==0 & y==0)
  fp <- sum(pred==1 & y==0); fn <- sum(pred==0 & y==1)
  tibble(split = split_name,
         auc = safe_auc(y, pc),
         accuracy = (tp+tn)/length(y),
         precision = ifelse(tp+fp==0, NA_real_, tp/(tp+fp)),
         recall = ifelse(tp+fn==0, NA_real_, tp/(tp+fn)),
         f1 = {prec <- ifelse(tp+fp==0, NA_real_, tp/(tp+fp)); rec <- ifelse(tp+fn==0, NA_real_, tp/(tp+fn)); ifelse(is.na(prec)|is.na(rec)|(prec+rec)==0, NA_real_, 2*prec*rec/(prec+rec))},
         brier_cal = brier(y, pc),
         brier_raw = brier(y, pr),
         logloss_cal = logloss_vec(y, pc),
         logloss_raw = logloss_vec(y, pr))
}
m_val <- calc_metrics(val_preds,  "val")
m_tst <- calc_metrics(test_preds, "test")

m_file_vt <- metrics |> mutate(split = tolower(split)) |> filter(split %in% c("val","test")) |> arrange(split)
mm_vt     <- bind_rows(m_val, m_tst) |> arrange(split)

cmp_numeric <- function(a,b, tol=1e-8){ all(abs(a-b) <= tol | (is.na(a) & is.na(b))) }
join_cmp_vt <- m_file_vt |>
  select(split, auc, accuracy, precision, recall, f1) |>
  left_join(mm_vt |> select(split, auc_calc=auc, accuracy_calc=accuracy, precision_calc=precision, recall_calc=recall, f1_calc=f1), by="split")
checks$metrics_match_vt <- with(join_cmp_vt,
                                cmp_numeric(auc, auc_calc) && cmp_numeric(accuracy, accuracy_calc) &&
                                  cmp_numeric(precision, precision_calc) && cmp_numeric(recall, recall_calc) &&
                                  cmp_numeric(f1, f1_calc))

# -------------------- 5) Calibration consistency --------------------
cal_cmp_ord <- cal_cmp |> arrange(brier, desc(auc))
checks$calib_method_matches_comparison <- identical(cal_method, cal_cmp_ord$method[1])
checks$brier_improved_val   <- isTRUE(m_val$brier_cal   <= m_val$brier_raw   + 1e-12)
checks$logloss_improved_val <- isTRUE(m_val$logloss_cal <= m_val$logloss_raw + 1e-12)
is_monotone_nondec <- function(x, y){ ord <- order(x); all(diff(y[ord]) >= -1e-12) }
checks$calibration_monotone_val <- is_monotone_nondec(val_preds$p_raw, val_preds$p_cal)

# -------------------- 6) Deep checks (optional) --------------------
deep_rows <- NULL
if (MODE == "deep") {
  mdl <- bundle$model
  meds <- bundle$medians
  reimpute <- function(df) {
    X <- df[, feat_cols, drop = FALSE]
    for (v in feat_cols) {
      suppressWarnings(X[[v]][!is.finite(as.numeric(X[[v]]))] <- NA)
      X[[v]][is.na(X[[v]])] <- meds[[v]][1]
      X[[v]] <- suppressWarnings(as.numeric(X[[v]]))
    }
    X
  }
  pred_raw <- function(X){
    if (inherits(mdl, "xgb.Booster")) {
      if (!requireNamespace("xgboost", quietly = TRUE)) return(NULL)
      d <- xgboost::xgb.DMatrix(as.matrix(X)); as.numeric(predict(mdl, d))
    } else if (inherits(mdl, "ranger")) {
      pr <- predict(mdl, data = X, type = "response")
      if (!is.null(pr$predictions) && is.matrix(pr$predictions) && "yes" %in% colnames(pr$predictions)) as.numeric(pr$predictions[,"yes"]) else as.numeric(pr$predictions)
    } else if ("train" %in% class(mdl)) {
      pr <- predict(mdl, newdata = X, type = "prob"); as.numeric(pr$yes)
    } else {
      pr <- tryCatch(predict(mdl, newdata = X, type = "response"), error=function(e) NULL)
      if (is.null(pr)) pr <- predict(mdl, newdata = X); as.numeric(pr)
    }
  }
  keys <- c("game_id","play_id","nfl_id","split")
  val_rows <- lev |> filter(split=="val")  |> arrange(!!!syms(keys))
  tst_rows <- lev |> filter(split=="test") |> arrange(!!!syms(keys))
  val_preds <- val_preds |> arrange(!!!syms(keys))
  test_preds<- test_preds |> arrange(!!!syms(keys))
  
  Xv <- reimpute(val_rows)
  Xt <- reimpute(tst_rows)
  pv <- pred_raw(Xv)
  pt <- pred_raw(Xt)
  
  ok_val <- if (is.null(pv)) NA else (all(is.finite(pv)) && all(abs(pv - as.numeric(val_preds$p_raw)) <= 1e-9))
  ok_tst <- if (is.null(pt)) NA else (all(is.finite(pt)) && all(abs(pt - as.numeric(test_preds$p_raw)) <= 1e-9))
  checks$deep_raw_match_val  <- ok_val
  checks$deep_raw_match_test <- ok_tst
  
  deep_rows <- tibble(split=c("val","test"), raw_match=c(ok_val, ok_tst))
  readr::write_csv(deep_rows, OUT_DEEP_CSV)
}

# -------------------- 7) Hashes --------------------
hash_row <- function(path){ tibble(file = basename(path), bytes = file.info(path)$size, md5 = digest(path, algo = "md5", file = TRUE)) }
hashes <- bind_rows(lapply(paths, hash_row))
if (file.exists(PATH_CALIB_RDS)) hashes <- bind_rows(hashes, hash_row(PATH_CALIB_RDS))
readr::write_csv(hashes, OUT_HASHES_CSV)

# -------------------- 8) Status + report --------------------
status <- tibble(
  check = c(
    "splits_present",
    "val_rows_match",
    "test_rows_match",
    "val_keys_unique",
    "test_keys_unique",
    "bundle_has_fields",
    "bundle_version_v2",
    "bundle_label_ok",
    "features_in_lev",
    "medians_one_row",
    "metrics_match_val_test",
    "calib_method_matches_comparison",
    "brier_improved_val",
    "logloss_improved_val",
    "calibration_monotone_val",
    if (MODE=="deep") c("deep_raw_match_val","deep_raw_match_test") else character(0)
  ),
  status = c(
    pass(checks$splits_ok),
    pass(checks$val_rows_match),
    pass(checks$test_rows_match),
    pass(checks$val_keys_unique),
    pass(checks$test_keys_unique),
    pass(checks$bundle_has_fields),
    pass(checks$bundle_version_v2),
    pass(checks$bundle_label_ok),
    pass(checks$features_in_lev),
    pass(checks$medians_one_row),
    pass(checks$metrics_match_vt),
    pass(checks$calib_method_matches_comparison),
    pass(checks$brier_improved_val),
    pass(checks$logloss_improved_val),
    pass(checks$calibration_monotone_val),
    if (MODE=="deep") c(pass(checks$deep_raw_match_val), pass(checks$deep_raw_match_test)) else character(0)
  )
)

# Append glmnet presence checks
cmp_glm <- cal_cmp
meth <- cal_method
st2 <- tibble::tibble(
  check=c("glmnet_in_compare","chosen_method_in_compare"),
  status=c(if ("platt_ridge_glmnet" %in% cmp_glm$method) "PASS" else "FAIL",
           if (meth %in% cmp_glm$method) "PASS" else "FAIL"),
  details=c("", paste0("chosen=", meth))
)
status <- bind_rows(status, st2)

readr::write_csv(status, OUT_STATUS_CSV)

rep <- c(
  "# Model 04 v2 — Verification report (20a unified)",
  "",
  paste0("- Mode: ", MODE),
  paste0("- Calibration method chosen in 20: ", cal_method),
  paste0("- Metrics parity (val/test): ", status$status[status$check=="metrics_match_val_test"]),
  paste0("- Brier improvement (val): ", status$status[status$check=="brier_improved_val"]),
  paste0("- LogLoss improvement (val): ", status$status[status$check=="logloss_improved_val"]),
  paste0("- Monotone mapping (val): ", status$status[status$check=="calibration_monotone_val"]),
  if (MODE=="deep") paste0("- RAW reproduction val/test: ",
                           paste(status$status[status$check %in% c("deep_raw_match_val","deep_raw_match_test")], collapse=",")) else NULL,
  "",
  "## File hashes",
  paste(capture.output(print(hashes)), collapse = "\n"),
  "",
  "## Status table",
  paste(capture.output(print(status)), collapse = "\n")
)
writeLines(rep[!vapply(rep, is.null, logical(1))], OUT_REPORT_MD, useBytes = TRUE)

message("Wrote:\n  - ", OUT_STATUS_CSV,
        "\n  - ", OUT_REPORT_MD,
        "\n  - ", OUT_HASHES_CSV,
        if (MODE=="deep") paste0("\n  - ", OUT_DEEP_CSV) else "")

# -------------------- 99) Console summary --------------------
st <- readr::read_csv(OUT_STATUS_CSV, show_col_types = FALSE) |> janitor::clean_names()
st <- st |> mutate(is_fail = status == "FAIL", is_na = status == "N/A")
n_fail  <- sum(st$is_fail, na.rm = TRUE)
n_neutral <- sum(st$is_na, na.rm = TRUE)
n_total_req <- nrow(st) - n_neutral
overall <- if (n_fail == 0) "PASS" else "FAIL"

# Echo chosen calibration method from Script 20 (console)
meth_file <- PATH_CALIB_METHOD
if (file.exists(meth_file)) {
  meth <- readLines(meth_file, warn = FALSE)[1]
  message("Calibration method (20): ", meth)
}

cat("\n================ Verifier Overall =================\n")
cat("Overall: ", overall, "\n", sep = "")
cat("Checks: ", (n_total_req - n_fail), "/", n_total_req, " passed; ",
    n_neutral, " N/A\n", sep = "")
if (n_fail > 0) {
  cat("\nFailed checks:\n")
  print(st |> filter(status == "FAIL") |> select(check, details))
}
if (file.exists(OUT_DEEP_CSV)) {
  cat("\nDeep raw reproduction:\n")
  deep <- tryCatch(readr::read_csv(OUT_DEEP_CSV, show_col_types = FALSE), error = function(e) NULL)
  if (!is.null(deep)) print(deep)
}
cat("\nReport: ", OUT_REPORT_MD, "\n", sep = "")
cat("Hashes: ", OUT_HASHES_CSV,  "\n", sep = "")

if (identical(overall, "FAIL")) {
  stop("Verification FAILED. See artifacts/v2_model04_verify_status.csv for details.", call. = FALSE)
} else {
  message("Verification PASSED.")
}










#!/usr/bin/env Rscript

# =====================================================================
# 21_threshold_sensitivity_v2.R — Repeat Script 12 on v2 models
#   - M03: threshold sweep for primary (1.5 yd) and backup (1.0 yd)
#           using the v2 champion prefix (rf or xgb)
#   - M04: coverage vs accuracy sweep (use calibrated probabilities when available)
#
# Outputs:
#   - artifacts/v2_model03_threshold_sweep.csv
#   - artifacts/v2_model04_threshold_sweep.csv
#   - artifacts/v2_threshold_sensitivity_report.md
#   - artifacts/v2_threshold_sensitivity_status.csv
#   - artifacts/v2_threshold_sensitivity_status.md
# =====================================================================

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

.ensure_pkgs <- function(pkgs){
  missing <- setdiff(pkgs, rownames(installed.packages()))
  if (length(missing)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(missing, quiet = TRUE))
  }
}
.ensure_pkgs(c("tidyverse","readr","janitor","scales"))
rm(.ensure_pkgs)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(scales)
})

# -------------------- Behavior flags --------------------
# Require calibrated probabilities for M04 by default.
# If neither separate *_cal.csv nor a p_cal column is present, the script will STOP.
STRICT_CAL <- TRUE

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
DIRS <- list(artifacts = B("artifacts"))
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

# -------------------- Paths --------------------
# M03 champion-aware prefixes
CHAMP_PATH <- file.path(DIRS$artifacts, "v2_model03_champion.txt")
if (!file.exists(CHAMP_PATH)) {
  stop("Missing artifacts/v2_model03_champion.txt (from Script 18). Cannot proceed.", call. = FALSE)
}
champ_prefix <- trimws(readLines(CHAMP_PATH, warn = FALSE, n = 1))
if (!nzchar(champ_prefix)) stop("Champion file present but empty.", call. = FALSE)

# Inputs (M03) from champion prefix
P_M03_VAL      <- file.path(DIRS$artifacts, paste0(champ_prefix, "_val_preds.csv"))
P_M03_TEST     <- file.path(DIRS$artifacts, paste0(champ_prefix, "_test_preds.csv"))
P_M03_VAL_1P0  <- file.path(DIRS$artifacts, paste0(champ_prefix, "_val_preds_1p0.csv"))
P_M03_TEST_1P0 <- file.path(DIRS$artifacts, paste0(champ_prefix, "_test_preds_1p0.csv"))
RDS_M03_PRI    <- file.path(DIRS$artifacts, paste0(champ_prefix, "_model_rds.rds"))
RDS_M03_TGT    <- file.path(DIRS$artifacts, paste0(champ_prefix, "_model_rds_1p0.rds"))

# Inputs (M04) — prefer calibrated; refuse uncalibrated when STRICT_CAL is TRUE
P_M04_VAL_CAL  <- file.path(DIRS$artifacts, "v2_model04_val_preds_cal.csv")
P_M04_TEST_CAL <- file.path(DIRS$artifacts, "v2_model04_test_preds_cal.csv")
P_M04_VAL_RAW  <- file.path(DIRS$artifacts, "v2_model04_val_preds.csv")
P_M04_TEST_RAW <- file.path(DIRS$artifacts, "v2_model04_test_preds.csv")

# Outputs
OUT_M03   <- file.path(DIRS$artifacts, "v2_model03_threshold_sweep.csv")
OUT_M04   <- file.path(DIRS$artifacts, "v2_model04_threshold_sweep.csv")
OUT_REP   <- file.path(DIRS$artifacts, "v2_threshold_sensitivity_report.md")
OUT_STAT  <- file.path(DIRS$artifacts, "v2_threshold_sensitivity_status.csv")
OUT_STATM <- file.path(DIRS$artifacts, "v2_threshold_sensitivity_status.md")

# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
safe_ratio <- function(num, den) ifelse(den > 0, num/den, NA_real_)

md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
req  <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }

# -------------------- Load inputs & guards --------------------
# M03
req(P_M03_VAL,      basename(P_M03_VAL))
req(P_M03_TEST,     basename(P_M03_TEST))
req(P_M03_VAL_1P0,  basename(P_M03_VAL_1P0))
req(P_M03_TEST_1P0, basename(P_M03_TEST_1P0))

m03_rds_primary <- if (file.exists(RDS_M03_PRI)) readRDS(RDS_M03_PRI) else NULL
m03_rds_1p0     <- if (file.exists(RDS_M03_TGT)) readRDS(RDS_M03_TGT) else NULL

m03_val      <- read_csv_clean(P_M03_VAL)
m03_test     <- read_csv_clean(P_M03_TEST)
m03_val_1p0  <- read_csv_clean(P_M03_VAL_1P0)
m03_test_1p0 <- read_csv_clean(P_M03_TEST_1P0)

for (nm in c("y","p_cal")) {
  if (!nm %in% names(m03_val))      stop(basename(P_M03_VAL),     " missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_test))     stop(basename(P_M03_TEST),    " missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_val_1p0))  stop(basename(P_M03_VAL_1P0), " missing column: ", nm, call. = FALSE)
  if (!nm %in% names(m03_test_1p0)) stop(basename(P_M03_TEST_1P0)," missing column: ", nm, call. = FALSE)
}

normalize_core <- function(df, split_name){
  need <- c("game_id","play_id","nfl_id","y","p_cal")
  miss <- setdiff(need, names(df))
  if (length(miss)) stop("Missing columns: ", paste(miss, collapse=", "))
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y),
      p_cal   = as.numeric(p_cal),
      split   = split_name
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_cal)
}

m03_val      <- normalize_core(m03_val,      "val")
m03_test     <- normalize_core(m03_test,     "test")
m03_val_1p0  <- normalize_core(m03_val_1p0,  "val")
m03_test_1p0 <- normalize_core(m03_test_1p0, "test")

# M04 loader
load_m04 <- function(cal_path, raw_path, split_name){
  # Preferred: standalone calibrated files
  if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    need <- c("game_id","play_id","nfl_id","y","p_cal")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(cal_path), " missing columns: ", paste(miss, collapse=", "), call. = FALSE)
    source_used <- "separate_calibrated_file"
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
  } else {
    # Fall back to the standard preds file
    req(raw_path, basename(raw_path))
    df <- read_csv_clean(raw_path)
    need_core <- c("game_id","play_id","nfl_id","y")
    miss_core <- setdiff(need_core, names(df))
    if (length(miss_core)) stop(basename(raw_path), " missing columns: ", paste(miss_core, collapse=", "), call. = FALSE)
    # Choose column with strict calibrated-by-default
    if ("p_cal" %in% names(df)) {
      source_used <- "embedded_p_cal_in_raw"
      df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
    } else if (isTRUE(STRICT_CAL)) {
      stop("Calibrated probabilities required (STRICT_CAL=TRUE) but neither ", basename(cal_path),
           " nor a p_cal column in ", basename(raw_path), " is available.", call. = FALSE)
    } else if ("p_raw" %in% names(df)) {
      source_used <- "p_raw_fallback"
      df <- df |> mutate(split = split_name, p_used = as.numeric(p_raw))
    } else if ("p_go" %in% names(df)) {
      source_used <- "legacy_p_go_fallback"
      df <- df |> mutate(split = split_name, p_used = as.numeric(p_go))
    } else {
      stop(basename(raw_path), " missing probability columns (expected p_cal or p_raw or p_go).", call. = FALSE)
    }
  }
  attr(df, "m04_source_used") <- source_used
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y)
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_used)
}

m04_val  <- load_m04(P_M04_VAL_CAL,  P_M04_VAL_RAW,  "val")
m04_test <- load_m04(P_M04_TEST_CAL, P_M04_TEST_RAW, "test")
m04_val_source  <- attr(m04_val, "m04_source_used")
m04_test_source <- attr(m04_test, "m04_source_used")

# -------------------- M03: threshold sweep --------------------
ths <- seq(0, 1, by = 0.01)

sweep_bin <- function(df, split_name, label_name){
  y <- as.integer(df$y)
  p <- as.numeric(df$p_cal)
  tibble(th = ths) |>
    rowwise() |>
    mutate(
      tp = sum(y == 1 & p >= th, na.rm = TRUE),
      fp = sum(y == 0 & p >= th, na.rm = TRUE),
      tn = sum(y == 0 & p <  th, na.rm = TRUE),
      fn = sum(y == 1 & p <  th, na.rm = TRUE),
      n  = tp + fp + tn + fn,
      precision = safe_ratio(tp, tp + fp),
      recall    = safe_ratio(tp, tp + fn),
      f1        = ifelse(is.na(precision) | is.na(recall) | (precision+recall)==0, NA_real_,
                         2*precision*recall/(precision+recall)),
      pred_pos_rate = safe_ratio(tp + fp, n),
      prevalence    = mean(y, na.rm = TRUE)
    ) |>
    ungroup() |>
    mutate(split = split_name, label = label_name, .before = 1)
}

m03_primary_val  <- sweep_bin(m3v  <- m03_val,     "val",  "primary_1p5")
m03_primary_test <- sweep_bin(m3t  <- m03_test,    "test", "primary_1p5")
m03_1p0_val      <- sweep_bin(m31v <- m03_val_1p0, "val",  "backup_1p0")
m03_1p0_test     <- sweep_bin(m31t <- m03_test_1p0,"test", "backup_1p0")

m03_sweep <- bind_rows(m03_primary_val, m03_primary_test, m03_1p0_val, m03_1p0_test)

# Add RDS-selected thresholds (if available) for reporting
sel_th_primary <- if (!is.null(m03_rds_primary) && !is.null(m03_rds_primary$threshold)) as.numeric(m03_rds_primary$threshold) else NA_real_
sel_th_1p0     <- if (!is.null(m03_rds_1p0)     && !is.null(m03_rds_1p0$threshold))     as.numeric(m03_rds_1p0$threshold)     else NA_real_

m03_sel <- tibble(
  label = c("primary_1p5","backup_1p0"),
  sel_threshold = c(sel_th_primary, sel_th_1p0)
)

# -------------------- M04: coverage vs accuracy sweep --------------------
rank_and_cover <- function(df_one_split){
  # Per-play ranking and top probability
  plays <- df_one_split |>
    group_by(game_id, play_id) |>
    mutate(rank = rank(-p_used, ties.method = "first")) |>
    summarise(
      max_p = max(p_used, na.rm = TRUE),
      top1  = as.integer(any(y == 1 & rank == 1)),
      rr    = {
        if (any(y == 1)) {
          r <- rank[y == 1]
          1 / min(r, na.rm = TRUE)
        } else NA_real_
      },
      .groups = "drop"
    )
  plays
}

sweep_cov <- function(df, split_name){
  plays <- rank_and_cover(df)
  tibble(th = ths) |>
    rowwise() |>
    mutate(
      covered = sum(plays$max_p >= th, na.rm = TRUE),
      total   = sum(!is.na(plays$max_p)),
      cov     = safe_ratio(covered, total),
      acc_top = {
        idx <- which(plays$max_p >= th)
        if (length(idx) == 0) NA_real_ else safe_ratio(sum(plays$top1[idx], na.rm = TRUE), length(idx))
      },
      mean_rr = mean(plays$rr[plays$max_p >= th], na.rm = TRUE)
    ) |>
    ungroup() |>
    mutate(split = split_name, .before = 1)
}

m04_val_sweep  <- sweep_cov(m04_val,  "val")
m04_test_sweep <- sweep_cov(m04_test, "test")

m04_sweep <- bind_rows(m04_val_sweep, m04_test_sweep)

# -------------------- Write outputs --------------------
readr::write_csv(m03_sweep, OUT_M03)
readr::write_csv(m04_sweep, OUT_M04)

# -------------------- M04 calibration sanity (validation split) --------------------
m04_sanity <- NULL
if (file.exists(P_M04_VAL_RAW)) {
  df_raw <- read_csv_clean(P_M04_VAL_RAW)
  if (all(c("y") %in% names(df_raw))) {
    yv <- as.integer(df_raw$y)
    eps <- 1e-15
    have_cal <- "p_cal" %in% names(df_raw)
    have_raw <- "p_raw" %in% names(df_raw)
    if (have_cal || have_raw) {
      brier <- function(p,y) mean((p - y)^2, na.rm = TRUE)
      logloss <- function(p,y) {
        p <- pmin(pmax(p, eps), 1 - eps)
        -mean(y*log(p) + (1-y)*log(1-p), na.rm = TRUE)
      }
      met <- tibble::tibble()
      if (have_raw) {
        pr <- as.numeric(df_raw$p_raw)
        met <- dplyr::bind_rows(met, tibble::tibble(model="raw", brier=brier(pr,yv), logloss=logloss(pr,yv)))
      }
      if (have_cal) {
        pc <- as.numeric(df_raw$p_cal)
        met <- dplyr::bind_rows(met, tibble::tibble(model="cal", brier=brier(pc,yv), logloss=logloss(pc,yv)))
      }
      if (nrow(met) > 0) {
        m04_sanity <- met
      }
    }
  }
}

# -------------------- Report --------------------
rep_lines <- c(
  paste0("# Threshold sensitivity v2 — champion ", champ_prefix),
  "",
  "## M03 (binary F1 / precision / recall)",
  paste0("- Input (primary): `", basename(P_M03_VAL), "`, `", basename(P_M03_TEST), "`"),
  paste0("- Input (backup 1.0): `", basename(P_M03_VAL_1P0), "`, `", basename(P_M03_TEST_1P0), "`"),
  if (!is.na(sel_th_primary)) paste0("- Selected threshold (primary): ", format(sel_th_primary, digits = 4)) else "- Selected threshold (primary): NA",
  if (!is.na(sel_th_1p0))     paste0("- Selected threshold (1.0): ",     format(sel_th_1p0, digits = 4)) else "- Selected threshold (1.0): NA",
  "",
  "## M04 (coverage vs accuracy)",
  if (file.exists(P_M04_VAL_CAL)) "- Using separate calibrated files" else if (any(c(m04_val_source, m04_test_source) == "embedded_p_cal_in_raw")) "- Using embedded calibrated p_cal" else "- Using raw predictions",
  paste0("- M04 source (val): ", m04_val_source),
  paste0("- M04 source (test): ", m04_test_source),
  "",
  "- Outputs:",
  paste0("  - ", basename(OUT_M03)),
  paste0("  - ", basename(OUT_M04))
)

if (!is.null(m04_sanity)) {
  rep_lines <- c(rep_lines, "", "### M04 calibration sanity (validation):",
                 paste0("- raw:   brier=", sprintf("%.6f", m04_sanity$brier[m04_sanity$model=="raw"]), 
                        ", logloss=", sprintf("%.6f", m04_sanity$logloss[m04_sanity$model=="raw"])),
                 paste0("- cal:   brier=", sprintf("%.6f", m04_sanity$brier[m04_sanity$model=="cal"]), 
                        ", logloss=", sprintf("%.6f", m04_sanity$logloss[m04_sanity$model=="cal"])))
}

writeLines(rep_lines, OUT_REP, useBytes = TRUE)

# -------------------- Basic status checks --------------------
cov_ok <- all(diff(m04_sweep$cov[m04_sweep$split=="val"]) <= 1e-12, na.rm = TRUE) &&
  all(diff(m04_sweep$cov[m04_sweep$split=="test"]) <= 1e-12, na.rm = TRUE)
cov_zero_ok <- all(abs(m04_sweep$cov[m04_sweep$th==0] - 1) < 1e-9, na.rm = TRUE)

status_tbl <- tibble::tibble(
  step    = c("21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2", "21_threshold_sensitivity_v2"),
  check   = c("m03_present", "m04_present", "coverage_monotone", "coverage_th0_is_one", "m03_metrics_present", "coverage_column_present", "calibration_metrics_present"),
  status  = c(pass(nrow(m03_sweep) > 0), pass(nrow(m04_sweep) > 0), pass(cov_ok), pass(cov_zero_ok),
              pass(all(c("f1","precision","recall") %in% names(m03_sweep))), pass("cov" %in% names(m04_sweep)),
              pass(!is.null(m04_sanity))),
  details = c(
    sprintf("rows=%s", nrow(m03_sweep)),
    sprintf("rows=%s", nrow(m04_sweep)),
    if (cov_ok) "OK" else "coverage not non-increasing",
    if (cov_zero_ok) "OK" else "coverage(th=0)!=1",
    "F1/precision/recall present across grid",
    "coverage column present across grid",
    if (!is.null(m04_sanity)) sprintf("raw brier=%.6f, cal brier=%.6f", 
                                      m04_sanity$brier[m04_sanity$model=="raw"],
                                      m04_sanity$brier[m04_sanity$model=="cal"]) else "no metrics"
  )
)

readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# Threshold sensitivity v2 — Status", "", md_table(status_tbl)), OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) stop("Threshold sensitivity v2 validation FAILED. See artifacts/v2_threshold_sensitivity_status.*", call. = FALSE)
message("Threshold sensitivity v2 verification: PASS.")

# -------------------- Console breadcrumbs --------------------
message("Wrote:",
        "\n  - ", OUT_M03,
        "\n  - ", OUT_M04,
        "\n  - ", OUT_REP,
        "\n  - ", OUT_STAT, " and ", OUT_STATM)










#!/usr/bin/env Rscript

# =====================================================================
# 22_select_apply_pstar_v2.R — Repeat Script 12a on v2 models
#   - Select p* for:
#       * M03 primary (1.5 yd) and backup (1.0 yd)
#       * M04 assignment (coverage vs accuracy)
#   - Apply p* to predictions on val and test, write evals + status
#   - Optional: δ abstain margin scaffolding (OFF by default)
#
# Inputs (from Script 21 & v2 models):
#   - artifacts/v2_model03_threshold_sweep.csv
#   - artifacts/v2_model04_threshold_sweep.csv
#   - artifacts/v2_model03_champion.txt -> champion prefix ("v2_model03_xgb" or "v2_model03_rf")
#   - artifacts/{champ}_val_preds.csv, {champ}_test_preds.csv
#   - artifacts/{champ}_val_preds_1p0.csv, {champ}_test_preds_1p0.csv
#   - artifacts/v2_model04_val_preds_cal.csv (preferred) OR artifacts/v2_model04_val_preds.csv with p_cal column
#   - artifacts/v2_model04_test_preds_cal.csv (preferred) OR artifacts/v2_model04_test_preds.csv with p_cal column
#
# Outputs:
