# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
safe_ratio <- function(num, den) ifelse(den > 0, num/den, NA_real_)
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }

