# -------------------- Selection rules (mirror 12a) --------------------
pick_m03 <- function(df_sw_label){
  val <- df_sw_label |> filter(split == "val") |> arrange(th)
  if (!nrow(val)) return(tibble(p_star = NA_real_, objective = NA_character_, objective_val = NA_real_, note = NA_character_))
  if (all(is.na(val$f1))) {
    tpr <- safe_ratio(val$tp, val$tp + val$fn)
    fpr <- safe_ratio(val$fp, val$fp + val$tn)
    j <- tpr - fpr
    best <- max(replace_na(j, -Inf), na.rm = TRUE)
    i <- which.min(ifelse(j >= best - 1e-9, val$th, Inf))
    tibble(p_star = val$th[i], objective = "youden_j_on_val", objective_val = j[i], note = "tie->lower_th")
  } else {
    best <- max(replace_na(val$f1, -Inf), na.rm = TRUE)
    i <- which.min(ifelse(val$f1 >= best - 1e-9, val$th, Inf))
    tibble(p_star = val$th[i], objective = "f1_on_val", objective_val = val$f1[i], note = "tie->lower_th")
  }
}

pick_m04 <- function(df_sw_val, tol = 0.005){
  if (!nrow(df_sw_val)) return(tibble(p_star = NA_real_, objective = NA_character_, objective_val = NA_real_, note = NA_character_))
  cand <- df_sw_val |> mutate(expected_correct = coverage * top1_on_cov)
  best <- max(replace_na(cand$expected_correct, -Inf), na.rm = TRUE)
  tmp <- cand |> dplyr::filter(expected_correct >= best - tol) |> dplyr::arrange(th)
  tie <- tmp[1, , drop = FALSE]
  tibble(p_star = tie$th[1], objective = "coverage_x_top1_on_val", objective_val = tie$expected_correct[1],
         note = sprintf("min_th_within_%.3f_of_best", tol))
}

# -------------------- Select p* --------------------
