  { sel <- pick_m03(m03_sw |> filter(label == "backup_1p0"));  tibble(model="M03_backup_1p0",  sel) },
  { sel <- pick_m04(m04_sw |> filter(split == "val"));         tibble(model="M04_assignment",    sel) }
)

