# -------------------- Apply & evaluate --------------------
eval_bin <- function(df, th){
  y <- as.integer(df$y)
  p <- if ("p_cal" %in% names(df)) as.numeric(df$p_cal) else as.numeric(df$p_used)
  tp <- sum(y==1 & p>=th, na.rm=TRUE)
  fp <- sum(y==0 & p>=th, na.rm=TRUE)
  tn <- sum(y==0 & p< th, na.rm=TRUE)
  fn <- sum(y==1 & p< th, na.rm=TRUE)
  n  <- tp+fp+tn+fn
  precision <- safe_ratio(tp, tp+fp)
  recall    <- safe_ratio(tp, tp+fn)
  f1 <- ifelse(is.na(precision) | is.na(recall) | (precision+recall)==0, NA_real_, 2*precision*recall/(precision+recall))
  tibble(tp=tp, fp=fp, tn=tn, fn=fn, n=n,
         precision=precision, recall=recall, f1=f1,
         pred_pos_rate=safe_ratio(tp+fp, n), prevalence=mean(y, na.rm = TRUE))
}

best_th_from_val <- function(sw_df){
  v <- sw_df |> filter(split=="val")
  if (!nrow(v)) return(NA_real_)
  if (all(is.na(v$f1))) {
    tpr <- safe_ratio(v$tp, v$tp+v$fn); fpr <- safe_ratio(v$fp, v$fp+v$tn)
    v$J <- tpr - fpr; v$th[which.max(replace_na(v$J, -Inf))]
  } else {
    best <- max(replace_na(v$f1, -Inf), na.rm = TRUE)
    v$th[which.min(ifelse(v$f1 >= best - 1e-9, v$th, Inf))]
  }
}

mk_m03_eval <- function(label_name, df_val, df_test, sw_label, p_star){
  th_best <- best_th_from_val(sw_label)
  ths <- tibble(threshold_type = c("p_star","baseline_0p50","best_f1_val"),
                th = c(p_star, 0.50, th_best))
  bind_rows(
    ths |> mutate(split="val")  |> rowwise() |> mutate(eval = list(eval_bin(df_val, th)))  |> unnest(eval) |> ungroup(),
    ths |> mutate(split="test") |> rowwise() |> mutate(eval = list(eval_bin(df_test, th))) |> unnest(eval) |> ungroup()
  ) |>
    mutate(label = label_name, .before = 1)
}

mk_m04_eval <- function(df, split_name, p_star){
  # Per-play ranking and top probability
  plays <- df |>
    group_by(game_id, play_id) |>
    mutate(rank = rank(-p_used, ties.method = "first")) |>
    summarise(
      max_p = max(p_used, na.rm = TRUE),
      top1  = as.integer(any(y == 1 & rank == 1)),
      rr    = { if (any(y == 1)) { r <- rank[y==1]; 1/min(r, na.rm = TRUE) } else NA_real_ },
      .groups = "drop"
    )
  ths <- tibble(th = c(p_star, 0.00, 0.50),
                threshold_type = c("p_star","baseline_0p00","baseline_0p50"))
  ths |>
    rowwise() |>
    mutate(
      covered = sum(plays$max_p >= th, na.rm = TRUE),
      total   = sum(!is.na(plays$max_p)),
      coverage = safe_ratio(covered, total),
      abstain_rate = 1 - coverage,
      top1_on_cov = {
        idx <- which(plays$max_p >= th)
        if (length(idx) == 0) NA_real_ else safe_ratio(sum(plays$top1[idx], na.rm = TRUE), length(idx))
      },
      mrr_on_cov = mean(plays$rr[plays$max_p >= th], na.rm = TRUE),
      expected_correct = coverage * top1_on_cov
    ) |>
    ungroup() |>
    mutate(split = split_name, .before = 1) |>
    select(split, threshold_type, th, covered, coverage, abstain_rate, top1_on_cov, mrr_on_cov, expected_correct)
}

# Build evals
m03_eval <- bind_rows(
  mk_m03_eval("primary_1p5", m03_val,     m03_test,     m03_sw |> filter(label=="primary_1p5"), ops$p_star[ops$model=="M03_primary_1p5"]),
  mk_m03_eval("backup_1p0",  m03_val_1p0, m03_test_1p0, m03_sw |> filter(label=="backup_1p0"),  ops$p_star[ops$model=="M03_backup_1p0"])
)
m04_eval <- bind_rows(
  mk_m04_eval(m04_val,  "val",  ops$p_star[ops$model=="M04_assignment"]),
  mk_m04_eval(m04_test, "test", ops$p_star[ops$model=="M04_assignment"])
)

