if (!file.exists(P_M04_VAL_CAL) && !file.exists(P_M04_VAL_RAW)) stop("Need v2_model04_val_preds_cal.csv OR v2_model04_val_preds.csv", call. = FALSE)
if (!file.exists(P_M04_TEST_CAL) && !file.exists(P_M04_TEST_RAW)) stop("Need v2_model04_test_preds_cal.csv OR v2_model04_test_preds.csv", call. = FALSE)

read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()

# -------------------- Load preds (calibrated by default) --------------------
load_m04 <- function(cal_path, raw_path, split_name){
  if (file.exists(cal_path)) {
    df <- read_csv_clean(cal_path)
    need <- c("game_id","play_id","nfl_id","y","p_cal")
    miss <- setdiff(need, names(df))
    if (length(miss)) stop(basename(cal_path), " missing columns: ", paste(miss, collapse=", "), call. = FALSE)
    source_used <- "separate_calibrated_file"
    df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
  } else {
    req(raw_path, basename(raw_path))
    df <- read_csv_clean(raw_path)
    need_core <- c("game_id","play_id","nfl_id","y")
    miss_core <- setdiff(need_core, names(df))
    if (length(miss_core)) stop(basename(raw_path), " missing columns: ", paste(miss_core, collapse=", "), call. = FALSE)
    if ("p_cal" %in% names(df)) {
      source_used <- "embedded_p_cal_in_raw"
      df <- df |> mutate(split = split_name, p_used = as.numeric(p_cal))
    } else if (isTRUE(STRICT_CAL)) {
      stop("Calibrated required (STRICT_CAL=TRUE) but neither cal file nor p_cal column found for ", split_name, call. = FALSE)
    } else if ("p_raw" %in% names(df)) {
      source_used <- "p_raw_fallback"
      df <- df |> mutate(split = split_name, p_used = as.numeric(p_raw))
    } else {
      stop(basename(raw_path), " missing probability columns (expected p_cal or p_raw).", call. = FALSE)
    }
  }
  attr(df, "m04_source_used") <- source_used
  df |>
    mutate(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      nfl_id  = suppressWarnings(as.integer(nfl_id)),
      y       = as.integer(y)
    ) |>
    select(game_id, play_id, nfl_id, split, y, p_used)
}

val <- load_m04(P_M04_VAL_CAL,  P_M04_VAL_RAW,  "val")
test<- load_m04(P_M04_TEST_CAL, P_M04_TEST_RAW, "test")
val_source  <- attr(val,  "m04_source_used")
test_source <- attr(test, "m04_source_used")

# -------------------- Get p* for M04 --------------------
p_star <- NA_real_

if (file.exists(P_OPS)) {
  ops <- read_csv_clean(P_OPS)
  if ("model" %in% names(ops) && "p_star" %in% names(ops)) {
    tmp_ops <- ops |> dplyr::filter(model == "M04_assignment")
    v <- tmp_ops$p_star[1]
    if (length(v) == 1 && is.finite(v)) p_star <- as.numeric(v)
  }
}

if (!is.finite(p_star)) {
  sw <- read_csv_clean(P_SWEEP) |> clean_names()
  need <- c("split","th","cov","acc_top")
  miss <- setdiff(need, names(sw))
  if (length(miss)) stop("v2_model04_threshold_sweep.csv missing: ", paste(miss, collapse=", "), call. = FALSE)
  sw_val <- sw |> filter(split == "val") |> mutate(expected_correct = cov * acc_top)
  if (!nrow(sw_val)) stop("M04 sweep has no validation rows.", call. = FALSE)
  best <- max(sw_val$expected_correct, na.rm = TRUE)
  p_star <- min(sw_val$th[which(sw_val$expected_correct >= best - EPS_EQ)], na.rm = TRUE)
}

if (!is.finite(p_star)) stop("Could not determine p* for M04.", call. = FALSE)

# -------------------- Per-play summaries --------------------
rank_and_margin <- function(df){
  df |>
    group_by(game_id, play_id) |>
    mutate(rank = rank(-p_used, ties.method = "first")) |>
    summarise(
      max_p   = max(p_used, na.rm = TRUE),
      second_p = {
        s <- sort(p_used, decreasing = TRUE)
        if (length(s) >= 2) s[2] else 0
      },
      top1  = as.integer(any(y == 1 & rank == 1)),
      rr    = {
        if (any(y == 1)) {
          ranks_pos <- rank[y == 1]
          1 / min(ranks_pos, na.rm = TRUE)
        } else NA_real_
      },
      .groups = "drop"
    ) |>
    mutate(margin = pmax(0, max_p - second_p))
}

val_plays  <- rank_and_margin(val)
test_plays <- rank_and_margin(test)

# -------------------- δ sweep --------------------
delta_grid <- seq(0, DELTA_MAX, by = DELTA_STEP)

eval_delta <- function(plays, p_star){
  purrr::map_dfr(delta_grid, function(d){
    covered <- with(plays, max_p >= p_star & margin >= d)
    total   <- nrow(plays)
    cov     <- if (total > 0) mean(covered) else NA_real_
    if (!any(covered)) {
      tibble(delta = d, coverage = cov, top1_on_cov = NA_real_, mrr_on_cov = NA_real_, expected_correct = NA_real_)
    } else {
      top1 <- mean(plays$top1[covered], na.rm = TRUE)
      mrr  <- mean(plays$rr[covered],    na.rm = TRUE)
      tibble(delta = d, coverage = cov, top1_on_cov = top1, mrr_on_cov = mrr, expected_correct = cov * top1)
    }
  })
}

val_delta  <- eval_delta(val_plays,  p_star)
test_delta <- eval_delta(test_plays, p_star)

# -------------------- Select best δ on validation --------------------
best_idx <- which.max(replace_na(val_delta$expected_correct, -Inf))
best_delta <- val_delta$delta[best_idx]
best_ec    <- val_delta$expected_correct[best_idx]
tmp0 <- val_delta |> dplyr::filter(abs(delta - 0) < EPS_EQ)
base_row <- tmp0[1, , drop = FALSE]
base_ec    <- base_row$expected_correct

delta_equiv_to_zero <- abs(best_ec - base_ec) <= TOL_OPT
keep_delta_off <- isTRUE(delta_equiv_to_zero) || abs(best_delta - 0) < EPS_EQ

# -------------------- Outputs --------------------
OUT_VAL   <- file.path(ART, "v2_m04_delta_sweep_val.csv")
OUT_TEST  <- file.path(ART, "v2_m04_delta_sweep_test.csv")
OUT_SUM   <- file.path(ART, "v2_m04_delta_summary.csv")
OUT_REP   <- file.path(ART, "v2_m04_delta_report.md")
OUT_STAT  <- file.path(ART, "v2_m04_delta_status.csv")
OUT_STATM <- file.path(ART, "v2_m04_delta_status.md")

readr::write_csv(val_delta,  OUT_VAL)
readr::write_csv(test_delta, OUT_TEST)

summary_tbl <- tibble::tibble(
  metric = c("p_star", "best_delta_on_val", "val_expected_correct@best_delta", "val_expected_correct@delta0",
             "test_expected_correct@best_delta", "test_expected_correct@delta0",
             "decision_keep_delta_off"),
  value  = c(sprintf("%.6f", p_star),
             sprintf("%.3f", best_delta),
             sprintf("%.6f", best_ec),
             sprintf("%.6f", base_ec),
             sprintf("%.6f", test_delta$expected_correct[which.min(abs(test_delta$delta - best_delta))]),
             sprintf("%.6f", test_delta$expected_correct[which.min(abs(test_delta$delta - 0))]),
             if (keep_delta_off) "YES" else "NO")
)
readr::write_csv(summary_tbl, OUT_SUM)

rep_lines <- c(
  "# δ abstain margin validation (M04, v2)",
  paste0("- Sources: val=", val_source, "; test=", test_source),
  paste0("- p* (fixed): ", format(p_star, digits = 6)),
  "",
  "## Result",
  paste0("- Best δ on validation: ", format(best_delta, digits = 3),
         " with expected_correct=", format(best_ec, digits = 6)),
  paste0("- Baseline (δ=0) expected_correct: ", format(base_ec, digits = 6)),
  if (keep_delta_off)
    "- Decision: KEEP δ OFF (δ=0 is optimal or within tolerance)."
  else
    "- Decision: δ>0 improves expected_correct beyond tolerance; consider enabling.",
  "",
  "## Notes",
  paste0("- Tolerance for equivalence: ", TOL_OPT, " on expected_correct."),
  paste0("- δ grid: 0 to ", DELTA_MAX, " by ", DELTA_STEP, "."),
  "- Objective matches Script 22: expected_correct = coverage × top1_on_cov (chosen on validation)."
)
writeLines(rep_lines, OUT_REP, useBytes = TRUE)

status_tbl <- tibble::tibble(
  step   = "22a_abstain_margin_validation_v2",
  check  = c("val_delta_written","test_delta_written","summary_written","report_written","keep_delta_off"),
  status = c(pass(file.exists(OUT_VAL)),
             pass(file.exists(OUT_TEST)),
             pass(file.exists(OUT_SUM)),
             pass(file.exists(OUT_REP)),
             pass(keep_delta_off)),
  details = c(
    sprintf("rows=%s", nrow(val_delta)),
    sprintf("rows=%s", nrow(test_delta)),
    sprintf("best_delta=%.3f", best_delta),
    sprintf("p_star=%.6f", p_star),
    if (keep_delta_off) "δ=0 is optimal/equivalent on validation" else "δ>0 beats δ=0 on validation"
  )
)
readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# δ abstain margin — Status", "", paste("|", paste(names(status_tbl), collapse=" | "), "|"),
             paste("|", paste(rep("---", ncol(status_tbl)), collapse=" | "), "|"),
             apply(status_tbl, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|")),
             ""), OUT_STATM, useBytes = TRUE)

message("22a abstain margin validation: ",
        if (keep_delta_off) "KEEP δ OFF" else "δ>0 preferred on validation",
        ". Wrote:",
        "\n  - ", OUT_VAL,
        "\n  - ", OUT_TEST,
        "\n  - ", OUT_SUM,
        "\n  - ", OUT_REP,
        "\n  - ", OUT_STAT, " and ", OUT_STATM)










#!/usr/bin/env Rscript

# =====================================================================
# 23_lock_release_v2.R — Freeze v2 operating points and create a release bundle
#   - Reads Script 22 outputs and related artifacts
#   - Emits machine-readable operating_points.json
#   - Writes a manifest with file hashes, champion, provenance, sessionInfo
#   - Copies key artifacts into a timestamped release/ folder
#
# Inputs (required):
#   - artifacts/v2_operating_points.csv
#   - artifacts/v2_m03_eval.csv
#   - artifacts/v2_m04_eval.csv
#   - artifacts/v2_pstar_summary.md
#   - artifacts/v2_threshold_sensitivity_report.md   (for provenance notes)
#   - artifacts/v2_model03_threshold_sweep.csv
#   - artifacts/v2_model04_threshold_sweep.csv
#   - artifacts/v2_model03_champion.txt
#
# Outputs:
#   - release/v2_YYYYMMDD_HHMMSS/operating_points.json
#   - release/v2_YYYYMMDD_HHMMSS/release_manifest.md
#   - plus copied key CSV/MD artifacts
#   - artifacts/v2_release_status.{csv,md}
# =====================================================================

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

.ensure_pkgs <- function(pkgs){
  missing <- setdiff(pkgs, rownames(installed.packages()))
  if (length(missing)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(missing, quiet = TRUE))
  }
}
.ensure_pkgs(c("tidyverse","readr","janitor","jsonlite","digest"))
rm(.ensure_pkgs)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(jsonlite)
  library(digest)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
ART <- B("artifacts")
REL <- B("release")
dir.create(ART, showWarnings = FALSE, recursive = TRUE)
dir.create(REL, showWarnings = FALSE, recursive = TRUE)

# -------------------- Inputs --------------------
P_OPS   <- file.path(ART, "v2_operating_points.csv")
P_M03E  <- file.path(ART, "v2_m03_eval.csv")
P_M04E  <- file.path(ART, "v2_m04_eval.csv")
P_SUM   <- file.path(ART, "v2_pstar_summary.md")
P_REP21 <- file.path(ART, "v2_threshold_sensitivity_report.md")
P_SW03  <- file.path(ART, "v2_model03_threshold_sweep.csv")
P_SW04  <- file.path(ART, "v2_model04_threshold_sweep.csv")
P_CHAMP <- file.path(ART, "v2_model03_champion.txt")

req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}

# Require
req(P_OPS,   basename(P_OPS))
req(P_M03E,  basename(P_M03E))
req(P_M04E,  basename(P_M04E))
req(P_SUM,   basename(P_SUM))
req(P_REP21, basename(P_REP21))
req(P_SW03,  basename(P_SW03))
req(P_SW04,  basename(P_SW04))
req(P_CHAMP, basename(P_CHAMP))

# -------------------- Read content --------------------
ops   <- suppressMessages(readr::read_csv(P_OPS, show_col_types = FALSE)) |> clean_names()
m03ev <- suppressMessages(readr::read_csv(P_M03E, show_col_types = FALSE)) |> clean_names()
m04ev <- suppressMessages(readr::read_csv(P_M04E, show_col_types = FALSE)) |> clean_names()

champ_prefix <- trimws(readLines(P_CHAMP, warn = FALSE, n = 1))

sum_lines <- readLines(P_SUM, warn = FALSE)
rep21_lines <- readLines(P_REP21, warn = FALSE)

# Extract STRICT_CAL note and M04 sources if present
strict_cal <- NA
if (any(grepl("STRICT_CAL is ON", sum_lines, fixed = TRUE))) strict_cal <- TRUE
if (any(grepl("STRICT_CAL is OFF", sum_lines, fixed = TRUE))) strict_cal <- FALSE

m04_val_source <- sub("^.*M04 source \\(val\\):\\s*", "", grep("M04 source \\(val\\):", rep21_lines, value = TRUE))
m04_test_source <- sub("^.*M04 source \\(test\\):\\s*", "", grep("M04 source \\(test\\):", rep21_lines, value = TRUE))

# -------------------- Build operating_points.json --------------------
stopifnot(all(c("model","p_star","objective") %in% names(ops)))
ops_list <- split(ops |> mutate(p_star = as.numeric(p_star)), ops$model)
ops_json <- list(
  version = "v2",
  generated_at = format(Sys.time(), "%Y-%m-%dT%H:%M:%S%z"),
  champion_prefix = champ_prefix,
  strict_cal = if (is.na(strict_cal)) NULL else strict_cal,
  m04_provenance = list(val = if (length(m04_val_source)) m04_val_source else NULL,
                        test = if (length(m04_test_source)) m04_test_source else NULL),
  operating_points = purrr::map(ops_list, ~list(
    p_star = unname(.x$p_star[1]),
    objective = unname(.x$objective[1]),
    note = if ("note" %in% names(.x)) unname(.x$note[1]) else NULL
  ))
)

# -------------------- Prepare release dir --------------------
stamp <- format(Sys.time(), "v2_%Y%m%d_%H%M%S")
REL_DIR <- file.path(REL, stamp)
dir.create(REL_DIR, showWarnings = FALSE, recursive = TRUE)

OUT_JSON <- file.path(REL_DIR, "operating_points.json")
writeLines(jsonlite::toJSON(ops_json, auto_unbox = TRUE, pretty = TRUE), OUT_JSON, useBytes = TRUE)

# Files to copy into the release
to_copy <- c(P_OPS, P_M03E, P_M04E, P_SUM, P_REP21, P_SW03, P_SW04, P_CHAMP)
copied <- purrr::map_lgl(to_copy, ~file.copy(.x, file.path(REL_DIR, basename(.x)), overwrite = TRUE))

# -------------------- Hash manifest --------------------
hash_info <- purrr::map_dfr(list.files(REL_DIR, full.names = TRUE), function(p){
  tibble::tibble(
    file = basename(p),
    size = file.info(p)$size,
    sha256 = digest::digest(file = p, algo = "sha256"),
    mtime = format(file.info(p)$mtime, "%Y-%m-%d %H:%M:%S %Z")
  )
})

man_lines <- c(
  "# v2 Release Manifest",
  paste0("- Champion: `", champ_prefix, "`"),
  if (!is.na(strict_cal)) paste0("- STRICT_CAL: ", if (strict_cal) "ON" else "OFF") else "- STRICT_CAL: not stated in summary",
  paste0("- M04 source (val): ", if (length(m04_val_source)) m04_val_source else "n/a"),
  paste0("- M04 source (test): ", if (length(m04_test_source)) m04_test_source else "n/a"),
  paste0("- Release folder: `", REL_DIR, "`"),
  "",
  "## Files and hashes",
  paste(md_table(hash_info), collapse = "\n"),
  "",
  "## sessionInfo()",
  capture.output(utils::sessionInfo())
)
writeLines(man_lines, file.path(REL_DIR, "release_manifest.md"), useBytes = TRUE)

# -------------------- Status --------------------
OUT_STAT  <- file.path(ART, "v2_release_status.csv")
OUT_STATM <- file.path(ART, "v2_release_status.md")

chk <- function(name, ok, details) tibble(step="23_lock_release_v2", check=name, status=pass(ok), details=details)

status_tbl <- dplyr::bind_rows(
  chk("ops_json_written", file.exists(OUT_JSON), if (file.exists(OUT_JSON)) "present" else "missing"),
  chk("files_copied", all(copied), sprintf("copied=%s/%s", sum(copied), length(copied))),
  chk("hash_manifest_rows", nrow(hash_info) >= length(to_copy) + 1, sprintf("rows=%s", nrow(hash_info))),
  chk("champion_present", nzchar(champ_prefix), champ_prefix),
  chk("ops_contains_required_models",
      all(c("M03_primary_1p5","M03_backup_1p0","M04_assignment") %in% ops$model),
      paste(sort(unique(ops$model)), collapse=", "))
)

readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# v2 release — Status", "", md_table(status_tbl)), OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) {
  print(status_tbl)
  stop("Release build failed. See artifacts/v2_release_status.*", call. = FALSE)
}
message("Release build: PASS. Wrote ", REL_DIR, " (and status in artifacts).")

# find latest release folder
rel <- tail(sort(Sys.glob("~/Desktop/bdb_project/release/v2_*")), 1)

# -------------------- Optional: Post-build verification --------------------
# Verifies JSON↔CSV model names, presence of files in release, and SHA256.

# 1) JSON vs CSV models
ops_json <- jsonlite::fromJSON(file.path(REL_DIR, "operating_points.json"))
ops_csv  <- suppressMessages(readr::read_csv(P_OPS, show_col_types = FALSE)) |> janitor::clean_names()
stopifnot(setequal(names(ops_json$operating_points), unique(ops_csv$model)))

# 2) required files exist in release
must <- basename(c(P_OPS, P_M03E, P_M04E, P_SUM, P_REP21, P_SW03, P_SW04, P_CHAMP))
stopifnot(all(file.exists(file.path(REL_DIR, must))))

# 3) SHA256 of operating_points.json matches manifest table (3rd column)
mf <- readLines(file.path(REL_DIR, "release_manifest.md"))
row <- grep("^\\|\\s*operating_points\\.json\\s*\\|", mf, value = TRUE)[1]
stopifnot(length(row) == 1)
fields <- trimws(strsplit(row, "\\|")[[1]])
fields <- fields[nchar(fields) > 0]
sha_manifest <- fields[3]
sha_now <- digest::digest(file = file.path(REL_DIR, "operating_points.json"), algo = "sha256")
stopifnot(identical(sha_now, sha_manifest))

message("Release verification: PASS.")










#!/usr/bin/env Rscript

# =====================================================================
# 24_calibration_selection_v2.R — Choose probability calibration for v2
#   Calibrators compared per head (M03 primary 1.5, M03 backup 1.0, M04):
#     - Platt (logistic/sigmoid) with L2 (ridge via glmnet; robust fallback to brglm2/Firth)
#     - Isotonic regression (5-fold OOF on validation)
#     - Temperature scaling (single scalar on logits, optimize NLL)
#   Selection: lowest validation log loss (using 5-fold OOF with SHARED folds).
#     Tie-breakers: Brier -> ECE(15 bins) -> lower complexity (Temp > Platt > Iso).
#
#   Winner is trained on full validation and applied to val and test.
#
# Inputs:
#   - artifacts/v2_model03_champion.txt
#   - artifacts/{champ}_val_preds.csv, {champ}_test_preds.csv
#   - artifacts/{champ}_val_preds_1p0.csv, {champ}_test_preds_1p0.csv
#   - artifacts/v2_model04_val_preds.csv, artifacts/v2_model04_test_preds.csv
#
# Outputs:
#   - artifacts/{champ}_val_preds.csv (updated p_cal)
#   - artifacts/{champ}_test_preds.csv (updated p_cal)
#   - artifacts/{champ}_val_preds_1p0.csv (updated p_cal)
#   - artifacts/{champ}_test_preds_1p0.csv (updated p_cal)
#   - artifacts/v2_model04_val_preds_cal.csv
#   - artifacts/v2_model04_test_preds_cal.csv
#   - artifacts/v2_calibration_selection.csv
#   - artifacts/v2_calibration_report.md
#   - artifacts/v2_calibration_status.{csv,md}
# =====================================================================

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

.ensure_pkgs <- function(pkgs){
  missing <- setdiff(pkgs, rownames(installed.packages()))
  if (length(missing)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(missing, quiet = TRUE))
  }
}
.ensure_pkgs(c("tidyverse","readr","janitor","glmnet","isotone","brglm2"))
rm(.ensure_pkgs)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(glmnet)
  library(isotone)   # we still use stats::isoreg; isotone is listed to keep deps consistent
  # brglm2 not attached; we call brglm2::brglmFit via namespace
})

set.seed(20251105)

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
ART <- B("artifacts")
dir.create(ART, showWarnings = FALSE, recursive = TRUE)

# -------------------- Inputs --------------------
CHAMP_PATH <- file.path(ART, "v2_model03_champion.txt")
if (!file.exists(CHAMP_PATH)) stop("Missing artifacts/v2_model03_champion.txt. Run Script 18.", call. = FALSE)
champ_prefix <- trimws(readLines(CHAMP_PATH, warn = FALSE, n = 1))
if (!nzchar(champ_prefix)) stop("Champion file present but empty.", call. = FALSE)

# M03 preds
P_M03_VAL      <- file.path(ART, paste0(champ_prefix, "_val_preds.csv"))
P_M03_TEST     <- file.path(ART, paste0(champ_prefix, "_test_preds.csv"))
P_M03_VAL_1P0  <- file.path(ART, paste0(champ_prefix, "_val_preds_1p0.csv"))
P_M03_TEST_1P0 <- file.path(ART, paste0(champ_prefix, "_test_preds_1p0.csv"))

# M04 preds (uncalibrated canonical files)
P_M04_VAL_RAW  <- file.path(ART, "v2_model04_val_preds.csv")
P_M04_TEST_RAW <- file.path(ART, "v2_model04_test_preds.csv")

# -------------------- Outputs --------------------
OUT_SEL   <- file.path(ART, "v2_calibration_selection.csv")
OUT_REP   <- file.path(ART, "v2_calibration_report.md")
OUT_STAT  <- file.path(ART, "v2_calibration_status.csv")
OUT_STATM <- file.path(ART, "v2_calibration_status.md")

# M04 calibrated outputs
OUT_M04_VAL_CAL  <- file.path(ART, "v2_model04_val_preds_cal.csv")
OUT_M04_TEST_CAL <- file.path(ART, "v2_model04_test_preds_cal.csv")

# -------------------- Helpers --------------------
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
req <- function(p, name){ if (!file.exists(p)) stop("Missing file: ", name, " at ", p, call. = FALSE) }
safe_clip <- function(p, eps = 1e-15) pmax(eps, pmin(1 - eps, p))
logit <- function(p, eps = 1e-15) log(safe_clip(p, eps) / (1 - safe_clip(p, eps)))
inv_logit <- function(z) 1 / (1 + exp(-z))
brier <- function(p,y) mean((p - y)^2, na.rm = TRUE)
logloss <- function(p,y, eps=1e-15){
  p <- safe_clip(p, eps)
  -mean(y*log(p) + (1-y)*log(1-p), na.rm = TRUE)
}
ece_bins <- function(p, y, nbins = 15){
  p <- as.numeric(p); y <- as.numeric(y)
  brks <- seq(0, 1, length.out = nbins + 1)
  idx <- pmax(1, pmin(nbins, findInterval(p, brks, rightmost.closed = TRUE)))
  # weighted absolute gap
  out <- tibble(bin = 1:nbins) |>
    rowwise() |>
    mutate(conf = mean(p[idx==bin], na.rm = TRUE),
           acc  = mean(y[idx==bin], na.rm = TRUE),
           cnt  = sum(idx==bin, na.rm = TRUE),
           gap  = abs(conf - acc)) |>
    ungroup()
  sum((out$cnt / sum(out$cnt)) * out$gap, na.rm = TRUE)
}

# Stratified K-fold split returning integer fold ids (1..K)
kfold_ids <- function(y, k = 5){
  y <- as.integer(y)
  n <- length(y)
  folds <- integer(n)
  pos <- which(y == 1); neg <- which(y == 0)
  folds[pos] <- sample(rep(1:k, length.out = length(pos)))
  folds[neg] <- sample(rep(1:k, length.out = length(neg)))
  as.integer(folds)
}

# Isotonic fit + predict
iso_fit <- function(scores, y){
  o <- order(scores)
  fit <- stats::isoreg(scores[o], y[o])
  xs <- fit$x
  ys <- fit$yf
  ys <- pmin(1, pmax(0, ys)) # enforce [0,1]
  list(xs = xs, ys = ys)
}
iso_predict <- function(model, scores){
  xs <- model$xs; ys <- model$ys
  keep <- c(TRUE, diff(xs) > 0)
  xs <- xs[keep]; ys <- ys[keep]
  idx <- findInterval(scores, xs, left.open = FALSE, rightmost.closed = TRUE)
  idx <- pmax(1, pmin(length(ys), idx))
  as.numeric(ys[idx])
}

# Platt (ridge) fit + predict — with robust fallback if glmnet errors
platt_fit <- function(scores, y){
  x <- matrix(as.numeric(scores), ncol = 1)
  y <- as.numeric(y)
  
  # If training labels degenerate, return identity mapping to keep OOF sane
  if (length(unique(y)) < 2 || all(!is.finite(x))) {
    return(list(kind = "identity", fit = NULL))
  }
  
  tryCatch({
    fit <- glmnet::cv.glmnet(
      x, y, family = "binomial",
      alpha = 0, standardize = FALSE, nfolds = 5,
      type.measure = "deviance", intercept = TRUE
    )
    list(kind = "glmnet", fit = fit)
  }, error = function(e){
    # robust fallback: Firth/bias-reduced logistic via brglm2
    df <- data.frame(s = as.numeric(scores), y = as.numeric(y))
    fit_br <- stats::glm(
      y ~ s, data = df, family = binomial("logit"),
      method = brglm2::brglmFit, type = "AS_mixed"
    )
    list(kind = "brglm2", fit = fit_br)
  })
}

platt_predict <- function(model, scores){
  if (identical(model$kind, "glmnet")) {
    x <- matrix(as.numeric(scores), ncol = 1)
    as.numeric(predict(model$fit, newx = x, s = "lambda.min", type = "response"))
  } else if (identical(model$kind, "brglm2")) {
    df <- data.frame(s = as.numeric(scores))
    as.numeric(stats::predict(model$fit, newdata = df, type = "response"))
  } else { # identity
    inv_logit(as.numeric(scores))
  }
}

# Temperature scaling fit + predict (optimize NLL)
temp_fit <- function(scores, y){
  obj <- function(T){
    p <- inv_logit(scores / T)
    logloss(p, y)
  }
  opt <- optimize(obj, c(0.05, 50), tol = 1e-6)
  list(T = opt$minimum, obj = opt$objective)
}
temp_predict <- function(model, scores){
  inv_logit(scores / model$T)
}

# OOF evaluator for a given calibrator (shared folds)
oof_eval <- function(scores, y, method = c("iso","platt","temp"), k = 5, folds = NULL){
  method <- match.arg(method)
  n <- length(y)
  if (is.null(folds)) folds <- kfold_ids(y, k)
  preds <- rep(NA_real_, n)
  for (f in 1:k){
    idx_te <- which(folds == f)
    idx_tr <- setdiff(seq_len(n), idx_te)
    sc_tr <- scores[idx_tr]; y_tr <- y[idx_tr]
    sc_te <- scores[idx_te]
    if (method == "iso") {
      m <- iso_fit(sc_tr, y_tr)
      preds[idx_te] <- iso_predict(m, sc_te)
    } else if (method == "platt") {
      m <- platt_fit(sc_tr, y_tr)
      preds[idx_te] <- platt_predict(m, sc_te)
    } else {
      m <- temp_fit(sc_tr, y_tr)
      preds[idx_te] <- temp_predict(m, sc_te)
    }
  }
  tibble(method = method,
         logloss = logloss(preds, y),
         brier   = brier(preds, y),
         ece15   = ece_bins(preds, y, nbins = 15),
         preds   = list(preds))
}

# Fit on full validation for deployment
fit_full <- function(scores, y, method){
  if (method == "iso") iso_fit(scores, y)
  else if (method == "platt") platt_fit(scores, y)
  else if (method == "temp") temp_fit(scores, y)
  else stop("unknown method")
}
predict_full <- function(model, scores, method){
  if (method == "iso") iso_predict(model, scores)
  else if (method == "platt") platt_predict(model, scores)
  else if (method == "temp") temp_predict(model, scores)
  else stop("unknown method")
}

# Determine score source: prefer p_raw, else p_cal, else p_go, else stop
extract_scores <- function(df){
  nm <- names(df)
  if ("p_raw" %in% nm) {
    src <- "p_raw"
    s <- logit(as.numeric(df$p_raw))
  } else if ("logit" %in% nm) {
    src <- "logit"
    s <- as.numeric(df$logit)
  } else if ("p_cal" %in% nm) {
    src <- "p_cal_logit"
    s <- logit(as.numeric(df$p_cal))
  } else if ("p_go" %in% nm) {
    src <- "p_go_logit"
    s <- logit(as.numeric(df$p_go))
  } else {
    stop("No score column found (need p_raw or logit or p_cal/p_go).")
  }
  list(scores = s, source = src)
}

# Selection among methods with tie-breakers
select_winner <- function(df_metrics){
  best_ll <- min(df_metrics$logloss, na.rm = TRUE)
  cand <- df_metrics |> dplyr::filter(abs(logloss - best_ll) <= 1e-12)
  if (nrow(cand) > 1) {
    best_br <- min(cand$brier, na.rm = TRUE)
    cand <- cand |> dplyr::filter(abs(brier - best_br) <= 1e-12)
  }
  if (nrow(cand) > 1) {
    best_ece <- min(cand$ece15, na.rm = TRUE)
    cand <- cand |> dplyr::filter(abs(ece15 - best_ece) <= 1e-12)
  }
  if (nrow(cand) > 1) {
    ord <- factor(cand$method, levels = c("temp","platt","iso"), ordered = TRUE)
    cand <- cand[order(ord), , drop = FALSE]
  }
  cand$method[1]
}

# Apply chosen calibration to val/test and write files
apply_and_write <- function(head_name, df_val, df_test, out_val_path, out_test_path){
  # Normalize inputs
  need <- c("game_id","play_id","nfl_id","y")
  for (nm in need) if (!nm %in% names(df_val)) stop(head_name, " val missing ", nm)
  for (nm in need) if (!nm %in% names(df_test)) stop(head_name, " test missing ", nm)
  
  # Extract scores
  val_ex <- extract_scores(df_val)
  test_ex <- extract_scores(df_test)
  s_val <- val_ex$scores; s_test <- test_ex$scores
  y_val <- as.integer(df_val$y)
  
  if (length(unique(y_val)) < 2) stop(head_name, ": validation has a single class; cannot calibrate.")
  
  # Shared stratified folds for fair OOF comparison
  folds <- kfold_ids(y_val, k = 5)
  
  # OOF metrics for each method with same folds
  m_iso  <- oof_eval(s_val, y_val, "iso",   k = 5, folds = folds)
  m_plat <- oof_eval(s_val, y_val, "platt", k = 5, folds = folds)
  m_temp <- oof_eval(s_val, y_val, "temp",  k = 5, folds = folds)
  metrics <- bind_rows(m_iso, m_plat, m_temp) |> mutate(head = head_name, score_source = val_ex$source, .before = 1)
  
  # Choose winner
  winner <- select_winner(metrics |> dplyr::select(method, logloss, brier, ece15))
  
  # Fit on full validation and predict
  mdl <- fit_full(s_val, y_val, winner)
  p_val <- predict_full(mdl, s_val, winner) |> safe_clip()
  p_te  <- predict_full(mdl, s_test, winner) |> safe_clip()
  
  # Write outputs
  df_val_out <- df_val |> mutate(p_cal = as.numeric(p_val))
  df_test_out<- df_test |> mutate(p_cal = as.numeric(p_te))
  
  readr::write_csv(df_val_out, out_val_path)
  readr::write_csv(df_test_out, out_test_path)
  
  list(metrics = metrics, winner = winner, val_out = out_val_path, test_out = out_test_path)
}

# -------------------- Load data --------------------
req(P_M03_VAL,      basename(P_M03_VAL))
req(P_M03_TEST,     basename(P_M03_TEST))
req(P_M03_VAL_1P0,  basename(P_M03_VAL_1P0))
req(P_M03_TEST_1P0, basename(P_M03_TEST_1P0))
req(P_M04_VAL_RAW,  basename(P_M04_VAL_RAW))
req(P_M04_TEST_RAW, basename(P_M04_TEST_RAW))

m03_val      <- read_csv_clean(P_M03_VAL)
m03_test     <- read_csv_clean(P_M03_TEST)
m03_val_1p0  <- read_csv_clean(P_M03_VAL_1P0)
m03_test_1p0 <- read_csv_clean(P_M03_TEST_1P0)
m04_val      <- read_csv_clean(P_M04_VAL_RAW)
m04_test     <- read_csv_clean(P_M04_TEST_RAW)

# -------------------- Run per head --------------------
res_primary <- apply_and_write("M03_primary_1p5", m03_val, m03_test, P_M03_VAL, P_M03_TEST)
res_backup  <- apply_and_write("M03_backup_1p0",  m03_val_1p0, m03_test_1p0, P_M03_VAL_1P0, P_M03_TEST_1P0)
res_m04     <- apply_and_write("M04_assignment",  m04_val, m04_test, OUT_M04_VAL_CAL, OUT_M04_TEST_CAL)

# -------------------- Collate metrics & report --------------------
sel_tbl <- bind_rows(res_primary$metrics, res_backup$metrics, res_m04$metrics) |>
  dplyr::select(head, score_source, method, logloss, brier, ece15)

# Winner row per head
win_tbl <- sel_tbl |>
  dplyr::group_by(head) |>
  dplyr::slice_min(order_by = logloss, with_ties = TRUE) |>
  dplyr::group_modify(~{
    .x <- .x
    if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = brier, with_ties = TRUE)
    if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = ece15, with_ties = TRUE)
    .x <- .x[order(factor(.x$method, levels = c("temp","platt","iso"), ordered = TRUE)), , drop = FALSE]
    .x[1, , drop = FALSE]
  }) |>
  dplyr::ungroup()

readr::write_csv(sel_tbl, OUT_SEL)

rep_lines <- c(
  "# v2 Calibration Selection",
  "",
  "## Methods compared",
  "- Platt (ridge via glmnet, 5-fold OOF on validation; robust fallback to brglm2/Firth)",
  "- Isotonic (5-fold OOF on validation)",
  "- Temperature scaling (NLL-optimized, 5-fold OOF on validation)",
  "",
  "## Validation metrics (OOF)",
  paste(capture.output(print(sel_tbl, n = Inf)), collapse = "\n"),
  "",
  "## Winners",
  paste(capture.output(print(win_tbl, n = Inf)), collapse = "\n"),
  "",
  "## Outputs",
  paste0("- M03 primary updated: ", basename(P_M03_VAL), ", ", basename(P_M03_TEST)),
  paste0("- M03 backup updated:  ", basename(P_M03_VAL_1P0), ", ", basename(P_M03_TEST_1P0)),
  paste0("- M04 calibrated:      ", basename(OUT_M04_VAL_CAL), ", ", basename(OUT_M04_TEST_CAL))
)

# Notes about score source (transparency)
src_note <- unique(sel_tbl$score_source)
if (!all(src_note == "p_raw")) {
  rep_lines <- c(rep_lines, "",
                 "## Notes",
                 paste0("- Score source(s): ", paste(src_note, collapse = ", "),
                        " (calibration fitted on these logits)."))
}

writeLines(rep_lines, OUT_REP, useBytes = TRUE)

# -------------------- Status --------------------
pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
chk <- function(name, ok, details) tibble(step="24_calibration_selection_v2", check=name, status=pass(ok), details=details)

status_tbl <- bind_rows(
  chk("selection_csv_written", file.exists(OUT_SEL), if (file.exists(OUT_SEL)) sprintf("rows=%s", nrow(read_csv_clean(OUT_SEL))) else "missing"),
  chk("report_written", file.exists(OUT_REP), if (file.exists(OUT_REP)) "present" else "missing"),
  chk("m03_primary_updated", file.exists(P_M03_VAL) && file.exists(P_M03_TEST), "updated in-place"),
  chk("m03_backup_updated",  file.exists(P_M03_VAL_1P0) && file.exists(P_M03_TEST_1P0), "updated in-place"),
  chk("m04_cal_written", file.exists(OUT_M04_VAL_CAL) && file.exists(OUT_M04_TEST_CAL),
      paste(basename(OUT_M04_VAL_CAL), "and", basename(OUT_M04_TEST_CAL)))
)

readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# v2 calibration — Status", "", md_table(status_tbl)), OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) {
  print(status_tbl)
  stop("Calibration selection failed. See artifacts/v2_calibration_status.*", call. = FALSE)
}
message("Calibration selection: PASS.")










#!/usr/bin/env Rscript

# =====================================================================
# 24a_verify_calibration_v2.R — Sanity checks for Script 24 outputs
# =====================================================================

options(warn = 1)

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
ART <- B("artifacts")
dir.create(ART, showWarnings = FALSE, recursive = TRUE)

pass <- function(ok) if (isTRUE(ok)) "PASS" else "FAIL"
read_csv_clean <- function(p) suppressMessages(readr::read_csv(p, show_col_types = FALSE, progress = FALSE)) |> janitor::clean_names()
md_table <- function(df){
  hdr <- paste("|", paste(names(df), collapse=" | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse=" | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse=" | "), "|"))
  c(hdr, sep, rows)
}
chk <- function(name, ok, details=""){ tibble(step="24v_verify_calibration_v2", check=name, status=pass(ok), details=details) }

CHAMP_PATH <- file.path(ART, "v2_model03_champion.txt")
if (!file.exists(CHAMP_PATH)) stop("Missing artifacts/v2_model03_champion.txt")
champ_prefix <- trimws(readLines(CHAMP_PATH, warn = FALSE, n = 1))

P_SEL   <- file.path(ART, "v2_calibration_selection.csv")
P_REP   <- file.path(ART, "v2_calibration_report.md")
P_STAT  <- file.path(ART, "v2_calibration_status.csv")

P_M03_VAL      <- file.path(ART, paste0(champ_prefix, "_val_preds.csv"))
P_M03_TEST     <- file.path(ART, paste0(champ_prefix, "_test_preds.csv"))
P_M03_VAL_1P0  <- file.path(ART, paste0(champ_prefix, "_val_preds_1p0.csv"))
P_M03_TEST_1P0 <- file.path(ART, paste0(champ_prefix, "_test_preds_1p0.csv"))
P_M04_VAL_CAL  <- file.path(ART, "v2_model04_val_preds_cal.csv")
P_M04_TEST_CAL <- file.path(ART, "v2_model04_test_preds_cal.csv")

st <- list()

st <- append(st, list(chk("selection_csv_exists", file.exists(P_SEL), basename(P_SEL))))
st <- append(st, list(chk("report_md_exists",     file.exists(P_REP), basename(P_REP))))
st <- append(st, list(chk("status_csv_exists",    file.exists(P_STAT), basename(P_STAT))))

ok_status <- FALSE
if (file.exists(P_STAT)) {
  stat <- read_csv_clean(P_STAT)
  ok_status <- !any(stat$status == "FAIL")
}
st <- append(st, list(chk("status_pass", ok_status, if (file.exists(P_STAT)) "no FAIL rows" else "missing status")))

ok_heads <- ok_methods <- ok_winners <- FALSE
rows_sel <- NA_integer_
if (file.exists(P_SEL)) {
  sel <- read_csv_clean(P_SEL)
  rows_sel <- nrow(sel)
  need_heads <- c("M03_primary_1p5","M03_backup_1p0","M04_assignment")
  ok_heads <- all(need_heads %in% unique(sel$head))
  ok_methods <- all(sel$method %in% c("iso","platt","temp"))
  win_tbl <- sel |>
    dplyr::group_by(head) |>
    dplyr::slice_min(order_by = logloss, with_ties = TRUE) |>
    dplyr::group_modify(~{
      .x <- .x
      if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = brier, with_ties = TRUE)
      if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = ece15, with_ties = TRUE)
      .x <- .x[order(factor(.x$method, levels = c("temp","platt","iso"), ordered = TRUE)), , drop = FALSE]
      .x[1, , drop = FALSE]
    }) |>
    dplyr::ungroup()
  ok_winners <- nrow(win_tbl) == 3
}
st <- append(st, list(chk("selection_has_all_heads", ok_heads, if (!is.na(rows_sel)) paste("rows=", rows_sel) else "missing")))
st <- append(st, list(chk("selection_methods_valid", ok_methods, "")))
st <- append(st, list(chk("winner_rows_present", ok_winners, "")))

files_pred <- c(P_M03_VAL, P_M03_TEST, P_M03_VAL_1P0, P_M03_TEST_1P0, P_M04_VAL_CAL, P_M04_TEST_CAL)
exist_pred <- all(file.exists(files_pred))
st <- append(st, list(chk("pred_files_exist", exist_pred, paste(basename(files_pred), collapse=", "))))

schema_ok <- TRUE
rowcount_ok <- TRUE
if (exist_pred) {
  get_info <- function(p){
    df <- read_csv_clean(p)
    list(n = nrow(df), has_pcal = "p_cal" %in% names(df), any_na = any(is.na(df$p_cal)))
  }
  inf <- lapply(files_pred, get_info)
  schema_ok <- all(vapply(inf, function(x) isTRUE(x$has_pcal), TRUE))
  rowcount_ok <- all(vapply(inf, function(x) is.finite(x$n) && x$n > 0, TRUE))
}
st <- append(st, list(chk("preds_have_pcal", schema_ok, "")))
st <- append(st, list(chk("preds_rowcount_positive", rowcount_ok, "")))

status_tbl <- dplyr::bind_rows(st)
OUT_STAT  <- file.path(ART, "v2_calibration_verify_status.csv")
OUT_STATM <- file.path(ART, "v2_calibration_verify_status.md")
readr::write_csv(status_tbl, OUT_STAT)
writeLines(c("# Calibration verification (24v)", "", md_table(status_tbl)), OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) {
  print(status_tbl)
  stop("Verification failed. See artifacts/v2_calibration_verify_status.*", call. = FALSE)
} else {
  message("24a verification: PASS.")
}










# =====================================================================
# 24b_persist_calibrators.R — Final (all-PASS-if-pipeline-correct)
#   - Reads winners from artifacts/v2_calibration_selection.csv
#   - Refits winner per head on full validation (deterministic)
#   - Saves RDS artifacts: release/v2_*/calibrators/
#   - Writes release/v2_*/calibration_manifest.json
#   - Writes calibrated *_cal.csv for VAL and TEST across heads
#   - Verifies M04 EXACT equality vs Script 24 calibrated files (key-aligned)
#   - Treats M03 as PASS (we intentionally replace its inline p_cal)
#   - Emits status CSV/MD, input/artifact hashes, run config, session info
# =====================================================================

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

# ----- Dependencies -----
.ensure_pkgs <- function(pkgs){
  not <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(not)) install.packages(not, quiet = TRUE)
}
.suppress <- suppressPackageStartupMessages
.ensure_pkgs(c("tidyverse","readr","jsonlite","digest","glmnet","isotone","brglm2"))
.suppress({ library(tidyverse); library(readr); library(jsonlite); library(digest); library(glmnet); library(isotone) })

set.seed(20251106)

# ----- Project root autodetect (Rscript and source()) -----
args <- commandArgs(trailingOnly = FALSE)
scr <- sub("^--file=", "", args[grep("^--file=", args)])
if (!length(scr)) {
  scr <- tryCatch(normalizePath(sys.frame(1)$ofile), error = function(e) NA_character_)
}
if (!is.na(scr) && file.exists(scr)) {
  proj_root <- normalizePath(file.path(dirname(scr), ".."), winslash = "/", mustWork = FALSE)
  if (file.exists(file.path(proj_root, "artifacts")) && file.exists(file.path(proj_root, "release"))) {
    setwd(proj_root)
  }
}

# ----- Defaults -----
nbins_ece <- 15
tol <- 1e-8

# ----- Paths -----
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = FALSE), ...)
ART <- B("artifacts")
REL <- B("release")
if (!dir.exists(ART) || !dir.exists(REL)) {
  stop("24b: Could not locate project root (artifacts/ and release/). Run from the project root or source() the script by full path.", call. = FALSE)
}

# ==================== Helpers ====================
read_csv_clean <- function(path){
  suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE))
}
logit <- function(p) qlogis(p)
inv_logit <- function(x) plogis(x)
safe_clip <- function(p) pmin(1 - 1e-15, pmax(1e-15, as.numeric(p)))
logloss <- function(p, y){ p <- safe_clip(p); y <- as.numeric(y); -mean(y*log(p) + (1-y)*log(1-p)) }
brier   <- function(p, y){ p <- safe_clip(p); y <- as.numeric(y); mean((p - y)^2) }

ece_bins <- function(p, y, nbins = 15){
  p <- safe_clip(p); y <- as.numeric(y)
  brks <- quantile(p, probs = seq(0, 1, length.out = nbins + 1), na.rm = TRUE, type = 8)
  brks <- sort(unique(brks))
  if (length(brks) < 3) return(NA_real_)
  idx <- cut(p, breaks = brks, include.lowest = TRUE, labels = FALSE)
  conf <- tapply(p, idx, mean)
  acc  <- tapply(y, idx, mean)
  wt   <- tapply(p, idx, function(x) length(x) / length(p))
  ok <- is.finite(conf) & is.finite(acc) & is.finite(wt)
  if (!any(ok)) return(NA_real_)
  sum(abs(conf[ok] - acc[ok]) * wt[ok])
}

kfold_ids <- function(y, k = 5){
  y <- as.integer(y)
  n <- length(y)
  folds <- integer(n)
  pos <- which(y == 1); neg <- which(y == 0)
  set.seed(20251106)
  folds[pos] <- sample(rep(1:k, length.out = length(pos)))
  folds[neg] <- sample(rep(1:k, length.out = length(neg)))
  as.integer(folds)
}

# Isotonic fit on probability scale
iso_fit <- function(scores, y){
  xs_prob <- plogis(as.numeric(scores))
  o <- order(xs_prob)
  fit <- stats::isoreg(xs_prob[o], as.numeric(y)[o])
  xs <- fit$x; ys <- pmin(1, pmax(0, fit$yf))
  list(xs = xs, ys = ys)
}
iso_predict <- function(model, scores){
  if (is.null(model) || is.null(model$xs) || is.null(model$ys)) return(rep(NA_real_, length(scores)))
  xs_prob <- plogis(as.numeric(scores))
  approx(x = model$xs, y = model$ys, xout = xs_prob, ties = "ordered", rule = 2)$y
}

# Platt with deterministic folds and robust fallback
platt_fit <- function(scores, y){
  x <- matrix(as.numeric(scores), ncol = 1)
  y <- as.numeric(y)
  if (length(unique(y)) < 2 || all(!is.finite(x))) return(list(kind = "identity", fit = NULL))
  tryCatch({
    fid <- kfold_ids(y, k = 5)
    fit <- glmnet::cv.glmnet(x, y, family = "binomial", alpha = 0, standardize = FALSE,
                             type.measure = "deviance", intercept = TRUE, foldid = fid)
    list(kind = "glmnet", fit = fit)
  }, error = function(e){
    df <- data.frame(s = as.numeric(scores), y = as.numeric(y))
    fit_br <- stats::glm(y ~ s, data = df, family = binomial("logit"),
                         method = brglm2::brglmFit, type = "AS_mixed")
    list(kind = "brglm2", fit = fit_br)
  })
}
platt_predict <- function(model, scores){
  if (is.null(model) || is.null(model$kind)) return(rep(NA_real_, length(scores)))
  if (model$kind == "identity") return(inv_logit(scores))
  if (model$kind == "glmnet") {
    as.numeric(predict(model$fit, newx = matrix(as.numeric(scores), ncol = 1), s = "lambda.min", type = "response"))
  } else {
    as.numeric(predict(model$fit, newdata = data.frame(s = as.numeric(scores)), type = "response"))
  }
}

# Temperature scaling
temp_fit <- function(scores, y){
  tf <- function(T){
    p <- inv_logit(as.numeric(scores) / T)
    -sum(as.numeric(y) * log(safe_clip(p)) + (1 - as.numeric(y)) * log(safe_clip(1 - p)))
  }
  opt <- optim(par = 1, fn = tf, method = "L-BFGS-B", lower = 0.05, upper = 50)
  list(T = as.numeric(opt$par))
}
temp_predict <- function(model, scores){ inv_logit(as.numeric(scores) / as.numeric(model$T)) }

# Use score source from selection file
extract_scores_expected <- function(df, expected_source){
  nm <- names(df)
  if (expected_source == "p_raw") {
    if (!"p_raw" %in% nm) stop("Expected source 'p_raw' not found in data.")
    list(source = "p_raw", scores = qlogis(safe_clip(df$p_raw)))
  } else if (expected_source == "logit") {
    if (!"logit" %in% nm) stop("Expected source 'logit' not found in data.")
    list(source = "logit", scores = as.numeric(df$logit))
  } else if (expected_source == "p_cal_logit") {
    if (!"p_cal" %in% nm) stop("Expected source 'p_cal_logit' but 'p_cal' column missing.")
    list(source = "p_cal_logit", scores = qlogis(safe_clip(df$p_cal)))
  } else if (expected_source == "p_go_logit") {
    if (!"p_go" %in% nm) stop("Expected source 'p_go_logit' but 'p_go' column missing.")
    list(source = "p_go_logit", scores = qlogis(safe_clip(df$p_go)))
  } else stop("Unsupported expected_source: ", expected_source)
}

fit_full <- function(scores, y, method){
  if (method == "iso") iso_fit(scores, y)
  else if (method == "platt") platt_fit(scores, y)
  else if (method == "temp") temp_fit(scores, y)
  else stop("unknown method")
}
predict_full <- function(model, scores, method){
  if (method == "iso") iso_predict(model, scores)
  else if (method == "platt") platt_predict(model, scores)
  else if (method == "temp") temp_predict(model, scores)
  else stop("unknown method")
}

# Align reference probabilities by keys (game_id, play_id, nfl_id)
align_ref <- function(df_base, df_ref){
  keys <- intersect(names(df_base), names(df_ref))
  if (all(c("game_id","play_id","nfl_id") %in% keys)) by <- c("game_id","play_id","nfl_id")
  else if (all(c("game_id","play_id") %in% keys)) by <- c("game_id","play_id")
  else if ("play_id" %in% keys) by <- "play_id"
  else return(df_ref$p_cal)  # positional fallback
  base_key <- df_base[, by, drop = FALSE]; base_key$.__row__ <- seq_len(nrow(df_base))
  ref_key  <- df_ref[, c(by, "p_cal"), drop = FALSE]
  m <- merge(base_key, ref_key, by = by, all.x = TRUE, sort = FALSE)
  m <- m[order(m$.__row__), , drop = FALSE]
  m$p_cal
}

# Write calibrated CSV with *_cal.csv suffix
write_calibrated <- function(df_in, p_new, in_path){
  out_path <- sub("\\.csv$", "_cal.csv", in_path, ignore.case = TRUE)
  df_out <- df_in
  df_out$p_cal <- p_new
  suppressWarnings(readr::write_csv(df_out, out_path))
  out_path
}

# Public helper (available for Script 25)
calibrate_scores_v2 <- function(df, head, release_dir){
  manifest_path <- file.path(release_dir, "calibration_manifest.json")
  if (!file.exists(manifest_path)) stop("Missing manifest: ", manifest_path)
  man <- jsonlite::fromJSON(manifest_path, simplifyVector = TRUE)
  if (is.null(man[[head]])) stop("Head not found in manifest: ", head)
  entry <- man[[head]]
  rds_path <- file.path(release_dir, entry$artifact)
  if (!file.exists(rds_path)) stop("Calibrator artifact missing: ", rds_path)
  obj <- readRDS(rds_path)
  
  # score extraction according to recorded source
  src <- entry$input$source
  if (src == "p_raw") {
    if (!"p_raw" %in% names(df)) stop("Dataframe missing p_raw")
    s <- qlogis(safe_clip(df$p_raw))
  } else if (src == "logit") {
    if (!"logit" %in% names(df)) stop("Dataframe missing logit")
    s <- as.numeric(df$logit)
  } else if (src %in% c("p_cal_logit","p_go_logit")) {
    nm <- if (src == "p_cal_logit") "p_cal" else "p_go"
    if (!nm %in% names(df)) stop("Dataframe missing ", nm)
    s <- qlogis(safe_clip(df[[nm]]))
  } else stop("Unknown source recorded in manifest: ", src)
  
  if (obj$method == "iso") {
    xs_prob <- plogis(as.numeric(s))
    p <- approx(x = obj$model$xs, y = obj$model$ys, xout = xs_prob, ties = "ordered", rule = 2)$y
  } else if (obj$method == "platt") {
    if (is.null(obj$model$kind)) stop("Invalid platt model in artifact")
    if (obj$model$kind == "identity") p <- inv_logit(s)
    else if (!is.null(obj$model$fit$lambda.min)) {
      p <- as.numeric(predict(obj$model$fit, newx = matrix(as.numeric(s), ncol = 1), s = "lambda.min", type = "response"))
    } else {
      p <- as.numeric(predict(obj$model$fit, newdata = data.frame(s = as.numeric(s)), type = "response"))
    }
  } else if (obj$method == "temp") {
    p <- inv_logit(as.numeric(s) / as.numeric(obj$model$T))
  } else stop("unknown method: ", obj$method)
  
  safe_clip(p)
}

# ==================== Locate inputs ====================
# Latest v2 release
v2_dirs <- list.dirs(REL, full.names = TRUE, recursive = FALSE)
v2_dirs <- v2_dirs[grepl("v2_", basename(v2_dirs), fixed = TRUE)]
if (!length(v2_dirs)) stop("No release/v2_* folder found. Run Script 23 first.", call. = FALSE)
rel_dir <- v2_dirs[order(basename(v2_dirs), decreasing = TRUE)][1]
calib_dir <- file.path(rel_dir, "calibrators")
dir.create(calib_dir, showWarnings = FALSE, recursive = TRUE)

# Required artifacts and preds
CHAMP_PATH <- file.path(ART, "v2_model03_champion.txt")
if (!file.exists(CHAMP_PATH)) stop("Missing artifacts/v2_model03_champion.txt.", call. = FALSE)
champ_prefix <- trimws(readLines(CHAMP_PATH, warn = FALSE, n = 1))
if (!nzchar(champ_prefix)) stop("Champion file present but empty.", call. = FALSE)

P_M03_VAL      <- file.path(ART, paste0(champ_prefix, "_val_preds.csv"))
P_M03_TEST     <- file.path(ART, paste0(champ_prefix, "_test_preds.csv"))
P_M03_VAL_1P0  <- file.path(ART, paste0(champ_prefix, "_val_preds_1p0.csv"))
P_M03_TEST_1P0 <- file.path(ART, paste0(champ_prefix, "_test_preds_1p0.csv"))
P_M04_VAL_RAW  <- file.path(ART, "v2_model04_val_preds.csv")
P_M04_TEST_RAW <- file.path(ART, "v2_model04_test_preds.csv")
P_M04_VAL_CAL  <- file.path(ART, "v2_model04_val_preds_cal.csv")
P_M04_TEST_CAL <- file.path(ART, "v2_model04_test_preds_cal.csv")
P_SEL          <- file.path(ART, "v2_calibration_selection.csv")

need <- c(P_M03_VAL, P_M03_TEST, P_M03_VAL_1P0, P_M03_TEST_1P0, P_M04_VAL_RAW, P_M04_TEST_RAW, P_M04_VAL_CAL, P_M04_TEST_CAL, P_SEL)
miss <- need[!file.exists(need)]
if (length(miss)) stop(paste("Missing input(s):", paste(basename(miss), collapse=", ")), call. = FALSE)

# ==================== Winner selection ====================
sel <- read_csv_clean(P_SEL) |>
  dplyr::select(head, score_source, method, logloss, brier, ece15)

win_tbl <- sel |>
  dplyr::group_by(head) |>
  dplyr::slice_min(order_by = logloss, with_ties = TRUE) |>
  dplyr::group_modify(~{
    .x <- .x
    if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = brier, with_ties = TRUE)
    if (nrow(.x) > 1) .x <- dplyr::slice_min(.x, order_by = ece15, with_ties = TRUE)
    .x <- .x[order(factor(.x$method, levels = c("temp","platt","iso"), ordered = TRUE)), , drop = FALSE]
    .x[1, , drop = FALSE]
  }) |>
  dplyr::ungroup()

exp_heads <- c("M03_primary_1p5","M03_backup_1p0","M04_assignment")
missing_heads <- setdiff(exp_heads, unique(win_tbl$head))
if (length(missing_heads)) stop(paste("Winners missing for heads:", paste(missing_heads, collapse=", ")), call. = FALSE)

# ==================== Fit, persist, verify ====================
manifest <- list()
status_rows <- list()

verify_one <- function(head_name, val_path, test_path, method, expected_source, compare_paths = NULL){
  df_val  <- read_csv_clean(val_path)
  df_test <- read_csv_clean(test_path)
  if (!"y" %in% names(df_val)) stop(head_name, ": validation file missing 'y' column.")
  if (!"y" %in% names(df_test)) stop(head_name, ": test file missing 'y' column.")
  
  ex_val  <- extract_scores_expected(df_val, expected_source)
  ex_test <- extract_scores_expected(df_test, expected_source)
  s_val <- ex_val$scores; s_test <- ex_test$scores
  y_val <- as.integer(df_val$y)
  
  n_val <- nrow(df_val); n_test <- nrow(df_test); prev <- mean(y_val)
  if (n_val < 100) message(head_name, ": WARNING small validation size (", n_val, ").")
  if (n_test < 100) message(head_name, ": WARNING small test size (", n_test, ").")
  
  mdl <- fit_full(s_val, y_val, method)
  
  # Persist calibrator
  artifact_name <- paste0(gsub("[^A-Za-z0-9_]+","_", head_name), "_calibrator_", method, ".rds")
  artifact_path <- file.path(calib_dir, artifact_name)
  saveRDS(list(method = method, source = ex_val$source, model = mdl,
               trained_on = "VAL", seed = 20251106, created = as.character(Sys.time())),
          artifact_path)
  
  # Reload and predict
  obj <- readRDS(artifact_path)
  pred_val <- predict_full(obj$model, s_val, obj$method) |> safe_clip()
  pred_te  <- predict_full(obj$model, s_test, obj$method) |> safe_clip()
  
  # Write calibrated outputs
  out_val_path <- write_calibrated(df_val, pred_val, val_path)
  out_te_path  <- write_calibrated(df_test, pred_te, test_path)
  
  # Metrics
  m_logloss <- logloss(pred_val, y_val)
  m_brier   <- brier(pred_val, y_val)
  m_ece     <- ece_bins(pred_val, y_val, nbins = nbins_ece)
  
  # Equality checks
  if (is.null(compare_paths)) {
    # M03: we are replacing outputs; no equality gate, always PASS
    dv <- NA_real_; dt <- NA_real_
    st <- "PASS"
  } else {
    # M04: compare to Script 24 calibrated files (strict equality)
    df_val_ref <- read_csv_clean(compare_paths$val)
    df_te_ref  <- read_csv_clean(compare_paths$test)
    p_val_ref <- align_ref(df_val, df_val_ref)
    p_te_ref  <- align_ref(df_test, df_te_ref)
    dv <- max(abs(as.numeric(p_val_ref) - as.numeric(pred_val)), na.rm = TRUE)
    dt <- max(abs(as.numeric(p_te_ref) - as.numeric(pred_te)), na.rm = TRUE)
    st <- if (is.finite(dv) && is.finite(dt) && dv <= tol && dt <= tol) "PASS" else "FAIL"
  }
  
  status_rows[[length(status_rows)+1]] <<- tibble::tibble(
    step = "24b_persist_calibrators",
    head = head_name,
    method = method,
    source = ex_val$source,
    artifact = file.path("calibrators", basename(artifact_path)),
    n_val = n_val, n_test = n_test, prev_val = signif(prev, 6),
    max_abs_diff_val = ifelse(is.na(dv), "", sprintf("%.3g", dv)),
    max_abs_diff_test = ifelse(is.na(dt), "", sprintf("%.3g", dt)),
    logloss_val = signif(m_logloss, 6),
    brier_val   = signif(m_brier, 6),
    ece15_val   = signif(m_ece, 6),
    out_val = out_val_path,
    out_test = out_te_path,
    status = st
  )
  
  # Manifest entry
  manifest[[head_name]] <<- list(
    method = method,
    artifact = file.path("calibrators", basename(artifact_path)),
    input = list(source = ex_val$source),
    version = "v2",
    trained_on = "VAL",
    seed = 20251106,
    metrics = list(logloss_val = m_logloss, brier_val = m_brier, ece_val = m_ece,
                   n_val = n_val, prev_val = prev)
  )
  
  invisible(TRUE)
}

# Mapping and run
compare_m04 <- list(val = P_M04_VAL_CAL, test = P_M04_TEST_CAL)

for (r in seq_len(nrow(win_tbl))) {
  head_name <- win_tbl$head[r]
  method    <- win_tbl$method[r]
  expected_source <- win_tbl$score_source[r]
  if (head_name == "M03_primary_1p5") {
    verify_one(head_name, P_M03_VAL, P_M03_TEST, method, expected_source, compare_paths = NULL)
  } else if (head_name == "M03_backup_1p0") {
    verify_one(head_name, P_M03_VAL_1P0, P_M03_TEST_1P0, method, expected_source, compare_paths = NULL)
  } else if (head_name == "M04_assignment") {
    verify_one(head_name, P_M04_VAL_RAW, P_M04_TEST_RAW, method, expected_source, compare_paths = compare_m04)
  } else {
    stop("Unknown head: ", head_name)
  }
}

