writeLines(jsonlite::toJSON(manifest, pretty = TRUE, auto_unbox = TRUE), manifest_path, useBytes = TRUE)

hash_file <- function(p){
  if (!file.exists(p)) return(NA_character_)
  digest::digest(file = p, algo = "sha256")
}
