  cat("Calibrator artifacts written: ", length(artifacts_written), "\n", sep = "")
  cat("Manifest: ", manifest_path, "\n", sep = "")
  cat("Status CSV: ", OUT_STAT, "\n", sep = "")
  cat("Status MD: ", OUT_STATM, "\n", sep = "")
  cat("Input hashes: ", file.path(ART, "v2_calibration_input_hashes.json"), "\n", sep = "")
  cat("Artifact hashes: ", file.path(ART, "v2_calibration_artifact_hashes.json"), "\n", sep = "")
  cat("==============================================\n\n")
  invisible(status_tbl)
}










#!/usr/bin/env Rscript
# =====================================================================
# Script 24c — Reliability & Robustness Suite (Calibration CIs, Threshold Uncertainty, Subgroups, Shift)
# Purpose
#   Quantify and visualize how well probabilities behave before and after calibration, with uncertainty.
#   Check stability across subgroups and guard against data shift.
#   Produce a PASS/WARN/FAIL gate for moving to Script 25.
#
# Inputs (defaults; override via CLI)
#   artifacts/{head}_val_preds.csv
#   artifacts/{head}_val_preds_cal.csv
#   artifacts/{head}_test_preds.csv
#   artifacts/{head}_test_preds_cal.csv
#   release/v2_*/operating_points.json (for p* thresholds)
#   release/v2_*/calibration_manifest.json
#   Optional “incoming batch”: score/incoming_batch_scores.csv with a raw score/prob/logit col.
#
# Outputs
#   Reliability diagrams, bootstrap ECE/LogLoss/Brier CIs, threshold uncertainty sweeps/bootstraps,
#   subgroup diagnostics, shift diagnostics (PSI/KS), and a single gate CSV/MD.
# =====================================================================

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  warn = 1,
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

set.seed(2026L)  # deterministic bootstrap CIs for reliability suite

# ---------- Dependencies ----------
.ensure_pkgs <- function(pkgs){
  not <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(not)) install.packages(not, quiet = TRUE)
}
.suppress <- suppressPackageStartupMessages
.ensure_pkgs(c("data.table","readr","jsonlite","ggplot2","scales","patchwork","digest","isotone"))
.suppress({ library(data.table); library(readr); library(jsonlite); library(ggplot2); library(scales); library(patchwork); library(digest); library(isotone) })

# ---------- CLI parsing (simple) ----------
argv <- commandArgs(trailingOnly = TRUE)
arg_val <- function(key, default = NULL){
  m <- which(argv == key)
  if (length(m) && m < length(argv)) return(argv[m+1])
  default
}
has_flag <- function(key) any(argv == key)

VAL_DIR   <- arg_val("--val-dir", "artifacts")
TEST_DIR  <- arg_val("--test-dir", "artifacts")
REL_DIR   <- arg_val("--release-dir", NA_character_)
HEADS     <- strsplit(arg_val("--heads", "M03_primary_1p5,M03_backup_1p0,M04_assignment"), ",")[[1]]
LABEL_COL <- arg_val("--label-col", "y")
PRE_COL   <- arg_val("--pre-col", "p_raw")
POST_COL  <- arg_val("--post-col", "p_cal")
NBINS     <- as.integer(arg_val("--bins", "15"))
BBOOTS    <- as.integer(arg_val("--boots", if (has_flag("--fast")) "200" else "500"))
OBJ       <- toupper(arg_val("--pstar-objective", "F1"))
INCOMING  <- arg_val("--incoming", NA_character_)
IN_COL    <- arg_val("--incoming-col", NA_character_)
IN_IS_LOGIT <- has_flag("--incoming-is-logit")
SUBGROUP_LIST <- arg_val("--subgroups", NA_character_)
FAST      <- has_flag("--fast")

# ---------- Project root autodetect ----------
# If release dir not provided, take latest v2_* under release/
if (is.na(REL_DIR) || !dir.exists(REL_DIR)) {
  rel_root <- "release"
  if (!dir.exists(rel_root)) stop("24c: release/ not found. Provide --release-dir.")
  v2_dirs <- list.dirs(rel_root, full.names = TRUE, recursive = FALSE)
  v2_dirs <- v2_dirs[grepl("v2_", basename(v2_dirs), fixed = TRUE)]
  if (!length(v2_dirs)) stop("24c: No release/v2_* folder found. Provide --release-dir.")
  REL_DIR <- v2_dirs[order(basename(v2_dirs), decreasing = TRUE)][1]
}

# ---------- Output dirs ----------
DIR_RELI <- file.path("artifacts", "v2_reliability")
DIR_TU   <- file.path("artifacts", "v2_threshold_uncertainty")
DIR_SG   <- file.path("artifacts", "v2_subgroups")
