# ---------- Helpers ----------
safe_clip <- function(p) pmin(1 - 1e-15, pmax(1e-15, as.numeric(p)))
logloss <- function(p, y){ p <- safe_clip(p); y <- as.numeric(y); -mean(y*log(p) + (1-y)*log(1-p)) }
brier   <- function(p, y){ p <- safe_clip(p); y <- as.numeric(y); mean((p - y)^2) }

# Equal-count bins with fallback to equal-width if ties collapse
make_bins <- function(prob, nbins = 15){
  prob <- safe_clip(prob)
  brks <- unique(quantile(prob, probs = seq(0, 1, length.out = nbins + 1), na.rm = TRUE, type = 8))
  if (length(brks) < 3) brks <- seq(0, 1, length.out = nbins + 1)
  brks[1] <- 0; brks[length(brks)] <- 1
  brks
}

reldiag_stats <- function(prob, y, nbins = 15){
  prob <- safe_clip(prob); y <- as.numeric(y)
  brks <- make_bins(prob, nbins)
  idx <- cut(prob, breaks = brks, include.lowest = TRUE, labels = FALSE)
  DT <- data.table(bin = idx, prob = prob, y = y)
  agg <- DT[, .(conf = mean(prob), acc = mean(y), n = .N), by = bin][order(bin)]
  agg$bin_lo <- head(brks, -1)[agg$bin]
  agg$bin_hi <- tail(brks, -1)[agg$bin]
  agg
}

reldiag_stats_with_brks <- function(prob, y, brks){
  prob <- pmin(1-1e-15, pmax(1e-15, as.numeric(prob))); y <- as.numeric(y)
  idx <- cut(prob, breaks = brks, include.lowest = TRUE, labels = FALSE)
  DT <- data.table(bin = idx, prob = prob, y = y)
  agg <- DT[, .(conf = mean(prob), acc = mean(y), n = .N), by = bin][order(bin)]
  agg$bin_lo <- head(brks, -1)[agg$bin]; agg$bin_hi <- tail(brks, -1)[agg$bin]
  agg
}

ece_from_bins <- function(bin_df){
  if (!nrow(bin_df)) return(NA_real_)
  w <- bin_df$n / sum(bin_df$n)
  sum(abs(bin_df$acc - bin_df$conf) * w)
}

bootstrap_metrics <- function(prob, y, nb = 500, nbins = 15){
  prob <- safe_clip(prob); y <- as.numeric(y)
  n <- length(y)
  if (n < 200) return(list(ece_ci = c(NA,NA), brier_ci = c(NA,NA), logloss_ci = c(NA,NA), ece = NA, brier = NA, logloss = NA))
  # stratified resampling by label
  idx_pos <- which(y == 1); idx_neg <- which(y == 0)
  B_ece <- numeric(nb); B_brier <- numeric(nb); B_logloss <- numeric(nb)
  for (b in seq_len(nb)){
    s_pos <- if (length(idx_pos)) sample(idx_pos, length(idx_pos), replace = TRUE) else integer(0)
    s_neg <- if (length(idx_neg)) sample(idx_neg, length(idx_neg), replace = TRUE) else integer(0)
    s <- c(s_pos, s_neg)
    pd <- prob[s]; yd <- y[s]
    bins <- reldiag_stats(pd, yd, nbins)
    B_ece[b] <- ece_from_bins(bins)
    B_brier[b] <- brier(pd, yd)
    B_logloss[b] <- logloss(pd, yd)
  }
  list(
    ece_ci = quantile(B_ece, c(0.025, 0.975), na.rm = TRUE, names = FALSE),
    brier_ci = quantile(B_brier, c(0.025, 0.975), na.rm = TRUE, names = FALSE),
    logloss_ci = quantile(B_logloss, c(0.025, 0.975), na.rm = TRUE, names = FALSE),
    ece = ece_from_bins(reldiag_stats(prob, y, nbins)),
    brier = brier(prob, y),
    logloss = logloss(prob, y)
  )
}

plot_reldiag <- function(pre_bins, post_bins, out_png){
  # Reliability curve: x=confidence, y=accuracy; 45-degree reference
  g <- ggplot() +
    geom_abline(slope = 1, intercept = 0, linetype = "dashed") +
    geom_line(data = pre_bins, aes(x = conf, y = acc), linewidth = 0.9, alpha = 0.7) +
    geom_point(data = pre_bins, aes(x = conf, y = acc), size = 1.5, alpha = 0.7) +
    geom_line(data = post_bins, aes(x = conf, y = acc), linewidth = 1.0) +
    geom_point(data = post_bins, aes(x = conf, y = acc), size = 1.7) +
    coord_cartesian(xlim = c(0,1), ylim = c(0,1)) +
    labs(x = "Confidence (mean p)", y = "Observed accuracy", title = "Reliability diagram: pre (thin) vs post (thick)") +
    theme_minimal(base_size = 12)
  ggsave(out_png, g, width = 6.5, height = 5.0, dpi = 120)
}

plot_delta <- function(pre_bins, post_bins, out_png){
  df <- merge(pre_bins[, .(bin, conf_pre = conf, acc_pre = acc, n_pre = n)],
              post_bins[, .(bin, conf_post = conf, acc_post = acc, n_post = n)],
              by = "bin", all = TRUE)
  df$delta <- (df$acc_post - df$conf_post) - (df$acc_pre - df$conf_pre)
  g <- ggplot(df, aes(x = bin, y = delta)) +
    geom_hline(yintercept = 0, linetype = "dashed") +
    geom_col(width = 0.8) +
    labs(x = "Bin", y = "Post minus pre (calibration error)", title = "Calibration delta by bin") +
    theme_minimal(base_size = 12)
  ggsave(out_png, g, width = 6.5, height = 4.0, dpi = 120)
}

# Threshold metrics on grid
th_metrics <- function(prob, y, thr){
  y <- as.integer(y); pred <- as.integer(prob >= thr)
  tp <- sum(pred == 1 & y == 1); fp <- sum(pred == 1 & y == 0)
  tn <- sum(pred == 0 & y == 0); fn <- sum(pred == 0 & y == 1)
  precision <- if ((tp+fp)==0) NA_real_ else tp/(tp+fp)
  recall <- if ((tp+fn)==0) NA_real_ else tp/(tp+fn)
  f1 <- if (is.na(precision) || is.na(recall) || (precision+recall)==0) NA_real_ else 2*precision*recall/(precision+recall)
  tpr <- recall
  fpr <- if ((fp+tn)==0) NA_real_ else fp/(fp+tn)
  spec <- if ((tn+fp)==0) NA_real_ else tn/(tn+fp)
  data.table(threshold = thr, precision = precision, recall = recall, F1 = f1, TPR = tpr, FPR = fpr, specificity = spec)
}

threshold_sweep <- function(prob, y, pstar, objective = "F1", step = 0.002, span = 0.1){
  grid <- seq(max(0, pstar - span), min(1, pstar + span), by = step)
  rbindlist(lapply(grid, function(t) th_metrics(prob, y, t)))
}

threshold_boot <- function(prob, y, pstar, objective = "F1", nb = 500, step = 0.002, span = 0.1){
  n <- length(y); idx_pos <- which(y==1); idx_neg <- which(y==0)
  best_thr <- numeric(nb)
  for (b in seq_len(nb)){
    s_pos <- if (length(idx_pos)) sample(idx_pos, length(idx_pos), replace = TRUE) else integer(0)
    s_neg <- if (length(idx_neg)) sample(idx_neg, length(idx_neg), replace = TRUE) else integer(0)
    s <- c(s_pos, s_neg)
    sw <- threshold_sweep(prob[s], y[s], pstar, objective = objective, step = step, span = span)
    obj <- sw[[objective]]
    j <- suppressWarnings(which.max(obj))
    best_thr[b] <- if (length(j) && length(sw$threshold) >= j) sw$threshold[j] else pstar
  }
  data.table(pstar_boot = best_thr)
}

# PSI and KS
psi_equal_width <- function(base, comp, bins = 10){
  base <- as.numeric(base); comp <- as.numeric(comp)
  lo <- min(base, na.rm = TRUE); hi <- max(base, na.rm = TRUE)
  if (!is.finite(lo) || !is.finite(hi) || lo == hi) return(list(psi = NA_real_, table = data.table()))
  edges <- seq(lo, hi, length.out = bins + 1)
  b_ct <- hist(base, breaks = edges, plot = FALSE)$counts
  c_ct <- hist(comp, breaks = edges, plot = FALSE)$counts
  b_p <- pmax(b_ct / sum(b_ct), 1e-6)
  c_p <- pmax(c_ct / sum(c_ct), 1e-6)
  PSI <- sum((c_p - b_p) * log(c_p / b_p))
  tab <- data.table(bin = seq_len(bins), base_ct = b_ct, comp_ct = c_ct, base_p = b_p, comp_p = c_p)
  list(psi = PSI, table = tab)
}

ks_2sample <- function(base, comp){
  base <- as.numeric(base); comp <- as.numeric(comp)
  suppressWarnings({
    tt <- try(stats::ks.test(base, comp), silent = TRUE)
  })
  if (inherits(tt, "try-error")) return(list(D = NA_real_, p = NA_real_))
  list(D = as.numeric(tt$statistic), p = as.numeric(tt$p.value))
}

# Utility
read_json_safely <- function(p){
  if (!file.exists(p)) return(NULL)
  tryCatch(jsonlite::fromJSON(p, simplifyVector = TRUE), error = function(e) NULL)
}

# Resolve per-head files with fallbacks for known patterns
resolve_files <- function(head){
  # Primary attempt: head_* naming
  val_pre  <- file.path(VAL_DIR,  paste0(head, "_val_preds.csv"))
  val_post <- file.path(VAL_DIR,  paste0(head, "_val_preds_cal.csv"))
  te_pre   <- file.path(TEST_DIR, paste0(head, "_test_preds.csv"))
  te_post  <- file.path(TEST_DIR, paste0(head, "_test_preds_cal.csv"))
  if (file.exists(val_pre) && file.exists(val_post) && file.exists(te_pre) && file.exists(te_post)) {
    return(list(val_pre = val_pre, val_post = val_post, te_pre = te_pre, te_post = te_post))
  }
  # M03 mapping via champion
  champ_file <- file.path("artifacts", "v2_model03_champion.txt")
  if (grepl("^M03_", head) && file.exists(champ_file)){
    champ <- trimws(readLines(champ_file, warn = FALSE, n = 1))
    if (head == "M03_primary_1p5"){
      vpre  <- file.path("artifacts", paste0(champ, "_val_preds.csv"))
      vpost <- file.path("artifacts", paste0(champ, "_val_preds_cal.csv"))
      tpre  <- file.path("artifacts", paste0(champ, "_test_preds.csv"))
      tpost <- file.path("artifacts", paste0(champ, "_test_preds_cal.csv"))
      if (all(file.exists(c(vpre,vpost,tpre,tpost)))) return(list(val_pre=vpre,val_post=vpost,te_pre=tpre,te_post=tpost))
    }
    if (head == "M03_backup_1p0"){
      vpre  <- file.path("artifacts", paste0(champ, "_val_preds_1p0.csv"))
      vpost <- file.path("artifacts", paste0(champ, "_val_preds_1p0_cal.csv"))
      tpre  <- file.path("artifacts", paste0(champ, "_test_preds_1p0.csv"))
      tpost <- file.path("artifacts", paste0(champ, "_test_preds_1p0_cal.csv"))
      if (all(file.exists(c(vpre,vpost,tpre,tpost)))) return(list(val_pre=vpre,val_post=vpost,te_pre=tpre,te_post=tpost))
    }
  }
  # M04 mapping
  if (head == "M04_assignment"){
    vpre  <- file.path("artifacts", "v2_model04_val_preds.csv")
    vpost <- file.path("artifacts", "v2_model04_val_preds_cal.csv")
    tpre  <- file.path("artifacts", "v2_model04_test_preds.csv")
    tpost <- file.path("artifacts", "v2_model04_test_preds_cal.csv")
    if (all(file.exists(c(vpre,vpost,tpre,tpost)))) return(list(val_pre=vpre,val_post=vpost,te_pre=tpre,te_post=tpost))
  }
  stop("24c: Could not resolve file paths for head: ", head)
}

# Find p* from operating_points.json; fallback 0.5
get_pstar <- function(head, rel_dir, objective = "F1"){
  op_path <- file.path(rel_dir, "operating_points.json")
  op <- read_json_safely(op_path)
  if (is.null(op)) return(0.5)
  # Try nested head -> objective -> pstar; else flat per head
  if (!is.null(op[[head]])){
    if (!is.null(op[[head]][[objective]]) && !is.null(op[[head]][[objective]]$pstar)) return(as.numeric(op[[head]][[objective]]$pstar))
    if (!is.null(op[[head]]$pstar)) return(as.numeric(op[[head]]$pstar))
  }
  # Try objective at root
  if (!is.null(op[[objective]]) && !is.null(op[[objective]]$pstar)) return(as.numeric(op[[objective]]$pstar))
  0.5
}

# Choose prob column; if missing, try common fallbacks (logit -> plogis)
choose_prob_col <- function(DT, desired){
  if (!is.null(desired) && desired %in% names(DT)) return(list(prob = DT[[desired]], src = desired))
  for (cand in c("p_raw","p","prob","probability","p_go","p_cal")){
    if (cand %in% names(DT)) {
      v <- DT[[cand]]
      if (grepl("logit", cand, fixed = TRUE)) v <- plogis(v)
      return(list(prob = v, src = cand))
    }
  }
  # try logit
  if ("logit" %in% names(DT)) return(list(prob = plogis(DT$logit), src = "logit"))
  stop("24c: Could not locate a probability-like column in predictions file.")
}

# Subgroup candidates: categorical (<=20 unique) columns, excluding IDs and prob/label
find_subgroup_cols <- function(DT, label_col, pre_col, post_col, explicit = NULL){
  if (!is.null(explicit) && !is.na(explicit) && nzchar(explicit)) {
    xs <- strsplit(explicit, ",")[[1]]
    return(xs[xs %in% names(DT)])
  }
  bad <- tolower(c(label_col, pre_col, post_col,
                   "game_id","play_id","nfl_id","id","player_id","season","week","datetime"))
  keep <- character(0)
  for (nm in names(DT)){
    nm_low <- tolower(nm)
    if (nm_low %in% bad) next
    v <- DT[[nm]]
    if (is.character(v) || is.factor(v)) {
      u <- length(unique(v))
      if (u >= 2 && u <= 20) keep <- c(keep, nm)
    } else if (is.integer(v) || is.numeric(v)) {
      u <- length(unique(v))
      if (u >= 2 && u <= 20) keep <- c(keep, nm)
    }
  }
  unique(keep)
}

# ---------- Main per-head routine ----------
MIN_SUB_N <- 200

process_head <- function(head){
  files <- resolve_files(head)
  # Read data
  VAL_PRE  <- suppressMessages(readr::read_csv(files$val_pre,  show_col_types = FALSE))
  VAL_POST <- suppressMessages(readr::read_csv(files$val_post, show_col_types = FALSE))
  TE_PRE   <- suppressMessages(readr::read_csv(files$te_pre,   show_col_types = FALSE))
  TE_POST  <- suppressMessages(readr::read_csv(files$te_post,  show_col_types = FALSE))
  
  if (!(LABEL_COL %in% names(VAL_PRE))) stop(head, ": label column '", LABEL_COL, "' missing in VAL.")
  if (!(LABEL_COL %in% names(TE_PRE)))  stop(head, ": label column '", LABEL_COL, "' missing in TEST.")
  
  # Prob columns
  pre_val <- choose_prob_col(VAL_PRE, PRE_COL)$prob
  pre_te  <- choose_prob_col(TE_PRE,  PRE_COL)$prob
  post_val<- choose_prob_col(VAL_POST,POST_COL)$prob
  post_te <- choose_prob_col(TE_POST, POST_COL)$prob
  y_val <- as.numeric(VAL_PRE[[LABEL_COL]]); y_te <- as.numeric(TE_PRE[[LABEL_COL]])
  
  # Reliability bins and plots
  pre_bins_val  <- reldiag_stats(pre_val,  y_val, NBINS)
  post_bins_val <- reldiag_stats(post_val, y_val, NBINS)
  pre_bins_te   <- reldiag_stats(pre_te,   y_te, NBINS)
  post_bins_te  <- reldiag_stats(post_te,  y_te, NBINS)
  
  fn_reli_pre_val  <- file.path(DIR_RELI, paste0(head, "_VAL_reldiag_pre.png"))
  fn_reli_post_val <- file.path(DIR_RELI, paste0(head, "_VAL_reldiag_post.png"))
  fn_reli_delta_val<- file.path(DIR_RELI, paste0(head, "_VAL_reldiag_delta.png"))
  fn_reli_pre_te   <- file.path(DIR_RELI, paste0(head, "_TEST_reldiag_pre.png"))
  fn_reli_post_te  <- file.path(DIR_RELI, paste0(head, "_TEST_reldiag_post.png"))
  fn_reli_delta_te <- file.path(DIR_RELI, paste0(head, "_TEST_reldiag_delta.png"))
  plot_reldiag(pre_bins_val, post_bins_val, fn_reli_post_val) # combined
  plot_reldiag(pre_bins_te,  post_bins_te,  fn_reli_post_te)
  # Also write individual pre plots for completeness
  plot_reldiag(pre_bins_val, pre_bins_val, fn_reli_pre_val)
  plot_reldiag(pre_bins_te,  pre_bins_te,  fn_reli_pre_te)
  # VAL delta with common bins (no warnings)
  br_val <- make_bins(c(pre_val, post_val), NBINS)
  pre_bins_val_c  <- reldiag_stats_with_brks(pre_val,  y_val, br_val)
  post_bins_val_c <- reldiag_stats_with_brks(post_val, y_val, br_val)
  dfv <- merge(pre_bins_val_c[, .(bin, conf_pre = conf, acc_pre = acc)],
               post_bins_val_c[, .(bin, conf_post = conf, acc_post = acc)],
               by = "bin", all = TRUE)
  dfv <- dfv[is.finite(conf_pre) & is.finite(acc_pre) & is.finite(conf_post) & is.finite(acc_post), ]
  dfv$delta <- (dfv$acc_post - dfv$conf_post) - (dfv$acc_pre - dfv$conf_pre)
  ggplot(dfv, aes(x = bin, y = delta)) +
    geom_hline(yintercept = 0, linetype = "dashed") +
    geom_col(width = 0.8) +
    labs(x = "Bin", y = "Post minus pre (calibration error)", title = "Calibration delta by bin (VAL)") +
    theme_minimal(base_size = 12)
  ggsave(fn_reli_delta_val, width = 6.5, height = 4.0, dpi = 120)
  # TEST delta with common bins (no warnings)
  br_te <- make_bins(c(pre_te, post_te), NBINS)
  pre_bins_te_c  <- reldiag_stats_with_brks(pre_te,  y_te, br_te)
  post_bins_te_c <- reldiag_stats_with_brks(post_te, y_te, br_te)
  dft <- merge(pre_bins_te_c[, .(bin, conf_pre = conf, acc_pre = acc)],
               post_bins_te_c[, .(bin, conf_post = conf, acc_post = acc)],
               by = "bin", all = TRUE)
  dft <- dft[is.finite(conf_pre) & is.finite(acc_pre) & is.finite(conf_post) & is.finite(acc_post), ]
  dft$delta <- (dft$acc_post - dft$conf_post) - (dft$acc_pre - dft$conf_pre)
  ggplot(dft, aes(x = bin, y = delta)) +
    geom_hline(yintercept = 0, linetype = "dashed") +
    geom_col(width = 0.8) +
    labs(x = "Bin", y = "Post minus pre (calibration error)", title = "Calibration delta by bin (TEST)") +
    theme_minimal(base_size = 12)
  ggsave(fn_reli_delta_te, width = 6.5, height = 4.0, dpi = 120)
  
  # ECE/LogLoss/Brier + bootstrap CI
  BVAL_pre  <- bootstrap_metrics(pre_val,  y_val, nb = BBOOTS, nbins = NBINS)
  BVAL_post <- bootstrap_metrics(post_val, y_val, nb = BBOOTS, nbins = NBINS)
  BTE_pre   <- bootstrap_metrics(pre_te,   y_te,  nb = BBOOTS, nbins = NBINS)
  BTE_post  <- bootstrap_metrics(post_te,  y_te,  nb = BBOOTS, nbins = NBINS)
  
  # Write ECE bootstrap CSV
  ece_val_csv <- file.path(DIR_RELI, paste0(head, "_VAL_ece_bootstrap.csv"))
  ece_te_csv  <- file.path(DIR_RELI, paste0(head, "_TEST_ece_bootstrap.csv"))
  write_csv(data.frame(split="VAL", pre = BVAL_pre$ece, post = BVAL_post$ece,
                       pre_lo = BVAL_pre$ece_ci[1], pre_hi = BVAL_pre$ece_ci[2],
                       post_lo = BVAL_post$ece_ci[1], post_hi = BVAL_post$ece_ci[2]), ece_val_csv)
  write_csv(data.frame(split="TEST", pre = BTE_pre$ece, post = BTE_post$ece,
                       pre_lo = BTE_pre$ece_ci[1], pre_hi = BTE_pre$ece_ci[2],
                       post_lo = BTE_post$ece_ci[1], post_hi = BTE_post$ece_ci[2]), ece_te_csv)
  
  # Write metrics CSV
  met_val_csv <- file.path(DIR_RELI, paste0(head, "_VAL_metrics.csv"))
  met_te_csv  <- file.path(DIR_RELI, paste0(head, "_TEST_metrics.csv"))
  nll_improve_val <- (BVAL_pre$logloss - BVAL_post$logloss)
  nll_improve_te  <- (BTE_pre$logloss  - BTE_post$logloss)
  write_csv(data.frame(split="VAL",
                       logloss_pre = BVAL_pre$logloss, logloss_post = BVAL_post$logloss,
                       brier_pre = BVAL_pre$brier, brier_post = BVAL_post$brier,
                       ece_pre = BVAL_pre$ece, ece_post = BVAL_post$ece,
                       logloss_pre_lo = BVAL_pre$logloss_ci[1], logloss_pre_hi = BVAL_pre$logloss_ci[2],
                       logloss_post_lo = BVAL_post$logloss_ci[1], logloss_post_hi = BVAL_post$logloss_ci[2],
                       brier_pre_lo = BVAL_pre$brier_ci[1], brier_pre_hi = BVAL_pre$brier_ci[2],
                       brier_post_lo = BVAL_post$brier_ci[1], brier_post_hi = BVAL_post$brier_ci[2],
                       ece_pre_lo = BVAL_pre$ece_ci[1], ece_pre_hi = BVAL_pre$ece_ci[2],
                       ece_post_lo = BVAL_post$ece_ci[1], ece_post_hi = BVAL_post$ece_ci[2],
                       nll_improvement = nll_improve_val),
            met_val_csv)
  write_csv(data.frame(split="TEST",
                       logloss_pre = BTE_pre$logloss, logloss_post = BTE_post$logloss,
                       brier_pre = BTE_pre$brier, brier_post = BTE_post$brier,
                       ece_pre = BTE_pre$ece, ece_post = BTE_post$ece,
                       logloss_pre_lo = BTE_pre$logloss_ci[1], logloss_pre_hi = BTE_pre$logloss_ci[2],
                       logloss_post_lo = BTE_post$logloss_ci[1], logloss_post_hi = BTE_post$logloss_ci[2],
                       brier_pre_lo = BTE_pre$brier_ci[1], brier_pre_hi = BTE_pre$brier_ci[2],
                       brier_post_lo = BTE_post$brier_ci[1], brier_post_hi = BTE_post$brier_ci[2],
                       ece_pre_lo = BTE_pre$ece_ci[1], ece_pre_hi = BTE_pre$ece_ci[2],
                       ece_post_lo = BTE_post$ece_ci[1], ece_post_hi = BTE_post$ece_ci[2],
                       nll_improvement = nll_improve_te),
            met_te_csv)
  
  # Threshold uncertainty around p*
  pstar <- get_pstar(head, REL_DIR, objective = OBJ)
  sweep_val <- threshold_sweep(post_val, y_val, pstar = pstar, objective = OBJ, step = 0.002, span = 0.1)
  sweep_te  <- threshold_sweep(post_te,  y_te,  pstar = pstar, objective = OBJ, step = 0.002, span = 0.1)
  sweep_val_csv <- file.path(DIR_TU, paste0(head, "_VAL_sweep.csv"))
  sweep_te_csv  <- file.path(DIR_TU, paste0(head, "_TEST_sweep.csv"))
  write_csv(sweep_val, sweep_val_csv); write_csv(sweep_te, sweep_te_csv)
  
  boot_thr <- threshold_boot(post_val, y_val, pstar = pstar, objective = OBJ, nb = BBOOTS, step = 0.002, span = 0.1)
  boot_thr_csv <- file.path(DIR_TU, paste0(head, "_VAL_pstar_boot.csv"))
  write_csv(boot_thr, boot_thr_csv)
  
  # Simple sweep plot (VAL)
  sp_png <- file.path(DIR_TU, paste0(head, "_VAL_sweep_plot.png"))
  gg <- ggplot(sweep_val, aes(x = threshold, y = .data[[OBJ]])) +
    geom_line() + geom_vline(xintercept = pstar, linetype = "dashed") +
    labs(title = paste0("Threshold sweep (", OBJ, ") around p*=", sprintf("%.3f", pstar)), y = OBJ, x = "Threshold") +
    theme_minimal(base_size = 12)
  ggsave(sp_png, gg, width = 6.5, height = 4.0, dpi = 120)
  
  # Subgroup diagnostics
  cand_cols <- find_subgroup_cols(VAL_POST, LABEL_COL, PRE_COL, POST_COL, SUBGROUP_LIST)
  sg_summ_rows <- list()
  for (feat in cand_cols){
    # Build subgroup table if sufficient size
    DTv <- data.table(group = VAL_POST[[feat]], pre = pre_val, post = post_val, y = y_val)
    DTt <- data.table(group = TE_POST[[feat]],  pre = pre_te,  post = post_te,  y = y_te)
    # only levels with >= MIN_SUB_N
    keep_lv <- names(which(table(DTv$group) >= MIN_SUB_N))
    if (!length(keep_lv)) next
    DTv <- DTv[group %in% keep_lv]; DTt <- DTt[group %in% keep_lv]
    
    # per subgroup metrics pre/post (VAL)
    DTv_met <- DTv[, .(
      n = .N,
      ece_pre = {b <- reldiag_stats(pre, y, NBINS); ece_from_bins(b)},
      ece_post= {b <- reldiag_stats(post, y, NBINS); ece_from_bins(b)},
      logloss_pre = logloss(pre, y),
      logloss_post= logloss(post, y),
      brier_pre = brier(pre, y),
      brier_post= brier(post, y)
    ), by = group]
    
    # Flagging
    DTv_met[, `:=`(
      flag_ece = (ece_post - ece_pre) > 0.01,
      flag_ll  = (logloss_post - logloss_pre) > 0.005
    )]
    
    # Write per-feature CSV
    f_csv_val <- file.path(DIR_SG, paste0(head, "_VAL_by_", feat, ".csv"))
    write_csv(DTv_met, f_csv_val)
    
    # Plot small multiples for post only (VAL)
    bins_post <- DTv[, {b <- reldiag_stats(post, y, NBINS); b[, group := .BY$group]; b}, by = group]
    pg <- ggplot(bins_post, aes(x = conf, y = acc)) +
      geom_abline(slope = 1, intercept = 0, linetype = "dashed") +
      geom_line() + geom_point(size = 1.2) +
      facet_wrap(~group) +
      coord_cartesian(xlim = c(0,1), ylim = c(0,1)) +
      labs(title = paste0("Reliability by ", feat, " (post, VAL)"), x = "Confidence", y = "Accuracy") +
      theme_minimal(base_size = 11)
    ggsave(file.path(DIR_SG, paste0(head, "_VAL_by_", feat, ".png")), pg, width = 8, height = 6, dpi = 120)
    
    # Collect summary flags
    sg_summ_rows[[length(sg_summ_rows)+1]] <- data.table(feature = feat, DTv_met)
  }
  sg_summary <- if (length(sg_summ_rows)) rbindlist(sg_summ_rows, fill = TRUE) else data.table()
  if (nrow(sg_summary)) write_csv(sg_summary, file.path(DIR_SG, paste0(head, "_VAL_summary.csv")))
  
  # Shift diagnostics (VAL vs TEST; and optional incoming)
  # Base score for shift = pre-calibration score
  score_val <- pre_val; score_te <- pre_te
  psi_vt <- psi_equal_width(score_val, score_te, bins = 10)
  ks_vt  <- ks_2sample(score_val, score_te)
  psi_csv <- file.path(DIR_SHIFT, paste0(head, "_VAL_vs_TEST_psi.csv"))
  ks_csv  <- file.path(DIR_SHIFT, paste0(head, "_VAL_vs_TEST_ks.csv"))
  write_csv(data.frame(psi = psi_vt$psi), psi_csv)
  write_csv(data.frame(D = ks_vt$D, p = ks_vt$p), ks_csv)
  
  # Incoming batch
  psi_vin <- NA_real_; ks_in <- list(D = NA_real_, p = NA_real_)
  if (!is.na(INCOMING) && file.exists(INCOMING)){
    IN <- suppressMessages(readr::read_csv(INCOMING, show_col_types = FALSE))
    if (!is.na(IN_COL) && IN_COL %in% names(IN)){
      inc_score <- IN[[IN_COL]]
      if (IN_IS_LOGIT) inc_score <- plogis(inc_score)
      psi_vin <- psi_equal_width(score_val, inc_score, bins = 10)
      ks_in   <- ks_2sample(score_val, inc_score)
      write_csv(data.frame(psi = psi_vin$psi), file.path(DIR_SHIFT, paste0(head, "_VAL_vs_INCOMING_psi.csv")))
      write_csv(data.frame(D = ks_in$D, p = ks_in$p), file.path(DIR_SHIFT, paste0(head, "_VAL_vs_INCOMING_ks.csv")))
    }
  }
  
  # Gate logic per head
  fail_rule <- (BVAL_post$logloss - BVAL_pre$logloss) > 0.002 ||
    (BVAL_post$ece - BVAL_pre$ece) > 0.01
  
  warn_shift <- (!is.na(psi_vt$psi) && psi_vt$psi > 0.25) ||
    (!is.na(ks_vt$D) && !is.na(ks_vt$p) && ks_vt$D > 0.15 && ks_vt$p < 1e-6)
  if (!is.na(psi_vin)) {
    warn_shift <- warn_shift || (psi_vin$psi > 0.25) ||
      (!is.na(ks_in$D) && !is.na(ks_in$p) && ks_in$D > 0.15 && ks_in$p < 1e-6)
  }
  
  warn_sub <- FALSE
  if (nrow(sg_summary)){
    warn_sub <- any(sg_summary$flag_ece | sg_summary$flag_ll, na.rm = TRUE)
  }
  
  status <- if (fail_rule) "FAIL" else if (warn_shift || warn_sub) "WARN" else "PASS"
  
  list(
    head = head,
    status = status,
    paths = files,
    metrics = list(
      val_pre = BVAL_pre, val_post = BVAL_post,
      te_pre = BTE_pre, te_post = BTE_post
    ),
    plots = list(
      reli_val = fn_reli_post_val, reli_te = fn_reli_post_te,
      delta_val = fn_reli_delta_val, delta_te = fn_reli_delta_te
    ),
    sweep = list(val = sweep_val_csv, te = sweep_te_csv, plot = sp_png),
    subgroups = list(summary = if (nrow(sg_summary)) file.path(DIR_SG, paste0(head, "_VAL_summary.csv")) else NA_character_),
    shift = list(psi = psi_csv, ks = ks_csv)
  )
}

# ---------- Run over heads ----------
results <- lapply(HEADS, function(h){
  tryCatch(process_head(h),
           error = function(e) {
             message("24c: Head ", h, " failed: ", conditionMessage(e))
             list(head = h, status = "FAIL", error = conditionMessage(e))
           })
})

# ---------- Write status and report ----------
status_tbl <- data.table::rbindlist(lapply(results, function(r) data.table::as.data.table(list(head = r$head, status = r$status))), fill = TRUE)
out_status_csv <- file.path("artifacts", "v2_reliability_status.csv")
readr::write_csv(status_tbl, out_status_csv)

# Overall status = min over ordering PASS > WARN > FAIL
ord <- c("FAIL" = 0, "WARN" = 1, "PASS" = 2)
overall <- names(sort(c("PASS","WARN","FAIL"), decreasing = TRUE))[1]
overall <- if (nrow(status_tbl)) names(which.max(tapply(names(ord)[match(status_tbl$status, names(ord))], 1:nrow(status_tbl), function(x) ord[x])))[1] else "FAIL"
# Simpler: if any FAIL -> FAIL; else if any WARN -> WARN; else PASS
overall <- if (any(status_tbl$status == "FAIL")) "FAIL" else if (any(status_tbl$status == "WARN")) "WARN" else "PASS"

# MD report
out_md <- file.path("artifacts", "v2_reliability_report.md")
lines <- c(
  "# Reliability & Robustness (24c)",
  "",
  paste0("- Release dir: ", basename(REL_DIR)),
  paste0("- Heads: ", paste(HEADS, collapse = ", ")),
  paste0("- Bins: ", NBINS, ", Bootstraps: ", BBOOTS, ", Objective: ", OBJ),
  paste0("- Overall status: **", overall, "**"),
  "",
  "## Per-head status",
  paste0("- ", status_tbl$head, ": **", status_tbl$status, "**")
)
writeLines(lines, out_md, useBytes = TRUE)

message("24c: Reliability suite completed. Overall status: ", overall)
cat("Status CSV: ", out_status_csv, "\n", sep = "")
cat("Report MD: ", out_md, "\n", sep = "")










# =====================================================================
# 25_shrinkage_sweep_capabilities.R — Sweep K for capability profiles
#   Rebuild capability profiles across an expanded K grid
#   (fixed log-spaced + data-driven anchors).
#
#   Inputs:
#     - training CSVs in a folder named "train" under project root
#       (files like: input_YYYY_wNN.csv), or override TRAIN_DIR env var.
#   Outputs:
#     - artifacts/sweep_capabilities_k.csv
#     - artifacts/sweep_capabilities_k_status.{csv,md}
#
#   How to run (no guessing):
#     setwd("<project root>") ; Rscript Code/25_shrinkage_sweep_capabilities.R
#     # or
#     BDB_ROOT="<project root>" Rscript Code/25_shrinkage_sweep_capabilities.R
#     # or
#     TRAIN_DIR="<project root>/train" Rscript Code/25_shrinkage_sweep_capabilities.R
# =====================================================================

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","purrr","stringr","scales","tibble"))

# -------------------- 0.1) Root and train detection --------------------
path_exists <- function(p) tryCatch(dir.exists(p) || file.exists(p), error = function(e) FALSE)

normu <- function(p) normalizePath(p, mustWork = FALSE)

# Try to get the path of this script when run via Rscript or source()
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  # source() path detection heuristics
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      # source("path", ...) case
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  # Fallback: working directory
  normu(".")
}

ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}

# Predicate: directory has both Code/ and train/
looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"train"))

# Compute PROJECT_ROOT
PROJECT_ROOT <- NA_character_
# 1) Env override
bdb_env <- Sys.getenv("BDB_ROOT","")
if (nzchar(bdb_env)) {
  PROJECT_ROOT <- normu(bdb_env)
} else {
  # 2) From script location
  sf <- this_file()
  if (file.exists(sf)) {
    # If script resides in .../Code, prefer its parent
    sdir <- dirname(sf)
    if (basename(sdir) %in% c("Code","code")) {
      cand <- normu(file.path(sdir, ".."))
      if (looks_like_root(cand)) PROJECT_ROOT <- cand
    }
    if (is.na(PROJECT_ROOT)) {
      PROJECT_ROOT <- ascend_until(sdir, looks_like_root, max_steps = 6)
    }
  }
  # 3) From working directory
  if (is.na(PROJECT_ROOT)) {
    PROJECT_ROOT <- ascend_until(getwd(), looks_like_root, max_steps = 6)
  }
}
# 4) Last resort: use getwd()
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

# TRAIN_DIR: first env override, then <root>/train
TRAIN_DIR <- Sys.getenv("TRAIN_DIR","")
if (!nzchar(TRAIN_DIR)) TRAIN_DIR <- file.path(PROJECT_ROOT, "train")
TRAIN_DIR <- normu(TRAIN_DIR)

# Artifacts dir
ARTIFACTS_DIR <- file.path(PROJECT_ROOT, "artifacts")
dir.create(ARTIFACTS_DIR, recursive = TRUE, showWarnings = FALSE)

# -------------------- 1) Load training files --------------------
# Regex pattern WITHOUT backslash escapes (escape-free):
PATTERN <- "^input_[0-9]{4}_w[0-9]{2}[.]csv$"
if (!dir.exists(TRAIN_DIR)) {
  stop(sprintf("Training directory not found: %s. Set TRAIN_DIR or BDB_ROOT correctly.", TRAIN_DIR), call. = FALSE)
}
files <- list.files(TRAIN_DIR, pattern = PATTERN, full.names = TRUE)
if (!length(files)) {
  stop(sprintf("No training CSVs found in %s. Expected pattern: %s", TRAIN_DIR, PATTERN), call. = FALSE)
}
message(sprintf("[1/8] Found %d training files under %s.", length(files), TRAIN_DIR))

read_csv_clean <- function(path) readr::read_csv(path, show_col_types = FALSE, progress = FALSE) |> janitor::clean_names()
require_cols <- function(df, cols, where="data") {
  miss <- setdiff(cols, names(df))
  if (length(miss)) stop(sprintf("Missing required columns in %s: %s", where, paste(miss, collapse=", ")), call. = FALSE)
  invisible(TRUE)
}

dat <- purrr::map_dfr(files, read_csv_clean)

# -------------------- 2) Column cleanup --------------------
dat <- dat |>
  janitor::clean_names() |>
  dplyr::rename(
    game_id  = dplyr::any_of("game_id"),
    play_id  = dplyr::any_of("play_id"),
    nfl_id   = dplyr::any_of(c("nfl_id","nflid")),
    frame_id = dplyr::any_of(c("frame_id","frameid")),
    x = dplyr::any_of("x"),
    y = dplyr::any_of("y"),
    s = dplyr::any_of("s"),
    a = dplyr::any_of("a"),
    dir = dplyr::any_of("dir"),
    o = dplyr::any_of("o"),
    event = dplyr::any_of("event")
  )

require_cols(dat, c("nfl_id","frame_id"), "tracking data (ids)")
require_cols(dat, c("s","dir"), "tracking data (capability features)")

# Minimal type normalization
num_cols <- intersect(c("x","y","s","a","dir","o"), names(dat))
for (nm in num_cols) dat[[nm]] <- suppressWarnings(as.numeric(dat[[nm]]))
dat$frame_id <- suppressWarnings(as.integer(dat$frame_id))
dat$nfl_id   <- as.character(dat$nfl_id)

# -------------------- 3) Sanity filters --------------------
DT <- 0.1  # seconds per frame (10 Hz)

dat <- dat |>
  dplyr::filter(!is.na(nfl_id), !is.na(frame_id)) |>
  dplyr::filter(!is.na(s), s >= 0, s <= 12)

if ("a" %in% names(dat)) {
  dat <- dat |> dplyr::filter(is.na(a) | (a >= -10 & a <= 10))
}

dat <- dat |> dplyr::filter(!is.na(dir), dir >= 0, dir <= 360)

message(sprintf("[2/8] Frames after sanity filters: %s", scales::comma(nrow(dat))))

# -------------------- 4) Turn-rate prep --------------------
deg_unwrap <- function(deg){
  rad <- deg * pi/180
  out <- numeric(length(rad))
  if (length(rad)) out[1] <- rad[1]
  if (length(rad) > 1) {
    for (i in 2:length(rad)) {
      d <- rad[i] - rad[i-1]
      d <- atan2(sin(d), cos(d))  # wrap to [-pi, pi]
      out[i] <- out[i-1] + d
    }
  }
  out * 180/pi
}

turn_rate_tbl_full <- dat |>
  dplyr::arrange(nfl_id, frame_id) |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    turn_rate_abs = list({
      ang <- deg_unwrap(dir)
      if (length(ang) < 2) numeric(0) else abs(diff(ang)) / DT
    }),
    .groups = "drop"
  ) |>
  dplyr::mutate(
    n_turn = purrr::map_int(turn_rate_abs, length),
    turn_rate_p95_raw = purrr::map_dbl(turn_rate_abs, ~ if (length(.x)) quantile(.x, 0.95, na.rm = TRUE) else NA_real_)
  )

turn_pooled <- unlist(turn_rate_tbl_full$turn_rate_abs, use.names = FALSE)
turn_prior <- if (length(turn_pooled)) suppressWarnings(quantile(turn_pooled, 0.95, na.rm = TRUE)) else NA_real_

turn_rate_tbl <- turn_rate_tbl_full |>
  dplyr::select(nfl_id, n_turn, turn_rate_p95_raw)

# -------------------- 5) Per-player raw summaries --------------------
cap_raw <- dat |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    n_v = dplyr::n(),
    v_max_raw = suppressWarnings(quantile(s, 0.95, na.rm = TRUE)),
    a_max_raw = if ("a" %in% names(dat)) suppressWarnings(quantile(pmax(a, 0), 0.95, na.rm = TRUE)) else NA_real_,
    .groups = "drop"
  ) |>
  dplyr::left_join(turn_rate_tbl, by = "nfl_id")

stopifnot(nrow(cap_raw) > 0)

# -------------------- 6) Global priors --------------------
v_prior <- suppressWarnings(quantile(dat$s, 0.95, na.rm = TRUE))
a_prior <- if ("a" %in% names(dat)) suppressWarnings(quantile(pmax(dat$a, 0), 0.95, na.rm = TRUE)) else NA_real_

# -------------------- 7) K grid (fixed + data-driven) --------------------
K_fixed <- c(0L, 25L, 50L, 100L, 200L, 350L, 500L, 750L, 1000L, 1500L, 2500L, 4000L, 7000L, 20000L)

n_q <- suppressWarnings(quantile(cap_raw$n_v, c(0.25, 0.5, 0.75), na.rm = TRUE))
w_targets <- c(0.2, 0.5, 0.8)
K_from_w <- function(n, w) n * (1/w - 1)
K_derived <- as.integer(round(outer(n_q, w_targets, K_from_w)))
K_derived <- K_derived[is.finite(K_derived) & K_derived >= 0]

# CLI override for K list
args <- commandArgs(trailingOnly = TRUE)
if (length(args) >= 1 && nzchar(args[1])) {
  Ks <- suppressWarnings(as.integer(strsplit(args[1], ",")[[1]]))
  Ks <- Ks[!is.na(Ks)]
} else {
  Ks <- sort(unique(c(K_fixed, K_derived)))
}
Ks <- Ks[Ks <= 100000]
if (!length(Ks)) stop("K grid is empty after processing.", call. = FALSE)
message(sprintf("[3/8] Using %d K values: %s", length(Ks), paste(Ks, collapse = ",")))

# -------------------- 8) Shrink + sweep --------------------
shrink_vec <- function(est, n, prior, k) {
  w <- if (k == 0) ifelse(n > 0, 1, NA_real_) else n / (n + k)
  out <- w * est + (1 - w) * prior
  out[is.na(w) | is.na(est)] <- NA_real_
  out
}

cap_k <- purrr::map_dfr(Ks, function(K){
  has_a <- "a_max_raw" %in% names(cap_raw) && !all(is.na(cap_raw$a_max_raw))
  v_max_vec     <- shrink_vec(cap_raw$v_max_raw,        cap_raw$n_v,   v_prior,   K)
  a_max_vec     <- if (has_a) shrink_vec(cap_raw$a_max_raw, cap_raw$n_v,   a_prior,   K) else rep(NA_real_, nrow(cap_raw))
  turn_rate_vec <- shrink_vec(cap_raw$turn_rate_p95_raw, cap_raw$n_turn, turn_prior, K)
  
  tibble::tibble(
    nfl_id = cap_raw$nfl_id,
    K      = as.integer(K),
    v_max  = pmin(pmax(v_max_vec, 4), 12),
    a_max  = a_max_vec,
    turn_rate_p95 = turn_rate_vec,
    n_v    = cap_raw$n_v,
    n_turn = cap_raw$n_turn
  )
})

# -------------------- 9) Write artifact + brief status --------------------
OUT_CSV   <- file.path(ARTIFACTS_DIR, "sweep_capabilities_k.csv")
OUT_STAT  <- file.path(ARTIFACTS_DIR, "sweep_capabilities_k_status.csv")
OUT_STATM <- file.path(ARTIFACTS_DIR, "sweep_capabilities_k_status.md")

readr::write_csv(cap_k, OUT_CSV)
message(sprintf("[4/8] Wrote %s rows to %s", nrow(cap_k), OUT_CSV))

rng <- function(x) {
  if (all(is.na(x))) return("NA")
  paste0(sprintf("%.3f", suppressWarnings(min(x, na.rm = TRUE))), " .. ", sprintf("%.3f", suppressWarnings(max(x, na.rm = TRUE))))
}

status_by_k <- cap_k |>
  dplyr::group_by(K) |>
  dplyr::summarise(
    n_rows = dplyr::n(),
    v_non_missing = sum(!is.na(v_max)),
    a_non_missing = sum(!is.na(a_max)),
    t_non_missing = sum(!is.na(turn_rate_p95)),
    v_range = rng(v_max),
    a_range = rng(a_max),
    t_range = rng(turn_rate_p95),
    .groups = "drop"
  )

chk <- function(name, ok, details) tibble::tibble(step="25_shrinkage_sweep_capabilities", check=name, status=if (isTRUE(ok)) "PASS" else "FAIL", details=details)

status_tbl <- dplyr::bind_rows(
  chk("artifact_written", file.exists(OUT_CSV), if (file.exists(OUT_CSV)) sprintf("rows=%s", nrow(cap_k)) else "missing"),
  chk("k_values", length(Ks) == dplyr::n_distinct(cap_k$K), paste("K(n)=", length(Ks))),
  chk("non_missing_positive", all(status_by_k$v_non_missing > 0 & status_by_k$t_non_missing > 0), "v and turn present for all K" )
)

readr::write_csv(status_tbl, OUT_STAT)
rep_lines <- c(
  "# Capability shrinkage sweep (K)",
  "",
  "## Paths",
  paste0("PROJECT_ROOT: ", PROJECT_ROOT),
  paste0("TRAIN_DIR:    ", TRAIN_DIR),
  paste0("ARTIFACTS:    ", ARTIFACTS_DIR),
  "",
  "## K grid used",
  paste0("`", paste(Ks, collapse=", "), "`"),
  "",
  "## Summary by K",
  paste(capture.output(print(status_by_k, n = Inf)), collapse = "\n"),
  "",
  "## Checks",
  paste(capture.output(print(status_tbl, n = Inf)), collapse = "\n")
)
writeLines(rep_lines, OUT_STATM, useBytes = TRUE)

if (any(status_tbl$status == "FAIL")) {
  print(status_tbl)
  stop("Sweep produced failures. See artifacts/sweep_capabilities_k_status.*", call. = FALSE)
}

