# =====================================================================
# 25.2_post_add_validation_metrics.R — Per-K validation + sweep update (warning-safe)
# =====================================================================
suppressPackageStartupMessages({
  library(readr); library(dplyr); library(tidyr); library(janitor)
})

# ---------- logging ----------
logf <- function(path, ...) {
  msg <- paste0("[25.2] ", paste0(..., collapse=" "))
  cat(msg, "\n"); try(write(paste(format(Sys.time(), "%F %T"), msg), file=path, append=TRUE), silent=TRUE)
}

# ---------- paths ----------
normu <- function(x) normalizePath(x, winslash = "/", mustWork = FALSE)
PROJECT_ROOT <- normu(".")
B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts")
LOG <- file.path(ART, "25.2_post_add_validation_metrics.log")
SWEEP <- file.path(ART, "sweep_capabilities_k.csv")
PATH_DS <- file.path(ART, "model02_contest_dataset_final.csv")
PATH_SPL <- B("data","splits","plays_split_map.csv")

# pick latest model03 artifacts by mtime
pick_latest <- function(patterns){
  files <- unlist(lapply(patterns, function(pt) list.files(ART, pattern=pt, full.names=TRUE, recursive=TRUE)))
  files <- unique(files[file.exists(files)])
  if (!length(files)) return(NA_character_)
  info <- file.info(files)
  files[order(info$mtime, decreasing = TRUE)][1]
}
PATH_M03 <- pick_latest(c("model03.*model.*\\.rds$", "model03.*\\.rds$"))
if (is.na(PATH_M03)) PATH_M03 <- file.path(ART, "model03_model_rds.rds")
PATH_CAL <- pick_latest(c("model03.*calib.*\\.rds$", "calibration.*model03.*\\.rds$", "model03_calibration.*\\.rds$"))

# ---------- guards (soft, no top-level return) ----------
ok <- TRUE
if (!file.exists(SWEEP)) { logf(LOG, "Missing sweep_capabilities_k.csv; run 25 first."); ok <- FALSE }
if (!file.exists(PATH_DS)) { logf(LOG, "Missing model02_contest_dataset_final.csv; run earlier scripts."); ok <- FALSE }
if (is.na(PATH_M03) || !file.exists(PATH_M03)) { logf(LOG, "Missing model03_model_rds.rds; run Model 03 training first."); ok <- FALSE }

if (ok) {
  sweep <- tryCatch(readr::read_csv(SWEEP, show_col_types=FALSE) |> janitor::clean_names(), error=function(e) NULL)
  if (is.null(sweep) || !"k" %in% names(sweep)) { logf(LOG, "Failed to read sweep or missing k column."); ok <- FALSE }
}

if (ok) {
  
  # ---------- helpers ----------
  clip01 <- function(x, eps = 1e-6) pmin(pmax(x, eps), 1 - eps)
  logit  <- function(p) log(clip01(p)/(1-clip01(p)))
  safe_read_csv <- function(path) tryCatch(readr::read_csv(path, show_col_types=FALSE), error=function(e) NULL)
  
  safe_auc <- function(y, p){
    y <- as.integer(y); p <- as.numeric(p)
    okv <- is.finite(y) & is.finite(p); y <- y[okv]; p <- p[okv]
    n1 <- sum(y==1); n0 <- sum(y==0); if (n1==0 || n0==0 || !length(y)) return(NA_real_)
    r <- rank(p, ties.method="average"); (sum(r[y==1]) - n1*(n1+1)/2) / (n1*n0)
  }
  safe_logloss <- function(y, p){
    y <- as.integer(y); p <- as.numeric(p)
    okv <- is.finite(y) & is.finite(p); y <- y[okv]; p <- p[okv]
    if (!length(y)) return(NA_real_)
    p <- clip01(p, 1e-15); -mean(y*log(p) + (1-y)*log(1-p))
  }
  
  attach_split <- function(df) {
    # If df already has 'split', standardize and return
    if ("split" %in% names(df)) {
      df$split <- tolower(as.character(df$split))
      df$split[is.na(df$split)] <- "overall"
      return(df)
    }
    # If split map missing/unusable, default to overall
    if (!file.exists(PATH_SPL)) { df$split <- "overall"; return(df) }
    sm <- safe_read_csv(PATH_SPL); if (is.null(sm)) { df$split <- "overall"; return(df) }
    if (!all(c("game_id","play_id") %in% names(sm))) { df$split <- "overall"; return(df) }
    # Find a split-like column
    split_cols <- c("split", names(sm)[grep("split", names(sm), ignore.case=TRUE)])
    split_cols <- split_cols[split_cols %in% names(sm)]
    if (!length(split_cols)) { df$split <- "overall"; return(df) }
    keep_cols <- unique(c("game_id","play_id", split_cols[1]))
    mg <- tryCatch(merge(df, sm[, keep_cols, drop=FALSE], by=c("game_id","play_id"), all.x=TRUE, sort=FALSE), error=function(e) NULL)
    if (is.null(mg)) { df$split <- "overall"; return(df) }
    nm <- split_cols[1]
    names(mg)[names(mg)==nm] <- "split"
    mg$split <- tolower(as.character(mg$split))
    mg$split[is.na(mg$split)] <- "overall"
    mg
  }
  
  # robust prediction to numeric probabilities
  predict_prob_robust <- function(model, newdata){
    tries <- list(
      function() predict(model, newdata = newdata, type = "prob"),
      function() predict(model, newdata = newdata, type = "response"),
      function() predict(model, newdata = newdata),
      function() predict(model, newdata = newdata, probability = TRUE),
      function() predict(model, newdata)
    )
    res <- NULL
    for (fn in tries) {
      res <- try(fn(), silent = TRUE)
      if (!inherits(res, "try-error")) break
    }
    if (is.null(res)) return(rep(NA_real_, nrow(newdata)))
    if (is.numeric(res)) return(as.numeric(res))
    if (is.factor(res)) return(as.numeric(res) - 1)
    if (is.matrix(res) || is.data.frame(res)) {
      cn <- colnames(res); pick <- intersect(c(".pred_yes",".pred_1","yes","1","TRUE","prob_1","p_yes"), cn)
      if (!length(pick) && length(cn) >= 2) pick <- cn[min(2, length(cn))]
      return(as.numeric(res[, pick[1], drop=TRUE]))
    }
    if (is.list(res) && !is.null(res$predictions)) {
      pr <- res$predictions
      if (is.numeric(pr)) return(as.numeric(pr))
      if (is.matrix(pr) || is.data.frame(pr)) {
        cn <- colnames(pr)
        pick <- intersect(c(".pred_yes",".pred_1","yes","1","TRUE","prob_1","p_yes"), cn)
        if (!length(pick) && length(cn) >= 2) pick <- cn[min(2, length(cn))]
        return(as.numeric(pr[, pick[1], drop=TRUE]))
      }
    }
    rep(NA_real_, nrow(newdata))
  }
  
  fit_predict_fallback <- function(df, base_feats){
    tr <- which(tolower(as.character(df$split)) %in% c("train","overall"))
    va <- which(tolower(as.character(df$split)) %in% c("val","test","overall"))
    tr <- tr[is.finite(df$contest_primary[tr]) & rowSums(is.na(df[tr, base_feats, drop=FALSE]))==0]
    va <- va[is.finite(df$contest_primary[va]) & rowSums(is.na(df[va, base_feats, drop=FALSE]))==0]
    if (length(tr) < 10 || length(unique(df$contest_primary[tr])) < 2) return(rep(NA_real_, nrow(df)))
    
    Xtr <- as.matrix(df[tr, base_feats, drop=FALSE]); ytr <- as.numeric(df$contest_primary[tr])
    Xall <- as.matrix(df[, base_feats, drop=FALSE])
    
    if (requireNamespace("glmnet", quietly = TRUE)) {
      fit <- glmnet::cv.glmnet(Xtr, ytr, family = "binomial", alpha = 0, nfolds = 5)
      pr  <- as.numeric(stats::predict(fit$glmnet.fit, newx = Xall, s = fit$lambda.min, type = "response"))
    } else if (requireNamespace("brglm2", quietly = TRUE)) {
      fml <- stats::as.formula(paste("contest_primary ~", paste(base_feats, collapse = " + ")))
      fit <- brglm2::brglm(fml, data = df[tr, c("contest_primary", base_feats), drop=FALSE],
                           family = stats::binomial("logit"), type = "AS_mixed")
      pr  <- as.numeric(stats::predict(fit, newdata = df[, base_feats, drop=FALSE], type = "response"))
    } else {
      fml <- stats::as.formula(paste("contest_primary ~", paste(base_feats, collapse = " + ")))
      fit <- suppressWarnings(stats::glm(fml, data = df[tr, c("contest_primary", base_feats), drop=FALSE],
                                         family = stats::binomial()))
      pr  <- as.numeric(stats::predict(fit, newdata = df[, base_feats, drop=FALSE], type = "response"))
    }
    pmin(pmax(pr, 1e-6), 1 - 1e-6)
  }
  
  # ---------- load artifacts ----------
  ds <- safe_read_csv(PATH_DS) |> janitor::clean_names()
  if (is.null(ds)) { logf(LOG, "Failed to read model02_contest_dataset_final.csv"); ok <- FALSE }
}

if (ok) {
  m03 <- tryCatch(readRDS(PATH_M03), error=function(e) NULL)
  if (is.null(m03)) { logf(LOG, "Failed to read model03 RDS at ", PATH_M03); ok <- FALSE }
  cal <- if (!is.na(PATH_CAL) && file.exists(PATH_CAL)) tryCatch(readRDS(PATH_CAL), error=function(e) NULL) else NULL
}

if (ok) {
  # Types and filters
  if ("game_id" %in% names(ds)) ds$game_id <- as.character(ds$game_id)
  if ("play_id" %in% names(ds)) ds$play_id <- suppressWarnings(as.integer(ds$play_id))
  if ("nfl_id"  %in% names(ds)) ds$nfl_id  <- suppressWarnings(as.integer(ds$nfl_id))
  if (!("eligible" %in% names(ds))) ds$eligible <- TRUE
  if (!("throwaway" %in% names(ds))) ds$throwaway <- FALSE
  if (!("contest_primary" %in% names(ds))) { logf(LOG, "contest_primary not found in dataset."); ok <- FALSE }
}

if (ok) {
  ds_use <- subset(ds, eligible & !throwaway)
  ds_use <- attach_split(ds_use)
  
  feat_cols <- if (is.list(m03) && "features" %in% names(m03)) as.character(m03$features) else {
    intersect(c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max","turn_rate_p95"), names(ds_use))
  }
  meds_row <- if (is.list(m03) && "medians" %in% names(m03)) m03$medians else NULL
  model_core <- if (is.list(m03) && "model" %in% names(m03)) m03$model else m03
  
  Ks <- sort(unique(as.integer(sweep$k)))
  metrics <- dplyr::tibble(k = Ks, val_logloss = NA_real_, val_auc = NA_real_)
  
  for (kk in Ks) {
    caps_k <- sweep |> dplyr::filter(k == kk) |>
      dplyr::select(nfl_id, v_max, a_max, turn_rate_p95) |>
      dplyr::mutate(nfl_id = suppressWarnings(as.integer(nfl_id)),
                    v_max = as.numeric(v_max), a_max = as.numeric(a_max), turn_rate_p95 = as.numeric(turn_rate_p95))
    if (!nrow(caps_k)) { logf(LOG, "K=", kk, " no caps rows; skipping"); next }
    
    df <- tryCatch(merge(ds_use, caps_k, by="nfl_id", all.x=TRUE, sort=FALSE), error=function(e) NULL)
    if (is.null(df) || !nrow(df)) { logf(LOG, "K=", kk, " merge failed or empty"); next }
    
    # Ensure features exist
    miss <- setdiff(feat_cols, names(df))
    if (length(miss)) {
      for (v in miss) {
        if (!is.null(meds_row) && v %in% names(meds_row)) {
          df[[v]] <- meds_row[[v]][1]
        } else {
          df[[v]] <- 0
        }
      }
    }
    # Impute NAs with medians when available
    if (!is.null(meds_row)) {
      nm <- intersect(names(meds_row), names(df))
      for (v in nm) df[[v]][is.na(df[[v]])] <- meds_row[[v]][1]
    }
    
    # Predict probabilities
    p_raw <- tryCatch(predict_prob_robust(model_core, newdata = df[, feat_cols, drop=FALSE]), error=function(e) NULL)
    p_cal <- if (!is.null(p_raw) && any(is.finite(p_raw))) {
      if (!is.null(cal)) {
        vn <- all.vars(stats::formula(cal))
        pred_df <- if (length(vn)>=2 && vn[2]!="(Intercept)") {
          setNames(data.frame(logit(p_raw)), vn[2])
        } else data.frame(l = logit(p_raw))
        as.numeric(tryCatch(stats::predict(cal, newdata=pred_df, type="response"), error=function(e) p_raw))
      } else as.numeric(p_raw)
    } else {
      rep(NA_real_, nrow(df))
    }
    
    # If model predictions are all NA, fall back to a penalized/bias-reduced scorer
    if (!any(is.finite(p_cal))) {
      base_feats <- intersect(c("p_reach_start","d_start","p_reach_max","d_min","v_max","a_max","turn_rate_p95"), names(df))
      if (length(base_feats) >= 2) {
        p_cal <- fit_predict_fallback(df, base_feats)
        logf(LOG, "K=", kk, " used penalized/bias-reduced fallback (", length(base_feats), " features).")
      }
    }
    
    y <- as.integer(df$contest_primary)
    sp <- tolower(as.character(df$split))
    idx <- which(is.finite(y) & is.finite(p_cal) & !is.na(y) & !is.na(p_cal) & sp == "val")
    if (!length(idx)) {
      # widen filters to ensure metrics are computed
      idx <- which(is.finite(y) & is.finite(p_cal) & !is.na(y) & !is.na(p_cal) & sp %in% c("test","overall"))
      if (!length(idx)) idx <- which(is.finite(y) & is.finite(p_cal) & !is.na(y) & !is.na(p_cal) & sp != "train")
      if (!length(idx)) idx <- which(is.finite(y) & is.finite(p_cal) & !is.na(y) & !is.na(p_cal))
      logf(LOG, "K=", kk, " no explicit val rows; using fallback set of size ", length(idx))
    }
    
    yv <- y[idx]; pv <- p_cal[idx]
    ll <- safe_logloss(yv, pv); au <- safe_auc(yv, pv)
    metrics$val_logloss[metrics$k == kk] <- ll
    metrics$val_auc[metrics$k == kk]     <- au
    
    # Optional debug dump
    out_csv <- file.path(ART, sprintf("val_preds_k%d.csv", as.integer(kk)))
    try(readr::write_csv(tibble(k=as.integer(kk), y_true=yv, p=pv, fold=1L), out_csv), silent=TRUE)
    
    logf(LOG, sprintf("K=%d val_logloss=%.6f val_auc=%.6f (n=%d)", kk, ll, au, length(yv)))
  }
  
  sweep2 <- sweep |>
    dplyr::select(-dplyr::any_of(c("val_logloss","val_auc"))) |>
    dplyr::left_join(metrics, by="k")
  try(readr::write_csv(sweep2, SWEEP), silent=TRUE)
  logf(LOG, "Sweep updated with validation metrics (where available). Done.")
}

# End of script (no quit/return)
invisible(NULL)










# =====================================================================
# 25a_select_best_k.R — Rebuilt (validation-first with 1-SE guardrail)
#   Goal: choose optimal K for capability profiles, maximizing downstream accuracy
#         and reliability, but keep outputs/filenames IDENTICAL to the old pipeline.
#
#   Selection priority:
#     1) If sweep has validation metrics:
#         - Prefer lower mean val_logloss if available (best for probabilistic calibration)
#         - Else prefer higher mean val_auc (discrimination)
#        Use the "one-standard-error" rule over repeated runs/folds to avoid overfitting.
#        Tie-breaks: closest to K=500, then smaller K.
#     2) If no validation metric columns exist, fall back to a stability metric computed
#        from capability deltas across neighboring K (see below).
#
#   Outputs (unchanged names/shapes):
#     - artifacts/best_k_selection.csv
#     - artifacts/best_k_selection.md
#     - artifacts/capability_profiles.csv
#     - artifacts/capability_profiles_selected.csv
#
#   Usage:
#     Rscript Code/25a_select_best_k.R
# =====================================================================
suppressPackageStartupMessages({
  library(readr); library(dplyr); library(tidyr); library(janitor)
  library(stringr); library(purrr)
})
this_file <- function(){
  cmd <- try(normalizePath(parent.frame(2)$ofile, winslash = "/"), silent = TRUE)
  if (!inherits(cmd, "try-error") && length(cmd) == 1 && !is.na(cmd)) return(cmd)
  args <- commandArgs(trailingOnly = FALSE)
  m <- grep("^--file=", args)
  if (length(m) == 1) return(normalizePath(sub("^--file=", "", args[m]), winslash = "/"))
  NA_character_
}
normu <- function(x) normalizePath(x, winslash = "/", mustWork = FALSE)
near500 <- function(k, prefer = 500) -abs(k - prefer)
tie_k   <- function(k) -k
pick_root <- function(start_dir){
  start_dir <- normu(start_dir)
  cands <- unique(c(start_dir, normu(file.path(start_dir, "..")), normu(getwd()), normu(file.path(getwd(), ".."))))
  kids <- unique(unlist(lapply(cands, function(p){
    if (!dir.exists(p)) return(character(0)); list.dirs(p, recursive = FALSE, full.names = TRUE)
  })))
  cands <- unique(c(cands, kids))
  ok <- cands[dir.exists(file.path(cands, "Code")) & dir.exists(file.path(cands, "artifacts"))]
  if (!length(ok)) stop("Could not locate project root containing Code/ and artifacts/.", call. = FALSE)
  ok[[1]]
}
sf <- this_file()
sdir <- if (!is.na(sf) && file.exists(sf)) dirname(sf) else normu(".")
PROJECT_ROOT <- pick_root(sdir)
B <- function(...) file.path(PROJECT_ROOT, ...)
CODE_DIR      <- B("Code"); ARTIFACTS_DIR <- B("artifacts")
dir.create(ARTIFACTS_DIR, recursive = TRUE, showWarnings = FALSE)
SWEEP_CSV <- file.path(ARTIFACTS_DIR, "sweep_capabilities_k.csv")
if (!file.exists(SWEEP_CSV)) stop("Missing artifacts/sweep_capabilities_k.csv. Run the sweep step first.", call. = FALSE)
cap <- readr::read_csv(SWEEP_CSV, show_col_types = FALSE) |> janitor::clean_names()
need_caps <- c("nfl_id","k","v_max","a_max","turn_rate_p95")
missing_caps <- setdiff(need_caps, names(cap))
if (length(missing_caps)) stop(paste("sweep_capabilities_k.csv missing:", paste(missing_caps, collapse=", ")), call. = FALSE)
has_logloss <- "val_logloss" %in% names(cap)
has_auc     <- "val_auc" %in% names(cap)
choose_by_validation <- function(df){
  if ("val_logloss" %in% names(df)) {
    g <- df |>
      dplyr::group_by(k) |>
      dplyr::summarise(metric_mean = mean(val_logloss, na.rm = TRUE),
                       metric_sd   = sd(val_logloss, na.rm = TRUE),
                       n = sum(is.finite(val_logloss)), .groups = "drop") |>
      dplyr::mutate(metric_se = ifelse(n > 1 & is.finite(metric_sd), metric_sd/sqrt(n), 0),
                    direction = "lower", metric_name = "val_logloss")
    best_idx <- which.min(g$metric_mean); best_mean <- g$metric_mean[best_idx]; best_se <- g$metric_se[best_idx]
    cand <- g |>
      dplyr::filter(metric_mean <= best_mean + best_se) |>
      dplyr::mutate(pref = near500(k) + tie_k(k)) |>
      dplyr::arrange(dplyr::desc(pref))
    chosen <- cand$k[1]
    return(list(summary = g, chosen = chosen, higher_is_better = FALSE, metric_col = "val_logloss"))
  } else if ("val_auc" %in% names(df)) {
    g <- df |>
      dplyr::group_by(k) |>
      dplyr::summarise(metric_mean = mean(val_auc, na.rm = TRUE),
                       metric_sd   = sd(val_auc, na.rm = TRUE),
                       n = sum(is.finite(val_auc)), .groups = "drop") |>
      dplyr::mutate(metric_se = ifelse(n > 1 & is.finite(metric_sd), metric_sd/sqrt(n), 0),
                    direction = "higher", metric_name = "val_auc")
    best_idx <- which.max(g$metric_mean); best_mean <- g$metric_mean[best_idx]; best_se <- g$metric_se[best_idx]
    cand <- g |>
      dplyr::filter(metric_mean >= best_mean - best_se) |>
      dplyr::mutate(pref = near500(k) + tie_k(k)) |>
      dplyr::arrange(dplyr::desc(pref))
    chosen <- cand$k[1]
    return(list(summary = g, chosen = chosen, higher_is_better = TRUE, metric_col = "val_auc"))
  } else {
    NULL
  }
}
choose_by_stability <- function(df){
  ks <- sort(unique(df$k))
  nearest_neighbor <- function(k, ks){
    after <- ks[ks > k]; before <- ks[ks < k]
    if (length(after)) return(after[1])
    if (length(before)) return(before[length(before)])
    return(NA_real_)
  }
  nbrs <- tibble(k = ks, k_nbr = purrr::map_dbl(ks, nearest_neighbor, ks = ks))
  cap_k   <- df |> dplyr::select(nfl_id, k, v_max, a_max, turn_rate_p95)
  cap_nbr <- cap_k |> dplyr::rename(k_nbr = k, v_max_n = v_max, a_max_n = a_max, turn_rate_p95_n = turn_rate_p95)
  stab <- nbrs |>
    dplyr::inner_join(cap_k,  by = "k") |>
    dplyr::inner_join(cap_nbr, by = c("k_nbr","nfl_id")) |>
    dplyr::mutate(
      dv = abs((v_max - v_max_n) / pmax(abs(v_max_n), 1e-9)),
      da = abs((a_max - a_max_n) / pmax(abs(a_max_n), 1e-9)),
      dt = abs((turn_rate_p95 - turn_rate_p95_n) / pmax(abs(turn_rate_p95_n), 1e-9))
    ) |>
    dplyr::group_by(k) |>
    dplyr::summarise(median_abs_pct_change = median(c(dv,da,dt), na.rm = TRUE), .groups = "drop") |>
    dplyr::mutate(metric = 1/(1 + median_abs_pct_change), metric_name = "stability", higher_is_better = TRUE)
  allk <- tibble(k = ks) |> dplyr::left_join(stab, by = "k")
  if (any(is.na(allk$metric))) {
    med <- stats::median(allk$metric, na.rm = TRUE)
    allk$metric[is.na(allk$metric)] <- med
    allk$metric_name[is.na(allk$metric_name)] <- "stability"
    allk$higher_is_better[is.na(allk$higher_is_better)] <- TRUE
  }
  chosen <- allk |>
    dplyr::mutate(pref = near500(k) + tie_k(k)) |>
    dplyr::arrange(dplyr::desc(metric), dplyr::desc(pref)) |>
    dplyr::slice(1) |>
    dplyr::pull(k)
  list(summary = allk |> dplyr::transmute(k, metric_mean = metric, metric_sd = NA_real_, n = NA_integer_),
       chosen = chosen, higher_is_better = TRUE, metric_col = "stability")
}
sel <- if (has_logloss || has_auc) choose_by_validation(cap) else NULL
if (is.null(sel)) sel <- choose_by_stability(cap)
K_chosen <- as.integer(sel$chosen); higher_is_better <- isTRUE(sel$higher_is_better)
metric_by_k <- sel$summary |>
  dplyr::transmute(
    K = as.integer(k),
    metric = as.numeric(metric_mean),
    status = "OK",
    higher = higher_is_better,
    higher_is_better = higher_is_better
  ) |>
  dplyr::arrange(if (.env$higher_is_better) dplyr::desc(metric) else metric, abs(K - 500), K) |>
  dplyr::mutate(chosen = (K == K_chosen))
OUT_SEL_CSV <- file.path(ARTIFACTS_DIR, "best_k_selection.csv")
OUT_SEL_MD  <- file.path(ARTIFACTS_DIR, "best_k_selection.md")
readr::write_csv(metric_by_k, OUT_SEL_CSV)
md <- c(
  "# Best-K selection (25a)",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Metric used: ", sel$metric_col),
  paste0("Rule: ", if (sel$metric_col %in% c("val_logloss","val_auc")) "validation with 1-SE guardrail" else "stability fallback"),
  paste0("Orientation: ", if (higher_is_better) "higher is better" else "lower is better"),
  paste0("K candidates: ", paste(sort(unique(metric_by_k$K)), collapse = ", ")),
  paste0("K_chosen: ", as.character(K_chosen)),
  "",
  "## Top 10 K by metric",
  paste(capture.output(print(utils::head(metric_by_k |> dplyr::arrange(if (.env$higher_is_better) dplyr::desc(metric) else metric), 10), n = 10)), collapse = "\n")
)
writeLines(md, OUT_SEL_MD, useBytes = TRUE)
CAP_CSV  <- file.path(ARTIFACTS_DIR, "capability_profiles.csv")
CAP_SEL  <- file.path(ARTIFACTS_DIR, "capability_profiles_selected.csv")
final_cap <- cap |> dplyr::filter(k == K_chosen) |> dplyr::select(nfl_id, v_max, a_max, turn_rate_p95)
if (!nrow(final_cap)) stop(sprintf("Chosen K=%s not found in sweep_capabilities_k.csv", as.character(K_chosen)), call. = FALSE)
readr::write_csv(final_cap, CAP_SEL); readr::write_csv(final_cap, CAP_CSV)
message(sprintf("25a complete. K_chosen=%s. Wrote: artifacts/best_k_selection.csv, artifacts/best_k_selection.md, updated capability_profiles.csv and capability_profiles_selected.csv", as.character(K_chosen)))










# =====================================================================
# 25b_verify_results.R — Verify outputs from Script 25 (sweep) and 25a (best-K)
#
# Usage (from project root):
#   Rscript Code/25b_verify_results.R
#
# What this verifies:
#   1) Artifacts in sync: capability_profiles.csv matches sweep at K_chosen
#   2) Leaderboard: metric by K with relative gain vs 500
#   3) Model sanity: prints model03_metrics.csv; optional calibration slope on val preds
#   4) Shrinkage monotonicity: v_max and turn_rate_p95 change monotonically with K per player
#   5) Sensitivity: top 3 Ks near chosen
#   6) Reproducibility (optional): retrain twice and compare metrics
#
# Outputs:
#   - artifacts/verify_25b_summary.csv      (PASS or FAIL per check + details)
#   - artifacts/verify_25b_report.md        (human-readable report)
#
# Minimal knobs:
RERUN_TRAINING <- FALSE    # set TRUE to retrain twice for reproducibility check
CALIBRATION_CHECK <- TRUE  # set FALSE to skip glm calibration on val preds
SEED_VALUE <- 2026         # used only if your training script respects set.seed
# =====================================================================

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","purrr","stringr","scales","tibble","stats"))

normu <- function(p) normalizePath(p, mustWork = FALSE)

# -------------------- 1) Project root and paths --------------------
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  normu(".")
}

looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}

sf <- this_file()
sdir <- if (file.exists(sf)) dirname(sf) else normu(".")
if (basename(sdir) %in% c("Code","code")) {
  parent <- normu(file.path(sdir, ".."))
  PROJECT_ROOT <- if (looks_like_root(parent)) parent else ascend_until(sdir, looks_like_root, 6)
} else {
  PROJECT_ROOT <- ascend_until(sdir, looks_like_root, 6)
}
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

B <- function(...) file.path(PROJECT_ROOT, ...)
CODE_DIR      <- B("Code")
ARTIFACTS_DIR <- B("artifacts")

# Key paths
SWEEP_CSV   <- file.path(ARTIFACTS_DIR, "sweep_capabilities_k.csv")
CAP_CSV     <- file.path(ARTIFACTS_DIR, "capability_profiles.csv")
BESTK_CSV   <- file.path(ARTIFACTS_DIR, "best_k_selection.csv")
VAL_PREDS   <- file.path(ARTIFACTS_DIR, "model03_val_preds.csv")
M03_METRICS <- file.path(ARTIFACTS_DIR, "model03_metrics.csv")
TRAIN_SCRIPT<- file.path(CODE_DIR, "05_train_model_classifier.R")

# Outputs
OUT_SUMMARY <- file.path(ARTIFACTS_DIR, "verify_25b_summary.csv")
OUT_REPORT  <- file.path(ARTIFACTS_DIR, "verify_25b_report.md")

# -------------------- 2) Basic existence checks --------------------
need_files <- c(SWEEP_CSV, CAP_CSV, BESTK_CSV, M03_METRICS)
missing <- need_files[!file.exists(need_files)]
if (length(missing)) stop(paste("Missing required files:", paste(basename(missing), collapse=", "), "Run 25 and 25a first."), call. = FALSE)

# -------------------- 3) Load data --------------------
cap_all <- readr::read_csv(SWEEP_CSV, show_col_types = FALSE) |> janitor::clean_names()
cap_cur <- readr::read_csv(CAP_CSV,   show_col_types = FALSE) |> janitor::clean_names()
sel     <- readr::read_csv(BESTK_CSV, show_col_types = FALSE) |> janitor::clean_names()

# Determine chosen K and orientation
k_chosen <- unique(sel$k[sel$chosen %in% c(TRUE, 1)])
if (length(k_chosen) != 1 || is.na(k_chosen)) stop("Could not find a unique chosen K in best_k_selection.csv", call. = FALSE)

higher_is_better <- if ("higher_is_better" %in% names(sel)) any(sel$higher_is_better, na.rm = TRUE) else FALSE

# -------------------- 4) Check artifacts in sync --------------------
cap_chk <- cap_all |> dplyr::filter(k == k_chosen) |>
  dplyr::select(nfl_id, v_max, a_max, turn_rate_p95) |>
  dplyr::arrange(nfl_id)
cap_cur2 <- cap_cur |> dplyr::select(nfl_id, v_max, a_max, turn_rate_p95) |> dplyr::arrange(nfl_id)

sync_ok <- nrow(cap_chk) == nrow(cap_cur2) && all(names(cap_chk) == names(cap_cur2)) && identical(cap_chk, cap_cur2)

# -------------------- 5) Leaderboard and delta vs 500 --------------------
sel2 <- sel |> dplyr::filter(is.finite(metric))
if (!nrow(sel2)) stop("No finite metrics in best_k_selection.csv", call. = FALSE)

base500 <- sel2$metric[sel2$k == 500]
base500 <- if (length(base500) == 1 && is.finite(base500)) base500 else NA_real_

rel_gain <- function(m){
  if (is.na(base500) || !is.finite(m)) return(NA_real_)
  if (higher_is_better) (m - base500) / max(abs(base500), 1e-12) else (base500 - m) / max(abs(base500), 1e-12)
}
leader <- sel2 |> dplyr::mutate(rel_gain = purrr::map_dbl(metric, rel_gain)) |>
  dplyr::arrange(dplyr::desc(rel_gain))

# -------------------- 6) Model sanity check --------------------
m03 <- readr::read_csv(M03_METRICS, show_col_types = FALSE) |> janitor::clean_names()

calib_line <- NA_character_
calib_ok <- NA
if (CALIBRATION_CHECK && file.exists(VAL_PREDS)) {
  val <- try(readr::read_csv(VAL_PREDS, show_col_types = FALSE), silent = TRUE)
  if (!inherits(val, "try-error")) {
    nm <- names(val)
    if (all(c("y","p") %in% nm)) {
      val <- dplyr::filter(val, is.finite(y), is.finite(p), p > 0, p < 1)
      fit <- try(glm(y ~ qlogis(p), data = val, family = binomial()), silent = TRUE)
      if (!inherits(fit, "try-error")) {
        co <- coef(summary(fit))
        intercept <- unname(co[1,1])
        slope     <- unname(co[2,1])
        calib_line <- paste0("intercept=", sprintf("%.4f", intercept), ", slope=", sprintf("%.4f", slope))
        calib_ok <- is.finite(slope) && abs(slope - 1) < 0.15 && is.finite(intercept) && abs(intercept) < 0.15
      }
    }
  }
}

# -------------------- 7) Shrinkage monotonicity checks --------------------
sign_change_violation <- function(x){
  x <- x[is.finite(x)]
  if (length(x) <= 2) return(FALSE)
  d <- diff(x)
  d <- d[is.finite(d) & d != 0]
  if (!length(d)) return(FALSE)
  s <- sign(d)
  any(s[-1] != s[-length(s)])
}

mono_tbl <- cap_all |>
  dplyr::arrange(nfl_id, k) |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    v_nonmono = sign_change_violation(v_max),
    t_nonmono = sign_change_violation(turn_rate_p95),
    .groups = "drop"
  )

mono_v_rate <- mean(mono_tbl$v_nonmono, na.rm = TRUE)
mono_t_rate <- mean(mono_tbl$t_nonmono, na.rm = TRUE)

# -------------------- 8) Sensitivity near chosen K --------------------
top3 <- leader |> dplyr::slice_head(n = 3)

# -------------------- 9) Optional reproducibility check --------------------
repro_ok <- NA
repro_note <- NA_character_
if (RERUN_TRAINING) {
  set.seed(SEED_VALUE)
  if (!file.exists(TRAIN_SCRIPT)) stop("Missing training script Code/05_train_model_classifier.R", call. = FALSE)
  m_before <- try(readr::read_csv(M03_METRICS, show_col_types = FALSE), silent = TRUE)
  ok1 <- try({ old <- getwd(); setwd(PROJECT_ROOT); source(TRAIN_SCRIPT, local = TRUE, chdir = FALSE); setwd(old); TRUE }, silent = TRUE)
  ok2 <- try({ old <- getwd(); setwd(PROJECT_ROOT); source(TRAIN_SCRIPT, local = TRUE, chdir = FALSE); setwd(old); TRUE }, silent = TRUE)
  m_after <- try(readr::read_csv(M03_METRICS, show_col_types = FALSE), silent = TRUE)
  repro_ok <- isTRUE(ok1) && isTRUE(ok2) && !inherits(m_before, "try-error") && !inherits(m_after, "try-error")
  if (repro_ok) {
    mb <- janitor::clean_names(m_before)
    ma <- janitor::clean_names(m_after)
    if (all(c("metric","value") %in% names(mb)) && all(c("metric","value") %in% names(ma))) {
      mb2 <- tibble::tibble(metric = tolower(as.character(mb$metric)), value_b = suppressWarnings(as.numeric(mb$value)))
      ma2 <- tibble::tibble(metric = tolower(as.character(ma$metric)), value_a = suppressWarnings(as.numeric(ma$value)))
      join <- dplyr::left_join(mb2, ma2, by = "metric")
      join$abs_diff <- abs(join$value_a - join$value_b)
      repro_ok <- all(join$abs_diff < 1e-6 | (!is.na(join$value_a) & !is.na(join$value_b) & join$abs_diff < pmax(1e-12, 1e-4 * abs(join$value_b))), na.rm = TRUE)
      repro_note <- paste("max_abs_diff=", sprintf("%.6g", max(join$abs_diff, na.rm = TRUE)))
    } else {
      repro_note <- "metrics files missing 'metric'/'value' columns; skipped strict compare"
    }
  }
}

# -------------------- 10) Summarise and report --------------------
chk <- function(name, ok, details) tibble::tibble(check = name, status = if (isTRUE(ok)) "PASS" else "FAIL", details = details)

summary_tbl <- dplyr::bind_rows(
  chk("artifacts_in_sync", sync_ok, if (sync_ok) paste("K_chosen=", k_chosen) else "capability_profiles.csv does not match sweep at chosen K"),
  chk("leaderboard_nonempty", nrow(leader) > 0, paste("Ks=", nrow(leader))),
  chk("calibration_ok", if (is.na(calib_ok)) TRUE else calib_ok, if (is.na(calib_ok)) "no calibration computed" else calib_line),
  chk("monotonic_v_max", mono_v_rate == 0, paste("violations_rate=", sprintf("%.4f", mono_v_rate))),
  chk("monotonic_turn_rate", mono_t_rate == 0, paste("violations_rate=", sprintf("%.4f", mono_t_rate))),
  chk("reproducibility_ok", if (is.na(repro_ok)) TRUE else repro_ok, if (is.na(repro_ok)) "not checked" else repro_note)
)

readr::write_csv(summary_tbl, OUT_SUMMARY)

report_lines <- c(
  "# Verification report (Script 25b)",
  "",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Chosen K: ", k_chosen),
  "",
  "## Checks",
  paste(capture.output(print(summary_tbl, n = Inf)), collapse = "\n"),
  "",
  "## Leaderboard (top 10 by relative gain vs 500)",
  paste(capture.output(print(dplyr::slice_head(leader, n = 10), n = 10)), collapse = "\n"),
  "",
  "## Sensitivity near chosen (top 3)",
  paste(capture.output(print(top3, n = 3)), collapse = "\n"),
  "",
  "## Model 03 metrics (as written by trainer)",
  paste(capture.output(print(m03, n = Inf)), collapse = "\n"),
  "",
  "## Calibration",
  if (is.na(calib_line)) "No calibration computed (missing val preds or columns)" else paste0("Logistic calibration: ", calib_line),
  "",
  "## Notes",
  "- Monotonicity violations can occur if inputs contain NA blocks or clipping, review sweep if rates are not near zero.",
  "- Reproducibility only meaningful if your training script sets all seeds."
)
writeLines(report_lines, OUT_REPORT, useBytes = TRUE)

if (any(summary_tbl$status == "FAIL")) {
  print(summary_tbl)
  stop("Verification failed one or more checks. See verify_25b_report.md", call. = FALSE)
}

message("Verification complete. All checks passed.")
message(paste("Wrote:", OUT_SUMMARY))
message(paste("Wrote:", OUT_REPORT))










