if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())
B <- function(...) file.path(PROJECT_ROOT, ...)

ART <- B("artifacts")
dir.create(ART, recursive = TRUE, showWarnings = FALSE)

# Inputs
OP_FILE   <- file.path(ART, "v2_operating_points.csv")
CAL_METHOD_FILE <- file.path(ART, "v2_model04_calibration_method.txt")
CHOICE_FILE <- file.path(ART, "sweep_inputs_choice.csv")   # lambda_reach + ELIG_THRESHOLD (from Script 17b)
