  file.path(ART, "v2_model04_test_preds_cal.csv"),
  file.path(ART, "v2_model04_test_preds.csv"),
  file.path(ART, "v2_model04_val_preds_cal.csv"),
  file.path(ART, "v2_model04_val_preds.csv")
)
PRED_FILE <- PRED_CAND[file.exists(PRED_CAND)]
PRED_FILE <- if (length(PRED_FILE)) PRED_FILE[[1]] else ""

if (!file.exists(OP_FILE)) stop("Missing artifacts/v2_operating_points.csv (from Script 22).", call. = FALSE)
if (!nzchar(PRED_FILE)) stop("Missing v2 Model04 predictions. Looked for: v2_model04_*_preds(_cal).csv", call. = FALSE)

# If calibration method exists and is non-empty, require calibrated preds when available
cal_method <- if (file.exists(CAL_METHOD_FILE)) trimws(readLines(CAL_METHOD_FILE, warn = FALSE, n = 1)) else ""
STRICT_CAL <- nzchar(cal_method)
if (STRICT_CAL && !grepl("_preds_cal\\.csv$", PRED_FILE)) {
  cand_cal <- PRED_CAND[grepl("_preds_cal\\.csv$", PRED_CAND)]
  if (any(file.exists(cand_cal))) {
    PRED_FILE <- cand_cal[file.exists(cand_cal)][1]
  } else {
    stop("Calibration method present (", cal_method, ") but no calibrated predictions file found.", call. = FALSE)
  }
}

# Outputs
OUT_DEF   <- file.path(ART, "score_per_defender_v2.csv")
OUT_PLAY  <- file.path(ART, "score_per_play_v2.csv")
OUT_STAT  <- file.path(ART, "score_v2_status.md")

# Operating points (global + maybe overrides if your CSV has group columns)
op <- readr::read_csv(OP_FILE, show_col_types = FALSE) |> janitor::clean_names()
pick_rows <- function(df){
  rows <- df
  if ("model" %in% names(rows)) {
    rows <- rows[grepl("m04|model04|assign|defen|v2", tolower(as.character(rows$model))), , drop = FALSE]
    if (!nrow(rows)) rows <- df
  }
  rows
}
op <- pick_rows(op)
p_star <- suppressWarnings(as.numeric(op$p_star[1]))
if (!is.finite(p_star)) p_star <- 0.5
p_star <- max(0, min(1, p_star))

# Predictions
pred <- readr::read_csv(PRED_FILE, show_col_types = FALSE) |> janitor::clean_names()
nm <- names(pred)

# Required IDs
id_sets <- list(c("game_id","play_id","nfl_id"), c("gameid","playid","nflid"))
id_cols <- NULL
for (cand in id_sets) if (all(cand %in% nm)) { id_cols <- cand; break }
if (is.null(id_cols)) stop("Predictions require game_id, play_id, nfl_id (or gameid/playid/nflid).", call. = FALSE)

# Probability column(s)
p_cols <- c("p_go_cal","p_go","p_cal","p","prob","prediction")
p_col <- NULL
for (c in p_cols) if (c %in% nm) { p_col <- c; break }
if (is.null(p_col)) stop("Could not find probability column (expected one of p_go_cal, p_go, p_cal, p, prob, prediction).", call. = FALSE)

# Normalize IDs and clamp probs
pred <- pred |>
  dplyr::select(dplyr::all_of(c(id_cols, p_col))) |>
  dplyr::rename(p_go = !!rlang::sym(p_col)) |>
  (\(df){
    if ("gameid" %in% names(df) && !("game_id" %in% names(df))) df$game_id <- df$gameid
    if ("playid" %in% names(df) && !("play_id" %in% names(df))) df$play_id <- df$playid
    if ("nflid"  %in% names(df) && !("nfl_id"  %in% names(df))) df$nfl_id  <- df$nflid
    df
  })() |>
  dplyr::mutate(
    game_id = as.character(game_id),
    play_id = as.character(play_id),
    nfl_id  = as.character(nfl_id),
    p_go    = pmin(pmax(suppressWarnings(as.numeric(p_go)), 0), 1)
  ) |>
  dplyr::filter(is.finite(p_go))

# Dedupe per defender per play (max p_go)
pred <- pred |>
  dplyr::group_by(game_id, play_id, nfl_id) |>
  dplyr::summarise(p_go = max(p_go, na.rm = TRUE), .groups = "drop")

# Selection
ranked <- pred |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::arrange(dplyr::desc(p_go), .by_group = TRUE) |>
  dplyr::mutate(rank = dplyr::row_number(), eligible = p_go + EPS >= p_star) |>
  dplyr::ungroup()

plays <- ranked |> dplyr::distinct(game_id, play_id)

margins <- ranked |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(
    top_p = if (dplyr::n() >= 1) p_go[1] else NA_real_,
    second_p = if (dplyr::n() >= 2) p_go[2] else NA_real_,
    margin = top_p - second_p,
    .groups = "drop"
  )

# Optional abstain delta if present in operating points
delta <- NA_real_
cand_delta_cols <- intersect(c("delta_margin","delta","abstain_margin"), names(op))
if (length(cand_delta_cols)) {
  d <- suppressWarnings(as.numeric(op[[cand_delta_cols[1]]][1]))
  if (is.finite(d)) delta <- d
}
winner <- ranked |>
  dplyr::filter(eligible) |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::slice_head(n = 1) |>
  dplyr::ungroup() |>
  dplyr::select(game_id, play_id, nfl_id, p_go) |>
  dplyr::left_join(margins, by = c("game_id","play_id")) |>
  dplyr::mutate(
    pass_delta = if (is.finite(delta)) is.finite(margin) & margin + EPS >= delta else TRUE,
    assigned = pass_delta
  )

ties <- ranked |>
  dplyr::filter(eligible) |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(n_top = sum(abs(p_go - max(p_go)) <= EPS), .groups = "drop") |>
  dplyr::mutate(tie_abstain = n_top > 1)

winner <- winner |>
  dplyr::left_join(ties, by = c("game_id","play_id")) |>
  dplyr::mutate(assigned = assigned & !isTRUE(tie_abstain))

# Outputs
def_out <- ranked |>
  dplyr::left_join(
    winner |> dplyr::select(game_id, play_id, nfl_id, assigned) |> dplyr::rename(selected = assigned),
