  ) |>
  dplyr::mutate(selected = ifelse(is.na(selected), FALSE, selected)) |>
  dplyr::select(game_id, play_id, nfl_id, p_go, eligible, selected, rank)

play_out <- plays |>
  dplyr::left_join(
    winner |> dplyr::select(game_id, play_id, nfl_id, p_go, margin, assigned) |>
      dplyr::rename(nfl_id_assigned = nfl_id, p_go_assigned = p_go),
    by = c("game_id","play_id")
  ) |>
  dplyr::mutate(
    assigned = ifelse(is.na(assigned), FALSE, assigned),
    p_go_assigned = ifelse(assigned, p_go_assigned, NA_real_),
    nfl_id_assigned = ifelse(assigned, as.character(nfl_id_assigned), NA_character_)
  )

readr::write_csv(def_out, OUT_DEF)
readr::write_csv(play_out, OUT_PLAY)

# Status & provenance: log upstream knobs and calibration
lambda_ch <- NA_real_; et_ch <- NA_real_; pstar_src <- "artifacts/v2_operating_points.csv"
if (file.exists(CHOICE_FILE)) {
  ch <- tryCatch(readr::read_csv(CHOICE_FILE, show_col_types = FALSE), error = function(e) NULL)
  if (!is.null(ch)) {
    if ("lambda_reach" %in% names(ch)) lambda_ch <- suppressWarnings(as.numeric(ch$lambda_reach[1]))
    if ("ELIG_THRESHOLD" %in% names(ch)) et_ch <- suppressWarnings(as.numeric(ch$ELIG_THRESHOLD[1]))
  }
}

n_total <- nrow(plays)
n_assigned <- sum(play_out$assigned, na.rm = TRUE)
coverage <- if (n_total > 0) n_assigned / n_total else NA_real_
rep <- c(
  "# v2 scoring report (Script 26)",
  "",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Predictions file: ", PRED_FILE),
  paste0("Calibration method: ", ifelse(nzchar(cal_method), cal_method, "n/a")),
  paste0("Operating p*: ", sprintf('%.6f', p_star), " (source: ", pstar_src, ")"),
  paste0("Abstain delta: ", ifelse(is.finite(delta), sprintf('%.6f', delta), "NA")),
  paste0("Upstream knobs (from sweep_inputs_choice.csv): lambda_reach=", ifelse(is.na(lambda_ch), "NA", format(lambda_ch)),
         ", ELIG_THRESHOLD=", ifelse(is.na(et_ch), "NA", format(et_ch))),
  "",
  "## Totals",
  paste0("Plays total: ", n_total),
  paste0("Assignments made: ", n_assigned),
  paste0("Coverage rate: ", sprintf('%.2f%%', 100*coverage))
)
writeLines(rep, OUT_STAT, useBytes = TRUE)

