message(paste("Wrote:", OUT_PLAY))
message(paste("Wrote:", OUT_STAT))










# =====================================================================
# 26a_verify_scoring_v2.R — Verify outputs from Script 26 (score_v2) [ID-type safe, clearer messaging]
# =====================================================================

options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","purrr","stringr","tibble","rlang"))

normu <- function(p) normalizePath(p, mustWork = FALSE)
EPS <- 1e-9

normalize_ids <- function(df){
  cols <- intersect(c("game_id","play_id","nfl_id","nfl_id_assigned"), names(df))
  for (c in cols) df[[c]] <- as.character(df[[c]])
  df
}

# -------------------- Locate project root --------------------
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  normu(".")
}
looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}

sf <- this_file()
sdir <- if (file.exists(sf)) dirname(sf) else normu(".")
if (basename(sdir) %in% c("Code","code")) {
  parent <- normu(file.path(sdir, ".."))
  PROJECT_ROOT <- if (looks_like_root(parent)) parent else ascend_until(sdir, looks_like_root, 6)
} else {
  PROJECT_ROOT <- ascend_until(sdir, looks_like_root, 6)
}
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts")

# -------------------- Paths --------------------
DEF_FILE  <- file.path(ART, "score_per_defender_v2.csv")
PLAY_FILE <- file.path(ART, "score_per_play_v2.csv")
STAT_FILE <- file.path(ART, "score_v2_status.md")
OP_FILE   <- file.path(ART, "v2_operating_points.csv")

PRED_CAND <- c(
  file.path(ART, "v2_model04_test_preds_cal.csv"),
  file.path(ART, "v2_model04_test_preds.csv"),
  file.path(ART, "v2_model04_val_preds_cal.csv"),
  file.path(ART, "v2_model04_val_preds.csv")
)
PRED_FILE <- PRED_CAND[file.exists(PRED_CAND)]
PRED_FILE <- if (length(PRED_FILE)) PRED_FILE[[1]] else ""

OUT_SUM  <- file.path(ART, "verify_26a_summary.csv")
OUT_REP  <- file.path(ART, "verify_26a_report.md")
OUT_FAIL <- file.path(ART, "verify_26a_mismatches.csv")

need <- c(DEF_FILE, PLAY_FILE)
missing <- need[!file.exists(need)]
if (length(missing)) stop(paste("Missing required outputs:", paste(basename(missing), collapse=", "), "Run Script 26 first."), call. = FALSE)

# -------------------- Load data --------------------
def <- readr::read_csv(DEF_FILE, show_col_types = FALSE) |> janitor::clean_names() |> normalize_ids()
play <- readr::read_csv(PLAY_FILE, show_col_types = FALSE) |> janitor::clean_names() |> normalize_ids()

# Optional thresholds present?
has_pstar <- "p_star_final" %in% names(def)
has_delta <- "delta_final" %in% names(def)

# If not present, attempt to load global from OP file
p_star_global <- NA_real_; delta_global <- NA_real_
if (!has_pstar || !has_delta) {
  if (file.exists(OP_FILE)) {
    op <- readr::read_csv(OP_FILE, show_col_types = FALSE) |> janitor::clean_names()
    if ("p_star" %in% names(op)) p_star_global <- suppressWarnings(as.numeric(op$p_star[1]))
    if (any(c("delta","delta_margin","abstain_margin") %in% names(op))) {
      for (nm in c("delta","delta_margin","abstain_margin")) if (nm %in% names(op)) {
        v <- suppressWarnings(as.numeric(op[[nm]][1])); if (is.finite(v)) { delta_global <- v; break }
      }
    }
  }
}

# -------------------- 1) Internal consistency --------------------
sel_per_play <- def |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(n_selected = sum(selected %in% TRUE), .groups = "drop")

chk_join <- play |>
  dplyr::left_join(sel_per_play, by = c("game_id","play_id")) |>
  dplyr::mutate(n_selected = ifelse(is.na(n_selected), 0L, n_selected))

ok_one_selected <- all(chk_join$n_selected %in% c(0L,1L))
ok_assigned_match <- all(chk_join$assigned == (chk_join$n_selected == 1L))

# -------------------- 2) Recompute selection from per-defender table --------------------
def2 <- def |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::arrange(dplyr::desc(p_go), .by_group = TRUE) |>
  dplyr::mutate(
    pstar_use = if ("p_star_final" %in% names(def)) p_star_final else p_star_global,
    delta_use = if ("delta_final" %in% names(def)) delta_final else delta_global,
    eligible2 = ifelse(is.finite(pstar_use), p_go + 1e-9 >= pstar_use, p_go + 1e-9 >= 0.5),
    rank2 = dplyr::row_number()
  ) |>
  dplyr::ungroup()

margins <- def2 |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(
    top_p = if (dplyr::n() >= 1) p_go[1] else NA_real_,
    second_p = if (dplyr::n() >= 2) p_go[2] else NA_real_,
    margin = top_p - second_p,
    pstar_play = dplyr::first(pstar_use),
    delta_play = dplyr::first(delta_use),
    .groups = "drop"
  )

winner2 <- def2 |>
  dplyr::filter(eligible2) |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::slice_head(n = 1) |>
  dplyr::ungroup() |>
  dplyr::select(game_id, play_id, nfl_id, p_go) |>
  dplyr::left_join(margins, by = c("game_id","play_id")) |>
  dplyr::mutate(
    pass_delta = ifelse(is.finite(delta_play), is.finite(margin) & margin + 1e-9 >= delta_play, TRUE),
    assigned2 = pass_delta
  )

ties2 <- def2 |>
  dplyr::filter(eligible2) |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(n_top = sum(abs(p_go - max(p_go)) <= 1e-9), .groups = "drop") |>
  dplyr::mutate(tie_abstain = n_top > 1)

winner2 <- winner2 |>
  dplyr::left_join(ties2, by = c("game_id","play_id")) |>
  dplyr::mutate(assigned2 = assigned2 & !isTRUE(tie_abstain))

pred_play <- def |>
  dplyr::filter(selected %in% TRUE) |>
  dplyr::transmute(game_id, play_id, nfl_id_pred = as.character(nfl_id), assigned_pred = TRUE)

cmp <- play |>
  dplyr::left_join(pred_play, by = c("game_id","play_id")) |>
  dplyr::mutate(assigned_pred = ifelse(is.na(assigned_pred), FALSE, assigned_pred)) |>
  dplyr::left_join(winner2 |> dplyr::transmute(game_id, play_id, nfl_id_win = as.character(nfl_id), assigned2), by = c("game_id","play_id"))

ok_assigned_logic <- all(cmp$assigned == cmp$assigned2, na.rm = TRUE)
ok_winner_logic <- all(cmp$nfl_id_assigned == ifelse(cmp$assigned2, cmp$nfl_id_win, NA_character_), na.rm = TRUE)

mismatch <- cmp |>
  dplyr::filter( (assigned != assigned2) | (assigned2 & (nfl_id_assigned != nfl_id_win)) )

# -------------------- 3) Optional end-to-end recompute from predictions --------------------
e2e_ok <- NA
e2e_note <- NA_character_
if (nzchar(PRED_FILE) && file.exists(OP_FILE)) {
  pred <- try(readr::read_csv(PRED_FILE, show_col_types = FALSE), silent = TRUE)
  if (!inherits(pred, "try-error")) {
    pred <- janitor::clean_names(pred)
    nm <- names(pred)
    id_sets <- list(c("game_id","play_id","nfl_id"), c("gameid","playid","nflid"))
    id_cols <- NULL
    for (cand in id_sets) if (all(cand %in% nm)) { id_cols <- cand; break }
    p_cols <- c("p_go_cal","p_go","p_cal","p","prob","prediction")
    p_col <- NULL; for (c in p_cols) if (c %in% nm) { p_col <- c; break }
    if (!is.null(id_cols) && !is.null(p_col)) {
      pr <- pred |>
        dplyr::select(dplyr::all_of(c(id_cols, p_col))) |>
        dplyr::rename(p_go = !!rlang::sym(p_col)) |>
        (\(df){
          if ("gameid" %in% names(df) && !("game_id" %in% names(df))) df$game_id <- df$gameid
          if ("playid" %in% names(df) && !("play_id" %in% names(df))) df$play_id <- df$playid
          if ("nflid"  %in% names(df) && !("nfl_id"  %in% names(df))) df$nfl_id  <- df$nflid
          df
        })() |>
        dplyr::mutate(
          game_id = as.character(game_id),
          play_id = as.character(play_id),
          nfl_id  = as.character(nfl_id),
          p_go    = pmin(pmax(suppressWarnings(as.numeric(p_go)), 0), 1)
        ) |>
        dplyr::group_by(game_id, play_id, nfl_id) |>
        dplyr::summarise(p_go = max(p_go, na.rm = TRUE), .groups = "drop")
      op <- readr::read_csv(OP_FILE, show_col_types = FALSE) |> janitor::clean_names()
      pstar <- if ("p_star" %in% names(op)) suppressWarnings(as.numeric(op$p_star[1])) else 0.5
      if (!is.finite(pstar)) pstar <- 0.5
      delta <- NA_real_
      for (nm in c("delta","delta_margin","abstain_margin")) if (nm %in% names(op)) {
        v <- suppressWarnings(as.numeric(op[[nm]][1])); if (is.finite(v)) { delta <- v; break }
      }
      r2 <- pr |>
        dplyr::group_by(game_id, play_id) |>
        dplyr::arrange(dplyr::desc(p_go), .by_group = TRUE) |>
        dplyr::mutate(eligible = p_go + 1e-9 >= pstar) |>
        dplyr::ungroup()
      marg2 <- r2 |>
        dplyr::group_by(game_id, play_id) |>
        dplyr::summarise(top_p = if (dplyr::n() >= 1) p_go[1] else NA_real_,
                         second_p = if (dplyr::n() >= 2) p_go[2] else NA_real_,
                         margin = top_p - second_p, .groups = "drop")
      win2 <- r2 |>
        dplyr::filter(eligible) |>
        dplyr::group_by(game_id, play_id) |>
        dplyr::slice_head(n = 1) |>
        dplyr::ungroup() |>
        dplyr::select(game_id, play_id, nfl_id, p_go) |>
        dplyr::left_join(marg2, by = c("game_id","play_id")) |>
        dplyr::mutate(pass_delta = if (is.finite(delta)) is.finite(margin) & margin + 1e-9 >= delta else TRUE,
                      assigned_e2e = pass_delta)
      ties2 <- r2 |>
        dplyr::filter(eligible) |>
        dplyr::group_by(game_id, play_id) |>
        dplyr::summarise(n_top = sum(abs(p_go - max(p_go)) <= 1e-9), .groups = "drop") |>
        dplyr::mutate(tie_abstain = n_top > 1)
      win2 <- win2 |>
        dplyr::left_join(ties2, by = c("game_id","play_id")) |>
        dplyr::mutate(assigned_e2e = assigned_e2e & !isTRUE(tie_abstain))
      
      cmp2 <- play |>
        dplyr::left_join(win2 |> dplyr::transmute(game_id, play_id, nfl_id_e2e = as.character(nfl_id), assigned_e2e), by = c("game_id","play_id"))
      e2e_ok <- all(cmp2$assigned == cmp2$assigned_e2e, na.rm = TRUE) &&
        all(cmp2$nfl_id_assigned == ifelse(cmp2$assigned_e2e, cmp2$nfl_id_e2e, NA_character_), na.rm = TRUE)
      e2e_note <- paste("Compared against", basename(PRED_FILE), "with global thresholds.")
    } else {
      e2e_ok <- NA; e2e_note <- "Predictions missing required columns; skipped."
    }
  }
}

chk <- function(name, ok, details) tibble::tibble(check = name, status = if (isTRUE(ok)) "PASS" else if (is.na(ok)) "SKIP" else "FAIL", details = details)

summary_tbl <- dplyr::bind_rows(
  chk("one_selection_per_play", ok_one_selected, "At most 1 selected defender per play"),
  chk("assigned_matches_selected", ok_assigned_match, "play.assigned equals (n_selected==1)"),
  chk("decision_rule_assigned", ok_assigned_logic, "Assigned matches recomputed rule (per-defender)"),
  chk("decision_rule_winner", ok_winner_logic, "Assigned nfl_id matches recomputed winner"),
  chk("end_to_end_recompute", e2e_ok, if (is.na(e2e_ok)) "Skipped (no preds/op file)" else e2e_note)
)

readr::write_csv(summary_tbl, OUT_SUM)
if (nrow(mismatch)) readr::write_csv(mismatch, OUT_FAIL)

rep <- c(
  "# Verification report (26a)",
  "",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Per-def table: ", DEF_FILE),
  paste0("Per-play table: ", PLAY_FILE),
  if (file.exists(OP_FILE)) paste0("Operating points: ", OP_FILE) else "Operating points: not found",
  if (nzchar(PRED_FILE)) paste0("Predictions (for e2e): ", PRED_FILE) else "Predictions (for e2e): not found",
  "",
  "## Summary",
  paste(capture.output(print(summary_tbl, n = Inf)), collapse = "\n"),
  if (nrow(mismatch)) c("", "## Mismatches (first 20)", paste(capture.output(print(utils::head(mismatch, 20), n = 20)), collapse = "\n")) else "",
  "",
  "## Notes",
  "- All ID columns are coerced to character to avoid type-mismatch joins.",
  "- Recomputed rule mirrors Script 26 with EPS tolerance."
)
writeLines(rep, OUT_REP, useBytes = TRUE)

n_fail <- sum(summary_tbl$status == "FAIL", na.rm = TRUE)
n_skip <- sum(summary_tbl$status == "SKIP", na.rm = TRUE)

if (n_fail > 0) {
  print(summary_tbl)
  stop("26a verification failed. See verify_26a_report.md and verify_26a_mismatches.csv", call. = FALSE)
} else {
  if (n_skip > 0) {
    message(sprintf("26a verification complete. All checks passed (%d skipped).", n_skip))
  } else {
    message("26a verification complete. All checks passed.")
  }
  message(paste("Wrote:", OUT_SUM))
  message(paste("Wrote:", OUT_REP))
  if (file.exists(OUT_FAIL)) message(paste("Wrote:", OUT_FAIL))
}










