norm_ids <- function(df){
  if ("gameid" %in% names(df) && !("game_id" %in% names(df))) df$game_id <- df$gameid
  if ("playid" %in% names(df) && !("play_id" %in% names(df))) df$play_id <- df$playid
  if ("nflid_assigned" %in% names(df) && !("nfl_id_assigned" %in% names(df))) df$nfl_id_assigned <- df$nflid_assigned
  df$game_id <- as.character(df$game_id)
  df$play_id <- as.character(df$play_id)
  if ("nfl_id_assigned" %in% names(df)) df$nfl_id_assigned <- as.character(df$nfl_id_assigned)
  df
}
play <- norm_ids(play)

req_cols <- c("game_id","play_id","nfl_id_assigned","assigned")
missing_cols <- setdiff(req_cols, names(play))
