  dplyr::transmute(
    game_id = as.character(game_id),
    play_id = as.character(play_id),
    nfl_id  = dplyr::if_else(assigned_flag, as.character(nfl_id_assigned), NA_character_)
  ) |>
  dplyr::arrange(game_id, play_id)

n_total      <- nrow(submission)
n_assigned   <- sum(!is.na(submission$nfl_id))
n_unassigned <- n_total - n_assigned

readr::write_csv(submission, OUT_CSV, na = "")

# -------------------- Status + manifest --------------------
op_lines <- character()
if (file.exists(OP_FILE)) {
  op <- tryCatch(readr::read_csv(OP_FILE, show_col_types = FALSE), error = function(e) NULL)
  if (!is.null(op)) {
    op <- janitor::clean_names(op)
    pstar <- if ("p_star" %in% names(op)) suppressWarnings(as.numeric(op$p_star[1])) else NA_real_
    delta <- NA_real_
    for (nm in c("delta","delta_margin","abstain_margin")) if (nm %in% names(op)) {
      v <- suppressWarnings(as.numeric(op[[nm]][1])); if (is.finite(v)) { delta <- v; break }
    }
    op_lines <- c(op_lines,
                  paste0("p*: ", ifelse(is.finite(pstar), sprintf('%.6f', pstar), "NA")),
                  paste0("delta: ", ifelse(is.finite(delta), sprintf('%.6f', delta), "NA"))
    )
  }
}
cal_line <- if (file.exists(CAL_FILE)) {
  m <- trimws(readLines(CAL_FILE, warn = FALSE, n = 1))
  paste0("calibration: ", ifelse(nzchar(m), m, "n/a"))
} else {
  "calibration: n/a"
}

status <- c(
  "# Submission v2 status (Script 27)",
  "",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Input per-play file: ", PLAY_FILE),
  if (file.exists(DEF_FILE)) paste0("Input per-def file: ", DEF_FILE) else "Input per-def file: n/a",
  if (length(op_lines)) c("Operating points:", op_lines) else "Operating points: n/a",
  cal_line,
  "",
  "## Submission output",
  paste0("Rows total: ", n_total),
  paste0("Assigned rows: ", n_assigned),
  paste0("Unassigned rows: ", n_unassigned),
  "",
  paste0("CSV: ", OUT_CSV)
)
writeLines(status, OUT_MD, useBytes = TRUE)

manifest <- list(
  project_root = PROJECT_ROOT,
  created_at = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
  inputs = list(
    score_per_play_v2 = PLAY_FILE,
    score_per_defender_v2 = if (file.exists(DEF_FILE)) DEF_FILE else NULL,
    operating_points = if (file.exists(OP_FILE)) OP_FILE else NULL,
    calibration_method = if (file.exists(CAL_FILE)) CAL_FILE else NULL
  ),
  outputs = list(
    submission_csv = OUT_CSV,
    submission_zip = OUT_ZIP,
    status_md = OUT_MD
  ),
  counts = list(
    total = n_total,
    assigned = n_assigned,
    unassigned = n_unassigned
  )
)
jsonlite::write_json(manifest, OUT_MAN, pretty = TRUE, auto_unbox = TRUE)

# -------------------- Zip with fallback --------------------
zip_hardened <- function(zipfile, files, workdir){
  # prefer utils::zip; if it fails, try zip::zipr if available; else warn
  owd <- getwd(); on.exit(setwd(owd), add = TRUE)
  setwd(workdir)
  # make filenames relative to workdir
  rel <- basename(files)
  ok <- FALSE
  try({
    utils::zip(zipfile = zipfile, files = rel)
    ok <- TRUE
  }, silent = TRUE)
  if (!ok) {
    if (requireNamespace("zip", quietly = TRUE)) {
      zip::zipr(zipfile, rel)
      ok <- TRUE
    }
  }
  if (!ok) warning("Could not create zip archive; 'zip' external tool not found and 'zip' package not installed.")
  invisible(ok)
}

zip_hardened(OUT_ZIP, c(OUT_CSV, OUT_MD, OUT_MAN), ART)

message("Submission finalized.")
message(paste("Wrote CSV:", OUT_CSV))
message(paste("Wrote ZIP:", OUT_ZIP))
message(paste("Wrote status:", OUT_MD))
message(paste("Wrote manifest:", OUT_MAN))










# =====================================================================
# 27a_verify_submission_v2.R — Verify final submission package (Script 27)
#
# Usage (from project root):
#   Rscript Code/27a_verify_submission_v2.R
#
# Verifies:
#   1) submission_v2.csv schema, duplicates, blanks, character validation
#   2) Consistency with submission_v2_status.md (row/assigned/unassigned counts)
#   3) Optional: score_per_play_v2.csv cross-check (if present)
#   4) Optional: submission_v2.zip contains expected files
#
# Writes:
#   artifacts/verify_27a_summary.csv
#   artifacts/verify_27a_report.md
#   artifacts/verify_27a_issues.csv      (if any)
#   artifacts/submission_v2_sample.csv    (small sample for spot check)
# =====================================================================

# -------------------- Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("tidyverse","readr","janitor","stringr","jsonlite","rlang","tibble"))

normu <- function(p) normalizePath(p, mustWork = FALSE)
EPS <- 1e-9

# -------------------- Project root discovery --------------------
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  normu(".")
}
looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}
sf <- this_file()
sdir <- if (file.exists(sf)) dirname(sf) else normu(".")
if (basename(sdir) %in% c("Code","code")) {
  parent <- normu(file.path(sdir, ".."))
  PROJECT_ROOT <- if (looks_like_root(parent)) parent else ascend_until(sdir, looks_like_root, 6)
} else {
  PROJECT_ROOT <- ascend_until(sdir, looks_like_root, 6)
}
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts")
dir.create(ART, recursive = TRUE, showWarnings = FALSE)

# -------------------- Paths --------------------
SUB_CSV <- file.path(ART, "submission_v2.csv")
SUB_MD  <- file.path(ART, "submission_v2_status.md")
SUB_ZIP <- file.path(ART, "submission_v2.zip")
PLAY26  <- file.path(ART, "score_per_play_v2.csv")
OUT_SUM <- file.path(ART, "verify_27a_summary.csv")
OUT_REP <- file.path(ART, "verify_27a_report.md")
OUT_ISS <- file.path(ART, "verify_27a_issues.csv")
SAMPLE  <- file.path(ART, "submission_v2_sample.csv")

# -------------------- Helpers --------------------
normalize_ids <- function(df){
  cols <- intersect(c("game_id","play_id","nfl_id","nfl_id_assigned"), names(df))
  for (c in cols) df[[c]] <- as.character(df[[c]])
  df
}
pass <- function(x) isTRUE(x)
skp  <- function(x) isTRUE(is.na(x))

mkcheck <- function(name, ok, details){
  tibble::tibble(check = name, status = if (pass(ok)) "PASS" else if (skp(ok)) "SKIP" else "FAIL", details = details)
}

# -------------------- 1) Load submission CSV --------------------
if (!file.exists(SUB_CSV)) stop("Missing artifacts/submission_v2.csv. Run Script 27 first.", call. = FALSE)
sub <- readr::read_csv(SUB_CSV, show_col_types = FALSE) |> janitor::clean_names() |> normalize_ids()

issues <- list()

# Required columns
req <- c("game_id","play_id","nfl_id")
missing_cols <- setdiff(req, names(sub))
ok_cols <- length(missing_cols) == 0
if (!ok_cols) issues <- append(issues, list(paste("Missing required columns:", paste(missing_cols, collapse = ", "))))

# Duplicates
dups_n <- if (ok_cols) sub |> dplyr::summarise(n = sum(duplicated(dplyr::across(c(game_id, play_id))))) |> dplyr::pull(n) else NA_integer_
ok_dups <- if (ok_cols) dups_n == 0L else NA
if (isFALSE(ok_dups)) issues <- append(issues, list(paste("Duplicate (game_id, play_id) rows:", dups_n)))

# Blank nfl_id
blank_nfl <- if (ok_cols) sum(is.na(sub$nfl_id) | trimws(sub$nfl_id) == "") else NA_integer_
# Non-digit nfl_id (only count among non-blank)
non_digit_nfl <- if (ok_cols) sum(sub$nfl_id != "" & !grepl("^[0-9]+$", sub$nfl_id)) else NA_integer_

# Save sample
try({
  utils::write.table(head(sub, 5), file = SAMPLE, sep = ",", row.names = FALSE, col.names = TRUE, quote = FALSE)
}, silent = TRUE)

# -------------------- 2) Parse status.md and compare counts --------------------
status_rows <- NA_integer_; status_assigned <- NA_integer_; status_unassigned <- NA_integer_
if (file.exists(SUB_MD)) {
  md <- readLines(SUB_MD, warn = FALSE)
  # extract integers from lines like: "Rows total: 1100"
  parse_int <- function(prefix){
    m <- md[grepl(paste0("^", prefix, "\\s*:"), md)]
    if (length(m)) {
      v <- suppressWarnings(as.integer(gsub("[^0-9]", "", m[1])))
      if (!is.na(v)) return(v)
    }
    NA_integer_
  }
  status_rows       <- parse_int("Rows total")
  status_assigned   <- parse_int("Assigned rows")
  status_unassigned <- parse_int("Unassigned rows")
}

# Computed counts
rows_total      <- nrow(sub)
rows_assigned   <- if (ok_cols) sum(!(is.na(sub$nfl_id) | trimws(sub$nfl_id) == "")) else NA_integer_
rows_unassigned <- if (ok_cols) rows_total - rows_assigned else NA_integer_

ok_counts <- is.na(status_rows) || (status_rows == rows_total)
if (!ok_counts && !is.na(status_rows)) issues <- append(issues, list(paste0("Rows mismatch: status=", status_rows, " vs computed=", rows_total)))

ok_assigned_ct <- is.na(status_assigned) || (status_assigned == rows_assigned)
if (!ok_assigned_ct && !is.na(status_assigned)) issues <- append(issues, list(paste0("Assigned mismatch: status=", status_assigned, " vs computed=", rows_assigned)))

ok_unassigned_ct <- is.na(status_unassigned) || (status_unassigned == rows_unassigned)
if (!ok_unassigned_ct && !is.na(status_unassigned)) issues <- append(issues, list(paste0("Unassigned mismatch: status=", status_unassigned, " vs computed=", rows_unassigned)))

# -------------------- 3) Optional cross-check with 26 outputs --------------------
ok_cross <- NA
if (file.exists(PLAY26)) {
  play <- readr::read_csv(PLAY26, show_col_types = FALSE) |> janitor::clean_names() |> normalize_ids()
  # Require columns
  needed26 <- c("game_id","play_id","assigned","nfl_id_assigned")
  if (all(needed26 %in% names(play)) && ok_cols) {
    # Normalize assigned to logical
    assigned_flag <- tolower(trimws(as.character(play$assigned))) %in% c("true","1","t")
    play$assigned_flag <- assigned_flag
    # Join
    j <- sub |>
      dplyr::left_join(play |> dplyr::select(game_id, play_id, assigned_flag, nfl_id_assigned), by = c("game_id","play_id"))
    # Conditions
    cond_assigned   <- j$assigned_flag & (trimws(j$nfl_id) == trimws(as.character(j$nfl_id_assigned)))
    cond_unassigned <- (!j$assigned_flag) & (is.na(j$nfl_id) | trimws(j$nfl_id) == "")
    ok_cross <- all(cond_assigned | cond_unassigned, na.rm = TRUE)
    if (!ok_cross) {
      bad <- j[!(cond_assigned | cond_unassigned), c("game_id","play_id","nfl_id","nfl_id_assigned","assigned_flag")]
      readr::write_csv(bad, OUT_ISS)
      issues <- append(issues, list(paste0("Cross-check with score_per_play_v2.csv failed; see ", OUT_ISS)))
    }
  } else {
    ok_cross <- NA
  }
}

# -------------------- 4) Optional: check zip contents --------------------
ok_zip <- NA
if (file.exists(SUB_ZIP)) {
  z <- try(utils::unzip(SUB_ZIP, list = TRUE), silent = TRUE)
  if (!inherits(z, "try-error")) {
    want <- c("submission_v2.csv","submission_v2_status.md","submission_v2_manifest.json")
    ok_zip <- all(want %in% z$Name)
    if (!ok_zip) issues <- append(issues, list(paste("Zip missing files:", paste(setdiff(want, z$Name), collapse = ", "))))
  } else {
    ok_zip <- NA
  }
}

# -------------------- Summaries --------------------
summary_tbl <- dplyr::bind_rows(
  mkcheck("csv_columns_present", ok_cols, if (ok_cols) "game_id, play_id, nfl_id present" else paste("Missing:", paste(missing_cols, collapse=", "))),
  mkcheck("no_duplicate_keys", ok_dups, "No duplicate (game_id, play_id) rows"),
  mkcheck("status_rows_match", ok_counts, "Rows in status.md match computed total (or status.md missing)"),
  mkcheck("status_assigned_match", ok_assigned_ct, "Assigned rows in status.md match computed (or missing)"),
  mkcheck("status_unassigned_match", ok_unassigned_ct, "Unassigned rows in status.md match computed (or missing)"),
  mkcheck("crosscheck_with_26", ok_cross, "submission_v2.csv consistent with score_per_play_v2.csv (if present)"),
  mkcheck("zip_contains_expected", ok_zip, "ZIP includes CSV, status, and manifest (if present)")
)

# Add metrics row
metrics <- tibble::tibble(
  metric = c("rows_total","rows_assigned","rows_unassigned","blank_nfl_id","non_digit_nfl_id"),
  value  = c(rows_total, rows_assigned, rows_unassigned, blank_nfl, non_digit_nfl)
)

readr::write_csv(summary_tbl, OUT_SUM)
if (length(issues)) readr::write_csv(tibble::tibble(issue = unlist(issues)), OUT_ISS)

# -------------------- Report --------------------
rep <- c(
  "# Verification report (27a)",
  "",
  paste0("Project root: ", PROJECT_ROOT),
  paste0("Submission CSV: ", SUB_CSV),
  paste0("Status file: ", if (file.exists(SUB_MD)) SUB_MD else "not found"),
  paste0("ZIP file: ", if (file.exists(SUB_ZIP)) SUB_ZIP else "not found"),
  paste0("26 per-play file: ", if (file.exists(PLAY26)) PLAY26 else "not found"),
  "",
  "## Summary",
  paste(capture.output(print(summary_tbl, n = Inf)), collapse = "\n"),
  "",
  "## Metrics",
  paste(capture.output(print(metrics, n = Inf)), collapse = "\n"),
  if (file.exists(SAMPLE)) c("", "## Sample (first 5 rows of submission_v2.csv)", paste(readLines(SAMPLE, warn = FALSE), collapse = "\n")) else ""
)
writeLines(rep, OUT_REP, useBytes = TRUE)

n_fail <- sum(summary_tbl$status == "FAIL", na.rm = TRUE)
n_skip <- sum(summary_tbl$status == "SKIP", na.rm = TRUE)

if (n_fail > 0) {
  message("27a verification completed with FAILURES. See report for details.")
} else {
  if (n_skip > 0) {
    message(sprintf("27a verification complete. All checks passed (%d skipped).", n_skip))
  } else {
    message("27a verification complete. All checks passed.")
  }
}
message(paste("Wrote:", OUT_SUM))
message(paste("Wrote:", OUT_REP))
if (file.exists(OUT_ISS)) message(paste("Wrote:", OUT_ISS))
if (file.exists(SAMPLE)) message(paste("Wrote:", SAMPLE))










#!/usr/bin/env Rscript

# =====================================================================
# 27b_freeze_env.R — Freeze environment: package versions + checksums
#
# Usage (from project root):
#   Rscript Code/27b_freeze_env.R
#
# Writes (under artifacts/):
#   env_session_info.txt
#   env_packages.csv
#   env_lock.json
#   artifacts_checksums.csv
# =====================================================================

options(stringsAsFactors = FALSE)
quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("jsonlite","tools","tibble","readr","dplyr","janitor"))

normu <- function(p) normalizePath(p, mustWork = FALSE)
looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(".")
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  normu(getwd())
}
PROJECT_ROOT <- ascend_until(getwd(), looks_like_root, 6)
B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts"); dir.create(ART, showWarnings = FALSE, recursive = TRUE)

# 1) sessionInfo
capture.output(utils::sessionInfo(), file = file.path(ART, "env_session_info.txt"))

# 2) installed packages
ip <- as.data.frame(installed.packages(), stringsAsFactors = FALSE)
pk <- ip[, c("Package","Version","LibPath","Built")]
pk <- janitor::clean_names(pk)
readr::write_csv(pk, file.path(ART, "env_packages.csv"))

# 3) lockfile (tiny JSON)
lock <- list(
  generated_at = format(Sys.time(), "%Y-%m-%d %H:%M:%S %Z"),
  r_version = paste(R.version$major, R.version$minor, sep = "."),
  platform = R.version$platform,
  packages = setNames(as.list(pk$version), pk$package)
)
jsonlite::write_json(lock, file.path(ART, "env_lock.json"), pretty = TRUE, auto_unbox = TRUE)

# 4) checksums for artifacts
art_dir <- ART
files <- list.files(art_dir, full.names = TRUE, recursive = TRUE, include.dirs = FALSE)
files <- files[file.info(files)$isdir == FALSE]
if (length(files)) {
  sums <- tools::md5sum(files)
  df <- tibble::tibble(file = names(sums), md5 = as.character(sums))
  readr::write_csv(df, file.path(ART, "artifacts_checksums.csv"))
}
message("27b complete. Wrote env and checksums under artifacts/.")










# =====================================================================
# 27c_diff_submission.R — Diff current vs previous submissions (with HARD GATE)
#
# Behavior:
#   - Always writes artifacts/submission_diff.csv.
#   - First run (no baseline): creates baseline pointer + writes EMPTY diff.
#   - Later runs:
#       * If no changes: diff is empty, baseline pointer updates to current snapshot.
#       * If changes exist: diff lists changed plays, HARD GATE fails (exit status 1),
#                          and baseline pointer is NOT updated.
#   - Override (not recommended): set env SUBMISSION_DIFF_ALLOW=1 to bypass the gate.
#
# Usage (from anywhere):
#   Rscript Code/27c_diff_submission.R
# =====================================================================

options(stringsAsFactors = FALSE)
quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("readr","dplyr","janitor","tibble","stringr"))

normu <- function(p) normalizePath(p, mustWork = FALSE)

# Robust script path resolver (works for Rscript and source())
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  normu(".")
}

looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}

sf <- this_file()
sdir <- if (file.exists(sf)) dirname(sf) else normu(".")
if (basename(sdir) %in% c("Code","code")) {
  parent <- normu(file.path(sdir, ".."))
  PROJECT_ROOT <- if (looks_like_root(parent)) parent else ascend_until(sdir, looks_like_root, 6)
} else {
  PROJECT_ROOT <- ascend_until(sdir, looks_like_root, 6)
}
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts"); dir.create(ART, showWarnings = FALSE, recursive = TRUE)

CUR <- file.path(ART, "submission_v2.csv")
if (!file.exists(CUR)) stop(paste0("Missing ", CUR, ". Run Script 27 first."), call. = FALSE)

ts <- format(Sys.time(), "%Y%m%d_%H%M%S")
SNAP <- file.path(ART, paste0("submission_v2_", ts, ".csv"))
BASE_PATH <- file.path(ART, "submission_v2_previous.csv")
OUT <- file.path(ART, "submission_diff.csv")

# Snapshot current (always)
file.copy(CUR, SNAP, overwrite = TRUE)

# Determine baseline
baseline <- if (file.exists(BASE_PATH)) BASE_PATH else {
  older <- list.files(ART, pattern = "^submission_v2_\\d{8}_\\d{6}\\.csv$", full.names = TRUE)
  older <- setdiff(older, SNAP)
  if (length(older)) older[order(older)][length(older)] else NA_character_
}

# Load current
cur <- readr::read_csv(CUR, show_col_types = FALSE) |> janitor::clean_names()
if (!all(c("game_id","play_id","nfl_id") %in% names(cur))) stop("submission_v2.csv must have game_id, play_id, nfl_id", call. = FALSE)
cur <- cur |> dplyr::mutate(game_id = as.character(game_id), play_id = as.character(play_id), nfl_id = as.character(nfl_id))

n_changed <- 0L

if (!is.na(baseline) && file.exists(baseline)) {
  base <- readr::read_csv(baseline, show_col_types = FALSE) |> janitor::clean_names()
  base <- base |> dplyr::mutate(game_id = as.character(game_id), play_id = as.character(play_id), nfl_id = as.character(nfl_id))
  joined <- cur |> dplyr::full_join(base, by = c("game_id","play_id"), suffix = c("_cur","_base"))
  changed <- joined |> dplyr::filter(
    (is.na(nfl_id_base) & !is.na(nfl_id_cur)) |
      (!is.na(nfl_id_base) & is.na(nfl_id_cur)) |
      (!is.na(nfl_id_base) & !is.na(nfl_id_cur) & nfl_id_cur != nfl_id_base)
  )
  readr::write_csv(changed, OUT)
  n_changed <- nrow(changed)
  message(paste0("Wrote diff: ", OUT, " (", n_changed, " changed plays)"))
} else {
  # First run: write an empty diff so downstream steps always have a file
  empty <- tibble::tibble(
    game_id = character(),
    play_id = character(),
    nfl_id_cur = character(),
    nfl_id_base = character()
  )
  readr::write_csv(empty, OUT)
  message(paste0("First baseline created. Wrote empty diff (0 changed plays): ", OUT))
}

# Baseline pointer update policy:
#   - First run: set baseline to current snapshot
#   - Later runs: update only if n_changed == 0 (identical); otherwise keep the old baseline
if (!file.exists(BASE_PATH) || is.na(baseline)) {
  file.copy(CUR, BASE_PATH, overwrite = TRUE)
  message(paste("Baseline pointer created:", BASE_PATH))
} else if (n_changed == 0L) {
  file.copy(CUR, BASE_PATH, overwrite = TRUE)
  message(paste("Baseline pointer updated:", BASE_PATH))
} else {
  message("Baseline pointer NOT updated due to changes.")
}

# HARD GATE: fail if changes detected, unless explicitly allowed
allow <- identical(Sys.getenv("SUBMISSION_DIFF_ALLOW"), "1")
if (n_changed > 0L && !allow) {
  message(sprintf("Hard gate: %d changed plays vs baseline. See %s", n_changed, OUT))
  quit(status = 1)
} else {
  message(sprintf("Hard gate: %d changed plays. Proceeding.", n_changed))
  invisible(NULL)
}










# =====================================================================
# 27d_release_pipeline.R — One-shot, self-contained release pipeline
#
# What it does, in order:
#   0) Preconditions: submission exists, 27c hard gate result respected
#   1) Ensure 27d_model_card.Rmd exists (auto-generate if missing), then render HTML
#   2) Inline drift check (PSI/KS) with hard gate (PSI > threshold fails)
#   3) Inline environment freeze: sessionInfo, package versions, artifact checksums
#   4) Inline archive: zip Code + artifacts into versioned release ZIP
#
# Controls (env vars):
#   SUBMISSION_DIFF_ALLOW=1      # bypass 27c hard gate if diffs exist
#   DRIFT_PSI_THRESHOLD=0.25     # PSI threshold
#   DRIFT_ALLOW=1                # bypass drift gate
#   RELEASE_VERSION=v2.0         # override archive version tag
#
# Usage:
#   Rscript Code/27d_release_pipeline.R
#   # or from anywhere:
#   source("~/Desktop/bdb_project/Code/27d_release_pipeline.R")
# =====================================================================

options(stringsAsFactors = FALSE)
quiet_pkgs <- function(pkgs){
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}
quiet_pkgs(c("readr","dplyr","janitor","tibble","jsonlite","rlang","stringr","tools"))

normu <- function(p) normalizePath(p, mustWork = FALSE)

# Robust script path resolver (Rscript + source())
this_file <- function(){
  a <- commandArgs(trailingOnly = FALSE)
  i <- grep("^--file=", a)
  if (length(i)) return(normu(sub("^--file=", "", a[i[1]])))
  cf <- sys.calls()
  for (k in rev(seq_along(cf))) {
    call <- cf[[k]]
    if (as.character(call[[1]]) %in% c("source")) {
      args <- as.list(call)[-1]
      for (v in args) if (is.character(v) && length(v) == 1) return(normu(v))
    }
  }
  normu(".")
}

looks_like_root <- function(p) dir.exists(file.path(p,"Code")) && dir.exists(file.path(p,"artifacts"))
ascend_until <- function(start, predicate, max_steps = 6){
  cur <- normu(start)
  for (i in 0:max_steps) {
    if (predicate(cur)) return(cur)
    parent <- normu(file.path(cur, ".."))
    if (identical(parent, cur)) break
    cur <- parent
  }
  NA_character_
}

sf <- this_file()
sdir <- if (file.exists(sf)) dirname(sf) else normu(".")
if (basename(sdir) %in% c("Code","code")) {
  parent <- normu(file.path(sdir, ".."))
  PROJECT_ROOT <- if (looks_like_root(parent)) parent else ascend_until(sdir, looks_like_root, 6)
} else {
  PROJECT_ROOT <- ascend_until(sdir, looks_like_root, 6)
}
if (is.na(PROJECT_ROOT)) PROJECT_ROOT <- normu(getwd())

B <- function(...) file.path(PROJECT_ROOT, ...)
ART <- B("artifacts"); dir.create(ART, showWarnings = FALSE, recursive = TRUE)
CODE <- B("Code"); dir.create(CODE, showWarnings = FALSE, recursive = TRUE)

