# -------------------- 2) Inline drift check --------------------
PRED_CAND <- c(
  file.path(ART, "v2_model04_test_preds_cal.csv"),
  file.path(ART, "v2_model04_val_preds_cal.csv"),
  file.path(ART, "v2_model04_test_preds.csv"),
  file.path(ART, "v2_model04_val_preds.csv")
)
PRED_FILE <- PRED_CAND[file.exists(PRED_CAND)]
PRED_FILE <- if (length(PRED_FILE)) PRED_FILE[[1]] else ""
PSI_FILE <- file.path(ART, "drift_psi.csv")
DRIFT_REP <- file.path(ART, "drift_report.md")

PSI <- NA_real_
KS  <- NA_real_

if (nzchar(PRED_FILE)) {
  pr <- readr::read_csv(PRED_FILE, show_col_types = FALSE) |> janitor::clean_names()
  pcol <- intersect(names(pr), c("p_go_cal","p_go","p","prob","prediction"))[1]
  if (!is.na(pcol)) {
    p <- suppressWarnings(as.numeric(pr[[pcol]])); p <- p[is.finite(p) & p >= 0 & p <= 1]
    BASE_BINS <- file.path(ART, "preds_baseline_bins.csv")
    # Build or load baseline edges
    if (file.exists(BASE_BINS)) {
      bb <- try(readr::read_csv(BASE_BINS, show_col_types = FALSE), silent = TRUE)
      cuts <- if (!inherits(bb, "try-error") && "cut" %in% names(bb)) bb$cut else seq(0,1,by=0.1)
      cuts <- sort(unique(pmax(pmin(cuts,1),0)))
      if (min(cuts) > 0) cuts <- c(0, cuts)
      if (max(cuts) < 1) cuts <- c(cuts, 1)
    } else {
      cuts <- quantile(p, probs = seq(0, 1, by = 0.1), na.rm = TRUE, names = FALSE)
      cuts <- sort(unique(pmax(pmin(cuts, 1), 0)))
      readr::write_csv(tibble::tibble(cut = cuts), BASE_BINS)
    }
    # Proportions
    bin_prop <- function(x, edges){
      bins <- cut(x, breaks = unique(edges), include.lowest = TRUE, right = TRUE, dig.lab = 16)
      prop <- as.numeric(table(bins)) / length(x)
      tibble::tibble(bin = seq_along(prop), prop = prop)
    }
    bb_df <- try(readr::read_csv(BASE_BINS, show_col_types = FALSE), silent = TRUE)
    if (!inherits(bb_df, "try-error") && "prop" %in% names(bb_df)) {
      base_prop <- bb_df$prop; base_prop <- base_prop / sum(base_prop)
      base <- tibble::tibble(bin = seq_along(base_prop), prop = base_prop)
    } else {
      base <- bin_prop(p, cuts)
      readr::write_csv(tibble::tibble(cut = cuts, prop = base$prop), BASE_BINS)
    }
    cur <- bin_prop(p, cuts)
    eps <- 1e-6
    PSI <- sum( (cur$prop - base$prop) * log( (cur$prop + eps) / (base$prop + eps) ) )
    KS  <- max(abs(cumsum(base$prop) - cumsum(cur$prop)))
    psi_tbl <- dplyr::tibble(
      metric = c("PSI","KS"),
      value = c(PSI, KS),
      pred_file = basename(PRED_FILE),
      bins = length(base$prop)
    )
    readr::write_csv(psi_tbl, PSI_FILE)
    rep <- c(
      "# Drift report (27d inline)",
      "",
      paste0("Predictions file: ", PRED_FILE),
      paste0("Probability column: ", pcol),
      paste0("Bins: ", length(base$prop)),
      "",
      "## Metrics",
      paste0("- PSI: ", signif(PSI, 6)),
      paste0("- KS:  ", signif(KS, 6)),
      "",
      "## Guidance",
      "- PSI < 0.1 negligible; 0.1–0.25 moderate; > 0.25 investigate.",
      "- KS closer to 0 means distributions are similar."
    )
    writeLines(rep, DRIFT_REP, useBytes = TRUE)
  } else {
    writeLines("No probability column found; drift check skipped.", DRIFT_REP, useBytes = TRUE)
  }
} else {
  writeLines("No predictions file found; drift check skipped.", DRIFT_REP, useBytes = TRUE)
}

# Hard gate on PSI
thresh <- as.numeric(Sys.getenv("DRIFT_PSI_THRESHOLD", "0.25"))
allow  <- identical(Sys.getenv("DRIFT_ALLOW"), "1")
if (is.finite(PSI) && PSI > thresh && !allow) {
  stop(sprintf("Hard gate: PSI %.4f exceeds threshold %.4f. See %s", PSI, thresh, DRIFT_REP), call. = FALSE)
}

