zip_hardened <- function(zipfile, files, workdir){
  owd <- getwd(); on.exit(setwd(owd), add = TRUE)
  setwd(workdir)
  rel <- gsub(paste0("^", normalizePath(workdir, winslash="/", mustWork=TRUE), "/?"), "", normalizePath(files, winslash="/", mustWork=TRUE))
  rel <- rel[rel != ""]
  ok <- FALSE
  try({ utils::zip(zipfile = zipfile, files = rel); ok <- TRUE }, silent = TRUE)
  if (!ok && requireNamespace("zip", quietly = TRUE)) { zip::zipr(zipfile, rel); ok <- TRUE }
  if (!ok) warning("Could not create zip archive. Install.packages('zip') to enable fallback.")
  invisible(ok)
}
zip_hardened(REL_ZIP, FILES, PROJECT_ROOT)

