read_csv_clean <- function(path) {
  suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |>
    janitor::clean_names()
}

require_cols <- function(df, cols, where = "data"){
  miss <- setdiff(cols, names(df))
  if (length(miss)) {
    stop(sprintf("Missing required columns in %s: %s", where, paste(miss, collapse = ", ")), call. = FALSE)
  }
  invisible(TRUE)
}

md_table <- function(df){
  if (!nrow(df)) return(character(0))
  hdr <- paste("|", paste(names(df), collapse = " | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df)), collapse = " | "), "|")
  rows <- apply(df, 1, function(r) paste("|", paste(as.character(r), collapse = " | "), "|"))
  c(hdr, sep, rows)
}

pass_flag <- function(x) if (isTRUE(x)) "PASS" else "FAIL"

