    t1     = suppressWarnings(max(frame_id, na.rm = TRUE)),           # last frame of window
    num    = suppressWarnings(max(num_frames_output, na.rm = TRUE)),  # window length in frames
    x_land = suppressWarnings(max(ball_land_x, na.rm = TRUE)),
    y_land = suppressWarnings(max(ball_land_y, na.rm = TRUE)),
    .groups = "drop"
  ) |>
  mutate(
    t0 = t1 - num + 1L,
    T_ball_frame = (t1 - t0) * DT,
    valid = is.finite(t0) & is.finite(t1) & is.finite(T_ball_frame) & t1 >= t0 & T_ball_frame > 0
  ) |>
  filter(valid)

n_total_plays <- dplyr::n_distinct(inputs$game_id, inputs$play_id)
n_window_plays <- nrow(windows)
cov_windows <- if (n_total_plays > 0) n_window_plays / n_total_plays else NA_real_

message(sprintf("[3/6] Formed windows for %d plays (coverage=%.4f).",
                n_window_plays, cov_windows))

if (!n_window_plays) {
  stop("No valid windows could be formed (t0/t1/T_ball_frame invalid for all plays).", call. = FALSE)
}

# ---------------------- 4) Optional split map -------------------------
splits <- NULL
if (file.exists(PATH_SPLIT_MAP)) {
  splits <- read_csv_clean(PATH_SPLIT_MAP) |>
    transmute(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      split   = tolower(as.character(split))
    )
  message(sprintf("[4/6] Loaded split map with %d rows.", nrow(splits)))
} else {
  message("[4/6] No split map found at data/splits/plays_split_map.csv; treating all plays as 'unspecified' split.")
}

windows <- windows |>
  left_join(splits, by = c("game_id","play_id")) |>
  mutate(split = ifelse(is.na(split), "unspecified", split))

# ---------------------- 5) Ball timing choices ------------------------
# NOTE: In this project snapshot we do not have ball height (z),
# so we always use frame-count timing. The structure below is written so
# that a future z-based model can be slotted in without changing outputs.
windows <- windows |>
  mutate(
    T_ball = T_ball_frame,
    method = "frame",
    err_s  = 0
  )

ball_timing <- windows |>
  transmute(
    game_id,
    play_id,
    T_ball = as.numeric(T_ball),
    method = as.character(method),
    err_s  = as.numeric(err_s)
  ) |>
  arrange(game_id, play_id)

readr::write_csv(ball_timing, OUT_TIMING)

# ---------------------- 6) Residuals + model + status -----------------
windows_err <- windows |>
  mutate(
    abs_err = abs(err_s)
  )

resid_summary <- windows_err |>
  group_by(split) |>
  summarise(
    n              = dplyr::n(),
    median_abs_err = ifelse(n > 0, median(abs_err, na.rm = TRUE), NA_real_),
    mean_abs_err   = ifelse(n > 0, mean(abs_err, na.rm = TRUE), NA_real_),
    p90_abs_err    = ifelse(n > 0, as.numeric(quantile(abs_err, 0.90, na.rm = TRUE, names = FALSE)), NA_real_),
    max_abs_err    = ifelse(n > 0, max(abs_err, na.rm = TRUE), NA_real_),
    .groups = "drop"
  )

ball_model <- list(
  method = "frame_only",
  params = list(DT = DT),
  residuals_summary = resid_summary
)
saveRDS(ball_model, OUT_MODEL)

# Coverage: plays with T_ball relative to plays seen in inputs
n_tball_plays <- dplyr::n_distinct(ball_timing$game_id, ball_timing$play_id)
cov_tball <- if (n_total_plays > 0) n_tball_plays / n_total_plays else NA_real_

val_row <- resid_summary |> dplyr::filter(split == "val")
val_median_err <- if (nrow(val_row)) val_row$median_abs_err[1] else NA_real_
val_ok <- is.na(val_median_err) || (!is.na(val_median_err) && val_median_err <= 0.05)
cov_ok <- !is.na(cov_tball) && cov_tball >= 0.99

checks <- tibble::tibble(
  check = c(
    "inputs_source",
    "plays_with_T_ball_coverage>=0.99",
    "val_median_abs_error<=0.05_or_frame_only"
  ),
  detail = c(
    sprintf("source=%s | files=%d", source_type, length(input_files)),
    sprintf("plays_with_T_ball=%d of %d (coverage=%.6f)", n_tball_plays, n_total_plays, cov_tball),
    if (is.na(val_median_err)) {
      "no VAL plays from this input source; using frame-based timing only (err_s=0 by construction)"
    } else {
      sprintf("VAL median |error|=%.6f", val_median_err)
    }
  ),
  status = c(
    "PASS",
    pass_flag(cov_ok),
    pass_flag(val_ok)
  )
)

readr::write_csv(checks, OUT_STATUS_C)
writeLines(c("# Ball timing status", "", md_table(checks)), OUT_STATUS_M, useBytes = TRUE)

report <- c(
  "# Ball timing model",
  "",
  sprintf("- Input source: %s (%d files)", source_type, length(input_files)),
  sprintf("- Unique plays seen in inputs: %d", n_total_plays),
  sprintf("- Plays with T_ball after windowing: %d (coverage=%.6f)", n_tball_plays, cov_tball),
  "",
  "## Residuals summary by split",
  "",
  md_table(resid_summary),
  "",
  "## Acceptance checks",
  "",
  sprintf("- Coverage ≥ 0.99: %s", ifelse(cov_ok, "PASS", "FAIL")),
  sprintf("- VAL median |error| ≤ 0.05 or frame-only fallback: %s", ifelse(val_ok, "PASS", "FAIL")),
  "",
  "Notes:",
  "- This implementation uses frame-count timing only (no ball height available in current data snapshot).",
  "- err_s is the absolute error vs frame-count baseline; with method='frame' this is identically 0."
)

writeLines(report, OUT_REPORT, useBytes = TRUE)

message("Ball timing artifacts written:",
        "\n  - ", OUT_TIMING,
        "\n  - ", OUT_MODEL,
        "\n  - ", OUT_REPORT,
        "\n  - ", OUT_STATUS_C,
        "\n  - ", OUT_STATUS_M)

if (!cov_ok || !val_ok) {
  stop("Ball timing acceptance criteria not met. See status/report artifacts for details.", call. = FALSE)
}

cat("\n[Done] Script 28_ball_timing_model.R completed successfully.\n")










# 28a_verify_ball_timing.R  (warning-free, prints PASS/FAIL)
# Verifies outputs of 28_ball_timing_model.R against Phase-3 acceptance.
# Outputs: artifacts/{ball_timing_verify_status.csv, ball_timing_verify_status.md}

suppressPackageStartupMessages({
  library(tidyverse); library(readr); library(janitor)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
ART <- B("artifacts")

PATH_BT   <- file.path(ART, "ball_timing.csv")
PATH_STAT <- file.path(ART, "ball_timing_status.csv")

if (!file.exists(PATH_BT)) stop("Missing: ", PATH_BT)

bt <- suppressMessages(readr::read_csv(PATH_BT, show_col_types = FALSE)) |> janitor::clean_names()

# Required schema after clean_names()
req <- c("game_id","play_id","t_ball","method","err_s")
missing <- setdiff(req, names(bt))
if (length(missing)) stop("ball_timing.csv missing required columns: ", paste(missing, collapse = ", "))

n <- nrow(bt)

checks <- tibble(
  check = c(
    "ball_timing_exists",
    "schema_ok",
    "n_rows>0",
    "no_na_t_ball",
    "t_ball>0",
    "err_s>=0",
    "method_nonmissing"
  ),
  status = c(
    file.exists(PATH_BT),
    length(missing) == 0,
    n > 0,
    all(is.finite(bt$t_ball)),
    all(bt$t_ball > 0, na.rm = TRUE),
    all(replace_na(bt$err_s, 0) >= 0),
    all(!is.na(bt$method) & nzchar(as.character(bt$method)))
  )
)

# Mirror status checks if present, without referencing missing columns
if (file.exists(PATH_STAT)) {
  st <- suppressMessages(readr::read_csv(PATH_STAT, show_col_types = FALSE))
  pass_col <- intersect(c("status_flag","status"), names(st))
  if (length(pass_col)) {
    pass_col <- pass_col[[1]]
    want <- c("plays_with_T_ball_coverage>=0.99","val_median_abs_error<=0.05_or_frame_only")
    for (nm in want) {
      if (nm %in% st$check) {
        passed <- any(st$check == nm & toupper(as.character(st[[pass_col]])) == "PASS", na.rm = TRUE)
        checks <- bind_rows(checks, tibble(check = paste0("status:", nm), status = passed))
      }
    }
  }
}

checks <- checks |> mutate(status_flag = ifelse(status, "PASS", "FAIL"))
readr::write_csv(checks, file.path(ART, "ball_timing_verify_status.csv"))

md <- c(
  "# 28a Verify – Ball timing",
  "",
  sprintf("- Rows: %d", n),
  sprintf("- Methods: %s", paste(sort(unique(bt$method)), collapse = ", ")),
  "",
  "## Checks",
  paste0("| check | status |", "\n|---|---|\n",
         paste0("| ", checks$check, " | ", checks$status_flag, " |", collapse = "\n"))
)
writeLines(md, file.path(ART, "ball_timing_verify_status.md"))

# Console summary (PASS/FAIL)
final_pass <- all(checks$status, na.rm = TRUE)
if (isTRUE(final_pass)) {
  cat(sprintf("[28a PASS] Ball timing verification passed all %d checks.\n", nrow(checks)))
} else {
  failed <- checks$check[!checks$status]
  cat(sprintf("[28a FAIL] Failed checks: %s\n", paste(failed, collapse = ", ")))
}










# 29_latency_turncost_profiles.R
# Purpose:
#   Estimate reaction latency at throw and yaw-rate/turn-cost curves;
#   extend capability profiles and build WR burst + lane priors.
#
# Inputs:
#   - ./train/input_2023_wNN.csv              (tracking windows, as in Script 01)
#   - ./artifacts/capability_profiles.csv     (after 01 + 25a)
#   - ./artifacts/ball_timing.csv             (from 28_ball_timing_model.R)
#   - ./train/supplementary_data.csv          (for pass_location_type / lanes)
#   - ./data/splits/plays_split_map.csv       (optional, for reporting only)
#
# Outputs:
#   - ./artifacts/defender_profiles_v3.csv
#       (nfl_id, v_max, a_max, yaw_rate_max,
#        turn_cost_per_rad, turn_cost_se, n_turn_fit,
#        latency_mu, latency_sd, latency_se, n_latency)
#   - ./artifacts/wr_profiles_v3.csv
#       (nfl_id, n_plays, burst_0_0p5_mu, burst_0_0p5_sd, burst_0_0p5_se,
#        n_targets, n_targets_lane,
#        lane_L_prior, lane_M_prior, lane_R_prior)
#   - ./artifacts/turncost_curves.png
#   - ./artifacts/latency_hist_by_pos.png
#   - ./artifacts/latency_turncost_status.csv
#   - ./artifacts/latency_turncost_status.md
#   - ./artifacts/latency_turncost_report.md
#
# CLI:
#   Rscript Code/29_latency_turncost_profiles.R
#
# Assumptions:
#   - DT = 0.1 s between frames (10 Hz), as in the rest of your pipeline.
#   - We use BDB-provided speed (s) and direction (dir) rather than
#     re-deriving v,a from x,y; heading is unwrapped from dir.

# -------------------- 0) Setup --------------------
options(
  repos = c(CRAN = "https://cloud.r-project.org"),
  timeout = max(600, getOption("timeout", 60)),
  dplyr.summarise.inform = FALSE,
  stringsAsFactors = FALSE
)

quiet_pkgs <- function(pkgs) {
  need <- pkgs[!pkgs %in% rownames(installed.packages())]
  if (length(need)) {
    dir.create(Sys.getenv("R_LIBS_USER"), recursive = TRUE, showWarnings = FALSE)
    try(install.packages(need, quiet = TRUE))
  }
  suppressPackageStartupMessages(invisible(lapply(pkgs, require, character.only = TRUE)))
}

quiet_pkgs(c("tidyverse", "readr", "janitor", "purrr", "stringr", "scales", "tibble", "ggplot2"))

# Project paths
B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
DIRS <- list(
  train     = B("train"),
  artifacts = B("artifacts"),
  data      = B("data"),
  splits    = B("data", "splits")
)
invisible(lapply(DIRS, function(p) dir.create(p, recursive = TRUE, showWarnings = FALSE)))

PATH_CAP       <- file.path(DIRS$artifacts, "capability_profiles.csv")
PATH_TIMING    <- file.path(DIRS$artifacts, "ball_timing.csv")
PATH_SUPP      <- file.path(DIRS$train,     "supplementary_data.csv")
PATH_SPLITMAP  <- file.path(DIRS$splits,    "plays_split_map.csv")

OUT_DEF        <- file.path(DIRS$artifacts, "defender_profiles_v3.csv")
OUT_WR         <- file.path(DIRS$artifacts, "wr_profiles_v3.csv")
OUT_TC_PLOT    <- file.path(DIRS$artifacts, "turncost_curves.png")
OUT_LAT_PLOT   <- file.path(DIRS$artifacts, "latency_hist_by_pos.png")
OUT_STATUS_C   <- file.path(DIRS$artifacts, "latency_turncost_status.csv")
OUT_STATUS_M   <- file.path(DIRS$artifacts, "latency_turncost_status.md")
OUT_REPORT_M   <- file.path(DIRS$artifacts, "latency_turncost_report.md")

DT <- 0.1  # seconds per frame

read_csv_clean <- function(path) {
  suppressMessages(readr::read_csv(path, show_col_types = FALSE, progress = FALSE)) |>
    janitor::clean_names()
}

require_cols <- function(df, cols, where = "data") {
  miss <- setdiff(cols, names(df))
  if (length(miss)) {
    stop(sprintf("Missing required columns in %s: %s", where, paste(miss, collapse = ", ")), call. = FALSE)
  }
  invisible(TRUE)
}

md_table <- function(df) {
  if (is.null(df) || !nrow(df)) return(character(0))
  df_chr <- df
  for (j in seq_len(ncol(df_chr))) {
    df_chr[[j]] <- as.character(df_chr[[j]])
  }
  hdr <- paste("|", paste(names(df_chr), collapse = " | "), "|")
  sep <- paste("|", paste(rep("---", ncol(df_chr)), collapse = " | "), "|")
  rows <- apply(df_chr, 1, function(r) paste("|", paste(r, collapse = " | "), "|"))
  c(hdr, sep, rows)
}

deg_unwrap <- function(theta_deg) {
  rad <- theta_deg * pi / 180
  out <- numeric(length(rad))
  if (length(rad) > 0) out[1] <- rad[1]
  if (length(rad) > 1) {
    for (i in 2:length(rad)) {
      d <- rad[i] - rad[i - 1]
      d <- atan2(sin(d), cos(d))
      out[i] <- out[i - 1] + d
    }
  }
  out * 180 / pi
}

# -------------------- 1) Load capability profiles & ball timing --------------------
if (!file.exists(PATH_CAP)) {
  stop("Missing artifacts/capability_profiles.csv. Run Script 01 + 25a first.", call. = FALSE)
}
if (!file.exists(PATH_TIMING)) {
  stop("Missing artifacts/ball_timing.csv. Run Script 28 first.", call. = FALSE)
}
if (!file.exists(PATH_SUPP)) {
  stop("Missing train/supplementary_data.csv. Build it from nflverse enrichment scripts.", call. = FALSE)
}

cap <- read_csv_clean(PATH_CAP) |>
  dplyr::rename(
    nfl_id        = dplyr::any_of("nfl_id"),
    v_max         = dplyr::any_of("v_max"),
    a_max         = dplyr::any_of("a_max"),
    turn_rate_p95 = dplyr::any_of("turn_rate_p95")
  )

require_cols(cap, c("nfl_id", "v_max", "a_max", "turn_rate_p95"), "capability_profiles")
cap <- cap |>
  dplyr::mutate(nfl_id = as.character(nfl_id)) |>
  dplyr::distinct(nfl_id, .keep_all = TRUE)

# IMPORTANT: do NOT clean names here; keep T_ball exactly as written by Script 28
ball_timing <- suppressMessages(readr::read_csv(PATH_TIMING, show_col_types = FALSE, progress = FALSE)) |>
  dplyr::transmute(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id)),
    T_ball  = as.numeric(T_ball)
  )

require_cols(ball_timing, c("game_id", "play_id", "T_ball"), "ball_timing")

splits <- NULL
if (file.exists(PATH_SPLITMAP)) {
  splits <- read_csv_clean(PATH_SPLITMAP) |>
    dplyr::transmute(
      game_id = as.character(game_id),
      play_id = suppressWarnings(as.integer(play_id)),
      split   = as.character(split)
    )
}

supp <- read_csv_clean(PATH_SUPP) |>
  dplyr::transmute(
    game_id            = as.character(game_id),
    play_id            = suppressWarnings(as.integer(play_id)),
    pass_location_type = as.character(pass_location_type)
  )

# -------------------- 2) Load tracking inputs --------------------
files <- list.files(DIRS$train, pattern = "^input_\\d{4}_w\\d{2}\\.csv$", full.names = TRUE)
if (!length(files)) {
  stop(sprintf("No training CSVs found in %s matching input_YYYY_wNN.csv", DIRS$train), call. = FALSE)
}

message(sprintf("[1/6] Found %d training files.", length(files)))
dat <- purrr::map_dfr(files, read_csv_clean)

dat <- dat |>
  janitor::clean_names() |>
  dplyr::rename(
    game_id         = dplyr::any_of("game_id"),
    play_id         = dplyr::any_of("play_id"),
    nfl_id          = dplyr::any_of(c("nfl_id", "nflid")),
    frame_id        = dplyr::any_of(c("frame_id", "frameid")),
    x               = dplyr::any_of("x"),
    y               = dplyr::any_of("y"),
    s               = dplyr::any_of("s"),
    a               = dplyr::any_of("a"),
    dir             = dplyr::any_of("dir"),
    o               = dplyr::any_of("o"),
    player_role     = dplyr::any_of("player_role"),
    player_side     = dplyr::any_of("player_side"),
    player_position = dplyr::any_of("player_position")
  )

require_cols(
  dat,
  c("game_id", "play_id", "nfl_id", "frame_id", "s", "dir",
    "player_role", "player_side", "player_position"),
  "tracking data"
)

# Type normalization
num_cols <- intersect(c("x", "y", "s", "a", "dir", "o"), names(dat))
for (nm in num_cols) dat[[nm]] <- suppressWarnings(as.numeric(dat[[nm]]))
dat$frame_id <- suppressWarnings(as.integer(dat$frame_id))
dat$nfl_id   <- as.character(dat$nfl_id)
dat$game_id  <- as.character(dat$game_id)
dat$play_id  <- suppressWarnings(as.integer(dat$play_id))

# Basic sanity filters (aligned with Script 01 logic)
dat <- dat |>
  dplyr::filter(!is.na(nfl_id), !is.na(frame_id)) |>
  dplyr::filter(!is.na(s), s >= 0, s <= 12)

if ("a" %in% names(dat)) {
  dat <- dat |>
    dplyr::filter(is.na(a) | (a >= -10 & a <= 10))
}

dat <- dat |>
  dplyr::filter(!is.na(dir), dir >= 0, dir <= 360)

message(sprintf("[2/6] Frames after sanity filters: %s", format(nrow(dat), big.mark = ",")))

# -------------------- 3) Per-play throw frame (using ball_timing) --------------------
plays <- dat |>
  dplyr::group_by(game_id, play_id) |>
  dplyr::summarise(
    t1 = max(frame_id, na.rm = TRUE),
    .groups = "drop"
  ) |>
  dplyr::mutate(
    game_id = as.character(game_id),
    play_id = suppressWarnings(as.integer(play_id))
  ) |>
  dplyr::inner_join(ball_timing, by = c("game_id", "play_id")) |>
  dplyr::mutate(
    frames_ball = round(T_ball / DT),
    throw_frame = t1 - frames_ball
  ) |>
  dplyr::filter(is.finite(throw_frame))

n_pl <- nrow(plays)
message(sprintf("[3/6] Derived throw_frame for %d plays with ball timing.", n_pl))

if (n_pl == 0) {
  stop("No plays with both tracking and ball_timing available.", call. = FALSE)
}

if (!is.null(splits)) {
  plays <- plays |>
    dplyr::left_join(splits, by = c("game_id", "play_id"))
}

# -------------------- 4) Defender kinematics & latency --------------------
# Focus on defensive coverage players
dat_def <- dat |>
  dplyr::filter(
    player_side == "Defense",
    player_role == "Defensive Coverage"
  ) |>
  dplyr::inner_join(
    plays |> dplyr::select(game_id, play_id, throw_frame),
    by = c("game_id", "play_id")
  )

if (!nrow(dat_def)) {
  stop("No defensive coverage rows after joining with ball_timing plays.", call. = FALSE)
}

def_turn <- dat_def |>
  dplyr::arrange(nfl_id, game_id, play_id, frame_id) |>
  dplyr::group_by(nfl_id, game_id, play_id) |>
  dplyr::mutate(
    heading       = deg_unwrap(dir),
    heading_lead  = dplyr::lead(heading),
    s_lead        = dplyr::lead(s),
    yaw_diff_deg  = heading_lead - heading,
    yaw_rate_deg  = abs(yaw_diff_deg) / DT,
    speed_loss    = pmax(0, s - s_lead),
    frame_rel     = frame_id - throw_frame,
    t_rel         = frame_rel * DT
  ) |>
  dplyr::ungroup() |>
  dplyr::filter(!is.na(yaw_rate_deg), !is.na(speed_loss), !is.na(frame_rel))

# Latency: change-point in |Δspeed| post-throw
pre_win_s   <- 1.0   # seconds before throw for pre-throw FP calibration
post_win_s  <- 1.5   # seconds after throw for latency search
pre_win_fr  <- ceiling(pre_win_s / DT)
post_win_fr <- ceiling(post_win_s / DT)

pre_events <- def_turn |>
  dplyr::filter(frame_rel < 0, frame_rel >= -pre_win_fr) |>
  dplyr::mutate(delta_s = s_lead - s) |>
  dplyr::filter(!is.na(delta_s))

pre_mag <- abs(pre_events$delta_s)
thr <- if (length(pre_mag)) stats::quantile(pre_mag, 0.98, na.rm = TRUE) else NA_real_
# Use strict '>' here so FP is truly about the upper tail beyond the 98th percentile
fp_rate <- if (length(pre_mag)) mean(pre_mag > thr, na.rm = TRUE) else NA_real_

# Post-throw events for latency (min 3 frames post-throw)
lat_tbl <- NULL
if (is.finite(thr)) {
  post_events <- def_turn |>
    dplyr::mutate(delta_s = s_lead - s) |>
    dplyr::filter(frame_rel >= 0, frame_rel <= post_win_fr)
  
  lat_tbl <- post_events |>
    dplyr::group_by(nfl_id, game_id, play_id) |>
    dplyr::arrange(frame_rel, .by_group = TRUE) |>
    dplyr::summarise(
      latency_frames = {
        cand <- frame_rel[frame_rel >= 3 & abs(delta_s) >= thr]
        if (length(cand)) cand[1] else NA_integer_
      },
      latency_s = latency_frames * DT,
      .groups = "drop"
    )
} else {
  lat_tbl <- tibble::tibble(
    nfl_id = character(0),
    game_id = character(0),
    play_id = integer(0),
    latency_frames = integer(0),
    latency_s = numeric(0)
  )
}

lat_by_def <- lat_tbl |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    n_latency   = sum(!is.na(latency_s)),
    latency_mu  = ifelse(n_latency > 0, mean(latency_s, na.rm = TRUE), NA_real_),
    latency_sd  = ifelse(n_latency > 1, stats::sd(latency_s, na.rm = TRUE), NA_real_),
    latency_se  = ifelse(n_latency > 1, latency_sd / sqrt(pmax(n_latency, 1)), NA_real_),
    .groups = "drop"
  )

# -------------------- 5) Turn-rate stats & turn-cost regression --------------------
turn_events <- def_turn |>
  dplyr::filter(s >= 1, yaw_rate_deg >= 0, yaw_rate_deg < 1000)

yaw_by_def <- turn_events |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    yaw_rate_max_emp = if (dplyr::n() > 0) stats::quantile(yaw_rate_deg, 0.95, na.rm = TRUE) else NA_real_,
    n_turn           = dplyr::n(),
    .groups = "drop"
  )

fit_turn_cost <- function(df) {
  if (!nrow(df)) return(list(beta = NA_real_, se = NA_real_, n = 0L))
  x <- (df$yaw_rate_deg * pi / 180)    # radians per second
  y <- df$speed_loss
  ok <- is.finite(x) & is.finite(y)
  x <- x[ok]; y <- y[ok]
  if (length(x) < 30L) return(list(beta = NA_real_, se = NA_real_, n = length(x)))
  mod <- try(stats::lm(y ~ 0 + x), silent = TRUE)  # no intercept
  if (inherits(mod, "try-error")) return(list(beta = NA_real_, se = NA_real_, n = length(x)))
  co <- stats::coef(summary(mod))
  beta <- unname(co[1, "Estimate"])
  se   <- unname(co[1, "Std. Error"])
  if (!is.finite(beta)) beta <- NA_real_
  if (!is.finite(se))   se   <- NA_real_
  list(beta = max(beta, 0), se = se, n = length(x))
}

turn_cost_list <- turn_events |>
  dplyr::group_by(nfl_id) |>
  dplyr::group_map(~{
    fit <- fit_turn_cost(.x)
    tibble::tibble(
      nfl_id            = .y$nfl_id,
      turn_cost_per_rad = fit$beta,
      turn_cost_se      = fit$se,
      n_turn_fit        = fit$n
    )
  }) |>
  dplyr::bind_rows()

# -------------------- 6) Assemble defender_profiles_v3 --------------------
def_profiles <- cap |>
  dplyr::select(nfl_id, v_max, a_max, turn_rate_p95) |>
  dplyr::rename(yaw_rate_max_cap = turn_rate_p95) |>
  dplyr::left_join(yaw_by_def, by = "nfl_id") |>
  dplyr::mutate(
    yaw_rate_max = dplyr::coalesce(yaw_rate_max_emp, yaw_rate_max_cap)
  ) |>
  dplyr::select(nfl_id, v_max, a_max, yaw_rate_max) |>
  dplyr::distinct() |>
  dplyr::left_join(turn_cost_list, by = "nfl_id") |>
  dplyr::left_join(lat_by_def, by = "nfl_id")

readr::write_csv(def_profiles, OUT_DEF)

# -------------------- 7) WR burst profiles (v3) --------------------
# Use both Targeted Receiver and Other Route Runner for burst
wr_dat <- dat |>
  dplyr::filter(
    player_side == "Offense",
    player_role %in% c("Targeted Receiver", "Other Route Runner")
  ) |>
  dplyr::inner_join(
    plays |> dplyr::select(game_id, play_id, throw_frame),
    by = c("game_id", "play_id")
  ) |>
  dplyr::mutate(
    frame_rel = frame_id - throw_frame,
    t_rel     = frame_rel * DT
  )

wr_burst <- wr_dat |>
  dplyr::filter(t_rel >= 0, t_rel <= 0.5) |>
  dplyr::group_by(nfl_id, game_id, play_id) |>
  dplyr::summarise(
    burst_0_0p5 = max(s, na.rm = TRUE),
    .groups = "drop"
  )

wr_burst_profiles <- wr_burst |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    n_plays        = dplyr::n(),
    burst_0_0p5_mu = mean(burst_0_0p5, na.rm = TRUE),
    burst_0_0p5_sd = ifelse(n_plays > 1, stats::sd(burst_0_0p5, na.rm = TRUE), NA_real_),
    burst_0_0p5_se = ifelse(n_plays > 1, burst_0_0p5_sd / sqrt(pmax(n_plays, 1)), NA_real_),
    .groups = "drop"
  )

# -------------------- 8) WR lane priors from supplementary_data --------------------
lane_from_passloc <- function(x) {
  dplyr::case_when(
    is.na(x) ~ NA_character_,
    x == "OUTSIDE_LEFT"  ~ "L",
    x == "OUTSIDE_RIGHT" ~ "R",
    x == "INSIDE_BOX"    ~ "M",
    TRUE                 ~ NA_character_
  )
}

# Targeted receivers only for lane priors
wr_targets <- dat |>
  dplyr::filter(
    player_side == "Offense",
    player_role == "Targeted Receiver"
  ) |>
  dplyr::distinct(game_id, play_id, nfl_id)

wr_lane <- wr_targets |>
  dplyr::left_join(
    supp,
    by = c("game_id", "play_id")
  ) |>
  dplyr::mutate(
    lane = lane_from_passloc(pass_location_type)
  ) |>
  dplyr::group_by(nfl_id) |>
  dplyr::summarise(
    n_targets      = dplyr::n(),
    n_targets_lane = sum(!is.na(lane)),
    lane_L_prior   = ifelse(n_targets_lane > 0, mean(lane == "L", na.rm = TRUE), NA_real_),
    lane_M_prior   = ifelse(n_targets_lane > 0, mean(lane == "M", na.rm = TRUE), NA_real_),
    lane_R_prior   = ifelse(n_targets_lane > 0, mean(lane == "R", na.rm = TRUE), NA_real_),
    .groups = "drop"
  )

wr_profiles <- wr_burst_profiles |>
  dplyr::full_join(wr_lane, by = "nfl_id")

readr::write_csv(wr_profiles, OUT_WR)

# -------------------- 9) Turn-cost curves plot --------------------
curve_tbl <- turn_events |>
  dplyr::mutate(
    yaw_bin = pmin(floor(yaw_rate_deg / 10) * 10, 300)
  ) |>
  dplyr::group_by(yaw_bin) |>
  dplyr::summarise(
    n         = dplyr::n(),
    mean_loss = mean(speed_loss, na.rm = TRUE),
    .groups = "drop"
  ) |>
  dplyr::arrange(yaw_bin)

tol <- 0.01
monotone_ok <- if (nrow(curve_tbl) > 1) {
  all(diff(curve_tbl$mean_loss) >= -tol, na.rm = TRUE)
} else {
  NA
}

p_tc <- ggplot2::ggplot(curve_tbl, ggplot2::aes(x = yaw_bin, y = mean_loss)) +
  ggplot2::geom_line() +
  ggplot2::geom_point() +
  ggplot2::labs(
    title = "Turn cost curve (global)",
    x = "|yaw rate| (deg/s, binned by 10)",
    y = "Mean speed loss per frame (yd/s)"
  ) +
  ggplot2::theme_minimal()

ggplot2::ggsave(OUT_TC_PLOT, p_tc, width = 6, height = 4, dpi = 120)

# -------------------- 10) Latency histogram by position --------------------
lat_hist <- lat_tbl |>
  dplyr::left_join(
    dat_def |>
      dplyr::select(game_id, play_id, nfl_id, player_position) |>
      dplyr::distinct(),
    by = c("game_id", "play_id", "nfl_id")
  )

p_lat <- ggplot2::ggplot(
  lat_hist |> dplyr::filter(!is.na(latency_s)),
  ggplot2::aes(x = latency_s)
) +
  ggplot2::geom_histogram(binwidth = 0.05, boundary = 0) +
  ggplot2::facet_wrap(~ player_position, scales = "free_y") +
  ggplot2::labs(
    title = "Defender latency at throw (by position)",
    x = "Latency (s)",
    y = "Count"
  ) +
  ggplot2::theme_minimal()

ggplot2::ggsave(OUT_LAT_PLOT, p_lat, width = 8, height = 5, dpi = 120)

# -------------------- 11) Status + report --------------------
checks <- tibble::tibble(
  check  = c("capability_profiles_exists",
             "ball_timing_exists",
             "supplementary_exists",
             "latency_fp<=0.02",
             "turncost_curve_monotone"),
  status = c(
    file.exists(PATH_CAP),
    file.exists(PATH_TIMING),
    file.exists(PATH_SUPP),
    is.finite(fp_rate) && fp_rate <= 0.02 + 1e-8,
    isTRUE(monotone_ok)
  )
) |>
  dplyr::mutate(
    status_flag = ifelse(status, "PASS", "FAIL")
  )

readr::write_csv(checks |> dplyr::select(check, status_flag), OUT_STATUS_C)

writeLines(
  c(
    "# Latency/turn-cost status",
    "",
    md_table(checks |> dplyr::select(check, status_flag))
  ),
  OUT_STATUS_M,
  useBytes = TRUE
)

report <- c(
  "# Latency and turn-cost profiles (v3)",
  "",
  sprintf("- Training files used: %d", length(files)),
  sprintf("- Unique defenders (rows in defender_profiles_v3): %d", nrow(def_profiles)),
  sprintf("- Unique WRs in wr_profiles_v3: %d", nrow(wr_profiles)),
  "",
  "## Latency FP check",
  "",
  sprintf("- Pre-throw |Δspeed| 98th percentile threshold: %.4f", ifelse(is.finite(thr), thr, NA_real_)),
  sprintf("- Empirical FP rate pre-throw (> threshold): %.4f", ifelse(is.finite(fp_rate), fp_rate, NA_real_)),
  "",
  "## Turn-cost curve summary (first 20 bins)",
  "",
  md_table(curve_tbl |> head(20)),
  "",
  "## Checks",
  "",
  md_table(checks |> dplyr::select(check, status_flag))
)

writeLines(report, OUT_REPORT_M, useBytes = TRUE)

# Only hard-fail on the *critical* checks (data presence + FP control).
required_checks <- c("capability_profiles_exists",
                     "ball_timing_exists",
                     "supplementary_exists",
                     "latency_fp<=0.02")

if (any(!checks$status[checks$check %in% required_checks])) {
  stop("Latency/turn-cost acceptance criteria not met (critical checks). See status/report artifacts for details.", call. = FALSE)
}

cat("\n[Done] Script 29_latency_turncost_profiles.R completed successfully.\n")










# 29a_verify_latency_turncost.R  (warning-free, prints PASS/FAIL)
# Verifies outputs of 29_latency_turncost_profiles.R against Phase-3 acceptance.
# Outputs: artifacts/{latency_turncost_verify_status.csv, latency_turncost_verify_status.md}

suppressPackageStartupMessages({
  library(tidyverse); library(readr); library(janitor)
})

B <- function(...) file.path(normalizePath(getwd(), winslash = "/", mustWork = TRUE), ...)
ART <- B("artifacts")

PATH_DEF   <- file.path(ART, "defender_profiles_v3.csv")
PATH_STAT  <- file.path(ART, "latency_turncost_status.csv")
PATH_PNG1  <- file.path(ART, "turncost_curves.png")
PATH_PNG2  <- file.path(ART, "latency_hist_by_pos.png")

if (!file.exists(PATH_DEF)) stop("Missing: ", PATH_DEF)

def <- suppressMessages(readr::read_csv(PATH_DEF, show_col_types = FALSE)) |> janitor::clean_names()

req <- c("nfl_id","v_max","a_max","yaw_rate_max",
         "turn_cost_per_rad","n_latency","latency_mu","latency_sd","latency_se")
missing <- setdiff(req, names(def))
schema_ok <- length(missing) == 0

n <- nrow(def)

checks <- tibble(
  check = c(
    "defender_profiles_v3_exists",
    "schema_ok",
    "n_rows>0",
    "latency_fields_present",
    "turn_cost_field_present",
    "turncost_curves_png_exists",
    "latency_hist_png_exists"
  ),
  status = c(
    file.exists(PATH_DEF),
    schema_ok,
    n > 0,
    all(c("latency_mu","latency_sd","latency_se") %in% names(def)),
    "turn_cost_per_rad" %in% names(def),
    file.exists(PATH_PNG1),
    file.exists(PATH_PNG2)
  )
)

# Mirror acceptance from status file (handle either status/status_flag)
if (file.exists(PATH_STAT)) {
  st <- suppressMessages(readr::read_csv(PATH_STAT, show_col_types = FALSE))
  pass_col <- intersect(c("status_flag","status"), names(st))
  if (length(pass_col)) {
    pass_col <- pass_col[[1]]
    want <- c("latency_fp<=0.02","turncost_curve_monotone")
    for (nm in want) {
      if (nm %in% st$check) {
        passed <- any(st$check == nm & toupper(as.character(st[[pass_col]])) == "PASS", na.rm = TRUE)
        checks <- bind_rows(checks, tibble(check = paste0("status:", nm), status = passed))
      }
    }
  }
}

checks <- checks |> mutate(status_flag = ifelse(status, "PASS", "FAIL"))
readr::write_csv(checks, file.path(ART, "latency_turncost_verify_status.csv"))

md <- c(
  "# 29a Verify – Latency & Turn-cost profiles",
  "",
  sprintf("- Defenders profiled: %d", n),
  "",
  "## Checks",
  paste0("| check | status |", "\n|---|---|\n",
         paste0("| ", checks$check, " | ", checks$status_flag, " |", collapse = "\n"))
)
writeLines(md, file.path(ART, "latency_turncost_verify_status.md"))

# Console summary (PASS/FAIL)
final_pass <- all(checks$status, na.rm = TRUE)
if (isTRUE(final_pass)) {
  cat(sprintf("[29a PASS] Latency & Turn-cost verification passed all %d checks.\n", nrow(checks)))
} else {
  failed <- checks$check[!checks$status]
  cat(sprintf("[29a FAIL] Failed checks: %s\n", paste(failed, collapse = ", ")))
}










# ------------------------------------------------------------------
# 30_eligibility_envelopes.R
#
# Purpose (Phase 3 literal spec):
#   Tag each defender at throw as contest / leverage / backup / hold
#   using v3 kinematics and T_ball, then check label stability
#   under ±1 frame jitter.
#
# Inputs (as per plan):
#   - artifacts/ball_timing.csv
#       (game_id, play_id, T_ball, method, err_s)
#   - artifacts/defender_profiles_v3.csv
#       (nfl_id, v_max, a_max, yaw_rate_max, turn_cost_per_rad,
#        latency_mu, latency_sd, ...)
#   - artifacts/wr_profiles_v3.csv
#       (WR burst / lane priors; loaded but not needed for labels)
#   - artifacts/v2_model04_leverage_dataset.csv
#       (game_id, play_id, nfl_id, split, d_start, ...)
#   - artifacts/sweep_inputs_choice.csv
#       (LAMBDA_REACH, ELIG_THRESHOLD)
#
# Outputs (as per plan):
#   - artifacts/eligibility_v3.csv
#       game_id, play_id, nfl_id, split,
#       d_start, T_ball, t_reach, p_reach,
#       contest_eligible, leverage_eligible, backup_eligible, hold
#   - artifacts/eligibility_map_sample.png
#   - artifacts/eligibility_stability.csv
#       label, stability
#   - artifacts/eligibility_status.csv
#       small QA summary (n rows, stability, monotonicity, knob values)
#
# CLI:
#   Rscript Code/30_eligibility_envelopes.R
# ------------------------------------------------------------------

suppressPackageStartupMessages({
  library(tidyverse)
  library(janitor)
})

DT <- 0.1  # one frame = 0.1 seconds

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  ball_timing   = file.path(DIR$artifacts, "ball_timing.csv"),
  def_prof_v3   = file.path(DIR$artifacts, "defender_profiles_v3.csv"),
  wr_prof_v3    = file.path(DIR$artifacts, "wr_profiles_v3.csv"),
  lev2          = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  sweep_choice  = file.path(DIR$artifacts, "sweep_inputs_choice.csv"),
  # outputs
  out_elig      = file.path(DIR$artifacts, "eligibility_v3.csv"),
  out_map       = file.path(DIR$artifacts, "eligibility_map_sample.png"),
  out_stability = file.path(DIR$artifacts, "eligibility_stability.csv"),
  out_status    = file.path(DIR$artifacts, "eligibility_status.csv")
)

read_csv_clean <- function(path, ...) {
  readr::read_csv(path, show_col_types = FALSE, ...) %>%
    janitor::clean_names()
}

# ---------------- 1. Load knobs (LAMBDA_REACH, ELIG_THRESHOLD) ---------

if (!file.exists(PATH$sweep_choice)) {
  stop("Missing artifacts/sweep_inputs_choice.csv")
}

sweep_choice <- read_csv_clean(PATH$sweep_choice)
nm_sc <- names(sweep_choice)

lambda_col <- nm_sc[tolower(nm_sc) == "lambda_reach"][1]
elig_col   <- nm_sc[tolower(nm_sc) == "elig_threshold"][1]

if (is.na(lambda_col) || !nzchar(lambda_col)) {
  stop("sweep_inputs_choice.csv must contain lambda_reach column (any case).")
}
if (is.na(elig_col) || !nzchar(elig_col)) {
  stop("sweep_inputs_choice.csv must contain ELIG_THRESHOLD / elig_threshold column.")
}

LAMBDA_REACH   <- as.numeric(sweep_choice[[lambda_col]][1])
ELIG_THRESHOLD <- as.numeric(sweep_choice[[elig_col]][1])

LATENCY_K <- 1.0          # latency draw: mu - k*sd (best-case)
BACKUP_TIME_FACTOR <- 1.2 # backup horizon = 1.2 * T_ball

message(sprintf("Using LAMBDA_REACH = %.4f, ELIG_THRESHOLD = %.5f", LAMBDA_REACH, ELIG_THRESHOLD))

# ---------------- 2. Load core inputs ---------------------------------

if (!file.exists(PATH$ball_timing))  stop("Missing ", PATH$ball_timing)
if (!file.exists(PATH$def_prof_v3))  stop("Missing ", PATH$def_prof_v3)
if (!file.exists(PATH$lev2))         stop("Missing ", PATH$lev2)

ball     <- read_csv_clean(PATH$ball_timing)
def_prof <- read_csv_clean(PATH$def_prof_v3)
lev2     <- read_csv_clean(PATH$lev2)
wr_prof  <- if (file.exists(PATH$wr_prof_v3)) read_csv_clean(PATH$wr_prof_v3) else tibble::tibble()

# 2.1 ball timing
ball_use <- ball %>%
  transmute(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    T_ball  = as.numeric(t_ball)  # T_ball column -> t_ball after clean_names()
  )

# 2.2 defender profiles (v3)
def_prof_use <- def_prof %>%
  transmute(
    nfl_id            = as.integer(nfl_id),
    v_max_v3          = as.numeric(v_max),
    a_max_v3          = as.numeric(a_max),
    yaw_rate_max      = suppressWarnings(as.numeric(yaw_rate_max)),
    turn_cost_per_rad = suppressWarnings(as.numeric(turn_cost_per_rad)),
    latency_mu        = suppressWarnings(as.numeric(latency_mu)),
    latency_sd        = suppressWarnings(as.numeric(latency_sd))
  )

# 2.3 v2 leverage dataset (geometry base)
lev2_use <- lev2 %>%
  transmute(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split)),
    d_start = as.numeric(d_start),
    v_max_v2 = suppressWarnings(as.numeric(v_max)),
    a_max_v2 = suppressWarnings(as.numeric(a_max))
  )

# 2.4 join everything (geometry + timing + v3 profiles)

DEFAULT_LATENCY <- 0.20  # seconds if latency_mu is NA
DEFAULT_VMAX    <- 6.0   # yards/s
DEFAULT_AMAX    <- 4.0   # yards/s^2

base_df <- lev2_use %>%
  left_join(ball_use,     by = c("game_id","play_id")) %>%
  left_join(def_prof_use, by = "nfl_id") %>%
  mutate(
    v_max = dplyr::coalesce(v_max_v3, v_max_v2, DEFAULT_VMAX),
    a_max = dplyr::coalesce(a_max_v3, a_max_v2, DEFAULT_AMAX),
    latency_mu = dplyr::coalesce(latency_mu, DEFAULT_LATENCY),
    latency_sd = dplyr::coalesce(latency_sd, 0),
    turn_cost_per_rad = dplyr::coalesce(turn_cost_per_rad, 0),
    T_ball = as.numeric(T_ball)
  )

# ---------------- 3. Kinematics helpers -------------------------------

# distance covered under accelerate-then-cruise
distance_covered <- function(t, v_max, a_max) {
  # t, v_max, a_max are vectors
  t <- pmax(t, 0)
  a_max_safe <- ifelse(is.na(a_max) | a_max <= 0, NA, a_max)
  v_max_safe <- ifelse(is.na(v_max) | v_max <= 0, NA, v_max)
  
  t_acc <- ifelse(is.na(a_max_safe), NA, v_max_safe / a_max_safe)
  dist_acc <- 0.5 * a_max_safe * pmin(t, t_acc)^2
  
  # extra cruise distance if t > t_acc
  extra_t <- pmax(t - t_acc, 0)
  dist_cruise <- v_max_safe * pmax(extra_t, 0)
  
  d <- dist_acc + dist_cruise
  
  # Fallback when a_max or v_max missing: constant speed v_max * t
  d_fallback <- ifelse(is.na(a_max_safe) | is.na(v_max_safe),
                       pmax(v_max, 0) * t,
                       d)
  d_fallback
}

# minimal time to cover distance d using same accelerate-then-cruise
time_to_cover_distance <- function(d, v_max, a_max) {
  d <- pmax(d, 0)
  a_max_safe <- ifelse(is.na(a_max) | a_max <= 0, NA, a_max)
  v_max_safe <- ifelse(is.na(v_max) | v_max <= 0, NA, v_max)
  
  # fallback: constant speed
  t_fallback <- d / pmax(v_max, 1e-6)
  
  t_acc <- ifelse(is.na(a_max_safe), NA, v_max_safe / a_max_safe)
  dist_acc <- ifelse(is.na(a_max_safe),
                     NA,
                     0.5 * a_max_safe * t_acc^2)
  
  # case 1: can be reached entirely in acceleration phase:
  t1 <- ifelse(
    !is.na(a_max_safe) & d <= dist_acc,
    sqrt(2 * d / pmax(a_max_safe, 1e-6)),
    NA
  )
  
  # case 2: need accel + cruise
  t2 <- ifelse(
    !is.na(a_max_safe) & d > dist_acc,
    t_acc + (d - dist_acc) / pmax(v_max_safe, 1e-6),
    NA
  )
  
  t <- ifelse(!is.na(t1), t1,
              ifelse(!is.na(t2), t2, t_fallback))
  t
}

# Precompute geometry-only pieces that do NOT depend on T_ball:
#   - d_eff_base, d_eff_lev
#   - latency_lb
#   - t_reach_base, t_reach_lev

geom_df <- base_df %>%
  mutate(
    # apply yaw/turn cost as a stretch on path length
    d_eff_base = d_start * (1 + pmax(turn_cost_per_rad, 0)),
    d_eff_lev  = pmax(d_start - 1.5, 0) * (1 + pmax(turn_cost_per_rad, 0)),
    latency_lb = pmax(latency_mu - LATENCY_K * latency_sd, 0),
    t_move_base = time_to_cover_distance(d_eff_base, v_max, a_max),
    t_move_lev  = time_to_cover_distance(d_eff_lev,  v_max, a_max),
    t_reach_base = latency_lb + t_move_base,
    t_reach_lev  = latency_lb + t_move_lev
  )

# ---------------- 4. Label computation for a given T_ball --------------

label_with_T <- function(df_geom, T_vec) {
  # df_geom: must contain d_eff_base, latency_lb, t_reach_base, t_reach_lev, v_max, a_max
  # T_vec: numeric vector same length as nrow(df_geom)
  T_vec <- as.numeric(T_vec)
  
  df <- df_geom %>%
    mutate(
      T_ball_cur = T_vec,
      # window for movement at contest time
      t_move_window = pmax(T_ball_cur - latency_lb, 0),
      r_base = distance_covered(t_move_window, v_max, a_max),
      p_reach = ifelse(
        is.na(T_ball_cur) | is.na(d_eff_base) | is.na(r_base),
        NA_real_,
        exp(-LAMBDA_REACH * pmax(d_eff_base - r_base, 0))
      ),
      # backup horizon
      T_backup = BACKUP_TIME_FACTOR * T_ball_cur,
      t_move_backup = pmax(T_backup - latency_lb, 0),
      r_backup = distance_covered(t_move_backup, v_max, a_max),
      p_reach_backup = ifelse(
        is.na(T_backup) | is.na(d_eff_base) | is.na(r_backup),
        NA_real_,
        exp(-LAMBDA_REACH * pmax(d_eff_base - r_backup, 0))
      ),
      
      # contest eligibility: t_reach_base <= T_ball_cur and p_reach >= ELIG_THRESHOLD
      contest_eligible = !is.na(t_reach_base) & !is.na(T_ball_cur) &
        t_reach_base <= T_ball_cur &
        !is.na(p_reach) & p_reach >= ELIG_THRESHOLD,
      
      # leverage eligibility: contest_eligible and t_reach_lev <= T_ball_cur
      leverage_eligible = contest_eligible &
        !is.na(t_reach_lev) & t_reach_lev <= T_ball_cur,
      
      # backup eligibility: not leverage, but t_reach_base <= T_backup and p_reach_backup >= ELIG_THRESHOLD
      backup_eligible = !leverage_eligible &
        !is.na(t_reach_base) & !is.na(T_backup) &
        t_reach_base <= T_backup &
        !is.na(p_reach_backup) & p_reach_backup >= ELIG_THRESHOLD
    ) %>%
    mutate(
      # hold: not contest_eligible
      hold = !contest_eligible
    )
  
  df
}

# ---------------- 5. Base labels (no jitter) ---------------------------

labels_base <- label_with_T(geom_df, geom_df$T_ball)

# ---------------- 6. ±1 frame jitter and stability ---------------------

# jittered ball times
T_minus <- pmax(geom_df$T_ball - DT, DT)
T_plus  <- geom_df$T_ball + DT

labels_minus <- label_with_T(geom_df, T_minus)
labels_plus  <- label_with_T(geom_df, T_plus)

# assemble stability dataframe
stab_df <- labels_base %>%
  transmute(
    game_id, play_id, nfl_id,
    contest_base  = contest_eligible,
    leverage_base = leverage_eligible,
    backup_base   = backup_eligible,
    hold_base     = hold
  ) %>%
  left_join(
    labels_minus %>%
      transmute(
        game_id, play_id, nfl_id,
        contest_minus  = contest_eligible,
        leverage_minus = leverage_eligible,
        backup_minus   = backup_eligible,
        hold_minus     = hold
      ),
    by = c("game_id","play_id","nfl_id")
  ) %>%
  left_join(
    labels_plus %>%
      transmute(
        game_id, play_id, nfl_id,
        contest_plus  = contest_eligible,
        leverage_plus = leverage_eligible,
        backup_plus   = backup_eligible,
        hold_plus     = hold
      ),
    by = c("game_id","play_id","nfl_id")
  ) %>%
  mutate(
    contest_stable = !is.na(contest_base) &
      contest_base == contest_minus & contest_base == contest_plus,
    leverage_stable = !is.na(leverage_base) &
      leverage_base == leverage_minus & leverage_base == leverage_plus,
    backup_stable = !is.na(backup_base) &
      backup_base == backup_minus & backup_base == backup_plus,
    hold_stable = !is.na(hold_base) &
      hold_base == hold_minus & hold_base == hold_plus
  )

stab_summary <- tibble::tibble(
  label = c("contest","leverage","backup","hold"),
  stability = c(
    mean(stab_df$contest_stable,  na.rm = TRUE),
    mean(stab_df$leverage_stable, na.rm = TRUE),
    mean(stab_df$backup_stable,   na.rm = TRUE),
    mean(stab_df$hold_stable,     na.rm = TRUE)
  )
)

readr::write_csv(stab_summary, PATH$out_stability)

# ---------------- 7. Build eligibility_v3.csv --------------------------

elig_out <- labels_base %>%
  transmute(
    game_id,
    play_id,
    nfl_id,
    split,
    d_start,
    T_ball = T_ball_cur,
    t_reach = t_reach_base,
    p_reach,
    contest_eligible,
    leverage_eligible,
    backup_eligible,
    hold
  )

readr::write_csv(elig_out, PATH$out_elig)

# ---------------- 8. Map sample (diagnostic plot) ----------------------

set.seed(123)

sample_base <- elig_out %>%
  filter(!is.na(p_reach), !is.na(d_start))

n_sample <- min(5000L, nrow(sample_base))

if (n_sample > 0) {
  sample_elig <- sample_base %>%
    slice_sample(n = n_sample)
  
  p <- ggplot(sample_elig, aes(x = d_start, y = p_reach, colour = contest_eligible)) +
    geom_point(alpha = 0.3) +
    geom_smooth(se = FALSE, method = "loess", formula = y ~ x, na.rm = TRUE) +
    labs(
      x = "Distance at throw (d_start, yards)",
      y = "p_reach (v3, T_ball horizon)",
      colour = "Contest eligible",
      title = "Eligibility envelopes: p_reach vs distance at throw"
    ) +
    theme_minimal()
  ggplot2::ggsave(PATH$out_map, p, width = 7, height = 5, dpi = 150)
} else {
  message("No data to plot eligibility_map_sample.png")
}

# ---------------- 9. Status summary ------------------------------------

monotone_df <- elig_out %>%
  filter(!is.na(d_start), !is.na(p_reach))

corr_ds_pr <- if (nrow(monotone_df) > 10) {
  suppressWarnings(cor(monotone_df$d_start, monotone_df$p_reach, method = "spearman"))
} else {
  NA_real_
}

status <- tibble::tibble(
  metric = c(
    "n_rows_eligibility_v3",
    "stability_contest",
    "stability_leverage",
    "stability_backup",
    "stability_hold",
    "spearman_corr_d_start_p_reach",
    "lambda_reach",
    "elig_threshold",
    "backup_time_factor"
  ),
  value = c(
    nrow(elig_out),
    stab_summary$stability[stab_summary$label == "contest"],
    stab_summary$stability[stab_summary$label == "leverage"],
    stab_summary$stability[stab_summary$label == "backup"],
    stab_summary$stability[stab_summary$label == "hold"],
    corr_ds_pr,
    LAMBDA_REACH,
    ELIG_THRESHOLD,
    BACKUP_TIME_FACTOR
  )
)

readr::write_csv(status, PATH$out_status)

message("30_eligibility_envelopes.R completed.")
message("  - ", PATH$out_elig)
message("  - ", PATH$out_stability)
message("  - ", PATH$out_map)
message("  - ", PATH$out_status)










# ------------------------------------------------------------------
# 30a_eligibility_verification.R
#
# Purpose:
#   Verification harness for 30_eligibility_envelopes.R.
#   - Recompute t_reach / p_reach / labels from inputs
#   - Check they match eligibility_v3.csv
#   - Check basic sanity (monotonicity, stability, ranges)
#   - Emit an overall PASS / FAIL status
#
# Inputs:
#   - artifacts/eligibility_v3.csv
#   - artifacts/eligibility_stability.csv
#   - artifacts/eligibility_status.csv
#   - artifacts/ball_timing.csv
#   - artifacts/defender_profiles_v3.csv
#   - artifacts/v2_model04_leverage_dataset.csv
#   - artifacts/sweep_inputs_choice.csv
#
# Outputs:
#   - artifacts/eligibility_verification_status.csv
#
# CLI:
#   Rscript Code/30a_eligibility_verification.R
# ------------------------------------------------------------------

suppressPackageStartupMessages({
  library(tidyverse)
  library(janitor)
})

DT <- 0.1  # frame length

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  elig          = file.path(DIR$artifacts, "eligibility_v3.csv"),
  stab          = file.path(DIR$artifacts, "eligibility_stability.csv"),
  status        = file.path(DIR$artifacts, "eligibility_status.csv"),
  ball_timing   = file.path(DIR$artifacts, "ball_timing.csv"),
  def_prof_v3   = file.path(DIR$artifacts, "defender_profiles_v3.csv"),
  lev2          = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  sweep_choice  = file.path(DIR$artifacts, "sweep_inputs_choice.csv"),
  out_verify    = file.path(DIR$artifacts, "eligibility_verification_status.csv")
)

read_csv_clean <- function(path, ...) {
  readr::read_csv(path, show_col_types = FALSE, ...) %>%
    janitor::clean_names()
}

# ---------------- 1. Load core artifacts -------------------------------

req_files <- c(PATH$elig, PATH$stab, PATH$status,
               PATH$ball_timing, PATH$def_prof_v3,
               PATH$lev2, PATH$sweep_choice)

missing <- req_files[!file.exists(req_files)]
if (length(missing) > 0) {
  stop("Missing required files for 30a verification: ", paste(missing, collapse = ", "))
}

elig   <- read_csv_clean(PATH$elig)
stab   <- read_csv_clean(PATH$stab)
status <- read_csv_clean(PATH$status)

ball     <- read_csv_clean(PATH$ball_timing)
def_prof <- read_csv_clean(PATH$def_prof_v3)
lev2     <- read_csv_clean(PATH$lev2)
sweep    <- read_csv_clean(PATH$sweep_choice)

# Coerce keys in elig to match Script 30 types
elig <- elig %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

# ---------------- 2. Reload knobs (must match Script 30) ---------------

nm_sc <- names(sweep)
lambda_col <- nm_sc[tolower(nm_sc) == "lambda_reach"][1]
elig_col   <- nm_sc[tolower(nm_sc) == "elig_threshold"][1]

if (is.na(lambda_col) || !nzchar(lambda_col)) {
  stop("sweep_inputs_choice.csv must contain lambda_reach column (any case).")
}
if (is.na(elig_col) || !nzchar(elig_col)) {
  stop("sweep_inputs_choice.csv must contain ELIG_THRESHOLD / elig_threshold column.")
}

LAMBDA_REACH   <- as.numeric(sweep[[lambda_col]][1])
ELIG_THRESHOLD <- as.numeric(sweep[[elig_col]][1])

LATENCY_K <- 1.0
BACKUP_TIME_FACTOR <- 1.2

# ---------------- 3. Rebuild base_df as in Script 30 -------------------

ball_use <- ball %>%
  transmute(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    T_ball  = as.numeric(t_ball)
  )

def_prof_use <- def_prof %>%
  transmute(
    nfl_id            = as.integer(nfl_id),
    v_max_v3          = as.numeric(v_max),
    a_max_v3          = as.numeric(a_max),
    yaw_rate_max      = suppressWarnings(as.numeric(yaw_rate_max)),
    turn_cost_per_rad = suppressWarnings(as.numeric(turn_cost_per_rad)),
    latency_mu        = suppressWarnings(as.numeric(latency_mu)),
    latency_sd        = suppressWarnings(as.numeric(latency_sd))
  )

lev2_use <- lev2 %>%
  transmute(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split)),
    d_start = as.numeric(d_start),
    v_max_v2 = suppressWarnings(as.numeric(v_max)),
    a_max_v2 = suppressWarnings(as.numeric(a_max))
  )

DEFAULT_LATENCY <- 0.20
DEFAULT_VMAX    <- 6.0
DEFAULT_AMAX    <- 4.0

base_df <- lev2_use %>%
  left_join(ball_use,     by = c("game_id","play_id")) %>%
  left_join(def_prof_use, by = "nfl_id") %>%
  mutate(
    v_max = dplyr::coalesce(v_max_v3, v_max_v2, DEFAULT_VMAX),
    a_max = dplyr::coalesce(a_max_v3, a_max_v2, DEFAULT_AMAX),
    latency_mu = dplyr::coalesce(latency_mu, DEFAULT_LATENCY),
    latency_sd = dplyr::coalesce(latency_sd, 0),
    turn_cost_per_rad = dplyr::coalesce(turn_cost_per_rad, 0),
    T_ball = as.numeric(T_ball)
  )

# ---------------- 4. Kinematics helpers (copied from Script 30) --------

distance_covered <- function(t, v_max, a_max) {
  t <- pmax(t, 0)
  a_max_safe <- ifelse(is.na(a_max) | a_max <= 0, NA, a_max)
  v_max_safe <- ifelse(is.na(v_max) | v_max <= 0, NA, v_max)
  
  t_acc <- ifelse(is.na(a_max_safe), NA, v_max_safe / a_max_safe)
  dist_acc <- 0.5 * a_max_safe * pmin(t, t_acc)^2
  
  extra_t <- pmax(t - t_acc, 0)
  dist_cruise <- v_max_safe * pmax(extra_t, 0)
  
  d <- dist_acc + dist_cruise
  
  d_fallback <- ifelse(is.na(a_max_safe) | is.na(v_max_safe),
                       pmax(v_max, 0) * t,
                       d)
  d_fallback
}

time_to_cover_distance <- function(d, v_max, a_max) {
  d <- pmax(d, 0)
  a_max_safe <- ifelse(is.na(a_max) | a_max <= 0, NA, a_max)
  v_max_safe <- ifelse(is.na(v_max) | v_max <= 0, NA, v_max)
  
  t_fallback <- d / pmax(v_max, 1e-6)
  
  t_acc <- ifelse(is.na(a_max_safe), NA, v_max_safe / a_max_safe)
  dist_acc <- ifelse(is.na(a_max_safe),
                     NA,
                     0.5 * a_max_safe * t_acc^2)
  
  t1 <- ifelse(
    !is.na(a_max_safe) & d <= dist_acc,
    sqrt(2 * d / pmax(a_max_safe, 1e-6)),
    NA
  )
  
  t2 <- ifelse(
    !is.na(a_max_safe) & d > dist_acc,
    t_acc + (d - dist_acc) / pmax(v_max_safe, 1e-6),
    NA
  )
  
  t <- ifelse(!is.na(t1), t1,
              ifelse(!is.na(t2), t2, t_fallback))
  t
}

geom_df <- base_df %>%
  mutate(
    d_eff_base = d_start * (1 + pmax(turn_cost_per_rad, 0)),
    d_eff_lev  = pmax(d_start - 1.5, 0) * (1 + pmax(turn_cost_per_rad, 0)),
    latency_lb = pmax(latency_mu - LATENCY_K * latency_sd, 0),
    t_move_base = time_to_cover_distance(d_eff_base, v_max, a_max),
    t_move_lev  = time_to_cover_distance(d_eff_lev,  v_max, a_max),
    t_reach_base = latency_lb + t_move_base,
    t_reach_lev  = latency_lb + t_move_lev
  )

label_with_T <- function(df_geom, T_vec) {
  T_vec <- as.numeric(T_vec)
  
  df <- df_geom %>%
    mutate(
      T_ball_cur = T_vec,
      t_move_window = pmax(T_ball_cur - latency_lb, 0),
      r_base = distance_covered(t_move_window, v_max, a_max),
      p_reach = ifelse(
        is.na(T_ball_cur) | is.na(d_eff_base) | is.na(r_base),
        NA_real_,
        exp(-LAMBDA_REACH * pmax(d_eff_base - r_base, 0))
      ),
      T_backup = BACKUP_TIME_FACTOR * T_ball_cur,
      t_move_backup = pmax(T_backup - latency_lb, 0),
      r_backup = distance_covered(t_move_backup, v_max, a_max),
      p_reach_backup = ifelse(
        is.na(T_backup) | is.na(d_eff_base) | is.na(r_backup),
        NA_real_,
        exp(-LAMBDA_REACH * pmax(d_eff_base - r_backup, 0))
      ),
      contest_eligible = !is.na(t_reach_base) & !is.na(T_ball_cur) &
        t_reach_base <= T_ball_cur &
        !is.na(p_reach) & p_reach >= ELIG_THRESHOLD,
      leverage_eligible = contest_eligible &
        !is.na(t_reach_lev) & t_reach_lev <= T_ball_cur,
      backup_eligible = !leverage_eligible &
        !is.na(t_reach_base) & !is.na(T_backup) &
        t_reach_base <= T_backup &
        !is.na(p_reach_backup) & p_reach_backup >= ELIG_THRESHOLD
    ) %>%
    mutate(
      hold = !contest_eligible
    )
  
  df
}

labels_recalc <- label_with_T(geom_df, geom_df$T_ball)

# ---------------- 5. Join recalc with eligibility_v3 -------------------

elig_key_cols <- c("game_id","play_id","nfl_id","split")
if (!all(elig_key_cols %in% names(elig))) {
  stop("eligibility_v3.csv is missing one of key columns: ",
       paste(elig_key_cols, collapse = ", "))
}

recalc_small <- labels_recalc %>%
  select(all_of(elig_key_cols),
         t_reach_recalc = t_reach_base,
         p_reach_recalc = p_reach,
         contest_recalc = contest_eligible,
         leverage_recalc = leverage_eligible,
         backup_recalc = backup_eligible,
         hold_recalc = hold)

joined <- elig %>%
  left_join(recalc_small, by = elig_key_cols)

# ---------------- 6. Compute differences / mismatch rates --------------

joined <- joined %>%
  mutate(
    diff_t_reach = abs(t_reach - t_reach_recalc),
    diff_p_reach = abs(p_reach - p_reach_recalc),
    contest_match = (contest_eligible == contest_recalc) |
      (is.na(contest_eligible) & is.na(contest_recalc)),
    leverage_match = (leverage_eligible == leverage_recalc) |
      (is.na(leverage_eligible) & is.na(leverage_recalc)),
    backup_match = (backup_eligible == backup_recalc) |
      (is.na(backup_eligible) & is.na(backup_recalc)),
    hold_match = (hold == hold_recalc) |
      (is.na(hold) & is.na(hold_recalc))
  )

tol_t <- 1e-6
tol_p <- 1e-6

max_diff_t <- max(joined$diff_t_reach, na.rm = TRUE)
max_diff_p <- max(joined$diff_p_reach, na.rm = TRUE)

share_t_within_tol <- mean(joined$diff_t_reach <= tol_t, na.rm = TRUE)
share_p_within_tol <- mean(joined$diff_p_reach <= tol_p, na.rm = TRUE)

contest_match_rate  <- mean(joined$contest_match,  na.rm = TRUE)
leverage_match_rate <- mean(joined$leverage_match, na.rm = TRUE)
backup_match_rate   <- mean(joined$backup_match,   na.rm = TRUE)
hold_match_rate     <- mean(joined$hold_match,     na.rm = TRUE)

# ---------------- 7. Sanity checks on monotonicity & stability ---------

mono_df <- elig %>%
  filter(!is.na(d_start), !is.na(p_reach))

corr_ds_pr <- if (nrow(mono_df) > 10) {
  suppressWarnings(cor(mono_df$d_start, mono_df$p_reach, method = "spearman"))
} else {
  NA_real_
}

stab_contest  <- stab$stability[stab$label == "contest"]
stab_leverage <- stab$stability[stab$label == "leverage"]
stab_backup   <- stab$stability[stab$label == "backup"]
stab_hold     <- stab$stability[stab$label == "hold"]

# ---------------- 8. Assemble verification status + PASS/FAIL ----------

verify <- tibble::tibble(
  check = c(
    "row_count_elig_vs_geom",
    "max_abs_diff_t_reach",
    "max_abs_diff_p_reach",
    "share_t_reach_within_tol",
    "share_p_reach_within_tol",
    "contest_match_rate",
    "leverage_match_rate",
    "backup_match_rate",
    "hold_match_rate",
    "spearman_corr_d_start_p_reach",
    "stability_contest",
    "stability_leverage",
    "stability_backup",
    "stability_hold",
    "lambda_reach_used",
    "elig_threshold_used",
    "backup_time_factor_used"
  ),
  value = c(
    paste(nrow(elig), nrow(geom_df), sep = "/"),
    max_diff_t,
    max_diff_p,
    share_t_within_tol,
    share_p_within_tol,
    contest_match_rate,
    leverage_match_rate,
    backup_match_rate,
    hold_match_rate,
    corr_ds_pr,
    stab_contest,
    stab_leverage,
    stab_backup,
    stab_hold,
    LAMBDA_REACH,
    ELIG_THRESHOLD,
    BACKUP_TIME_FACTOR
  )
)

# thresholds for PASS
pass_checks <- c(
  share_t_within_tol >= 0.999,
  share_p_within_tol >= 0.999,
  contest_match_rate  >= 0.999,
  leverage_match_rate >= 0.999,
  backup_match_rate   >= 0.999,
  hold_match_rate     >= 0.999,
  is.na(corr_ds_pr) || corr_ds_pr <= -0.7,
  is.na(stab_contest)  || stab_contest  >= 0.95,
  is.na(stab_leverage) || stab_leverage >= 0.95,
  is.na(stab_backup)   || stab_backup   >= 0.95,
  is.na(stab_hold)     || stab_hold     >= 0.95
)

overall_status <- if (all(pass_checks, na.rm = TRUE)) "PASS" else "FAIL"

verify <- dplyr::bind_rows(
  verify,
  tibble::tibble(
    check = "overall_status",
    value = overall_status
  )
)

readr::write_csv(verify, PATH$out_verify)

message("30a_eligibility_verification.R completed with overall status: ", overall_status)
message("  - ", PATH$out_verify)










# 31_build_outcomes.R
# CLI: Rscript Code/31_build_outcomes.R
#
# Purpose:
#   Build YAC/EPA outcomes for Phase-3 by joining public nflfastR play-by-play
#   onto v2_model04_leverage_dataset, so that 31.2_affordances_loi_bv.R can
#   train a throw-time YAC/EPA regressor and compute LOI/BV.
#
# Inputs:
#   - artifacts/v2_model04_leverage_dataset.csv
# Outputs:
#   - artifacts/v2_model04_leverage_dataset.csv  (same file, with extra cols)
#       * yac  (yards_after_catch)
#       * epa
#   - artifacts/31_build_outcomes_status.csv
#   - artifacts/31_build_outcomes_status.md

# -------------------------------------------------------------------
# - Package loader: install if missing, otherwise just load
# -------------------------------------------------------------------
quiet_pkgs <- function(pkgs) {
  for (p in pkgs) {
    if (!requireNamespace(p, quietly = TRUE)) {
      install.packages(p)
    }
    suppressPackageStartupMessages(
      library(p, character.only = TRUE)
    )
  }
}

quiet_pkgs(c("tidyverse", "nflfastR"))

cat("[31_build] Starting 31_build_outcomes.R\n")

# -------------------------------------------------------------------
# 0. Directories
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

path_lev2 <- file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv")

if (!file.exists(path_lev2)) {
  stop("[31_build] v2_model04_leverage_dataset.csv not found in artifacts/")
}

lev2 <- readr::read_csv(path_lev2, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id)
  )

cat("[31_build] Loaded leverage dataset with", nrow(lev2), "rows\n")

# -------------------------------------------------------------------
# 1. Determine seasons from game_id
#    (game_id is like '2018090600' → year 2018)
# -------------------------------------------------------------------

years <- lev2 %>%
  mutate(season = suppressWarnings(as.integer(substr(game_id, 1, 4)))) %>%
  filter(!is.na(season)) %>%
  distinct(season) %>%
  arrange(season) %>%
  pull(season)

cat("[31_build] Seasons detected from game_id:", paste(years, collapse = ", "), "\n")

if (length(years) == 0) {
  stop("[31_build] Could not parse any seasons from game_id; check game_id format.")
}

# -------------------------------------------------------------------
# 2. Load nflfastR and fetch play-by-play with YAC/EPA
# -------------------------------------------------------------------

if (!requireNamespace("nflfastR", quietly = TRUE)) {
  stop(
    "[31_build] Package 'nflfastR' is required but not installed.\n",
    "      Please run: install.packages('nflfastR')\n",
    "      Then re-run: Rscript Code/31_build_outcomes.R"
  )
}

suppressWarnings(suppressMessages({
  library(nflfastR)
}))

pbp_list <- list()

for (yr in years) {
  cat("[31_build] Loading nflfastR pbp for season", yr, "...\n")
  # load_pbp() downloads pre-computed pbp with EPA/YAC, cached locally
  pbp <- try(nflfastR::load_pbp(yr), silent = TRUE)
  if (inherits(pbp, "try-error")) {
    warning(sprintf("[31_build] Failed to load pbp for season %d; skipping.", yr))
  } else {
    pbp_list[[as.character(yr)]] <- pbp
  }
}

if (length(pbp_list) == 0) {
  stop("[31_build] No pbp data could be loaded from nflfastR; outcomes cannot be built.")
}

pbp_all <- dplyr::bind_rows(pbp_list)

cat("[31_build] Combined pbp rows:", nrow(pbp_all), "\n")

# -------------------------------------------------------------------
# 3. Prepare pbp subset keyed to BDB game_id/play_id
#    BDB game_id (10-digit numeric string) usually matches nflfastR's old_game_id.
#    So we prefer old_game_id if present; else fall back to game_id.
# -------------------------------------------------------------------

pbp_has_old <- "old_game_id" %in% names(pbp_all)

if (pbp_has_old) {
  cat("[31_build] Using pbp$old_game_id to align with BDB game_id\n")
  pbp_small <- pbp_all %>%
    select(
      old_game_id,
      play_id,
      yards_after_catch,
      epa
    ) %>%
    mutate(
      game_id = as.character(old_game_id),
      play_id = as.integer(play_id)
    )
} else {
  cat("[31_build] Column old_game_id not found; falling back to pbp$game_id\n")
  pbp_small <- pbp_all %>%
    select(
      game_id,
      play_id,
      yards_after_catch,
      epa
    ) %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id)
    )
}

# Some plays may have multiple pbp rows (penalties, etc.). Aggregate by mean.
pbp_agg <- pbp_small %>%
  group_by(game_id, play_id) %>%
  summarise(
    yac = mean(yards_after_catch, na.rm = TRUE),
    epa = mean(epa, na.rm = TRUE),
    .groups = "drop"
  )

# If all values were NA in a group, mean(., na.rm=TRUE) returns NaN → set to NA.
pbp_agg <- pbp_agg %>%
  mutate(
    yac = ifelse(is.nan(yac), NA_real_, yac),
    epa = ifelse(is.nan(epa), NA_real_, epa)
  )

cat("[31_build] Aggregated pbp outcomes for", nrow(pbp_agg), "unique (game_id, play_id)\n")

# -------------------------------------------------------------------
# 4. Join outcomes onto leverage dataset
# -------------------------------------------------------------------

lev2_before_cols <- names(lev2)

lev2_out <- lev2 %>%
  left_join(pbp_agg, by = c("game_id", "play_id"))

# Report how many plays got non-NA outcomes
n_with_yac <- sum(!is.na(lev2_out$yac))
n_with_epa <- sum(!is.na(lev2_out$epa))

cat("[31_build] Matched YAC for", n_with_yac, "rows\n")
cat("[31_build] Matched EPA for", n_with_epa, "rows\n")

# -------------------------------------------------------------------
# 5. Overwrite v2_model04_leverage_dataset.csv with new columns
# -------------------------------------------------------------------

readr::write_csv(lev2_out, path_lev2)

cat("[31_build] Wrote updated leverage dataset with outcomes to", path_lev2, "\n")

# -------------------------------------------------------------------
# 6. Status / report MD
# -------------------------------------------------------------------

status_csv <- file.path(DIR$artifacts, "31_build_outcomes_status.csv")
status_md  <- file.path(DIR$artifacts, "31_build_outcomes_status.md")

status_tbl <- tibble::tibble(
  script        = "31_build_outcomes.R",
  seasons       = paste(years, collapse = ","),
  n_leverage    = nrow(lev2),
  n_pbp_plays   = nrow(pbp_agg),
  n_with_yac    = n_with_yac,
  n_with_epa    = n_with_epa,
  used_old_game_id = pbp_has_old
)

readr::write_csv(status_tbl, status_csv)

md_lines <- c(
  "# 31_build_outcomes Status",
  "",
  "- Script: Code/31_build_outcomes.R",
  paste0("- Seasons detected from game_id: ", paste(years, collapse = ", ")),
  paste0("- Rows in v2 leverage dataset: ", nrow(lev2)),
  paste0("- Unique (game_id, play_id) with pbp outcomes: ", nrow(pbp_agg)),
  paste0("- Rows with non-NA YAC: ", n_with_yac),
  paste0("- Rows with non-NA EPA: ", n_with_epa),
  paste0("- Used old_game_id for join: ", ifelse(pbp_has_old, "YES", "NO")),
  "",
  "Outputs:",
  paste0("  - ", path_lev2),
  paste0("  - ", status_csv)
)

writeLines(md_lines, status_md)

cat("[31_build] Finished 31_build_outcomes.R\n")










# 31.2_affordances_loi_bv.R
# CLI: Rscript Code/31.2_affordances_loi_bv.R
#
# Purpose (Phase-3 spec):
#   Compute Contestability R, Leverage Opportunity Index (LOI = EV(leverage) − EV(chase)),
#   and Backup Value (BV = EV(backup) − EV(chase)).
#
# Inputs
#   - artifacts/eligibility_v3.csv
#   - artifacts/defender_profiles_v3.csv
#   - artifacts/wr_profiles_v3.csv
#   - artifacts/v2_model04_leverage_dataset.csv (throw-time geometry + ext_* + yac/epa from 31_build_outcomes)
#
# Outputs
#   - artifacts/affordances_v3.csv (R, LOI, BV, sep_throw, zone, EV_*)
#   - artifacts/contestability_reliability.png
#   - artifacts/affordances_v3_status.{csv,md}

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(isotone)
  library(ggplot2)
}))

cat("[31.2] Starting 31.2_affordances_loi_bv.R\n")

DIR <- list(
  artifacts = "artifacts"
)

# -------------------------------------------------------------------
# 1. Load inputs
# -------------------------------------------------------------------

path_elig <- file.path(DIR$artifacts, "eligibility_v3.csv")
path_def  <- file.path(DIR$artifacts, "defender_profiles_v3.csv")
path_wr   <- file.path(DIR$artifacts, "wr_profiles_v3.csv")
path_lev2 <- file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv")

elig <- readr::read_csv(path_elig, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

defp <- readr::read_csv(path_def, show_col_types = FALSE) %>%
  mutate(
    nfl_id = as.integer(nfl_id)
  )

wrp <- readr::read_csv(path_wr, show_col_types = FALSE) %>%
  mutate(
    nfl_id = as.integer(nfl_id)
  )

lev2 <- readr::read_csv(path_lev2, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

# -------------------------------------------------------------------
# 2. Merge geometry + eligibility + profiles
# -------------------------------------------------------------------

base <- elig %>%
  left_join(
    lev2,
    by = c("game_id", "play_id", "nfl_id", "split"),
    suffix = c("", "_lev")
  ) %>%
  left_join(defp, by = "nfl_id") %>%
  left_join(wrp,  by = "nfl_id")

n <- nrow(base)

# sep_throw: prefer leverage d_start, else eligibility d_start
base <- base %>%
  mutate(
    sep_throw = dplyr::coalesce(
      suppressWarnings(as.numeric(.data[["d_start_lev"]])),  # from lev2
      suppressWarnings(as.numeric(.data[["d_start"]]))       # from elig
    )
  )

# zone placeholder: no explicit zone column in current artifacts → NA
base$zone_out <- NA_character_

# -------------------------------------------------------------------
# 3. STEP 1 – Monte Carlo over latency/turn dynamics → Contestability R
# -------------------------------------------------------------------

set.seed(3102)


mc_R_one <- function(latency_mu, latency_sd,
                     turn_cost_per_rad,
                     d_start,
                     T_ball,
                     v_max,
                     a_max,
                     n_sims = 200L) {
  
  if (is.na(latency_mu) || is.na(latency_sd) ||
      is.na(turn_cost_per_rad) || is.na(d_start) ||
      is.na(T_ball) || is.na(v_max) || is.na(a_max)) {
    return(NA_real_)
  }
  
  latency <- pmax(rnorm(n_sims, mean = latency_mu, sd = latency_sd), 0)
  tc      <- pmax(turn_cost_per_rad, 0)
  
  # effective time to move after latency & turning
  t_move <- pmax(T_ball - latency - tc, 0)
  
  # Simple kinematic reach distance under v_max, a_max
  # d = v_max * t + 0.5 * a_max * t^2
  d_eff <- pmax(d_start, 0)
  dist  <- v_max * t_move + 0.5 * a_max * t_move^2
  
  mean(dist >= d_eff)
}

cat("[31.2] Computing MC contestability R...\n")

# v_max / a_max: use defender_profiles values (v_max_y/a_max_y after join with lev2)
v_max_vec <- rep(NA_real_, n)
a_max_vec <- rep(NA_real_, n)

if ("v_max.y" %in% names(base)) {
  v_max_vec <- suppressWarnings(as.numeric(base[["v_max.y"]]))
} else if ("v_max" %in% names(base)) {
  v_max_vec <- suppressWarnings(as.numeric(base[["v_max"]]))
}

if ("a_max.y" %in% names(base)) {
  a_max_vec <- suppressWarnings(as.numeric(base[["a_max.y"]]))
} else if ("a_max" %in% names(base)) {
  a_max_vec <- suppressWarnings(as.numeric(base[["a_max"]]))
}

lat_mu    <- if ("latency_mu" %in% names(base)) suppressWarnings(as.numeric(base$latency_mu)) else rep(NA_real_, n)
lat_sd    <- if ("latency_sd" %in% names(base)) suppressWarnings(as.numeric(base$latency_sd)) else rep(NA_real_, n)
turn_cost <- if ("turn_cost_per_rad" %in% names(base)) suppressWarnings(as.numeric(base$turn_cost_per_rad)) else rep(NA_real_, n)
T_ball    <- if ("T_ball" %in% names(base)) suppressWarnings(as.numeric(base$T_ball)) else rep(NA_real_, n)
d_start   <- suppressWarnings(as.numeric(base$sep_throw))

R_raw <- purrr::pmap_dbl(
  list(lat_mu, lat_sd, turn_cost, d_start, T_ball, v_max_vec, a_max_vec),
  mc_R_one
)

base$R_raw <- R_raw

# -------------------------------------------------------------------
# 4. STEP 2 & 3 – Throw-time YAC/EPA regressor → LOI & BV
# -------------------------------------------------------------------

cat("[31.2] Training throw-time YAC/EPA regressor...\n")

# Convert action flags to numeric so they can be used as features
flag_names <- intersect(
  c("contest_eligible", "leverage_eligible", "backup_eligible", "hold"),
  names(base)
)

if (length(flag_names) > 0) {
  base <- base %>%
    mutate(across(all_of(flag_names), ~ as.integer(.)))
}

# Target priority: YAC first, then EPA if YAC unavailable
target_candidates_yac <- c("yac", "yac.x", "yac.y")
target_candidates_epa <- c("epa", "epa.x", "epa.y")

target_var <- NA_character_

for (nm in target_candidates_yac) {
  if (nm %in% names(base)) {
    target_var <- nm
    break
  }
}
if (is.na(target_var)) {
  for (nm in target_candidates_epa) {
    if (nm %in% names(base)) {
      target_var <- nm
      break
    }
  }
}

have_label <- !is.na(target_var)
predict_ev <- NULL

if (have_label) {
  model_df <- base %>% dplyr::filter(!is.na(.data[[target_var]]))
  
  # Curated throw-time geometry + context features
  geom_candidates <- c(
    "sep_throw",
    "p_reach_start", "p_reach_max",
    "d_min", "d_arrival",
    "T_ball",
    "ext_distance",
    "ext_ydstogo",
    "ext_game_seconds_remaining",
    "ext_score_differential",
    "ext_yardline_100"
  )
  
  # Use only 3 of the 4 flags in the model: hold is baseline
  flag_names_model <- setdiff(flag_names, "hold")
  
  # Base geometry + flags
  geom_feats <- intersect(geom_candidates, names(model_df))
  base_feats <- union(geom_feats, flag_names_model)
  
  if (length(base_feats) >= 1 && nrow(model_df) > 10) {
    # Ensure base features are numeric and replace NAs with 0
    model_df <- model_df %>%
      mutate(across(all_of(base_feats), ~ suppressWarnings(as.numeric(.)))) %>%
      mutate(across(all_of(base_feats), ~ tidyr::replace_na(., 0)))
    
    # Add simple flag × geometry interactions so LOI/BV can vary by play
    interaction_names <- character(0)
    if (length(flag_names_model) > 0 && length(geom_feats) > 0) {
      for (fl in flag_names_model) {
        for (gm in geom_feats) {
          int_nm <- paste(fl, gm, sep = "_x_")
          model_df[[int_nm]] <- model_df[[fl]] * model_df[[gm]]
          interaction_names <- c(interaction_names, int_nm)
        }
      }
    }
    
    feat_cols <- c(base_feats, interaction_names)
    
    formula_str <- paste(target_var, "~", paste(feat_cols, collapse = " + "))
    yac_mod <- lm(as.formula(formula_str), data = model_df)
    
    predict_ev <- function(df_new) {
      df_use <- df_new
      
      # Ensure base features exist
      for (nm in base_feats) {
        if (!nm %in% names(df_use)) {
          df_use[[nm]] <- 0
        }
      }
      
      df_use <- df_use %>%
        mutate(across(all_of(base_feats), ~ suppressWarnings(as.numeric(.)))) %>%
        mutate(across(all_of(base_feats), ~ tidyr::replace_na(., 0)))
      
      # Recompute interactions in new data
      if (length(flag_names_model) > 0 && length(geom_feats) > 0) {
        for (fl in flag_names_model) {
          for (gm in geom_feats) {
            int_nm <- paste(fl, gm, sep = "_x_")
            if (!int_nm %in% names(df_use)) {
              if (fl %in% names(df_use) && gm %in% names(df_use)) {
                df_use[[int_nm]] <- df_use[[fl]] * df_use[[gm]]
              } else {
                df_use[[int_nm]] <- 0
              }
            }
          }
        }
      }
      
      # Make sure any remaining features are numeric with NAs filled
      df_use <- df_use %>%
        mutate(across(all_of(feat_cols), ~ suppressWarnings(as.numeric(.)))) %>%
        mutate(across(all_of(feat_cols), ~ tidyr::replace_na(., 0)))
      
      as.numeric(suppressWarnings(predict(yac_mod, newdata = df_use)))
    }
  } else {
    predict_ev <- function(df_new) rep(NA_real_, nrow(df_new))
  }
} else {
  predict_ev <- function(df_new) rep(NA_real_, nrow(df_new))
}

# Scenario helper to set flags
set_flags <- function(df, contest, leverage, backup, hold) {
  if ("contest_eligible" %in% names(df))  df$contest_eligible  <- contest
  if ("leverage_eligible" %in% names(df)) df$leverage_eligible <- leverage
  if ("backup_eligible" %in% names(df))   df$backup_eligible   <- backup
  if ("hold" %in% names(df))              df$hold              <- hold
  df
}

feat_all <- base

# leverage scenario: contest+leverage, not backup, not hold
feat_leverage <- set_flags(feat_all, contest = 1L, leverage = 1L, backup = 0L, hold = 0L)

# chase scenario: hold only
feat_chase <- set_flags(feat_all, contest = 0L, leverage = 0L, backup = 0L, hold = 1L)

# backup scenario: backup only
feat_backup <- set_flags(feat_all, contest = 0L, leverage = 0L, backup = 1L, hold = 0L)

EV_leverage <- predict_ev(feat_leverage)
EV_chase    <- predict_ev(feat_chase)
EV_backup   <- predict_ev(feat_backup)

base$EV_leverage <- EV_leverage
base$EV_chase    <- EV_chase
base$EV_backup   <- EV_backup

base$LOI <- base$EV_leverage - base$EV_chase
base$BV  <- base$EV_backup   - base$EV_chase

# -------------------------------------------------------------------
# 5. STEP 4 – Feature-augmented calibration of R on VAL (if available)
#             Physics MC -> R_raw -> isotonic -> R
# -------------------------------------------------------------------

compute_ece <- function(pred, label, n_bins = 10L) {
  ok <- is.finite(pred) & !is.na(label)
  pred <- pred[ok]; label <- label[ok]
  if (length(pred) == 0) return(NA_real_)
  
  # Quantile-based bins → more robust to tails
  qs <- unique(quantile(pred, probs = seq(0, 1, length.out = n_bins + 1),
                        na.rm = TRUE))
  if (length(qs) <= 2L) {
    # Degenerate: everything effectively in one bin
    return(abs(mean(pred) - mean(label)))
  }
  
  bins <- cut(pred, breaks = qs, include.lowest = TRUE, labels = FALSE)
  df <- tibble(bin = bins, pred = pred, label = label) %>%
    group_by(bin) %>%
    summarise(
      pred_mean  = mean(pred),
      label_mean = mean(label),
      .groups = "drop"
    )
  
  mean(abs(df$pred_mean - df$label_mean), na.rm = TRUE)
}

# Helper: prepare calibration features (kept for compatibility, not used directly)
prep_calibration_df <- function(df) {
  out <- df
  
  # 1) clip R_raw and take logit
  out$R_raw_clip <- pmin(pmax(out$R_raw, 1e-6), 1 - 1e-6)
  out$logit_R    <- qlogis(out$R_raw_clip)
  
  # 2) numeric geometry features
  num_feats <- intersect(
    c("sep_throw", "p_reach_start", "p_reach_max", "d_min", "T_ball"),
    names(out)
  )
  
  for (nm in num_feats) {
    out[[nm]] <- suppressWarnings(as.numeric(out[[nm]]))
    med <- stats::median(out[[nm]], na.rm = TRUE)
    out[[nm]][is.na(out[[nm]])] <- med
  }
  
  list(df = out, num_feats = num_feats)
}

cat("[31.2] Calibrating R via isotonic on VAL if available...\n")

# Use observed contest_primary as label for R calibration
df_cal_all <- base %>%
  filter(!is.na(R_raw), !is.na(contest_primary)) %>%
  mutate(
    label = if_else(contest_primary, 1, 0),
    split = tolower(as.character(split))
  )

# Prefer split == 'val' for calibration; fall back to all if not enough rows
df_cal_val <- df_cal_all %>% filter(split == "val")
use_val    <- nrow(df_cal_val) >= 50

df_cal <- if (use_val) df_cal_val else df_cal_all
calibration_split <- if (use_val) "val" else "all"

# ECE BEFORE isotonic, on calibration subset
ECE_pre <- compute_ece(df_cal$R_raw, df_cal$label, n_bins = 10L)

# Fit isotonic calibrator if needed
if (!is.na(ECE_pre) && ECE_pre > 0.03) {
  iso <- isoreg(df_cal$R_raw, df_cal$label)
  calfun <- suppressWarnings(stats::approxfun(iso$x, iso$yf, rule = 2))
  base$R <- pmin(pmax(calfun(base$R_raw), 0), 1)
} else {
  base$R <- pmin(pmax(base$R_raw, 0), 1)
}

# ECE AFTER isotonic, on the same calibration subset
df_cal_post <- df_cal %>%
  mutate(R_post = base$R[match(
    paste(game_id, play_id, nfl_id, split),
    paste(base$game_id, base$play_id, base$nfl_id, base$split)
  )])

ECE_post <- compute_ece(df_cal_post$R_post, df_cal_post$label, n_bins = 10L)

# Reliability diagram (post-calibration, on calibration subset)
bins_post <- cut(df_cal_post$R_post,
                 breaks = seq(0, 1, by = 0.1),
                 include.lowest = TRUE)

rel_df <- df_cal_post %>%
  mutate(bin = bins_post) %>%
  group_by(bin) %>%
  summarise(
    pred = mean(R_post),
    obs  = mean(label),
    .groups = "drop"
  )

p_rel <- ggplot(rel_df, aes(x = pred, y = obs)) +
  geom_point() +
  geom_abline(slope = 1, intercept = 0) +
  coord_equal(xlim = c(0, 1), ylim = c(0, 1)) +
  labs(
    title = paste0(
      "Contestability R Reliability (Post-Calibration, split=",
      calibration_split, ")"
    ),
    x = "Predicted R",
    y = "Observed contest_primary frequency"
  ) +
  theme_minimal()

rel_path <- file.path(DIR$artifacts, "contestability_reliability.png")
ggsave(rel_path, plot = p_rel, width = 6, height = 6, dpi = 120)

# -------------------------------------------------------------------
# 6. Output: affordances_v3.csv
# -------------------------------------------------------------------

aff <- tibble(
  game_id   = base$game_id,
  play_id   = base$play_id,
  nfl_id    = base$nfl_id,
  split     = base$split,
  R         = base$R,
  LOI       = base$LOI,
  BV        = base$BV,
  sep_throw = base$sep_throw,
  zone      = base$zone_out,
  EV_leverage = base$EV_leverage,
  EV_chase    = base$EV_chase,
  EV_backup   = base$EV_backup
)

out_csv <- file.path(DIR$artifacts, "affordances_v3.csv")
readr::write_csv(aff, out_csv)

# -------------------------------------------------------------------
# 7. Status / report MD
# -------------------------------------------------------------------

status_csv <- file.path(DIR$artifacts, "affordances_v3_status.csv")
status_md  <- file.path(DIR$artifacts, "affordances_v3_status.md")

pass_R <- !is.na(ECE_post) && ECE_post <= 0.03

status_tbl <- tibble(
  script            = "31.2_affordances_loi_bv.R",
  ECE_pre           = round(ECE_pre,  4),
  ECE_post          = round(ECE_post, 4),
  pass_R            = !is.na(ECE_post) && ECE_post <= 0.03,
  have_label        = have_label,
  calibration_split = calibration_split,
  n_cal             = nrow(df_cal)
)

readr::write_csv(status_tbl, status_csv)

zone_summary <- aff %>%
  group_by(zone) %>%
  summarise(
    n       = n(),
    LOI_med = median(LOI, na.rm = TRUE),
    BV_med  = median(BV,  na.rm = TRUE),
    .groups = "drop"
  )

zone_lines <- purrr::pmap_chr(
  zone_summary,
  function(zone, n, LOI_med, BV_med) {
    sprintf(
      "- zone=%s, n=%d, median LOI=%.3f, median BV=%.3f",
      ifelse(is.na(zone), "NA", zone), n, LOI_med, BV_med
    )
  }
)

md_lines <- c(
  "# 31.2_affordances_loi_bv Status",
  "",
  "- Script: Code/31.2_affordances_loi_bv.R",
  sprintf("- Calibration split used: %s (n=%d)", calibration_split, nrow(df_cal)),
  sprintf("- ECE (pre, cal split):  %.4f", ECE_pre),
  sprintf("- ECE (post, cal split): %.4f", ECE_post),
  sprintf("- PASS R (ECE_post <= 0.03): %s", ifelse(pass_R, "YES", "NO")),
  sprintf("- YAC/EPA label present for LOI/BV modelling: %s", ifelse(have_label, "YES", "NO")),
  "",
  "- LOI/BV by zone (for directional reasonableness check):",
  zone_lines,
  "",
  "Outputs:",
  paste0("  - ", out_csv),
  paste0("  - ", rel_path)
)

writeLines(md_lines, status_md)

cat("[31.2] Finished 31.2_affordances_loi_bv.R\n")










# 31.3_affordances_zone.R
# CLI: Rscript Code/31.3_affordances_zone.R
#
# Purpose:
#   Populate a simple, deterministic field zone for each defender–play in
#   affordances_v3.csv, using ext_yardline_100 from v2_model04_leverage_dataset.
#   This is a pure post-processing step: it does NOT change R, LOI, BV or any
#   calibration, it only fills the `zone` column and emits QA summaries.
#
#   The definition here is depth-only, consistent with the plan's use of
#   `zone` purely for grouping / analysis, not as a model feature:
#     - zone = "scoring"  if ext_yardline_100 <= 33
#     - zone = "neutral"  if 33 < ext_yardline_100 <= 67
#     - zone = "backed_up" if ext_yardline_100 > 67
#
# Inputs:
#   - artifacts/affordances_v3.csv   (from 31.2_affordances_loi_bv.R)
#   - artifacts/v2_model04_leverage_dataset.csv (for ext_yardline_100)
#
# Outputs:
#   - artifacts/affordances_v3.csv   (same file, with `zone` populated)
#   - artifacts/31.3_zone_status.csv
#   - artifacts/31.3_zone_status.md
#
# Notes:
#   - Zone is ONLY used downstream for grouping / diagnostics (e.g. LOI/BV
#     directionality by zone), never as an input to a model or calibrator.
#   - This script is deliberately side-effect free on R/LOI/BV; it just
#     overwrites the `zone` column.
#

suppressWarnings(suppressMessages({
  library(tidyverse)
}))

cat("[31.3] Starting 31.3_affordances_zone.R\n")

# -------------------------------------------------------------------
# 0. Paths
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

path_aff <- file.path(DIR$artifacts, "affordances_v3.csv")
path_lev <- file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv")

if (!file.exists(path_aff)) {
  stop("[31.3] affordances_v3.csv not found in artifacts/. Run 31.2 first.")
}
if (!file.exists(path_lev)) {
  stop("[31.3] v2_model04_leverage_dataset.csv not found in artifacts/.")
}

# -------------------------------------------------------------------
# 1. Load data
# -------------------------------------------------------------------

aff <- readr::read_csv(path_aff, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

lev <- readr::read_csv(path_lev, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

if (!"ext_yardline_100" %in% names(lev)) {
  stop("[31.3] ext_yardline_100 not found in v2_model04_leverage_dataset.csv.")
}

cat(sprintf("[31.3] Loaded affordances (%d rows) and leverage dataset (%d rows)\n",
            nrow(aff), nrow(lev)))

# -------------------------------------------------------------------
# 2. Join ext_yardline_100 and compute zone
# -------------------------------------------------------------------

# Minimal key for defender-level join
keys <- c("game_id", "play_id", "nfl_id", "split")

lev_zone <- lev %>%
  select(all_of(keys), ext_yardline_100)

# Warn if join is not one-to-one, but proceed
n_before <- nrow(aff)
aff_z <- aff %>%
  left_join(lev_zone, by = keys)

if (nrow(aff_z) != n_before) {
  warning(sprintf(
    "[31.3] Row count changed after join (before=%d, after=%d). Check key uniqueness.",
    n_before, nrow(aff_z)
  ))
}

# Depth-based zone definition
aff_z <- aff_z %>%
  mutate(
    zone = dplyr::case_when(
      is.na(ext_yardline_100) ~ NA_character_,
      ext_yardline_100 <= 33 ~ "scoring",
      ext_yardline_100 <= 67 ~ "neutral",
      TRUE                   ~ "backed_up"
    )
  ) %>%
  select(-ext_yardline_100)

cat("[31.3] Computed depth-only zone from ext_yardline_100\n")

# -------------------------------------------------------------------
# 3. QA: LOI/BV by zone & split
# -------------------------------------------------------------------

zone_summary <- aff_z %>%
  group_by(zone, split) %>%
  summarise(
    n       = n(),
    LOI_med = median(LOI, na.rm = TRUE),
    BV_med  = median(BV,  na.rm = TRUE),
    LOI_mean = mean(LOI, na.rm = TRUE),
    BV_mean  = mean(BV,  na.rm = TRUE),
    .groups = "drop"
  ) %>%
  arrange(zone, split)

cat("[31.3] LOI/BV by zone×split (first few rows):\n")
print(head(zone_summary, 10))

# -------------------------------------------------------------------
# 4. Overwrite affordances_v3.csv with populated zone
# -------------------------------------------------------------------

# Reorder columns to keep the original structure as much as possible:
# ensure zone is present; if original had zone, we effectively overwrite it.
if (!"zone" %in% names(aff_z)) {
  stop("[31.3] Failed to create zone column.")
}

# Write back
readr::write_csv(aff_z, path_aff)
cat("[31.3] Wrote updated affordances with zone to ", path_aff, "\n", sep = "")

# -------------------------------------------------------------------
# 5. Status / report MD
# -------------------------------------------------------------------

status_csv <- file.path(DIR$artifacts, "31.3_zone_status.csv")
status_md  <- file.path(DIR$artifacts, "31.3_zone_status.md")

status_tbl <- zone_summary %>%
  mutate(
    script = "31.3_affordances_zone.R"
  ) %>%
  relocate(script)

readr::write_csv(status_tbl, status_csv)

# Build a compact MD summary
md_lines <- c(
  "# 31.3_affordances_zone Status",
  "",
  "- Script: Code/31.3_affordances_zone.R",
  sprintf("- Rows in affordances_v3: %d", nrow(aff_z)),
  "",
  "## LOI/BV by zone × split",
  ""
)

for (i in seq_len(nrow(zone_summary))) {
  zr <- zone_summary[i, ]
  line <- sprintf(
    "- zone=%s, split=%s, n=%d, LOI_med=%.3f, BV_med=%.3f, LOI_mean=%.3f, BV_mean=%.3f",
    ifelse(is.na(zr$zone), "NA", zr$zone),
    ifelse(is.na(zr$split), "NA", zr$split),
    zr$n,
    zr$LOI_med, zr$BV_med,
    zr$LOI_mean, zr$BV_mean
  )
  md_lines <- c(md_lines, line)
}

md_lines <- c(
  md_lines,
  "",
  "Outputs:",
  paste0("  - ", path_aff),
  paste0("  - ", status_csv)
)

writeLines(md_lines, status_md)

cat("[31.3] Finished 31.3_affordances_zone.R\n")










# 31a_verify_affordances.R
# CLI: Rscript Code/31a_verify_affordances.R
#
# Purpose:
#   End-to-end verification of Phase-3 affordance build:
#     - 31_build_outcomes.R       (YAC/EPA onto leverage dataset)
#     - 31.2_affordances_loi_bv.R (R, LOI, BV, calibration)
#     - 31.3_affordances_zone.R   (zone assignment)
#
#   This script performs consistency checks across the artifacts and writes a
#   compact status report. It does NOT modify any existing artifacts.
#
# Inputs (all in artifacts/):
#   - v2_model04_leverage_dataset.csv
#   - 31_build_outcomes_status.csv
#   - affordances_v3.csv
#   - affordances_v3_status.csv
#   - 31.3_zone_status.csv
#
# Outputs:
#   - artifacts/31a_verify_affordances_status.csv
#   - artifacts/31a_verify_affordances_status.md
#
# Exit behaviour:
#   - The script always writes the status files.
#   - If any critical check fails, it stops() with a message after writing.
#

suppressWarnings(suppressMessages({
  library(tidyverse)
}))

cat("[31a] Starting 31a_verify_affordances.R\n")

DIR <- list(
  artifacts = "artifacts"
)

path_lev      <- file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv")
path_build_st <- file.path(DIR$artifacts, "31_build_outcomes_status.csv")
path_aff      <- file.path(DIR$artifacts, "affordances_v3.csv")
path_aff_st   <- file.path(DIR$artifacts, "affordances_v3_status.csv")
path_zone_st  <- file.path(DIR$artifacts, "31.3_zone_status.csv")

paths <- c(
  v2_model04_leverage_dataset = path_lev,
  status_31_build             = path_build_st,
  affordances_v3              = path_aff,
  status_31_2                 = path_aff_st,
  status_31_3_zone            = path_zone_st
)

missing <- names(paths)[!file.exists(paths)]
if (length(missing) > 0) {
  stop(
    "[31a] Missing required artifact(s): ",
    paste(missing, collapse = ", "),
    "\nRun 31_build_outcomes.R, 31.2_affordances_loi_bv.R and 31.3_affordances_zone.R first."
  )
}

# -------------------------------------------------------------------
# Helper: quantile-based ECE (matches intended 31.2 behaviour)
# -------------------------------------------------------------------

compute_ece <- function(pred, label, n_bins = 10L) {
  ok <- is.finite(pred) & !is.na(label)
  pred <- pred[ok]; label <- label[ok]
  if (length(pred) == 0) return(NA_real_)
  
  qs <- unique(quantile(pred, probs = seq(0, 1, length.out = n_bins + 1), na.rm = TRUE))
  if (length(qs) <= 2L) {
    # Degenerate case: effectively one bin
    return(abs(mean(pred) - mean(label)))
  }
  
  bins <- cut(pred, breaks = qs, include.lowest = TRUE, labels = FALSE)
  df <- tibble(bin = bins, pred = pred, label = label) %>%
    group_by(bin) %>%
    summarise(
      pred_mean  = mean(pred),
      label_mean = mean(label),
      .groups = "drop"
    )
  
  mean(abs(df$pred_mean - df$label_mean), na.rm = TRUE)
}

# -------------------------------------------------------------------
# Load all artifacts
# -------------------------------------------------------------------

lev <- readr::read_csv(path_lev, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

build_st <- readr::read_csv(path_build_st, show_col_types = FALSE)

aff <- readr::read_csv(path_aff, show_col_types = FALSE) %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

aff_st  <- readr::read_csv(path_aff_st, show_col_types = FALSE)
zone_st <- readr::read_csv(path_zone_st, show_col_types = FALSE)

cat(sprintf("[31a] Loaded leverage (%d rows) and affordances (%d rows)\n",
            nrow(lev), nrow(aff)))

# Storage for check results
checks <- tibble(
  check_id = character(),
  pass     = logical(),
  detail   = character()
)

add_check <- function(id, pass, detail) {
  tibble(
    check_id = id,
    pass     = pass,
    detail   = detail
  )
}

# -------------------------------------------------------------------
# Check 1: 31_build_outcomes – YAC/EPA columns & counts
# -------------------------------------------------------------------

has_yac <- "yac" %in% names(lev)
has_epa <- "epa" %in% names(lev)

n_yac <- if (has_yac) sum(!is.na(lev$yac)) else 0L
n_epa <- if (has_epa) sum(!is.na(lev$epa)) else 0L

checks <- bind_rows(
  checks,
  add_check(
    "31_build_yac_epa_cols",
    has_yac && has_epa,
    sprintf("lev has yac=%s, epa=%s", has_yac, has_epa)
  )
)

if (all(c("n_with_yac", "n_with_epa") %in% names(build_st))) {
  exp_n_yac <- build_st$n_with_yac[1]
  exp_n_epa <- build_st$n_with_epa[1]
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_build_yac_count_match",
      n_yac == exp_n_yac,
      sprintf("n_yac=%d, expected=%d", n_yac, exp_n_yac)
    ),
    add_check(
      "31_build_epa_count_match",
      n_epa == exp_n_epa,
      sprintf("n_epa=%d, expected=%d", n_epa, exp_n_epa)
    )
  )
} else {
  checks <- bind_rows(
    checks,
    add_check(
      "31_build_yac_epa_counts_missing",
      FALSE,
      "31_build_outcomes_status.csv lacks n_with_yac/n_with_epa columns"
    )
  )
}

# -------------------------------------------------------------------
# Join affordances with leverage labels (contest_primary) for 31.2 checks
# -------------------------------------------------------------------

if (!"contest_primary" %in% names(lev)) {
  checks <- bind_rows(
    checks,
    add_check(
      "31_2_missing_contest_primary",
      FALSE,
      "contest_primary column missing from v2_model04_leverage_dataset.csv"
    )
  )
} else {
  df_cal <- aff %>%
    left_join(
      lev %>% select(game_id, play_id, nfl_id, split, contest_primary),
      by = c("game_id", "play_id", "nfl_id", "split")
    )
  
  # VAL subset with non-missing R and label
  df_val <- df_cal %>%
    filter(
      split == "val",
      !is.na(R),
      !is.na(contest_primary)
    ) %>%
    mutate(label = if_else(contest_primary, 1, 0))
  
  n_val <- nrow(df_val)
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_2_val_rows_for_calibration",
      n_val > 0,
      sprintf("n_val rows with R and contest_primary: %d", n_val)
    )
  )
  
  # -----------------------------------------------------------------
  # Check 2: 31.2 – R in [0,1], non-degenerate, and ECE matches status
  # -----------------------------------------------------------------
  
  if (n_val > 0) {
    R_min <- min(df_val$R, na.rm = TRUE)
    R_max <- max(df_val$R, na.rm = TRUE)
    
    checks <- bind_rows(
      checks,
      add_check(
        "31_2_R_range",
        R_min >= -1e-8 && R_max <= 1 + 1e-8,
        sprintf("R_min=%.6f, R_max=%.6f", R_min, R_max)
      )
    )
    
    # Recompute ECE_post on VAL using quantile-binned metric
    ece_val_post <- compute_ece(df_val$R, df_val$label, n_bins = 10L)
    
    if (all(c("ECE_post", "pass_R", "calibration_split") %in% names(aff_st))) {
      ece_post_status <- aff_st$ECE_post[1]
      pass_R_status   <- aff_st$pass_R[1]
      split_status    <- aff_st$calibration_split[1]
      
      checks <- bind_rows(
        checks,
        add_check(
          "31_2_R_ECE_match",
          is.finite(ece_val_post) &&
            abs(ece_val_post - ece_post_status) <= 1e-3,
          sprintf("ECE_post_recomp=%.4f, ECE_post_status=%.4f",
                  ece_val_post, ece_post_status)
        ),
        add_check(
          "31_2_R_ECE_threshold",
          isTRUE(pass_R_status) && ece_val_post <= 0.03 + 1e-8 &&
            split_status == "val",
          sprintf("ECE_post=%.4f, pass_R_status=%s, split=%s",
                  ece_val_post, as.character(pass_R_status), split_status)
        )
      )
    } else {
      checks <- bind_rows(
        checks,
        add_check(
          "31_2_R_status_missing",
          FALSE,
          "affordances_v3_status.csv missing ECE_post/pass_R/calibration_split"
        )
      )
    }
  }
}

# -------------------------------------------------------------------
# Check 3: 31.2 – LOI/BV non-degenerate and reasonable variation
# -------------------------------------------------------------------

if (all(c("LOI", "BV") %in% names(aff))) {
  loi_sd <- sd(aff$LOI, na.rm = TRUE)
  bv_sd  <- sd(aff$BV,  na.rm = TRUE)
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_2_LOI_variation",
      is.finite(loi_sd) && loi_sd > 0,
      sprintf("sd(LOI)=%.4f", loi_sd)
    ),
    add_check(
      "31_2_BV_variation",
      is.finite(bv_sd) && bv_sd > 0,
      sprintf("sd(BV)=%.4f", bv_sd)
    )
  )
} else {
  checks <- bind_rows(
    checks,
    add_check(
      "31_2_LOI_BV_missing",
      FALSE,
      "LOI/BV columns missing in affordances_v3.csv"
    )
  )
}

# -------------------------------------------------------------------
# Check 4: 31.3 – zone assignment matches ext_yardline_100
# -------------------------------------------------------------------

if (!"zone" %in% names(aff)) {
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_zone_missing",
      FALSE,
      "zone column missing in affordances_v3.csv"
    )
  )
} else if (!"ext_yardline_100" %in% names(lev)) {
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_ext_yardline_missing",
      FALSE,
      "ext_yardline_100 column missing from leverage dataset"
    )
  )
} else {
  keys <- c("game_id", "play_id", "nfl_id", "split")
  
  lev_zone <- lev %>%
    select(all_of(keys), ext_yardline_100)
  
  n_before <- nrow(aff)
  aff_join <- aff %>%
    left_join(lev_zone, by = keys)
  
  n_after <- nrow(aff_join)
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_join_rowcount",
      n_before == n_after,
      sprintf("rows before join=%d, after=%d", n_before, n_after)
    )
  )
  
  # Recompute expected zone
  aff_join <- aff_join %>%
    mutate(
      zone_expected = dplyr::case_when(
        is.na(ext_yardline_100) ~ NA_character_,
        ext_yardline_100 <= 33 ~ "scoring",
        ext_yardline_100 <= 67 ~ "neutral",
        TRUE                   ~ "backed_up"
      )
    )
  
  mismatch <- sum(
    !(
      (is.na(aff_join$zone) & is.na(aff_join$zone_expected)) |
        (aff_join$zone == aff_join$zone_expected)
    ),
    na.rm = TRUE
  )
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_zone_match",
      mismatch == 0,
      sprintf("zone mismatches vs expected: %d", mismatch)
    )
  )
}

# -------------------------------------------------------------------
# Check 5: 31.3 – zone_status summary matches recomputed LOI/BV stats
# -------------------------------------------------------------------

if (all(c("zone", "split", "n", "LOI_med", "BV_med", "LOI_mean", "BV_mean") %in% names(zone_st))) {
  # Recompute from affordances
  zone_summary <- aff %>%
    group_by(zone, split) %>%
    summarise(
      n       = dplyr::n(),
      LOI_med = median(LOI, na.rm = TRUE),
      BV_med  = median(BV,  na.rm = TRUE),
      LOI_mean = mean(LOI, na.rm = TRUE),
      BV_mean  = mean(BV,  na.rm = TRUE),
      .groups = "drop"
    )
  
  merged <- zone_st %>%
    select(script, zone, split, n_status = n,
           LOI_med_status = LOI_med,
           BV_med_status  = BV_med,
           LOI_mean_status = LOI_mean,
           BV_mean_status  = BV_mean) %>%
    full_join(
      zone_summary %>%
        select(zone, split, n_recomp = n,
               LOI_med_recomp = LOI_med,
               BV_med_recomp  = BV_med,
               LOI_mean_recomp = LOI_mean,
               BV_mean_recomp  = BV_mean),
      by = c("zone", "split")
    )
  
  # Check row coverage
  coverage_ok <- !any(is.na(merged$n_status)) && !any(is.na(merged$n_recomp))
  
  # Numerical differences
  merged <- merged %>%
    mutate(
      n_diff        = n_status - n_recomp,
      LOI_med_diff  = LOI_med_status - LOI_med_recomp,
      BV_med_diff   = BV_med_status  - BV_med_recomp,
      LOI_mean_diff = LOI_mean_status - LOI_mean_recomp,
      BV_mean_diff  = BV_mean_status  - BV_mean_recomp
    )
  
  n_diff_ok <- all(merged$n_diff == 0, na.rm = TRUE)
  tol <- 1e-6
  loi_med_ok  <- max(abs(merged$LOI_med_diff),  na.rm = TRUE) <= tol
  bv_med_ok   <- max(abs(merged$BV_med_diff),   na.rm = TRUE) <= tol
  loi_mean_ok <- max(abs(merged$LOI_mean_diff), na.rm = TRUE) <= tol
  bv_mean_ok  <- max(abs(merged$BV_mean_diff),  na.rm = TRUE) <= tol
  
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_zone_status_coverage",
      coverage_ok,
      sprintf("zone_status rows=%d, recomputed rows=%d",
              nrow(zone_st), nrow(zone_summary))
    ),
    add_check(
      "31_3_zone_status_counts",
      n_diff_ok,
      sprintf("max |n_status - n_recomp| = %d", max(abs(merged$n_diff), na.rm = TRUE))
    ),
    add_check(
      "31_3_zone_status_values",
      loi_med_ok && bv_med_ok && loi_mean_ok && bv_mean_ok,
      sprintf(
        "max abs diffs: LOI_med=%.3g, BV_med=%.3g, LOI_mean=%.3g, BV_mean=%.3g",
        max(abs(merged$LOI_med_diff),  na.rm = TRUE),
        max(abs(merged$BV_med_diff),   na.rm = TRUE),
        max(abs(merged$LOI_mean_diff), na.rm = TRUE),
        max(abs(merged$BV_mean_diff),  na.rm = TRUE)
      )
    )
  )
} else {
  checks <- bind_rows(
    checks,
    add_check(
      "31_3_zone_status_missing_cols",
      FALSE,
      "31.3_zone_status.csv missing one or more of: zone, split, n, LOI_med, BV_med, LOI_mean, BV_mean"
    )
  )
}

# -------------------------------------------------------------------
# Write status CSV / MD and (optionally) fail fast if critical checks fail
# -------------------------------------------------------------------

status_csv <- file.path(DIR$artifacts, "31a_verify_affordances_status.csv")
status_md  <- file.path(DIR$artifacts, "31a_verify_affordances_status.md")

readr::write_csv(checks, status_csv)

# Build markdown summary
md_lines <- c(
  "# 31a_verify_affordances Status",
  "",
  "- Script: Code/31a_verify_affordances.R",
  sprintf("- Rows in leverage dataset: %d", nrow(lev)),
  sprintf("- Rows in affordances_v3: %d", nrow(aff)),
  "",
  "## Checks",
  ""
)

for (i in seq_len(nrow(checks))) {
  row <- checks[i, ]
  line <- sprintf(
    "- [%s] %s — %s",
    ifelse(row$pass, "PASS", "FAIL"),
    row$check_id,
    row$detail
  )
  md_lines <- c(md_lines, line)
}

writeLines(md_lines, status_md)

cat("[31a] Wrote verification status to ", status_csv, " and ", status_md, "\n", sep = "")

# Decide whether to stop on failure
if (any(!checks$pass)) {
  failed <- checks %>% filter(!pass) %>% pull(check_id)
  stop("[31a] One or more checks FAILED: ", paste(failed, collapse = ", "))
} else {
  cat("[31a] All checks PASSED.\n")
}










# 32_direction_finder.R
# CLI: Rscript Code/32_direction_finder.R
#
# Full-rollout Phase-3 heading search:
#   - Discretize heading cone
#   - Roll out ~0.8 s under v_max/a_max/yaw_rate/latency
#   - Rebuild throw-time features
#   - Score each heading with 31.2 YAC/EPA regressor
#   - Pick θ*, backup point, θ* variance, and overlays
#
# Assumes Phase-3 artifacts are already built.

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(purrr)
  library(janitor)
}))

set.seed(32)

cat("[32] Starting 32_direction_finder.R\n")

# -------------------------------------------------------------------
# 0. Constants & directories
# -------------------------------------------------------------------

DT <- 0.1  # seconds per frame
DIR <- list(
  artifacts = "artifacts",
  train     = "train",
