# -------------------------------------------------------------------
# 3. Load or fit throw-time YAC/EPA model (aligned with 31.2)
# -------------------------------------------------------------------

load_or_fit_yac_model <- function(path_lev2, path_elig, path_model_rds) {
  if (file.exists(path_model_rds)) {
    cat("[32] Loading throw-time YAC/EPA model from RDS\n")
    return(readRDS(path_model_rds))
  }
  
  cat("[32] Fitting throw-time YAC/EPA model (fallback; mirror 31.2 logic)\n")
  
  lev <- readr::read_csv(path_lev2, show_col_types = FALSE) %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
  
  elig_loc <- readr::read_csv(path_elig, show_col_types = FALSE) %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
  
  base <- elig_loc %>%
    left_join(
      lev,
      by = c("game_id","play_id","nfl_id","split"),
      suffix = c("", "_lev")
    )
  
  flag_names <- intersect(
    c("contest_eligible","leverage_eligible","backup_eligible","hold"),
    names(base)
  )
  if (length(flag_names) > 0) {
    base <- base %>%
      mutate(across(all_of(flag_names), ~ as.integer(.)))
  }
  
  target_candidates_yac <- c("yac","yac.x","yac.y")
  target_candidates_epa <- c("epa","epa.x","epa.y")
  
  target_var <- NA_character_
  for (nm in target_candidates_yac) {
    if (nm %in% names(base)) { target_var <- nm; break }
  }
  if (is.na(target_var)) {
    for (nm in target_candidates_epa) {
      if (nm %in% names(base)) { target_var <- nm; break }
    }
  }
  if (is.na(target_var)) {
    warning("[32] No YAC/EPA column found; EV model will be NA.")
    return(list(
      model            = NULL,
      feat_cols        = character(0),
      geom_feats       = character(0),
      flag_names_model = character(0),
      target_var       = NA_character_
    ))
  }
  
  model_df <- base %>% filter(split == "train", !is.na(.data[[target_var]]))
  
  geom_candidates <- c(
    "sep_throw",
    "p_reach_start", "p_reach_max",
    "d_min", "d_arrival",
    "T_ball",
    "ext_distance",
    "ext_ydstogo",
    "ext_game_seconds_remaining",
    "ext_score_differential",
    "ext_yardline_100"
  )
  
  flag_names_model <- setdiff(flag_names, "hold")
  
  geom_feats <- intersect(geom_candidates, names(model_df))
  base_feats <- union(geom_feats, flag_names_model)
  
  if (length(base_feats) >= 1 && nrow(model_df) > 10) {
    model_df <- model_df %>%
      mutate(across(all_of(base_feats), ~ suppressWarnings(as.numeric(.)))) %>%
      mutate(across(all_of(base_feats), ~ tidyr::replace_na(., 0)))
    
    interaction_names <- character(0)
    if (length(flag_names_model) > 0 && length(geom_feats) > 0) {
      for (fl in flag_names_model) {
        for (gm in geom_feats) {
          int_nm <- paste(fl, gm, sep = "_x_")
          model_df[[int_nm]] <- model_df[[fl]] * model_df[[gm]]
          interaction_names <- c(interaction_names, int_nm)
        }
      }
    }
    
    feat_cols <- c(base_feats, interaction_names)
    formula_str <- paste(target_var, "~", paste(feat_cols, collapse = " + "))
    yac_mod <- lm(as.formula(formula_str), data = model_df)
    
    obj <- list(
      model            = yac_mod,
      feat_cols        = feat_cols,
      geom_feats       = geom_feats,
      flag_names_model = flag_names_model,
      target_var       = target_var
    )
    saveRDS(obj, path_model_rds)
    obj
  } else {
    warning("[32] Not enough data to train EV model; EV will be NA.")
    list(
      model            = NULL,
      feat_cols        = character(0),
      geom_feats       = character(0),
      flag_names_model = flag_names_model,
      target_var       = target_var
    )
  }
}

model_obj <- load_or_fit_yac_model(PATH$lev2, PATH$elig, PATH$model_rds)

predict_ev_throw <- function(df_new, model_obj) {
  if (is.null(model_obj$model) || !length(model_obj$feat_cols)) {
    return(rep(NA_real_, nrow(df_new)))
  }
  
  feat_cols        <- model_obj$feat_cols
  geom_feats       <- model_obj$geom_feats
  flag_names_model <- model_obj$flag_names_model
  yac_mod          <- model_obj$model
  
  df_use <- df_new
  base_feats <- union(geom_feats, flag_names_model)
  
  for (nm in base_feats) {
    if (!nm %in% names(df_use)) df_use[[nm]] <- 0
  }
  
  df_use <- df_use %>%
    mutate(across(all_of(base_feats), ~ suppressWarnings(as.numeric(.)))) %>%
    mutate(across(all_of(base_feats), ~ tidyr::replace_na(., 0)))
  
  if (length(flag_names_model) > 0 && length(geom_feats) > 0) {
    for (fl in flag_names_model) {
      for (gm in geom_feats) {
        int_nm <- paste(fl, gm, sep = "_x_")
        if (!int_nm %in% names(df_use)) {
          df_use[[int_nm]] <- df_use[[fl]] * df_use[[gm]]
        }
      }
    }
  }
  
  missing <- setdiff(feat_cols, names(df_use))
  for (nm in missing) df_use[[nm]] <- 0
  
  df_use <- df_use %>%
    mutate(across(all_of(feat_cols), ~ suppressWarnings(as.numeric(.)))) %>%
    mutate(across(all_of(feat_cols), ~ tidyr::replace_na(., 0)))
  
  as.numeric(suppressWarnings(predict(yac_mod, newdata = df_use)))
}

set_flags <- function(df, contest, leverage, backup, hold) {
  if ("contest_eligible" %in% names(df))  df$contest_eligible  <- contest
  if ("leverage_eligible" %in% names(df)) df$leverage_eligible <- leverage
  if ("backup_eligible" %in% names(df))   df$backup_eligible   <- backup
  if ("hold" %in% names(df))              df$hold              <- hold
  df
}

# -------------------------------------------------------------------
# 4. Kinematics helper (from 30)
# -------------------------------------------------------------------

distance_covered <- function(t, v_max, a_max) {
  t <- pmax(t, 0)
  a_max_safe <- ifelse(is.na(a_max) | a_max <= 0, NA, a_max)
  v_max_safe <- ifelse(is.na(v_max) | v_max <= 0, NA, v_max)
  
  t_acc <- ifelse(is.na(a_max_safe), NA, v_max_safe / a_max_safe)
  dist_acc <- 0.5 * a_max_safe * pmin(t, t_acc)^2
  
  extra_t <- pmax(t - t_acc, 0)
  dist_cruise <- v_max_safe * pmax(extra_t, 0)
  
  d <- dist_acc + dist_cruise
  d_fallback <- ifelse(is.na(a_max_safe) | is.na(v_max_safe),
                       pmax(v_max, 0) * t, d)
  d_fallback
}

