read_tracking_all <- function(dir_train, dir_score) {
  read_one <- function(path, source) {
    df <- readr::read_csv(path, show_col_types = FALSE) %>%
      janitor::clean_names()
    
    need_cols <- c("game_id","play_id","nfl_id","frame_id",
                   "x","y","s","dir","o",
                   "num_frames_output","ball_land_x","ball_land_y")
    for (nm in need_cols) {
      if (!nm %in% names(df)) df[[nm]] <- NA
    }
    
    df %>%
      mutate(
        game_id = as.character(game_id),
        play_id = as.integer(play_id),
        nfl_id  = as.integer(nfl_id),
        frame_id = as.integer(frame_id),
        s        = as.numeric(s),
        dir      = as.numeric(dir),
        o        = as.numeric(o),
        num_frames_output = as.integer(num_frames_output),
        ball_land_x       = as.numeric(ball_land_x),
        ball_land_y       = as.numeric(ball_land_y),
        source     = source,
        input_file = basename(path)
      )
  }
  
  train_files <- if (dir.exists(dir_train)) {
    list.files(dir_train, pattern = "^input_.*\\.csv$", full.names = TRUE)
  } else character(0)
  
  score_files <- if (dir.exists(dir_score)) {
    list.files(dir_score, pattern = "^test_.*\\.csv$", full.names = TRUE)
  } else character(0)
  
  cat(sprintf("[32] Found %d train input files, %d score test files\n",
              length(train_files), length(score_files)))
  
  train_df <- if (length(train_files)) {
    purrr::map_dfr(train_files, read_one, source = "train")
  } else tibble::tibble()
  
  score_df <- if (length(score_files)) {
    purrr::map_dfr(score_files, read_one, source = "score")
  } else tibble::tibble()
  
  bind_rows(train_df, score_df)
}

