# -------------------------------------------------------------------
# 7. Rollout engine
# -------------------------------------------------------------------

rollout_heading_2d <- function(state0,
                               heading_abs_deg,
                               v_max, a_max, yaw_rate_max,
                               latency_mu, latency_sd,
                               T_horizon, dt = 0.02) {
  x0   <- state0$x_def
  y0   <- state0$y_def
  v0   <- state0$s_def
  th0  <- state0$dir_def
  
  v_max <- as.numeric(v_max)
  a_max <- as.numeric(a_max)
  yaw_rate_max <- as.numeric(yaw_rate_max)
  latency_mu <- as.numeric(latency_mu)
  latency_sd <- as.numeric(latency_sd)
  
  if (!is.finite(v_max) || v_max <= 0) v_max <- 6.0
  if (!is.finite(a_max) || a_max <= 0) a_max <- 4.0
  if (!is.finite(yaw_rate_max) || yaw_rate_max <= 0) yaw_rate_max <- 360 # deg/s
  
  L <- max(latency_mu, 0)
  if (!is.finite(L)) L <- 0.2
  
  n_steps <- ceiling(T_horizon / dt)
  t_vec <- seq(0, by = dt, length.out = n_steps + 1L)
  
  x <- numeric(length(t_vec))
  y <- numeric(length(t_vec))
  v <- numeric(length(t_vec))
  th <- numeric(length(t_vec))
  
  x[1]  <- x0
  y[1]  <- y0
  v[1]  <- ifelse(is.finite(v0), v0, 0)
  th[1] <- ifelse(is.finite(th0), th0, heading_abs_deg)
  
  heading_target <- heading_abs_deg
  
  for (k in seq_len(n_steps)) {
    t_prev <- t_vec[k]
    t_cur  <- t_vec[k + 1L]
    
    th_prev <- th[k]
    v_prev  <- v[k]
    
    if (t_prev < L) {
      th_target_now <- th_prev
    } else {
      th_target_now <- heading_target
    }
    
    dtheta <- th_target_now - th_prev
    dtheta <- (dtheta + 180) %% 360 - 180
    
    max_dtheta <- yaw_rate_max * (t_cur - t_prev)  # deg/step
    if (!is.finite(max_dtheta) || max_dtheta <= 0) max_dtheta <- 360
    dtheta_clamped <- max(min(dtheta, max_dtheta), -max_dtheta)
    
    th_cur <- th_prev + dtheta_clamped
    
    v_cur <- v_prev + a_max * (t_cur - t_prev)
    if (is.finite(v_max)) v_cur <- pmin(v_cur, v_max)
    v_cur <- pmax(v_cur, 0)
    
    th_rad <- th_cur * pi / 180
    x_cur  <- x[k] + v_cur * cos(th_rad) * (t_cur - t_prev)
    y_cur  <- y[k] + v_cur * sin(th_rad) * (t_cur - t_prev)
    
    x[k + 1L]  <- x_cur
    y[k + 1L]  <- y_cur
    v[k + 1L]  <- v_cur
    th[k + 1L] <- th_cur
  }
  
  tibble(
    t  = t_vec,
    x  = x,
    y  = y,
    v  = v,
    th = th
  )
}

# -------------------------------------------------------------------
# 8. Feature reconstruction from rollout
# -------------------------------------------------------------------

build_features_from_rollout <- function(path_df,
                                        T_ball,
                                        target_x, target_y,
                                        base_row,
                                        lambda_reach) {
  T_ball <- as.numeric(T_ball)
  if (!is.finite(T_ball) || T_ball <= 0) return(NULL)
  
  target_x <- as.numeric(target_x)
  target_y <- as.numeric(target_y)
  if (!is.finite(target_x) || !is.finite(target_y)) return(NULL)
  
  df <- path_df %>%
    mutate(
      dist = sqrt((x - target_x)^2 + (y - target_y)^2)
    )
  
  df_ball <- df %>% filter(t <= T_ball + 1e-6)
  if (!nrow(df_ball)) return(NULL)
  
  sep_throw <- df$dist[1]
  d_min     <- suppressWarnings(min(df_ball$dist, na.rm = TRUE))
  idx_arr   <- which.min(abs(df_ball$t - T_ball))
  d_arrival <- df_ball$dist[idx_arr]
  
  p_reach_start <- exp(-lambda_reach * pmax(sep_throw, 0))
  p_reach_max   <- exp(-lambda_reach * pmax(d_min, 0))
  
  out <- base_row
  out$sep_throw     <- sep_throw
  out$d_min         <- d_min
  out$d_arrival     <- d_arrival
  out$p_reach_start <- p_reach_start
  out$p_reach_max   <- p_reach_max
  out$T_ball        <- T_ball
  
  out
}

