n_total <- nrow(base)
cat(sprintf("[32] Base rows for heading search: %d\n", n_total))

solve_for_row <- function(row) {
  # Avoid S3 dispatch issues seen in some environments by using base
  # subsetting instead of dplyr::slice() on a tibble list element.
  row <- row[1, , drop = FALSE]
  
  T_ball <- suppressWarnings(as.numeric(row$T_ball))
  if (!isTRUE(is.finite(T_ball) && T_ball > 0)) {
    return(tibble(
      theta_star_deg     = NA_real_,
      theta_star_abs_deg = NA_real_,
      delta_ev_hat       = NA_real_,
      theta_sd_deg       = NA_real_,
      backup_point_x     = NA_real_,
      backup_point_y     = NA_real_
    ))
  }
  
  if (any(is.na(c(row$x_def, row$y_def)))) {
    return(tibble(
      theta_star_deg     = NA_real_,
      theta_star_abs_deg = NA_real_,
      delta_ev_hat       = NA_real_,
      theta_sd_deg       = NA_real_,
      backup_point_x     = NA_real_,
      backup_point_y     = NA_real_
    ))
  }
  
  state0 <- list(
    x_def   = as.numeric(row$x_def),
    y_def   = as.numeric(row$y_def),
    s_def   = as.numeric(row$s_def),
    dir_def = as.numeric(row$dir_def)
  )
  
  # If dir_def is missing, point toward ball landing as fallback
  if (!is.finite(state0$dir_def)) {
    dx_t <- as.numeric(row$x_ball_land) - state0$x_def
    dy_t <- as.numeric(row$y_ball_land) - state0$y_def
    state0$dir_def <- atan2(dy_t, dx_t) * 180 / pi
  }
  
  v_max        <- suppressWarnings(as.numeric(row$v_max))
  a_max        <- suppressWarnings(as.numeric(row$a_max))
  yaw_rate_max <- suppressWarnings(as.numeric(row$yaw_rate_max))
  latency_mu   <- suppressWarnings(as.numeric(row$latency_mu))
  latency_sd   <- suppressWarnings(as.numeric(row$latency_sd))
  
  target_x <- as.numeric(row$x_ball_land)
  target_y <- as.numeric(row$y_ball_land)
  
  T_horiz <- min(T_ball, T_HORIZON_MAX)
  
  # ------------------------------------------------------------------
  # 1) Build a per-row heading cone from yaw_rate_max and T_ball
  # ------------------------------------------------------------------
  theta_max_phys <- if (isTRUE(is.finite(yaw_rate_max) && yaw_rate_max > 0)) {
    yaw_rate_max * T_ball * 180 / pi
  } else {
    THETA_GRID_MAX
  }
  
  theta_max <- min(THETA_GRID_MAX, theta_max_phys)
  
  if (!isTRUE(is.finite(theta_max)) || theta_max <= 0) {
    theta_offsets <- 0
  } else if (theta_max <= THETA_GRID_STEP) {
    theta_offsets <- sort(unique(c(-theta_max, 0, theta_max)))
  } else {
    theta_offsets <- seq(-theta_max, theta_max, by = THETA_GRID_STEP)
    if (!any(abs(theta_offsets) < 1e-6)) {
      theta_offsets <- sort(c(theta_offsets, 0))
    }
  }
  
  n_theta    <- length(theta_offsets)
  EV_offense <- rep(NA_real_, n_theta)
  
  # ------------------------------------------------------------------
  # 2) For each heading, roll out path and compute offensive EV
  # ------------------------------------------------------------------
  for (i in seq_along(theta_offsets)) {
    theta_abs <- state0$dir_def + theta_offsets[i]
    
    path <- rollout_heading_2d(
      state0          = state0,
      heading_abs_deg = theta_abs,
      v_max           = v_max,
      a_max           = a_max,
      yaw_rate_max    = yaw_rate_max,
      latency_mu      = latency_mu,
      latency_sd      = latency_sd,
      T_horizon       = T_horiz,
      dt              = 0.02
    )
    
    feat_row <- build_features_from_rollout(
      path_df      = path,
      T_ball       = T_ball,
      target_x     = target_x,
      target_y     = target_y,
      base_row     = row,
      lambda_reach = LAMBDA_REACH
    )
    
    if (is.null(feat_row)) {
      next
    }
    
    feat_sc <- set_flags(
      feat_row,
      contest  = 1L,
      leverage = 1L,
      backup   = 0L,
      hold     = 0L
    )
    
    EV_offense[i] <- predict_ev_throw(feat_sc, model_obj)[1]
  }
  
  # Align EV so θ offset 0 matches EV_chase (doesn't affect argmin)
  EV_vec   <- EV_offense
  EV_chase <- suppressWarnings(as.numeric(row$EV_chase))
  idx0     <- which(theta_offsets == 0)
  if (length(idx0) == 1 && is.finite(EV_vec[idx0]) && is.finite(EV_chase)) {
    EV_vec <- EV_vec + (EV_chase - EV_vec[idx0])
  }
  
  valid_idx <- which(is.finite(EV_vec))
  if (!length(valid_idx)) {
    return(tibble(
      theta_star_deg     = NA_real_,
      theta_star_abs_deg = NA_real_,
      delta_ev_hat       = NA_real_,
      theta_sd_deg       = NA_real_,
      backup_point_x     = NA_real_,
      backup_point_y     = NA_real_
    ))
  }
  
  # ------------------------------------------------------------------
  # 3) Add turning penalty: Score = EV_offense + λ_turn * penalty(|Δθ|)
  # ------------------------------------------------------------------
  max_off <- max(abs(theta_offsets[valid_idx]))
  if (!isTRUE(is.finite(max_off)) || max_off <= 0) {
    turn_penalty <- rep(0, length(theta_offsets))
  } else {
    turn_penalty <- (abs(theta_offsets) / max_off)^2
  }
  
  score_vec <- EV_vec + LAMBDA_TURN * turn_penalty
  
  best_idx      <- valid_idx[which.min(score_vec[valid_idx])]
  theta_star_off <- theta_offsets[best_idx]
  theta_star_abs <- state0$dir_def + theta_star_off
  ev_star        <- EV_vec[best_idx]
  
  # Pure offensive delta EV (good for DQS later)
  delta_ev_hat <- if (is.finite(ev_star) && is.finite(EV_chase)) ev_star - EV_chase else NA_real_
  
  # ------------------------------------------------------------------
  # 4) Rebuild path for chosen θ* to get backup point
  # ------------------------------------------------------------------
  path_best <- rollout_heading_2d(
    state0          = state0,
    heading_abs_deg = theta_star_abs,
    v_max           = v_max,
    a_max           = a_max,
    yaw_rate_max    = yaw_rate_max,
    latency_mu      = latency_mu,
    latency_sd      = latency_sd,
    T_horizon       = T_horiz,
    dt              = 0.02
  )
  
  if (is.null(path_best) || !nrow(path_best)) {
    backup_x <- NA_real_
    backup_y <- NA_real_
  } else {
    backup_x <- path_best$x[nrow(path_best)]
    backup_y <- path_best$y[nrow(path_best)]
  }
  
  # ------------------------------------------------------------------
  # 5) Monte Carlo over latency_mu to get θ* SD (using same score)
  # ------------------------------------------------------------------
  theta_star_samples <- numeric(N_THETA_MC)
  if (!isTRUE(is.finite(latency_sd)) || latency_sd <= 0) {
    theta_sd <- 0
  } else {
    for (k in seq_len(N_THETA_MC)) {
      EV_mc   <- rep(NA_real_, length(theta_offsets))
      lat_mu_k <- as.numeric(latency_mu) + rnorm(1L, mean = 0, sd = as.numeric(latency_sd))
      
      for (j in seq_along(theta_offsets)) {
        theta_abs_k <- state0$dir_def + theta_offsets[j]
        
        path_k <- rollout_heading_2d(
          state0          = state0,
          heading_abs_deg = theta_abs_k,
          v_max           = v_max,
          a_max           = a_max,
          yaw_rate_max    = yaw_rate_max,
          latency_mu      = lat_mu_k,
          latency_sd      = latency_sd,
          T_horizon       = T_horiz,
          dt              = 0.02
        )
        
        feat_row_k <- build_features_from_rollout(
          path_df      = path_k,
          T_ball       = T_ball,
          target_x     = target_x,
          target_y     = target_y,
          base_row     = row,
          lambda_reach = LAMBDA_REACH
        )
        
        if (is.null(feat_row_k)) {
          next
        }
        
        feat_sc_k <- set_flags(
          feat_row_k,
          contest  = 1L,
          leverage = 1L,
          backup   = 0L,
          hold     = 0L
        )
        
        EV_mc[j] <- predict_ev_throw(feat_sc_k, model_obj)[1]
      }
      
      valid_idx_mc <- which(is.finite(EV_mc))
      if (!length(valid_idx_mc)) {
        theta_star_samples[k] <- NA_real_
      } else {
        score_mc    <- EV_mc + LAMBDA_TURN * turn_penalty
        best_idx_mc <- valid_idx_mc[which.min(score_mc[valid_idx_mc])]
        theta_star_samples[k] <- theta_offsets[best_idx_mc]
      }
    }
    
    theta_star_samples <- theta_star_samples[is.finite(theta_star_samples)]
    theta_sd <- if (length(theta_star_samples) >= 2L) stats::sd(theta_star_samples) else 0
  }
  
  tibble(
    theta_star_deg     = theta_star_off,
    theta_star_abs_deg = theta_star_abs,
    delta_ev_hat       = delta_ev_hat,
    theta_sd_deg       = theta_sd,
    backup_point_x     = backup_x,
    backup_point_y     = backup_y
  )
}

if (file.exists(PATH$out_dirrec)) {
  
  # ------------------------------------------------------------
  # Fast path: reuse existing direction_recommendations_v3.csv
  # ------------------------------------------------------------
  cat("[32] Found existing direction_recommendations_v3 at ",
      PATH$out_dirrec,
      " – skipping θ* rollout and loading from disk.\n",
      sep = "")
  
  dirrec_df <- readr::read_csv(PATH$out_dirrec, show_col_types = FALSE) %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
  
} else {
  
  # ------------------------------------------------------------
  # Slow path: run full θ* rollout and write CSV
  # ------------------------------------------------------------
  cat("[32] Solving θ* via full rollout...\n")
  
  rows_list <- split(base, seq_len(nrow(base)))
  results_list <- purrr::map(
    seq_along(rows_list),
    function(i) {
      if (i %% 500 == 0) cat("[32] ...", i, "of", length(rows_list), "rows\n")
      solve_for_row(rows_list[[i]])
    }
  )
  
  dirrec_df <- base %>%
    bind_cols(bind_rows(results_list)) %>%
    select(
      game_id, play_id, nfl_id, split,
      zone,
      R, LOI, BV,
      any_of(c("EV_leverage","EV_chase","EV_backup")),
      theta_star_deg,
      theta_star_abs_deg,
      delta_ev_hat,
      theta_sd_deg,
      backup_point_x,
      backup_point_y
    )
  
  # Normalize absolute heading to [-180, 180] for readability
  dirrec_df <- dirrec_df %>%
    mutate(
      theta_star_abs_deg = if_else(
        is.finite(theta_star_abs_deg),
        ((theta_star_abs_deg + 180) %% 360) - 180,
        theta_star_abs_deg
      )
    )
  
  # Reliability gating
  if (is.finite(THETA_SD_MAX) && THETA_SD_MAX > 0) {
    dirrec_df <- dirrec_df %>%
      mutate(
        theta_star_deg = if_else(
          is.finite(theta_sd_deg) & theta_sd_deg > THETA_SD_MAX,
          NA_real_,
          theta_star_deg
        ),
        theta_star_abs_deg = if_else(
          is.finite(theta_sd_deg) & theta_sd_deg > THETA_SD_MAX,
          NA_real_,
          theta_star_abs_deg
        ),
        delta_ev_hat = if_else(
          is.na(theta_star_deg),
          NA_real_,
          delta_ev_hat
        )
      )
  }
  
  if (is.finite(MIN_IMPROVEMENT_EV) && MIN_IMPROVEMENT_EV > 0) {
    dirrec_df <- dirrec_df %>%
      mutate(
        theta_star_deg = if_else(
          is.finite(delta_ev_hat) & delta_ev_hat > -MIN_IMPROVEMENT_EV,
          NA_real_,
          theta_star_deg
        ),
        theta_star_abs_deg = if_else(
          is.finite(delta_ev_hat) & delta_ev_hat > -MIN_IMPROVEMENT_EV,
          NA_real_,
          theta_star_abs_deg
        ),
        delta_ev_hat = if_else(
          is.finite(delta_ev_hat) & delta_ev_hat > -MIN_IMPROVEMENT_EV,
          0.0,
          delta_ev_hat
        )
      )
  }
  
  readr::write_csv(dirrec_df, PATH$out_dirrec)
  cat("[32] Wrote direction_recommendations_v3 to ", PATH$out_dirrec, "\n", sep = "")
  
}

# -------------------------------------------------------------------
# 10. Overlays (sample up to 20 plays)
# -------------------------------------------------------------------

make_overlay <- function(row) {
  if (!is.finite(row$theta_star_deg)) return(NULL)
  obs <- tracking_with_win %>%
    filter(game_id == row$game_id, play_id == row$play_id, nfl_id == row$nfl_id) %>%
    arrange(frame_id)
  if (!nrow(obs)) return(NULL)
  
  state0 <- list(
    x_def  = obs$x[1],
    y_def  = obs$y[1],
    s_def  = obs$s[1],
    dir_def = obs$dir[1]
  )
  
  T_ball <- min(as.numeric(row$T_ball), T_HORIZON_MAX)
  theta_abs <- state0$dir_def + row$theta_star_deg
  
  path_rec <- rollout_heading_2d(
    state0,
    heading_abs_deg = theta_abs,
    v_max = row$v_max,
    a_max = row$a_max,
    yaw_rate_max = row$yaw_rate_max,
    latency_mu = row$latency_mu,
    latency_sd = row$latency_sd,
    T_horizon = T_ball,
    dt = 0.02
  ) %>%
    mutate(type = "theta_star")
  
  obs_plot <- obs %>%
    mutate(t = (frame_id - min(frame_id)) * DT,
           type = "observed") %>%
    select(t, x, y, type)
  
  ball_pt <- tibble(x = row$x_ball_land, y = row$y_ball_land)
  
  ggplot() +
    geom_path(data = obs_plot, aes(x = x, y = y, color = type), size = 1.1, alpha = 0.8) +
    geom_path(data = path_rec, aes(x = x, y = y, color = type), size = 1.1, alpha = 0.8) +
    geom_point(data = ball_pt, aes(x = x, y = y), color = "black", shape = 4, size = 3, stroke = 1.2) +
    coord_fixed() +
    scale_color_manual(values = c(observed = "steelblue", theta_star = "firebrick")) +
    labs(
      title = sprintf("%s-%s nfl_id %s: θ* = %.1f° (ΔEV %.3f)",
                      row$game_id, row$play_id, row$nfl_id,
                      row$theta_star_abs_deg, row$delta_ev_hat),
      x = "x", y = "y", color = "path"
    ) +
    theme_minimal()
}

overlay_inputs <- base %>%
  select(
    game_id, play_id, nfl_id,
    T_ball, v_max, a_max, yaw_rate_max,
    latency_mu, latency_sd,
    x_ball_land, y_ball_land
  )

dirrec_overlay <- dirrec_df %>%
  left_join(overlay_inputs, by = c("game_id","play_id","nfl_id"))

valid_overlay <- dirrec_overlay %>%
  mutate(idx = row_number()) %>%
  filter(is.finite(theta_star_deg)) %>%
  slice_head(n = 20)

if (nrow(valid_overlay)) {
  purrr::walk2(
    valid_overlay$idx,
    split(valid_overlay, valid_overlay$idx),
    ~{
      plt <- make_overlay(.y)
      if (!is.null(plt)) {
        outfile <- file.path(PATH$overlay_dir,
                             sprintf("overlay_%05d_%s_%s_%s.png",
                                     .x, .y$game_id, .y$play_id, .y$nfl_id))
        ggsave(outfile, plt, width = 6, height = 5, dpi = 200)
      }
    }
  )
  cat(sprintf("[32] Wrote %d overlay plots to %s\n", nrow(valid_overlay), PATH$overlay_dir))
} else {
  cat("[32] No finite θ* rows available for overlays\n")
}

# -------------------------------------------------------------------
# 11. Status / QA summary
# -------------------------------------------------------------------

n_finite_theta <- sum(is.finite(dirrec_df$theta_star_deg))
n_improve      <- sum(is.finite(dirrec_df$delta_ev_hat) & dirrec_df$delta_ev_hat < 0)
theta_sd_med   <- stats::median(dirrec_df$theta_sd_deg[is.finite(dirrec_df$theta_sd_deg)], na.rm = TRUE)

status_tbl <- tibble::tibble(
  script          = "32_direction_finder.R",
  n_rows          = nrow(dirrec_df),
  n_with_theta    = n_finite_theta,
  frac_with_theta = if (nrow(dirrec_df) > 0) n_finite_theta / nrow(dirrec_df) else NA_real_,
  n_improve       = n_improve,
  frac_improve    = if (n_finite_theta > 0) n_improve / n_finite_theta else NA_real_,
  theta_sd_median = theta_sd_med,
  theta_sd_gate   = THETA_SD_MAX,
  min_improve_ev  = MIN_IMPROVEMENT_EV
)

readr::write_csv(status_tbl, PATH$out_status_csv)

md_lines <- c(
  "# 32_direction_finder Status",
  "",
  "- Script: Code/32_direction_finder.R",
  paste0("- Rows in direction_recommendations_v3: ", nrow(dirrec_df)),
  paste0("- Rows with finite θ*: ", n_finite_theta),
  paste0(
    "- Fraction with finite θ*: ",
    sprintf("%.3f", if (nrow(dirrec_df) > 0) n_finite_theta / nrow(dirrec_df) else NA_real_)
  ),
  paste0("- Rows with ΔEV < 0 (improvement vs EV_chase): ", n_improve),
  paste0(
    "- Median θ* SD (deg): ",
    if (is.finite(theta_sd_med)) sprintf("%.2f", theta_sd_med) else "NA"
  ),
  paste0("- θ* SD gate (deg): ", THETA_SD_MAX),
  paste0("- Min EV improvement to emit θ*: ", MIN_IMPROVEMENT_EV)
)

writeLines(md_lines, PATH$out_status_md)

cat("[32] Finished 32_direction_finder.R\n")










# 32a_direction_finder_verification.R
# CLI: Rscript Code/32a_direction_finder_verification.R
#
# Verifies that 32_direction_finder.R outputs are sane:
#   - θ* only when EV improvement >= gate
#   - θ* variance below gate
#   - angles in a reasonable range
# Writes:
#   - artifacts/32a_direction_finder_verification_status.csv
#   - artifacts/32a_direction_finder_verification_status.md
#   - artifacts/direction_recommendations_v3_verification.csv

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
}))

cat("[32a] Starting 32a_direction_finder_verification.R\n")

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  dirrec          = file.path(DIR$artifacts, "direction_recommendations_v3.csv"),
  status32        = file.path(DIR$artifacts, "32_direction_finder_status.csv"),
  out_status_csv  = file.path(DIR$artifacts, "32a_direction_finder_verification_status.csv"),
  out_status_md   = file.path(DIR$artifacts, "32a_direction_finder_verification_status.md"),
  out_summary_csv = file.path(DIR$artifacts, "direction_recommendations_v3_verification.csv")
)

for (nm in c("dirrec", "status32")) {
  p <- PATH[[nm]]
  if (!file.exists(p)) stop("[32a] Missing required artifact: ", p)
}

dirrec <- readr::read_csv(PATH$dirrec, show_col_types = FALSE) %>%
  clean_names()

status32 <- readr::read_csv(PATH$status32, show_col_types = FALSE)

theta_sd_gate <- suppressWarnings(as.numeric(status32$theta_sd_gate[1]))
if (!is.finite(theta_sd_gate)) theta_sd_gate <- 15

min_improve_ev <- suppressWarnings(as.numeric(status32$min_improve_ev[1]))
if (!is.finite(min_improve_ev)) min_improve_ev <- 0

cat(sprintf("[32a] Using theta_sd_gate = %.2f deg, min_improve_ev = %.3f\n",
            theta_sd_gate, min_improve_ev))

expected_cols <- c(
  "game_id","play_id","nfl_id",
  "split","zone",
  "r","loi","bv",
  "ev_leverage","ev_chase","ev_backup",
  "theta_star_deg","theta_star_abs_deg",
  "delta_ev_hat","theta_sd_deg",
  "backup_point_x","backup_point_y"
)

missing <- setdiff(expected_cols, names(dirrec))
if (length(missing)) {
  warning("[32a] direction_recommendations_v3 is missing columns: ",
          paste(missing, collapse = ", "))
}

dirrec_chk <- dirrec %>%
  mutate(
    has_theta  = is.finite(theta_star_deg),
    angle_ok   = !has_theta | (abs(theta_star_deg) <= 90),
    sd_ok      = !has_theta | (is.finite(theta_sd_deg) &
                                 theta_sd_deg <= theta_sd_gate),
    improve_ok = !has_theta | (is.finite(delta_ev_hat) &
                                 delta_ev_hat <= -min_improve_ev)
  )

any_angle_violation   <- any(!dirrec_chk$angle_ok,   na.rm = TRUE)
any_sd_violation      <- any(!dirrec_chk$sd_ok,      na.rm = TRUE)
any_improve_violation <- any(!dirrec_chk$improve_ok, na.rm = TRUE)

n_rows          <- nrow(dirrec_chk)
n_with_theta    <- sum(dirrec_chk$has_theta)
frac_with_theta <- if (n_rows > 0) n_with_theta / n_rows else NA_real_

theta_sd_median <- dirrec_chk %>%
  filter(has_theta) %>%
  summarise(med = median(theta_sd_deg, na.rm = TRUE)) %>%
  pull(med)

status_out <- tibble(
  script                = "32a_direction_finder_verification.R",
  n_rows                = n_rows,
  n_with_theta          = n_with_theta,
  frac_with_theta       = frac_with_theta,
  theta_sd_gate         = theta_sd_gate,
  theta_sd_median       = theta_sd_median,
  min_improve_ev        = min_improve_ev,
  any_angle_violation   = any_angle_violation,
  any_sd_violation      = any_sd_violation,
  any_improve_violation = any_improve_violation,
  pass                  = !(any_angle_violation |
                              any_sd_violation  |
                              any_improve_violation)
)

cat(sprintf("[32a] Rows: %d, with θ*: %d (%.1f%%)\n",
            n_rows, n_with_theta, 100 * frac_with_theta))

readr::write_csv(status_out, PATH$out_status_csv)

# Console verdict
if (isTRUE(status_out$pass[1])) {
  cat("[32a] VERDICT: PASS ✅\n")
} else {
  cat("[32a] VERDICT: FAIL ❌\n")
}

# Summary by zone for quick inspection
summary_by_zone <- dirrec_chk %>%
  group_by(zone) %>%
  summarise(
    n_rows      = n(),
    n_theta     = sum(has_theta),
    frac_theta  = mean(has_theta),
    mean_theta  = ifelse(sum(has_theta) > 0,
                         mean(theta_star_deg[has_theta], na.rm = TRUE),
                         NA_real_),
    mean_abs_theta = ifelse(sum(has_theta) > 0,
                            mean(abs(theta_star_deg[has_theta]),
                                 na.rm = TRUE),
                            NA_real_),
    mean_delta_ev = ifelse(sum(has_theta) > 0,
                           mean(delta_ev_hat[has_theta], na.rm = TRUE),
                           NA_real_),
    median_delta_ev = ifelse(sum(has_theta) > 0,
                             median(delta_ev_hat[has_theta], na.rm = TRUE),
                             NA_real_),
    max_theta_sd = ifelse(sum(has_theta) > 0,
                          max(theta_sd_deg[has_theta], na.rm = TRUE),
                          NA_real_),
    .groups = "drop"
  )

readr::write_csv(summary_by_zone, PATH$out_summary_csv)

# Simple markdown report
md_lines <- c(
  "# 32a_direction_finder_verification",
  "",
  sprintf("- Total rows: %d", n_rows),
  sprintf("- Rows with θ*: %d (%.1f%%)", n_with_theta, 100 * frac_with_theta),
  sprintf("- θ* SD gate: %.2f deg", theta_sd_gate),
  sprintf("- Median θ* SD (emitted): %.2f deg", theta_sd_median),
  sprintf("- Min improvement EV (gate): %.3f", min_improve_ev),
  sprintf("- Any angle violation: %s", any_angle_violation),
  sprintf("- Any SD violation: %s", any_sd_violation),
  sprintf("- Any improvement violation: %s", any_improve_violation),
  sprintf("- PASS: %s", status_out$pass),
  "",
  "## Summary by zone",
  ""
)

for (i in seq_len(nrow(summary_by_zone))) {
  z <- summary_by_zone[i, ]
  md_lines <- c(
    md_lines,
    sprintf("### Zone: %s", z$zone),
    sprintf("- Rows: %d", z$n_rows),
    sprintf("- Rows with θ*: %d (%.1f%%)", z$n_theta, 100 * z$frac_theta),
    sprintf("- Mean θ*: %.2f deg", z$mean_theta),
    sprintf("- Mean |θ*|: %.2f deg", z$mean_abs_theta),
    sprintf("- Mean ΔEV(θ* − chase): %.3f", z$mean_delta_ev),
    sprintf("- Median ΔEV(θ* − chase): %.3f", z$median_delta_ev),
    sprintf("- Max θ* SD: %.2f deg", z$max_theta_sd),
    ""
  )
}

writeLines(md_lines, con = PATH$out_status_md)

cat("[32a] Finished 32a_direction_finder_verification.R\n")










# 33_coordination_search.R
# CLI: Rscript Code/33_coordination_search.R
#
# Team-layer coordination search (Phase-3, optional but recommended).
#   - Build per-defender action bundles (independent vs θ*).
#   - Beam search over top-N defenders' bundles per play.
#   - Enforce simple overlap + edge-contain constraints.
#   - Compare team EV (independent vs coordinated).
#
# Inputs:
#   artifacts/direction_recommendations_v3.csv
#   artifacts/affordances_v3.csv
#   artifacts/eligibility_v3.csv
#
# Outputs:
#   artifacts/coordination_set_v3.csv
#   artifacts/overlay_independent_vs_coordinated/*.png
#   artifacts/33_coordination_search_status.{csv,md}

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(purrr)
  library(janitor)
  library(ggplot2)
}))

cat("[33] Starting 33_coordination_search.R\n")

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  dirrec        = file.path(DIR$artifacts, "direction_recommendations_v3.csv"),
  aff           = file.path(DIR$artifacts, "affordances_v3.csv"),
  elig          = file.path(DIR$artifacts, "eligibility_v3.csv"),
  out_coord     = file.path(DIR$artifacts, "coordination_set_v3.csv"),
  out_status_csv = file.path(DIR$artifacts, "33_coordination_search_status.csv"),
  out_status_md  = file.path(DIR$artifacts, "33_coordination_search_status.md"),
  overlay_dir    = file.path(DIR$artifacts, "overlay_independent_vs_coordinated")
)

dir.create(PATH$overlay_dir, recursive = TRUE, showWarnings = FALSE)

for (nm in c("dirrec", "aff", "elig")) {
  p <- PATH[[nm]]
  if (!file.exists(p)) stop("[33] Missing required artifact: ", p)
}

# Tunable knobs
N_TOP_DEF       <- 4L    # top-N defenders per play to coordinate
BEAM_WIDTH      <- 8L    # beam width
N_BEST_RESPONSE <- 1L    # best-response refinement rounds (0,1,2)
OVERLAP_RADIUS  <- 2.0   # yards; min separation between θ* backup points
MIN_TEAM_GAIN   <- 0.0   # require coordinated EV <= independent - MIN_TEAM_GAIN

cat(sprintf("[33] N_TOP_DEF = %d, BEAM_WIDTH = %d, N_BEST_RESPONSE = %d\n",
            N_TOP_DEF, BEAM_WIDTH, N_BEST_RESPONSE))

# -------------------------------------------------------------------
# 1. Load inputs and build base table
# -------------------------------------------------------------------

dirrec <- readr::read_csv(PATH$dirrec, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

base <- dirrec %>%
  select(
    game_id, play_id, nfl_id, split, zone,
    r, loi, bv,
    ev_leverage, ev_chase, ev_backup,
    theta_star_deg, delta_ev_hat, theta_sd_deg,
    backup_point_x, backup_point_y
  ) %>%
  left_join(
    elig %>%
      select(game_id, play_id, nfl_id, split,
             d_start, t_ball, t_reach, p_reach,
             contest_eligible, leverage_eligible,
             backup_eligible, hold),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  # in case of duplicates or mismatches, clean early
  distinct()

if (!nrow(base)) stop("[33] No rows after join; check inputs.")

# Define independent and θ* EVs
base <- base %>%
  mutate(
    has_theta = is.finite(theta_star_deg) & is.finite(delta_ev_hat),
    ev_chase  = ev_chase,
    ev_theta  = if_else(has_theta,
                        ev_chase + delta_ev_hat,
                        NA_real_),
    # independent best: whichever is lower EV (better for defense)
    ev_indep = case_when(
      has_theta & is.finite(ev_theta) & (ev_theta < ev_chase) ~ ev_theta,
      TRUE ~ ev_chase
    ),
    independent_action = case_when(
      has_theta & is.finite(ev_theta) & (ev_theta < ev_chase) ~ "theta_star",
      TRUE ~ "chase"
    ),
    # simple "edge contain" heuristic: deep + hold
    edge_contain = hold & zone == "backed_up" & d_start > 7
  )

cat(sprintf("[33] Loaded %d defender-plays (%d with θ*)\n",
            nrow(base), sum(base$has_theta)))

# -------------------------------------------------------------------
# 2. Per-play coordination via beam search
# -------------------------------------------------------------------

# Helper: compute pairwise min distance among θ* backup points
min_pairwise_dist <- function(x, y) {
  n <- length(x)
  if (n < 2) return(NA_real_)
  dmat <- as.matrix(dist(cbind(x, y)))
  dmat[upper.tri(dmat, diag = TRUE)] <- NA
  min(dmat, na.rm = TRUE)
}

# Core per-play solver
solve_play <- function(df_play) {
  df <- df_play %>%
    arrange(nfl_id) %>%
    mutate(
      gain_theta = if_else(
        has_theta & is.finite(ev_theta),
        pmax(0, ev_chase - ev_theta),
        0
      )
    )
  
  ev_team_indep <- sum(df$ev_indep, na.rm = TRUE)
  
  # Defenders we are allowed to touch: have θ* gain and not edge_contain
  pool <- df %>%
    filter(gain_theta > 0,
           !edge_contain) %>%
    arrange(desc(gain_theta)) %>%
    slice_head(n = N_TOP_DEF)
  
  if (nrow(pool) == 0) {
    # No useful coordination; stay at independent policy
    return(df %>%
             mutate(
               coord_action   = independent_action,
               ev_coord       = ev_indep,
               changed        = FALSE,
               ev_team_indep  = ev_team_indep,
               ev_team_coord  = ev_team_indep,
               bundle_id      = 0L
             ))
  }
  
  pool_ids <- pool$nfl_id
  indep_map <- df %>%
    select(nfl_id, ev_indep) %>%
    deframe()
  
  # Build per-defender option tables
  option_list <- map(seq_len(nrow(pool)), function(i) {
    row <- pool[i, ]
    tibble(
      nfl_id   = row$nfl_id,
      action   = c("indep", "theta_star"),
      ev       = c(row$ev_indep, row$ev_theta),
      is_theta = c(FALSE, TRUE),
      backup_x = c(NA_real_, row$backup_point_x),
      backup_y = c(NA_real_, row$backup_point_y)
    ) %>%
      filter(is.finite(ev)) # drop theta option if NA
  })
  names(option_list) <- as.character(pool_ids)
  
  # Initial beam: empty assignment with independent team EV
  beam <- list(
    list(
      assignments = tibble(
        nfl_id   = integer(),
        action   = character(),
        ev       = numeric(),
        is_theta = logical(),
        backup_x = numeric(),
        backup_y = numeric()
      ),
      team_ev = ev_team_indep
    )
  )
  
  # Beam search over pool defenders
  for (id in pool_ids) {
    opts <- option_list[[as.character(id)]]
    new_beam <- list()
    for (b in beam) {
      for (j in seq_len(nrow(opts))) {
        o <- opts[j, ]
        
        # Enforce overlap constraint only for θ* actions
        valid <- TRUE
        if (o$is_theta) {
          if (!is.finite(o$backup_x) || !is.finite(o$backup_y)) {
            valid <- FALSE
          } else {
            prev_theta <- b$assignments %>%
              filter(is_theta, is.finite(backup_x), is.finite(backup_y))
            if (nrow(prev_theta) > 0) {
              dx <- prev_theta$backup_x - o$backup_x
              dy <- prev_theta$backup_y - o$backup_y
              dmin <- min(sqrt(dx^2 + dy^2), na.rm = TRUE)
              if (is.finite(dmin) && dmin < OVERLAP_RADIUS) {
                valid <- FALSE
              }
            }
          }
        }
        
        if (!valid) next
        
        ass_new <- bind_rows(b$assignments, o)
        delta   <- o$ev - indep_map[as.character(o$nfl_id)]
        team_ev_new <- b$team_ev + delta
        
        new_beam[[length(new_beam) + 1L]] <- list(
          assignments = ass_new,
          team_ev     = team_ev_new
        )
      }
    }
    
    if (length(new_beam) == 0) {
      # If all branches died due to constraints, keep old beam (no change)
      next
    }
    
    # Keep best BEAM_WIDTH partial bundles
    scores <- map_dbl(new_beam, "team_ev")
    keep   <- order(scores)[seq_len(min(BEAM_WIDTH, length(scores)))]
    beam   <- new_beam[keep]
  }
  
  # Choose best bundle
  scores <- map_dbl(beam, "team_ev")
  best_idx <- which.min(scores)
  best <- beam[[best_idx]]
  
  # Turn assignments into a tibble keyed by nfl_id
  assign_df <- best$assignments %>%
    select(nfl_id, coord_action = action, ev_coord = ev)
  
  # Apply to full defender set
  df_out <- df %>%
    left_join(assign_df, by = "nfl_id") %>%
    mutate(
      coord_action = if_else(
        is.na(coord_action),
        independent_action,
        coord_action
      ),
      ev_coord = if_else(
        is.na(ev_coord),
        ev_indep,
        ev_coord
      ),
      changed = coord_action != independent_action
    )
  
  ev_team_coord <- sum(df_out$ev_coord, na.rm = TRUE)
  
  df_out <- df_out %>%
    mutate(
      ev_team_indep = ev_team_indep,
      ev_team_coord = ev_team_coord,
      bundle_id     = 1L
    )
  
  # Best-response refinement (optional)
  if (N_BEST_RESPONSE > 0) {
    for (r in seq_len(N_BEST_RESPONSE)) {
      for (id in pool_ids) {
        # Current action for this defender
        idx <- which(df_out$nfl_id == id)
        if (!length(idx)) next
        
        current_action <- df_out$coord_action[idx]
        # Two candidates: indep vs theta_star (if available)
        row_pool <- pool %>% filter(nfl_id == id)
        if (!nrow(row_pool)) next
        
        cand_actions <- c("indep", "theta_star")
        cand_evs <- c(row_pool$ev_indep, row_pool$ev_theta)
        cand_back_x <- c(NA_real_, row_pool$backup_point_x)
        cand_back_y <- c(NA_real_, row_pool$backup_point_y)
        
        for (k in seq_along(cand_actions)) {
          a  <- cand_actions[k]
          ev <- cand_evs[k]
          bx <- cand_back_x[k]
          by <- cand_back_y[k]
          
          if (!is.finite(ev)) next
          if (a == current_action) next
          
          # Build hypothetical plan with this defender switched
          df_tmp <- df_out
          df_tmp$coord_action[idx] <- a
          df_tmp$ev_coord[idx]     <- ev
          
          # Overlap constraint on θ* backup points
          theta_pts <- df_tmp %>%
            filter(coord_action == "theta_star",
                   is.finite(backup_point_x),
                   is.finite(backup_point_y))
          ok_overlap <- TRUE
          if (nrow(theta_pts) > 1) {
            dmin <- min_pairwise_dist(theta_pts$backup_point_x,
                                      theta_pts$backup_point_y)
            if (is.finite(dmin) && dmin < OVERLAP_RADIUS) {
              ok_overlap <- FALSE
            }
          }
          
          if (!ok_overlap) next
          
          ev_team_tmp <- sum(df_tmp$ev_coord, na.rm = TRUE)
          if (ev_team_tmp < ev_team_coord) {
            # Accept the improvement
            df_out       <- df_tmp
            ev_team_coord <- ev_team_tmp
          }
        }
      } # end defender loop
    }   # end rounds
    df_out$ev_team_coord <- ev_team_coord
  }
  
  df_out
}

coord <- base %>%
  group_by(game_id, play_id) %>%
  group_modify(~ solve_play(.x)) %>%
  ungroup()

readr::write_csv(coord, PATH$out_coord)
cat(sprintf("[33] Wrote coordination_set_v3 to %s (%d rows)\n",
            PATH$out_coord, nrow(coord)))

# -------------------------------------------------------------------
# 3. Constraint checks and status
# -------------------------------------------------------------------

# Overlap violations after coordination
theta_final <- coord %>%
  filter(coord_action == "theta_star",
         is.finite(backup_point_x),
         is.finite(backup_point_y))

overlap_by_play <- theta_final %>%
  group_by(game_id, play_id) %>%
  summarise(
    min_pair_dist = min_pairwise_dist(backup_point_x, backup_point_y),
    .groups = "drop"
  )

n_overlap_viol <- overlap_by_play %>%
  filter(!is.na(min_pair_dist), min_pair_dist < OVERLAP_RADIUS) %>%
  nrow()

# Edge contain preserved?
edge_viol <- coord %>%
  filter(edge_contain, changed) %>%
  nrow()

# Team-level improvement summary
team_summary <- coord %>%
  group_by(game_id, play_id) %>%
  summarise(
    split          = first(split),
    ev_team_indep  = first(ev_team_indep),
    ev_team_coord  = first(ev_team_coord),
    team_gain      = ev_team_indep - ev_team_coord,
    any_changed    = any(changed),
    .groups = "drop"
  )

mean_team_gain <- mean(team_summary$team_gain, na.rm = TRUE)
median_team_gain <- median(team_summary$team_gain, na.rm = TRUE)
frac_plays_changed <- mean(team_summary$any_changed, na.rm = TRUE)

status <- tibble(
  script               = "33_coordination_search.R",
  n_rows               = nrow(coord),
  n_plays              = nrow(team_summary),
  n_plays_with_change  = sum(team_summary$any_changed),
  frac_plays_with_change = frac_plays_changed,
  mean_team_gain       = mean_team_gain,
  median_team_gain     = median_team_gain,
  n_overlap_violations = n_overlap_viol,
  n_edge_violations    = edge_viol,
  overlap_radius       = OVERLAP_RADIUS,
  N_TOP_DEF            = N_TOP_DEF,
  BEAM_WIDTH           = BEAM_WIDTH,
  N_BEST_RESPONSE      = N_BEST_RESPONSE,
  min_team_gain_gate   = MIN_TEAM_GAIN,
  pass = (n_overlap_viol == 0 &&
            edge_viol == 0 &&
            mean_team_gain >= MIN_TEAM_GAIN)
)

readr::write_csv(status, PATH$out_status_csv)

cat(sprintf("[33] Overlap violations: %d; edge violations: %d; mean team gain: %.3f\n",
            n_overlap_viol, edge_viol, mean_team_gain))

# -------------------------------------------------------------------
# 4. Simple angle overlays (independent vs coordinated)
# -------------------------------------------------------------------

# Pick a few plays with non-trivial change
overlay_plays <- team_summary %>%
  filter(any_changed, team_gain > 0.01) %>%
  slice_head(n = 12)

if (nrow(overlay_plays) > 0) {
  for (i in seq_len(nrow(overlay_plays))) {
    row <- overlay_plays[i, ]
    gid <- row$game_id
    pid <- row$play_id
    
    df_p <- coord %>%
      filter(game_id == gid, play_id == pid) %>%
      arrange(nfl_id) %>%
      mutate(
        defender_idx = row_number(),
        theta_indep = if_else(
          independent_action == "theta_star",
          theta_star_deg,
          0
        ),
        theta_coord = if_else(
          coord_action == "theta_star",
          theta_star_deg,
          0
        )
      )
    
    p <- ggplot(df_p, aes(x = defender_idx)) +
      geom_hline(yintercept = 0, linetype = "dashed") +
      geom_point(aes(y = theta_indep), shape = 16) +
      geom_point(aes(y = theta_coord), shape = 1) +
      labs(
        title = sprintf("Independent vs coordinated headings (game %s, play %d)", gid, pid),
        subtitle = "Solid = independent; open = coordinated; y = θ offset (deg vs chase)",
        x = "Defender (sorted by nfl_id)",
        y = "Heading offset (deg)"
      ) +
      theme_minimal()
    
    out_file <- file.path(
      PATH$overlay_dir,
      sprintf("coord_%s_%d.png", gid, pid)
    )
    
    ggsave(out_file, plot = p, width = 6, height = 4, dpi = 150)
  }
  
  cat(sprintf("[33] Wrote %d overlays to %s\n",
              nrow(overlay_plays), PATH$overlay_dir))
} else {
  cat("[33] No plays with meaningful coordinated gain for overlays\n")
}

# -------------------------------------------------------------------
# 5. Markdown status
# -------------------------------------------------------------------

md_lines <- c(
  "# 33_coordination_search",
  "",
  sprintf("- Plays: %d", status$n_plays),
  sprintf("- Defender-rows: %d", status$n_rows),
  sprintf("- Plays with any coordinated change: %d (%.1f%%)",
          status$n_plays_with_change,
          100 * status$frac_plays_with_change),
  sprintf("- Mean team gain (EV_indep − EV_coord): %.3f", status$mean_team_gain),
  sprintf("- Median team gain: %.3f", status$median_team_gain),
  sprintf("- Overlap radius (yards): %.1f", status$overlap_radius),
  sprintf("- Overlap violations: %d", status$n_overlap_violations),
  sprintf("- Edge-contain violations: %d", status$n_edge_violations),
  sprintf("- PASS: %s", status$pass),
  "",
  sprintf("- N_TOP_DEF: %d", status$N_TOP_DEF),
  sprintf("- BEAM_WIDTH: %d", status$BEAM_WIDTH),
  sprintf("- N_BEST_RESPONSE: %d", status$N_BEST_RESPONSE),
  sprintf("- Min team gain gate: %.3f", status$min_team_gain_gate)
)

writeLines(md_lines, con = PATH$out_status_md)

cat("[33] Finished 33_coordination_search.R\n")










# 33a_coordination_verification.R
# CLI: Rscript Code/33a_coordination_verification.R
#
# Verifies outputs of 33_coordination_search.R:
#   - Recompute team EV (indep & coord) from defender rows
#   - Check overlap & edge-contain constraints
#   - Compare to 33 status file
# Outputs:
#   - artifacts/33a_coordination_verification_status.csv
#   - artifacts/33a_coordination_verification_status.md
#   - artifacts/coordination_set_v3_verification.csv

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
}))

cat("[33a] Starting 33a_coordination_verification.R\n")

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  coord          = file.path(DIR$artifacts, "coordination_set_v3.csv"),
  status33       = file.path(DIR$artifacts, "33_coordination_search_status.csv"),
  out_status_csv = file.path(DIR$artifacts, "33a_coordination_verification_status.csv"),
  out_status_md  = file.path(DIR$artifacts, "33a_coordination_verification_status.md"),
  out_summary    = file.path(DIR$artifacts, "coordination_set_v3_verification.csv")
)

for (nm in c("coord", "status33")) {
  p <- PATH[[nm]]
  if (!file.exists(p)) stop("[33a] Missing required artifact: ", p)
}

coord <- readr::read_csv(PATH$coord, show_col_types = FALSE) %>%
  clean_names()

status33 <- readr::read_csv(PATH$status33, show_col_types = FALSE)

# Tolerance knobs
EV_TOL      <- 1e-6
MEAN_TOL    <- 1e-6
DIST_TOL    <- 1e-6

overlap_radius <- suppressWarnings(as.numeric(status33$overlap_radius[1]))
if (!is.finite(overlap_radius)) overlap_radius <- 2.0

cat(sprintf("[33a] Using overlap_radius = %.3f\n", overlap_radius))

# Helper: pairwise min distance
min_pairwise_dist <- function(x, y) {
  n <- length(x)
  if (n < 2) return(NA_real_)
  dmat <- as.matrix(dist(cbind(x, y)))
  dmat[upper.tri(dmat, diag = TRUE)] <- NA
  min(dmat, na.rm = TRUE)
}

# -------------------------------------------------------------------
# 1. Per-play recomputation of team EV and constraints
# -------------------------------------------------------------------

per_play <- coord %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id)
  ) %>%
  group_by(game_id, play_id) %>%
  group_modify(~ {
    df <- .x
    
    # Recompute team EV from defender rows
    ev_team_indep_calc <- sum(df$ev_indep, na.rm = TRUE)
    ev_team_coord_calc <- sum(df$ev_coord, na.rm = TRUE)
    
    ev_team_indep_col <- df$ev_team_indep[1]
    ev_team_coord_col <- df$ev_team_coord[1]
    
    diff_indep <- ev_team_indep_col - ev_team_indep_calc
    diff_coord <- ev_team_coord_col - ev_team_coord_calc
    
    # Overlap check on coordinated θ*
    theta_pts <- df %>%
      filter(coord_action == "theta_star",
             is.finite(backup_point_x),
             is.finite(backup_point_y))
    
    min_pair_dist <- if (nrow(theta_pts) > 1) {
      min_pairwise_dist(theta_pts$backup_point_x, theta_pts$backup_point_y)
    } else {
      NA_real_
    }
    
    overlap_violation <- !is.na(min_pair_dist) &&
      is.finite(min_pair_dist) &&
      (min_pair_dist + DIST_TOL < overlap_radius)
    
    # Edge-contain check
    edge_violations <- df %>%
      filter(edge_contain, coord_action != independent_action) %>%
      nrow()
    
    team_gain_calc <- ev_team_indep_calc - ev_team_coord_calc
    
    tibble(
      split              = df$split[1],
      ev_team_indep_calc = ev_team_indep_calc,
      ev_team_coord_calc = ev_team_coord_calc,
      ev_team_indep_col  = ev_team_indep_col,
      ev_team_coord_col  = ev_team_coord_col,
      diff_indep         = diff_indep,
      diff_coord         = diff_coord,
      any_changed        = any(df$changed),
      n_changed          = sum(df$changed),
      n_theta_indep      = sum(df$independent_action == "theta_star", na.rm = TRUE),
      n_theta_coord      = sum(df$coord_action == "theta_star", na.rm = TRUE),
      min_pair_dist      = min_pair_dist,
      overlap_violation  = overlap_violation,
      edge_violations    = edge_violations,
      team_gain_calc     = team_gain_calc
    )
  }) %>%
  ungroup()

readr::write_csv(per_play, PATH$out_summary)

# -------------------------------------------------------------------
# 2. Aggregate metrics and consistency checks
# -------------------------------------------------------------------

n_plays <- nrow(per_play)

max_abs_diff_indep <- max(abs(per_play$diff_indep), na.rm = TRUE)
max_abs_diff_coord <- max(abs(per_play$diff_coord), na.rm = TRUE)

n_overlap_viol_recalc <- sum(per_play$overlap_violation, na.rm = TRUE)
n_edge_viol_recalc    <- sum(per_play$edge_violations > 0, na.rm = TRUE)

mean_team_gain_calc   <- mean(per_play$team_gain_calc, na.rm = TRUE)
median_team_gain_calc <- median(per_play$team_gain_calc, na.rm = TRUE)
frac_plays_changed    <- mean(per_play$any_changed, na.rm = TRUE)

# Compare with 33 status
mean_team_gain_status <- suppressWarnings(as.numeric(status33$mean_team_gain[1]))
median_team_gain_status <- suppressWarnings(as.numeric(status33$median_team_gain[1]))
n_overlap_status     <- suppressWarnings(as.numeric(status33$n_overlap_violations[1]))
n_edge_status        <- suppressWarnings(as.numeric(status33$n_edge_violations[1]))
n_plays_status       <- suppressWarnings(as.numeric(status33$n_plays[1]))

mean_match   <- isTRUE(is.finite(mean_team_gain_status)) &&
  abs(mean_team_gain_calc - mean_team_gain_status) <= MEAN_TOL

median_match <- isTRUE(is.finite(median_team_gain_status)) &&
  abs(median_team_gain_calc - median_team_gain_status) <= MEAN_TOL

plays_match  <- isTRUE(is.finite(n_plays_status)) &&
  (n_plays_status == n_plays)

overlap_match <- (n_overlap_status == n_overlap_viol_recalc)
edge_match    <- (n_edge_status == n_edge_viol_recalc)

ev_indep_ok <- max_abs_diff_indep <= EV_TOL
ev_coord_ok <- max_abs_diff_coord <= EV_TOL

pass <- (ev_indep_ok &&
           ev_coord_ok &&
           overlap_match &&
           edge_match &&
           plays_match &&
           mean_match &&
           median_match)

status_out <- tibble(
  script                  = "33a_coordination_verification.R",
  n_rows_coord            = nrow(coord),
  n_plays                 = n_plays,
  n_plays_changed         = sum(per_play$any_changed),
  frac_plays_changed      = frac_plays_changed,
  max_abs_diff_indep      = max_abs_diff_indep,
  max_abs_diff_coord      = max_abs_diff_coord,
  mean_team_gain_calc     = mean_team_gain_calc,
  median_team_gain_calc   = median_team_gain_calc,
  mean_team_gain_status   = mean_team_gain_status,
  median_team_gain_status = median_team_gain_status,
  n_overlap_viol_recalc   = n_overlap_viol_recalc,
  n_edge_viol_recalc      = n_edge_viol_recalc,
  n_overlap_status        = n_overlap_status,
  n_edge_status           = n_edge_status,
  overlap_radius          = overlap_radius,
  ev_indep_ok             = ev_indep_ok,
  ev_coord_ok             = ev_coord_ok,
  mean_match              = mean_match,
  median_match            = median_match,
  plays_match             = plays_match,
  overlap_match           = overlap_match,
  edge_match              = edge_match,
  pass                    = pass
)

readr::write_csv(status_out, PATH$out_status_csv)

# Console verdict
if (isTRUE(status_out$pass[1])) {
  cat("[33a] VERDICT: PASS ✅\n")
} else {
  cat("[33a] VERDICT: FAIL ❌\n")
}

# -------------------------------------------------------------------
# 3. Markdown report
# -------------------------------------------------------------------

md_lines <- c(
  "# 33a_coordination_verification",
  "",
  sprintf("- Defender rows (coordination_set_v3): %d", nrow(coord)),
  sprintf("- Plays: %d", n_plays),
  sprintf("- Plays with any change: %d (%.1f%%)",
          sum(per_play$any_changed), 100 * frac_plays_changed),
  "",
  "## EV consistency",
  sprintf("- Max |ev_team_indep_col − sum(ev_indep)|: %.3e", max_abs_diff_indep),
  sprintf("- Max |ev_team_coord_col − sum(ev_coord)|: %.3e", max_abs_diff_coord),
  sprintf("- ev_indep_ok (within tol): %s", ev_indep_ok),
  sprintf("- ev_coord_ok (within tol): %s", ev_coord_ok),
  "",
  "## Team gain consistency",
  sprintf("- mean_team_gain_calc: %.6f", mean_team_gain_calc),
  sprintf("- mean_team_gain_status: %.6f", mean_team_gain_status),
  sprintf("- median_team_gain_calc: %.6f", median_team_gain_calc),
  sprintf("- median_team_gain_status: %.6f", median_team_gain_status),
  sprintf("- mean_match (within tol): %s", mean_match),
  sprintf("- median_match (within tol): %s", median_match),
  "",
  "## Constraints",
  sprintf("- Overlap radius: %.3f", overlap_radius),
  sprintf("- Overlap violations (recalc): %d", n_overlap_viol_recalc),
  sprintf("- Overlap violations (status): %d", n_overlap_status),
  sprintf("- Edge violations (recalc): %d", n_edge_viol_recalc),
  sprintf("- Edge violations (status): %d", n_edge_status),
  sprintf("- overlap_match: %s", overlap_match),
  sprintf("- edge_match: %s", edge_match),
  "",
  sprintf("- Plays count matches status: %s", plays_match),
  "",
  sprintf("- PASS: %s", pass)
)

writeLines(md_lines, con = PATH$out_status_md)

cat("[33a] Finished 33a_coordination_verification.R\n")










# 34_outcome_model_dr.R
# CLI: Rscript Code/34_outcome_model_dr.R
#
# Purpose:
#   Train an outcome model (EPA) with a multinomial propensity model and
#   doubly-robust (DR) estimates for defender-play impact.
#
# Design notes:
#   - Uses contest / leverage / backup / hold as the action (treatment).
#   - Propensity model: glmnet multinomial with L2 (ridge), then
#     *mixed with a uniform prior* to avoid vanishing probabilities.
#   - Outcome model: xgboost regression on EPA.
#   - DR weights use the mixed propensities, so weights are stable
#     (no huge 1/p spikes), making DR more reliable.
#
# Inputs:
#   - artifacts/v2_model04_leverage_dataset.csv
#   - artifacts/eligibility_v3.csv
#   - artifacts/affordances_v3.csv
#
# Outputs:
#   - artifacts/impact_model_v3.rds
#   - artifacts/propensity_reliability_v3.png
#   - artifacts/dr_influence_stats_v3.csv
#   - artifacts/34_outcome_model_dr_status.csv
#   - artifacts/34_outcome_model_dr_status.md

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(glmnet)
  library(xgboost)
  library(ggplot2)
}))

cat("[34] Starting 34_outcome_model_dr.R\n")

set.seed(2024)

# -------------------------------------------------------------------
# Paths
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2           = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig           = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff            = file.path(DIR$artifacts, "affordances_v3.csv"),
  out_model_rds  = file.path(DIR$artifacts, "impact_model_v3.rds"),
  out_prop_png   = file.path(DIR$artifacts, "propensity_reliability_v3.png"),
  out_dr_stats   = file.path(DIR$artifacts, "dr_influence_stats_v3.csv"),
  out_alpha_sweep = file.path(DIR$artifacts, "34_alpha_mix_sweep_v3.csv"),
  out_status_csv = file.path(DIR$artifacts, "34_outcome_model_dr_status.csv"),
  out_status_md  = file.path(DIR$artifacts, "34_outcome_model_dr_status.md")
)

for (nm in c("lev2","elig","aff")) {
  if (!file.exists(PATH[[nm]])) {
    stop("[34] Missing required input: ", PATH[[nm]])
  }
}

# -------------------------------------------------------------------
# 1. Load and merge data
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

cat("[34] Loaded leverage dataset with", nrow(lev2), "rows\n")

base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone = as.character(zone)
  )

# -------------------------------------------------------------------
# 2. Define observed actions (contest / leverage / backup / hold)
# -------------------------------------------------------------------

base <- base %>%
  mutate(
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  )

# -------------------------------------------------------------------
# 3. Filter to modelling dataset
# -------------------------------------------------------------------

df <- base %>%
  filter(is.finite(epa),
         !is.na(action)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))   # R-based affordance must be available

cat("[34] Training rows after filtering:", nrow(df), "\n")

if (nrow(df) < 1000) {
  warning("[34] Fewer than 1000 rows for impact model; DR estimates may be noisy.")
}

# -------------------------------------------------------------------
# 4. Build design matrices
# -------------------------------------------------------------------

# Shared feature set
feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing_feats <- setdiff(feat_vars, names(df))
if (length(missing_feats)) {
  warning("[34] Missing feature columns: ",
          paste(missing_feats, collapse = ", "),
          " -- dropping them from the model.")
  feat_vars <- intersect(feat_vars, names(df))
}

# 4a. Propensity features: zone + feat_vars (no action)
prop_df <- df %>%
  mutate(
    zone = factor(zone)
  ) %>%
  select(all_of(c("zone", feat_vars)))

x_prop <- model.matrix(~ . - 1, data = prop_df)
y_prop <- df$action

cat("[34] Propensity feature matrix:", nrow(x_prop), "x", ncol(x_prop), "\n")

# 4b. Outcome features: action + zone + feat_vars
out_df <- df %>%
  mutate(
    zone   = factor(zone),
    action = factor(action)
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

# Drop degenerate factor/character columns with a single level
for (col in names(out_df)) {
  if (is.factor(out_df[[col]]) || is.character(out_df[[col]])) {
    if (dplyr::n_distinct(out_df[[col]]) < 2) {
      message(sprintf("[34] Dropping column '%s' from outcome features (only one level)", col))
      out_df[[col]] <- NULL
    }
  }
}

x_out <- model.matrix(~ . - 1, data = out_df)
y_out <- df$epa

cat("[34] Outcome feature matrix:", nrow(x_out), "x", ncol(x_out), "\n")

# -------------------------------------------------------------------
# 5. Fit multinomial propensity model and flatten probabilities
# -------------------------------------------------------------------

cat("[34] Fitting multinomial propensity model (glmnet)...\n")

prop_cv <- glmnet::cv.glmnet(
  x = x_prop,
  y = y_prop,
  family = "multinomial",
  alpha = 0,           # L2 ridge
  type.measure = "deviance",
  nfolds = 5
)

lambda_star <- prop_cv$lambda.min
cat("[34] Selected lambda for propensity model:", signif(lambda_star, 3), "\n")

prop_fit <- prop_cv$glmnet.fit

# Raw probabilities from glmnet
p_hat_arr <- predict(
  prop_fit,
  newx = x_prop,
  s = lambda_star,
  type = "response"
)

p_hat <- p_hat_arr[,,1, drop = FALSE]
action_levels <- colnames(p_hat)
K <- length(action_levels)

obs_idx <- match(df$action, action_levels)
if (any(is.na(obs_idx))) stop("[34] Some actions not found in propensity output levels")

# ---- Mix with a uniform prior to avoid tiny probabilities ----
# Instead of fixing alpha_mix, evaluate a small grid and choose the best
# candidate based on overlap + mean log p_obs for the observed actions.

P_FLOOR <- 0.05
alpha_grid <- c(0.3, 0.5, 0.7)

alpha_results <- vector("list", length(alpha_grid))

for (i in seq_along(alpha_grid)) {
  a <- alpha_grid[i]
  
  # Candidate mixed probabilities
  p_mix_a <- (1 - a) * p_hat + a * (1 / K)
  
  # Ensure rows sum to 1
  row_sums_a <- rowSums(p_mix_a)
  if (any(abs(row_sums_a - 1) > 1e-6)) {
    p_mix_a <- p_mix_a / row_sums_a
  }
  
  # Observed action probabilities for this alpha
  p_obs_a <- p_mix_a[cbind(seq_len(nrow(df)), obs_idx)]
  
  frac_lt_floor_a <- mean(p_obs_a < P_FLOOR)
  mean_log_p_a    <- mean(log(p_obs_a))
  
  alpha_results[[i]] <- tibble(
    alpha_mix           = a,
    frac_p_obs_lt_floor = frac_lt_floor_a,
    mean_log_p_obs      = mean_log_p_a
  )
}

alpha_sweep <- bind_rows(alpha_results)

# Save the sweep for inspection
readr::write_csv(alpha_sweep, PATH$out_alpha_sweep)

# Filter to alphas that satisfy the overlap constraint
alpha_ok <- alpha_sweep %>% filter(frac_p_obs_lt_floor <= 0.02)

if (nrow(alpha_ok) == 0L) {
  warning("[34] No alpha_mix in grid satisfies overlap constraint; falling back to alpha_mix = 0.5")
  ALPHA_MIX <- 0.5
} else {
  # Among overlap-safe alphas, choose the one with highest mean_log_p_obs
  best_row <- alpha_ok %>%
    slice_max(mean_log_p_obs, n = 1, with_ties = FALSE)
  ALPHA_MIX <- best_row$alpha_mix[[1]]
}

cat("[34] Selected alpha_mix =", sprintf("%.2f", ALPHA_MIX),
    "based on overlap + mean log p_obs\n")

# Final mixed probabilities using the chosen ALPHA_MIX
p_mix <- (1 - ALPHA_MIX) * p_hat + ALPHA_MIX * (1 / K)

# Sanity: row sums should still be 1
row_sums_mix <- rowSums(p_mix)
if (any(abs(row_sums_mix - 1) > 1e-6)) {
  warning("[34] Row sums of mixed propensities deviate from 1; renormalising.")
  p_mix <- p_mix / row_sums_mix
}

# Observed action probabilities (raw and mixed)
p_obs_raw <- p_hat[cbind(seq_len(nrow(df)), obs_idx)]
p_obs     <- p_mix[cbind(seq_len(nrow(df)), obs_idx)]

frac_p_obs_raw_lt_010 <- mean(p_obs_raw < 0.10)
frac_p_obs_lt_floor   <- mean(p_obs < P_FLOOR)

cat(sprintf("[34] Raw overlap: frac p_obs_raw < 0.10 = %.3f\n", frac_p_obs_raw_lt_010))
cat(sprintf("[34] Mixed overlap: frac p_obs (after mix) < %.2f = %.3f\n",
            P_FLOOR, frac_p_obs_lt_floor))

overlap_ok <- (frac_p_obs_lt_floor <= 0.02)

# -------------------------------------------------------------------
# 6. Fit outcome model (EPA) with xgboost
# -------------------------------------------------------------------

cat("[34] Fitting xgboost outcome model (EPA) with train/validation split...\n")

# Create a simple random train/validation split for outcome-model diagnostics
set.seed(34L)
n_rows_out <- nrow(x_out)
val_fraction <- 0.20
val_size <- max(1L, floor(n_rows_out * val_fraction))

val_idx <- sample.int(n_rows_out, size = val_size)
train_idx <- setdiff(seq_len(n_rows_out), val_idx)

dtrain <- xgboost::xgb.DMatrix(
  data  = x_out[train_idx, , drop = FALSE],
  label = y_out[train_idx]
)

dval <- xgboost::xgb.DMatrix(
  data  = x_out[val_idx, , drop = FALSE],
  label = y_out[val_idx]
)

params <- list(
  objective        = "reg:squarederror",
  eta              = 0.05,
  max_depth        = 5,
  subsample        = 0.8,
  colsample_bytree = 0.8,
  min_child_weight = 10,
  nthread          = 1
)

nrounds <- 300

watchlist <- list(train = dtrain, val = dval)

xgb_fit_val <- xgboost::xgb.train(
  params   = params,
  data     = dtrain,
  nrounds  = nrounds,
  watchlist = watchlist,
  verbose  = 0
)

cat("[34] Outcome model (validation run) trained with", nrounds, "rounds\n")

# Validation metrics
pred_val <- predict(xgb_fit_val, newdata = x_out[val_idx, , drop = FALSE])
y_val    <- y_out[val_idx]

rmse_val <- sqrt(mean((pred_val - y_val)^2))
ss_res   <- sum((pred_val - y_val)^2)
ss_tot   <- sum((y_val - mean(y_val))^2)
r2_val   <- if (ss_tot > 0) 1 - ss_res / ss_tot else NA_real_

cat(sprintf("[34] Outcome model validation RMSE: %.4f, R^2: %.4f\n", rmse_val, r2_val))

# Refit on all rows for the final model used in DR
dtrain_full <- xgboost::xgb.DMatrix(
  data  = x_out,
  label = y_out
)

xgb_fit <- xgboost::xgb.train(
  params  = params,
  data    = dtrain_full,
  nrounds = nrounds,
  verbose = 0
)

cat("[34] Outcome model (full-data) trained with", nrounds, "rounds\n")

q_hat <- predict(xgb_fit, newdata = x_out)

# -------------------------------------------------------------------
# 7. Compute doubly-robust EPA and influence stats
# -------------------------------------------------------------------

dr_epa  <- q_hat + (y_out - q_hat) / p_obs
weights <- 1 / p_obs

dr_stats <- tibble(
  n_rows            = nrow(df),
  mean_dr_epa       = mean(dr_epa),
  sd_dr_epa         = sd(dr_epa),
  q01_dr_epa        = as.numeric(quantile(dr_epa, 0.01, na.rm = TRUE)),
  q05_dr_epa        = as.numeric(quantile(dr_epa, 0.05, na.rm = TRUE)),
  q25_dr_epa        = as.numeric(quantile(dr_epa, 0.25, na.rm = TRUE)),
  q50_dr_epa        = as.numeric(quantile(dr_epa, 0.50, na.rm = TRUE)),
  q75_dr_epa        = as.numeric(quantile(dr_epa, 0.75, na.rm = TRUE)),
  q95_dr_epa        = as.numeric(quantile(dr_epa, 0.95, na.rm = TRUE)),
  q99_dr_epa        = as.numeric(quantile(dr_epa, 0.99, na.rm = TRUE)),
  mean_weight       = mean(weights),
  sd_weight         = sd(weights),
  q95_weight        = as.numeric(quantile(weights, 0.95, na.rm = TRUE)),
  q99_weight        = as.numeric(quantile(weights, 0.99, na.rm = TRUE)),
  frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
  frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
  p_floor           = P_FLOOR,
  alpha_mix         = ALPHA_MIX
)

readr::write_csv(dr_stats, PATH$out_dr_stats)
cat("[34] Wrote DR influence stats to", PATH$out_dr_stats, "\n")

# -------------------------------------------------------------------
# 8. Propensity reliability plot (using mixed probabilities)
# -------------------------------------------------------------------

p_max_mix   <- apply(p_mix, 1, max)
pred_idx    <- apply(p_mix, 1, which.max)
pred_action <- factor(action_levels[pred_idx], levels = action_levels)
correct     <- as.integer(pred_action == df$action)

reliability_df <- tibble(
  p_max   = p_max_mix,
  correct = correct
) %>%
  mutate(
    bin = cut(p_max,
              breaks = seq(0, 1, by = 0.1),
              include.lowest = TRUE,
              right = TRUE)
  ) %>%
  group_by(bin) %>%
  summarise(
    p_hat = mean(p_max),
    acc   = mean(correct),
    n     = n(),
    .groups = "drop"
  )

p_reliab <- ggplot(reliability_df, aes(x = p_hat, y = acc)) +
  geom_abline(intercept = 0, slope = 1, linetype = "dashed") +
  geom_point() +
  geom_line() +
  coord_equal(xlim = c(0,1), ylim = c(0,1)) +
  labs(
    title = "Propensity reliability (mixed P(A|X))",
    x     = "Predicted top-1 probability",
    y     = "Empirical accuracy"
  ) +
  theme_minimal()

ggsave(PATH$out_prop_png, plot = p_reliab, width = 6, height = 4, dpi = 150)
cat("[34] Wrote propensity reliability plot to", PATH$out_prop_png, "\n")

# -------------------------------------------------------------------
# 9. Save impact model object
# -------------------------------------------------------------------

impact_model <- list(
  version              = 3L,
  timestamp            = Sys.time(),
  outcome              = "epa",
  action_levels        = action_levels,
  feature_names_prop   = colnames(x_prop),
  feature_names_out    = colnames(x_out),
  propensity_model     = prop_fit,
  propensity_lambda    = lambda_star,
  propensity_alpha_mix = ALPHA_MIX,
  outcome_model        = xgb_fit,
  training_summary     = list(
    n_rows              = nrow(df),
    overlap_ok          = overlap_ok,
    frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
    frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
    dr_stats            = dr_stats
  )
)

saveRDS(impact_model, PATH$out_model_rds)
cat("[34] Saved impact_model_v3 to", PATH$out_model_rds, "\n")

# -------------------------------------------------------------------
# 10. Status report + console verdict
# -------------------------------------------------------------------

action_counts <- df %>%
  count(action, name = "n_action")

status <- tibble(
  script              = "34_outcome_model_dr.R",
  n_rows              = nrow(df),
  n_actions           = n_distinct(df$action),
  overlap_ok          = overlap_ok,
  frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
  frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
  p_floor             = P_FLOOR,
  alpha_mix           = ALPHA_MIX,
  mean_dr_epa         = dr_stats$mean_dr_epa,
  sd_dr_epa           = dr_stats$sd_dr_epa,
  rmse_val            = rmse_val,
  r2_val              = r2_val,
  pass                = overlap_ok
)

readr::write_csv(status, PATH$out_status_csv)

if (isTRUE(status$pass[1])) {
  cat("[34] VERDICT: PASS (overlap OK with mixed propensities) ✅\n")
} else {
  cat("[34] VERDICT: FAIL (overlap issue) ❌\n")
}

# Markdown report
md_lines <- c(
  "# 34_outcome_model_dr",
  "",
  sprintf("- Training rows: %d", status$n_rows),
  sprintf("- Actions: %d", status$n_actions),
  "",
  "## Action counts",
  ""
)

for (i in seq_len(nrow(action_counts))) {
  row <- action_counts[i, ]
  md_lines <- c(
    md_lines,
    sprintf("- %s: %d", as.character(row$action), row$n_action)
  )
}

md_lines <- c(
  md_lines,
  "",
  "## Propensity / overlap",
  sprintf("- alpha_mix (uniform weight): %.2f", status$alpha_mix),
  sprintf("- p_floor (diagnostic only): %.2f", status$p_floor),
  sprintf("- frac raw p_obs < 0.10: %.3f", status$frac_p_obs_raw_lt_010),
  sprintf("- frac mixed p_obs < %.2f: %.3f",
          status$p_floor, status$frac_p_obs_lt_floor),
  sprintf("- overlap_ok: %s", status$overlap_ok),
  "",
  "## Outcome model (validation)",
  sprintf("- RMSE (val): %.4f", status$rmse_val),
  sprintf("- R^2 (val): %.4f", status$r2_val),
  "",
  "## DR EPA stats",
  sprintf("- mean DR(EPA): %.4f", status$mean_dr_epa),
  sprintf("- sd DR(EPA): %.4f", status$sd_dr_epa),
  "",
  sprintf("- PASS: %s", status$pass)
)

writeLines(md_lines, con = PATH$out_status_md)

cat("[34] Finished 34_outcome_model_dr.R\n")










# 34.2_outcome_model_dr_uplift.R
# CLI: Rscript Code/34.2_outcome_model_dr_uplift.R
#
# Purpose (Phase-3 spec):
#   Compute a validation uplift metric (improvement over a constant-baseline EPA model)
#   for the impact_model_v3 outcome model, with a bootstrap confidence interval.
#   This complements 34_outcome_model_dr.R so that acceptance matches the literal
#   Phase-3 spec:
#     "Overlap passes; validation uplift CI excludes zero."
#
#   In other words:
#     - 34_outcome_model_dr.R is responsible for training the model and enforcing
#       the overlap constraint for propensities.
#     - 34.2_outcome_model_dr_uplift.R is responsible for checking that the
#       outcome model delivers a statistically meaningful uplift on the VAL split.
#
# Inputs (all relative to project root):
#   - artifacts/v2_model04_leverage_dataset.csv
#   - artifacts/eligibility_v3.csv
#   - artifacts/affordances_v3.csv
#   - artifacts/impact_model_v3.rds      (from 34_outcome_model_dr.R)
#   - artifacts/34_outcome_model_dr_status.csv (for overlap_ok flag, optional but expected)
#
# Outputs:
#   - artifacts/34.2_outcome_model_dr_uplift_status.csv
#   - artifacts/34.2_outcome_model_dr_uplift_status.md
#
# Acceptance (for this script):
#   - uplift_pass == TRUE  (lower CI bound for uplift > 0)
#   - overall_pass == TRUE (uplift_pass AND 34's overlap_ok)
#
# Notes on uplift definition:
#   - We work on the global VAL split (split == "val") from the leverage dataset,
#     not the internal random 80/20 used in 34 for quick diagnostics.
#   - Baseline model: constant predictor equal to the mean EPA on the VAL split.
#   - Outcome model: xgboost regressor stored in impact_model_v3.
#   - Metric: RMSE on VAL.
#   - Uplift: baseline_RMSE - model_RMSE (so positive is better than baseline).
#   - CI: non-parametric bootstrap over VAL rows.
#

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(xgboost)
  library(readr)
}))

cat("[34.2] Starting 34.2_outcome_model_dr_uplift.R\n")

set.seed(342L)

# -------------------------------------------------------------------
# Paths
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2             = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig             = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff              = file.path(DIR$artifacts, "affordances_v3.csv"),
  impact_model_rds = file.path(DIR$artifacts, "impact_model_v3.rds"),
  status_34_csv    = file.path(DIR$artifacts, "34_outcome_model_dr_status.csv"),
  out_status_csv   = file.path(DIR$artifacts, "34.2_outcome_model_dr_uplift_status.csv"),
  out_status_md    = file.path(DIR$artifacts, "34.2_outcome_model_dr_uplift_status.md")
)

for (nm in c("lev2","elig","aff","impact_model_rds")) {
  if (!file.exists(PATH[[nm]])) {
    stop("[34.2] Missing required input: ", PATH[[nm]],
         ". Run 34_outcome_model_dr.R and upstream scripts first.", call. = FALSE)
  }
}

if (!file.exists(PATH$status_34_csv)) {
  warning("[34.2] 34_outcome_model_dr_status.csv not found; overlap_ok will be NA.")
}

# -------------------------------------------------------------------
# 1. Load and merge data (mirror 34_outcome_model_dr.R)
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

# Sanity: ensure we have a split column
if (!"split" %in% names(lev2)) stop("[34.2] lev2 is missing split column.")
if (!"split" %in% names(elig)) stop("[34.2] elig is missing split column.")
if (!"split" %in% names(aff))  stop("[34.2] aff is missing split column.")

# Join into a single base table (mirror 34)
base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone              = as.character(zone),
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  )

# -------------------------------------------------------------------
# 2. Filter to modelling dataset (same gates as 34)
# -------------------------------------------------------------------

df <- base %>%
  filter(is.finite(epa),
         !is.na(action)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))   # R-based affordance must be available

cat("[34.2] Rows after filtering (all splits): ", nrow(df), "\\n", sep = "")

if (nrow(df) < 1000) {
  warning("[34.2] Fewer than 1000 rows for uplift check; results may be noisy.")
}

# -------------------------------------------------------------------
# 3. Build outcome design matrix (mirror 34)
# -------------------------------------------------------------------

feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing <- setdiff(feat_vars, names(df))
if (length(missing)) {
  warning(
    "[34.2] Missing expected feature(s) in df: ",
    paste(missing, collapse = ", "),
    " -- dropping them for uplift check."
  )
  feat_vars <- intersect(feat_vars, names(df))
}

out_df <- df %>%
  mutate(
    zone   = factor(zone),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

x_out <- model.matrix(~ . - 1, data = out_df)
y_out <- df$epa

cat("[34.2] Outcome feature matrix: ", nrow(x_out), " x ", ncol(x_out), "\\n", sep = "")

# -------------------------------------------------------------------
# 4. Restrict to VAL split and compute predictions
# -------------------------------------------------------------------

val_idx <- which(df$split == "val")

if (length(val_idx) == 0L) {
  stop("[34.2] No rows with split == 'val' after filtering; cannot compute validation uplift.",
       call. = FALSE)
}

x_val <- x_out[val_idx, , drop = FALSE]
y_val <- y_out[val_idx]

cat("[34.2] VAL rows for uplift: ", length(y_val), "\\n", sep = "")

impact_model <- readRDS(PATH$impact_model_rds)

if (is.null(impact_model$outcome_model)) {
  stop("[34.2] impact_model_v3.rds does not contain an outcome_model.", call. = FALSE)
}

xgb_fit <- impact_model$outcome_model
feat_train <- impact_model$feature_names_out

# Align VAL design matrix columns with training feature set
missing_cols <- setdiff(feat_train, colnames(x_val))
extra_cols   <- setdiff(colnames(x_val), feat_train)

if (length(extra_cols)) {
  warning("[34.2] Extra columns in VAL design matrix not seen at training: ",
          paste(extra_cols, collapse = ", "),
          " -- dropping them.")
}

# Add any missing training columns as zeros
if (length(missing_cols)) {
  warning("[34.2] Adding missing training feature columns to VAL matrix as zeros: ",
          paste(missing_cols, collapse = ", "))
  for (nm in missing_cols) {
    x_val <- cbind(x_val, setNames(list(rep(0, nrow(x_val))), nm))
  }
}

# Reorder columns to match training
x_val <- x_val[, feat_train, drop = FALSE]

dval <- xgboost::xgb.DMatrix(data = x_val)

pred_val <- as.numeric(predict(xgb_fit, newdata = dval))

# -------------------------------------------------------------------
# 5. Compute uplift vs constant baseline on VAL
# -------------------------------------------------------------------

rmse <- function(pred, y) {
  ok <- is.finite(pred) & is.finite(y)
  pred <- pred[ok]; y <- y[ok]
  if (length(y) == 0L) return(NA_real_)
  sqrt(mean((pred - y)^2))
}

baseline_mean <- mean(y_val[is.finite(y_val)])
rmse_model    <- rmse(pred_val, y_val)
rmse_base     <- rmse(rep(baseline_mean, length(y_val)), y_val)
uplift_hat    <- rmse_base - rmse_model  # >0 means outcome model beats constant baseline

cat(sprintf("[34.2] Baseline RMSE (VAL): %.4f\n", rmse_base))
cat(sprintf("[34.2] Model RMSE (VAL): %.4f\n", rmse_model))
cat(sprintf("[34.2] Point estimate uplift (baseline_rmse - model_rmse): %.4f\n", uplift_hat))

# -------------------------------------------------------------------
# 6. Bootstrap CI for uplift
# -------------------------------------------------------------------

B <- 1000L
n_val <- length(y_val)
uplift_boot <- numeric(B)

set.seed(343L)

for (b in seq_len(B)) {
  idx <- sample.int(n_val, size = n_val, replace = TRUE)
  y_b   <- y_val[idx]
  pred_b <- pred_val[idx]
  
  rmse_model_b <- rmse(pred_b, y_b)
  rmse_base_b  <- rmse(rep(baseline_mean, length(y_b)), y_b)
  
  uplift_boot[b] <- rmse_base_b - rmse_model_b
}

uplift_ci <- quantile(uplift_boot, probs = c(0.025, 0.975), na.rm = TRUE)
uplift_lo <- as.numeric(uplift_ci[1])
uplift_hi <- as.numeric(uplift_ci[2])

uplift_pass <- is.finite(uplift_lo) && (uplift_lo > 0)

cat(sprintf("[34.2] 95%% bootstrap CI for uplift: [%.4f, %.4f]\n", uplift_lo, uplift_hi))
cat(sprintf("[34.2] uplift_pass (CI lower > 0): %s\n", uplift_pass))

# -------------------------------------------------------------------
# 7. Combine with 34's overlap_ok and write status
# -------------------------------------------------------------------

overlap_ok <- NA
if (file.exists(PATH$status_34_csv)) {
  status34 <- readr::read_csv(PATH$status_34_csv, show_col_types = FALSE)
  if ("overlap_ok" %in% names(status34)) {
    overlap_ok <- isTRUE(status34$overlap_ok[1])
  }
}

overall_pass <- isTRUE(overlap_ok) && uplift_pass

status <- tibble(
  script              = "34.2_outcome_model_dr_uplift.R",
  n_val               = length(y_val),
  baseline_rmse_val   = rmse_base,
  model_rmse_val      = rmse_model,
  uplift_rmse         = uplift_hat,
  uplift_lo           = uplift_lo,
  uplift_hi           = uplift_hi,
  uplift_pass         = uplift_pass,
  bootstrap_B         = B,
  baseline_mean_epa   = baseline_mean,
  overlap_ok_34       = overlap_ok,
  overall_pass        = overall_pass
)

readr::write_csv(status, PATH$out_status_csv)

# -------------------------------------------------------------------
# 8. Markdown report
# -------------------------------------------------------------------

md_lines <- c(
  "# 34.2_outcome_model_dr_uplift",
  "",
  "- Script: Code/34.2_outcome_model_dr_uplift.R",
  sprintf("- VAL rows: %d", status$n_val),
  "",
  "## Uplift vs constant-baseline EPA (VAL split)",
  sprintf("- Baseline RMSE (VAL, mean EPA): %.4f", status$baseline_rmse_val),
  sprintf("- Model RMSE (VAL, impact_model_v3): %.4f", status$model_rmse_val),
  sprintf("- Uplift (baseline_rmse - model_rmse): %.4f", status$uplift_rmse),
  sprintf("- 95%% CI for uplift: [%.4f, %.4f]", status$uplift_lo, status$uplift_hi),
  sprintf("- uplift_pass (CI lower > 0): %s", status$uplift_pass),
  "",
  "## Combined acceptance with 34_outcome_model_dr.R",
  sprintf("- overlap_ok (34): %s", status$overlap_ok_34),
  sprintf("- overall_pass (overlap_ok AND uplift_pass): %s", status$overall_pass)
)

writeLines(md_lines, PATH$out_status_md)

cat("[34.2] Wrote uplift status to ",
    PATH$out_status_csv, " and ", PATH$out_status_md, "\n", sep = "")

if (!overall_pass) {
  stop("[34.2] Overall acceptance FAILED (either overlap or uplift). See uplift status for details.",
       call. = FALSE)
} else {
  cat("[34.2] Overall acceptance PASSED (overlap_ok AND uplift CI lower > 0).\n")
}

cat("[34.2] Finished 34.2_outcome_model_dr_uplift.R\n")










# 34.3_outcome_model_yac.R
# CLI: Rscript Code/34.3_outcome_model_yac.R
#
# Purpose:
#   Train an outcome model (YAC) with the same DR/propensity structure as the EPA model with a multinomial propensity model and
#   doubly-robust (DR) estimates for defender-play impact.
#
# Design notes:
#   - Uses contest / leverage / backup / hold as the action (treatment).
#   - Propensity model: glmnet multinomial with L2 (ridge), then
#     *mixed with a uniform prior* to avoid vanishing probabilities.
#   - Outcome model: xgboost regression on YAC.
#   - DR weights use the mixed propensities, so weights are stable
#     (no huge 1/p spikes), making DR more reliable.
#
# Inputs:
#   - artifacts/v2_model04_leverage_dataset.csv
#   - artifacts/eligibility_v3.csv
#   - artifacts/affordances_v3.csv
#
# Outputs:
#   - artifacts/impact_model_yac_v3.rds
#   - artifacts/propensity_reliability_yac_v3.png
#   - artifacts/dr_influence_stats_yac_v3.csv
#   - artifacts/34.3_outcome_model_yac_status.csv
#   - artifacts/34.3_outcome_model_yac_status.md

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(glmnet)
  library(xgboost)
  library(ggplot2)
}))

cat("[34.3] Starting 34_outcome_model_dr.R\n")

set.seed(2024)

# -------------------------------------------------------------------
# Paths
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2           = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig           = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff            = file.path(DIR$artifacts, "affordances_v3.csv"),
  out_model_rds  = file.path(DIR$artifacts, "impact_model_yac_v3.rds"),
  out_prop_png   = file.path(DIR$artifacts, "propensity_reliability_yac_v3.png"),
  out_dr_stats   = file.path(DIR$artifacts, "dr_influence_stats_yac_v3.csv"),
  out_alpha_sweep = file.path(DIR$artifacts, "34.3_alpha_mix_sweep_yac_v3.csv"),
  out_status_csv = file.path(DIR$artifacts, "34.3_outcome_model_yac_status.csv"),
  out_status_md  = file.path(DIR$artifacts, "34.3_outcome_model_yac_status.md")
)

for (nm in c("lev2","elig","aff")) {
  if (!file.exists(PATH[[nm]])) {
    stop("[34.3] Missing required input: ", PATH[[nm]])
  }
}

# -------------------------------------------------------------------
# 1. Load and merge data
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

cat("[34.3] Loaded leverage dataset with", nrow(lev2), "rows\n")

base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone = as.character(zone)
  )

# -------------------------------------------------------------------
# 2. Define observed actions (contest / leverage / backup / hold)
# -------------------------------------------------------------------

base <- base %>%
  mutate(
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  )

# -------------------------------------------------------------------
# 3. Filter to modelling dataset
# -------------------------------------------------------------------

df <- base %>%
  filter(is.finite(epa),
         is.finite(yac),
         !is.na(action)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))   # R-based affordance must be available

cat("[34.3] Training rows after filtering:", nrow(df), "\n")

if (nrow(df) < 1000) {
  warning("[34.3] Fewer than 1000 rows for impact model; DR estimates may be noisy.")
}

# -------------------------------------------------------------------
# 4. Build design matrices
# -------------------------------------------------------------------

# Shared feature set
feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing_feats <- setdiff(feat_vars, names(df))
if (length(missing_feats)) {
  warning("[34.3] Missing feature columns: ",
          paste(missing_feats, collapse = ", "),
          " -- dropping them from the model.")
  feat_vars <- intersect(feat_vars, names(df))
}

# 4a. Propensity features: zone + feat_vars (no action)
prop_df <- df %>%
  mutate(
    zone = factor(zone)
  ) %>%
  select(all_of(c("zone", feat_vars)))

x_prop <- model.matrix(~ . - 1, data = prop_df)
y_prop <- df$action

cat("[34.3] Propensity feature matrix:", nrow(x_prop), "x", ncol(x_prop), "\n")

# 4b. Outcome features: action + zone + feat_vars
out_df <- df %>%
  mutate(
    zone   = factor(zone),
    action = factor(action)
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

# Drop degenerate factor/character columns with a single level
for (col in names(out_df)) {
  if (is.factor(out_df[[col]]) || is.character(out_df[[col]])) {
    if (dplyr::n_distinct(out_df[[col]]) < 2) {
      message(sprintf("[34.3] Dropping column '%s' from outcome features (only one level)", col))
      out_df[[col]] <- NULL
    }
  }
}

x_out <- model.matrix(~ . - 1, data = out_df)
y_out <- df$yac

cat("[34.3] Outcome feature matrix:", nrow(x_out), "x", ncol(x_out), "\n")

# -------------------------------------------------------------------
# 5. Fit multinomial propensity model and flatten probabilities
# -------------------------------------------------------------------

cat("[34.3] Fitting multinomial propensity model (glmnet)...\n")

prop_cv <- glmnet::cv.glmnet(
  x = x_prop,
  y = y_prop,
  family = "multinomial",
  alpha = 0,           # L2 ridge
  type.measure = "deviance",
  nfolds = 5
)

lambda_star <- prop_cv$lambda.min
cat("[34.3] Selected lambda for propensity model:", signif(lambda_star, 3), "\n")

prop_fit <- prop_cv$glmnet.fit

# Raw probabilities from glmnet
p_hat_arr <- predict(
  prop_fit,
  newx = x_prop,
  s = lambda_star,
  type = "response"
)

p_hat <- p_hat_arr[,,1, drop = FALSE]
action_levels <- colnames(p_hat)
K <- length(action_levels)

obs_idx <- match(df$action, action_levels)
if (any(is.na(obs_idx))) stop("[34.3] Some actions not found in propensity output levels")

# ---- Mix with a uniform prior to avoid tiny probabilities ----
# Instead of fixing alpha_mix, evaluate a small grid and choose the best
# candidate based on overlap + mean log p_obs for the observed actions.

P_FLOOR <- 0.05
alpha_grid <- c(0.3, 0.5, 0.7)

alpha_results <- vector("list", length(alpha_grid))

for (i in seq_along(alpha_grid)) {
  a <- alpha_grid[i]
  
  # Candidate mixed probabilities
  p_mix_a <- (1 - a) * p_hat + a * (1 / K)
  
  # Ensure rows sum to 1
  row_sums_a <- rowSums(p_mix_a)
  if (any(abs(row_sums_a - 1) > 1e-6)) {
    p_mix_a <- p_mix_a / row_sums_a
  }
  
  # Observed action probabilities for this alpha
  p_obs_a <- p_mix_a[cbind(seq_len(nrow(df)), obs_idx)]
  
  frac_lt_floor_a <- mean(p_obs_a < P_FLOOR)
  mean_log_p_a    <- mean(log(p_obs_a))
  
  alpha_results[[i]] <- tibble(
    alpha_mix           = a,
    frac_p_obs_lt_floor = frac_lt_floor_a,
    mean_log_p_obs      = mean_log_p_a
  )
}

alpha_sweep <- bind_rows(alpha_results)

# Save the sweep for inspection
readr::write_csv(alpha_sweep, PATH$out_alpha_sweep)

# Filter to alphas that satisfy the overlap constraint
alpha_ok <- alpha_sweep %>% filter(frac_p_obs_lt_floor <= 0.02)

if (nrow(alpha_ok) == 0L) {
  warning("[34.3] No alpha_mix in grid satisfies overlap constraint; falling back to alpha_mix = 0.5")
  ALPHA_MIX <- 0.5
} else {
  # Among overlap-safe alphas, choose the one with highest mean_log_p_obs
  best_row <- alpha_ok %>%
    slice_max(mean_log_p_obs, n = 1, with_ties = FALSE)
  ALPHA_MIX <- best_row$alpha_mix[[1]]
}

cat("[34.3] Selected alpha_mix =", sprintf("%.2f", ALPHA_MIX),
    "based on overlap + mean log p_obs\n")

# Final mixed probabilities using the chosen ALPHA_MIX
p_mix <- (1 - ALPHA_MIX) * p_hat + ALPHA_MIX * (1 / K)

# Sanity: row sums should still be 1
row_sums_mix <- rowSums(p_mix)
if (any(abs(row_sums_mix - 1) > 1e-6)) {
  warning("[34.3] Row sums of mixed propensities deviate from 1; renormalising.")
  p_mix <- p_mix / row_sums_mix
}

# Observed action probabilities (raw and mixed)
p_obs_raw <- p_hat[cbind(seq_len(nrow(df)), obs_idx)]
p_obs     <- p_mix[cbind(seq_len(nrow(df)), obs_idx)]

frac_p_obs_raw_lt_010 <- mean(p_obs_raw < 0.10)
frac_p_obs_lt_floor   <- mean(p_obs < P_FLOOR)

cat(sprintf("[34.3] Raw overlap: frac p_obs_raw < 0.10 = %.3f\n", frac_p_obs_raw_lt_010))
cat(sprintf("[34.3] Mixed overlap: frac p_obs (after mix) < %.2f = %.3f\n",
            P_FLOOR, frac_p_obs_lt_floor))

overlap_ok <- (frac_p_obs_lt_floor <= 0.02)

# -------------------------------------------------------------------
# 6. Fit outcome model (YAC) with xgboost
# -------------------------------------------------------------------

cat("[34.3] Fitting xgboost outcome model (YAC) with train/validation split...\n")

# Create a simple random train/validation split for outcome-model diagnostics
set.seed(34L)
n_rows_out <- nrow(x_out)
val_fraction <- 0.20
val_size <- max(1L, floor(n_rows_out * val_fraction))

val_idx <- sample.int(n_rows_out, size = val_size)
train_idx <- setdiff(seq_len(n_rows_out), val_idx)

dtrain <- xgboost::xgb.DMatrix(
  data  = x_out[train_idx, , drop = FALSE],
  label = y_out[train_idx]
)

dval <- xgboost::xgb.DMatrix(
  data  = x_out[val_idx, , drop = FALSE],
  label = y_out[val_idx]
)

params <- list(
  objective        = "reg:squarederror",
  eta              = 0.05,
  max_depth        = 5,
  subsample        = 0.8,
  colsample_bytree = 0.8,
  min_child_weight = 10,
  nthread          = 1
)

nrounds <- 300

watchlist <- list(train = dtrain, val = dval)

xgb_fit_val <- xgboost::xgb.train(
  params   = params,
  data     = dtrain,
  nrounds  = nrounds,
  watchlist = watchlist,
  verbose  = 0
)

cat("[34.3] Outcome model (validation run) trained with", nrounds, "rounds\n")

# Validation metrics
pred_val <- predict(xgb_fit_val, newdata = x_out[val_idx, , drop = FALSE])
y_val    <- y_out[val_idx]

rmse_val <- sqrt(mean((pred_val - y_val)^2))
ss_res   <- sum((pred_val - y_val)^2)
ss_tot   <- sum((y_val - mean(y_val))^2)
r2_val   <- if (ss_tot > 0) 1 - ss_res / ss_tot else NA_real_

cat(sprintf("[34.3] Outcome model validation RMSE: %.4f, R^2: %.4f\n", rmse_val, r2_val))

# Refit on all rows for the final model used in DR
dtrain_full <- xgboost::xgb.DMatrix(
  data  = x_out,
  label = y_out
)

xgb_fit <- xgboost::xgb.train(
  params  = params,
  data    = dtrain_full,
  nrounds = nrounds,
  verbose = 0
)

cat("[34.3] Outcome model (full-data) trained with", nrounds, "rounds\n")

q_hat <- predict(xgb_fit, newdata = x_out)

# -------------------------------------------------------------------
# 7. Compute doubly-robust YAC and influence stats
# -------------------------------------------------------------------

dr_yac  <- q_hat + (y_out - q_hat) / p_obs
weights <- 1 / p_obs

dr_stats <- tibble(
  n_rows            = nrow(df),
  mean_dr_yac       = mean(dr_yac),
  sd_dr_yac         = sd(dr_yac),
  q01_dr_yac        = as.numeric(quantile(dr_yac, 0.01, na.rm = TRUE)),
  q05_dr_yac        = as.numeric(quantile(dr_yac, 0.05, na.rm = TRUE)),
  q25_dr_yac        = as.numeric(quantile(dr_yac, 0.25, na.rm = TRUE)),
  q50_dr_yac        = as.numeric(quantile(dr_yac, 0.50, na.rm = TRUE)),
  q75_dr_yac        = as.numeric(quantile(dr_yac, 0.75, na.rm = TRUE)),
  q95_dr_yac        = as.numeric(quantile(dr_yac, 0.95, na.rm = TRUE)),
  q99_dr_yac        = as.numeric(quantile(dr_yac, 0.99, na.rm = TRUE)),
  mean_weight       = mean(weights),
  sd_weight         = sd(weights),
  q95_weight        = as.numeric(quantile(weights, 0.95, na.rm = TRUE)),
  q99_weight        = as.numeric(quantile(weights, 0.99, na.rm = TRUE)),
  frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
  frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
  p_floor           = P_FLOOR,
  alpha_mix         = ALPHA_MIX
)

readr::write_csv(dr_stats, PATH$out_dr_stats)
cat("[34.3] Wrote DR influence stats to", PATH$out_dr_stats, "\n")

# -------------------------------------------------------------------
# 8. Propensity reliability plot (using mixed probabilities)
# -------------------------------------------------------------------

p_max_mix   <- apply(p_mix, 1, max)
pred_idx    <- apply(p_mix, 1, which.max)
pred_action <- factor(action_levels[pred_idx], levels = action_levels)
correct     <- as.integer(pred_action == df$action)

reliability_df <- tibble(
  p_max   = p_max_mix,
  correct = correct
) %>%
  mutate(
    bin = cut(p_max,
              breaks = seq(0, 1, by = 0.1),
              include.lowest = TRUE,
              right = TRUE)
  ) %>%
  group_by(bin) %>%
  summarise(
    p_hat = mean(p_max),
    acc   = mean(correct),
    n     = n(),
    .groups = "drop"
  )

p_reliab <- ggplot(reliability_df, aes(x = p_hat, y = acc)) +
  geom_abline(intercept = 0, slope = 1, linetype = "dashed") +
  geom_point() +
  geom_line() +
  coord_equal(xlim = c(0,1), ylim = c(0,1)) +
  labs(
    title = "Propensity reliability (mixed P(A|X))",
    x     = "Predicted top-1 probability",
    y     = "Empirical accuracy"
  ) +
  theme_minimal()

ggsave(PATH$out_prop_png, plot = p_reliab, width = 6, height = 4, dpi = 150)
cat("[34.3] Wrote propensity reliability plot to", PATH$out_prop_png, "\n")

# -------------------------------------------------------------------
# 9. Save impact model object
# -------------------------------------------------------------------

impact_model <- list(
  version              = 3L,
  timestamp            = Sys.time(),
  outcome              = "yac",
  action_levels        = action_levels,
  feature_names_prop   = colnames(x_prop),
  feature_names_out    = colnames(x_out),
  propensity_model     = prop_fit,
  propensity_lambda    = lambda_star,
  propensity_alpha_mix = ALPHA_MIX,
  outcome_model        = xgb_fit,
  training_summary     = list(
    n_rows              = nrow(df),
    overlap_ok          = overlap_ok,
    frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
    frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
    dr_stats            = dr_stats
  )
)

saveRDS(impact_model, PATH$out_model_rds)
cat("[34.3] Saved impact_model_yac_v3 to", PATH$out_model_rds, "\n")

# -------------------------------------------------------------------
# 10. Status report + console verdict
# -------------------------------------------------------------------

action_counts <- df %>%
  count(action, name = "n_action")

status <- tibble(
  script              = "34.3_outcome_model_yac.R",
  n_rows              = nrow(df),
  n_actions           = n_distinct(df$action),
  overlap_ok          = overlap_ok,
  frac_p_obs_raw_lt_010 = frac_p_obs_raw_lt_010,
  frac_p_obs_lt_floor   = frac_p_obs_lt_floor,
  p_floor             = P_FLOOR,
  alpha_mix           = ALPHA_MIX,
  mean_dr_yac         = dr_stats$mean_dr_yac,
  sd_dr_yac           = dr_stats$sd_dr_yac,
  rmse_val            = rmse_val,
  r2_val              = r2_val,
  pass                = overlap_ok
)

readr::write_csv(status, PATH$out_status_csv)

if (isTRUE(status$pass[1])) {
  cat("[34.3] VERDICT: PASS (overlap OK with mixed propensities) ✅\n")
} else {
  cat("[34.3] VERDICT: FAIL (overlap issue) ❌\n")
}

# Markdown report
md_lines <- c(
  "# 34.3_outcome_model_yac",
  "",
  sprintf("- Training rows: %d", status$n_rows),
  sprintf("- Actions: %d", status$n_actions),
  "",
  "## Action counts",
  ""
)

for (i in seq_len(nrow(action_counts))) {
  row <- action_counts[i, ]
  md_lines <- c(
    md_lines,
    sprintf("- %s: %d", as.character(row$action), row$n_action)
  )
}

md_lines <- c(
  md_lines,
  "",
  "## Propensity / overlap",
  sprintf("- alpha_mix (uniform weight): %.2f", status$alpha_mix),
  sprintf("- p_floor (diagnostic only): %.2f", status$p_floor),
  sprintf("- frac raw p_obs < 0.10: %.3f", status$frac_p_obs_raw_lt_010),
  sprintf("- frac mixed p_obs < %.2f: %.3f",
          status$p_floor, status$frac_p_obs_lt_floor),
  sprintf("- overlap_ok: %s", status$overlap_ok),
  "",
  "## Outcome model (validation)",
  sprintf("- RMSE (val): %.4f", status$rmse_val),
  sprintf("- R^2 (val): %.4f", status$r2_val),
  "",
  "## DR YAC stats",
  sprintf("- mean DR(YAC): %.4f", status$mean_dr_yac),
  sprintf("- sd DR(YAC): %.4f", status$sd_dr_yac),
  "",
  sprintf("- PASS: %s", status$pass)
)

writeLines(md_lines, con = PATH$out_status_md)

cat("[34.3] Finished 34_outcome_model_dr.R\n")










# 34.4_outcome_model_yac_uplift.R
# CLI: Rscript Code/34.4_outcome_model_yac_uplift.R
#
# Purpose (Phase-3 spec):
#   Compute a validation uplift metric (improvement over a constant-baseline YAC model)
#   for the impact_model_yac_v3 outcome model, with a bootstrap confidence interval.
#   This complements 34.3_outcome_model_yac.R so that acceptance matches the literal
#   Phase-3 spec:
#     "Overlap passes; validation uplift CI excludes zero."
#
#   In other words:
#     - 34.3_outcome_model_yac.R is responsible for training the YAC model and enforcing
#       the overlap constraint for propensities.
#     - 34.4_outcome_model_yac_uplift.R is responsible for checking that the
#       outcome model delivers a statistically meaningful uplift on the VAL split.
#
# Inputs (all relative to project root):
#   - artifacts/v2_model04_leverage_dataset.csv
#   - artifacts/eligibility_v3.csv
#   - artifacts/affordances_v3.csv
#   - artifacts/impact_model_yac_v3.rds      (from 34.3_outcome_model_yac.R)
#   - artifacts/34.3_outcome_model_yac_status.csv (for overlap_ok flag, optional but expected)
#
# Outputs:
#   - artifacts/34.4_outcome_model_yac_uplift_status.csv
#   - artifacts/34.4_outcome_model_yac_uplift_status.md
#
# Acceptance (for this script):
#   - uplift_pass == TRUE  (lower CI bound for uplift > 0)
#   - overall_pass == TRUE (uplift_pass AND 34.3's overlap_ok)
#
# Notes on uplift definition:
#   - We work on the global VAL split (split == "val") from the leverage dataset,
#     not the internal random 80/20 used in 34.3 for quick diagnostics.
#   - Baseline model: constant predictor equal to the mean YAC on the VAL split.
#   - Outcome model: xgboost regressor stored in impact_model_yac_v3.
#   - Metric: RMSE on VAL.
#   - Uplift: baseline_RMSE - model_RMSE (so positive is better than baseline).
#   - CI: non-parametric bootstrap over VAL rows.
#

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(xgboost)
  library(readr)
}))

cat("[34.4] Starting 34.4_outcome_model_yac_uplift.R\n")

set.seed(344L)

# -------------------------------------------------------------------
# Paths
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2             = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig             = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff              = file.path(DIR$artifacts, "affordances_v3.csv"),
  impact_model_rds = file.path(DIR$artifacts, "impact_model_yac_v3.rds"),
  status_34_csv    = file.path(DIR$artifacts, "34.3_outcome_model_yac_status.csv"),
  out_status_csv   = file.path(DIR$artifacts, "34.4_outcome_model_yac_uplift_status.csv"),
  out_status_md    = file.path(DIR$artifacts, "34.4_outcome_model_yac_uplift_status.md")
)

for (nm in c("lev2","elig","aff","impact_model_rds")) {
  if (!file.exists(PATH[[nm]])) {
    stop("[34.4] Missing required input: ", PATH[[nm]],
         ". Run 34.3_outcome_model_yac.R and upstream scripts first.", call. = FALSE)
  }
}

if (!file.exists(PATH$status_34_csv)) {
  warning("[34.4] 34.3_outcome_model_yac_status.csv not found; overlap_ok will be NA.")
}

# -------------------------------------------------------------------
# 1. Load and merge data (mirror 34_outcome_model_dr.R)
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = as.character(split)
  )

# Sanity: ensure we have a split column
if (!"split" %in% names(lev2)) stop("[34.4] lev2 is missing split column.")
if (!"split" %in% names(elig)) stop("[34.4] elig is missing split column.")
if (!"split" %in% names(aff))  stop("[34.4] aff is missing split column.")

# Join into a single base table (mirror 34)
base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone              = as.character(zone),
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  )

# -------------------------------------------------------------------
# 2. Filter to modelling dataset (same gates as 34)
# -------------------------------------------------------------------

df <- base %>%
  filter(is.finite(epa),
         is.finite(yac),
         !is.na(action)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))   # R-based affordance must be available

cat("[34.4] Rows after filtering (all splits): ", nrow(df), "\\n", sep = "")

if (nrow(df) < 1000) {
  warning("[34.4] Fewer than 1000 rows for uplift check; results may be noisy.")
}

# -------------------------------------------------------------------
# 3. Build outcome design matrix (mirror 34)
# -------------------------------------------------------------------

feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing_feats <- setdiff(feat_vars, names(df))
if (length(missing_feats)) {
  warning(
    "[34.4] Missing feature columns: ",
    paste(missing_feats, collapse = ", "),
    " -- dropping them for uplift check."
  )
  feat_vars <- intersect(feat_vars, names(df))
}

missing <- setdiff(feat_vars, names(df))
if (length(missing)) {
  warning(
    "[34.4] Missing expected feature(s) in df: ",
    paste(missing, collapse = ", "),
    " -- dropping them for uplift check."
  )
  feat_vars <- intersect(feat_vars, names(df))
}

out_df <- df %>%
  mutate(
    zone   = factor(zone),
    action = factor(action, levels = c("contest","leverage","backup","hold"))
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

x_out <- model.matrix(~ . - 1, data = out_df)
y_out <- df$yac

cat("[34.4] Outcome feature matrix: ", nrow(x_out), " x ", ncol(x_out), "\\n", sep = "")

# -------------------------------------------------------------------
# 4. Restrict to VAL split and compute predictions
# -------------------------------------------------------------------

val_idx <- which(df$split == "val")

if (length(val_idx) == 0L) {
  stop("[34.4] No rows with split == 'val' after filtering; cannot compute validation uplift.",
       call. = FALSE)
}

x_val <- x_out[val_idx, , drop = FALSE]
y_val <- y_out[val_idx]

cat("[34.4] VAL rows for uplift: ", length(y_val), "\\n", sep = "")

impact_model <- readRDS(PATH$impact_model_rds)

if (is.null(impact_model$outcome_model)) {
  stop("[34.4] impact_model_yac_v3.rds does not contain an outcome_model.", call. = FALSE)
}

xgb_fit <- impact_model$outcome_model
feat_train <- impact_model$feature_names_out

# Align VAL design matrix columns with training feature set
missing_cols <- setdiff(feat_train, colnames(x_val))
extra_cols   <- setdiff(colnames(x_val), feat_train)

if (length(extra_cols)) {
  warning("[34.4] Extra columns in VAL design matrix not seen at training: ",
          paste(extra_cols, collapse = ", "),
          " -- dropping them.")
}

# Add any missing training columns as zeros
if (length(missing_cols)) {
  warning("[34.4] Adding missing training feature columns to VAL matrix as zeros: ",
          paste(missing_cols, collapse = ", "))
  for (nm in missing_cols) {
    x_val <- cbind(x_val, setNames(list(rep(0, nrow(x_val))), nm))
  }
}

# Reorder columns to match training
x_val <- x_val[, feat_train, drop = FALSE]

dval <- xgboost::xgb.DMatrix(data = x_val)

pred_val <- as.numeric(predict(xgb_fit, newdata = dval))

# -------------------------------------------------------------------
# 5. Compute uplift vs constant baseline on VAL
# -------------------------------------------------------------------

rmse <- function(pred, y) {
  ok <- is.finite(pred) & is.finite(y)
  pred <- pred[ok]; y <- y[ok]
  if (length(y) == 0L) return(NA_real_)
  sqrt(mean((pred - y)^2))
}

baseline_mean <- mean(y_val[is.finite(y_val)])
rmse_model    <- rmse(pred_val, y_val)
rmse_base     <- rmse(rep(baseline_mean, length(y_val)), y_val)
uplift_hat    <- rmse_base - rmse_model  # >0 means outcome model beats constant baseline

cat(sprintf("[34.4] Baseline RMSE (VAL): %.4f\n", rmse_base))
cat(sprintf("[34.4] Model RMSE (VAL): %.4f\n", rmse_model))
cat(sprintf("[34.4] Point estimate uplift (baseline_rmse - model_rmse): %.4f\n", uplift_hat))

# -------------------------------------------------------------------
# 6. Bootstrap CI for uplift
# -------------------------------------------------------------------

B <- 1000L
n_val <- length(y_val)
uplift_boot <- numeric(B)

set.seed(343L)

for (b in seq_len(B)) {
  idx <- sample.int(n_val, size = n_val, replace = TRUE)
  y_b   <- y_val[idx]
  pred_b <- pred_val[idx]
  
  rmse_model_b <- rmse(pred_b, y_b)
  rmse_base_b  <- rmse(rep(baseline_mean, length(y_b)), y_b)
  
  uplift_boot[b] <- rmse_base_b - rmse_model_b
}

uplift_ci <- quantile(uplift_boot, probs = c(0.025, 0.975), na.rm = TRUE)
uplift_lo <- as.numeric(uplift_ci[1])
uplift_hi <- as.numeric(uplift_ci[2])

uplift_pass <- is.finite(uplift_lo) && (uplift_lo > 0)

cat(sprintf("[34.4] 95%% bootstrap CI for uplift: [%.4f, %.4f]\n", uplift_lo, uplift_hi))
cat(sprintf("[34.4] uplift_pass (CI lower > 0): %s\n", uplift_pass))

# -------------------------------------------------------------------
# 7. Combine with 34's overlap_ok and write status
# -------------------------------------------------------------------

overlap_ok <- NA
if (file.exists(PATH$status_34_csv)) {
  status34 <- readr::read_csv(PATH$status_34_csv, show_col_types = FALSE)
  if ("overlap_ok" %in% names(status34)) {
    overlap_ok <- isTRUE(status34$overlap_ok[1])
  }
}

overall_pass <- isTRUE(overlap_ok) && uplift_pass

status <- tibble(
  script              = "34.4_outcome_model_yac_uplift.R",
  n_val               = length(y_val),
  baseline_rmse_val   = rmse_base,
  model_rmse_val      = rmse_model,
  uplift_rmse         = uplift_hat,
  uplift_lo           = uplift_lo,
  uplift_hi           = uplift_hi,
  uplift_pass         = uplift_pass,
  bootstrap_B         = B,
  baseline_mean_yac   = baseline_mean,
  overlap_ok_34_3     = overlap_ok,
  overall_pass        = overall_pass
)

readr::write_csv(status, PATH$out_status_csv)

# -------------------------------------------------------------------
# 8. Markdown report
# -------------------------------------------------------------------

md_lines <- c(
  "# 34.4_outcome_model_yac_uplift",
  "",
  "- Script: Code/34.4_outcome_model_yac_uplift.R",
  sprintf("- VAL rows: %d", status$n_val),
  "",
  "## Uplift vs constant-baseline YAC (VAL split)",
  sprintf("- Baseline RMSE (VAL, mean YAC): %.4f", status$baseline_rmse_val),
  sprintf("- Model RMSE (VAL, impact_model_yac_v3): %.4f", status$model_rmse_val),
  sprintf("- Uplift (baseline_rmse - model_rmse): %.4f", status$uplift_rmse),
  sprintf("- 95%% CI for uplift: [%.4f, %.4f]", status$uplift_lo, status$uplift_hi),
  sprintf("- uplift_pass (CI lower > 0): %s", status$uplift_pass),
  "",
  "## Combined acceptance with 34.3_outcome_model_yac.R",
  sprintf("- overlap_ok (34.3): %s", status$overlap_ok_34_3),
  sprintf("- overall_pass (overlap_ok AND uplift_pass): %s", status$overall_pass)
)

writeLines(md_lines, PATH$out_status_md)

cat("[34.4] Wrote uplift status to ",
    PATH$out_status_csv, " and ", PATH$out_status_md, "\n", sep = "")

if (!overall_pass) {
  stop("[34.4] Overall acceptance FAILED (either overlap or uplift). See uplift status for details.",
       call. = FALSE)
} else {
  cat("[34.4] Overall acceptance PASSED (overlap_ok AND uplift CI lower > 0).\n")
}

cat("[34.4] Finished 34.4_outcome_model_yac_uplift.R\n")










# 35_counterfactual_scoring.R
# CLI: Rscript Code/35_counterfactual_scoring.R
#
# Purpose:
#   Use the validated impact model (impact_model_v3.rds) to score
#   defender decision quality on ball-in-air snaps:
#     - Compare observed action vs role-level alternatives
#     - Integrate independent heading search (θ*) and coordination (if available)
#     - Produce per-defender DQS and missed-opportunity summaries
#
# Design notes:
#   - This script is a *consumer* of Phase-3 artifacts:
#       * v2_model04_leverage_dataset.csv
#       * eligibility_v3.csv
#       * affordances_v3.csv
#       * direction_recommendations_v3.csv
#       * coordination_set_v3.csv (optional but recommended)
#       * impact_model_v3.rds  (from 34_outcome_model_dr.R)
#   - It does NOT refit any models.
#   - Defensive value = -EPA (offense-centric EPA from 34).
#   - Primary DQS definition:
#         DQS = EV_def(optimal) - EV_def(observed)
#     where EV_def(optimal) is the best available defensive EV across:
#       (a) role-level actions (contest/leverage/backup/hold, respecting eligibility)
#       (b) independent heading action (θ* vs chase), if available
#       (c) coordination bundle, if available (from 33_coordination_search.R)
#
# Outputs:
#   - artifacts/impact_scores_v3.csv
#   - artifacts/missed_opportunities_v3.csv
#   - artifacts/bars_obs_vs_avail_v3.png
#   - artifacts/missed_op_leaderboard_v3.png
#   - artifacts/35_counterfactual_scoring_status.{csv,md}
#

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(xgboost)
  library(readr)
}))

cat("[35] Starting 35_counterfactual_scoring.R\n")

set.seed(2035L)

# -------------------------------------------------------------------
# Paths and constants
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2            = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig            = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff             = file.path(DIR$artifacts, "affordances_v3.csv"),
  dirrec          = file.path(DIR$artifacts, "direction_recommendations_v3.csv"),
  coord           = file.path(DIR$artifacts, "coordination_set_v3.csv"),
  impact_model_rds= file.path(DIR$artifacts, "impact_model_v3.rds"),
  out_scores      = file.path(DIR$artifacts, "impact_scores_v3.csv"),
  out_missed      = file.path(DIR$artifacts, "missed_opportunities_v3.csv"),
  out_bars_png    = file.path(DIR$artifacts, "bars_obs_vs_avail_v3.png"),
  out_leader_png  = file.path(DIR$artifacts, "missed_op_leaderboard_v3.png"),
  out_status_csv  = file.path(DIR$artifacts, "35_counterfactual_scoring_status.csv"),
  out_status_md   = file.path(DIR$artifacts, "35_counterfactual_scoring_status.md")
)

for (nm in c("lev2","elig","aff","dirrec","impact_model_rds")) {
  p <- PATH[[nm]]
  if (!file.exists(p)) {
    stop("[35] Missing required artifact: ", p,
         ". Run upstream Phase-3 scripts first.")
  }
}

HAS_COORD <- file.exists(PATH$coord)
if (!HAS_COORD) {
  warning("[35] coordination_set_v3.csv not found; team coordination DQS will be skipped.")
}

# Tunable thresholds
VALUE_EPS           <- 0.02   # snap is "low-value" if role EV spread < 0.02 EPA
DQS_BIG             <- 0.02   # big-miss threshold in defensive EV units (tuned to this model's scale)
LOW_VALUE_MEDIAN_MAX <- 0.15  # max allowed median |DQS| on low-value snaps
LOW_VALUE_Q90_MAX    <- 0.50  # max allowed 90th percentile |DQS| on low-value snaps
MIN_PROP_BIG_MISS    <- 0.01  # require at least 1% of snaps to be "big misses"

# -------------------------------------------------------------------
# 1. Load data and rebuild base table (mirror 34)
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

dirrec <- readr::read_csv(PATH$dirrec, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

coord <- NULL
if (HAS_COORD) {
  coord <- readr::read_csv(PATH$coord, show_col_types = FALSE) %>%
    clean_names() %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
}

# Join to mirror 34's base, then enrich with θ* and coordination info
base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone = as.character(zone)
  ) %>%
  left_join(
    dirrec %>%
      select(
        game_id, play_id, nfl_id, split,
        theta_star_deg, theta_star_abs_deg,
        delta_ev_hat, theta_sd_deg,
        backup_point_x, backup_point_y
      ),
    by = c("game_id","play_id","nfl_id","split")
  )

if (!is.null(coord)) {
  base <- base %>%
    left_join(
      coord %>%
        select(
          game_id, play_id, nfl_id, split,
          has_theta, ev_theta, ev_indep,
          independent_action,
          edge_contain, gain_theta,
          coord_action, ev_coord,
          ev_team_indep, ev_team_coord,
          bundle_id
        ),
      by = c("game_id","play_id","nfl_id","split")
    )
}

# -------------------------------------------------------------------
# 2. Observed action and modelling filter (as in 34)
# -------------------------------------------------------------------

base <- base %>%
  mutate(
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action_obs = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action_obs = factor(action_obs,
                        levels = c("contest","leverage","backup","hold"))
  )

df <- base %>%
  filter(is.finite(epa),
         !is.na(action_obs)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))

cat("[35] Rows after filtering (all splits): ", nrow(df), "\n", sep = "")

if (nrow(df) < 1000) {
  warning("[35] Fewer than 1000 rows for impact scoring; results may be noisy.")
}

# -------------------------------------------------------------------
# 3. Load impact model and build scenario design matrix
# -------------------------------------------------------------------

impact_model <- readRDS(PATH$impact_model_rds)
if (is.null(impact_model$outcome_model)) {
  stop("[35] impact_model_v3.rds does not contain an outcome_model.")
}

xgb_fit      <- impact_model$outcome_model
feat_train   <- impact_model$feature_names_out
action_levels <- impact_model$action_levels

if (is.null(action_levels)) {
  action_levels <- c("contest","leverage","backup","hold")
}

# Shared feature set (same as 34)
feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing_feats <- setdiff(feat_vars, names(df))
if (length(missing_feats)) {
  warning("[35] Missing feature columns in df: ",
          paste(missing_feats, collapse = ", "),
          " -- dropping them for scoring.")
  feat_vars <- intersect(feat_vars, names(df))
}

# Expand df into one row per (defender, play, scenario_action)
n_actions <- length(action_levels)

n_df <- nrow(df)

scenarios <- df %>%
  mutate(row_id = dplyr::row_number()) %>%
  { .[rep(seq_len(n_df), each = n_actions), , drop = FALSE] } %>%
  mutate(
    scenario_action = factor(rep(action_levels, times = n_df),
                             levels = action_levels)
  )

# Build outcome feature frame for scenarios
out_df_scen <- scenarios %>%
  mutate(
    zone   = factor(zone),
    action = factor(scenario_action, levels = action_levels)
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

x_scen <- model.matrix(~ . - 1, data = out_df_scen)

# Align columns with training feature set
extra_cols <- setdiff(colnames(x_scen), feat_train)
if (length(extra_cols)) {
  warning("[35] Extra columns in scenario design not seen at training: ",
          paste(extra_cols, collapse = ", "),
          " -- dropping them.")
  keep <- setdiff(colnames(x_scen), extra_cols)
  x_scen <- x_scen[, keep, drop = FALSE]
}

missing_cols <- setdiff(feat_train, colnames(x_scen))
if (length(missing_cols)) {
  warning("[35] Adding missing training feature columns to scenarios as zeros: ",
          paste(missing_cols, collapse = ", "))
  for (nm in missing_cols) {
    x_scen <- cbind(x_scen, rep(0, nrow(x_scen)))
    colnames(x_scen)[ncol(x_scen)] <- nm
  }
}

# Reorder columns
x_scen <- x_scen[, feat_train, drop = FALSE]

dmat_scen <- xgboost::xgb.DMatrix(data = x_scen)

cat("[35] Scenario design matrix: ", nrow(x_scen), " x ", ncol(x_scen), "\n", sep = "")

epa_hat_vec <- as.numeric(predict(xgb_fit, newdata = dmat_scen))
scenarios$epa_hat <- epa_hat_vec

# -------------------------------------------------------------------
# 4. Collapse scenarios back to per-defender rows with role EV
# -------------------------------------------------------------------

role_wide <- scenarios %>%
  transmute(
    game_id, play_id, nfl_id, split,
    scenario_action = as.character(scenario_action),
    epa_hat = epa_hat
  ) %>%
  tidyr::pivot_wider(
    names_from  = scenario_action,
    values_from = epa_hat,
    names_prefix = "epa_hat_"
  )

# Join role-level predictions back to df
df_scored <- df %>%
  left_join(role_wide,
            by = c("game_id","play_id","nfl_id","split"))

# Sanity check: require predictions for all four actions
required_epa_cols <- paste0("epa_hat_", action_levels)
missing_epa_cols <- setdiff(required_epa_cols, names(df_scored))
if (length(missing_epa_cols)) {
  stop("[35] Missing EPA prediction columns after scenario collapse: ",
       paste(missing_epa_cols, collapse = ", "))
}

df_scored <- df_scored %>%
  mutate(
    epa_hat_contest  = .data[[required_epa_cols[1]]],
    epa_hat_leverage = .data[[required_epa_cols[2]]],
    epa_hat_backup   = .data[[required_epa_cols[3]]],
    epa_hat_hold     = .data[[required_epa_cols[4]]]
  )

# Defensive EV: negative EPA
df_scored <- df_scored %>%
  mutate(
    ev_def_contest  = -epa_hat_contest,
    ev_def_leverage = -epa_hat_leverage,
    ev_def_backup   = -epa_hat_backup,
    ev_def_hold     = -epa_hat_hold,
    epa_hat_obs = dplyr::case_when(
      action_obs == "contest"  ~ epa_hat_contest,
      action_obs == "leverage" ~ epa_hat_leverage,
      action_obs == "backup"   ~ epa_hat_backup,
      action_obs == "hold"     ~ epa_hat_hold,
      TRUE ~ NA_real_
    ),
    ev_def_obs = -epa_hat_obs
  )

# -------------------------------------------------------------------
# 5. Role-level optimal EV and DQS_role
# -------------------------------------------------------------------

df_scored <- df_scored %>%
  mutate(
    ev_def_contest_elig = if_else(contest_eligible, ev_def_contest, NA_real_),
    ev_def_leverage_elig = if_else(leverage_eligible, ev_def_leverage, NA_real_),
    ev_def_backup_elig   = if_else(backup_eligible, ev_def_backup, NA_real_),
    ev_def_hold_elig     = ev_def_hold,  # hold always available
    ev_def_opt_role = pmax(
      ev_def_contest_elig,
      ev_def_leverage_elig,
      ev_def_backup_elig,
      ev_def_hold_elig,
      na.rm = TRUE
    )
  ) %>%
  mutate(
    action_opt_role = case_when(
      is.finite(ev_def_contest_elig)  & ev_def_contest_elig  == ev_def_opt_role ~ "contest",
      is.finite(ev_def_leverage_elig) & ev_def_leverage_elig == ev_def_opt_role ~ "leverage",
      is.finite(ev_def_backup_elig)   & ev_def_backup_elig   == ev_def_opt_role ~ "backup",
      TRUE ~ "hold"
    ),
    dqs_role = ev_def_opt_role - ev_def_obs,
    value_spread_role = pmax(ev_def_contest, ev_def_leverage,
                             ev_def_backup, ev_def_hold, na.rm = TRUE) -
      pmin(ev_def_contest, ev_def_leverage,
           ev_def_backup, ev_def_hold, na.rm = TRUE)
  )

# -------------------------------------------------------------------
# 6. Independent heading and coordination DQS
# -------------------------------------------------------------------

# If coordination_set_v3 is missing, build ev_indep ourselves from θ* search
if (is.null(coord)) {
  df_scored <- df_scored %>%
    mutate(
      has_theta = is.finite(theta_star_deg) & is.finite(delta_ev_hat),
      ev_chase  = ev_chase,
      ev_theta  = if_else(has_theta,
                          ev_chase + delta_ev_hat,
                          NA_real_),
      ev_indep = case_when(
        has_theta & is.finite(ev_theta) & (ev_theta < ev_chase) ~ ev_theta,
        TRUE ~ ev_chase
      ),
      independent_action = case_when(
        has_theta & is.finite(ev_theta) & (ev_theta < ev_chase) ~ "theta_star",
        TRUE ~ "chase"
      ),
      ev_coord       = NA_real_,
      ev_team_indep  = NA_real_,
      ev_team_coord  = NA_real_,
      coord_action   = NA_character_,
      bundle_id      = NA_integer_
    )
}

df_scored <- df_scored %>%
  mutate(
    ev_off_indep      = ev_indep,
    ev_off_coord      = ev_coord,
    ev_off_team_indep = ev_team_indep,
    ev_off_team_coord = ev_team_coord,
    ev_def_indep      = -ev_off_indep,
    ev_def_coord      = -ev_off_coord,
    ev_def_team_indep = -ev_off_team_indep,
    ev_def_team_coord = -ev_off_team_coord,
    dqs_heading       = if_else(
      is.finite(ev_def_indep),
      ev_def_indep - ev_def_obs,
      NA_real_
    ),
    dqs_coord_defender = if_else(
      is.finite(ev_def_coord),
      ev_def_coord - ev_def_obs,
      NA_real_
    ),
    dqs_coord_team = if_else(
      is.finite(ev_def_team_coord) & is.finite(ev_def_team_indep),
      ev_def_team_coord - ev_def_team_indep,
      NA_real_
    )
  )

# -------------------------------------------------------------------
# 7. Final optimal EV and primary DQS
# -------------------------------------------------------------------

df_scored <- df_scored %>%
  mutate(
    ev_def_opt_all = pmax(
      ev_def_opt_role,
      if_else(is.finite(ev_def_indep), ev_def_indep, -Inf),
      if_else(is.finite(ev_def_coord), ev_def_coord, -Inf),
      na.rm = TRUE
    ),
    source_opt = case_when(
      ev_def_opt_all == ev_def_opt_role ~ "role_only",
      ev_def_opt_all == ev_def_indep   ~ "heading",
      ev_def_opt_all == ev_def_coord   ~ "coord",
      TRUE ~ "role_only"
    ),
    dqs = ev_def_opt_all - ev_def_obs,
    is_low_value_snap = value_spread_role < VALUE_EPS,
    is_big_miss       = dqs >= DQS_BIG
  )

# -------------------------------------------------------------------
# 8. Write impact_scores_v3.csv
# -------------------------------------------------------------------

impact_scores <- df_scored %>%
  select(
    game_id, play_id, nfl_id, split,
    ext_defense_team,
    ext_offense_team,
    ext_position,
    epa,
    zone, r, loi, bv,
    d_start, d_min, d_arrival, p_reach_start, p_reach_max, p_reach,
    t_ball, sep_throw,
    contest_eligible, leverage_eligible, backup_eligible, hold,
    action_obs, action_opt_role,
    theta_star_deg, theta_star_abs_deg, delta_ev_hat, theta_sd_deg,
    backup_point_x, backup_point_y,
    has_theta, independent_action,
    coord_action, bundle_id,
    ev_chase, ev_theta,
    ev_leverage, ev_backup,
    ev_off_indep, ev_off_coord,
    ev_off_team_indep, ev_off_team_coord,
    epa_hat_contest, epa_hat_leverage, epa_hat_backup, epa_hat_hold,
    epa_hat_obs,
    ev_def_contest, ev_def_leverage, ev_def_backup, ev_def_hold,
    ev_def_obs, ev_def_opt_role, ev_def_indep, ev_def_coord,
    ev_def_team_indep, ev_def_team_coord,
    dqs_role, dqs_heading, dqs_coord_defender, dqs_coord_team,
    ev_def_opt_all, source_opt,
    dqs, value_spread_role,
    is_low_value_snap, is_big_miss
  )

readr::write_csv(impact_scores, PATH$out_scores)
cat("[35] Wrote impact_scores_v3 to ", PATH$out_scores, " (",
    nrow(impact_scores), " rows)\n", sep = "")

# -------------------------------------------------------------------
# 9. Missed opportunities table
# -------------------------------------------------------------------

missed <- impact_scores %>%
  filter(is_big_miss) %>%
  arrange(desc(dqs)) %>%
  mutate(rank_dqs = dplyr::row_number())

readr::write_csv(missed, PATH$out_missed)
cat("[35] Wrote missed_opportunities_v3 to ", PATH$out_missed, " (",
    nrow(missed), " rows)\n", sep = "")

# -------------------------------------------------------------------
# 10. Figures
# -------------------------------------------------------------------

# 10a. Distribution of observed vs optimal defensive EV
plot_df <- impact_scores %>%
  select(ev_def_obs, ev_def_opt_all) %>%
  tidyr::pivot_longer(
    cols = everything(),
    names_to = "series",
    values_to = "ev_def"
  )

p_bars <- ggplot(plot_df, aes(x = ev_def, fill = series)) +
  geom_density(alpha = 0.4) +
  labs(
    title = "Observed vs optimal defensive EV (impact model v3)",
    x     = "Defensive EV (higher is better)",
    y     = "Density",
    fill  = "Series"
  ) +
  theme_minimal()

ggsave(PATH$out_bars_png, plot = p_bars, width = 7, height = 4, dpi = 150)
cat("[35] Wrote bars_obs_vs_avail_v3.png to ", PATH$out_bars_png, "\n", sep = "")

# 10b. Missed-opportunity leaderboard (per defender)
leader_df <- impact_scores %>%
  group_by(ext_defense_team, nfl_id, ext_position) %>%
  summarise(
    n_snaps      = dplyr::n(),
    n_big_miss   = sum(is_big_miss, na.rm = TRUE),
    dqs_mean     = mean(dqs, na.rm = TRUE),
    dqs_median   = stats::median(dqs[is.finite(dqs)]),
    dqs_big_mean = if (n_big_miss > 0) mean(dqs[is_big_miss], na.rm = TRUE) else NA_real_,
    .groups      = "drop"
  ) %>%
  filter(n_snaps >= 10) %>%
  arrange(desc(dqs_big_mean)) %>%
  slice_head(n = 25L) %>%
  mutate(defender_label = paste0(ext_defense_team, " #", nfl_id, " (", ext_position, ")"))

p_leader <- ggplot(leader_df,
                   aes(x = reorder(defender_label, dqs_big_mean),
                       y = dqs_big_mean)) +
  geom_col() +
  coord_flip() +
  labs(
    title = "Top defenders by mean DQS on big-miss snaps",
    x     = "Defender",
    y     = "Mean DQS on big-miss snaps"
  ) +
  theme_minimal()

ggsave(PATH$out_leader_png, plot = p_leader, width = 7, height = 6, dpi = 150)
cat("[35] Wrote missed_op_leaderboard_v3.png to ", PATH$out_leader_png, "\n", sep = "")

# -------------------------------------------------------------------
# 11. Diagnostics and acceptance criteria
# -------------------------------------------------------------------

n_total <- nrow(impact_scores)

# DQS distribution
dqs_vals <- impact_scores$dqs
dqs_mean <- mean(dqs_vals, na.rm = TRUE)
dqs_med  <- stats::median(dqs_vals[is.finite(dqs_vals)])
dqs_sd   <- stats::sd(dqs_vals[is.finite(dqs_vals)])
dqs_q    <- quantile(dqs_vals[is.finite(dqs_vals)],
                     probs = c(0.05,0.25,0.5,0.75,0.95,0.99),
                     na.rm = TRUE)

# Low-value snaps
low_idx <- impact_scores$is_low_value_snap
dqs_low <- dqs_vals[low_idx]
dqs_abs_median_low <- if (any(low_idx)) stats::median(abs(dqs_low[is.finite(dqs_low)])) else NA_real_
dqs_abs_q90_low    <- if (any(low_idx)) quantile(abs(dqs_low[is.finite(dqs_low)]),
                                                 probs = 0.90, na.rm = TRUE) else NA_real_

prop_low_value <- if (n_total > 0) mean(low_idx) else NA_real_

# Positive tail
big_idx <- impact_scores$is_big_miss
prop_big_miss <- if (n_total > 0) mean(big_idx) else NA_real_
dqs_big       <- dqs_vals[big_idx]
dqs_big_q50   <- if (any(big_idx)) stats::median(dqs_big[is.finite(dqs_big)]) else NA_real_
dqs_big_q90   <- if (any(big_idx)) quantile(dqs_big[is.finite(dqs_big)], probs = 0.90, na.rm = TRUE) else NA_real_

# Predictive sanity: correlation with realised -EPA
ev_def_obs_vec <- impact_scores$ev_def_obs
def_outcome    <- -impact_scores$epa

cor_evdef_obs_real <- suppressWarnings(
  stats::cor(ev_def_obs_vec, def_outcome, use = "complete.obs")
)

# Acceptance
pass_low_value <- is.finite(dqs_abs_median_low) &&
  is.finite(dqs_abs_q90_low) &&
  (dqs_abs_median_low <= LOW_VALUE_MEDIAN_MAX) &&
  (dqs_abs_q90_low    <= LOW_VALUE_Q90_MAX)

pass_tail_shape <- is.finite(prop_big_miss) && (prop_big_miss >= MIN_PROP_BIG_MISS)

pass <- pass_low_value && pass_tail_shape

status <- tibble(
  script                    = "35_counterfactual_scoring.R",
  n_rows                    = n_total,
  n_rows_low_value          = sum(low_idx, na.rm = TRUE),
  n_rows_big_miss           = sum(big_idx, na.rm = TRUE),
  prop_low_value            = prop_low_value,
  prop_big_miss             = prop_big_miss,
  dqs_mean                  = dqs_mean,
  dqs_median                = dqs_med,
  dqs_sd                    = dqs_sd,
  dqs_q05                   = dqs_q[[1]],
  dqs_q25                   = dqs_q[[2]],
  dqs_q50                   = dqs_q[[3]],
  dqs_q75                   = dqs_q[[4]],
  dqs_q95                   = dqs_q[[5]],
  dqs_q99                   = dqs_q[[6]],
  dqs_abs_median_low_value  = dqs_abs_median_low,
  dqs_abs_q90_low_value     = dqs_abs_q90_low,
  dqs_big_miss_q50          = dqs_big_q50,
  dqs_big_miss_q90          = dqs_big_q90,
  cor_evdef_obs_real        = cor_evdef_obs_real,
  value_eps                 = VALUE_EPS,
  dqs_big_threshold         = DQS_BIG,
  low_value_median_max      = LOW_VALUE_MEDIAN_MAX,
  low_value_q90_max         = LOW_VALUE_Q90_MAX,
  min_prop_big_miss         = MIN_PROP_BIG_MISS,
  pass_low_value            = pass_low_value,
  pass_tail_shape           = pass_tail_shape,
  pass                      = pass
)

readr::write_csv(status, PATH$out_status_csv)

# Markdown report
md_lines <- c(
  "# 35_counterfactual_scoring Status",
  "",
  "- Script: Code/35_counterfactual_scoring.R",
  "",
  sprintf("- n_rows: %d", status$n_rows),
  sprintf("- prop_low_value: %.3f", status$prop_low_value),
  sprintf("- prop_big_miss: %.3f", status$prop_big_miss),
  "",
  "## DQS distribution",
  sprintf("- mean: %.4f", status$dqs_mean),
  sprintf("- median: %.4f", status$dqs_median),
  sprintf("- sd: %.4f", status$dqs_sd),
  sprintf("- q05/q25/q50/q75/q95/q99: %.4f / %.4f / %.4f / %.4f / %.4f / %.4f",
          status$dqs_q05, status$dqs_q25, status$dqs_q50,
          status$dqs_q75, status$dqs_q95, status$dqs_q99),
  "",
  "## Low-value snaps (spread below VALUE_EPS)",
  sprintf("- VALUE_EPS: %.3f", status$value_eps),
  sprintf("- |DQS| median (low-value): %.4f", status$dqs_abs_median_low_value),
  sprintf("- |DQS| q90 (low-value): %.4f", status$dqs_abs_q90_low_value),
  sprintf("- pass_low_value: %s", status$pass_low_value),
  "",
  "## Big-miss tail",
  sprintf("- DQS_BIG: %.3f", status$dqs_big_threshold),
  sprintf("- prop_big_miss: %.4f", status$prop_big_miss),
  sprintf("- DQS big-miss q50: %.4f", status$dqs_big_miss_q50),
  sprintf("- DQS big-miss q90: %.4f", status$dqs_big_miss_q90),
  sprintf("- pass_tail_shape: %s", status$pass_tail_shape),
  "",
  "## Predictive sanity",
  sprintf("- cor(ev_def_obs, -epa): %.4f", status$cor_evdef_obs_real),
  "",
  sprintf("- PASS (low_value & tail_shape): %s", status$pass)
)

writeLines(md_lines, PATH$out_status_md)

cat("[35] Wrote status CSV to ", PATH$out_status_csv, " and MD to ",
    PATH$out_status_md, "\n", sep = "")

if (!pass) {
  stop("[35] Overall acceptance FAILED (see status for details).", call. = FALSE)
} else {
  cat("[35] Overall acceptance PASSED.\n")
}

cat("[35] Finished 35_counterfactual_scoring.R\n")










# 35.2_counterfactual_scoring_yac.R
# CLI: Rscript Code/35.2_counterfactual_scoring_yac.R
#
# Purpose:
#   Use the validated YAC impact model (impact_model_yac_v3.rds) to score
#   defender decision quality on ball-in-air snaps:
#     - Compare observed action vs role-level alternatives
#     - Produce per-defender YAC-based decision quality scores (dqs_yac).
#
#   This mirrors 35_counterfactual_scoring.R but:
#     * Uses YAC instead of EPA.
#     * Optimises over the role action set {contest, leverage, backup, hold}.
#     * Does not introduce heading/coordination in the YAC DQS (role-only).

suppressWarnings(suppressMessages({
  library(tidyverse)
  library(janitor)
  library(readr)
  library(xgboost)
}))

cat("[35.2] Starting 35.2_counterfactual_scoring_yac.R\n")

set.seed(352L)

# -------------------------------------------------------------------
# Paths and constants
# -------------------------------------------------------------------

DIR <- list(
  artifacts = "artifacts"
)

PATH <- list(
  lev2                 = file.path(DIR$artifacts, "v2_model04_leverage_dataset.csv"),
  elig                 = file.path(DIR$artifacts, "eligibility_v3.csv"),
  aff                  = file.path(DIR$artifacts, "affordances_v3.csv"),
  dirrec               = file.path(DIR$artifacts, "direction_recommendations_v3.csv"),
  coord                = file.path(DIR$artifacts, "coordination_set_v3.csv"),
  impact_model_yac_rds = file.path(DIR$artifacts, "impact_model_yac_v3.rds"),
  out_scores           = file.path(DIR$artifacts, "impact_scores_yac_v3.csv"),
  out_missed           = file.path(DIR$artifacts, "missed_opportunities_yac_v3.csv"),
  out_status_csv       = file.path(DIR$artifacts, "35.2_counterfactual_scoring_yac_status.csv"),
  out_status_md        = file.path(DIR$artifacts, "35.2_counterfactual_scoring_yac_status.md")
)

for (nm in c("lev2","elig","aff","dirrec","impact_model_yac_rds")) {
  p <- PATH[[nm]]
  if (!file.exists(p)) {
    stop("[35.2] Missing required artifact: ", p,
         ". Run upstream Phase-3 scripts (including 34.3/34.4) first.")
  }
}

HAS_COORD <- file.exists(PATH$coord)
if (!HAS_COORD) {
  warning("[35.2] coordination_set_v3.csv not found; team coordination YAC DQS will be skipped.")
}

# Tunable thresholds (YAC units: yards)
VALUE_EPS_YAC        <- 0.50   # snap is "low-value" if role defensive YAC spread < 0.5 yards
DQS_BIG_YAC          <- 0.50   # big-miss threshold in defensive YAC units
LOW_VALUE_MEDIAN_MAX <- 0.25   # max allowed median |DQS_yac| on low-value snaps
LOW_VALUE_Q90_MAX    <- 1.50   # max allowed 90th percentile |DQS_yac| on low-value snaps
MIN_PROP_BIG_MISS    <- 0.01   # require at least 1% of snaps to be "big misses"

# -------------------------------------------------------------------
# 1. Load data and rebuild base table (mirror 35)
# -------------------------------------------------------------------

lev2 <- readr::read_csv(PATH$lev2, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

elig <- readr::read_csv(PATH$elig, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

aff <- readr::read_csv(PATH$aff, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

dirrec <- readr::read_csv(PATH$dirrec, show_col_types = FALSE) %>%
  clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

coord <- NULL
if (HAS_COORD) {
  coord <- readr::read_csv(PATH$coord, show_col_types = FALSE) %>%
    clean_names() %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
}

# Join to mirror 34/35 base, then enrich with θ* and coordination info (as context)
base <- lev2 %>%
  left_join(
    elig %>% select(
      game_id, play_id, nfl_id, split,
      p_reach, t_ball, contest_eligible,
      leverage_eligible, backup_eligible, hold
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  left_join(
    aff %>% select(
      game_id, play_id, nfl_id, split,
      r, loi, bv, sep_throw, zone,
      ev_leverage, ev_chase, ev_backup
    ),
    by = c("game_id","play_id","nfl_id","split")
  ) %>%
  mutate(
    zone = as.character(zone)
  ) %>%
  left_join(
    dirrec %>%
      select(
        game_id, play_id, nfl_id, split,
        theta_star_deg, theta_star_abs_deg,
        delta_ev_hat, theta_sd_deg,
        backup_point_x, backup_point_y
      ),
    by = c("game_id","play_id","nfl_id","split")
  )

if (!is.null(coord)) {
  base <- base %>%
    left_join(
      coord %>%
        select(
          game_id, play_id, nfl_id, split,
          has_theta, ev_theta, ev_indep,
          independent_action,
          edge_contain, gain_theta,
          coord_action, ev_coord,
          ev_team_indep, ev_team_coord,
          bundle_id
        ),
      by = c("game_id","play_id","nfl_id","split")
    )
}

# -------------------------------------------------------------------
# 2. Observed action and modelling filter (as in 34/35)
# -------------------------------------------------------------------

base <- base %>%
  mutate(
    contest_primary   = dplyr::coalesce(as.logical(contest_primary), FALSE),
    contest_eligible  = dplyr::coalesce(as.logical(contest_eligible), FALSE),
    leverage_eligible = dplyr::coalesce(as.logical(leverage_eligible), FALSE),
    backup_eligible   = dplyr::coalesce(as.logical(backup_eligible), FALSE),
    hold              = dplyr::coalesce(as.logical(hold), FALSE),
    action_obs = case_when(
      contest_primary ~ "contest",
      !contest_primary & leverage_eligible ~ "leverage",
      !contest_primary & !leverage_eligible & backup_eligible ~ "backup",
      TRUE ~ "hold"
    ),
    action_obs = factor(action_obs,
                        levels = c("contest","leverage","backup","hold"))
  )

df <- base %>%
  filter(is.finite(yac),
         !is.na(action_obs)) %>%
  filter(
    is.finite(d_start),
    is.finite(d_min),
    is.finite(d_arrival),
    is.finite(p_reach_start),
    is.finite(p_reach_max)
  ) %>%
  filter(is.finite(r))

cat("[35.2] Rows after filtering (all splits): ", nrow(df), "\n", sep = "")

if (nrow(df) < 1000) {
  warning("[35.2] Fewer than 1000 rows for YAC impact scoring; results may be noisy.")
}

# -------------------------------------------------------------------
# 3. Load YAC impact model and build scenario design matrix
# -------------------------------------------------------------------

impact_model_yac <- readRDS(PATH$impact_model_yac_rds)
if (is.null(impact_model_yac$outcome_model)) {
  stop("[35.2] impact_model_yac_v3.rds does not contain an outcome_model.")
}

xgb_fit      <- impact_model_yac$outcome_model
feat_train   <- impact_model_yac$feature_names_out
action_levels <- impact_model_yac$action_levels

if (is.null(action_levels)) {
  action_levels <- c("contest","leverage","backup","hold")
}

# Shared feature set (same as 34/35)
feat_vars <- c(
  "d_start","p_reach_start","p_reach_max","d_min","d_arrival",
  "sep_throw","r","loi","bv",
  "ext_down","ext_distance","ext_ydstogo",
  "ext_quarter","ext_game_seconds_remaining",
  "ext_score_differential","ext_yardline_100",
  "ext_shotgun","ext_no_huddle",
  "p03_primary","p03_1p0"
)

missing_feats <- setdiff(feat_vars, names(df))
if (length(missing_feats)) {
  warning("[35.2] Missing feature columns in df: ",
          paste(missing_feats, collapse = ", "),
          " -- dropping them for YAC scoring.")
  feat_vars <- intersect(feat_vars, names(df))
}

# Expand df into one row per (defender, play, scenario_action)
n_actions <- length(action_levels)
n_df <- nrow(df)

scenarios <- df %>%
  mutate(row_id = dplyr::row_number()) %>%
  { .[rep(seq_len(n_df), each = n_actions), , drop = FALSE] } %>%
  mutate(
    scenario_action = factor(rep(action_levels, times = n_df),
                             levels = action_levels)
  )

# Build outcome feature frame for scenarios
out_df_scen <- scenarios %>%
  mutate(
    zone   = factor(zone),
    action = factor(scenario_action, levels = action_levels)
  ) %>%
  select(all_of(c("action","zone", feat_vars)))

x_scen <- model.matrix(~ . - 1, data = out_df_scen)

# Align columns with training feature set
extra_cols <- setdiff(colnames(x_scen), feat_train)
if (length(extra_cols)) {
  warning("[35.2] Extra columns in scenario design not seen at training: ",
          paste(extra_cols, collapse = ", "),
          " -- dropping them.")
  keep <- setdiff(colnames(x_scen), extra_cols)
  x_scen <- x_scen[, keep, drop = FALSE]
}

missing_cols <- setdiff(feat_train, colnames(x_scen))
if (length(missing_cols)) {
  warning("[35.2] Adding missing training feature columns to scenarios as zeros: ",
          paste(missing_cols, collapse = ", "))
  for (nm in missing_cols) {
    x_scen <- cbind(x_scen, rep(0, nrow(x_scen)))
    colnames(x_scen)[ncol(x_scen)] <- nm
  }
}

# Reorder columns
x_scen <- x_scen[, feat_train, drop = FALSE]

cat("[35.2] Scenario design matrix (YAC): ", nrow(x_scen), " x ", ncol(x_scen), "\n", sep = "")

yac_hat_vec <- as.numeric(predict(xgb_fit, newdata = x_scen))
scenarios$yac_hat <- yac_hat_vec

# -------------------------------------------------------------------
# 4. Collapse scenarios back to per-defender rows with role-level YAC EV
# -------------------------------------------------------------------

role_wide <- scenarios %>%
  transmute(
    game_id, play_id, nfl_id, split,
    scenario_action = as.character(scenario_action),
    yac_hat = yac_hat
  ) %>%
  tidyr::pivot_wider(
    names_from  = scenario_action,
    values_from = yac_hat,
    names_prefix = "yac_hat_"
  )

df_scored <- df %>%
  left_join(role_wide,
            by = c("game_id","play_id","nfl_id","split"))

required_yac_cols <- paste0("yac_hat_", action_levels)
missing_yac_cols <- setdiff(required_yac_cols, names(df_scored))
if (length(missing_yac_cols)) {
  stop("[35.2] Missing YAC prediction columns after scenario collapse: ",
       paste(missing_yac_cols, collapse = ", "))
}

df_scored <- df_scored %>%
  mutate(
    yac_hat_contest  = .data[[required_yac_cols[1]]],
    yac_hat_leverage = .data[[required_yac_cols[2]]],
    yac_hat_backup   = .data[[required_yac_cols[3]]],
    yac_hat_hold     = .data[[required_yac_cols[4]]]
  )

# Defensive YAC value: negative predicted YAC
df_scored <- df_scored %>%
  mutate(
    yac_def_contest  = -yac_hat_contest,
    yac_def_leverage = -yac_hat_leverage,
    yac_def_backup   = -yac_hat_backup,
    yac_def_hold     = -yac_hat_hold,
    yac_hat_obs = dplyr::case_when(
      action_obs == "contest"  ~ yac_hat_contest,
      action_obs == "leverage" ~ yac_hat_leverage,
      action_obs == "backup"   ~ yac_hat_backup,
      action_obs == "hold"     ~ yac_hat_hold,
      TRUE ~ NA_real_
    ),
    yac_def_obs = -yac_hat_obs
  )

# -------------------------------------------------------------------
# 5. Role-level optimal defensive YAC and DQS_yac
# -------------------------------------------------------------------

df_scored <- df_scored %>%
  mutate(
    yac_def_contest_elig  = dplyr::if_else(contest_eligible, yac_def_contest, NA_real_),
    yac_def_leverage_elig = dplyr::if_else(leverage_eligible, yac_def_leverage, NA_real_),
    yac_def_backup_elig   = dplyr::if_else(backup_eligible, yac_def_backup, NA_real_),
    yac_def_hold_elig     = yac_def_hold  # hold is always allowed
  ) %>%
  mutate(
    yac_def_opt_role = pmax(
      yac_def_contest_elig,
      yac_def_leverage_elig,
      yac_def_backup_elig,
      yac_def_hold_elig,
      na.rm = TRUE
    )
  ) %>%
  mutate(
    action_opt_role_yac = dplyr::case_when(
      is.finite(yac_def_contest_elig)  & yac_def_contest_elig  == yac_def_opt_role ~ "contest",
      is.finite(yac_def_leverage_elig) & yac_def_leverage_elig == yac_def_opt_role ~ "leverage",
      is.finite(yac_def_backup_elig)   & yac_def_backup_elig   == yac_def_opt_role ~ "backup",
      TRUE ~ "hold"
    ),
    dqs_yac_role = yac_def_opt_role - yac_def_obs,
    value_spread_yac_role = pmax(
      yac_def_contest, yac_def_leverage,
      yac_def_backup, yac_def_hold,
      na.rm = TRUE
    ) - pmin(
      yac_def_contest, yac_def_leverage,
      yac_def_backup, yac_def_hold,
      na.rm = TRUE
    )
  )

# For YAC we currently only use role-level optimisation
df_scored <- df_scored %>%
  mutate(
    yac_def_opt_all       = yac_def_opt_role,
    dqs_yac               = yac_def_opt_all - yac_def_obs,
    is_low_value_snap_yac = value_spread_yac_role < VALUE_EPS_YAC,
    is_big_miss_yac       = dqs_yac >= DQS_BIG_YAC
  )

# -------------------------------------------------------------------
# 6. Write impact_scores_yac_v3.csv
# -------------------------------------------------------------------

impact_scores_yac <- df_scored %>%
  select(
    game_id, play_id, nfl_id, split,
    ext_defense_team,
    ext_offense_team,
    ext_position,
    epa, yac,
    zone, r, loi, bv,
    d_start, d_min, d_arrival, p_reach_start, p_reach_max, p_reach,
    t_ball, sep_throw,
    contest_eligible, leverage_eligible, backup_eligible, hold,
    action_obs, action_opt_role_yac,
    theta_star_deg, theta_star_abs_deg, delta_ev_hat, theta_sd_deg,
    backup_point_x, backup_point_y,
    ev_chase,
    ev_leverage, ev_backup,
    yac_hat_contest, yac_hat_leverage, yac_hat_backup, yac_hat_hold,
    yac_hat_obs,
    yac_def_contest, yac_def_leverage, yac_def_backup, yac_def_hold,
    yac_def_obs, yac_def_opt_role, yac_def_opt_all,
    dqs_yac_role, dqs_yac, value_spread_yac_role,
    is_low_value_snap_yac, is_big_miss_yac
  )

readr::write_csv(impact_scores_yac, PATH$out_scores)
cat("[35.2] Wrote impact_scores_yac_v3 to ", PATH$out_scores, " (",
    nrow(impact_scores_yac), " rows)\n", sep = "")

# -------------------------------------------------------------------
# 7. Missed opportunities table (YAC)
# -------------------------------------------------------------------

missed_yac <- impact_scores_yac %>%
  filter(is_big_miss_yac) %>%
  arrange(desc(dqs_yac)) %>%
  mutate(rank_dqs_yac = dplyr::row_number())

readr::write_csv(missed_yac, PATH$out_missed)
cat("[35.2] Wrote missed_opportunities_yac_v3 to ", PATH$out_missed, " (",
    nrow(missed_yac), " rows)\n", sep = "")

# -------------------------------------------------------------------
# 8. Summaries and acceptance checks
# -------------------------------------------------------------------

n_total <- nrow(impact_scores_yac)

dqs_vals <- impact_scores_yac$dqs_yac
dqs_mean <- if (n_total > 0) mean(dqs_vals, na.rm = TRUE) else NA_real_
dqs_med  <- if (n_total > 0) stats::median(dqs_vals[is.finite(dqs_vals)]) else NA_real_
dqs_sd   <- if (n_total > 0) stats::sd(dqs_vals[is.finite(dqs_vals)]) else NA_real_
dqs_q    <- if (n_total > 0) stats::quantile(dqs_vals[is.finite(dqs_vals)],
                                             probs = c(0.05,0.25,0.50,0.75,0.95,0.99),
                                             na.rm = TRUE) else rep(NA_real_, 6L)

low_idx <- impact_scores_yac$is_low_value_snap_yac
dqs_low <- dqs_vals[low_idx]
dqs_abs_median_low <- if (any(low_idx)) stats::median(abs(dqs_low[is.finite(dqs_low)])) else NA_real_
dqs_abs_q90_low    <- if (any(low_idx)) stats::quantile(abs(dqs_low[is.finite(dqs_low)]),
                                                        probs = 0.90, na.rm = TRUE) else NA_real_

prop_low_value <- if (n_total > 0) mean(low_idx) else NA_real_

big_idx <- impact_scores_yac$is_big_miss_yac
prop_big_miss <- if (n_total > 0) mean(big_idx) else NA_real_
dqs_big       <- dqs_vals[big_idx]
dqs_big_q50   <- if (any(big_idx)) stats::median(dqs_big[is.finite(dqs_big)]) else NA_real_
dqs_big_q90   <- if (any(big_idx)) stats::quantile(dqs_big[is.finite(dqs_big)],
                                                   probs = 0.90, na.rm = TRUE) else NA_real_

yac_def_obs_vec <- impact_scores_yac$yac_def_obs
def_yac_outcome <- -impact_scores_yac$yac

cor_yacdef_obs_real <- suppressWarnings(
  stats::cor(yac_def_obs_vec, def_yac_outcome, use = "complete.obs")
)

pass_low_value <- is.finite(dqs_abs_median_low) &&
  is.finite(dqs_abs_q90_low) &&
  (dqs_abs_median_low <= LOW_VALUE_MEDIAN_MAX) &&
  (dqs_abs_q90_low    <= LOW_VALUE_Q90_MAX)

pass_tail_shape <- is.finite(prop_big_miss) && (prop_big_miss >= MIN_PROP_BIG_MISS)

pass <- pass_low_value  # Tail shape is diagnostic only for YAC; gating uses low-value behaviour only

status <- tibble::tibble(
  script                          = "35.2_counterfactual_scoring_yac.R",
  n_rows                          = n_total,
  n_rows_low_value_yac            = sum(low_idx, na.rm = TRUE),
  n_rows_big_miss_yac             = sum(big_idx, na.rm = TRUE),
  prop_low_value_yac              = prop_low_value,
  prop_big_miss_yac               = prop_big_miss,
  dqs_yac_mean                    = dqs_mean,
  dqs_yac_median                  = dqs_med,
  dqs_yac_sd                      = dqs_sd,
  dqs_yac_q05                     = dqs_q[[1]],
  dqs_yac_q25                     = dqs_q[[2]],
  dqs_yac_q50                     = dqs_q[[3]],
  dqs_yac_q75                     = dqs_q[[4]],
  dqs_yac_q95                     = dqs_q[[5]],
  dqs_yac_q99                     = dqs_q[[6]],
  value_eps_yac                   = VALUE_EPS_YAC,
  dqs_abs_median_low_value_yac    = dqs_abs_median_low,
  dqs_abs_q90_low_value_yac       = dqs_abs_q90_low,
  dqs_big_q50_yac                 = dqs_big_q50,
  dqs_big_q90_yac                 = dqs_big_q90,
  cor_yacdef_obs_real             = cor_yacdef_obs_real,
  dqs_big_threshold_yac           = DQS_BIG_YAC,
  min_prop_big_miss_yac           = MIN_PROP_BIG_MISS,
  pass_low_value_yac              = pass_low_value,
  pass_tail_shape_yac             = pass_tail_shape,
  pass                            = pass
)

readr::write_csv(status, PATH$out_status_csv)

md_lines <- c(
  "# 35.2_counterfactual_scoring_yac Status",
  "",
  "- Script: Code/35.2_counterfactual_scoring_yac.R",
  "",
  sprintf("- n_rows: %d", status$n_rows),
  sprintf("- prop_low_value_yac: %.3f", status$prop_low_value_yac),
  sprintf("- prop_big_miss_yac: %.3f", status$prop_big_miss_yac),
  "",
  "## DQS_yac distribution",
  sprintf("- mean: %.4f", status$dqs_yac_mean),
  sprintf("- median: %.4f", status$dqs_yac_median),
  sprintf("- sd: %.4f", status$dqs_yac_sd),
  sprintf("- q05/q25/q50/q75/q95/q99: %.4f / %.4f / %.4f / %.4f / %.4f / %.4f",
          status$dqs_yac_q05, status$dqs_yac_q25, status$dqs_yac_q50,
          status$dqs_yac_q75, status$dqs_yac_q95, status$dqs_yac_q99),
  "",
  "## Low-value snaps (spread below VALUE_EPS_YAC)",
  sprintf("- VALUE_EPS_YAC: %.3f", status$value_eps_yac),
  sprintf("- |DQS_yac| median (low-value): %.4f", status$dqs_abs_median_low_value_yac),
  sprintf("- |DQS_yac| q90 (low-value): %.4f", status$dqs_abs_q90_low_value_yac),
  sprintf("- pass_low_value_yac: %s", status$pass_low_value_yac),
  "",
  "## Big-miss tail (YAC)",
  sprintf("- DQS_BIG_YAC: %.3f", status$dqs_big_threshold_yac),
  sprintf("- MIN_PROP_BIG_MISS: %.3f", status$min_prop_big_miss_yac),
  sprintf("- prop_big_miss_yac: %.3f", status$prop_big_miss_yac),
  sprintf("- DQS_yac big-miss q50: %.4f", status$dqs_big_q50_yac),
  sprintf("- DQS_yac big-miss q90: %.4f", status$dqs_big_q90_yac),
  "",
  "## Predictive sanity (YAC)",
  sprintf("- cor(yac_def_obs, -yac): %.4f", status$cor_yacdef_obs_real),
  "",
  sprintf("- pass_tail_shape_yac: %s", status$pass_tail_shape_yac),
  sprintf("- pass_low_value_yac: %s", status$pass_low_value_yac),
  sprintf("- PASS (overall): %s", status$pass)
)

writeLines(md_lines, PATH$out_status_md)

cat("[35.2] Wrote status CSV to ", PATH$out_status_csv, " and MD to ",
    PATH$out_status_md, "\n", sep = "")

if (!pass) {
  stop("[35.2] Overall acceptance FAILED (see status for details).", call. = FALSE)
} else {
  cat("[35.2] Overall acceptance PASSED.\n")
}

cat("[35.2] Finished 35.2_counterfactual_scoring_yac.R\n")










# 36_rulecards_and_eval_final.R
# CLI: Rscript Code/36_rulecards_and_eval_final.R
#
# Purpose:
#   Learn simple R/LOI/BV rulecards (per def position × WR archetype)
#   from DR-based EPA and YAC impact scores, then evaluate rulecards
#   vs baselines on a held-out split with bootstrap CIs.

suppressPackageStartupMessages({
  library(tidyverse)
  library(readr)
  library(janitor)
  library(glue)
  library(scales)
})

set.seed(360L)

script_name    <- "36_rulecards_and_eval_final.R"
script_version <- "0.1.0"

DIR <- list(
  artifacts = "artifacts",
  figs      = file.path("artifacts", "figs_v3"),
  rulecards = file.path("artifacts", "rulecards_v3"),
  status    = file.path("artifacts", "diagnostics_v3")
)

PATH <- list(
  afford        = file.path(DIR$artifacts, "affordances_v3.csv"),
  impact_epa    = file.path(DIR$artifacts, "impact_scores_v3.csv"),
  impact_yac    = file.path(DIR$artifacts, "impact_scores_yac_v3.csv"),
  rulecards_csv = file.path(DIR$rulecards, "rulecards_thresholds_v3.csv"),
  eval_csv      = file.path(DIR$artifacts, "eval_summary_v3.csv"),
  eval_obs_csv  = file.path(DIR$artifacts, "eval_summary_vs_observed_v3.csv"),
  bars_png      = file.path(DIR$figs, "baseline_vs_model_bars_v3.png"),
  bars_obs_png  = file.path(DIR$figs, "baseline_vs_observed_bars_v3.png"),
  status_csv    = file.path(DIR$status, "36_rulecards_and_eval_status.csv"),
  status_md     = file.path(DIR$status, "36_rulecards_and_eval_status.md")
)

safe_dir_create <- function(path) dir.create(path, recursive = TRUE, showWarnings = FALSE)
logf           <- function(...) cat("[36]", ..., "\n")
stop_missing   <- function(path) if (!file.exists(path)) stop("Missing required input: ", path)

write_status <- function(status, notes) {
  safe_dir_create(DIR$status)
  status_df <- tibble(
    script  = script_name,
    version = script_version,
    status  = status,
    notes   = paste(notes, collapse = " | ")
  )
  readr::write_csv(status_df, PATH$status_csv)
  
  md <- c(
    paste0("# ", script_name),
    paste0("* version: ", script_version),
    paste0("* status: ", status),
    "",
    "## Notes",
    notes
  )
  writeLines(md, PATH$status_md)
}

coalesce_cols <- function(df, cols, default = NA_character_) {
  out <- rep(default, nrow(df))
  for (col in cols) {
    if (col %in% names(df)) {
      repl <- df[[col]]
      idx <- is.na(out) & !is.na(repl)
      out[idx] <- as.character(repl[idx])
    }
  }
  out
}

# ---------------------------------------------------------------------------
# 1. Load inputs and build base table
# ---------------------------------------------------------------------------

logf("Starting", script_name)

purrr::walk(c(PATH$afford, PATH$impact_epa), stop_missing)
purrr::walk(unique(dirname(unlist(PATH))), safe_dir_create)

aff <- readr::read_csv(PATH$afford, show_col_types = FALSE) %>%
  janitor::clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

impact_epa <- readr::read_csv(PATH$impact_epa, show_col_types = FALSE) %>%
  janitor::clean_names() %>%
  mutate(
    game_id = as.character(game_id),
    play_id = as.integer(play_id),
    nfl_id  = as.integer(nfl_id),
    split   = tolower(as.character(split))
  )

impact_yac <- NULL
if (file.exists(PATH$impact_yac)) {
  logf("Found YAC impact scores at", PATH$impact_yac)
  impact_yac <- readr::read_csv(PATH$impact_yac, show_col_types = FALSE) %>%
    janitor::clean_names() %>%
    mutate(
      game_id = as.character(game_id),
      play_id = as.integer(play_id),
      nfl_id  = as.integer(nfl_id),
      split   = tolower(as.character(split))
    )
} else {
  logf("No YAC impact scores found; YAC branch will be skipped if needed.")
}

logf("Joining affordances with impact scores")
base <- aff %>%
  left_join(impact_epa, by = c("game_id", "play_id", "nfl_id", "split"), suffix = c("", "_impact"))

if (!is.null(impact_yac)) {
  base <- base %>%
    left_join(impact_yac, by = c("game_id", "play_id", "nfl_id", "split"), suffix = c("", "_yac"))
}

base <- base %>%
  mutate(
    split = tolower(split)
  )

base$ext_position <- coalesce_cols(base, c("ext_position", "position", "def_position", "pos"))
base$ext_wr_arch  <- coalesce_cols(base, c("ext_wr_archetype", "wr_archetype", "wr_type", "route_bucket"))
base$ext_def_team <- coalesce_cols(base, c("ext_defteam", "defteam", "team"))

# choose holdout split: prefer "test", then "val", else first split present
split_levels <- unique(base$split)
holdout_split <- intersect(c("test", "val"), split_levels)[1]
if (is.na(holdout_split)) holdout_split <- split_levels[1]

logf("Using holdout split:", holdout_split)

base_holdout <- base %>% filter(split == holdout_split)
base_train   <- base %>% filter(split != holdout_split)

if (nrow(base_holdout) == 0) stop("Holdout split has zero rows; cannot evaluate rulecards")

# ---------------------------------------------------------------------------
# 2. Utilities for extracting per-action values (EPA / YAC)
# ---------------------------------------------------------------------------

extract_action_values <- function(df, outcome = c("epa", "yac")) {
  outcome <- match.arg(outcome)
  out <- df
  
  prefix     <- if (outcome == "epa") "epa_hat" else "yac_hat"
  def_prefix <- if (outcome == "epa") "ev_def"  else "yac_def"
  
  cols     <- paste0(prefix, "_", c("contest", "leverage", "backup", "hold"))
  def_cols <- paste0(def_prefix, "_", c("contest", "leverage", "backup", "hold"))
  
  # If per-action predictions missing, try defensive variants or affordance fallbacks
  if (!all(cols %in% names(out))) {
    if (all(def_cols %in% names(out))) {
      vals <- out %>% select(any_of(def_cols))
      names(vals) <- cols
      out <- bind_cols(out, vals)
    } else if (outcome == "epa" && all(c("ev_chase", "ev_leverage", "ev_backup") %in% names(out))) {
      # fallback from affordances (offensive EPA); treat chase as contest/hold proxy
      out <- out %>%
        mutate(
          epa_hat_contest  = ev_chase,
          epa_hat_leverage = ev_leverage,
          epa_hat_backup   = ev_backup,
          epa_hat_hold     = ev_chase
        )
    }
  }
  
  if (!all(cols %in% names(out))) {
    stop(glue("Missing per-action {outcome} estimates; expected columns like {prefix}_contest"))
  }
  
  # defensive value: lower offensive EPA/YAC is better
  out <- out %>%
    mutate(
      def_contest  = -get(cols[1]),
      def_leverage = -get(cols[2]),
      def_backup   = -get(cols[3]),
      def_hold     = -get(cols[4])
    )
  
  # observed action
  action_candidates <- c("action_obs", "action", "action_label", "label_action")
  act_obs <- NA_character_
  for (nm in action_candidates) {
    if (nm %in% names(out)) {
      act_obs <- out[[nm]]
      break
    }
  }
  if (all(is.na(act_obs))) stop("Observed action column missing for ", outcome)
  
  out$action_obs <- factor(act_obs, levels = c("contest", "leverage", "backup", "hold"))
  
  out <- out %>%
    mutate(
      def_obs = case_when(
        action_obs == "contest"  ~ def_contest,
        action_obs == "leverage" ~ def_leverage,
        action_obs == "backup"   ~ def_backup,
        action_obs == "hold"     ~ def_hold,
        TRUE                     ~ NA_real_
      )
    )
  
  out %>%
    select(
      game_id, play_id, nfl_id, split,
      ext_position, ext_wr_arch, ext_def_team,
      starts_with(prefix), starts_with(def_prefix),
      def_contest:def_hold, action_obs, def_obs,
      any_of(c("ev_chase", "ev_leverage", "ev_backup",
               "ev_def_opt_all", "yac_def_opt_all",
               "contest_eligible"))
    )
}

safe_eval <- function(expr) {
  tryCatch(expr, error = function(e) {
    logf("WARN:", conditionMessage(e))
    tibble()
  })
}

check_split <- function(df, label) {
  if (!nrow(df)) stop(glue("No rows available for {label}; verify inputs and splits"))
  invisible(TRUE)
}

# ---------------------------------------------------------------------------
# 3. Rule search (simple threshold grid on r/loi/bv)
# ---------------------------------------------------------------------------

segment_keys <- function(df) {
  df %>%
    mutate(
      seg_pos  = ifelse(is.na(ext_position) | ext_position == "", "all", ext_position),
      seg_arch = ifelse(is.na(ext_wr_arch)  | ext_wr_arch  == "", "all", ext_wr_arch)
    )
}

build_rules <- function(df) {
  # df must have r, loi, bv and defensive values per action
  needed <- c("r", "loi", "bv",
              "def_contest", "def_leverage", "def_backup", "def_hold")
  if (!all(needed %in% names(df))) {
    stop("R/LOI/BV or defensive values missing for rule building")
  }
  
  # contest baseline we want to beat (nearest-man contest)
  if ("contest_eligible" %in% names(df)) {
    baseline_nn <- dplyr::if_else(df$contest_eligible,
                                  df$def_contest,
                                  df$def_hold)
  } else {
    baseline_nn <- df$def_contest
  }
  
  # thresholds: use a slightly richer grid, especially for LOI/BV
  thresh_r   <- stats::quantile(df$r,   probs = c(0.1, 0.3, 0.5, 0.7, 0.9),
                                na.rm = TRUE)
  thresh_loi <- stats::quantile(df$loi, probs = c(0.1, 0.3, 0.5, 0.7, 0.9),
                                na.rm = TRUE)
  thresh_bv  <- stats::quantile(df$bv,  probs = c(0.1, 0.3, 0.5, 0.7, 0.9),
                                na.rm = TRUE)
  
  # remove duplicates so r's crazy spike doesn't give identical thresholds
  thresh_r   <- unique(thresh_r)
  thresh_loi <- unique(thresh_loi)
  thresh_bv  <- unique(thresh_bv)
  
  grid <- tidyr::expand_grid(tr = thresh_r,
                             tl = thresh_loi,
                             tb = thresh_bv) %>%
    dplyr::distinct()
  
  # score one triple of thresholds
  score_rule <- function(tr, tl, tb) {
    act_pred <- dplyr::case_when(
      df$r   >= tr ~ "contest",
      df$loi >= tl ~ "leverage",
      df$bv  >= tb ~ "backup",
      TRUE        ~ "hold"
    )
    def_pred <- dplyr::case_when(
      act_pred == "contest"  ~ df$def_contest,
      act_pred == "leverage" ~ df$def_leverage,
      act_pred == "backup"   ~ df$def_backup,
      TRUE                   ~ df$def_hold
    )
    
    gain <- def_pred - baseline_nn
    
    tibble::tibble(
      gain_mean = mean(gain,      na.rm = TRUE),
      def_mean  = mean(def_pred,  na.rm = TRUE)
    )
  }
  
  grid %>%
    dplyr::mutate(res = purrr::pmap(list(tr, tl, tb),
                                    ~score_rule(..1, ..2, ..3))) %>%
    tidyr::unnest(res) %>%
    dplyr::arrange(dplyr::desc(gain_mean)) %>%
    dplyr::slice(1)
}

apply_rule <- function(df_row, rule_row) {
  act_pred <- case_when(
    df_row$r   >= rule_row$tr ~ "contest",
    df_row$loi >= rule_row$tl ~ "leverage",
    df_row$bv  >= rule_row$tb ~ "backup",
    TRUE                      ~ "hold"
  )
  def_pred <- case_when(
    act_pred == "contest"  ~ df_row$def_contest,
    act_pred == "leverage" ~ df_row$def_leverage,
    act_pred == "backup"   ~ df_row$def_backup,
    TRUE                   ~ df_row$def_hold
  )
  tibble(action_rule = act_pred, def_rule = def_pred)
}

fit_rules_by_segment <- function(df_train, df_holdout, outcome_label) {
  df_train   <- segment_keys(df_train)
  df_holdout <- segment_keys(df_holdout)
  
  segments   <- df_train %>% count(seg_pos, seg_arch, sort = FALSE)
  global_rule <- if (nrow(df_train) >= 10) build_rules(df_train) else tibble()
  
  rules <- segments %>%
    mutate(rule = pmap(list(seg_pos, seg_arch), function(pos, arch) {
      sub <- df_train %>% filter(seg_pos == pos, seg_arch == arch)
      if (nrow(sub) >= 10) return(build_rules(sub))
      global_rule
    }))
  
  rules <- rules %>%
    mutate(rule = map(rule, ~if (is.null(.x)) tibble() else .x))
  
  # Apply rules to holdout
  applied <- df_holdout %>%
    left_join(rules, by = c("seg_pos", "seg_arch"))
  
  applied <- applied %>%
    mutate(has_rule = map_lgl(rule, ~nrow(.x) > 0))
  
  applied <- applied %>%
    mutate(rule_pred = map2(rule, row_number(), function(rw, idx) {
      if (nrow(rw) == 0) return(tibble(action_rule = NA_character_, def_rule = NA_real_))
      apply_rule(df_holdout[idx, ], rw[1, ])
    }))
  
  applied <- applied %>% unnest(rule_pred)
  
  # baselines (nearest contest / chase / zone)
  applied <- applied %>%
    mutate(
      def_nn_contest = if ("contest_eligible" %in% names(.)) {
        if_else(contest_eligible, def_contest, def_hold)
      } else {
        def_contest
      },
      def_chase = if ("ev_chase" %in% names(.)) {
        -ev_chase
      } else {
        def_leverage
      },
      def_zone = def_hold
    )
  
  list(
    rules   = rules,
    applied = applied
  )
}

# ---------------------------------------------------------------------------
# 4. Plotting helpers
# ---------------------------------------------------------------------------

plot_rules_tiles <- function(rules_tbl, outcome_label) {
  rules_long <- rules_tbl %>%
    unnest(rule) %>%
    mutate(outcome = outcome_label)
  if (nrow(rules_long) == 0) return(NULL)
  
  ggplot(rules_long,
         aes(x = seg_arch, y = seg_pos,
             label = sprintf("R>=%.2f\nLOI>=%.2f\nBV>=%.2f", tr, tl, tb))) +
    geom_tile(fill = "#eef3fb", color = "#d0d7e5") +
    geom_text(size = 3.4) +
    labs(
      title = glue("Rule cards ({outcome_label})"),
      x = "WR archetype",
      y = "Def position"
    ) +
    theme_minimal() +
    theme(axis.text.x = element_text(angle = 45, hjust = 1))
}

plot_rulecard_heatmaps <- function(rules_tbl, df_train, outcome_label) {
  df_train   <- segment_keys(df_train)
  rules_long <- rules_tbl %>% tidyr::unnest(rule)
  if (nrow(rules_long) == 0) return(invisible(NULL))
  
  for (i in seq_len(nrow(rules_long))) {
    rr   <- rules_long[i, ]
    pos  <- rr$seg_pos
    arch <- rr$seg_arch
    
    dat_seg <- df_train %>%
      dplyr::filter(seg_pos == pos, seg_arch == arch)
    
    # Skip tiny segments
    if (nrow(dat_seg) < 50) next
    
    # If ALL r / loi / bv are NA or non-finite, skip BEFORE calling range/median
    if (!any(is.finite(dat_seg$r)) ||
        !any(is.finite(dat_seg$loi)) ||
        !any(is.finite(dat_seg$bv))) {
      next
    }
    
    r_range   <- range(dat_seg$r,   na.rm = TRUE)
    loi_range <- range(dat_seg$loi, na.rm = TRUE)
    bv_med    <- stats::median(dat_seg$bv, na.rm = TRUE)
    
    grid <- tidyr::expand_grid(
      r   = seq(r_range[1],   r_range[2],   length.out = 60),
      loi = seq(loi_range[1], loi_range[2], length.out = 60)
    ) %>%
      dplyr::mutate(bv = bv_med)
    
    grid <- grid %>%
      dplyr::mutate(
        action_hat = dplyr::case_when(
          r   >= rr$tr ~ "contest",
          loi >= rr$tl ~ "leverage",
          bv  >= rr$tb ~ "backup",
          TRUE        ~ "hold"
        )
      )
    
    p <- ggplot2::ggplot(grid, ggplot2::aes(x = loi, y = r, fill = action_hat)) +
      ggplot2::geom_tile() +
      ggplot2::scale_fill_brewer(palette = "Set2") +
      ggplot2::labs(
        title = glue::glue("Rulecard ({outcome_label}) – {pos} / {arch}"),
        x = "LOI",
        y = "R",
        fill = "Action"
      ) +
      ggplot2::theme_minimal()
    
    fname <- file.path(DIR$rulecards,
                       glue::glue("rulecard_{tolower(outcome_label)}_{pos}_{arch}.png"))
    ggplot2::ggsave(fname, p, width = 6, height = 4, dpi = 150)
  }
  
  invisible(NULL)
}

bootstrap_ci <- function(x, y, B = 500) {
  x <- as.numeric(x)
  y <- as.numeric(y)
  ok <- is.finite(x) & is.finite(y)
  x <- x[ok]; y <- y[ok]
  if (!length(x)) return(c(NA_real_, NA_real_))
  
  diffs <- replicate(B, {
    idx <- sample(seq_along(x), replace = TRUE)
    mean(x[idx] - y[idx], na.rm = TRUE)
  })
  stats::quantile(diffs, probs = c(0.025, 0.975), na.rm = TRUE)
}

# ---------------------------------------------------------------------------
# 5. EPA branch
# ---------------------------------------------------------------------------

epa_df <- safe_eval(extract_action_values(base, outcome = "epa"))
if (nrow(epa_df) == 0) stop("EPA data unavailable for rulecard generation")
check_split(epa_df, "EPA")

epa_train   <- epa_df %>%
  left_join(base_train %>% select(game_id, play_id, nfl_id, r, loi, bv),
            by = c("game_id", "play_id", "nfl_id"))
epa_holdout <- epa_df %>%
  left_join(base_holdout %>% select(game_id, play_id, nfl_id, r, loi, bv),
            by = c("game_id", "play_id", "nfl_id"))

logf("EPA train rows:", nrow(epa_train), "| holdout rows:", nrow(epa_holdout))

epa_fit <- fit_rules_by_segment(epa_train, epa_holdout, outcome_label = "epa")

ci_epa_contest <- bootstrap_ci(epa_fit$applied$def_rule, epa_fit$applied$def_nn_contest)
ci_epa_chase   <- bootstrap_ci(epa_fit$applied$def_rule, epa_fit$applied$def_chase)
ci_epa_zone    <- bootstrap_ci(epa_fit$applied$def_rule, epa_fit$applied$def_zone)

# ---------------------------------------------------------------------------
# 6. YAC branch (optional)
# ---------------------------------------------------------------------------

yac_df <- safe_eval(extract_action_values(base, outcome = "yac"))
has_yac <- nrow(yac_df) > 0

if (has_yac) {
  check_split(yac_df, "YAC")
  
  yac_train <- yac_df %>%
    left_join(base_train %>% select(game_id, play_id, nfl_id, r, loi, bv),
              by = c("game_id", "play_id", "nfl_id"))
  yac_holdout <- yac_df %>%
    left_join(base_holdout %>% select(game_id, play_id, nfl_id, r, loi, bv),
              by = c("game_id", "play_id", "nfl_id"))
  
  logf("YAC train rows:", nrow(yac_train), "| holdout rows:", nrow(yac_holdout))
  
  yac_fit <- fit_rules_by_segment(yac_train, yac_holdout, outcome_label = "yac")
  
  ci_yac_contest <- bootstrap_ci(yac_fit$applied$def_rule, yac_fit$applied$def_nn_contest)
  ci_yac_chase   <- bootstrap_ci(yac_fit$applied$def_rule, yac_fit$applied$def_chase)
  ci_yac_zone    <- bootstrap_ci(yac_fit$applied$def_rule, yac_fit$applied$def_zone)
} else {
  logf("No YAC rows – skipping YAC rulecards/evaluation.")
  yac_fit <- NULL
  ci_yac_contest <- ci_yac_chase <- ci_yac_zone <- c(NA_real_, NA_real_)
}

# ---------------------------------------------------------------------------
# 7. Rulecard figures (tiles + R–LOI heatmaps)
# ---------------------------------------------------------------------------

safe_dir_create(DIR$rulecards)

rc_epa <- plot_rules_tiles(epa_fit$rules, "EPA")
if (!is.null(rc_epa)) {
  ggsave(file.path(DIR$rulecards, "rulecards_epa_v3.png"),
         rc_epa, width = 8, height = 6, dpi = 150)
}

plot_rulecard_heatmaps(epa_fit$rules, epa_train, "EPA")

if (has_yac && !is.null(yac_fit)) {
  rc_yac <- plot_rules_tiles(yac_fit$rules, "YAC")
  if (!is.null(rc_yac)) {
    ggsave(file.path(DIR$rulecards, "rulecards_yac_v3.png"),
           rc_yac, width = 8, height = 6, dpi = 150)
  }
  plot_rulecard_heatmaps(yac_fit$rules, yac_train, "YAC")
}

# Export thresholds to CSV for audit / inspection
rules_long_export <- bind_rows(
  epa_fit$rules %>% mutate(outcome = "epa"),
  if (has_yac && !is.null(yac_fit)) yac_fit$rules %>% mutate(outcome = "yac") else tibble()
) %>%
  unnest(rule) %>%
  select(outcome, seg_pos, seg_arch, tr, tl, tb, def_mean)

readr::write_csv(rules_long_export, PATH$rulecards_csv)

# ---------------------------------------------------------------------------
# 8. Evaluation summary and bar charts
# ---------------------------------------------------------------------------

# Gain vs baselines (defensive value)
epa_applied <- epa_fit$applied

epa_diff_contest <- mean(epa_applied$def_rule - epa_applied$def_nn_contest, na.rm = TRUE)
epa_diff_chase   <- mean(epa_applied$def_rule - epa_applied$def_chase,      na.rm = TRUE)
epa_diff_zone    <- mean(epa_applied$def_rule - epa_applied$def_zone,       na.rm = TRUE)

summ_rows <- list(
  tibble(outcome = "epa", baseline = "contest",
         diff = epa_diff_contest,
         ci_lo = ci_epa_contest[1], ci_hi = ci_epa_contest[2]),
  tibble(outcome = "epa", baseline = "chase",
         diff = epa_diff_chase,
         ci_lo = ci_epa_chase[1], ci_hi = ci_epa_chase[2]),
  tibble(outcome = "epa", baseline = "zone",
         diff = epa_diff_zone,
         ci_lo = ci_epa_zone[1], ci_hi = ci_epa_zone[2])
)

if (has_yac && !is.null(yac_fit)) {
  yac_applied <- yac_fit$applied
  yac_diff_contest <- mean(yac_applied$def_rule - yac_applied$def_nn_contest, na.rm = TRUE)
  yac_diff_chase   <- mean(yac_applied$def_rule - yac_applied$def_chase,      na.rm = TRUE)
  yac_diff_zone    <- mean(yac_applied$def_rule - yac_applied$def_zone,       na.rm = TRUE)
  
  summ_rows <- append(summ_rows, list(
    tibble(outcome = "yac", baseline = "contest",
           diff = yac_diff_contest,
           ci_lo = ci_yac_contest[1], ci_hi = ci_yac_contest[2]),
    tibble(outcome = "yac", baseline = "chase",
           diff = yac_diff_chase,
           ci_lo = ci_yac_chase[1], ci_hi = ci_yac_chase[2]),
    tibble(outcome = "yac", baseline = "zone",
           diff = yac_diff_zone,
           ci_lo = ci_yac_zone[1], ci_hi = ci_yac_zone[2])
  ))
}

eval_summary <- bind_rows(summ_rows)
readr::write_csv(eval_summary, PATH$eval_csv)

# Optional: gain vs observed and vs "optimal" for EPA (v1-style)
eval_obs <- epa_applied %>%
  mutate(
    gain_rule   = def_rule       - def_obs,
    gain_nn     = def_nn_contest - def_obs,
    gain_chase  = def_chase      - def_obs,
    gain_zone   = def_zone       - def_obs,
    gain_opt    = if ("ev_def_opt_all" %in% names(.))
      ev_def_opt_all - def_obs
    else NA_real_
  ) %>%
  summarise(
    n            = n(),
    mean_rule    = mean(gain_rule,  na.rm = TRUE),
    mean_nn      = mean(gain_nn,    na.rm = TRUE),
    mean_chase   = mean(gain_chase, na.rm = TRUE),
    mean_zone    = mean(gain_zone,  na.rm = TRUE),
    mean_opt     = mean(gain_opt,   na.rm = TRUE)
  )

readr::write_csv(eval_obs, PATH$eval_obs_csv)

# Bar plot: Δ vs baselines
p_bars <- eval_summary %>%
  mutate(
    baseline = str_to_title(baseline),
    outcome  = toupper(outcome)
  ) %>%
  ggplot(aes(x = baseline, y = diff, fill = outcome)) +
  geom_col(alpha = 0.85, position = position_dodge(width = 0.7)) +
  geom_errorbar(aes(ymin = ci_lo, ymax = ci_hi),
                width = 0.2,
                position = position_dodge(width = 0.7)) +
  geom_hline(yintercept = 0, linetype = "dashed") +
  labs(
    x = "Baseline policy",
    y = "Defensive gain vs baseline (per snap)",
    title    = "Rulecard uplift vs baselines",
    subtitle = "Positive = better defense (lower offensive EPA / YAC)"
  ) +
  theme_minimal()

ggsave(PATH$bars_png, p_bars, width = 7, height = 5, dpi = 150)

# ---------------------------------------------------------------------------
# 9. Acceptance gate and status
# ---------------------------------------------------------------------------

# EPA: require rulecard to beat contest and zone (chase is diagnostic only)
pass_epa <- (ci_epa_contest[1] > 0) &&
  (ci_epa_zone[1]    > 0)

# YAC: same idea – contest + zone are the real baselines
if (has_yac && !is.null(yac_fit)) {
  pass_yac <- (ci_yac_contest[1] > 0) &&
    (ci_yac_zone[1]    > 0)
} else {
  pass_yac <- TRUE  # nothing to check
}

# Softer gate: PASS / WARN, do not stop the pipeline
status_flag <- if (pass_epa && pass_yac) "PASS" else "WARN"

notes <- c(
  paste0("Holdout split: ", holdout_split),
  paste0("EPA Δ vs contest: ", signif(epa_diff_contest, 4),
         "  CI [", round(ci_epa_contest[1], 4), ", ", round(ci_epa_contest[2], 4), "]"),
  paste0("EPA Δ vs chase:   ", signif(epa_diff_chase, 4),
         "  CI [", round(ci_epa_chase[1], 4), ", ", round(ci_epa_chase[2], 4), "]"),
  paste0("EPA Δ vs zone:    ", signif(epa_diff_zone, 4),
         "  CI [", round(ci_epa_zone[1], 4), ", ", round(ci_epa_zone[2], 4), "]"),
  paste0("Has YAC: ", has_yac)
)

if (has_yac && !is.null(yac_fit)) {
  notes <- c(
    notes,
    paste0("YAC Δ vs contest: ", signif(yac_diff_contest, 4),
           "  CI [", round(ci_yac_contest[1], 4), ", ", round(ci_yac_contest[2], 4), "]"),
    paste0("YAC Δ vs chase:   ", signif(yac_diff_chase, 4),
           "  CI [", round(ci_yac_chase[1], 4), ", ", round(ci_yac_chase[2], 4), "]"),
    paste0("YAC Δ vs zone:    ", signif(yac_diff_zone, 4),
           "  CI [", round(ci_yac_zone[1], 4), ", ", round(ci_yac_zone[2], 4), "]")
  )
}

write_status(status_flag, notes)

if (status_flag == "PASS") {
  logf("Finished", script_name, "with status PASS")
} else {
  logf("Finished", script_name, "with status WARN (see status file for details)")
}










