# -------------------------------------------------------------------
# Helpers
# -------------------------------------------------------------------

safe_dir_create <- function(path) {
  dir.create(path, recursive = TRUE, showWarnings = FALSE)
}

logf <- function(...) {
  cat("[37]", ..., "\n")
}

write_status <- function(status, notes) {
  safe_dir_create(DIR$status)
  status_df <- tibble(
    script  = script_name,
    version = script_version,
    status  = status,
    notes   = paste(notes, collapse = " | ")
  )
  write_csv(status_df, PATH$status_csv)
  
  md <- c(
    glue("# {script_name}"),
    glue("* version: {script_version}"),
    glue("* status: {status}"),
    "",
    "## Notes",
    notes
  )
  writeLines(md, PATH$status_md)
}

copy_if_exists <- function(src, dst) {
  if (!file.exists(src)) {
    return(list(status = "MISSING", src = src, dst = dst))
  }
  safe_dir_create(dirname(dst))
  ok <- file.copy(src, dst, overwrite = TRUE)
  list(status = if (ok) "OK" else "FAIL", src = src, dst = dst)
}

# Take first n PNGs from dir and grid them into a single PNG
grid_pngs_from_dir <- function(src_dir, out_path, n = 4, title = NULL) {
  if (!dir.exists(src_dir)) {
    return(list(status = "MISSING", src = src_dir, dst = out_path))
  }
  files <- list.files(src_dir, pattern = "\\.png$", full.names = TRUE)
  if (length(files) == 0) {
    return(list(status = "MISSING", src = src_dir, dst = out_path))
  }
  files <- head(files, n)
  
  plots <- lapply(files, function(f) {
    ggdraw() + draw_image(f)
  })
  
  n_plots <- length(plots)
  nrow <- ceiling(sqrt(n_plots))
  ncol <- ceiling(n_plots / nrow)
  
  p <- plot_grid(plotlist = plots, nrow = nrow, ncol = ncol)
  if (!is.null(title)) {
    p <- plot_grid(ggdraw() + draw_label(title, fontface = "bold", hjust = 0),
                   p, ncol = 1, rel_heights = c(0.1, 0.9))
  }
  
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 8, height = 6, dpi = 150)
  list(status = "OK", src = src_dir, dst = out_path)
}

# Convenience to append rows to fig index
# Create a simple placeholder PNG when a source figure is unavailable
make_placeholder <- function(label, out_path) {
  safe_dir_create(dirname(out_path))
  p <- ggplot() +
    theme_void() +
    annotate(
      "text",
      x = 0.5, y = 0.5,
      label = paste0(label, "\n(source figure not yet generated)"),
      size = 5, lineheight = 1.1
    ) +
    coord_cartesian(xlim = c(0, 1), ylim = c(0, 1))
  ggsave(out_path, p, width = 6, height = 4, dpi = 150)
  list(status = "PLACEHOLDER", src = NA_character_, dst = out_path)
}

# Build Fig1 directly from v3 tabular artifacts if no source PNG is available
build_fig1_from_artifacts <- function(out_path) {
  elig_path <- file.path(DIR$artifacts, "eligibility_v3.csv")
  afford_path <- file.path(DIR$artifacts, "affordances_v3.csv")
  if (!file.exists(elig_path) || !file.exists(afford_path)) {
    logf("WARN: eligibility_v3.csv or affordances_v3.csv missing – falling back to placeholder for Fig1.")
    return(make_placeholder("Fig1 – Observed tracks", out_path))
  }
  elig <- readr::read_csv(elig_path, show_col_types = FALSE)
  aff  <- readr::read_csv(afford_path, show_col_types = FALSE)
  dat <- dplyr::inner_join(
    elig %>% dplyr::select(game_id, play_id, nfl_id, split, d_start, T_ball, p_reach),
    aff  %>% dplyr::select(game_id, play_id, nfl_id, split, zone),
    by = c("game_id", "play_id", "nfl_id", "split")
  ) %>%
    dplyr::mutate(
      zone = forcats::fct_lump_n(zone, 4)
    )
  if (nrow(dat) == 0) {
    logf("WARN: No rows after join for Fig1 – falling back to placeholder.")
    return(make_placeholder("Fig1 – Observed tracks", out_path))
  }
  set.seed(1L)
  if (nrow(dat) > 3000) {
    dat <- dplyr::sample_n(dat, 3000)
  }
  p <- ggplot(dat, aes(x = d_start, y = T_ball, colour = zone)) +
    geom_point(alpha = 0.4, size = 0.6) +
    facet_wrap(~ zone, ncol = 2) +
    labs(
      title = "Observed coverage geometry at throw",
      x = "Start distance to target (yards)",
      y = "Ball flight time (s)",
      colour = "Zone"
    ) +
    theme_bw()
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 7, height = 5, dpi = 150)
  list(status = "OK", src = NA_character_, dst = out_path)
}

# Build Fig2 leverage-angle roses from direction_recommendations_v3.csv
build_fig2_from_artifacts <- function(out_path) {
  dr_path <- file.path(DIR$artifacts, "direction_recommendations_v3.csv")
  if (!file.exists(dr_path)) {
    logf("WARN: direction_recommendations_v3.csv missing – falling back to placeholder for Fig2.")
    return(make_placeholder("Fig2 – Leverage-angle roses", out_path))
  }
  dr <- readr::read_csv(dr_path, show_col_types = FALSE) %>%
    dplyr::filter(!is.na(theta_star_deg)) %>%
    dplyr::mutate(
      zone = forcats::fct_lump_n(zone, 4),
      theta_bin = cut(theta_star_deg,
                      breaks = seq(-180, 180, by = 15),
                      include.lowest = TRUE,
                      right = FALSE)
    ) %>%
    dplyr::group_by(zone, theta_bin) %>%
    dplyr::summarise(n = dplyr::n(), .groups = "drop") %>%
    dplyr::mutate(
      theta_mid = (as.numeric(theta_bin) - 0.5) * 15 - 180
    )
  if (nrow(dr) == 0) {
    logf("WARN: No non-missing theta_star_deg for Fig2 – falling back to placeholder.")
    return(make_placeholder("Fig2 – Leverage-angle roses", out_path))
  }
  p <- ggplot(dr, aes(x = theta_mid, y = n)) +
    geom_col() +
    coord_polar(start = 0) +
    facet_wrap(~ zone) +
    labs(
      title = "Leverage direction roses",
      x = "Direction (degrees)",
      y = "Count"
    ) +
    theme_minimal() +
    theme(
      axis.text.y = element_blank(),
      axis.ticks.y = element_blank()
    )
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 7, height = 5, dpi = 150)
  list(status = "OK", src = NA_character_, dst = out_path)
}

# Build Fig3 eligibility field map from eligibility_v3 + affordances_v3
build_fig3_from_artifacts <- function(out_path) {
  elig_path <- file.path(DIR$artifacts, "eligibility_v3.csv")
  afford_path <- file.path(DIR$artifacts, "affordances_v3.csv")
  if (!file.exists(elig_path) || !file.exists(afford_path)) {
    logf("WARN: eligibility_v3.csv or affordances_v3.csv missing – falling back to placeholder for Fig3.")
    return(make_placeholder("Fig3 – Eligibility field map", out_path))
  }
  elig <- readr::read_csv(elig_path, show_col_types = FALSE)
  aff  <- readr::read_csv(afford_path, show_col_types = FALSE)
  dat <- dplyr::inner_join(
    elig %>% dplyr::select(game_id, play_id, nfl_id, split, p_reach, contest_eligible),
    aff  %>% dplyr::select(game_id, play_id, nfl_id, split, zone, LOI, BV),
    by = c("game_id", "play_id", "nfl_id", "split")
  ) %>%
    dplyr::mutate(
      zone = forcats::fct_lump_n(zone, 4),
      LOI_bin = round(LOI),
      BV_bin  = round(BV)
    ) %>%
    dplyr::group_by(zone, LOI_bin, BV_bin) %>%
    dplyr::summarise(
      p_eligible = mean(contest_eligible, na.rm = TRUE),
      .groups = "drop"
    )
  if (nrow(dat) == 0) {
    logf("WARN: No rows after join for Fig3 – falling back to placeholder.")
    return(make_placeholder("Fig3 – Eligibility field map", out_path))
  }
  p <- ggplot(dat, aes(x = LOI_bin, y = BV_bin, fill = p_eligible)) +
    geom_tile() +
    facet_wrap(~ zone) +
    coord_equal() +
    labs(
      title = "Eligibility field map by zone",
      x = "Downfield (LOI, yards)",
      y = "Crossfield (BV, yards)",
      fill = "P(eligible)"
    ) +
    theme_minimal()
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 7, height = 5, dpi = 150)
  list(status = "OK", src = NA_character_, dst = out_path)
}

# Build Fig4 contestability vs separation from missed_opportunities_v3 + affordances_v3
build_fig4_from_artifacts <- function(out_path) {
  miss_path <- file.path(DIR$artifacts, "missed_opportunities_v3.csv")
  afford_path <- file.path(DIR$artifacts, "affordances_v3.csv")
  if (!file.exists(miss_path) || !file.exists(afford_path)) {
    logf("WARN: missed_opportunities_v3.csv or affordances_v3.csv missing – falling back to placeholder for Fig4.")
    return(make_placeholder("Fig4 – Contestability vs separation", out_path))
  }
  miss <- readr::read_csv(miss_path, show_col_types = FALSE)
  aff  <- readr::read_csv(afford_path, show_col_types = FALSE)
  dat <- dplyr::inner_join(
    miss %>% dplyr::select(game_id, play_id, nfl_id, split, contest_eligible),
    aff  %>% dplyr::select(game_id, play_id, nfl_id, split, sep_throw),
    by = c("game_id", "play_id", "nfl_id", "split")
  ) %>%
    dplyr::filter(!is.na(sep_throw)) %>%
    dplyr::mutate(
      contest = as.numeric(contest_eligible)
    )
  if (nrow(dat) == 0) {
    logf("WARN: No rows after join for Fig4 – falling back to placeholder.")
    return(make_placeholder("Fig4 – Contestability vs separation", out_path))
  }
  p <- ggplot(dat, aes(x = sep_throw, y = contest)) +
    stat_smooth(method = "loess", formula = y ~ x, se = TRUE) +
    labs(
      title = "Contestability vs WR–DB separation at throw",
      x = "Separation at throw (yards)",
      y = "P(contest)"
    ) +
    theme_minimal()
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 7, height = 5, dpi = 150)
  list(status = "OK", src = NA_character_, dst = out_path)
}

# Build Fig6 independent vs coordinated summary from coordination_set_v3.csv
build_fig6_from_artifacts <- function(out_path) {
  coord_path <- file.path(DIR$artifacts, "coordination_set_v3.csv")
  if (!file.exists(coord_path)) {
    logf("WARN: coordination_set_v3.csv missing – falling back to placeholder for Fig6.")
    return(make_placeholder("Fig6 – Independent vs coordinated overlays", out_path))
  }
  coord <- readr::read_csv(coord_path, show_col_types = FALSE) %>%
    dplyr::mutate(
      zone = forcats::fct_lump_n(zone, 4),
      gain_team = ev_team_coord - ev_team_indep
    )
  if (nrow(coord) == 0 || all(is.na(coord$gain_team))) {
    logf("WARN: No usable gain_team values for Fig6 – falling back to placeholder.")
    return(make_placeholder("Fig6 – Independent vs coordinated overlays", out_path))
  }
  summ <- coord %>%
    dplyr::group_by(zone) %>%
    dplyr::summarise(
      mean_gain = mean(gain_team, na.rm = TRUE),
      q25 = stats::quantile(gain_team, 0.25, na.rm = TRUE),
      q75 = stats::quantile(gain_team, 0.75, na.rm = TRUE),
      .groups = "drop"
    )
  p <- ggplot(summ, aes(x = reorder(zone, mean_gain), y = mean_gain)) +
    geom_col() +
    geom_errorbar(aes(ymin = q25, ymax = q75), width = 0.2) +
    coord_flip() +
    labs(
      title = "Impact of coordination by zone",
      x = "Zone",
      y = "Team EPA gain from coordination"
    ) +
    theme_minimal()
  safe_dir_create(dirname(out_path))
  ggsave(out_path, p, width = 7, height = 5, dpi = 150)
  list(status = "OK", src = NA_character_, dst = out_path)
}
add_fig_row <- function(idx_tbl, fig_id, filename, title, description,
                        source_scripts, status) {
  bind_rows(
    idx_tbl,
    tibble(
      fig_id         = fig_id,
      filename       = filename,
      title          = title,
      description    = description,
      source_scripts = source_scripts,
      status         = status
    )
  )
}

