    "knitr::include_graphics(\"../artifacts/figs_v3/fig3_eligibility_map.png\")",
    "```",
    "",
    "# 4. Contestability vs separation",
    "",
    "```{r fig4, echo=FALSE, message=FALSE, warning=FALSE}",
    "knitr::include_graphics(\"../artifacts/figs_v3/fig4_contest_vs_sep.png\")",
    "```",
    "",
    "# 5. Observed vs optimal direction ($\\theta^*$)",
    "",
    "```{r fig5, echo=FALSE, message=FALSE, warning=FALSE}",
    "knitr::include_graphics(\"../artifacts/figs_v3/fig5_observed_vs_theta_star.png\")",
    "```",
