                   "fig8_missed_op_leaderboard",
                   "fig9_rulecard")

missing_required <- fig_index %>%
  filter(fig_id %in% required_figs, status != "OK")

notes <- c()

if (nrow(missing_required) > 0) {
  notes <- c(
    notes,
    paste("Missing figures:", paste(missing_required$fig_id, collapse = ", "))
  )
}

if (!report_ok) {
  notes <- c(notes, "Report render had errors (see console).")
}

if (length(notes) == 0) {
  notes <- c("All required figures present; PDF and HTML rendered successfully.")
}

status_flag <- if (nrow(missing_required) == 0 && report_ok) "PASS" else "WARN"

write_status(status_flag, notes)

logf("Finished", script_name, "with status", status_flag)










